// ========== Role Factory (Standalone Fallback) ==========

const RoleType = {
  PM: 'pm',
  ARCHITECT: 'architect',
  ENGINEER: 'engineer',
  FRONTEND_ENGINEER: 'frontend',
  BACKEND_ENGINEER: 'backend',
  QA: 'qa',
  DEVOPS: 'devops',
  SECURITY: 'security',
  DATA_ENGINEER: 'data',
  DESIGNER: 'designer'
};

class Role {
  constructor(roleId, name, roleType, skills = []) {
    this.roleId = roleId;
    this.name = name;
    this.roleType = roleType;
    this.skills = skills;
    this.actions = {};
    this.inbox = [];
    this.outbox = [];
    this.context = {};
    this._initActions();
  }
  
  _initActions() {
    // Override in subclass
  }
  
  addAction(name, description, inputKeys = [], outputKey = '') {
    this.actions[name] = { name, description, inputKeys, outputKey };
  }
  
  canExecute(actionName) {
    return actionName in this.actions;
  }
  
  receive(message) {
    this.inbox.push(message);
  }
  
  send(receiver, content, msgType = 'action') {
    const msg = {
      sender: this.roleId,
      receiver,
      content,
      msgType,
      timestamp: new Date().toISOString()
    };
    this.outbox.push(msg);
    return msg;
  }
  
  toDict() {
    return {
      roleId: this.roleId,
      name: this.name,
      roleType: this.roleType,
      skills: this.skills,
      actions: Object.keys(this.actions)
    };
  }
}

class ProductManager extends Role {
  constructor(roleId = 'pm') {
    super(roleId, '产品经理', RoleType.PM, ['需求分析', '产品设计', '用户研究', '数据分析']);
  }
  
  _initActions() {
    this.addAction('analyze_requirements', '分析用户需求', ['user_input'], 'requirements');
    this.addAction('create_prd', '创建产品需求文档', ['requirements'], 'prd');
    this.addAction('prioritize_features', '功能优先级排序', ['features'], 'priority_list');
  }
  
  analyzeRequirements(context) {
    const userInput = context.user_input || context.project || '';
    
    const requirements = {
      raw_input: userInput,
      features: this._extractFeatures(userInput),
      constraints: this._extractConstraints(userInput),
      priority: /紧急|important/i.test(userInput) ? 'high' : 'normal'
    };
    
    return requirements;
  }
  
  _extractFeatures(text) {
    const features = [];
    const keywords = ['登录', '注册', '搜索', '支付', '管理', '分析', '导出', '导入'];
    for (const kw of keywords) {
      if (text.includes(kw)) features.push(kw);
    }
    if (!features.length) features.push('基础功能');
    return features;
  }
  
  _extractConstraints(text) {
    const constraints = [];
    if (/快速|fast/i.test(text)) constraints.push('性能优先');
    if (/安全|secure/i.test(text)) constraints.push('安全优先');
    return constraints;
  }
  
  createPRD(context) {
    const requirements = context.requirements || context;
    
    return {
      title: `${requirements.raw_input || '项目'} 产品需求文档`,
      features: requirements.features || [],
      constraints: requirements.constraints || [],
      created_at: new Date().toISOString(),
      sections: ['背景与目标', '用户画像', '功能列表', '非功能需求', '验收标准']
    };
  }
}

class Architect extends Role {
  constructor(roleId = 'architect') {
    super(roleId, '架构师', RoleType.ARCHITECT, ['架构设计', '系统设计', '技术选型', '性能优化']);
  }
  
  _initActions() {
    this.addAction('design_system', '设计系统架构', ['requirements'], 'design');
    this.addAction('select_tech_stack', '技术选型', ['requirements', 'constraints'], 'tech_stack');
    this.addAction('review_architecture', '架构评审', ['design'], 'review_comments');
  }
  
  designSystem(context) {
    const requirements = context.requirements || context;
    const features = requirements.features || [];
    
    let architecture;
    if (features.length > 5 || JSON.stringify(requirements).includes('微服务')) {
      architecture = 'microservices';
    } else if (features.length > 2) {
      architecture = 'modular_monolith';
    } else {
      architecture = 'simple';
    }
    
    return {
      architecture,
      components: this._designComponents(features),
      tech_stack: this._recommendStack(architecture),
      diagrams: ['系统架构图', '数据流图', '部署图'],
      created_at: new Date().toISOString()
    };
  }
  
  _designComponents(features) {
    return features.map(feat => ({
      name: feat,
      type: ['支付', '搜索'].includes(feat) ? 'service' : 'module',
      dependencies: []
    }));
  }
  
  _recommendStack(architecture) {
    const stacks = {
      microservices: {
        backend: 'Python + FastAPI',
        frontend: 'React',
        database: 'PostgreSQL + Redis',
        message_queue: 'RabbitMQ'
      },
      modular_monolith: {
        backend: 'Python + Django',
        frontend: 'Vue',
        database: 'PostgreSQL'
      },
      simple: {
        backend: 'Python + Flask',
        frontend: '简单 HTML/JS',
        database: 'SQLite'
      }
    };
    return stacks[architecture] || stacks.simple;
  }
}

class Engineer extends Role {
  constructor(roleId = 'engineer', name = '工程师') {
    super(roleId, name, RoleType.ENGINEER, ['Python', 'JavaScript', '代码实现', '单元测试']);
  }
  
  _initActions() {
    this.addAction('implement', '实现功能', ['design'], 'code');
    this.addAction('write_tests', '编写测试', ['code'], 'tests');
    this.addAction('code_review', '代码审查', ['code'], 'review_comments');
  }
  
  implement(context) {
    const design = context.design || context;
    
    return {
      files: this._generateFiles(design),
      language: design.tech_stack?.backend?.includes('Python') ? 'python' : 'javascript',
      created_at: new Date().toISOString()
    };
  }
  
  _generateFiles(design) {
    const files = [];
    const architecture = design.architecture || 'simple';
    
    if (architecture === 'simple' || architecture === 'modular_monolith') {
      files.push({
        path: 'app.py',
        content: '# Main application file\nimport flask\napp = flask.Flask(__name__)\n\n@app.route("/")\ndef index():\n    return "Hello World"\n\nif __name__ == "__main__":\n    app.run(debug=True)\n'
      });
    }
    
    return files;
  }
}

class QA extends Role {
  constructor(roleId = 'qa') {
    super(roleId, '测试工程师', RoleType.QA, ['测试用例设计', '缺陷跟踪', '自动化测试', '性能测试']);
  }
  
  _initActions() {
    this.addAction('design_tests', '设计测试用例', ['requirements', 'design'], 'test_cases');
    this.addAction('execute_tests', '执行测试', ['code', 'test_cases'], 'test_results');
  }
  
  designTests(context) {
    const requirements = context.requirements || {};
    const features = requirements.features || [];
    
    const testCases = features.map(feature => ({
      feature,
      cases: [
        { scenario: '正常流程', expected: '成功' },
        { scenario: '异常输入', expected: '错误处理' }
      ]
    }));
    
    return { test_cases: testCases, created_at: new Date().toISOString() };
  }
}

class DevOps extends Role {
  constructor(roleId = 'devops') {
    super(roleId, 'DevOps 工程师', RoleType.DEVOPS, ['CI/CD', '容器化', '监控', '部署']);
  }
  
  _initActions() {
    this.addAction('setup_ci_cd', '配置 CI/CD', ['repo'], 'ci_cd_config');
    this.addAction('create_dockerfile', '创建 Dockerfile', [], 'dockerfile');
    this.addAction('deploy', '部署应用', ['environment'], 'deployment_info');
  }
  
  setupCI(repo) {
    return {
      pipeline: 'GitHub Actions',
      stages: ['test', 'build', 'deploy'],
      created_at: new Date().toISOString()
    };
  }
}

function createRoleFactory() {
  return {
    ProductManager,
    Architect,
    Engineer,
    QA,
    DevOps,
    create(roleType, roleId) {
      switch (roleType) {
        case RoleType.PM:
          return new ProductManager(roleId);
        case RoleType.ARCHITECT:
          return new Architect(roleId);
        case RoleType.ENGINEER:
          return new Engineer(roleId);
        case RoleType.QA:
          return new QA(roleId);
        case RoleType.DEVOPS:
          return new DevOps(roleId);
        default:
          return new Engineer(roleId);
      }
    }
  };
}

// ========== Main Agent ==========

class Agent {
  constructor({
    llmProvider = 'openai',
    llmModel = null,
    outputDir = './output',
    useMemory = true,
    useSandbox = true,
    verbose = false
  } = {}) {
    this.roles = {
      pm: new ProductManager(),
      architect: new Architect(),
      engineer: new Engineer(),
      qa: new QA(),
      devops: new DevOps()
    };
    
    this.outputDir = outputDir;
    this.verbose = verbose;
    
    // Memory system - simplified integration
    this.memory = null;
    this.useMemory = useMemory;
    
    // Workflow engine
    this.workflowEngine = null;
    if (WorkflowEngine) {
      try {
        this.workflowEngine = new WorkflowEngine();
      } catch (e) {
        // Workflow engine not available
      }
    }
  }
  
  async run(description, projectType = 'fastapi', projectName = null) {
    // Project name
    if (!projectName) {
      projectName = this._extractProjectName(description);
    }
    
    this._printHeader(description, projectType, projectName);
    
    const result = {
      description,
      project_type: projectType,
      project_name: projectName,
      output_dir: this.outputDir,
      steps: {},
      files: [],
      success: true,
      error: null,
      timestamp: new Date().toISOString(),
      memory_used: false
    };
    
    try {
      // Step 1: Analyze requirements (PM)
      if (this.verbose) console.log('\n📋 步骤 1: 需求分析 (PM)...');
      const requirements = this.roles.pm.analyzeRequirements({ user_input: description });
      result.steps.requirements = requirements;
      
      // Step 2: System design (Architect)
      if (this.verbose) console.log('\n🏗️ 步骤 2: 系统设计 (架构师)...');
      const design = this.roles.architect.designSystem({ requirements });
      result.steps.design = design;
      
      // Step 3: Implementation (Engineer)
      if (this.verbose) console.log('\n💻 步骤 3: 代码实现 (工程师)...');
      const implementation = this.roles.engineer.implement({ design });
      result.steps.implementation = implementation;
      result.files = implementation.files || [];
      
      // Step 4: Testing (QA)
      if (this.verbose) console.log('\n🧪 步骤 4: 测试设计 (QA)...');
      const tests = this.roles.qa.designTests({ requirements, design });
      result.steps.tests = tests;
      
      // Step 5: DevOps setup
      if (this.verbose) console.log('\n🚀 步骤 5: DevOps 配置...');
      const devops = this.roles.devops.setupCI(projectName);
      result.steps.devops = devops;
      
      console.log('\n✅ 项目生成完成!');
      console.log(`📁 输出目录: ${this.outputDir}`);
      console.log(`📝 生成文件: ${result.files.length} 个`);
      
    } catch (error) {
      result.success = false;
      result.error = error.message;
      console.error(`\n❌ 项目生成失败: ${error.message}`);
    }
    
    return result;
  }
  
  _extractProjectName(description) {
    // Simple extraction - first meaningful phrase
    const words = description.split(/\s+/).slice(0, 3);
    return words.join('_').replace(/[^a-zA-Z0-9_\u4e00-\u9fff]/g, '').toLowerCase() || 'project';
  }
  
  _printHeader(description, projectType, projectName) {
    console.log('\n' + '='.repeat(60));
    console.log('🤖 Agent - 统一工作流引擎');
    console.log('='.repeat(60));
    console.log(`\n📝 描述: ${description}`);
    console.log(`🏷️  类型: ${projectType}`);
    console.log(`📦 项目: ${projectName}`);
    console.log();
  }
  
  chat() {
    console.log('\n💬 进入对话模式 (按 Ctrl+C 退出)');
    console.log('提示: 输入您的需求，系统会自动选择合适的角色处理\n');
    
    // Simple REPL
    const readline = require('readline');
    const rl = readline.createInterface({
      input: process.stdin,
      output: process.stdout
    });
    
    const prompt = () => {
      rl.question('\n👤 您: ', async (input) => {
        if (input.toLowerCase() === 'exit') {
          rl.close();
          return;
        }
        
        try {
          const result = await this.run(input);
          console.log('\n📤 Agent:', JSON.stringify(result, null, 2));
        } catch (e) {
          console.error('错误:', e.message);
        }
        
        prompt();
      });
    };
    
    prompt();
  }
}

// ========== CLI ==========

async function main() {
  const args = process.argv.slice(2);
  const command = args[0];
  
  if (!command || command === 'help') {
    console.log(`
Agent - 统一入口（记忆系统 + 工作流引擎）

Usage:
    node agent.js "开发一个博客系统"
    node agent.js "开发 API" --type fastapi
    node agent.js chat
    node agent.js history --task <task_id>
    node agent.js --help
`);
    process.exit(1);
  }
  
  if (command === 'chat') {
    const agent = new Agent({ verbose: true });
    agent.chat();
    return;
  }
  
  if (command === 'history') {
    const taskIdx = args.indexOf('--task');
    if (taskIdx !== -1) {
      console.log(`查看任务历史: ${args[taskIdx + 1]}`);
      // Would load from memory system
    }
    return;
  }
  
  // Run project generation
  const typeIdx = args.indexOf('--type');
  const llmIdx = args.indexOf('--llm');
  
  const description = args[0];
  const projectType = typeIdx !== -1 ? args[typeIdx + 1] : 'fastapi';
  const llmProvider = llmIdx !== -1 ? args[llmIdx + 1] : 'openai';
  
  const agent = new Agent({ llmProvider, verbose: true });
  await agent.run(description, projectType);
}

// Run if executed directly
if (import.meta.url === `file://${process.argv[1]}`) {
  main().catch(console.error);
}

export {
  Agent,
  Role,
  RoleType,
  ProductManager,
  Architect,
  Engineer,
  QA,
  DevOps,
  createRoleFactory
};

export default Agent;
/**
 * Agent Collaboration System v3.1 - 多Agent协作系统
 * 
 * Features:
 * - Agent registration & management
 * - Task assignment & tracking
 * - Dynamic role assignment
 * - Conflict detection & resolution
 * - Collab Bus for inter-agent communication
 * - Decision engine
 * 
 * Usage:
 *   node agent_collab_system.js register --id "agent_pm" --name "产品经理" --role "pm" --skills "需求分析,产品设计"
 *   node agent_collab_system.js list
 *   node agent_collab_system.js add-task --id "task_001" --type "development" --desc "开发用户系统"
 *   node agent_collab_system.js assign --task "task_001" --agent "agent_engineer"
 *   node agent_collab_system.js stats
 */

import fs from 'fs/promises';
import path from 'path';
import { fileURLToPath } from 'url';
import os from 'os';
import crypto from 'crypto';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// ========== Configuration ==========

const WORKSPACE = path.join(os.homedir(), '.openclaw', 'workspace');
const MEMORY_DIR = path.join(WORKSPACE, 'memory');
const COLLAB_DIR = path.join(MEMORY_DIR, 'collaboration');

const AGENTS_FILE = path.join(COLLAB_DIR, 'agent_profiles.json');
const TASKS_FILE = path.join(COLLAB_DIR, 'tasks.json');
const CONFLICTS_FILE = path.join(COLLAB_DIR, 'conflicts.json');
const EVENTS_FILE = path.join(COLLAB_DIR, 'events.jsonl');

// ========== Enums ==========

const AgentStatus = {
  ONLINE: 'online',
  BUSY: 'busy',
  OFFLINE: 'offline'
};

const TaskStatus = {
  PENDING: 'pending',
  ASSIGNED: 'assigned',
  IN_PROGRESS: 'in_progress',
  COMPLETED: 'completed',
  FAILED: 'failed'
};

const ConflictType = {
  REQUIREMENT: 'requirement',
  DESIGN: 'design',
  CODE: 'code',
  RESOURCE: 'resource'
};

const ConflictSeverity = {
  LOW: 'low',
  MEDIUM: 'medium',
  HIGH: 'high',
  CRITICAL: 'critical'
};

// ========== Data Classes ==========

class Agent {
  constructor({
    agentId,
    name,
    role,
    skills = [],
    expertise = [],
    workload = 0.0,
    status = AgentStatus.ONLINE,
    registeredAt = new Date().toISOString(),
    lastActive = new Date().toISOString(),
    completedTasks = 0,
    successRate = 1.0
  }) {
    this.agentId = agentId;
    this.name = name;
    this.role = role;
    this.skills = skills;
    this.expertise = expertise;
    this.workload = workload;
    this.status = status;
    this.registeredAt = registeredAt;
    this.lastActive = lastActive;
    this.completedTasks = completedTasks;
    this.successRate = successRate;
  }
  
  toDict() {
    return {
      agentId: this.agentId,
      name: this.name,
      role: this.role,
      skills: this.skills,
      expertise: this.expertise,
      workload: this.workload,
      status: this.status,
      registeredAt: this.registeredAt,
      lastActive: this.lastActive,
      completedTasks: this.completedTasks,
      successRate: this.successRate
    };
  }
  
  static fromDict(d) {
    return new Agent(d);
  }
}

class Task {
  constructor({
    taskId,
    taskType,
    description,
    requiredSkills = [],
    priority = 'normal',
    status = TaskStatus.PENDING,
    assignedTo = null,
    createdAt = new Date().toISOString(),
    updatedAt = new Date().toISOString(),
    completedAt = null,
    result = null
  }) {
    this.taskId = taskId;
    this.taskType = taskType;
    this.description = description;
    this.requiredSkills = requiredSkills;
    this.priority = priority;
    this.status = status;
    this.assignedTo = assignedTo;
    this.createdAt = createdAt;
    this.updatedAt = updatedAt;
    this.completedAt = completedAt;
    this.result = result;
  }
  
  toDict() {
    return {
      taskId: this.taskId,
      taskType: this.taskType,
      description: this.description,
      requiredSkills: this.requiredSkills,
      priority: this.priority,
      status: this.status,
      assignedTo: this.assignedTo,
      createdAt: this.createdAt,
      updatedAt: this.updatedAt,
      completedAt: this.completedAt,
      result: this.result
    };
  }
  
  static fromDict(d) {
    return new Task(d);
  }
}

class Conflict {
  constructor({
    conflictId,
    conflictType,
    severity,
    description,
    parties = [],
    detectedAt = new Date().toISOString(),
    resolved = false,
    resolution = null,
    resolvedAt = null
  }) {
    this.conflictId = conflictId;
    this.conflictType = conflictType;
    this.severity = severity;
    this.description = description;
    this.parties = parties;
    this.detectedAt = detectedAt;
    this.resolved = resolved;
    this.resolution = resolution;
    this.resolvedAt = resolvedAt;
  }
  
  toDict() {
    return {
      conflictId: this.conflictId,
      conflictType: this.conflictType,
      severity: this.severity,
      description: this.description,
      parties: this.parties,
      detectedAt: this.detectedAt,
      resolved: this.resolved,
      resolution: this.resolution,
      resolvedAt: this.resolvedAt
    };
  }
  
  static fromDict(d) {
    return new Conflict(d);
  }
}

// ========== Main System ==========

class AgentCollaborationSystem {
  constructor() {
    this._ensureDirs();
    this.agents = {};
    this.tasks = {};
    this.conflicts = [];
    this._loadAgents();
    this._loadTasks();
    this._loadConflicts();
    
    console.log(`✅ Agent 协作系统 v3.1 已初始化 (${Object.keys(this.agents).length} 个 Agent)`);
  }
  
  _ensureDirs() {
    fs.mkdir(COLLAB_DIR, { recursive: true });
  }
  
  async _loadAgents() {
    try {
      if (await fileExists(AGENTS_FILE)) {
        const data = JSON.parse(await fs.readFile(AGENTS_FILE, 'utf-8'));
        this.agents = Object.fromEntries(
          Object.entries(data).map(([k, v]) => [k, Agent.fromDict(v)])
        );
      }
    } catch (e) {
      this.agents = {};
    }
  }
  
  async _saveAgents() {
    const data = Object.fromEntries(
      Object.entries(this.agents).map(([k, v]) => [k, v.toDict()])
    );
    await fs.writeFile(AGENTS_FILE, JSON.stringify(data, null, 2), 'utf-8');
  }
  
  async _loadTasks() {
    try {
      if (await fileExists(TASKS_FILE)) {
        const data = JSON.parse(await fs.readFile(TASKS_FILE, 'utf-8'));
        this.tasks = Object.fromEntries(
          Object.entries(data).map(([k, v]) => [k, Task.fromDict(v)])
        );
      }
    } catch (e) {
      this.tasks = {};
    }
  }
  
  async _saveTasks() {
    const data = Object.fromEntries(
      Object.entries(this.tasks).map(([k, v]) => [k, v.toDict()])
    );
    await fs.writeFile(TASKS_FILE, JSON.stringify(data, null, 2), 'utf-8');
  }
  
  async _loadConflicts() {
    try {
      if (await fileExists(CONFLICTS_FILE)) {
        const data = JSON.parse(await fs.readFile(CONFLICTS_FILE, 'utf-8'));
        this.conflicts = data.map(c => Conflict.fromDict(c));
      }
    } catch (e) {
      this.conflicts = [];
    }
  }
  
  async _saveConflicts() {
    const data = this.conflicts.map(c => c.toDict());
    await fs.writeFile(CONFLICTS_FILE, JSON.stringify(data, null, 2), 'utf-8');
  }
  
  async _logEvent(eventType, data) {
    const event = {
      timestamp: new Date().toISOString(),
      event_type: eventType,
      ...data
    };
    await fs.appendFile(EVENTS_FILE, JSON.stringify(event) + '\n', 'utf-8');
  }
  
  // ===== Agent Management =====
  
  async registerAgent(agentId, name, role, skills, expertise = []) {
    const now = new Date().toISOString();
    const agent = new Agent({
      agentId,
      name,
      role,
      skills: Array.isArray(skills) ? skills : skills.split(',').map(s => s.trim()),
      expertise,
      workload: 0.0,
      status: AgentStatus.ONLINE,
      registeredAt: now,
      lastActive: now
    });
    
    this.agents[agentId] = agent;
    await this._saveAgents();
    await this._logEvent('agent_registered', { agentId, name, role });
    
    console.log(`✅ Agent 注册: ${name} (${agentId})`);
    return agent;
  }
  
  getAgent(agentId) {
    return this.agents[agentId] || null;
  }
  
  listAgents() {
    return Object.values(this.agents);
  }
  
  // ===== Task Management =====
  
  async addTask(taskId, taskType, description, requiredSkills = [], priority = 'normal') {
    const now = new Date().toISOString();
    const task = new Task({
      taskId,
      taskType,
      description,
      requiredSkills: Array.isArray(requiredSkills) ? requiredSkills : requiredSkills.split(',').map(s => s.trim()),
      priority,
      status: TaskStatus.PENDING,
      assignedTo: null,
      createdAt: now,
      updatedAt: now
    });
    
    this.tasks[taskId] = task;
    await this._saveTasks();
    await this._logEvent('task_created', { taskId, taskType });
    
    console.log(`✅ 任务创建: ${taskId} (${taskType})`);
    return task;
  }
  
  async assignTask(taskId, agentId) {
    if (!(taskId in this.tasks) || !(agentId in this.agents)) {
      return false;
    }
    
    const task = this.tasks[taskId];
    const agent = this.agents[agentId];
    
    task.assignedTo = agentId;
    task.status = TaskStatus.ASSIGNED;
    task.updatedAt = new Date().toISOString();
    
    agent.workload = Math.min(1.0, agent.workload + 0.2);
    agent.status = AgentStatus.BUSY;
    
    await this._saveTasks();
    await this._saveAgents();
    await this._logEvent('task_assigned', { taskId, agentId });
    
    console.log(`✅ 任务分配: ${taskId} → ${agent.name}`);
    return true;
  }
  
  async completeTask(taskId, result = null) {
    if (!(taskId in this.tasks)) return;
    
    const task = this.tasks[taskId];
    task.status = TaskStatus.COMPLETED;
    task.result = result;
    task.completedAt = new Date().toISOString();
    task.updatedAt = task.completedAt;
    
    if (task.assignedTo && task.assignedTo in this.agents) {
      const agent = this.agents[task.assignedTo];
      agent.workload = Math.max(0.0, agent.workload - 0.2);
      agent.completedTasks++;
      if (agent.workload < 0.3) {
        agent.status = AgentStatus.ONLINE;
      }
    }
    
    await this._saveTasks();
    await this._saveAgents();
    await this._logEvent('task_completed', { taskId });
    
    console.log(`✅ 任务完成: ${taskId}`);
  }
  
  listTasks(status = null) {
    let tasks = Object.values(this.tasks);
    if (status) {
      tasks = tasks.filter(t => t.status === status);
    }
    return tasks;
  }
  
  // ===== Dynamic Role Assignment =====
  
  recommendAgent(taskType, requiredSkills, strategy = 'skill_match') {
    const candidates = [];
    
    for (const agent of Object.values(this.agents)) {
      if (agent.status === AgentStatus.OFFLINE) continue;
      
      let score;
      if (strategy === 'skill_match') {
        score = requiredSkills.filter(s => agent.skills.includes(s)).length / Math.max(requiredSkills.length, 1);
      } else if (strategy === 'workload_balance') {
        score = 1.0 - agent.workload;
      } else {
        // hybrid
        const skillScore = requiredSkills.filter(s => agent.skills.includes(s)).length / Math.max(requiredSkills.length, 1);
        const workloadScore = 1.0 - agent.workload;
        score = skillScore * 0.7 + workloadScore * 0.3;
      }
      
      candidates.push([agent, score]);
    }
    
    candidates.sort((a, b) => b[1] - a[1]);
    return candidates;
  }
  
  // ===== Conflict Detection =====
  
  detectConflicts() {
    const newConflicts = [];
    
    // Resource conflict detection
    for (const agent of Object.values(this.agents)) {
      if (agent.workload > 0.9) {
        const conflict = new Conflict({
          conflictId: `conf_${new Date().toISOString().replace(/[-:T]/g, '').slice(0, 14)}_${agent.agentId.slice(0, 6)}`,
          conflictType: ConflictType.RESOURCE,
          severity: ConflictSeverity.HIGH,
          description: `Agent ${agent.name} 负载过高: ${(agent.workload * 100).toFixed(0)}%`,
          parties: [agent.agentId]
        });
        newConflicts.push(conflict);
      }
    }
    
    this.conflicts.push(...newConflicts);
    return this.conflicts;
  }
  
  resolveConflict(conflictId, resolution) {
    const conflict = this.conflicts.find(c => c.conflictId === conflictId);
    if (!conflict) return false;
    
    conflict.resolved = true;
    conflict.resolution = resolution;
    conflict.resolvedAt = new Date().toISOString();
    
    return true;
  }
  
  // ===== Broadcast & Events =====
  
  async broadcast(fromAgent, eventType, data = {}) {
    await this._logEvent('broadcast', { from_agent: fromAgent, event_type: eventType, data });
    console.log(`📢 广播: ${fromAgent} -> ${eventType}`);
  }
  
  async makeDecision(context, options, criteria, weights = null) {
    // Simple weighted decision
    const scores = options.map(option => {
      let score = 0;
      criteria.forEach((criterion, i) => {
        const weight = weights ? weights[criterion] || 1 : 1;
        // Simple heuristic scoring
        const optionScore = option.toLowerCase().includes(criterion.toLowerCase()) ? 1 : 0.5;
        score += optionScore * weight;
      });
      return score;
    });
    
    const winner = options[scores.indexOf(Math.max(...scores))];
    
    return {
      context,
      winner,
      scores: Object.fromEntries(options.map((o, i) => [o, scores[i]])),
      timestamp: new Date().toISOString()
    };
  }
  
  // ===== Statistics =====
  
  getStats() {
    const agentStats = Object.values(this.agents).map(a => ({
      name: a.name,
      workload: (a.workload * 100).toFixed(0) + '%',
      completed: a.completedTasks,
      successRate: (a.successRate * 100).toFixed(0) + '%'
    }));
    
    const taskStats = {
      total: Object.keys(this.tasks).length,
      pending: Object.values(this.tasks).filter(t => t.status === TaskStatus.PENDING).length,
      in_progress: Object.values(this.tasks).filter(t => t.status === TaskStatus.IN_PROGRESS).length,
      completed: Object.values(this.tasks).filter(t => t.status === TaskStatus.COMPLETED).length
    };
    
    return {
      agents: agentStats,
      tasks: taskStats,
      conflicts: {
        total: this.conflicts.length,
        unresolved: this.conflicts.filter(c => !c.resolved).length
      }
    };
  }
}

// ========== Utilities ==========

async function fileExists(filePath) {
  try {
    await fs.access(filePath);
    return true;
  } catch {
    return false;
  }
}

// ========== CLI ==========

async function main() {
  const args = process.argv.slice(2);
  const command = args[0];
  
  if (!command) {
    console.log(`
Agent Collaboration System v3.1

Usage:
    node agent_collab_system.js register --id "agent_pm" --name "产品经理" --role "pm" --skills "需求分析,产品设计"
    node agent_collab_system.js list
    node agent_collab_system.js status --id "agent_pm"
    node agent_collab_system.js add-task --id "task_001" --type "development" --desc "开发用户系统"
    node agent_collab_system.js assign --task "task_001" --agent "agent_engineer"
    node agent_collab_system.js complete --task "task_001" --result "完成"
    node agent_collab_system.js recommend --task-type "development" --skills "Python,API"
    node agent_collab_system.js stats
`);
    process.exit(1);
  }
  
  const system = new AgentCollaborationSystem();
  
  switch (command) {
    case 'register': {
      const idIdx = args.indexOf('--id');
      const nameIdx = args.indexOf('--name');
      const roleIdx = args.indexOf('--role');
      const skillsIdx = args.indexOf('--skills');
      
      const id = idIdx !== -1 ? args[idIdx + 1] : null;
      const name = nameIdx !== -1 ? args[nameIdx + 1] : null;
      const role = roleIdx !== -1 ? args[roleIdx + 1] : null;
      const skills = skillsIdx !== -1 ? args[skillsIdx + 1] : '';
      
      if (!id || !name || !role) {
        console.log('❌ 请提供 --id, --name, --role 参数');
        process.exit(1);
      }
      
      await system.registerAgent(id, name, role, skills);
      break;
    }
    
    case 'list': {
      const agents = system.listAgents();
      console.log(`\n👥 Agent 列表 (${agents.length}):\n`);
      for (const agent of agents) {
        console.log(`  [${agent.agentId}] ${agent.name} (${agent.role})`);
        console.log(`    技能: ${agent.skills.join(', ')}`);
        console.log(`    负载: ${(agent.workload * 100).toFixed(0)}% | 状态: ${agent.status}`);
        console.log();
      }
      break;
    }
    
    case 'status': {
      const idIdx = args.indexOf('--id');
      if (idIdx === -1) {
        console.log('❌ 请提供 --id 参数');
        process.exit(1);
      }
      
      const agent = system.getAgent(args[idIdx + 1]);
      if (!agent) {
        console.log('❌ Agent 不存在');
        process.exit(1);
      }
      
      console.log(`\n👤 Agent: ${agent.name}`);
      console.log(`   ID: ${agent.agentId}`);
      console.log(`   角色: ${agent.role}`);
      console.log(`   技能: ${agent.skills.join(', ')}`);
      console.log(`   负载: ${(agent.workload * 100).toFixed(0)}%`);
      console.log(`   状态: ${agent.status}`);
      console.log(`   已完成任务: ${agent.completedTasks}`);
      console.log(`   成功率: ${(agent.successRate * 100).toFixed(0)}%`);
      break;
    }
    
    case 'add-task': {
      const idIdx = args.indexOf('--id');
      const typeIdx = args.indexOf('--type');
      const descIdx = args.indexOf('--desc');
      const skillsIdx = args.indexOf('--skills');
      
      const id = idIdx !== -1 ? args[idIdx + 1] : `task_${Date.now()}`;
      const type = typeIdx !== -1 ? args[typeIdx + 1] : 'general';
      const desc = descIdx !== -1 ? args[descIdx + 1] : '';
      const skills = skillsIdx !== -1 ? args[skillsIdx + 1] : '';
      
      await system.addTask(id, type, desc, skills);
      break;
    }
    
    case 'assign': {
      const taskIdx = args.indexOf('--task');
      const agentIdx = args.indexOf('--agent');
      
      if (taskIdx === -1 || agentIdx === -1) {
        console.log('❌ 请提供 --task 和 --agent 参数');
        process.exit(1);
      }
      
      const success = await system.assignTask(args[taskIdx + 1], args[agentIdx + 1]);
      if (!success) {
        console.log('❌ 分配失败');
      }
      break;
    }
    
    case 'complete': {
      const taskIdx = args.indexOf('--task');
      const resultIdx = args.indexOf('--result');
      
      if (taskIdx === -1) {
        console.log('❌ 请提供 --task 参数');
        process.exit(1);
      }
      
      let result = {};
      if (resultIdx !== -1) {
        try {
          result = JSON.parse(args[resultIdx + 1]);
        } catch {}
      }
      
      await system.completeTask(args[taskIdx + 1], result);
      break;
    }
    
    case 'recommend': {
      const typeIdx = args.indexOf('--task-type');
      const skillsIdx = args.indexOf('--skills');
      const strategyIdx = args.indexOf('--strategy');
      
      const taskType = typeIdx !== -1 ? args[typeIdx + 1] : 'general';
      const skills = skillsIdx !== -1 ? args[skillsIdx + 1].split(',').map(s => s.trim()) : [];
      const strategy = strategyIdx !== -1 ? args[strategyIdx + 1] : 'skill_match';
      
      const candidates = system.recommendAgent(taskType, skills, strategy);
      console.log('\n🎯 推荐 Agent:\n');
      for (const [agent, score] of candidates.slice(0, 5)) {
        console.log(`  ${agent.name}: ${(score * 100).toFixed(0)}% 匹配`);
      }
      break;
    }
    
    case 'stats':
      console.log('\n📊 统计:\n');
      console.log(JSON.stringify(system.getStats(), null, 2));
      break;
    
    default:
      console.log(`❌ 未知命令: ${command}`);
      process.exit(1);
  }
}

// Run if executed directly
if (import.meta.url === `file://${process.argv[1]}`) {
  main().catch(console.error);
}

export {
  Agent,
  Task,
  Conflict,
  AgentStatus,
  TaskStatus,
  ConflictType,
  ConflictSeverity,
  AgentCollaborationSystem
};

export default AgentCollaborationSystem;
/**
 * Agent Memory - AI Agent 专用记忆系统 v4.0
 * 
 * Core Features:
 * - Auto extraction from conversations (using LLM)
 * - Context summary generation
 * - User profile maintenance (USER_MODEL.md)
 * - Agent self-awareness (AGENT_SELF.md)
 * - Capability boundary recording
 * 
 * Usage:
 *   node agent_memory.js extract --conversation "对话内容"
 *   node agent_memory.js context --query "当前任务"
 *   node agent_memory.js update-user
 *   node agent_memory.js learn --type success|failure --content "内容"
 *   node agent_memory.js status
 */

import fs from 'fs/promises';
import path from 'path';
import { fileURLToPath } from 'url';
import os from 'os';
import http from 'http';
import crypto from 'crypto';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// ========== Configuration ==========

const WORKSPACE = path.join(os.homedir(), '.openclaw', 'workspace');
const MEMORY_DIR = path.join(WORKSPACE, 'memory');
const ONTOLOGY_DIR = path.join(MEMORY_DIR, 'ontology');
const VECTOR_DB_DIR = path.join(MEMORY_DIR, 'vector');

const USER_MODEL_FILE = path.join(WORKSPACE, 'USER_MODEL.md');
const AGENT_SELF_FILE = path.join(WORKSPACE, 'AGENT_SELF.md');
const MEMORY_FILE = path.join(WORKSPACE, 'MEMORY.md');

const OLLAMA_URL = process.env.OLLAMA_HOST || 'http://localhost:11434';
const OLLAMA_EMBED_MODEL = process.env.OLLAMA_EMBED_MODEL || 'nomic-embed-text:latest';
const OLLAMA_LLM_MODEL = process.env.OLLAMA_LLM_MODEL || 'deepseek-v3.2:cloud';

// Ensure directories exist
await fs.mkdir(MEMORY_DIR, { recursive: true });
await fs.mkdir(ONTOLOGY_DIR, { recursive: true });
await fs.mkdir(VECTOR_DB_DIR, { recursive: true });

// ========== Memory Categories ==========

const MEMORY_CATEGORIES = {
  profile: '用户身份属性 (姓名、职业、位置等)',
  preferences: '用户偏好习惯 (喜欢/不喜欢、习惯做法)',
  entities: '持续存在的实体 (项目、设备、账号)',
  events: '发生的事件 (会议、完成任务、发生的事)',
  cases: '问题-解决方案对 (遇到什么问题、怎么解决的)',
  patterns: '可复用的处理流程 (做事方法)'
};

const ALWAYS_MERGE = new Set(['profile']);
const MERGE_SUPPORTED = new Set(['preferences', 'entities', 'patterns']);
const APPEND_ONLY = new Set(['events', 'cases']);

// ========== LLM Calls ==========

async function callLLM(prompt, model = null) {
  try {
    const result = await new Promise((resolve, reject) => {
      const req = http.request(
        `${OLLAMA_URL}/api/generate`,
        { method: 'POST', timeout: 60000 },
        (res) => {
          let data = '';
          res.on('data', chunk => data += chunk);
          res.on('end', () => {
            try {
              resolve(JSON.parse(data));
            } catch {
              reject(new Error('Invalid JSON response'));
            }
          });
        }
      );
      req.on('error', reject);
      req.on('timeout', () => reject(new Error('Request timeout')));
      req.write(JSON.stringify({
        model: model || OLLAMA_LLM_MODEL,
        prompt,
        stream: false,
        options: { temperature: 0.1 }
      }));
      req.end();
    });
    return result.response || null;
  } catch (e) {
    console.warn(`⚠️ LLM 调用失败: ${e.message}`);
    return null;
  }
}

async function callLLMJson(prompt, model = null) {
  const response = await callLLM(prompt, model);
  if (!response) return null;
  
  // Try direct JSON parse
  try {
    return JSON.parse(response);
  } catch {}
  
  // Try markdown code block
  const jsonMatch = response.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    try {
      return JSON.parse(jsonMatch[1]);
    } catch {}
  }
  
  // Try brace content
  const braceMatch = response.match(/\{[\s\S]*\}/);
  if (braceMatch) {
    try {
      return JSON.parse(braceMatch[0]);
    } catch {}
  }
  
  return null;
}

async function getEmbedding(text) {
  try {
    const result = await new Promise((resolve, reject) => {
      const req = http.request(
        `${OLLAMA_URL}/api/embeddings`,
        { method: 'POST', timeout: 30000 },
        (res) => {
          let data = '';
          res.on('data', chunk => data += chunk);
          res.on('end', () => {
            try {
              resolve(JSON.parse(data));
            } catch {
              reject(new Error('Invalid JSON'));
            }
          });
        }
      );
      req.on('error', reject);
      req.on('timeout', () => reject(new Error('Request timeout')));
      req.write(JSON.stringify({ model: OLLAMA_EMBED_MODEL, prompt: text }));
      req.end();
    });
    return result.embedding || null;
  } catch (e) {
    console.warn(`⚠️ Embedding 失败: ${e.message}`);
    return null;
  }
}

// ========== Auto Extraction ==========

const EXTRACTION_PROMPT = `你是一个记忆提取助手。从以下对话中提取值得记住的信息。

对话内容:
{conversation}

请提取以下类型的记忆:
1. profile - 用户身份信息 (姓名、职业、位置等)
2. preferences - 用户偏好 (喜欢/不喜欢、习惯做法)
3. entities - 重要实体 (项目名、设备、账号)
4. events - 重要事件 (会议、完成任务)
5. cases - 问题解决方案 (遇到什么问题、怎么解决的)
6. patterns - 处理模式 (可复用的方法)

返回 JSON 格式:
{
  "memories": [
    {
      "category": "preferences",
      "abstract": "一句话摘要",
      "detail": "详细说明",
      "importance": 0.7
    }
  ]
}

只提取真正有价值、对未来有用的信息。忽略寒暄、闲聊、无关细节。
`;

async function extractMemories(conversation) {
  const prompt = EXTRACTION_PROMPT.replace('{conversation}', conversation.slice(0, 4000));
  const result = await callLLMJson(prompt);
  
  if (!result || !result.memories) return [];
  return result.memories;
}

// ========== Context Generation ==========

const CONTEXT_PROMPT = `基于以下记忆，生成针对当前查询的上下文摘要。

用户画像:
{userModel}

相关记忆:
{memories}

当前查询: {query}

生成简洁的上下文摘要 (不超过 200 字)，包含:
1. 用户相关背景
2. 相关项目/任务
3. 需要注意的偏好
4. 可能相关的过去经验

只输出摘要内容，不要其他说明。
`;

async function generateContext(query, limit = 5) {
  // Load user model
  let userModel = '';
  try {
    userModel = await fs.readFile(USER_MODEL_FILE, 'utf-8');
  } catch {}
  
  // Search memories
  const memories = await searchMemories(query, limit);
  const memoriesText = memories.map(m => `- [${m.category}] ${m.text}`).join('\n');
  
  const prompt = CONTEXT_PROMPT
    .replace('{userModel}', userModel.slice(0, 1000))
    .replace('{memories}', memoriesText.slice(0, 2000))
    .replace('{query}', query);
  
  const context = await callLLM(prompt);
  return context || '无相关上下文';
}

async function searchMemories(query, limit = 5) {
  const results = [];
  
  // Vector search (simplified - would use LanceDB in production)
  const embedding = await getEmbedding(query);
  if (embedding) {
    // Would search LanceDB here
  }
  
  // Text search
  const textResults = await searchTextMemories(query, limit);
  results.push(...textResults);
  
  return results.slice(0, limit);
}

async function searchTextMemories(query, limit = 5) {
  const results = [];
  const queryLower = query.toLowerCase();
  
  try {
    const files = (await fs.readdir(MEMORY_DIR)).filter(f => f.endsWith('.md')).sort().reverse();
    
    for (const file of files) {
      const content = await fs.readFile(path.join(MEMORY_DIR, file), 'utf-8');
      const lines = content.split('\n');
      
      for (const line of lines) {
        if (line.toLowerCase().includes(queryLower)) {
          const match = line.match(/^- \[([^\]]+)\] \[([^\]]+)\] \[([^\]]+)\](?: \[I=([^\]]+)\])? (.+)$/);
          if (match) {
            const [, timestamp, category, scope, impStr, text] = match;
            results.push({
              text,
              category,
              importance: impStr ? parseFloat(impStr) : 0.5,
              source: 'text',
              file
            });
            if (results.length >= limit) break;
          }
        }
      }
      if (results.length >= limit) break;
    }
  } catch {}
  
  return results;
}

// ========== User Model Update ==========

async function updateUserModel() {
  const preferences = [];
  const entities = [];
  const profile = [];
  
  try {
    const files = await fs.readdir(MEMORY_DIR);
    
    for (const file of files) {
      if (!file.endsWith('.md')) continue;
      const content = await fs.readFile(path.join(MEMORY_DIR, file), 'utf-8');
      const lines = content.split('\n');
      
      for (const line of lines) {
        const match = line.match(/^- \[([^\]]+)\] \[([^\]]+)\].* (.+)$/);
        if (match) {
          const [, , category, text] = match;
          if (category === 'preferences') preferences.push(text);
          else if (category === 'entities') entities.push(text);
          else if (category === 'profile') profile.push(text);
        }
      }
    }
  } catch {}
  
  let content = '';
  try {
    content = await fs.readFile(USER_MODEL_FILE, 'utf-8');
  } catch {}
  
  // Update preferences section
  const prefSection = [...new Set(preferences)].map(p => `- ${p}`).join('\n');
  
  if (content.includes('## 沟通偏好')) {
    content = content.replace(
      /## 沟通偏好\n.*?(?=\n## |\n---|\Z)/s,
      `## 沟通偏好\n\n${prefSection}\n`
    );
  } else {
    content += `\n\n## 沟通偏好\n\n${prefSection}\n`;
  }
  
  await fs.writeFile(USER_MODEL_FILE, content, 'utf-8');
  return `✅ 已更新用户画像，偏好: ${[...new Set(preferences)].length} 条`;
}

// ========== Agent Learning ==========

async function recordLearning(learningType, content, context = '') {
  const today = new Date().toISOString().slice(0, 10);
  const timestamp = new Date().toISOString().slice(11, 19);
  
  const logFile = path.join(MEMORY_DIR, `${today}.md`);
  let entry = `- [${timestamp}] [learning] [${learningType}] ${content}`;
  if (context) {
    entry += ` | 上下文: ${context}`;
  }
  entry += '\n';
  
  await fs.appendFile(logFile, entry, 'utf-8');
  
  return `✅ 已记录学习: [${learningType}] ${content.slice(0, 50)}...`;
}

// ========== Memory Storage ==========

async function storeMemory(text, category = 'fact', scope = 'default', importance = null) {
  const today = new Date().toISOString().slice(0, 10);
  const timestamp = new Date().toISOString().slice(0, 19).replace('T', ' ');
  
  if (importance === null) {
    importance = scoreImportance(text, category);
  }
  
  const logFile = path.join(MEMORY_DIR, `${today}.md`);
  const entry = `- [${timestamp}] [${category}] [${scope}] [I=${importance.toFixed(2)}] ${text}\n`;
  
  await fs.appendFile(logFile, entry, 'utf-8');
  
  // Try vector storage
  let vectorStored = false;
  try {
    const embedding = await getEmbedding(text);
    if (embedding) {
      // Would store to LanceDB here
      vectorStored = true;
    }
  } catch {}
  
  let status = '✅ 已存储';
  if (vectorStored) status += ' (文本+向量)';
  else status += ' (文本)';
  
  return `${status}: ${text.slice(0, 50)}...`;
}

function scoreImportance(text, category) {
  let score = 0.5;
  const textLower = text.toLowerCase();
  
  // Category base scores
  const categoryScores = {
    decision: 0.8,
    preference: 0.7,
    entity: 0.6,
    event: 0.5,
    pattern: 0.6,
    fact: 0.4
  };
  score = categoryScores[category] || 0.5;
  
  // Keyword bonuses
  if (/决定|选择|确认/.test(text)) score += 0.1;
  if (/重要|关键/.test(text)) score += 0.1;
  if (/错误|失败|问题/.test(text)) score += 0.1;
  
  return Math.min(1.0, Math.max(0.0, score));
}

