// ========== Request Handlers ==========

async function handleListAgents() {
  const agents = await loadAgents();
  return {
    count: Object.keys(agents).length,
    agents: Object.values(agents).map(a => a.toJSON())
  };
}

async function handleGetAgent(agentId) {
  const agents = await loadAgents();
  const agent = agents[agentId];
  if (!agent) {
    return { error: 'Agent not found' }, 404;
  }
  return agent.toJSON();
}

async function handleRegisterAgent(data) {
  const agents = await loadAgents();
  const now = new Date().toISOString();
  const agent = new Agent({
    agentId: data.agent_id,
    name: data.name,
    role: data.role,
    skills: data.skills || [],
    expertise: data.expertise || [],
    status: 'online',
    registeredAt: now,
    lastActive: now
  });
  agents[agent.agentId] = agent;
  await saveAgents(agents);
  return { status: 'success', agent: agent.toJSON() };
}

async function handleListTasks(status = null) {
  const tasks = await loadTasks();
  let taskList = Object.values(tasks).map(t => t.toJSON());
  if (status) {
    taskList = taskList.filter(t => t.status === status);
  }
  return { count: taskList.length, tasks: taskList };
}

async function handleCreateTask(data) {
  const tasks = await loadTasks();
  const now = new Date().toISOString();
  const task = new Task({
    taskId: data.task_id,
    taskType: data.task_type || 'general',
    description: data.description || '',
    requiredSkills: data.required_skills || [],
    priority: data.priority || 'normal',
    status: 'pending',
    createdAt: now,
    updatedAt: now
  });
  tasks[task.taskId] = task;
  await saveTasks(tasks);
  return { status: 'success', task: task.toJSON() };
}

async function handleAssignTask(data) {
  const tasks = await loadTasks();
  const agents = await loadAgents();
  const task = tasks[data.task_id];
  if (!task) return { error: 'Task not found' }, 404;
  if (!agents[data.agent_id]) return { error: 'Agent not found' }, 404;
  
  task.status = 'assigned';
  task.assignedTo = data.agent_id;
  task.updatedAt = new Date().toISOString();
  
  await saveTasks(tasks);
  return { status: 'success' };
}

async function handleCompleteTask(data) {
  const tasks = await loadTasks();
  const task = tasks[data.task_id];
  if (!task) return { error: 'Task not found' }, 404;
  
  task.status = 'completed';
  task.result = data.result || {};
  task.completedAt = new Date().toISOString();
  task.updatedAt = task.completedAt;
  
  await saveTasks(tasks);
  return { status: 'success' };
}

async function handleStats() {
  const agents = await loadAgents();
  const tasks = await loadTasks();
  const taskList = Object.values(tasks).map(t => t.toJSON());
  
  return {
    agents: {
      total: Object.keys(agents).length,
      online: Object.values(agents).filter(a => a.status === 'online').length,
      busy: Object.values(agents).filter(a => a.status === 'busy').length
    },
    tasks: {
      total: taskList.length,
      pending: taskList.filter(t => t.status === 'pending').length,
      assigned: taskList.filter(t => t.status === 'assigned').length,
      completed: taskList.filter(t => t.status === 'completed').length
    }
  };
}

// ========== HTTP Server ==========

const PORT = parseInt(process.argv.find(a => a.startsWith('--port='))?.split('=')[1]) || 8080;

const server = http.createServer(async (req, res) => {
  const url = new URL(req.url, `http://localhost:${PORT}`);
  const path = url.pathname;
  const method = req.method;
  
  // CORS headers
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  
  if (method === 'OPTIONS') {
    res.writeHead(204);
    res.end();
    return;
  }
  
  // Set JSON content type
  res.setHeader('Content-Type', 'application/json');
  
  try {
    let body = '';
    if (['POST', 'PUT', 'PATCH'].includes(method)) {
      body = await new Promise((resolve, reject) => {
        let data = '';
        req.on('data', chunk => data += chunk);
        req.on('end', () => resolve(data));
        req.on('error', reject);
      });
    }
    
    const data = body ? JSON.parse(body) : {};
    
    // Routes
    if (path === '/' || path === '/ui') {
      res.writeHead(200, { 'Content-Type': 'text/html' });
      res.end(getDashboardHtml());
      return;
    }
    
    if (path === '/api/agents' && method === 'GET') {
      res.end(JSON.stringify(await handleListAgents()));
      return;
    }
    
    if (path === '/api/agents' && method === 'POST') {
      const result = await handleRegisterAgent(data);
      res.end(JSON.stringify(result));
      return;
    }
    
    if (path.startsWith('/api/agents/') && method === 'GET') {
      const agentId = path.split('/')[3];
      const result = await handleGetAgent(agentId);
      if (result.error) {
        res.writeHead(404);
      }
      res.end(JSON.stringify(result));
      return;
    }
    
    if (path === '/api/tasks' && method === 'GET') {
      const status = url.searchParams.get('status');
      res.end(JSON.stringify(await handleListTasks(status)));
      return;
    }
    
    if (path === '/api/tasks' && method === 'POST') {
      res.end(JSON.stringify(await handleCreateTask(data)));
      return;
    }
    
    if (path === '/api/tasks/assign' && method === 'POST') {
      const result = await handleAssignTask(data);
      res.end(JSON.stringify(result));
      return;
    }
    
    if (path === '/api/tasks/complete' && method === 'POST') {
      res.end(JSON.stringify(await handleCompleteTask(data)));
      return;
    }
    
    if (path === '/api/stats' && method === 'GET') {
      res.end(JSON.stringify(await handleStats()));
      return;
    }
    
    if (path === '/api/health' && method === 'GET') {
      res.end(JSON.stringify({ status: 'healthy', timestamp: new Date().toISOString() }));
      return;
    }
    
    // 404
    res.writeHead(404);
    res.end(JSON.stringify({ error: 'Not found' }));
    
  } catch (error) {
    console.error('Request error:', error);
    res.writeHead(500);
    res.end(JSON.stringify({ error: error.message }));
  }
});

server.listen(PORT, () => {
  console.log(`
🚀 REST API Server started
   Port: ${PORT}
   URL:  http://localhost:${PORT}
   UI:   http://localhost:${PORT}/ui
   API:  http://localhost:${PORT}/docs
`);
});

export { server };
export default server;
/**
 * routes.js - API Router
 * Route definitions for the memory API server
 */

import { getAllMemories, addMemory, deleteMemory } from '../storage.js';
import { hybridSearch } from '../fusion.js';
import { qmdSearch } from '../tools/qmd_search.js';
import { analyzeInsights } from '../tools/insights.js';
import { getSyncStatus } from '../backup/sync.js';
import { log } from '../utils/logger.js';

/**
 * Route definitions and handlers
 * Each route maps a path pattern to a handler function
 */
export const routes = [
  // ---- Memory CRUD ----
  {
    method: 'GET',
    path: '/memory',
    description: 'List all memories',
    handler: handleListMemories
  },
  {
    method: 'GET',
    path: '/memory/:id',
    description: 'Get a single memory by ID',
    handler: handleGetMemory
  },
  {
    method: 'POST',
    path: '/memory',
    description: 'Store a new memory',
    handler: handleStoreMemory
  },
  {
    method: 'DELETE',
    path: '/memory/:id',
    description: 'Delete a memory',
    handler: handleDeleteMemory
  },

  // ---- Search ----
  {
    method: 'GET',
    path: '/search',
    description: 'Search memories (hybrid)',
    handler: handleSearch
  },
  {
    method: 'GET',
    path: '/search/qmd',
    description: 'QMD-style search',
    handler: handleQMDSearch
  },

  // ---- Stats & Info ----
  {
    method: 'GET',
    path: '/stats',
    description: 'Get memory statistics',
    handler: handleStats
  },
  {
    method: 'GET',
    path: '/health',
    description: 'Health check',
    handler: handleHealth
  },
  {
    method: 'GET',
    path: '/insights',
    description: 'Get memory insights',
    handler: handleInsights
  },

  // ---- Sync ----
  {
    method: 'GET',
    path: '/sync/status',
    description: 'Get sync status',
    handler: handleSyncStatus
  },

  // ---- Graph ----
  {
    method: 'GET',
    path: '/graph',
    description: 'Get knowledge graph',
    handler: handleGraph
  }
];

// ---- Handlers ----

async function handleListMemories(req, params, query) {
  const limit = parseInt(query.limit || 50);
  const offset = parseInt(query.offset || 0);
  const memories = getAllMemories();
  return {
    memories: memories.slice(offset, offset + limit),
    total: memories.length,
    limit,
    offset
  };
}

async function handleGetMemory(req, params, query) {
  const { id } = params;
  const memories = getAllMemories();
  const mem = memories.find(m => m.id === id);
  if (!mem) {
    return { error: 'Memory not found' };
  }
  return { memory: mem };
}

async function handleStoreMemory(req, params, query, body) {
  if (!body || !body.text) {
    return { error: 'text is required' };
  }
  const mem = addMemory({
    text: body.text,
    category: body.category || 'general',
    importance: body.importance || 0.5,
    tags: body.tags || []
  });
  log('INFO', `Memory stored: ${mem.id}`);
  return { success: true, id: mem.id, memory: mem };
}

async function handleDeleteMemory(req, params, query) {
  const { id } = params;
  const success = deleteMemory(id);
  log('INFO', `Memory deleted: ${id}, success=${success}`);
  return { success };
}

async function handleSearch(req, params, query) {
  const q = query.q || query.query || '';
  const topK = parseInt(query.topK || query.k || 10);
  const mode = query.mode || 'hybrid';

  if (!q) {
    return { error: 'Query parameter (q) is required' };
  }

  try {
    const results = await hybridSearch(q, topK, mode);
    return {
      query: q,
      count: results.length,
      results: results.map(r => ({
        id: r.memory.id,
        text: r.memory.text,
        category: r.memory.category,
        importance: r.memory.importance,
        score: Math.round(r.fusionScore * 1000) / 1000,
        highlight: r.highlight || null
      }))
    };
  } catch (err) {
    log('ERROR', `Search error: ${err.message}`);
    return { error: err.message, results: [] };
  }
}

async function handleQMDSearch(req, params, query) {
  const q = query.q || query.query || '';
  const topK = parseInt(query.topK || query.k || 10);

  if (!q) {
    return { error: 'Query parameter (q) is required' };
  }

  try {
    const results = await qmdSearch(q, { topK });
    return {
      query: q,
      count: results.length,
      mode: 'qmd',
      results: results.map(r => ({
        id: r.id,
        text: r.text,
        category: r.category,
        score: Math.round(r.score * 1000) / 1000,
        mode: r.mode
      }))
    };
  } catch (err) {
    log('ERROR', `QMD search error: ${err.message}`);
    return { error: err.message, results: [] };
  }
}

async function handleStats(req, params, query) {
  const memories = getAllMemories();
  const categories = {};
  const tagCounts = {};
  
  for (const m of memories) {
    const cat = m.category || 'other';
    categories[cat] = (categories[cat] || 0) + 1;
    for (const tag of m.tags || []) {
      tagCounts[tag] = (tagCounts[tag] || 0) + 1;
    }
  }

  const topTags = Object.entries(tagCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 10)
    .map(([tag, count]) => ({ tag, count }));

  return {
    total: memories.length,
    categories,
    top_tags: topTags
  };
}

async function handleHealth(req, params, query) {
  let ollamaOk = false;
  try {
    const res = await fetch('http://localhost:11434/api/tags');
    ollamaOk = res.ok;
  } catch { }

  const memories = getAllMemories();

  return {
    status: 'ok',
    timestamp: new Date().toISOString(),
    memories: memories.length,
    ollama: ollamaOk ? 'connected' : 'disconnected',
    embedding_model: 'nomic-embed-text'
  };
}

async function handleInsights(req, params, query) {
  try {
    const result = await analyzeInsights();
    return JSON.parse(result.content[0].text);
  } catch (err) {
    log('ERROR', `Insights error: ${err.message}`);
    return { error: err.message };
  }
}

async function handleSyncStatus(req, params, query) {
  return getSyncStatus();
}

async function handleGraph(req, params, query) {
  // Placeholder - would call graph module
  return {
    entities: [],
    relations: [],
    node_count: 0,
    edge_count: 0
  };
}

/**
 * Parse route parameters from path
 * e.g., /memory/:id -> /memory/abc123 -> { id: 'abc123' }
 */
export function parseRouteParams(routePath, actualPath) {
  const routeParts = routePath.split('/');
  const actualParts = actualPath.split('/');
  const params = {};

  for (let i = 0; i < routeParts.length; i++) {
    if (routeParts[i].startsWith(':')) {
      const key = routeParts[i].slice(1);
      params[key] = actualParts[i] || null;
    }
  }

  return params;
}

/**
 * Match a route
 * Returns { matched: true, params: {} } or { matched: false }
 */
export function matchRoute(method, path, route) {
  if (route.method !== method) {
    return { matched: false };
  }

  const routeParts = route.path.split('/');
  const pathParts = path.split('/');

  if (routeParts.length !== pathParts.length) {
    return { matched: false };
  }

  for (let i = 0; i < routeParts.length; i++) {
    if (routeParts[i].startsWith(':')) {
      continue; // parameter, ok
    }
    if (routeParts[i] !== pathParts[i]) {
      return { matched: false };
    }
  }

  return {
    matched: true,
    params: parseRouteParams(route.path, path)
  };
}
/**
 * server.js - REST API 服务器
 * Ported from Python memory_api_server.py
 * 
 * HTTP API for memory operations
 */

import { createServer } from 'http';
import { URL } from 'url';
import { getAllMemories, addMemory, deleteMemory } from '../storage.js';
import { hybridSearch } from '../fusion.js';
import { log } from '../utils/logger.js';

const PORT = 38421;

function parseBody(req) {
  return new Promise((resolve, reject) => {
    let body = '';
    req.on('data', chunk => body += chunk);
    req.on('end', () => {
      try {
        resolve(body ? JSON.parse(body) : {});
      } catch {
        reject(new Error('Invalid JSON'));
      }
    });
    req.on('error', reject);
  });
}

function sendJSON(res, status, data) {
  res.writeHead(status, { 'Content-Type': 'application/json' });
  res.end(JSON.stringify(data));
}

async function handleRequest(req, res) {
  const url = new URL(req.url, `http://localhost:${PORT}`);
  const path = url.pathname.replace(/^\/+/, '').split('/');
  const query = Object.fromEntries(url.searchParams);

  try {
    // CORS
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') {
      res.writeHead(204);
      res.end();
      return;
    }

    const route = path[0] || '';

    // Routes
    if (route === 'memory') {
      await handleMemory(req, res, path.slice(1), query);
    } else if (route === 'search') {
      await handleSearch(req, res, query);
    } else if (route === 'stats') {
      handleStats(req, res);
    } else if (route === 'health') {
      sendJSON(res, 200, { status: 'ok', timestamp: new Date().toISOString() });
    } else if (route === '') {
      sendJSON(res, 200, { 
        name: 'unified-memory-api',
        version: '1.0.0',
        endpoints: ['/memory', '/search', '/stats', '/health']
      });
    } else {
      sendJSON(res, 404, { error: 'Not found', path: url.pathname });
    }
  } catch (err) {
    log('ERROR', `API error: ${err.message}`);
    sendJSON(res, 500, { error: err.message });
  }
}

async function handleMemory(req, res, parts, query) {
  const method = req.method;

  if (method === 'GET' && parts.length === 0) {
    // List memories
    const limit = parseInt(query.limit || 50);
    const offset = parseInt(query.offset || 0);
    const memories = getAllMemories();
    const paginated = memories.slice(offset, offset + limit);
    sendJSON(res, 200, {
      memories: paginated,
      total: memories.length,
      limit,
      offset
    });
  } else if (method === 'GET' && parts.length > 0) {
    // Get single memory
    const memId = parts[0];
    const memories = getAllMemories();
    const mem = memories.find(m => m.id === memId);
    if (mem) {
      sendJSON(res, 200, mem);
    } else {
      sendJSON(res, 404, { error: 'Memory not found' });
    }
  } else if (method === 'POST') {
    // Create memory
    const body = await parseBody(req);
    const mem = addMemory({
      text: body.text,
      category: body.category || 'general',
      importance: body.importance || 0.5,
      tags: body.tags || []
    });
    sendJSON(res, 201, { success: true, id: mem.id });
  } else if (method === 'DELETE' && parts.length > 0) {
    // Delete memory
    const memId = parts[0];
    const success = deleteMemory(memId);
    sendJSON(res, success ? 200 : 404, { success });
  } else {
    sendJSON(res, 405, { error: 'Method not allowed' });
  }
}

async function handleSearch(req, res, query) {
  const q = query.q || query.query || '';
  const topK = parseInt(query.topK || 10);
  const mode = query.mode || 'hybrid';

  if (!q) {
    sendJSON(res, 400, { error: 'Query required' });
    return;
  }

  const results = await hybridSearch(q, topK, mode);
  sendJSON(res, 200, {
    query: q,
    count: results.length,
    results: results.map(r => ({
      id: r.memory.id,
      text: r.memory.text,
      category: r.memory.category,
      importance: r.memory.importance,
      score: Math.round(r.fusionScore * 1000) / 1000
    }))
  });
}

function handleStats(req, res) {
  const memories = getAllMemories();
  const categories = {};
  for (const m of memories) {
    categories[m.category || 'other'] = (categories[m.category || 'other'] || 0) + 1;
  }
  sendJSON(res, 200, {
    total: memories.length,
    categories
  });
}

export function startServer(port = PORT) {
  const server = createServer(handleRequest);
  server.listen(port, () => {
    log('INFO', `Memory API server running on port ${port}`);
  });
  return server;
}

// CLI
if (process.argv[1] && process.argv[1].endsWith('server.js')) {
  startServer();
}
