/**
 * Proactive Recall - Anticipate what memories to recall
 */

import { readFileSync, existsSync } from 'fs';
import { join } from 'path';
import { getAllMemories } from '../storage.js';


const WORKSPACE = join(process.env.HOME || '/root', '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');

const CONTEXT_TRIGGERS = {
  project: ['项目', '开发', '代码', 'git', 'project', 'code'],
  meeting: ['会议', '讨论', 'meeting', 'discuss'],
  decision: ['决定', '选择', 'decided', 'choice'],
};

export function predictRecall(context) {
  const memories = getAllMemories();
  const contextLower = context.toLowerCase();
  const predictions = [];
  
  for (const mem of memories) {
    let relevance = 0;
    let reason = '';
    const textLower = (mem.text || '').toLowerCase();
    
    for (const [category, keywords] of Object.entries(CONTEXT_TRIGGERS)) {
      for (const keyword of keywords) {
        if (contextLower.includes(keyword) && textLower.includes(keyword)) {
          relevance += 2;
          reason = `Context keyword "${keyword}" matched`;
        }
      }
    }
    
    relevance += (mem.importance || 0.5) * 0.5;
    relevance += Math.log1p(mem.access_count || 0) * 0.3;
    
    if (relevance > 0) predictions.push({ memory: mem, relevance, reason });
  }
  
  predictions.sort((a, b) => b.relevance - a.relevance);
  return predictions.slice(0, 10);
}

export function printRecallReport(context) {
  const predictions = context ? predictRecall(context) : predictRecall('recent');
  console.log('\n🔔 Proactive Recall Predictions\n');
  console.log(`  Context: ${context || 'time-based'}`);
  console.log(`  Predictions: ${predictions.length}\n`);
  for (const pred of predictions.slice(0, 5)) {
    console.log(`  ${pred.relevance.toFixed(2)} - ${(pred.memory.text || '').substring(0, 50)}...`);
  }
  console.log('');
}

if (import.meta.url === `file://${process.argv[1]}`) {
  const args = process.argv.slice(2);
  printRecallReport(args.slice(1).join(' ') || undefined);
}
/**
 * Memory Reflection - Periodically review and consolidate memories
 */

import { readFileSync, existsSync, writeFileSync, mkdirSync } from 'fs';
import { join } from 'path';
import { getAllMemories } from '../storage.js';


const WORKSPACE = join(process.env.HOME || '/root', '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');

export function reflect(memory) {
  const insights = [];
  const text = memory.text || '';
  if (text.includes('喜欢') || text.includes('prefer')) insights.push('Expressed preference');
  if (text.includes('决定') || text.includes('decided')) insights.push('Made a decision');
  if (text.includes('项目') || text.includes('project')) insights.push('Related to project');
  
  const reflectionCount = memory.reflection_count || 0;
  let action = 'keep';
  if (reflectionCount >= 5 && (memory.importance || 0.5) < 0.3) action = 'archive';
  
  return { memoryId: memory.id || 'unknown', insights, action };
}

export function runReflectionCycle() {
  const memories = getAllMemories();
  for (const mem of memories) {
    mem.reflection_count = (mem.reflection_count || 0) + 1;
    mem.last_reflected = new Date().toISOString();
  }
  writeFileSync(join(MEMORY_DIR, 'memories.json'), JSON.stringify(memories, null, 2), 'utf-8');
  
  const results = memories.map(reflect);
  let archived = 0;
  for (const r of results) { if (r.action === 'archive') archived++; }
  
  console.log(`🪞 Reflection complete: ${memories.length} reflected, ${archived} archived`);
  return { totalReflected: memories.length, archived };
}

export function printReflectionReport() {
  const memories = getAllMemories();
  const results = memories.slice(0, 5).map(reflect);
  console.log('\n🪞 Memory Reflection Report\n');
  console.log(`  Total Memories: ${memories.length}`);
  for (const r of results.slice(0, 3)) console.log(`    [${r.memoryId}] ${r.insights.join(', ') || 'No insights'}`);
  console.log('');
}

if (require.main === module) {
  const args = process.argv.slice(2);
  if (args[0] === 'run') runReflectionCycle();
  else printReflectionReport();
}
/**
 * Memory Reminder System
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join } from 'path';

const WORKSPACE = join(process.env.HOME || '/root', '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const REMINDER_DIR = join(MEMORY_DIR, 'reminders');

function getReminderFile() {
  mkdirSync(REMINDER_DIR, { recursive: true });
  return join(REMINDER_DIR, 'reminders.json');
}

function loadReminders() {
  const file = getReminderFile();
  if (!existsSync(file)) return [];
  try { return JSON.parse(readFileSync(file, 'utf-8')); }
  catch { return []; }
}

function saveReminders(reminders) {
  writeFileSync(getReminderFile(), JSON.stringify(reminders, null, 2), 'utf-8');
}

export function createReminder(data) {
  const reminders = loadReminders();
  const reminder = {
    id: `remind_${Date.now()}_${Math.random().toString(36).substring(2, 6)}`,
    memoryId: data.memoryId,
    text: data.text,
    remindAt: data.remindAt,
    repeatInterval: data.repeatInterval,
    triggered: false,
    createdAt: new Date().toISOString(),
  };
  reminders.push(reminder);
  saveReminders(reminders);
  return reminder;
}

export function getPendingReminders() {
  const reminders = loadReminders();
  const now = new Date().toISOString();
  return reminders.filter(r => !r.triggered && r.remindAt <= now);
}

export function getAllReminders() {
  return loadReminders();
}

export function triggerReminder(id) {
  const reminders = loadReminders();
  const reminder = reminders.find(r => r.id === id);
  if (!reminder) return false;
  reminder.triggered = true;
  saveReminders(reminders);
  return true;
}

export function getReminderStats() {
  const reminders = loadReminders();
  return { total: reminders.length, pending: reminders.filter(r => !r.triggered).length, triggered: reminders.filter(r => r.triggered).length };
}

export function printReminderStatus() {
  const stats = getReminderStats();
  const pending = getPendingReminders();
  console.log('\n⏰ Memory Reminder Status\n');
  console.log(`  Total: ${stats.total}`);
  console.log(`  Pending: ${stats.pending}`);
  console.log(`  Triggered: ${stats.triggered}\n`);
  if (pending.length > 0) {
    console.log('  📋 Pending Reminders:');
    for (const r of pending.slice(0, 5)) console.log(`    - ${r.text} at ${r.remindAt}`);
  }
  console.log('');
}

if (require.main === module) {
  const args = process.argv.slice(2);
  if (args[0] === 'check') { const pending = getPendingReminders(); pending.forEach(r => triggerReminder(r.id)); console.log(`🔔 Triggered ${pending.length} reminders`); }
  else printReminderStatus();
}
/**
 * Memory Search - 增强搜索体验
 * 
 * 功能:
 * - 自然语言搜索
 * - 多维度过滤器
 * - 搜索历史
 * - 模糊匹配
 * 
 * Ported from memory_search.py
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'fs';
import { join } from 'path';
import { cosineSimilarity, getEmbedding } from '../utils/text.js';

const HOME = process.env.HOME || '/root';
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const VECTOR_DB_DIR = join(MEMORY_DIR, 'vector');
const SEARCH_HISTORY_FILE = join(MEMORY_DIR, 'search_history.json');
const OLLAMA_HOST = process.env.OLLAMA_HOST || 'http://localhost:11434';
const OLLAMA_EMBED_MODEL = process.env.OLLAMA_EMBED_MODEL || 'nomic-embed-text:latest';

// ============================================================
// Search History
// ============================================================

/**
 * @typedef {Object} SearchHistory
 * @property {Array<{query: string, timestamp: string, results: number}>} searches
 * @property {string[]} recent
 */

/**
 * Load search history from disk
 * @returns {SearchHistory}
 */
export function loadHistory() {
  if (existsSync(SEARCH_HISTORY_FILE)) {
    try {
      return JSON.parse(readFileSync(SEARCH_HISTORY_FILE, 'utf-8'));
    } catch {
      // ignore
    }
  }
  return { searches: [], recent: [] };
}

/**
 * Save search history to disk
 * @param {SearchHistory} history
 */
export function saveHistory(history) {
  try {
    mkdirSync(MEMORY_DIR, { recursive: true });
    writeFileSync(SEARCH_HISTORY_FILE, JSON.stringify(history, null, 2), 'utf-8');
  } catch (e) {
    // ignore
  }
}

/**
 * Record a search in history
 * @param {string} query
 * @param {number} resultCount
 */
export function recordSearch(query, resultCount) {
  const history = loadHistory();
  history.searches.push({
    query,
    timestamp: new Date().toISOString(),
    results: resultCount
  });
  // Keep last 50
  if (history.searches.length > 50) {
    history.searches = history.searches.slice(-50);
  }
  // Update recent
  if (!history.recent.includes(query)) {
    history.recent = [query, ...history.recent.slice(0, 9)];
  }
  saveHistory(history);
}

// ============================================================
// Core Search
// ============================================================

/**
 * Text similarity (Jaccard word overlap)
 * @param {string} query
 * @param {string} text
 * @returns {number}
 */
export function textSimilarity(query, text) {
  const queryWords = new Set(query.toLowerCase().split(/\s+/));
  const textWords = new Set(text.toLowerCase().split(/\s+/));
  if (queryWords.size === 0 || textWords.size === 0) return 0;
  const intersection = new Set([...queryWords].filter(w => textWords.has(w)));
  const union = new Set([...queryWords, ...textWords]);
  return intersection.size / union.size;
}

/**
 * Fallback keyword search
 * @param {Array} memories
 * @param {string} query
 * @param {number} k
 * @returns {Array}
 */
export function fallbackSearch(memories, query, k = 10) {
  const queryLower = query.toLowerCase();
  const results = [];

  for (const mem of memories) {
    const textLower = (mem.text || '').toLowerCase();
    let score = 0;

    // Exact contains
    if (textLower.includes(queryLower)) {
      score = 1.0;
    } else {
      const queryWords = new Set(queryLower.split(/\s+/));
      const textWords = new Set(textLower.split(/\s+/));
      const overlap = queryWords.size > 0
        ? [...queryWords].filter(w => textWords.has(w)).length / queryWords.size
        : 0;
      score = overlap;
    }

    if (score > 0.1) {
      results.push({
        id: mem.id,
        text: mem.text,
        category: mem.category || '',
        importance: mem.importance || 0.5,
        score: Math.round(score * 1000) / 1000,
        timestamp: mem.created_at || mem.timestamp || ''
      });
    }
  }

  results.sort((a, b) => b.score - a.score);
  return results.slice(0, k);
}

/**
 * Semantic search using Ollama embeddings
 * @param {Array} memories
 * @param {string} query
 * @param {number} k
 * @param {number} minScore
 * @returns {Promise<Array>}
 */
export async function semanticSearch(memories, query, k = 10, minScore = 0.3) {
  let queryVec = null;
  try {
    queryVec = await getEmbedding(query, OLLAMA_HOST, OLLAMA_EMBED_MODEL);
  } catch {
    // Fall back to keyword search
  }

  if (!queryVec) {
    return fallbackSearch(memories, query, k);
  }

  const results = [];

  for (const mem of memories) {
    const memVec = mem.embedding;
    if (!memVec) {
      // Use text similarity as fallback
      const textSim = textSimilarity(query, mem.text || '');
      if (textSim >= minScore) {
        results.push({
          id: mem.id,
          text: mem.text,
          category: mem.category || '',
          importance: mem.importance || 0.5,
          score: Math.round(textSim * 1000) / 1000,
          timestamp: mem.created_at || mem.timestamp || ''
        });
      }
      continue;
    }

    const sim = cosineSimilarity(queryVec, memVec);
    if (sim >= minScore) {
      results.push({
        id: mem.id,
        text: mem.text,
        category: mem.category || '',
        importance: mem.importance || 0.5,
        score: Math.round(sim * 1000) / 1000,
        timestamp: mem.created_at || mem.timestamp || ''
      });
    }
  }

  results.sort((a, b) => b.score - a.score);
  return results.slice(0, k);
}

/**
 * Filter search by multiple dimensions
 * @param {Array} memories
 * @param {object} filters
 * @returns {Array}
 */
export function filterSearch(memories, {
  category = null,
  minImportance = null,
  maxAgeDays = null,
  tags = null,
  hasTags = false,
  limit = 50
} = {}) {
  const cutoff = maxAgeDays
    ? Date.now() - maxAgeDays * 24 * 60 * 60 * 1000
    : null;

  const results = [];

  for (const mem of memories) {
    // Category filter
    if (category && (mem.category || '') !== category) continue;

    // Importance filter
    if (minImportance != null && (mem.importance || 0.5) < minImportance) continue;

    // Time filter
    if (cutoff) {
      const memTime = mem.created_at || mem.timestamp;
      if (memTime && memTime < cutoff) continue;
    }

    // Tag filter
    const memTags = new Set(mem.tags || []);
    if (hasTags && memTags.size === 0) continue;
    if (tags && !tags.some(t => memTags.has(t))) continue;

    results.push({
      id: mem.id,
      text: mem.text,
      category: mem.category || '',
      importance: mem.importance || 0.5,
      tags: mem.tags || [],
      timestamp: mem.created_at || mem.timestamp || ''
    });
  }

  return results.slice(0, limit);
}

/**
 * Get search suggestions based on history and memory content
 * @param {Array} memories
 * @param {string} prefix
 * @returns {string[]}
 */
export function getSearchSuggestions(memories, prefix) {
  const history = loadHistory();
  const suggestions = [];

  // From history
  for (const s of history.recent || []) {
    if (s.toLowerCase().includes(prefix.toLowerCase())) {
      suggestions.push(s);
    }
  }

  // From memory content words
  if (suggestions.length < 5) {
    for (const mem of (memories || []).slice(0, 20)) {
      const words = (mem.text || '').split(/\s+/).slice(0, 5);
      for (const word of words) {
        if (word.length > 2 && word.toLowerCase().includes(prefix.toLowerCase())) {
          if (!suggestions.includes(word)) {
            suggestions.push(word);
          }
        }
      }
    }
  }

  return [...new Set(suggestions)].slice(0, 10);
}

/**
 * Get search statistics
 * @returns {object}
 */
export function getSearchStats() {
  const history = loadHistory();
  const searches = history.searches || [];

  if (searches.length === 0) {
    return { total_searches: 0, popular_queries: [] };
  }

  /** @type {Map<string, number>} */
  const queryCounts = new Map();
  for (const s of searches) {
    queryCounts.set(s.query, (queryCounts.get(s.query) || 0) + 1);
  }

  const popular = [...queryCounts.entries()]
    .sort((a, b) => b[1] - a[1])
    .slice(0, 10)
    .map(([query, count]) => ({ query, count }));

  return {
    total_searches: searches.length,
    popular_queries: popular,
    recent_searches: searches.slice(-10)
  };
}

// ============================================================
// CLI Command Handler
// ============================================================

/**
 * Execute a search command
 * @param {string} command
 * @param {object} args
 * @param {Array} memories - loaded memories array
 * @returns {Promise<object>}
 */
export async function cmdSearch(command, args, memories) {
  const history = loadHistory();

  switch (command) {
    case 'search': {
      const { query, k = 10, json: asJson = false } = args;
      if (!query) return { error: '请提供搜索内容' };
      const results = await semanticSearch(memories, query, k);
      recordSearch(query, results.length);
      if (asJson) {
        return { type: 'json', data: results };
      }
      return {
        type: 'text',
        text: `🔍 搜索: ${query}\n   找到 ${results.length} 条结果\n\n` +
          results.map((r, i) =>
            `${i + 1}. [${r.category}] ${r.text.slice(0, 80)}...\n   评分: ${r.score.toFixed(3)} | 重要性: ${r.importance}`
          ).join('\n\n')
      };
    }

    case 'filter': {
      const { category, minImportance, maxAge, tags, hasTags, k = 50, json: asJson = false } = args;
      const results = filterSearch(memories, {
        category,
        minImportance: minImportance != null ? parseFloat(minImportance) : null,
        maxAgeDays: maxAge ? parseInt(maxAge) : null,
        tags,
        hasTags,
        limit: parseInt(k)
      });
      if (asJson) {
        return { type: 'json', data: results };
      }
      return {
        type: 'text',
        text: `🔍 过滤结果: ${results.length} 条\n\n` +
          results.map((r, i) =>
            `${i + 1}. [${r.category}] ${r.text.slice(0, 60)}...\n   重要性: ${r.importance} | 标签: ${JSON.stringify(r.tags || [])}`
          ).join('\n\n')
      };
    }

    case 'history': {
      const { json: asJson = false } = args;
      const recent = (history.searches || []).slice(-10);
      if (asJson) {
        return { type: 'json', data: recent };
      }
      return {
        type: 'text',
        text: '📜 搜索历史:\n' +
          [...recent].reverse().map(r =>
            `   ${r.timestamp.slice(0, 19)} - ${r.query} (${r.results}结果)`
          ).join('\n')
      };
    }

    case 'suggestions': {
      const { query } = args;
      if (!query) return { error: '请提供前缀' };
      const suggestions = getSearchSuggestions(memories, query);
      return {
        type: 'text',
        text: '💡 搜索建议:\n' + suggestions.map(s => `   ${s}`).join('\n')
      };
    }

    case 'stats': {
      const stats = getSearchStats();
      const { json: asJson = false } = args;
      if (asJson) {
        return { type: 'json', data: stats };
      }
      return {
        type: 'text',
        text: `📊 搜索统计\n   总搜索次数: ${stats.total_searches}\n\n   热门搜索:\n` +
          (stats.popular_queries || []).slice(0, 5).map(q => `     ${q.query}: ${q.count}次`).join('\n')
      };
    }

    default:
      return { error: `未知命令: ${command}` };
  }
}

export default {
  semanticSearch,
  fallbackSearch,
  filterSearch,
  getSearchSuggestions,
  getSearchStats,
  loadHistory,
  recordSearch,
  cmdSearch
};
/**
 * Sensitive Data Detection and Protection
 */

const SENSITIVE_PATTERNS = [
  { type: 'email', pattern: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/, description: 'Email address' },
  { type: 'phone', pattern: /\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/, description: 'Phone number' },
  { type: 'credit_card', pattern: /\b\d{4}[-\s]?\d{4}[-\s]?\d{4}[-\s]?\d{4}\b/, description: 'Credit card' },
  { type: 'api_key', pattern: /\b(?:api[_-]?key)[=:]\s*['"]?[A-Za-z0-9_-]{16,}['"]?/i, description: 'API Key' },
  { type: 'password', pattern: /\b(?:password|passwd)[=:]\s*['"]?[^\s'"]]{4,}['"]?/i, description: 'Password' },
];

export function detectSensitive(text) {
  const findings = [];
  for (const { type, pattern, description } of SENSITIVE_PATTERNS) {
    let match;
    const regex = new RegExp(pattern.source, 'gi');
    while ((match = regex.exec(text)) !== null) {
      findings.push({ type, value: match[0], description, start: match.index, end: match.index + match[0].length });
    }
  }
  return findings;
}

export function redactSensitive(text, replacement = '[REDACTED]') {
  const findings = detectSensitive(text);
  let result = text;
  let offset = 0;
  for (const finding of findings) {
    const start = finding.start + offset;
    const end = start + finding.value.length;
    result = result.substring(0, start) + replacement + result.substring(end);
    offset += replacement.length - finding.value.length;
  }
  return result;
}

export function hasSensitive(text) {
  return detectSensitive(text).length > 0;
}

if (require.main === module) {
  const text = process.argv.slice(2).join(' ') || 'test@example.com is my email';
  const findings = detectSensitive(text);
  console.log('\n🔒 Sensitive Data Detection\n');
  console.log(`  Text: ${text}\n`);
  if (findings.length === 0) console.log('  ✅ No sensitive data detected');
  else { for (const f of findings) console.log(`    - ${f.type}: ${f.description}`); }
  console.log(`\n  Redacted: ${redactSensitive(text)}`);
  console.log('');
}
/**
 * Memory Source Tracker - 记忆来源溯源系统
 * 
 * 功能:
 * - 记录记忆来源Agent
 * - 追溯记忆创建者
 * - 冲突时确认来源
 * - 来源统计分析
 * 
 * Ported from memory_source.py
 */

import { existsSync, readFileSync, appendFileSync, writeFileSync, mkdirSync } from 'fs';
import { join } from 'path';
import { createHash } from 'crypto';

const HOME = process.env.HOME || '/root';
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const SOURCE_DIR = join(MEMORY_DIR, 'source');
const SOURCE_FILE = join(SOURCE_DIR, 'sources.jsonl');

// ============================================================
// Utilities
// ============================================================

function ensureDirs() {
  if (!existsSync(SOURCE_DIR)) {
    mkdirSync(SOURCE_DIR, { recursive: true });
  }
  if (!existsSync(SOURCE_FILE)) {
    writeFileSync(SOURCE_FILE, '', 'utf-8');
  }
}

/**
 * Generate a short memory ID from text + timestamp
 * @param {string} text
 * @param {string} timestamp
 * @returns {string}
 */
function generateMemoryId(text, timestamp) {
  const hash = createHash('md5');
  hash.update(timestamp + text);
  return hash.digest('hex').slice(0, 12);
}

// ============================================================
// Core Functions
// ============================================================

/**
 * Store a memory with source tracking
 * @param {string} text
 * @param {string} agent
 * @param {string} category
 * @param {object} metadata
 * @returns {object}
 */
export function storeWithSource(text, agent, category = 'other', metadata = null) {
  ensureDirs();

  const timestamp = new Date().toISOString();
  const memoryId = generateMemoryId(text, timestamp);

  /** @type {object} */
  const sourceEntry = {
    memory_id: memoryId,
    timestamp,
    text,
    source_agent: agent,
    category,
    metadata: metadata || {},
    verified: false,
    conflicts: []
  };

  appendFileSync(SOURCE_FILE, JSON.stringify(sourceEntry, null, 2) + '\n', 'utf-8');

  return sourceEntry;
}

/**
 * Trace a memory's source
 * @param {string} memoryId
 * @returns {object|null}
 */
export function traceMemory(memoryId) {
  ensureDirs();

  const lines = readFileSync(SOURCE_FILE, 'utf-8').split('\n').filter(Boolean);
  for (const line of lines) {
    try {
      const entry = JSON.parse(line);
      if (entry.memory_id === memoryId) {
        return entry;
      }
    } catch {
      continue;
    }
  }
  return null;
}

/**
 * Find memories by source agent
 * @param {string} agent
 * @param {number} limit
 * @returns {Array<object>}
 */
export function findByAgent(agent, limit = 20) {
  ensureDirs();

  const memories = [];
  const lines = readFileSync(SOURCE_FILE, 'utf-8').split('\n').filter(Boolean);

  for (const line of lines) {
    try {
      const entry = JSON.parse(line);
      if (entry.source_agent === agent) {
        memories.push(entry);
      }
    } catch {
      continue;
    }
  }

  memories.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
  return memories.slice(0, limit);
}

/**
 * Find memories with conflicts
 * @returns {Array<object>}
 */
export function findConflicts() {
  ensureDirs();

  const conflicts = [];
  const lines = readFileSync(SOURCE_FILE, 'utf-8').split('\n').filter(Boolean);

  for (const line of lines) {
    try {
      const entry = JSON.parse(line);
      if (entry.conflicts && entry.conflicts.length > 0) {
        conflicts.push(entry);
      }
    } catch {
      continue;
    }
  }

  return conflicts;
}

/**
 * Verify a memory
 * @param {string} memoryId
 * @param {string} verifiedBy
 * @returns {object}
 */
export function verifyMemory(memoryId, verifiedBy) {
  ensureDirs();

  const lines = readFileSync(SOURCE_FILE, 'utf-8').split('\n').filter(Boolean);
  /** @type {string[]} */
  const entries = [];
  let verifiedEntry = null;

  for (const line of lines) {
    try {
      const entry = JSON.parse(line);
      if (entry.memory_id === memoryId) {
        entry.verified = true;
        entry.verified_by = verifiedBy;
        entry.verified_at = new Date().toISOString();
        verifiedEntry = entry;
      }
      entries.push(entry);
    } catch {
      // keep invalid lines as-is
      entries.push(line);
    }
  }

  if (verifiedEntry) {
    writeFileSync(SOURCE_FILE, entries.map(e => typeof e === 'string' ? e : JSON.stringify(e)).join('\n') + '\n', 'utf-8');
  }

  return verifiedEntry || {};
}

/**
 * Get source statistics
 * @returns {object}
 */
export function getStats() {
  ensureDirs();

  /** @type {object} */
  const stats = {
    total: 0,
    by_agent: {},
    by_category: {},
    verified: 0,
    unverified: 0,
    conflicts: 0
  };

  const lines = readFileSync(SOURCE_FILE, 'utf-8').split('\n').filter(Boolean);

  for (const line of lines) {
    try {
      const entry = JSON.parse(line);
      stats.total++;

      // By agent
      const agent = entry.source_agent || 'unknown';
      stats.by_agent[agent] = (stats.by_agent[agent] || 0) + 1;

      // By category
      const category = entry.category || 'other';
      stats.by_category[category] = (stats.by_category[category] || 0) + 1;

      // Verified
      if (entry.verified) {
        stats.verified++;
      } else {
        stats.unverified++;
      }

      // Conflicts
      if (entry.conflicts && entry.conflicts.length > 0) {
        stats.conflicts++;
      }
    } catch {
      continue;
    }
  }

  return stats;
}

// ============================================================
// CLI Handler
// ============================================================

/**
 * @param {string} command
 * @param {object} args
 * @returns {object}
 */
export function cmdSource(command, args) {
  switch (command) {
    case 'store': {
      const { text, agent, category = 'other' } = args;
      if (!text || !agent) {
        return { error: '缺少参数: --text, --agent' };
      }
      const entry = storeWithSource(text, agent, category);
      if (args.json) {
        return { type: 'json', data: entry };
      }
      return {
        type: 'text',
        text: `📝 存储记忆: [${entry.memory_id}] [${entry.source_agent}] ${entry.text.slice(0, 50)}...`
      };
    }

    case 'trace': {
      const { memoryId } = args;
      if (!memoryId) {
        return { error: '缺少参数: --memory-id' };
      }
      const entry = traceMemory(memoryId);
      if (!entry) {
        return { error: `❌ 记忆不存在: ${memoryId}` };
      }
      if (args.json) {
        return { type: 'json', data: entry };
      }
      return {
        type: 'text',
        text: `🔍 记忆来源: [${entry.memory_id}]\n` +
          `   来源Agent: ${entry.source_agent}\n` +
          `   时间: ${entry.timestamp}\n` +
          `   类别: ${entry.category}\n` +
          `   内容: ${entry.text.slice(0, 100)}...\n` +
          `   已验证: ${entry.verified ? '✅' : '❌'}`
      };
    }

    case 'find': {
      const { agent, limit = 20 } = args;
      if (!agent) {
        return { error: '缺少参数: --agent' };
      }
      const memories = findByAgent(agent, parseInt(limit));
      if (args.json) {
        return { type: 'json', data: memories };
      }
      return {
        type: 'text',
        text: `📋 [${agent}] 的记忆 (共 ${memories.length} 条)\n` +
          memories.map(m => `  [${m.memory_id}] ${m.text.slice(0, 50)}...`).join('\n')
      };
    }

    case 'conflicts': {
      const conflicts = findConflicts();
      if (args.json) {
        return { type: 'json', data: conflicts };
      }
      return {
        type: 'text',
        text: `⚠️ 冲突记忆 (共 ${conflicts.length} 条)\n` +
          conflicts.map(m => `  [${m.memory_id}] ${m.text.slice(0, 50)}...\n      冲突: ${JSON.stringify(m.conflicts)}`).join('\n')
      };
    }

    case 'verify': {
      const { memoryId, verifiedBy } = args;
      if (!memoryId || !verifiedBy) {
        return { error: '缺少参数: --memory-id, --verified-by' };
      }
      const entry = verifyMemory(memoryId, verifiedBy);
      if (args.json) {
        return { type: 'json', data: entry };
      }
      return {
        type: 'text',
        text: entry.memory_id
          ? `✅ 验证记忆: [${entry.memory_id}] 由 ${entry.verified_by} 验证`
          : `❌ 记忆不存在: ${memoryId}`
      };
    }

    case 'stats': {
      const stats = getStats();
      if (args.json) {
        return { type: 'json', data: stats };
      }
      return {
        type: 'text',
        text: `📊 来源统计\n` +
          `   总计: ${stats.total}\n` +
          `   按Agent: ${JSON.stringify(stats.by_agent)}\n` +
          `   按类别: ${JSON.stringify(stats.by_category)}\n` +
          `   已验证: ${stats.verified}\n` +
          `   未验证: ${stats.unverified}\n` +
          `   冲突数: ${stats.conflicts}`
      };
    }

    default:
      return { error: `未知命令: ${command}` };
  }
}

export default {
  storeWithSource,
  traceMemory,
  findByAgent,
  findConflicts,
  verifyMemory,
  getStats,
  cmdSource
};
/**
 * Standard Memory Format - Unified format for memory interchange
 */

export function validateMemory(memory) {
  const errors = [];
  if (!memory.id) errors.push('Missing required field: id');
  if (!memory.text) errors.push('Missing required field: text');
  if (memory.importance !== undefined && (memory.importance < 0 || memory.importance > 1)) errors.push('importance must be 0-1');
  if (memory.confidence !== undefined && (memory.confidence < 0 || memory.confidence > 1)) errors.push('confidence must be 0-1');
  const validCategories = ['preference', 'entity', 'fact', 'decision', 'learning', 'task', 'general'];
  if (memory.category && !validCategories.includes(memory.category)) errors.push(`Invalid category`);
  return { valid: errors.length === 0, errors };
}

export function normalizeMemory(memory) {
  const now = new Date().toISOString();
  return {
    id: memory.id || `mem_${Date.now()}`,
    text: memory.text || memory.content || '',
    category: memory.category || 'general',
    importance: normalizeNumber(memory.importance, 0.5, 0, 1),
    confidence: normalizeNumber(memory.confidence, 0.8, 0, 1),
    tags: Array.isArray(memory.tags) ? memory.tags : (memory.tags ? [memory.tags] : []),
    project: memory.project || 'default',
    created_at: normalizeDate(memory.created_at || memory.timestamp || now),
    updated_at: normalizeDate(memory.updated_at || now),
    access_count: memory.access_count || 0,
    metadata: memory.metadata || {},
  };
}

function normalizeNumber(value, defaultVal, min = 0, max = 1) {
  if (value === undefined || value === null) return defaultVal;
  const num = Number(value);
  if (isNaN(num)) return defaultVal;
  return Math.max(min, Math.min(max, num));
}

function normalizeDate(value) {
  if (!value) return undefined;
  try { return new Date(value).toISOString(); }
  catch { return undefined; }
}

export function serializeMemory(memory, options = {}) {
  const m = { ...memory };
  if (!options.includeMetadata) delete m.metadata;
  return JSON.stringify(m);
}

export function deserializeMemory(str) {
  try { return normalizeMemory(JSON.parse(str)); }
  catch { return null; }
}

if (require.main === module) {
  console.log('\n📦 Standard Format\n');
  console.log('  validateMemory(memory) - Validate memory object');
  console.log('  normalizeMemory(memory) - Normalize to standard format');
  console.log('  serializeMemory(memory) - Serialize to JSON');
  console.log('  deserializeMemory(str) - Deserialize from JSON');
  console.log('');
}
/**
 * Memory Streaming - Stream memory operations with async generators
 */

import { readFileSync, existsSync } from 'fs';
import { join } from 'path';
import { getAllMemories } from '../storage.js';


const WORKSPACE = join(process.env.HOME || '/root', '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');

export async function* streamMemories(batchSize = 10) {
  const memories = getAllMemories();
  for (let i = 0; i < memories.length; i += batchSize) {
    yield memories.slice(i, i + batchSize);
    await new Promise(resolve => setTimeout(resolve, 1));
  }
}

export async function* streamByCategory(category, batchSize = 10) {
  const allMemories = getAllMemories();
  const filtered = allMemories.filter(m => m.category === category);
  for (let i = 0; i < filtered.length; i += batchSize) {
    yield filtered.slice(i, i + batchSize);
    await new Promise(resolve => setTimeout(resolve, 1));
  }
}

export async function* streamSearch(query, batchSize = 10) {
  const memories = getAllMemories();
  const q = query.toLowerCase();
  const filtered = memories.filter(m => (m.text || '').toLowerCase().includes(q));
  for (let i = 0; i < filtered.length; i += batchSize) {
    yield filtered.slice(i, i + batchSize);
    await new Promise(resolve => setTimeout(resolve, 1));
  }
}

export async function countMemories() {
  let count = 0;
  for await (const _batch of streamMemories(100)) { count++; }
  return count;
}

if (require.main === module) {
  const args = process.argv.slice(2);
  if (args[0] === 'count') {
    countMemories().then(count => console.log(`\n📊 Total memories: ${count}\n`));
  } else {
    console.log('\n📺 Memory Streaming Demo\n');
    let batchNum = 0;
    for await (const batch of streamMemories(5)) {
      batchNum++;
      console.log(`  Batch ${batchNum}: ${batch.length} memories`);
      if (batchNum >= 3) break;
    }
    console.log('\n✅ Streaming complete\n');
  }
}
/**
 * tokenizer.js - 智能分块系统
 * 借鉴 QMD 的断点检测算法，实现自然语义分块
 * Ported from Python smart_chunk.py
 */

import { regexMatch } from '../utils/text.js';

// 断点类型和分数
const BREAK_TYPES = {
  h1: 100,
  h2: 90,
  h3: 80,
  h4: 70,
  h5: 60,
  h6: 50,
  codeblock: 80,
  hr: 60,
  blank: 20,
  list: 5,
  numlist: 5,
  newline: 1
};

/**
 * 找出所有代码块区域（这些区域内的内容不应被切断）
 */
function findCodeFences(text) {
  const regions = [];
  const fencePattern = /```/g;
  let match;
  
  while ((match = fencePattern.exec(text)) !== null) {
    if (regions.length % 2 === 0) {
      regions.push({ start: match.index, end: null });
    } else {
      regions[regions.length - 1].end = match.index + 3;
    }
  }
  
  // 未闭合的代码块
  if (regions.length % 2 !== 0) {
    regions[regions.length - 1].end = text.length;
  }
  
  return regions;
}

/**
 * 判断位置是否在代码块内
 */
function isInCodeFence(pos, fences) {
  for (const fence of fences) {
    if (pos >= fence.start && pos < fence.end) {
      return true;
    }
  }
  return false;
}

/**
 * 查找所有断点
 */
function findBreakpoints(text, maxTokens = 900) {
  const breakpoints = [];
  const fences = findCodeFences(text);
  
  // 标题断点
  const h1Pattern = /^# .+$/gm;
  const h2Pattern = /^## .+$/gm;
  const h3Pattern = /^### .+$/gm;
  const h4Pattern = /^#### .+$/gm;
  const h5Pattern = /^##### .+$/gm;
  const h6Pattern = /^###### .+$/gm;
  
  let m;
  while ((m = h1Pattern.exec(text)) !== null) {
    breakpoints.push({ pos: m.index, score: BREAK_TYPES.h1, type: 'h1' });
  }
  while ((m = h2Pattern.exec(text)) !== null) {
    breakpoints.push({ pos: m.index, score: BREAK_TYPES.h2, type: 'h2' });
  }
  while ((m = h3Pattern.exec(text)) !== null) {
    breakpoints.push({ pos: m.index, score: BREAK_TYPES.h3, type: 'h3' });
  }
  while ((m = h4Pattern.exec(text)) !== null) {
    breakpoints.push({ pos: m.index, score: BREAK_TYPES.h4, type: 'h4' });
  }
  while ((m = h5Pattern.exec(text)) !== null) {
    breakpoints.push({ pos: m.index, score: BREAK_TYPES.h5, type: 'h5' });
  }
  while ((m = h6Pattern.exec(text)) !== null) {
    breakpoints.push({ pos: m.index, score: BREAK_TYPES.h6, type: 'h6' });
  }
  
  // 代码块
  while ((m = /\n```/g.exec(text)) !== null) {
    if (!isInCodeFence(m.index, fences)) {
      breakpoints.push({ pos: m.index, score: BREAK_TYPES.codeblock, type: 'codeblock' });
    }
  }
  
  // 水平线
  while ((m = /\n(?:---|\*\*\*|___)\s*\n/g.exec(text)) !== null) {
    breakpoints.push({ pos: m.index, score: BREAK_TYPES.hr, type: 'hr' });
  }
  
  // 空行
  while ((m = /\n\n+/g.exec(text)) !== null) {
    breakpoints.push({ pos: m.index + 1, score: BREAK_TYPES.blank, type: 'blank' });
  }
  
  // 排序
  breakpoints.sort((a, b) => a.pos - b.pos);
  
  return breakpoints;
}

/**
 * 估算token数（简单按中英文混合估算）
 */
function estimateTokens(text) {
  const chinese = (text.match(/[\u4e00-\u9fff]/g) || []).length;
  const english = (text.match(/[a-zA-Z]+/g) || []).join('').length;
  const other = text.length - chinese - english;
  return Math.ceil(chinese * 1.5 + english * 0.25 + other * 0.5);
}

/**
 * 智能分块
 */
export function smartChunk(text, maxTokens = 900) {
  if (!text || text.trim().length === 0) {
    return [];
  }
  
  const breakpoints = findBreakpoints(text, maxTokens);
  const chunks = [];
  
  let chunkStart = 0;
  let currentTokens = 0;
  let currentChunk = '';
  
  for (let i = 0; i < text.length; i++) {
    const char = text[i];
    currentChunk += char;
    
    // 估算token
    if (/[\u4e00-\u9fff]/.test(char)) {
      currentTokens += 1.5;
    } else if (/[a-zA-Z]/.test(char)) {
      currentTokens += 0.25;
    } else {
      currentTokens += 0.5;
    }
    
    // 检查是否该分块
    if (currentTokens >= maxTokens) {
      // 找最近的断点
      const candidates = breakpoints.filter(bp => bp.pos > chunkStart && bp.pos < i);
      
      if (candidates.length > 0) {
        // 在最佳断点处切断
        const bestBp = candidates.reduce((best, c) => c.score > best.score ? c : best);
        const cutPos = bestBp.pos;
        chunks.push(text.slice(chunkStart, cutPos).trim());
        i = cutPos - 1;
      } else {
        // 硬切断
        chunks.push(currentChunk.trim());
      }
      
      currentTokens = 0;
      currentChunk = '';
      chunkStart = i + 1;
    }
  }
  
  // 剩余内容
  if (currentChunk.trim().length > 0) {
    chunks.push(currentChunk.trim());
  }
  
  return chunks.filter(c => c.length > 0);
}

/**
 * 简单分词（中英文）
 */
export function tokenize(text) {
  const tokens = [];
  
  // 英文单词
  const english = text.match(/[a-zA-Z]+/g) || [];
  tokens.push(...english.map(t => t.toLowerCase()));
  
  // 中文单字
  const chinese = text.match(/[\u4e00-\u9fff]/g) || [];
  tokens.push(...chinese);
  
  // 数字
  const numbers = text.match(/\d+/g) || [];
  tokens.push(...numbers);
  
  return tokens;
}
/**
 * Memory Trace - 决策追溯链
 * 
 * 功能:
 * - 追溯记忆的来源和决策背景
 * - 显示决策链条（A → B → C）
 * - 支持时间线视图
 * 
 * Ported from memory_trace.py
 */

import { existsSync, readFileSync } from 'fs';
import { join } from 'path';
import { getAllMemories } from '../storage.js';


const HOME = process.env.HOME || '/root';
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const MEMORIES_FILE = join(MEMORY_DIR, 'memories.json');
const TRACE_FILE = join(MEMORY_DIR, 'decision_traces.json');

// ============================================================
// Utilities
// ============================================================

/**
 * Load traces from file
 * @returns {{ traces: object, chains: Array }}
 */
export function loadTraces() {
  if (existsSync(TRACE_FILE)) {
    try {
      return JSON.parse(readFileSync(TRACE_FILE, 'utf-8'));
    } catch {
      // ignore
    }
  }
  return { traces: {}, chains: [] };
}

/**
 * Save traces to file
 * @param {{ traces: object, chains: Array }} traces
 */
export function saveTraces(traces) {
  // Ensure directory exists
  const { mkdirSync } = require('fs');
  mkdirSync(MEMORY_DIR, { recursive: true });
  require('fs').writeFileSync(TRACE_FILE, JSON.stringify(traces, null, 2), 'utf-8');
}

/**
 * Find a memory by ID (partial match)
 * @param {Array} memories
 * @param {string} memId
 * @returns {object|null}
 */
export function findMemoryById(memories, memId) {
  for (const m of memories) {
    const id = m.id || '';
    if (id.startsWith(memId) || id.includes(memId) || memId.includes(id.slice(-8))) {
      return m;
    }
  }
  return null;
}

/**
 * Find related memories based on keywords and time
 * @param {Array} memories
 * @param {object} mem
 * @returns {Array<object>}
 */
export function findRelatedMemories(memories, mem) {
  const related = [];
  const text = mem.text || '';
  
  // Extract Chinese keywords (simplified)
  const keywords = new Set();
  const chineseRegex = /[\u4e00-\u9fff]+/g;
  let match;
  while ((match = chineseRegex.exec(text)) !== null) {
    keywords.add(match[0]);
  }

  for (const m of memories) {
    if ((m.id || '') === (mem.id || '')) continue;

    const mText = m.text || '';
    const mKeywords = new Set();
    while ((match = chineseRegex.exec(mText)) !== null) {
      mKeywords.add(match[0]);
    }

    // Keyword overlap count
    const overlap = new Set([...keywords].filter(k => mKeywords.has(k))).size;
    if (overlap >= 2) {
      m.relevance = overlap;
      related.push(m);
    }
  }

  // Sort by relevance descending
  related.sort((a, b) => (b.relevance || 0) - (a.relevance || 0));
  return related.slice(0, 5);
}

// ============================================================
// Core Trace Functions
// ============================================================

/**
 * Trace a memory's origin and related chain
 * @param {string} memId
 * @returns {object}
 */
export function traceMemory(memId) {
  const memories = getAllMemories();
  const traces = loadTraces();

  const mem = findMemoryById(memories, memId);
  if (!mem) {
    return { error: `未找到记忆: ${memId}` };
  }

  // Find related memories
  const related = findRelatedMemories(memories, mem);

  // Build trace chain
  /** @type {object} */
  const chain = {
    target: {
      id: mem.id,
      text: (mem.text || '').slice(0, 100),
      timestamp: mem.timestamp || mem.created_at || '',
      category: mem.category
    },
    related: related.map(m => ({
      id: m.id,
      text: (m.text || '').slice(0, 60),
      relevance: m.relevance
    })),
    timeline: []
  };

  // Timeline (sorted by time)
  /** @type {Array} */
  const timelineMemories = [mem, ...related];
  timelineMemories.sort((a, b) => {
    const ta = a.timestamp || a.created_at || '';
    const tb = b.timestamp || b.created_at || '';
    return ta.localeCompare(tb);
  });

  for (const m of timelineMemories) {
    chain.timeline.push({
      timestamp: m.timestamp || m.created_at || '',
      text: (m.text || '').slice(0, 50),
      id: m.id
    });
  }

  return chain;
}

/**
 * Show decision timeline
 * @param {number} limit
 * @returns {Array<object>}
 */
export function showTimeline(limit = 10) {
  const memories = getAllMemories();

  // Filter decision category memories
  const decisions = memories
    .filter(m => m.category === 'decision')
    .sort((a, b) => {
      const ta = a.timestamp || a.created_at || '';
      const tb = b.timestamp || b.created_at || '';
      return tb.localeCompare(ta); // newest first
    })
    .slice(0, limit);

  return decisions.map((d, i) => ({
    order: i + 1,
    timestamp: d.timestamp || d.created_at || '',
    text: (d.text || '').slice(0, 80),
    id: d.id
  }));
}

// ============================================================
// CLI Handler
// ============================================================

/**
 * @param {string|null} memId
 * @param {object} args
 * @returns {object}
 */
export function cmdTrace(memId, args = {}) {
  const { timeline = false, limit = 10 } = args;

  if (timeline) {
    const tl = showTimeline(parseInt(limit));
    const lines = ['📅 决策时间线\n'];
    if (tl.length === 0) {
      lines.push('  暂无决策记录');
    } else {
      for (const t of tl) {
        lines.push(`  [${t.order}] ${t.timestamp.slice(0, 10)}`);
        lines.push(`      ${t.text}...`);
        lines.push('');
      }
    }
    return { type: 'text', text: lines.join('\n') };
  }

  if (!memId) {
    return {
      type: 'text',
      text: 'Usage: trace <memory-id> [--timeline] [--limit N]'
    };
  }

  const chain = traceMemory(memId);

  if (chain.error) {
    return { type: 'text', text: `❌ ${chain.error}` };
  }

  const lines = [`🔍 追溯记忆: ${memId}\n`];
  lines.push('📍 目标记忆:');
  lines.push(`   ${chain.target.text}...`);
  lines.push(`   ID: ${chain.target.id}`);
  lines.push(`   时间: ${chain.target.timestamp}`);

  if (chain.related && chain.related.length > 0) {
    lines.push('\n🔗 相关记忆:');
    for (const r of chain.related) {
      lines.push(`   [${r.relevance} 关键词] ${r.text}...`);
    }
  }

  if (chain.timeline && chain.timeline.length > 1) {
    lines.push('\n📅 时间线:');
    for (const t of chain.timeline) {
      lines.push(`   ${t.timestamp.slice(0, 10)} | ${t.text}...`);
    }
  }

  return { type: 'text', text: lines.join('\n') };
}

export default {
  getAllMemories,
  loadTraces,
  saveTraces,
  findMemoryById,
  findRelatedMemories,
  traceMemory,
  showTimeline,
  cmdTrace
};
/**
 * Memory Usage Analyzer - 记忆使用分析
 * 
 * 站在 AI Agent 用户角度，回答：
 * - 哪些记忆最有用？（访问频率）
 * - 哪些记忆浪费空间？（从未访问）
 * - 哪些记忆可能过时？（时效性）
 * - 记忆分布是否合理？（分类统计）
 * 
 * Ported from memory_usage.py
 */

import { existsSync, readFileSync } from 'fs';
import { join } from 'path';

const HOME = process.env.HOME || '/root';
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const VECTOR_DB_DIR = join(MEMORY_DIR, 'vector');
const ACCESS_LOG_FILE = join(MEMORY_DIR, 'access_history.json');
const USAGE_REPORT_FILE = join(MEMORY_DIR, 'usage_report.json');

// ============================================================
// MemoryUsageAnalyzer
// ============================================================

export class MemoryUsageAnalyzer {
  constructor() {
    /** @type {Array<object>} */
    this.memories = this._loadMemories();
    /** @type {{ accesses: Array, co_occurrences: object }} */
    this.accessLog = this._loadAccessLog();
  }

  /**
   * Load memories from storage
   * @returns {Array<object>}
   */
  _loadMemories() {
    try {
      const { getAllMemories } = require('../storage.js');
      return getAllMemories();
    } catch {
      // Fallback: try loading from file
      const memoryFile = join(MEMORY_DIR, 'memories.json');
      if (existsSync(memoryFile)) {
        try {
          const data = JSON.parse(readFileSync(memoryFile, 'utf-8'));
          return Array.isArray(data) ? data : (data.memories || []);
        } catch {
          // ignore
        }
      }
    }
    return [];
  }

  /**
   * Load access log
   * @returns {{ accesses: Array, co_occurrences: object }}
   */
  _loadAccessLog() {
    if (existsSync(ACCESS_LOG_FILE)) {
      try {
        return JSON.parse(readFileSync(ACCESS_LOG_FILE, 'utf-8'));
      } catch {
        // ignore
      }
    }
    return { accesses: [], co_occurrences: {} };
  }

  /**
   * Full analysis
   * @returns {object}
   */
  analyze() {
    const result = {
      total: this.memories.length,
      categories: {},
      access_stats: {},
      stale_memories: [],
      unused_memories: [],
      top_memories: [],
      recommendations: []
    };

    // 1. Category counts
    for (const m of this.memories) {
      const cat = m.category || 'general';
      result.categories[cat] = (result.categories[cat] || 0) + 1;
    }

    // 2. Access counts
    /** @type {Map<string, number>} */
    const accessCounts = new Map();
    for (const acc of this.accessLog.accesses || []) {
      const id = acc.id || acc.memory_id || '';
      accessCounts.set(id, (accessCounts.get(id) || 0) + 1);
    }

    // 3. Most accessed memories
    const sortedByAccess = [...accessCounts.entries()].sort((a, b) => b[1] - a[1]);
    for (const [memId, count] of sortedByAccess.slice(0, 5)) {
      const mem = this.memories.find(m => m.id === memId);
      if (mem) {
        result.top_memories.push({
          id: memId,
          text: (mem.text || '').slice(0, 50) + '...',
          access_count: count,
          category: mem.category
        });
      }
    }

    // 4. Never accessed memories
    for (const mem of this.memories) {
      if (!accessCounts.has(mem.id)) {
        result.unused_memories.push({
          id: mem.id,
          text: (mem.text || '').slice(0, 50) + '...',
          category: mem.category || 'general',
          importance: mem.importance || 0.5
        });
      }
    }

    // 5. Stale memories (>30 days old + low importance)
    const cutoff = Date.now() - 30 * 24 * 60 * 60 * 1000;
    for (const mem of this.memories) {
      const created = mem.created_at || mem.timestamp;
      if (!created) continue;
      const createdMs = typeof created === 'number' ? created : new Date(created).getTime();
      if (createdMs < cutoff && (mem.importance || 0.5) < 0.5) {
        const ageDays = Math.floor((Date.now() - createdMs) / (24 * 60 * 60 * 1000));
        result.stale_memories.push({
          id: mem.id,
          text: (mem.text || '').slice(0, 50) + '...',
          age_days: ageDays,
          importance: mem.importance || 0.5
        });
      }
    }

    // 6. Recommendations
    if (result.unused_memories.length > this.memories.length * 0.3) {
      result.recommendations.push({
        type: 'cleanup',
        message: `有 ${result.unused_memories.length} 条记忆从未被访问，建议清理或降低重要性`
      });
    }
    if (result.stale_memories.length > 5) {
      result.recommendations.push({
        type: 'archive',
        message: `有 ${result.stale_memories.length} 条记忆可能已过时，建议归档`
      });
    }
    if (result.top_memories.length === 0) {
      result.recommendations.push({
        type: 'usage',
        message: '没有访问记录，建议开始使用记忆系统'
      });
    }

    // 7. Access stats summary
    result.access_stats = {
      total_accesses: (this.accessLog.accesses || []).length,
      unique_accessed: accessCounts.size,
      never_accessed: this.memories.length - accessCounts.size,
      avg_access_per_memory: this.memories.length > 0
        ? Math.round((this.accessLog.accesses || []).length / Math.max(accessCounts.size, 1) * 100) / 100
        : 0
    };

    return result;
  }

  /**
   * Cleanup suggestions
   * @returns {object}
   */
  cleanupSuggest() {
    const analysis = this.analyze();

    /** @type {object} */
    const suggestions = {
      can_delete: [],
      can_archive: [],
      can_merge: [],
      can_boost: []
    };

    // Can delete: low importance + never accessed + >30 days
    for (const mem of analysis.unused_memories) {
      if (mem.importance < 0.3) {
        suggestions.can_delete.push(mem);
      }
    }

    // Can archive: stale
    suggestions.can_archive = analysis.stale_memories;

    // Can merge: similar content (simple keyword overlap)
    const texts = this.memories.map(m => ({ id: m.id, text: m.text || '' }));
    for (let i = 0; i < texts.length; i++) {
      for (let j = i + 1; j < texts.length; j++) {
        const words1 = new Set(texts[i].text.split(/\s+/));
        const words2 = new Set(texts[j].text.split(/\s+/));
        const intersection = new Set([...words1].filter(w => words2.has(w)));
        const union = new Set([...words1, ...words2]);
        const overlap = union.size > 0 ? intersection.size / union.size : 0;
        if (overlap > 0.6) {
          suggestions.can_merge.push({
            id1: texts[i].id,
            id2: texts[j].id,
            similarity: Math.round(overlap * 100) / 100,
            text1: texts[i].text.slice(0, 30) + '...',
            text2: texts[j].text.slice(0, 30) + '...'
          });
        }
      }
    }

    // Can boost: high access but low importance
    /** @type {Map<string, number>} */
    const accessCounts = new Map();
    for (const acc of this.accessLog.accesses || []) {
      const id = acc.id || acc.memory_id || '';
      accessCounts.set(id, (accessCounts.get(id) || 0) + 1);
    }
    for (const [memId, count] of accessCounts) {
      if (count > 3) {
        const mem = this.memories.find(m => m.id === memId);
        if (mem && (mem.importance || 0.5) < 0.7) {
          suggestions.can_boost.push({
            id: memId,
            text: (mem.text || '').slice(0, 50) + '...',
            current_importance: Math.round((mem.importance || 0.5) * 100) / 100,
            suggested_importance: Math.round(Math.min(0.9, (mem.importance || 0.5) + 0.2) * 100) / 100,
            access_count: count
          });
        }
      }
    }

    return suggestions;
  }

  /**
   * Usage report for recent N days
   * @param {number} days
   * @returns {object}
   */
  usageReport(days = 7) {
    const cutoff = Date.now() - days * 24 * 60 * 60 * 1000;

    /** @type {Array} */
    const recentAccesses = [];
    for (const acc of this.accessLog.accesses || []) {
      const accTime = acc.timestamp || acc.access_time;
      if (!accTime) continue;
      const accMs = typeof accTime === 'number' ? accTime : new Date(accTime).getTime();
      if (accMs > cutoff) {
        recentAccesses.push(acc);
      }
    }

    // Daily access counts
    /** @type {Map<string, number>} */
    const dailyAccess = new Map();
    for (const acc of recentAccesses) {
      const ts = acc.timestamp || acc.access_time;
      if (!ts) continue;
      const dateStr = new Date(ts).toISOString().slice(0, 10);
      dailyAccess.set(dateStr, (dailyAccess.get(dateStr) || 0) + 1);
    }

    // Category access
    /** @type {Map<string, number>} */
    const categoryAccess = new Map();
    for (const acc of recentAccesses) {
      const memId = acc.id || acc.memory_id;
      const mem = this.memories.find(m => m.id === memId);
      if (mem) {
        const cat = mem.category || 'general';
        categoryAccess.set(cat, (categoryAccess.get(cat) || 0) + 1);
      }
    }

    // Most active day
    let mostActiveDay = null;
    let maxCount = 0;
    for (const [date, count] of dailyAccess) {
      if (count > maxCount) {
        maxCount = count;
        mostActiveDay = date;
      }
    }

    return {
      period_days: days,
      total_accesses: recentAccesses.length,
      daily_access: Object.fromEntries([...dailyAccess.entries()].sort()),
      category_access: Object.fromEntries([...categoryAccess.entries()].sort()),
      avg_daily: Math.round(recentAccesses.length / days * 10) / 10,
      most_active_day: mostActiveDay
    };
  }

  /**
   * Get score for a single memory
   * @param {string} memId
   * @returns {object}
   */
  getMemoryScore(memId) {
    const mem = this.memories.find(m => m.id === memId);
    if (!mem) {
      return { error: 'Memory not found' };
    }

    // Access count
    let accessCount = 0;
    let recentAccess = null;
    const accesses = this.accessLog.accesses || [];
    for (let i = accesses.length - 1; i >= 0; i--) {
      const acc = accesses[i];
      if ((acc.id || acc.memory_id || '') === memId) {
        accessCount++;
        if (!recentAccess) {
          recentAccess = acc.timestamp || acc.access_time;
        }
      }
    }

    // Memory age
    const created = mem.created_at || mem.timestamp;
    const ageDays = created
      ? Math.floor((Date.now() - (typeof created === 'number' ? created : new Date(created).getTime())) / (24 * 60 * 60 * 1000))
      : 0;

    // Composite score
    const importance = mem.importance || 0.5;
    const accessScore = Math.min(accessCount / 10, 1) * 0.3;
    const freshnessScore = (1 - Math.min(ageDays / 365, 1)) * 0.3;
    const score = importance * 0.4 + accessScore + freshnessScore;

    const grade = score > 0.7 ? 'A' : score > 0.5 ? 'B' : score > 0.3 ? 'C' : 'D';

    return {
      id: memId,
      text: (mem.text || '').slice(0, 50) + '...',
      importance: Math.round(importance * 100) / 100,
      access_count: accessCount,
      age_days: ageDays,
      recent_access: recentAccess,
      score: Math.round(score * 1000) / 1000,
      grade
    };
  }
}

// ============================================================
// CLI Handler
// ============================================================

/**
 * @param {string} command
 * @param {object} args
 * @returns {object}
 */
export function cmdUsage(command, args) {
  const analyzer = new MemoryUsageAnalyzer();

  switch (command) {
    case 'analyze': {
      const result = analyzer.analyze();
      if (args.json) return { type: 'json', data: result };
      const lines = ['📊 记忆使用分析', '', `总记忆: ${result.total} 条`, '', '分类分布:'];
      for (const [cat, count] of Object.entries(result.categories)) {
        lines.push(`   ${cat || '未分类'}: ${count} 条`);
      }
      lines.push('', '访问统计:');
      const stats = result.access_stats;
      lines.push(`   总访问: ${stats.total_accesses} 次`);
      lines.push(`   已访问: ${stats.unique_accessed} 条`);
      lines.push(`   从未访问: ${stats.never_accessed} 条`);
      if (result.top_memories.length > 0) {
        lines.push('', '🔥 最常访问:');
        result.top_memories.forEach((m, i) => {
          lines.push(`   ${i + 1}. [${m.access_count}次] ${m.text}`);
        });
      }
      if (result.recommendations.length > 0) {
        lines.push('', '💡 建议:');
        result.recommendations.forEach(r => {
          lines.push(`   [${r.type}] ${r.message}`);
        });
      }
      return { type: 'text', text: lines.join('\n') };
    }

    case 'cleanup-suggest': {
      const result = analyzer.cleanupSuggest();
      if (args.json) return { type: 'json', data: result };
      const lines = ['🧹 清理建议', ''];
      lines.push(`可删除: ${result.can_delete.length} 条`);
      result.can_delete.slice(0, 3).forEach(m => lines.push(`   - ${m.text}`));
      lines.push(`\n可归档: ${result.can_archive.length} 条`);
      result.can_archive.slice(0, 3).forEach(m => lines.push(`   - ${m.text}`));
      lines.push(`\n可合并: ${result.can_merge.length} 对`);
      result.can_merge.slice(0, 3).forEach(p => lines.push(`   - ${p.text1} ↔ ${p.text2}`));
      lines.push(`\n可提升重要性: ${result.can_boost.length} 条`);
      result.can_boost.slice(0, 3).forEach(m => lines.push(`   - ${m.text} (${m.current_importance} → ${m.suggested_importance})`));
      return { type: 'text', text: lines.join('\n') };
    }

    case 'usage-report': {
      const result = analyzer.usageReport(parseInt(args.days) || 7);
      if (args.json) return { type: 'json', data: result };
      const lines = [`📈 使用报告 (最近 ${result.period_days} 天)`, '', `总访问: ${result.total_accesses} 次`];
      lines.push(`日均: ${result.avg_daily} 次`);
      lines.push(`最活跃: ${result.most_active_day || 'N/A'}`);
      lines.push('\n每日访问:');
      for (const [date, count] of Object.entries(result.daily_access || {})) {
        const bar = '█'.repeat(Math.min(count, 20));
        lines.push(`   ${date}: ${bar} ${count}`);
      }
      lines.push('\n分类访问:');
      for (const [cat, count] of Object.entries(result.category_access || {})) {
        lines.push(`   ${cat || '未分类'}: ${count} 次`);
      }
      return { type: 'text', text: lines.join('\n') };
    }

    case 'score': {
      if (!args.id) return { error: '请提供 --id' };
      const result = analyzer.getMemoryScore(args.id);
      if (result.error) return { error: result.error };
      if (args.json) return { type: 'json', data: result };
      return {
        type: 'text',
        text: `📊 记忆评分\n\n内容: ${result.text}\n` +
          `评分: ${result.score} (${result.grade})\n\n` +
          `重要性: ${result.importance}\n` +
          `访问次数: ${result.access_count}\n` +
          `记忆年龄: ${result.age_days} 天`
      };
    }

    default:
      return { error: `未知命令: ${command}` };
  }
}

export default {
  MemoryUsageAnalyzer,
  cmdUsage
};
/**
 * v2 Patch - Migration utilities for v2 breaking changes
 */

const V2_MIGRATION = {
  renamedFields: { 'content': 'text', 'category_name': 'category', 'imp': 'importance', 'conf': 'confidence' },
  removedFields: ['embedding_vector', 'vector_id', 'metadata_raw'],
  newFields: ['source', 'expires_at', 'project'],
};

export function migrateMemory(memory) {
  return {
    id: memory.id || `mem_${Date.now()}`,
    text: memory.content || '',
    category: memory.category_name || 'general',
    importance: memory.imp ?? 0.5,
    confidence: memory.conf ?? 0.8,
    tags: Array.isArray(memory.tags_arr) ? memory.tags_arr : [],
    project: 'default',
    created_at: memory.created_time || new Date().toISOString(),
    updated_at: memory.updated_time || new Date().toISOString(),
    access_count: 0,
    source: 'imported',
    metadata: {},
  };
}

export function needsMigration(memory) {
  return memory.content !== undefined || memory.category_name !== undefined;
}

export function getMigrationReport(memories) {
  let v1Count = 0, v2Count = 0;
  for (const mem of memories) {
    if (needsMigration(mem)) v1Count++;
    else v2Count++;
  }
  return { total: memories.length, v1Count, v2Count, needsMigration: v1Count };
}

