/**
 * Vector Backends - Multiple vector database backends
 */

export const BACKEND_NOTICE = `
🔢 Vector Backend Options for Node.js

1. LanceDB (RECOMMENDED)
   - npm install vectordb

2. sqlite-vec (OpenClaw built-in)
   - Automatic via OpenClaw

3. Qdrant (external service)
   - Requires running Qdrant server

NOT AVAILABLE: FAISS (C++ only)
`;

export class MemoryVectorStore {
  constructor() { this.vectors = new Map(); }
  
  async add(items) { for (const item of items) this.vectors.set(item.id, { vector: item.vector, data: item.data }); }
  
  async search(query, topK = 5) {
    const results = [];
    for (const [id, { vector, data }] of this.vectors) {
      results.push({ id, score: this.cosineSimilarity(query, vector), data });
    }
    return results.sort((a, b) => b.score - a.score).slice(0, topK);
  }
  
  async delete(ids) { for (const id of ids) this.vectors.delete(id); }
  async count() { return this.vectors.size; }
  
  cosineSimilarity(a, b) {
    if (a.length !== b.length) return 0;
    let dotProduct = 0, normA = 0, normB = 0;
    for (let i = 0; i < a.length; i++) { dotProduct += a[i] * b[i]; normA += a[i] * a[i]; normB += b[i] * b[i]; }
    const denominator = Math.sqrt(normA) * Math.sqrt(normB);
    return denominator > 0 ? dotProduct / denominator : 0;
  }
}

if (require.main === module) { console.log(BACKEND_NOTICE); }
/**
 * Vision Module - Image understanding via Ollama vision models
 * 
 * Supports:
 * - Ollama vision models (llava, llava-llama3, etc.)
 * - Cloudflare Workers AI (optional fallback)
 * 
 * Extracts: objects, text_in_image, scene_description, people, activities
 * Stores description as memory with category='visual'
 */

import { readFileSync, existsSync } from 'fs';
import { join } from 'path';
import { config } from '../config.js';
import { addMemory } from '../storage.js';

/** @returns {{ baseURL: string, model: string }} */
function getVisionProvider() {
  const ollamaBase = process.env.OLLAMA_BASE_URL || process.env.OLLAMA_HOST || 'http://localhost:11434';
  const model = process.env.OLLAMA_VISION_MODEL || 'llava';
  return { baseURL: ollamaBase, model };
}

/**
 * Read image file and return base64 string
 * @param {string} imagePath
 * @returns {string|null}
 */
function readImageBase64(imagePath) {
  try {
    // Support relative and absolute paths
    const absolutePath = imagePath.startsWith('/') ? imagePath : join(process.cwd(), imagePath);
    if (!existsSync(absolutePath)) {
      // Try workspace path
      const workspacePath = join(process.env.HOME || '/root', '.openclaw', 'workspace', imagePath);
      if (existsSync(workspacePath)) {
        const buffer = readFileSync(workspacePath);
        return buffer.toString('base64');
      }
      return null;
    }
    const buffer = readFileSync(absolutePath);
    return buffer.toString('base64');
  } catch {
    return null;
  }
}

/**
 * Check if Ollama vision model is available
 * @returns {Promise<boolean>}
 */
async function isVisionModelAvailable() {
  try {
    const { baseURL, model } = getVisionProvider();
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), 3000);
    const res = await fetch(`${baseURL}/api/tags`, { signal: controller.signal });
    clearTimeout(timer);
    if (!res.ok) return false;
    const json = await res.json();
    const models = json.models || json.user_defined_models || [];
    // Check if any available model is vision-capable (llava variants)
    const visionKeywords = ['llava', 'llava-llama3', 'moondream', 'vision'];
    return models.some(m => {
      const name = (m.name || '').toLowerCase();
      return visionKeywords.some(k => name.includes(k));
    }) || models.some(m => (m.name || '').includes(model));
  } catch {
    return false;
  }
}

/**
 * Analyze image using Ollama vision model
 * @param {string} imagePath - Image file path
 * @param {string} [imageBase64] - Optional base64 image data
 * @returns {Promise<{objects: string[], text_in_image: string, scene_description: string, people: string[], activities: string[]}>}
 */
async function analyzeImageWithOllama(imagePath, imageBase64) {
  const { baseURL, model } = getVisionProvider();
  
  // Get base64 from file if not provided
  const base64 = imageBase64 || readImageBase64(imagePath);
  if (!base64) {
    throw new Error(`Image not found: ${imagePath}`);
  }

  const prompt = `You are an expert image analyzer. Analyze this image and respond ONLY with a valid JSON object (no markdown, no explanation). Format:
{
  "objects": ["list of distinct objects detected"],
  "text_in_image": "any text visible in the image, or empty string if none",
  "scene_description": "brief description of the scene/setting",
  "people": ["names or descriptions of any people, or empty array"],
  "activities": ["actions or activities happening in the image, or empty array"]
}`;

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 30000);

  try {
    // Try /api/chat endpoint first (newer Ollama versions)
    const chatRes = await fetch(`${baseURL}/api/chat`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model,
        messages: [
          {
            role: 'user',
            content: prompt,
            images: [base64],
          }
        ],
        stream: false,
      }),
      signal: controller.signal,
    });

    clearTimeout(timer);

    if (chatRes.ok) {
      const json = await chatRes.json();
      const raw = json.message?.content || json.response || '';
      return parseVisionResponse(raw);
    }

    // Fallback to /api/generate
    const genRes = await fetch(`${baseURL}/api/generate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model,
        prompt,
        images: [base64],
        stream: false,
        options: { temperature: 0.1 },
      }),
      signal: controller.signal,
    });

    if (!genRes.ok) {
      throw new Error(`Ollama vision API error: ${genRes.status} ${genRes.statusText}`);
    }

    const json = await genRes.json();
    return parseVisionResponse(json.response || '');
  } catch (err) {
    clearTimeout(timer);
    throw err;
  }
}

/**
 * Parse the raw vision response into structured data
 * @param {string} raw
 * @returns {{objects: string[], text_in_image: string, scene_description: string, people: string[], activities: string[]}}
 */
function parseVisionResponse(raw) {
  try {
    // Try JSON parse directly
    const parsed = JSON.parse(raw);
    return {
      objects: Array.isArray(parsed.objects) ? parsed.objects : [],
      text_in_image: parsed.text_in_image || '',
      scene_description: parsed.scene_description || '',
      people: Array.isArray(parsed.people) ? parsed.people : [],
      activities: Array.isArray(parsed.activities) ? parsed.activities : [],
    };
  } catch {
    // Try to extract JSON from the raw text
    const jsonMatch = raw.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        const parsed = JSON.parse(jsonMatch[0]);
        return {
          objects: Array.isArray(parsed.objects) ? parsed.objects : [],
          text_in_image: parsed.text_in_image || '',
          scene_description: parsed.scene_description || '',
          people: Array.isArray(parsed.people) ? parsed.people : [],
          activities: Array.isArray(parsed.activities) ? parsed.activities : [],
        };
      } catch { /* fall through */ }
    }

    // Fallback: treat entire response as scene description
    return {
      objects: [],
      text_in_image: '',
      scene_description: raw.trim(),
      people: [],
      activities: [],
    };
  }
}

/**
 * Main vision analysis function
 * @param {object} params
 * @param {string} [params.imagePath] - Path to image file
 * @param {string} [params.imageBase64] - Base64-encoded image data
 * @param {boolean} [params.storeMemory] - Whether to store as memory (default: true)
 * @param {number} [params.importance] - Memory importance 0-1 (default: 0.5)
 * @param {string[]} [params.tags] - Additional tags for the memory
 * @returns {Promise<{analysis: object, memory_id: string|null, error: string|null}>}
 */
export async function analyzeImage({ imagePath, imageBase64, storeMemory = true, importance = 0.5, tags = [] }) {
  try {
    if (!imagePath && !imageBase64) {
      return { analysis: null, memory_id: null, error: 'Either imagePath or imageBase64 is required' };
    }

    const available = await isVisionModelAvailable();
    if (!available) {
      return {
        analysis: null,
        memory_id: null,
        error: 'No vision model available in Ollama. Please install llava: `ollama pull llava`',
      };
    }

    const analysis = await analyzeImageWithOllama(imagePath, imageBase64);

    // Build descriptive text for memory
    const parts = [];
    if (analysis.scene_description) parts.push(`Scene: ${analysis.scene_description}`);
    if (analysis.objects.length > 0) parts.push(`Objects: ${analysis.objects.join(', ')}`);
    if (analysis.text_in_image) parts.push(`Text: ${analysis.text_in_image}`);
    if (analysis.people.length > 0) parts.push(`People: ${analysis.people.join(', ')}`);
    if (analysis.activities.length > 0) parts.push(`Activities: ${analysis.activities.join(', ')}`);

    const description = parts.join(' | ');

    let memoryId = null;
    if (storeMemory && description) {
      const memory = addMemory({
        text: `[Visual Analysis] ${description}`,
        category: 'visual',
        importance,
        tags: ['visual', 'image', ...tags],
      });
      memoryId = memory.id;
    }

    return {
      analysis: {
        ...analysis,
        imagePath,
        description,
        stored: storeMemory,
      },
      memory_id: memoryId,
      error: null,
    };
  } catch (err) {
    return {
      analysis: null,
      memory_id: null,
      error: err.message || String(err),
    };
  }
}

export default { analyzeImage };
/**
 * src/decay/weibull_decay.js
 * Weibull 衰减模型 - 比指数衰减更接近人类遗忘曲线
 * 
 * Weibull 分布参数:
 * - shape (k): 形状参数，通常 1.5-3.0。k 越大，衰减越慢（记忆越持久）
 * - scale (λ): 尺度参数，通常 30-90 天。决定"半衰期"附近的衰减速度
 * 
 * 公式: strength(t) = exp(-(t/λ)^k) + access_bonus
 * 
 * 访问奖励: 每次访问增加 5% 强度，上限 +50%
 */

import { config } from '../config.js';

export class WeibullDecayModel {
  /**
   * @param {Object} opts
   * @param {number} [opts.shape=1.5] - 形状参数 k
   * @param {number} [opts.scale=30] - 尺度参数 λ（天数）
   */
  constructor({ shape, scale } = {}) {
    const weibullCfg = config.weibull_decay || {};
    this.shape = shape ?? weibullCfg.shape ?? 1.5;
    this.scale = scale ?? weibullCfg.scale ?? 30;
  }

  /**
   * 计算单条记忆的当前强度 (0-1)
   * 
   * @param {Object} params
   * @param {number} params.created_at - 记忆创建时间 (ms 时间戳)
   * @param {number} [params.last_access] - 最后访问时间 (ms 时间戳)，默认 now
   * @param {number} [params.access_count=0] - 访问次数
   * @returns {number} 强度值 0-1
   */
  getStrength({ created_at, last_access, access_count = 0 } = {}) {
    const now = Date.now();
    const last = last_access || now;
    
    // 记忆年龄（天数）
    const T = (last - created_at) / (1000 * 60 * 60 * 24);

    // Weibull 衰减
    const decay = Math.exp(-Math.pow(T / this.scale, this.shape));

    // 访问奖励（每访问一次 +5%，上限 50%）
    const accessBonus = Math.min((access_count || 0) * 0.05, 0.5);

    return Math.min(decay + accessBonus, 1.0);
  }

  /**
   * 获取需要淘汰的记忆
   * 
   * @param {Array} memories - 记忆数组
   * @param {Object} opts
   * @param {number} [opts.threshold=0.1] - 强度阈值，低于此值淘汰
   * @param {number} [opts.max_age_days=365] - 最大年龄，超过直接淘汰
   * @returns {Array} 需要淘汰的记忆
   */
  getPruneCandidates(memories, { threshold = 0.1, max_age_days = 365 } = {}) {
    return memories.filter(m => {
      const age_days = (Date.now() - m.created_at) / (1000 * 60 * 60 * 24);
      
      // 超过最大年龄直接淘汰
      if (age_days > max_age_days) return true;
      
      // 计算强度
      const strength = this.getStrength(m);
      return strength < threshold;
    });
  }

  /**
   * 获取强度分布统计
   */
  getStats(memories) {
    const buckets = {
      strong: 0,     // > 0.7
      moderate: 0,  // 0.3 - 0.7
      weak: 0,      // 0.1 - 0.3
      prune: 0,     // < 0.1
    };

    const strengths = memories.map(m => this.getStrength(m));

    for (const s of strengths) {
      if (s > 0.7) buckets.strong++;
      else if (s > 0.3) buckets.moderate++;
      else if (s > 0.1) buckets.weak++;
      else buckets.prune++;
    }

    return {
      shape: this.shape,
      scale: this.scale,
      total: memories.length,
      buckets,
      avgStrength: strengths.length 
        ? strengths.reduce((a, b) => a + b, 0) / strengths.length 
        : 0,
    };
  }
}

// 导出单例
let _instance = null;
export function getWeibullDecayModel(opts = {}) {
  if (!_instance) {
    _instance = new WeibullDecayModel(opts);
  }
  return _instance;
}
/**
 * src/decay/weibull_tools.js
 * Weibull 衰减统计工具
 */

import { z } from 'zod';
import { getWeibullDecayModel } from './weibull_decay.js';
import { getAllMemories } from '../storage.js';

export function registerDecayStatsTool(server) {

  server.registerTool('memory_decay_stats', {
    description: 'Show Weibull decay statistics: memory strength distribution across strong/moderate/weak/prune buckets. Helps understand memory health.',
    inputSchema: z.object({
      threshold: z.number().optional().default(0.1).describe('Prune threshold (default 0.1)'),
      maxAgeDays: z.number().optional().default(365).describe('Max age in days (default 365)'),
      shape: z.number().optional().describe('Weibull shape parameter (default from config 1.5)'),
      scale: z.number().optional().describe('Weibull scale parameter in days (default from config 30)'),
    }),
  }, async ({ threshold, maxAgeDays, shape, scale } = {}) => {
    try {
      const decayModel = getWeibullDecayModel({ shape, scale });
      const memories = await getAllMemories();
      
      const stats = decayModel.getStats(memories);
      const candidates = decayModel.getPruneCandidates(memories, { threshold, max_age_days: maxAgeDays });

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            model: 'Weibull',
            shape: decayModel.shape,
            scale: decayModel.scale,
            threshold,
            maxAgeDays,
            totalMemories: memories.length,
            strengthDistribution: stats.buckets,
            avgStrength: Math.round(stats.avgStrength * 1000) / 1000,
            pruneCandidates: candidates.length,
            candidatesPreview: candidates.slice(0, 5).map(m => ({
              id: m.id || m._id,
              content: (m.content || '').slice(0, 80),
              strength: Math.round(decayModel.getStrength(m) * 1000) / 1000,
            })),
          }, null, 2)
        }]
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Decay stats error: ${err.message}` }], isError: true };
    }
  });

  server.registerTool('memory_decay_strength', {
    description: 'Get the Weibull strength score for a specific memory.',
    inputSchema: z.object({
      memory_id: z.string().describe('Memory ID to check strength for'),
    }),
  }, async ({ memory_id }) => {
    try {
      const { getMemory } = await import('../storage.js');
      const memory = await getMemory(memory_id);
      if (!memory) {
        return { content: [{ type: 'text', text: `Memory not found: ${memory_id}` }], isError: true };
      }
      const decayModel = getWeibullDecayModel();
      const strength = decayModel.getStrength(memory);
      const pruneCandidates = decayModel.getPruneCandidates([memory]);
      
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            memory_id,
            strength: Math.round(strength * 1000) / 1000,
            shouldPrune: pruneCandidates.length > 0,
            model: 'Weibull',
            shape: decayModel.shape,
            scale: decayModel.scale,
          }, null, 2)
        }]
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });
}
/**
 * Episode Store v2 - Persistent storage for conversation episodes (v2 schema)
 *
 * Episode = a self-contained conversation unit around a single topic.
 * Default 8 turns, auto-splits when exceeded.
 *
 * Storage: memory/episodes.json
 * Schema:
 * {
 *   episodes: Episode[],
 *   metadata: { version, lastUpdated }
 * }
 *
 * Episode {
 *   id: "ep_<hash>",
 *   topic: "刘总问unified-memory功能",
 *   started_at: "2026-03-28T10:00:00+08:00",
 *   ended_at: "2026-03-28T10:30:00+08:00",
 *   turns: 12,           // conversation rounds (user+assistant)
 *   message_count: 24,  // raw message count
 *   memory_ids: [],     // associated memory IDs
 *   entities: [],       // extracted entities
 *   last_refresh: "...",
 *   status: "active" | "completed"
 * }
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { config } from '../config.js';

const __dirname = fileURLToPath(new URL('.', import.meta.url));
const EPISODE_FILE = path.join(config.memoryDir, 'episodes.json');

const EPISODE_STATUS = {
  ACTIVE: 'active',
  COMPLETED: 'completed',
};

const DEFAULT_MAX_TURNS = 8;

// ─── File I/O ────────────────────────────────────────────────────────────────

function ensureDir() {
  if (!existsSync(config.memoryDir)) {
    mkdirSync(config.memoryDir, { recursive: true });
  }
}

function loadEpisodes() {
  ensureDir();
  if (!existsSync(EPISODE_FILE)) {
    return createEmptyStore();
  }
  try {
    const raw = JSON.parse(readFileSync(EPISODE_FILE, 'utf-8'));
    return {
      episodes: Array.isArray(raw.episodes) ? raw.episodes : [],
      metadata: raw.metadata || { version: '2.0', lastUpdated: Date.now() },
    };
  } catch {
    return createEmptyStore();
  }
}

function createEmptyStore() {
  return {
    episodes: [],
    metadata: { version: '2.0', lastUpdated: Date.now() },
  };
}

function saveEpisodes(store) {
  ensureDir();
  store.metadata.lastUpdated = Date.now();
  writeFileSync(EPISODE_FILE, JSON.stringify(store, null, 2), 'utf-8');
}

function getStore() {
  return loadEpisodes();
}

// ─── ID Generation ───────────────────────────────────────────────────────────

function generateId(topic) {
  const seed = `${topic || 'untitled'}_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
  const hash = seed.split('').reduce((acc, c) => ((acc << 5) - acc + c.charCodeAt(0)) | 0, 0);
  return `ep_${Math.abs(hash).toString(36).slice(0, 12)}`;
}

// ─── Episode CRUD ───────────────────────────────────────────────────────────

/**
 * Create a new episode
 * @param {string} topic - Episode topic/title
 * @param {object} [opts]
 * @param {string[]} [opts.entities] - Pre-extracted entities
 * @returns {object} New episode
 */
export function createEpisode(topic, opts = {}) {
  const store = getStore();
  const now = new Date().toISOString();

  // End any existing active episode first
  const active = store.episodes.find(e => e.status === EPISODE_STATUS.ACTIVE);
  if (active) {
    endEpisodeInternal(store, active.id);
  }

  /** @type {object} */
  const episode = {
    id: generateId(topic),
    topic: topic || 'Untitled Episode',
    started_at: now,
    ended_at: null,
    turns: 0,
    message_count: 0,
    memory_ids: [],
    entities: opts.entities || [],
    last_refresh: now,
    status: EPISODE_STATUS.ACTIVE,
  };

  store.episodes.push(episode);
  saveEpisodes(store);
  return episode;
}

/**
 * End an episode — marks completed and generates a summary
 * @param {string} id - Episode ID
 * @returns {object|null} Updated episode or null if not found
 */
export function endEpisode(id) {
  const store = getStore();
  const updated = endEpisodeInternal(store, id);
  if (updated) saveEpisodes(store);
  return updated;
}

function endEpisodeInternal(store, id) {
  const episode = store.episodes.find(e => e.id === id);
  if (!episode || episode.status !== EPISODE_STATUS.ACTIVE) return null;

  const now = new Date().toISOString();
  episode.ended_at = now;
  episode.status = EPISODE_STATUS.COMPLETED;
  episode.last_refresh = now;
  return episode;
}

/**
 * Update episode fields
 * @param {string} id
 * @param {object} updates - Allowed: topic, entities, memory_ids, last_refresh
 * @returns {boolean}
 */
export function updateEpisode(id, updates) {
  const store = getStore();
  const episode = store.episodes.find(e => e.id === id);
  if (!episode) return false;

  const allowed = ['topic', 'entities', 'memory_ids', 'last_refresh', 'turns', 'message_count'];
  for (const key of allowed) {
    if (key in updates) episode[key] = updates[key];
  }
  episode.last_refresh = new Date().toISOString();
  saveEpisodes(store);
  return true;
}

/**
 * Get the currently active episode (if any)
 * @returns {object|null}
 */
export function getActiveEpisode() {
  const store = getStore();
  return store.episodes.find(e => e.status === EPISODE_STATUS.ACTIVE) || null;
}

/**
 * Get episode by ID
 * @param {string} id
 * @returns {object|null}
 */
export function getEpisode(id) {
  const store = getStore();
  return store.episodes.find(e => e.id === id) || null;
}

/**
 * Auto-split an episode if turns exceed maxTurns.
 * Creates a new episode continuing the same topic.
 * Returns { original, newEpisode }
 * @param {string} id - Episode ID to check
 * @param {number} [maxTurns] - Threshold for split (default 8)
 * @returns {object|null} null if no split needed, or { original, newEpisode }
 */
export function autoSplitEpisode(id, maxTurns = DEFAULT_MAX_TURNS) {
  const store = getStore();
  const episode = store.episodes.find(e => e.id === id);
  if (!episode) return null;

  if (episode.turns <= maxTurns) return null;

  // Create continuation episode with same topic
  const now = new Date().toISOString();
  const newEpisode = {
    id: generateId(episode.topic),
    topic: episode.topic,
    started_at: now,
    ended_at: null,
    turns: 0,
    message_count: 0,
    memory_ids: [],
    entities: [...episode.entities],
    last_refresh: now,
    status: EPISODE_STATUS.ACTIVE,
  };

  // End the original
  episode.ended_at = now;
  episode.status = EPISODE_STATUS.COMPLETED;

  store.episodes.push(newEpisode);
  saveEpisodes(store);

  return { original: episode, newEpisode };
}

/**
 * List episodes with optional pagination and status filter
 * @param {object} [opts]
 * @param {string} [opts.status] - 'active' | 'completed'
 * @param {number} [opts.limit] - Default 20
 * @param {number} [opts.offset] - Default 0
 * @returns {{ episodes: object[], total: number }}
 */
export function listEpisodes(opts = {}) {
  const { status, limit = 20, offset = 0 } = opts;
  const store = getStore();

  let episodes = store.episodes;
  if (status) {
    episodes = episodes.filter(e => e.status === status);
  }

  // Sort by started_at desc (most recent first)
  episodes.sort((a, b) => new Date(b.started_at) - new Date(a.started_at));

  return {
    episodes: episodes.slice(offset, offset + limit),
    total: episodes.length,
  };
}

/**
 * Delete an episode by ID
 * @param {string} id
 * @returns {boolean}
 */
export function deleteEpisode(id) {
  const store = getStore();
  const idx = store.episodes.findIndex(e => e.id === id);
  if (idx === -1) return false;
  store.episodes.splice(idx, 1);
  saveEpisodes(store);
  return true;
}

/**
 * Merge two episodes into one
 * @param {string} id1
 * @param {string} id2
 * @returns {object|null} Merged episode or null on failure
 */
export function mergeEpisodes(id1, id2) {
  const store = getStore();
  const ep1 = store.episodes.find(e => e.id === id1);
  const ep2 = store.episodes.find(e => e.id === id2);
  if (!ep1 || !ep2) return null;

  // Merge: ep1 survives, ep2's memory_ids and entities merged in
  const mergedMemoryIds = [...new Set([...ep1.memory_ids, ...ep2.memory_ids])];
  const mergedEntities = [...new Set([...ep1.entities, ...ep2.entities])];
  const now = new Date().toISOString();

  ep1.ended_at = now;
  ep1.status = EPISODE_STATUS.COMPLETED;
  ep1.memory_ids = mergedMemoryIds;
  ep1.entities = mergedEntities;
  ep1.last_refresh = now;

  // Remove ep2
  store.episodes = store.episodes.filter(e => e.id !== id2);
  saveEpisodes(store);
  return ep1;
}

// recallEpisodeAsync: full context including associated memories
export async function recallEpisodeAsync(id) {
  const episode = getEpisode(id);
  if (!episode) return null;

  let memories = [];
  try {
    const { getAllMemories: getM } = await import('../storage.js');
    const all = getM();
    memories = all.filter(m => episode.memory_ids.includes(m.id));
  } catch {
    memories = [];
  }

  return { episode, memories };
}

// recallEpisode: sync version (no memory lookup)
export function recallEpisode(id) {
  return getEpisode(id);
}

export { EPISODE_STATUS, DEFAULT_MAX_TURNS };
export default {
  createEpisode,
  endEpisode,
  updateEpisode,
  getActiveEpisode,
  getEpisode,
  autoSplitEpisode,
  listEpisodes,
  deleteEpisode,
  mergeEpisodes,
  recallEpisode,
  recallEpisodeAsync,
  EPISODE_STATUS,
  DEFAULT_MAX_TURNS,
};
/**
 * Episode Tools v2 — MCP tool definitions for Episode management
 *
 * 5 tools matching the v2 spec:
 * - memory_episode_start: Start a new episode
 * - memory_episode_end: End current active episode, generate summary
 * - memory_episode_list: List all episodes (paginated)
 * - memory_episode_recall: Recall full context of a specific episode
 * - memory_episode_merge: Merge two episodes into one
 *
 * Based on the Episode schema:
 * {
 *   id, topic, started_at, ended_at,
 *   turns, message_count,
 *   memory_ids, entities,
 *   last_refresh, status
 * }
 */

import { z } from 'zod';
import {
  createEpisode,
  endEpisode,
  updateEpisode,
  getActiveEpisode,
  getEpisode,
  autoSplitEpisode,
  listEpisodes,
  mergeEpisodes,
  recallEpisodeAsync,
  EPISODE_STATUS,
} from './episode_store.js';

/**
 * Register all episode tools with the MCP server
 * @param {object} server - MCP server instance (from @modelcontextprotocol/sdk)
 */
export function registerEpisodeTools(server) {

  // ─── memory_episode_start ──────────────────────────────────────────────────
  server.registerTool('memory_episode_start', {
    description: 'Start a new conversation episode. An episode represents a focused conversation session around a single topic. Automatically ends any existing active episode first.',
    inputSchema: z.object({
      topic: z.string().describe('Topic/title of the episode (e.g. "刘总问unified-memory功能")'),
    }),
  }, async ({ topic }) => {
    try {
      const episode = createEpisode(topic);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: true,
            episode: {
              id: episode.id,
              topic: episode.topic,
              started_at: episode.started_at,
              turns: episode.turns,
              message_count: episode.message_count,
              status: episode.status,
            },
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_end ────────────────────────────────────────────────────
  server.registerTool('memory_episode_end', {
    description: 'End the current active episode and generate a summary. Extracts key topics, decisions, and entities from the conversation.',
    inputSchema: z.object({
      episodeId: z.string().optional().describe('Episode ID to end. If omitted, ends the current active episode.'),
    }),
  }, async ({ episodeId }) => {
    try {
      let targetId = episodeId;

      // If no ID provided, find active episode
      if (!targetId) {
        const active = getActiveEpisode();
        if (!active) {
          return {
            content: [{
              type: 'text',
              text: JSON.stringify({ success: false, error: 'No active episode to end' }),
            }],
            isError: false,
          };
        }
        targetId = active.id;
      }

      const updated = endEpisode(targetId);
      if (!updated) {
        return { content: [{ type: 'text', text: JSON.stringify({ success: false, error: 'Episode not found or already ended' }) }], isError: true };
      }

      // Extract summary data from topic and entities
      const summary = generateEpisodeSummary(updated);

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: true,
            episode: {
              id: updated.id,
              topic: updated.topic,
              started_at: updated.started_at,
              ended_at: updated.ended_at,
              turns: updated.turns,
              message_count: updated.message_count,
              status: updated.status,
              entities: updated.entities,
            },
            summary,
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_list ───────────────────────────────────────────────────
  server.registerTool('memory_episode_list', {
    description: 'List all episodes with optional pagination and status filter.',
    inputSchema: z.object({
      status: z.enum(['active', 'completed']).optional().describe("Filter by status: 'active' or 'completed'"),
      limit: z.number().optional().default(20).describe('Number of episodes to return (default 20)'),
      offset: z.number().optional().default(0).describe('Offset for pagination (default 0)'),
    }),
  }, async ({ status, limit = 20, offset = 0 }) => {
    try {
      const result = listEpisodes({ status, limit, offset });

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            total: result.total,
            offset,
            limit,
            episodes: result.episodes.map(ep => ({
              id: ep.id,
              topic: ep.topic,
              started_at: ep.started_at,
              ended_at: ep.ended_at,
              turns: ep.turns,
              message_count: ep.message_count,
              entities: ep.entities,
              status: ep.status,
              last_refresh: ep.last_refresh,
            })),
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_recall ─────────────────────────────────────────────────
  server.registerTool('memory_episode_recall', {
    description: 'Recall the full context of a specific episode including associated memories.',
    inputSchema: z.object({
      episodeId: z.string().describe('Episode ID to recall'),
    }),
  }, async ({ episodeId }) => {
    try {
      const result = await recallEpisodeAsync(episodeId);

      if (!result) {
        return { content: [{ type: 'text', text: JSON.stringify({ success: false, error: 'Episode not found' }) }], isError: true };
      }

      const { episode, memories } = result;

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: true,
            episode: {
              id: episode.id,
              topic: episode.topic,
              started_at: episode.started_at,
              ended_at: episode.ended_at,
              turns: episode.turns,
              message_count: episode.message_count,
              memory_ids: episode.memory_ids,
              entities: episode.entities,
              last_refresh: episode.last_refresh,
              status: episode.status,
            },
            memories: memories.map(m => ({
              id: m.id,
              text: m.text,
              category: m.category,
              importance: m.importance,
              created_at: m.created_at,
            })),
            memory_count: memories.length,
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_merge ──────────────────────────────────────────────────
  server.registerTool('memory_episode_merge', {
    description: 'Merge two episodes into one. The first episode survives; the second is deleted. All memory IDs and entities from both are combined.',
    inputSchema: z.object({
      episodeId1: z.string().describe('First episode ID (will be the surviving episode)'),
      episodeId2: z.string().describe('Second episode ID (will be deleted after merge)'),
    }),
  }, async ({ episodeId1, episodeId2 }) => {
    try {
      if (episodeId1 === episodeId2) {
        return { content: [{ type: 'text', text: JSON.stringify({ success: false, error: 'Cannot merge an episode with itself' }) }], isError: true };
      }

      const merged = mergeEpisodes(episodeId1, episodeId2);

      if (!merged) {
        return { content: [{ type: 'text', text: JSON.stringify({ success: false, error: 'One or both episodes not found' }) }], isError: true };
      }

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: true,
            merged: {
              id: merged.id,
              topic: merged.topic,
              started_at: merged.started_at,
              ended_at: merged.ended_at,
              turns: merged.turns,
              message_count: merged.message_count,
              memory_ids: merged.memory_ids,
              entities: merged.entities,
              status: merged.status,
            },
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });
}

// ─── Helpers ────────────────────────────────────────────────────────────────

/**
 * Generate a human-readable summary from episode metadata
 * @param {object} episode
 * @returns {object}
 */
function generateEpisodeSummary(episode) {
  const lines = [];
  if (episode.entities && episode.entities.length) {
    lines.push(`涉及实体: ${episode.entities.join(', ')}`);
  }
  lines.push(`总轮次: ${episode.turns} turns, ${episode.message_count} 条消息`);

  return {
    topic: episode.topic,
    entities: episode.entities || [],
    turns: episode.turns,
    message_count: episode.message_count,
    description: lines.join(' | '),
  };
}

// Aliases for consistent naming (episodes can be "started" or "created", "ended" or "completed")
export { createEpisode as startEpisode };
export { endEpisode as completeEpisode };

export default { registerEpisodeTools };
/**
 * Entity Extraction - 从记忆文本中提取实体
 * 支持：PERSON, ORGANIZATION, PROJECT, TOPIC, TOOL, LOCATION, DATE, EVENT
 *
 * @module graph/entity
 */

import { createHash } from 'crypto';
import { config } from '../config.js';

// 实体类型定义
export const ENTITY_TYPES = {
  PERSON: 'person',
  ORGANIZATION: 'organization',
  PROJECT: 'project',
  TOPIC: 'topic',
  TOOL: 'tool',
  LOCATION: 'location',
  DATE: 'date',
  EVENT: 'event',
};

// 生成实体唯一 ID: ent_${hash(name+type).slice(0,8)}
export function generateEntityId(name, type) {
  const hash = createHash('md5').update(`${name}::${type}`).digest('hex');
  return `ent_${hash.slice(0, 8)}`;
}

/**
 * 规则预提取（正则）：@人名、#项目、##主题、日期、组织名
 * @param {string} text
 * @returns {Array<{ name: string, type: string, method: 'rule' }>}
 */
export function extractEntitiesRuleBased(text) {
  /** @type {Array<{ name: string, type: string, method: string }>} */
  const entities = [];

  // @xxx → person
  const atMentions = text.match(/@([^\s@,，、。！？!?,.\n]+)/g) || [];
  for (const m of atMentions) {
    const name = m.slice(1);
    if (name.length > 0 && name.length < 50) {
      entities.push({ name, type: ENTITY_TYPES.PERSON, method: 'rule' });
    }
  }

  // #xxx → topic 或 project（通过上下文判断）
  const hashtags = text.match(/#([^\s#,，、。！？!?,.\n]+)/g) || [];
  for (const m of hashtags) {
    const name = m.slice(1);
    if (name.length > 0 && name.length < 50) {
      const lower = name.toLowerCase();
      const type = lower.includes('project') || lower.includes('项目') || lower.includes('任务')
        ? ENTITY_TYPES.PROJECT
        : ENTITY_TYPES.TOPIC;
      entities.push({ name, type, method: 'rule' });
    }
  }

  // 中文关键词识别：飞书、钉钉、OpenClaw、MetaGPT 等（用已有 toolKeywords 更安全）
  // 中文姓名用 @ 提及更可靠，不再用正则猜测

  // 组织/公司名：xxx有限公司、xxx实验室、xxx公司、xxx团队、xxx部门
  const orgPatterns = [
    /([^\s]{2,20})(?:有限公司|股份有限公司|Ltd\.?|Inc\.?|Corp\.?|实验室|研究院|研究所|团队|部门|公司|机构|组织)/g,
  ];
  for (const pat of orgPatterns) {
    let match;
    pat.lastIndex = 0;
    while ((match = pat.exec(text)) !== null) {
      const name = match[1].trim();
      if (name.length > 1) {
        entities.push({ name, type: ENTITY_TYPES.ORGANIZATION, method: 'rule' });
      }
    }
  }

  // 日期：YYYY年MM月DD日、YYYY-MM-DD、MM/DD/YYYY、MM月DD日、今天/明天/昨天
  const datePatterns = [
    /(\d{4}年\d{1,2}月\d{1,2}日)/g,
    /(\d{4}-\d{2}-\d{2})/g,
    /(\d{1,2}\/\d{1,2}\/\d{4})/g,
    /(\d{1,2}月\d{1,2}日)/g,
    /(今天|明天|昨天|后天|前天|大前天|大后天)/g,
    /(周一|周二|周三|周四|周五|周六|周日|星期一|星期二|星期三|星期四|星期五|星期六|星期日)/g,
  ];
  for (const pat of datePatterns) {
    let match;
    pat.lastIndex = 0;
    while ((match = pat.exec(text)) !== null) {
      const name = match[1];
      entities.push({ name, type: ENTITY_TYPES.DATE, method: 'rule' });
    }
  }

  // 工具类关键词
  const toolKeywords = [
    '飞书', '钉钉', 'Slack', '微信', 'QQ', '企业微信', 'Teams', 'Telegram',
    'VSCode', 'Vim', 'Neovim', 'Emacs', 'Sublime', 'JetBrains',
    'GitHub', 'GitLab', 'Gitee', 'Jira', 'Notion', 'Figma', 'Sketch',
    'Docker', 'Kubernetes', 'k8s', 'Nginx', 'Redis', 'MongoDB', 'MySQL', 'PostgreSQL',
    'Python', 'JavaScript', 'TypeScript', 'Go', 'Rust', 'Java', 'C++', 'Ruby',
    'Ollama', 'OpenAI', 'Claude', 'DeepSeek', 'Qwen', 'Kimi', 'ChatGPT', 'Cursor',
    'npm', 'yarn', 'pnpm', 'pip', 'conda', 'brew',
  ];
  for (const tool of toolKeywords) {
    const escaped = tool.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regex = new RegExp(`\\b${escaped}\\b`, 'gi');
    let match;
    while ((match = regex.exec(text)) !== null) {
      entities.push({ name: tool, type: ENTITY_TYPES.TOOL, method: 'rule' });
    }
  }

  // 事件关键词
  const eventKeywords = [
    '会议', 'meeting', '讨论', '评审', '面试', '发布会', '发布', '上线', '版本发布',
    'debug', '重构', '迁移', '部署', '培训', '周会', '例会', '头脑风暴',
  ];
  for (const kw of eventKeywords) {
    const escaped = kw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regex = new RegExp(`\\b${escaped}\\b`, 'gi');
    let match;
    while ((match = regex.exec(text)) !== null) {
      entities.push({ name: kw, type: ENTITY_TYPES.EVENT, method: 'rule' });
    }
  }

  return entities;
}

/**
 * 调用 LLM 二次提取（更精准）
 * @param {string} text
 * @param {object} context
 * @returns {Promise<Array<{ name: string, type: string, method: 'llm' }>>}
 */
export async function extractEntitiesLLM(text, context = {}) {
  const providers = config.llmProviders || [];
  if (providers.length === 0) {
    return [];
  }

  const provider = providers[0];
  const url = `${provider.baseURL}/api/generate`;

  const prompt = `从以下文本中提取所有实体（人物、组织、项目、主题、工具、地点、日期、事件），返回 JSON 数组格式。

要求：
- 每条实体包含：name（名称）、type（类型，可选值：person/organization/project/topic/tool/location/date/event）
- 只返回你知道确实存在的实体，不要猜测
- 如果不确定类型，优先使用最具体的类型
- 返回纯 JSON 数组，不要其他文字

文本：
${text.slice(0, 2000)}

返回格式示例：
[
  {"name": "刘总", "type": "person"},
  {"name": "OpenClaw", "type": "project"},
  {"name": "飞书", "type": "tool"}
]`;

  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 30000);

    const res = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: provider.model,
        prompt,
        stream: false,
        options: { temperature: 0.1 },
      }),
      signal: controller.signal,
    });

    clearTimeout(timeout);

    if (!res.ok) return [];

    const data = await res.json();
    const response = data.response || data.output || '';

    // Try to extract JSON from response
    let jsonStr = response.trim();
    const jsonMatch = jsonStr.match(/\[[\s\S]*\]/);
    if (jsonMatch) {
      jsonStr = jsonMatch[0];
    }

    const extracted = JSON.parse(jsonStr);
    if (!Array.isArray(extracted)) return [];

    return extracted
      .filter(e => e.name && e.type && Object.values(ENTITY_TYPES).includes(e.type))
      .map(e => ({ name: e.name.trim(), type: e.type, method: 'llm' }));
  } catch (err) {
    // Fallback silently
    return [];
  }
}

/**
 * 规则 + LLM 混合提取
 * @param {string} text
 * @param {object} options
 * @returns {Promise<Array<{ id: string, name: string, type: string, method: string }>>}
 */
export async function extractEntities(text, options = {}) {
  const { useLLM = true } = options;

  // 1. 规则预提取
  const ruleEntities = extractEntitiesRuleBased(text);

  // 2. LLM 二次提取（可选）
  let llmEntities = [];
  if (useLLM && text.length >= 10) {
    llmEntities = await extractEntitiesLLM(text, options);
  }

  // 3. 合并去重
  const merged = [...ruleEntities, ...llmEntities];
  const deduped = mergeDuplicateEntities(merged);

  // 4. 添加 ID
  return deduped.map(e => ({
    id: generateEntityId(e.name, e.type),
    name: e.name,
    type: e.type,
    method: e.method,
  }));
}

/**
 * 实体消歧（同义实体合并）
 * 基于精确匹配 + 类型相同合并
 * @param {Array<{ name: string, type: string, method?: string }>} entities
 * @returns {Array<{ name: string, type: string, method: string }>}
 */
export function mergeDuplicateEntities(entities) {
  /** @type {Map<string, { name: string, type: string, method: string, count: number }>} */
  const map = new Map();

  for (const e of entities) {
    // Normalize: trim + lowercase for comparison
    const key = `${e.name.trim()}::${e.type}`;
    if (map.has(key)) {
      map.get(key).count++;
    } else {
      map.set(key, { name: e.name.trim(), type: e.type, method: e.method || 'rule', count: 1 });
    }
  }

  return Array.from(map.values()).map(({ name, type, method, count }) => ({
    name,
    type,
    method,
    count,
  }));
}
