/**
 * Memory Integration - 系统集成
 * 
 * Ported from memory_integration.py
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'fs';
import { join } from 'path';

const HOME = process.env.HOME || '/root';
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const INTEGRATION_DIR = join(MEMORY_DIR, 'integration');

// ============================================================
// Integrations
// ============================================================

const INTEGRATIONS = {
  feishu: {
    name: '飞书',
    description: '飞书消息、文档、日程集成',
    events: ['message', 'doc_created', 'calendar_event']
  },
  qq: {
    name: 'QQ',
    description: 'QQ消息集成',
    events: ['message']
  },
  wechat: {
    name: '微信',
    description: '微信消息集成',
    events: ['message']
  },
  github: {
    name: 'GitHub',
    description: 'GitHub PR/Issue 集成',
    events: ['pr_opened', 'pr_merged', 'issue_created']
  },
  notion: {
    name: 'Notion',
    description: 'Notion 页面同步',
    events: ['page_created', 'page_updated']
  }
};

// ============================================================
// IntegrationManager
// ============================================================

export class IntegrationManager {
  constructor() {
    mkdirSync(INTEGRATION_DIR, { recursive: true });
    this.configFile = join(INTEGRATION_DIR, 'config.json');
    this.logFile = join(INTEGRATION_DIR, 'events.jsonl');
    this.config = this._loadConfig();
  }

  _loadConfig() {
    if (existsSync(this.configFile)) {
      try { return JSON.parse(readFileSync(this.configFile, 'utf-8')); } catch { /* ignore */ }
    }
    return { enabled: {}, handlers: {} };
  }

  _saveConfig() {
    writeFileSync(this.configFile, JSON.stringify(this.config, null, 2), 'utf-8');
  }

  listIntegrations() {
    return Object.entries(INTEGRATIONS).map(([id, info]) => ({
      id,
      ...info,
      enabled: !!(this.config.enabled && this.config.enabled[id])
    }));
  }

  enable(integrationId) {
    if (!INTEGRATIONS[integrationId]) {
      return { success: false, error: '未知集成' };
    }
    if (!this.config.enabled) this.config.enabled = {};
    this.config.enabled[integrationId] = true;
    this._saveConfig();
    return { success: true };
  }

  disable(integrationId) {
    if (this.config.enabled) {
      delete this.config.enabled[integrationId];
    }
    this._saveConfig();
    return { success: true };
  }

  /**
   * Log an event from an integration
   * @param {string} integrationId
   * @param {string} eventType
   * @param {object} data
   */
  logEvent(integrationId, eventType, data) {
    const entry = {
      integration: integrationId,
      event_type: eventType,
      data,
      timestamp: new Date().toISOString()
    };
    const fs = require('fs');
    fs.appendFileSync(this.logFile, JSON.stringify(entry) + '\n', 'utf-8');
    return entry;
  }

  /**
   * Get recent events
   * @param {string} integrationId
   * @param {number} limit
   */
  getEvents(integrationId, limit = 50) {
    if (!existsSync(this.logFile)) return [];
    const lines = readFileSync(this.logFile, 'utf-8').split('\n').filter(Boolean);
    const events = [];
    for (const line of lines.slice(-limit)) {
      try {
        const entry = JSON.parse(line);
        if (!integrationId || entry.integration === integrationId) {
          events.push(entry);
        }
      } catch { /* skip */ }
    }
    return events.reverse();
  }

  getStatus() {
    const enabled = Object.keys(this.config.enabled || {}).filter(k => this.config.enabled[k]);
    return {
      total_integrations: Object.keys(INTEGRATIONS).length,
      enabled_count: enabled.length,
      enabled,
      integrations: this.listIntegrations()
    };
  }
}

export default { IntegrationManager, INTEGRATIONS };
/**
 * LLM Provider - 统一 LLM 调用接口 v1.0
 * 
 * 支持:
 * - OpenAI (GPT-4, GPT-3.5)
 * - Claude (Claude-3 Opus, Sonnet, Haiku)
 * - 智谱 AI (GLM-4)
 * - 百度千帆 (ERNIE)
 * - 阿里通义 (Qwen)
 * - Ollama (本地)
 * 
 * Usage:
 *     import { LLMProviderFactory } from './system/llm_provider.js';
 *     
 *     const llm = LLMProviderFactory.create("openai", { model: "gpt-4" });
 *     const response = await llm.generate("写一个贪吃蛇游戏");
 *     
 *     for await (const chunk of llm.stream("写一首诗")) {
 *       process.stdout.write(chunk);
 *     }
 */

// ============================================================
// Types & Interfaces
// ============================================================

/**
 * @typedef {Object} LLMResponse
 * @property {string} content - 响应内容
 * @property {string} model - 使用的模型
 * @property {number} tokensUsed - 总 token 数
 * @property {number} inputTokens - 输入 token 数
 * @property {number} outputTokens - 输出 token 数
 * @property {string} finishReason - 结束原因
 * @property {number} latency - 延迟（秒）
 * @property {string} provider - 提供商名称
 */

/**
 * @typedef {Object} Message
 * @property {string} role - system|user|assistant
 * @property {string} content - 消息内容
 */

// ============================================================
// Base Provider
// ============================================================

export class BaseLLMProvider {
  constructor(apiKey = null, model = null, baseUrl = null, config = {}) {
    this.apiKey = apiKey || this._getApiKey();
    this.model = model || this._getDefaultModel();
    this.baseUrl = baseUrl;
    this.config = config;
  }

  name = 'base';

  _getApiKey() {
    const envVar = `${this.name.toUpperCase()}_API_KEY`;
    return process.env[envVar] || null;
  }

  _getDefaultModel() {
    return 'unknown';
  }

  /**
   * Generate a response
   * @param {string} prompt
   * @param {string|undefined} system
   * @param {Message[]|undefined} messages
   * @param {Object} kwargs
   * @returns {Promise<LLMResponse>}
   */
  async generate(prompt, system = null, messages = null, ...kwargs) {
    throw new Error('Not implemented');
  }

  /**
   * Stream generate
   * @param {string} prompt
   * @param {string|undefined} system
   * @param {Message[]|undefined} messages
   * @param {Object} kwargs
   * @returns {AsyncGenerator<string>}
   */
  async *stream(prompt, system = null, messages = null, ...kwargs) {
    throw new Error('Not implemented');
  }

  _buildMessages(prompt, system, messages) {
    /** @type {Object[]} */
    const result = [];

    if (system) {
      result.push({ role: 'system', content: system });
    }

    if (messages) {
      for (const m of messages) {
        result.push({ role: m.role, content: m.content });
      }
    }

    if (prompt) {
      result.push({ role: 'user', content: prompt });
    }

    return result;
  }

  toDict() {
    return {
      name: this.name,
      model: this.model,
      baseUrl: this.baseUrl,
    };
  }
}

// ============================================================
// OpenAI Provider
// ============================================================

export class OpenAIProvider extends BaseLLMProvider {
  constructor(apiKey = null, model = null, baseUrl = null, ...kwargs) {
    super(apiKey, model, baseUrl, kwargs);
    this.name = 'openai';
  }

  _getDefaultModel() {
    return 'gpt-4';
  }

  async generate(prompt, system = null, messages = null, ...kwargs) {
    const start = Date.now();

    try {
      // Dynamic import for openai package
      const { default: OpenAI } = await import('openai');
      
      const client = new OpenAI({
        apiKey: this.apiKey,
        baseURL: this.baseUrl,
      });

      const msgList = this._buildMessages(prompt, system, messages);

      const response = await client.chat.completions.create({
        model: this.model,
        messages: msgList,
        ...kwargs,
      });

      return {
        content: response.choices[0].message.content,
        model: response.model,
        tokensUsed: response.usage.total_tokens,
        inputTokens: response.usage.prompt_tokens,
        outputTokens: response.usage.completion_tokens,
        finishReason: response.choices[0].finish_reason,
        latency: (Date.now() - start) / 1000,
        provider: this.name,
      };
    } catch (e) {
      return this._mockResponse(prompt, start, e.message);
    }
  }

  async *stream(prompt, system = null, messages = null, ...kwargs) {
    try {
      const { default: OpenAI } = await import('openai');
      
      const client = new OpenAI({
        apiKey: this.apiKey,
        baseURL: this.baseUrl,
      });

      const msgList = this._buildMessages(prompt, system, messages);

      const stream = await client.chat.completions.create({
        model: this.model,
        messages: msgList,
        stream: true,
        ...kwargs,
      });

      for await (const chunk of stream) {
        if (chunk.choices[0].delta.content) {
          yield chunk.choices[0].delta.content;
        }
      }
    } catch (e) {
      yield `[错误] ${e.message}`;
    }
  }

  _mockResponse(prompt, start, error = null) {
    const latency = (Date.now() - start) / 1000;
    const preview = prompt.length > 200 ? prompt.slice(0, 200) + '...' : prompt;
    return {
      content: error ? `[错误] ${error}` : `[模拟响应] 基于提示生成内容...\n\n提示: ${preview}`,
      model: this.model,
      tokensUsed: Math.floor(prompt.length / 4),
      inputTokens: 0,
      outputTokens: 0,
      finishReason: error ? 'error' : 'stop',
      latency,
      provider: `${this.name}_mock`,
    };
  }
}

// ============================================================
// Claude Provider
// ============================================================

export class ClaudeProvider extends BaseLLMProvider {
  constructor(apiKey = null, model = null, ...kwargs) {
    super(apiKey, model, null, kwargs);
    this.name = 'claude';
  }

  _getDefaultModel() {
    return 'claude-3-opus-20240229';
  }

  async generate(prompt, system = null, messages = null, ...kwargs) {
    const start = Date.now();

    try {
      const Anthropic = await import('@anthropic-ai/sdk');
      const client = new Anthropic.default({ apiKey: this.apiKey });

      const msgList = this._buildMessages(prompt, null, messages);

      const params = {
        model: this.model,
        messages: msgList,
        max_tokens: kwargs.max_tokens || 4096,
      };

      if (system) {
        params.system = system;
      }

      const response = await client.messages.create(params);

      return {
        content: response.content[0].text,
        model: response.model,
        tokensUsed: response.usage.input_tokens + response.usage.output_tokens,
        inputTokens: response.usage.input_tokens,
        outputTokens: response.usage.output_tokens,
        finishReason: response.stop_reason,
        latency: (Date.now() - start) / 1000,
        provider: this.name,
      };
    } catch (e) {
      return this._mockResponse(prompt, start, e.message);
    }
  }

  async *stream(prompt, system = null, messages = null, ...kwargs) {
    try {
      const Anthropic = await import('@anthropic-ai/sdk');
      const client = new Anthropic.default({ apiKey: this.apiKey });

      const msgList = this._buildMessages(prompt, null, messages);

      const params = {
        model: this.model,
        messages: msgList,
        max_tokens: kwargs.max_tokens || 4096,
        stream: true,
      };

      if (system) {
        params.system = system;
      }

      const stream = await client.messages.stream(params);

      for await (const event of stream) {
        if (event.type === 'content_block_delta' && event.delta.type === 'text_delta') {
          yield event.delta.text;
        }
      }
    } catch (e) {
      yield `[错误] ${e.message}`;
    }
  }

  _mockResponse(prompt, start, error = null) {
    const latency = (Date.now() - start) / 1000;
    const preview = prompt.length > 200 ? prompt.slice(0, 200) : prompt;
    return {
      content: error ? `[错误] ${error}` : `[Claude 模拟] 基于提示生成...\n\n${preview}`,
      model: this.model,
      tokensUsed: Math.floor(prompt.length / 4),
      inputTokens: 0,
      outputTokens: 0,
      finishReason: error ? 'error' : 'stop',
      latency,
      provider: `${this.name}_mock`,
    };
  }
}

