export class OllamaLLM extends LLM {
  constructor(model = 'qwen2.5:7b') {
    super();
    this.model = model;
    this.available = false;
    this._checkAvailable();
  }

  async _checkAvailable() {
    try {
      const res = await fetch(`${OLLAMA_URL}/api/tags`, { signal: AbortSignal.timeout(5000) });
      this.available = res.ok;
    } catch {
      this.available = false;
    }
  }

  async generate(prompt, options = {}) {
    const {
      maxTokens = 512,
      temperature = 0.7,
      stop = [],
    } = options;

    if (!this.available) {
      return `[LLM 不可用] ${prompt.slice(0, 100)}...`;
    }

    try {
      const response = await fetch(`${OLLAMA_URL}/api/generate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: this.model,
          prompt,
          stream: false,
          options: {
            num_predict: maxTokens,
            temperature,
            stop: stop || [],
          },
        }),
        signal: AbortSignal.timeout(60000),
      });

      if (response.ok) {
        const data = await response.json();
        return data.response || '';
      }
    } catch (e) {
      console.warn(`⚠️ Ollama generate 失败: ${e.message}`);
    }

    return '';
  }

  async *stream(prompt, options = {}) {
    const {
      maxTokens = 512,
      temperature = 0.7,
      stop = [],
    } = options;

    if (!this.available) {
      yield `[LLM 不可用] ${prompt.slice(0, 100)}...`;
      return;
    }

    try {
      const response = await fetch(`${OLLAMA_URL}/api/generate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: this.model,
          prompt,
          stream: true,
          options: {
            num_predict: maxTokens,
            temperature,
            stop: stop || [],
          },
        }),
      });

      if (!response.ok) {
        yield `[错误] HTTP ${response.status}`;
        return;
      }

      const reader = response.body.getReader();
      const decoder = new TextDecoder();

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const lines = decoder.decode(value).split('\n');
        for (const line of lines) {
          if (line.trim()) {
            try {
              const data = JSON.parse(line);
              if (data.response) {
                yield data.response;
              }
            } catch {}
          }
        }
      }
    } catch (e) {
      yield `[错误] ${e.message}`;
    }
  }
}

