import { existsSync, readdirSync, readFileSync, writeFileSync, mkdirSync } from 'fs';
import { join } from 'path';

const HOME = process.env.HOME || '/root';
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const PLUGIN_DIR = join(MEMORY_DIR, 'plugins');
const PLUGIN_CONFIG_FILE = join(PLUGIN_DIR, 'plugins.json');

// ============================================================
// Plugin System
// ============================================================

export class PluginManager {
  constructor() {
    mkdirSync(PLUGIN_DIR, { recursive: true });
    this.pluginsFile = join(PLUGIN_DIR, 'plugins.json');
    this.plugins = this._loadPlugins();
  }

  _loadPlugins() {
    if (existsSync(this.pluginsFile)) {
      try { return JSON.parse(readFileSync(this.pluginsFile, 'utf-8')); } catch { /* ignore */ }
    }
    return { plugins: {}, hooks: {} };
  }

  _savePlugins() {
    writeFileSync(this.pluginsFile, JSON.stringify(this.plugins, null, 2), 'utf-8');
  }

  /**
   * Register a plugin
   * @param {string} pluginId
   * @param {object} plugin
   */
  register(pluginId, plugin) {
    this.plugins.plugins[pluginId] = {
      ...plugin,
      id: pluginId,
      enabled: true,
      registered_at: new Date().toISOString()
    };
    this._savePlugins();
    return { success: true };
  }

  /**
   * Enable a plugin
   * @param {string} pluginId
   */
  enable(pluginId) {
    if (this.plugins.plugins[pluginId]) {
      this.plugins.plugins[pluginId].enabled = true;
      this._savePlugins();
    }
    return { success: true };
  }

  /**
   * Disable a plugin
   * @param {string} pluginId
   */
  disable(pluginId) {
    if (this.plugins.plugins[pluginId]) {
      this.plugins.plugins[pluginId].enabled = false;
      this._savePlugins();
    }
    return { success: true };
  }

  /**
   * Register a hook
   * @param {string} hookName
   * @param {string} pluginId
   * @param {string} handler
   */
  registerHook(hookName, pluginId, handler) {
    if (!this.plugins.hooks[hookName]) this.plugins.hooks[hookName] = [];
    this.plugins.hooks[hookName].push({ pluginId, handler });
    this._savePlugins();
  }

  /**
   * Trigger a hook
   * @param {string} hookName
   * @param {object} data
   */
  async triggerHook(hookName, data) {
    const hooks = this.plugins.hooks[hookName] || [];
    const results = [];
    for (const hook of hooks) {
      const plugin = this.plugins.plugins[hook.pluginId];
      if (plugin && plugin.enabled) {
        results.push({ pluginId: hook.pluginId, result: data });
      }
    }
    return results;
  }

  listPlugins() {
    return Object.values(this.plugins.plugins);
  }

  getPlugin(pluginId) {
    return this.plugins.plugins[pluginId] || null;
  }

  getStatus() {
    const all = Object.values(this.plugins.plugins);
    const enabled = all.filter(p => p.enabled);
    return {
      total: all.length,
      enabled: enabled.length,
      plugins: all.map(p => ({ id: p.id, name: p.name, enabled: p.enabled }))
    };
  }
}

export default { PluginManager };
/**
 * Preheat System - Preload hot memories for fast retrieval
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join } from 'path';
import { getAllMemories } from '../storage.js';


const WORKSPACE = join(process.env.HOME || '/root', '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const PREHEAT_DIR = join(MEMORY_DIR, 'preheat');

export function classifyMemories(config = {}) {
  const hotThreshold = config.hotThreshold ?? 10;
  const warmThreshold = config.warmThreshold ?? 3;
  const memories = getAllMemories();
  
  const hot = [], warm = [], cold = [];
  
  for (const mem of memories) {
    const accessCount = mem.access_count || 0;
    if (accessCount >= hotThreshold) hot.push(mem);
    else if (accessCount >= warmThreshold) warm.push(mem);
    else cold.push(mem);
  }
  
  return { hot: hot.slice(0, 100), warm: warm.slice(0, 200), cold };
}

export function preheat() {
  const { hot, warm } = classifyMemories();
  const cache = { generatedAt: new Date().toISOString(), hot, warm, hotIds: hot.map(m => m.id), warmIds: warm.map(m => m.id) };
  mkdirSync(PREHEAT_DIR, { recursive: true });
  writeFileSync(join(PREHEAT_DIR, 'preheat_cache.json'), JSON.stringify(cache, null, 2), 'utf-8');
  return { hot: hot.length, warm: warm.length, total: hot.length + warm.length };
}

export function getPreheatStatus() {
  const file = join(PREHEAT_DIR, 'preheat_cache.json');
  if (!existsSync(file)) return { hotCount: 0, warmCount: 0, totalCount: 0, isStale: true };
  try {
    const cache = JSON.parse(readFileSync(file, 'utf-8'));
    return { hotCount: cache.hot.length, warmCount: cache.warm.length, totalCount: cache.hot.length + cache.warm.length, cacheAge: cache.generatedAt, isStale: false };
  } catch { return { hotCount: 0, warmCount: 0, totalCount: 0, isStale: true }; }
}

if (require.main === module) {
  const args = process.argv.slice(2);
  if (args[0] === 'run') { const result = preheat(); console.log(`🔥 Preheat: ${result.hot} hot + ${result.warm} warm = ${result.total} total`); }
  else { const status = getPreheatStatus(); console.log(`🔥 Preheat: ${status.hotCount} hot, ${status.warmCount} warm`); }
}
/**
 * Code Sandbox - Docker 代码执行沙箱 v1.0
 * 
 * 功能:
 * - Docker 隔离执行
 * - 多语言支持（Python、JavaScript、TypeScript、Bash、Go）
 * - 资源限制（内存、CPU、超时）
 * - 安全隔离
 * - 本地降级执行
 * 
 * Usage:
 *     import { CodeSandbox } from './system/sandbox.js';
 *     
 *     const sandbox = new CodeSandbox({ timeout: 60 });
 *     const result = await sandbox.execute("print('Hello World')", "python");
 *     console.log(result.output);
 */

// ============================================================
// Imports
// ============================================================

import { spawn } from 'child_process';
import { existsSync } from 'fs';
import { join } from 'path';
import { createHash } from 'crypto';
import { randomUUID } from 'crypto';
import { tmpdir } from 'os';
import { mkdirSync, writeFileSync, readFileSync, rmSync } from 'fs';

// ============================================================
// Execution Result
// ============================================================

export class ExecutionResult {
  constructor({
    success = false,
    output = '',
    error = '',
    exitCode = -1,
    duration = 0,
    language = '',
    containerId = '',
    files = {},
    metrics = {},
  }) {
    this.success = success;
    this.output = output;
    this.error = error;
    this.exitCode = exitCode;
    this.duration = duration;
    this.language = language;
    this.containerId = containerId;
    this.files = files;
    this.metrics = metrics;
  }

  toJSON() {
    return {
      success: this.success,
      output: this.output,
      error: this.error,
      exitCode: this.exitCode,
      duration: this.duration,
      language: this.language,
      files: this.files,
      metrics: this.metrics,
    };
  }
}

// ============================================================
// Code Sandbox
// ============================================================

export class CodeSandbox {
  // Docker images for each language
  static IMAGES = {
    'python': 'python:3.11-slim',
    'python3': 'python:3.11-slim',
    'javascript': 'node:18-slim',
    'js': 'node:18-slim',
    'typescript': 'node:18-slim',
    'ts': 'node:18-slim',
    'bash': 'alpine:latest',
    'shell': 'alpine:latest',
    'go': 'golang:1.21-alpine',
    'golang': 'golang:1.21-alpine',
    'java': 'openjdk:17-slim',
    'rust': 'rust:slim',
    'ruby': 'ruby:3.2-slim',
  };

  // File extensions
  static EXTENSIONS = {
    'python': '.py',
    'python3': '.py',
    'javascript': '.js',
    'js': '.js',
    'typescript': '.ts',
    'ts': '.ts',
    'bash': '.sh',
    'shell': '.sh',
    'go': '.go',
    'golang': '.go',
    'java': '.java',
    'rust': '.rs',
    'ruby': '.rb',
  };

  // Run commands
  static RUN_COMMANDS = {
    'python': ['python', 'main.py'],
    'python3': ['python', 'main.py'],
    'javascript': ['node', 'main.js'],
    'js': ['node', 'main.js'],
    'typescript': ['npx', 'ts-node', 'main.ts'],
    'ts': ['npx', 'ts-node', 'main.ts'],
    'bash': ['sh', 'main.sh'],
    'shell': ['sh', 'main.sh'],
    'go': ['go', 'run', 'main.go'],
    'golang': ['go', 'run', 'main.go'],
    'java': ['java', 'Main.java'],
    'rust': ['sh', '-c', 'rustc main.rs -o main && ./main'],
    'ruby': ['ruby', 'main.rb'],
  };

  /**
   * @param {Object} options
   */
  constructor(options = {}) {
    this.timeout = options.timeout || 60;
    this.memoryLimit = options.memoryLimit || '256m';
    this.cpuLimit = options.cpuLimit || '1';
    this.networkDisabled = options.networkDisabled !== false;
    this.useDocker = options.useDocker;
    this._localExecutors = new Map();
    this._detectLocalExecutors();
    if (this.useDocker === undefined) {
      this.useDocker = this._checkDocker();
    }
  }

  _checkDocker() {
    try {
      const { execSync } = require('child_process');
      execSync('docker version', { stdio: 'ignore' });
      return true;
    } catch {
      return false;
    }
  }

  _detectLocalExecutors() {
    const executors = ['python', 'python3', 'node', 'bash', 'sh', 'go', 'ruby'];
    const { execSync } = require('child_process');

    for (const exec of executors) {
      try {
        execSync('which ' + exec, { stdio: 'ignore' });
        this._localExecutors.set(exec, true);
      } catch {
        this._localExecutors.set(exec, false);
      }
    }

    // Map language to executables
    this._langExecutors = {
      'python': this._localExecutors.get('python3') || this._localExecutors.get('python') ? ['python3', 'python'] : [],
      'python3': this._localExecutors.get('python3') ? ['python3'] : [],
      'javascript': this._localExecutors.get('node') ? ['node'] : [],
      'js': this._localExecutors.get('node') ? ['node'] : [],
      'bash': this._localExecutors.get('bash') ? ['bash'] : (this._localExecutors.get('sh') ? ['sh'] : []),
      'shell': this._localExecutors.get('bash') ? ['bash'] : (this._localExecutors.get('sh') ? ['sh'] : []),
      'go': this._localExecutors.get('go') ? ['go'] : [],
      'ruby': this._localExecutors.get('ruby') ? ['ruby'] : [],
    };
  }

  /**
   * Execute code
   * @param {string} code
   * @param {string} language
   * @param {Object} options
   * @returns {Promise<ExecutionResult>}
   */
  async execute(code, language = 'python', options = {}) {
    const {
      files = null,
      env = null,
      stdin = null,
      workdirFiles = null,
    } = options;

    language = language.toLowerCase();

    if (!CodeSandbox.IMAGES[language]) {
      return new ExecutionResult({
        success: false,
        output: '',
        error: `不支持的语言: ${language}。支持: ${Object.keys(CodeSandbox.IMAGES).join(', ')}`,
        exitCode: -1,
        duration: 0,
        language,
      });
    }

    if (this.useDocker) {
      return this._dockerExecute(code, language, files, env, stdin, workdirFiles);
    } else {
      return this._localExecute(code, language, files, env, stdin, workdirFiles);
    }
  }

  /**
   * Docker execution
   * @private
   */
  async _dockerExecute(code, language, files, env, stdin, workdirFiles) {
    const startTime = Date.now();
    let containerId = '';
    const tmpDir = join(tmpdir(), `sandbox_${randomUUID().slice(0, 8)}`);

    try {
      mkdirSync(tmpDir, { recursive: true });

      // Write main code file
      const ext = CodeSandbox.EXTENSIONS[language] || '.txt';
      const mainFile = join(tmpDir, `main${ext}`);
      writeFileSync(mainFile, code, 'utf-8');

      // Write additional files
      if (files) {
        for (const [name, content] of Object.entries(files)) {
          writeFileSync(join(tmpDir, name), content, 'utf-8');
        }
      }

      // Write workdir files
      if (workdirFiles) {
        for (const [name, content] of Object.entries(workdirFiles)) {
          writeFileSync(join(tmpDir, name), content, 'utf-8');
        }
      }

      const image = CodeSandbox.IMAGES[language];

      // Build docker command
      /** @type {string[]} */
      const dockerCmd = [
        'docker', 'run', '--rm',
        '-v', `${tmpDir}:/workspace`,
        '-w', '/workspace',
        '--memory', this.memoryLimit,
        '--cpus', this.cpuLimit,
      ];

      // Network settings
      if (this.networkDisabled) {
        dockerCmd.push('--network=none');
      }

      // Environment variables
      if (env) {
        for (const [k, v] of Object.entries(env)) {
          dockerCmd.extend(['-e', `${k}=${v}`]);
        }
      }

      // Container name for tracking
      containerId = `sandbox_${Date.now()}`;
      dockerCmd.extend(['--name', containerId]);

      // Image and command
      dockerCmd.push(image);
      dockerCmd.push(...(CodeSandbox.RUN_COMMANDS[language] || ['cat', 'main.txt']));

      // Execute
      const result = await this._runProcess(dockerCmd, {
        timeout: this.timeout,
        input: stdin,
      });

      const duration = (Date.now() - startTime) / 1000;

      // Collect generated files
      const outputFiles = {};
      try {
        const { readdirSync } = require('fs');
        const dirFiles = readdirSync(tmpDir);
        for (const f of dirFiles) {
          if (f !== `main${ext}`) {
            try {
              outputFiles[f] = readFileSync(join(tmpDir, f), 'utf-8');
            } catch {}
          }
        }
      } catch {}

      return new ExecutionResult({
        success: result.exitCode === 0,
        output: result.stdout,
        error: result.stderr,
        exitCode: result.exitCode,
        duration,
        language,
        containerId,
        files: outputFiles,
        metrics: {
          memory_limit: this.memoryLimit,
          cpu_limit: this.cpuLimit,
          network_disabled: this.networkDisabled,
        },
      });
    } catch (e) {
      const duration = (Date.now() - startTime) / 1000;

      if (e.message && e.message.includes('Timeout')) {
        return new ExecutionResult({
          success: false,
          output: '',
          error: `执行超时 (${this.timeout}s)`,
          exitCode: -1,
          duration: this.timeout,
          language,
          containerId,
        });
      }

      return new ExecutionResult({
        success: false,
        output: '',
        error: e.message,
        exitCode: -1,
        duration,
        language,
      });
    } finally {
      // Cleanup
      try { rmSync(tmpDir, { recursive: true, force: true }); } catch {}
    }
  }

  /**
   * Local execution (fallback)
   * @private
   */
  async _localExecute(code, language, files, env, stdin, workdirFiles) {
    const startTime = Date.now();
    const tmpDir = join(tmpdir(), `sandbox_${randomUUID().slice(0, 8)}`);

    try {
      mkdirSync(tmpDir, { recursive: true });

      // Check if language is available locally
      const executors = this._langExecutors[language] || [];
      if (executors.length === 0) {
        const available = [...new Set(Object.values(this._langExecutors).flat())];
        return new ExecutionResult({
          success: false,
          output: '',
          error: `本地执行不支持: ${language}。可用: ${available.join(', ')}`,
          exitCode: -1,
          duration: 0,
          language,
        });
      }

      // Write code
      const ext = CodeSandbox.EXTENSIONS[language] || '.txt';
      const mainFile = join(tmpDir, `main${ext}`);
      writeFileSync(mainFile, code, 'utf-8');

      // Write additional files
      if (files) {
        for (const [name, content] of Object.entries(files)) {
          writeFileSync(join(tmpDir, name), content, 'utf-8');
        }
      }

      // Build command
      let cmd;
      const exec = executors[0];

      if (language === 'python' || language === 'python3') {
        cmd = [exec, mainFile];
      } else if (language === 'javascript' || language === 'js') {
        cmd = [exec, mainFile];
      } else if (language === 'bash' || language === 'shell') {
        cmd = [exec, mainFile];
      } else if (language === 'go') {
        cmd = [exec, 'run', mainFile];
      } else if (language === 'ruby') {
        cmd = [exec, mainFile];
      } else {
        cmd = ['cat', mainFile];
      }

      // Execute
      const result = await this._runProcess(cmd, {
        timeout: this.timeout,
        input: stdin,
        cwd: tmpDir,
        env,
      });

      return new ExecutionResult({
        success: result.exitCode === 0,
        output: result.stdout,
        error: result.stderr,
        exitCode: result.exitCode,
        duration: (Date.now() - startTime) / 1000,
        language,
        metrics: { mode: 'local' },
      });
    } catch (e) {
      return new ExecutionResult({
        success: false,
        output: '',
        error: e.message,
        exitCode: -1,
        duration: (Date.now() - startTime) / 1000,
        language,
      });
    } finally {
      try { rmSync(tmpDir, { recursive: true, force: true }); } catch {}
    }
  }

  /**
   * Run a process with timeout
   * @private
   */
  _runProcess(cmd, options = {}) {
    return new Promise((resolve) => {
      const {
        timeout = 60,
        input = null,
        cwd = null,
        env = null,
      } = options;

      const procEnv = env ? { ...process.env, ...env } : undefined;

      const proc = spawn(cmd[0], cmd.slice(1), {
        cwd,
        env: procEnv,
        stdio: input ? ['pipe', 'pipe', 'pipe'] : ['ignore', 'pipe', 'pipe'],
      });

      let stdout = '';
      let stderr = '';
      let timedOut = false;

      const timer = setTimeout(() => {
        timedOut = true;
        proc.kill('SIGKILL');
      }, timeout * 1000);

      if (input && proc.stdin) {
        proc.stdin.write(input);
        proc.stdin.end();
      }

      if (proc.stdout) {
        proc.stdout.on('data', (data) => { stdout += data.toString(); });
      }
      if (proc.stderr) {
        proc.stderr.on('data', (data) => { stderr += data.toString(); });
      }

      proc.on('close', (code) => {
        clearTimeout(timer);
        resolve({
          stdout,
          stderr,
          exitCode: timedOut ? -1 : code,
          timedOut,
        });
      });

      proc.on('error', (e) => {
        clearTimeout(timer);
        resolve({
          stdout: '',
          stderr: e.message,
          exitCode: -1,
          timedOut: false,
        });
      });
    });
  }

  /**
   * Test code
   * @param {string} code
   * @param {string} testCode
   * @param {string} language
   * @param {string} testFramework
   * @returns {Promise<ExecutionResult>}
   */
  async testCode(code, testCode = null, language = 'python', testFramework = 'pytest') {
    let fullCode;

    if (language === 'python') {
      if (testFramework === 'pytest' && testCode) {
        fullCode = `${code}\n\n# Tests\n${testCode}`;
      } else {
        fullCode = `${code}\n\nif __name__ == '__main__':\n${testCode || ''}`;
      }
    } else if (language === 'javascript' || language === 'js') {
      fullCode = `${code}\n\n// Tests\n${testCode || ''}`;
    } else {
      fullCode = code;
    }

    return this.execute(fullCode, language);
  }

  /**
   * Run a file
   * @param {string} filePath
   * @param {string|null} language
   * @param {Object} options
   * @returns {Promise<ExecutionResult>}
   */
  async runFile(filePath, language = null, options = {}) {
    if (!existsSync(filePath)) {
      return new ExecutionResult({
        success: false,
        output: '',
        error: `文件不存在: ${filePath}`,
        exitCode: -1,
        duration: 0,
      });
    }

    // Auto-detect language
    if (!language) {
      const ext = filePath.split('.').pop().toLowerCase();
      const extMap = {
        'py': 'python',
        'js': 'javascript',
        'ts': 'typescript',
        'sh': 'bash',
        'go': 'go',
        'rb': 'ruby',
      };
      language = extMap[ext] || 'python';
    }

    const code = readFileSync(filePath, 'utf-8');
    return this.execute(code, language, options);
  }

  /**
   * List supported languages
   * @returns {string[]}
   */
  listLanguages() {
    return Object.keys(CodeSandbox.IMAGES);
  }

  /**
   * Get executor info
   * @returns {Object}
   */
  getExecutorInfo() {
    return {
      docker_available: this.useDocker,
      local_executors: Object.fromEntries(this._localExecutors),
      supported_languages: this.listLanguages(),
      config: {
        timeout: this.timeout,
        memory_limit: this.memoryLimit,
        cpu_limit: this.cpuLimit,
        network_disabled: this.networkDisabled,
      },
    };
  }
}

// ============================================================
// CLI
// ============================================================

async function main() {
  const args = process.argv.slice(2);
  const command = args[0] || 'info';

  let useDocker = undefined;
  if (args.includes('--docker')) useDocker = true;
  if (args.includes('--local')) useDocker = false;

  const sandbox = new CodeSandbox({ useDocker });

  if (command === 'info') {
    const info = sandbox.getExecutorInfo();
    console.log('沙箱信息:');
    console.log(`  Docker 可用: ${info.docker_available}`);
    console.log('  本地执行器:');
    for (const [lang, available] of Object.entries(info.local_executors)) {
      console.log(`    - ${lang}: ${available ? '✅' : '❌'}`);
    }
    console.log(`  支持的语言: ${info.supported_languages.join(', ')}`);
    console.log(`  配置: ${JSON.stringify(info.config)}`);
    return;
  }

  if (command === 'run') {
    const codeIndex = args.indexOf('--code');
    const fileIndex = args.indexOf('--file');
    const langIndex = args.indexOf('--language');
    const lang = langIndex >= 0 ? args[langIndex + 1] : 'python';

    let result;
    if (codeIndex >= 0) {
      const code = args.slice(codeIndex + 1).join(' ').replace(/^['"]|['"]$/g, '');
      result = await sandbox.execute(code, lang);
    } else if (fileIndex >= 0) {
      result = await sandbox.runFile(args[fileIndex + 1], lang);
    } else {
      console.error('请提供 --code 或 --file');
      process.exit(1);
    }

    console.log(`成功: ${result.success}`);
    console.log(`退出码: ${result.exitCode}`);
    console.log(`耗时: ${result.duration.toFixed(2)}s`);
    console.log(`输出:\n${result.output}`);
    if (result.error) console.log(`错误:\n${result.error}`);
    return;
  }

  if (command === 'test') {
    const code = args.find(a => a.startsWith('--code='))?.split('=')[1] ||
      "def add(a, b):\n    return a + b";
    const testCode = `
def test_add():
    assert add(1, 2) == 3
    assert add(0, 0) == 0
    print('All tests passed!')
`;
    const result = await sandbox.testCode(code, testCode, 'python');
    console.log(`测试${result.success ? '通过' : '失败'}`);
    console.log(`输出: ${result.output}`);
    if (result.error) console.log(`错误: ${result.error}`);
    return;
  }

  if (command === 'demo') {
    const demos = {
      'python': "print('Hello from Python!')\nfor i in range(3):\n    print(f'Count: {i}')",
      'javascript': "console.log('Hello from JavaScript!');\nfor(let i = 0; i < 3; i++) {\n  console.log(`Count: ${i}`);\n}",
      'bash': "echo 'Hello from Bash!'\nfor i in 1 2 3; do\n  echo \"Count: $i\"\ndone",
    };

    for (const [lang, code] of Object.entries(demos)) {
      console.log(`\n--- ${lang.toUpperCase()} ---`);
      const result = await sandbox.execute(code, lang);
      console.log(`成功: ${result.success}`);
      console.log(`输出: ${result.output.slice(0, 100)}`);
    }
  }
}

const isMain = process.argv[1]?.endsWith('sandbox.js') || process.argv[1]?.endsWith('sandbox.mjs');
if (isMain) {
  main().catch(console.error);
}

export default CodeSandbox;
/**
 * Task Queue - 智能任务分配系统 v1.0
 * 
 * Features:
 * - Smart task assignment (skill matching, load balancing, round-robin, volunteer, expert-first)
 * - Task status tracking & handoff
 * - Agent Profile integration
 * - Collab Bus integration
 * - Priority-based DAG scheduling
 * 
 * Usage:
 *   node task_queue.js add "title" --desc "description" --skills "python,coding" --priority 7
 *   node task_queue.js assign <id> --strategy skill_match
 *   node task_queue.js start <id> --agent xiao-zhi
 *   node task_queue.js complete <id> --result '{"status":"success"}'
 *   node task_queue.js handoff <id> --from xiao-zhi --to xiao-liu --reason "需要飞书操作"
 *   node task_queue.js list --agent xiao-zhi
 *   node task_queue.js stats
 */

import fs from 'fs/promises';
import path from 'path';
import { fileURLToPath } from 'url';
import os from 'os';
import crypto from 'crypto';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// ========== Configuration ==========

const WORKSPACE = path.join(os.homedir(), '.openclaw', 'workspace');
const MEMORY_DIR = path.join(WORKSPACE, 'memory');
const TASK_DIR = path.join(MEMORY_DIR, 'tasks');
const STORAGE_FILE = path.join(TASK_DIR, 'tasks.json');
const HISTORY_FILE = path.join(TASK_DIR, 'history.jsonl');
const PROFILES_FILE = path.join(TASK_DIR, 'profiles.json');
const EVENTS_FILE = path.join(TASK_DIR, 'events.jsonl');

// Ensure directories
await fs.mkdir(TASK_DIR, { recursive: true });

// ========== Enums ==========

const TaskStatus = {
  PENDING: 'pending',
  ASSIGNED: 'assigned',
  IN_PROGRESS: 'in_progress',
  COMPLETED: 'completed',
  FAILED: 'failed',
  CANCELLED: 'cancelled'
};

const AssignmentStrategy = {
  SKILL_MATCH: 'skill_match',
  LOAD_BALANCE: 'load_balance',
  ROUND_ROBIN: 'round_robin',
  VOLUNTEER: 'volunteer',
  EXPERT_FIRST: 'expert_first'
};

// ========== Data Classes ==========

class Task {
  constructor({
    taskId = null,
    title,
    description = '',
    requiredSkills = [],
    priority = 5,
    status = TaskStatus.PENDING,
    assignedTo = null,
    createdBy = null,
    createdAt = new Date(),
    startedAt = null,
    completedAt = null,
    result = null,
    handoffHistory = []
  }) {
    this.taskId = taskId || crypto.randomUUID().slice(0, 12);
    this.title = title;
    this.description = description;
    this.requiredSkills = requiredSkills;
    this.priority = Math.min(10, Math.max(1, priority));
    this.status = status;
    this.assignedTo = assignedTo;
    this.createdBy = createdBy;
    this.createdAt = createdAt instanceof Date ? createdAt.toISOString() : createdAt;
    this.startedAt = startedAt;
    this.completedAt = completedAt;
    this.result = result;
    this.handoffHistory = handoffHistory;
  }
  
  toDict() {
    return {
      taskId: this.taskId,
      title: this.title,
      description: this.description,
      requiredSkills: this.requiredSkills,
      priority: this.priority,
      status: this.status,
      assignedTo: this.assignedTo,
      createdBy: this.createdBy,
      createdAt: this.createdAt,
      startedAt: this.startedAt,
      completedAt: this.completedAt,
      result: this.result,
      handoffHistory: this.handoffHistory
    };
  }
  
  static fromDict(d) {
    return new Task({
      taskId: d.taskId,
      title: d.title,
      description: d.description,
      requiredSkills: d.requiredSkills || [],
      priority: d.priority || 5,
      status: d.status || TaskStatus.PENDING,
      assignedTo: d.assignedTo,
      createdBy: d.createdBy,
      createdAt: d.createdAt,
      startedAt: d.startedAt,
      completedAt: d.completedAt,
      result: d.result,
      handoffHistory: d.handoffHistory || []
    });
  }
}

class AgentProfile {
  constructor(agentId, name = null) {
    this.agentId = agentId;
    this.name = name || agentId;
    this.skills = {}; // skill -> score (0-1)
    this.workload = 0.0;
    this.expertise = [];
    this.preferences = {};
    this.trustScores = {};
    this.taskHistory = [];
    this.successRate = 1.0;
  }
  
  addSkill(skill, score) {
    this.skills[skill.toLowerCase()] = Math.min(1.0, Math.max(0.0, score));
  }
  
  hasSkill(skill) {
    return skill.toLowerCase() in this.skills;
  }
  
  getSkillScore(skill) {
    return this.skills[skill.toLowerCase()] || 0.0;
  }
  
  toDict() {
    return {
      agentId: this.agentId,
      name: this.name,
      skills: this.skills,
      workload: this.workload,
      expertise: this.expertise,
      preferences: this.preferences,
      trustScores: this.trustScores,
      taskHistory: this.taskHistory.slice(-20),
      successRate: this.successRate
    };
  }
  
  static fromDict(d) {
    const profile = new AgentProfile(d.agentId, d.name);
    profile.skills = d.skills || {};
    profile.workload = d.workload || 0.0;
    profile.expertise = d.expertise || [];
    profile.preferences = d.preferences || {};
    profile.trustScores = d.trustScores || {};
    profile.taskHistory = d.taskHistory || [];
    profile.successRate = d.successRate || 1.0;
    return profile;
  }
}

class AgentProfileManager {
  constructor(storagePath) {
    this.storagePath = storagePath;
    this.profiles = {};
    this._load();
  }
  
  async _load() {
    try {
      if (await fileExists(this.storagePath)) {
        const data = JSON.parse(await fs.readFile(this.storagePath, 'utf-8'));
        for (const [agentId, profileData] of Object.entries(data.profiles || {})) {
          this.profiles[agentId] = AgentProfile.fromDict(profileData);
        }
      }
    } catch (e) {
      // File doesn't exist or parse error
    }
    
    // Default agents
    if (!this.profiles['xiao-zhi']) {
      this.profiles['xiao-zhi'] = new AgentProfile('xiao-zhi', '小智');
      this.profiles['xiao-zhi'].addSkill('coding', 0.9);
      this.profiles['xiao-zhi'].addSkill('python', 0.9);
      this.profiles['xiao-zhi'].addSkill('planning', 0.85);
      this.profiles['xiao-zhi'].addSkill('documentation', 0.8);
    }
    
    if (!this.profiles['xiao-liu']) {
      this.profiles['xiao-liu'] = new AgentProfile('xiao-liu', '小六');
      this.profiles['xiao-liu'].addSkill('feishu', 0.95);
      this.profiles['xiao-liu'].addSkill('communication', 0.9);
      this.profiles['xiao-liu'].addSkill('coordination', 0.85);
    }
  }
  
  async _save() {
    const data = {
      profiles: Object.fromEntries(
        Object.entries(this.profiles).map(([k, v]) => [k, v.toDict()])
      )
    };
    await fs.writeFile(this.storagePath, JSON.stringify(data, null, 2), 'utf-8');
  }
  
  getProfile(agentId) {
    return this.profiles[agentId] || null;
  }
  
  getAllAgents() {
    return Object.values(this.profiles);
  }
  
  async updateWorkload(agentId, delta) {
    if (agentId in this.profiles) {
      this.profiles[agentId].workload = Math.max(0, this.profiles[agentId].workload + delta);
      await this._save();
    }
  }
  
  async recordTaskCompletion(agentId, taskId, success) {
    if (agentId in this.profiles) {
      const profile = this.profiles[agentId];
      profile.taskHistory.push(success ? `${taskId}_success` : `${taskId}_failed`);
      // Update success rate
      const total = profile.taskHistory.length;
      const successful = profile.taskHistory.filter(t => t.endsWith('_success')).length;
      profile.successRate = successful / total || 1.0;
      await this._save();
    }
  }
}

class CollabBus {
  constructor(logPath) {
    this.logPath = logPath;
    this.subscribers = {}; // topic -> agent_ids
  }
  
  async _ensureLog() {
    await fs.mkdir(path.dirname(this.logPath), { recursive: true });
    try {
      await fs.access(this.logPath);
    } catch {
      await fs.writeFile(this.logPath, '', 'utf-8');
    }
  }
  
  async publish(eventType, data, fromAgent = 'system') {
    await this._ensureLog();
    
    const event = {
      id: crypto.createHash('md5').update(`${Date.now()}${eventType}`).digest('hex').slice(0, 12),
      timestamp: new Date().toISOString(),
      type: eventType,
      from: fromAgent,
      data
    };
    
    await fs.appendFile(this.logPath, JSON.stringify(event) + '\n', 'utf-8');
    return event.id;
  }
  
  async notifyTaskAssigned(taskId, agentId, assignedBy = 'system') {
    return this.publish('task_assigned', {
      taskId,
      agentId,
      assignedBy
    }, assignedBy);
  }
  
  async notifyTaskHandoff(taskId, fromAgent, toAgent, reason) {
    return this.publish('task_handoff', {
      taskId,
      fromAgent,
      toAgent,
      reason
    }, fromAgent);
  }
  
  async notifyTaskCompleted(taskId, agentId, result) {
    return this.publish('task_completed', {
      taskId,
      agentId,
      result
    }, agentId);
  }
  
  async getRecentEvents(limit = 20) {
    try {
      const content = await fs.readFile(this.logPath, 'utf-8');
      const lines = content.split('\n').filter(l => l.trim());
      return lines.slice(-limit).map(l => JSON.parse(l));
    } catch {
      return [];
    }
  }
}

class AssignmentEngine {
  constructor(agentProfiles) {
    this.agentProfiles = agentProfiles;
    this.roundRobinIndex = 0;
  }
  
  findBestAgent(task, strategy) {
    const agents = this.agentProfiles.getAllAgents();
    if (!agents.length) return null;
    
    switch (strategy) {
      case AssignmentStrategy.SKILL_MATCH:
        return this._skillMatch(task, agents);
      case AssignmentStrategy.LOAD_BALANCE:
        return this._loadBalance(task, agents);
      case AssignmentStrategy.ROUND_ROBIN:
        return this._roundRobin(task, agents);
      case AssignmentStrategy.EXPERT_FIRST:
        return this._expertFirst(task, agents);
      default:
        return agents[0].agentId;
    }
  }
  
  _skillMatch(task, agents) {
    let bestAgent = null;
    let bestScore = -1;
    
    for (const agent of agents) {
      let score = this.calculateSkillMatchScore(task, agent.agentId);
      score -= agent.workload * 0.1;
      if (score > bestScore) {
        bestScore = score;
        bestAgent = agent.agentId;
      }
    }
    
    return bestAgent;
  }
  
  _loadBalance(task, agents) {
    let bestAgent = null;
    let minWorkload = Infinity;
    
    for (const agent of agents) {
      if (task.requiredSkills.length > 0) {
        const skillScore = this.calculateSkillMatchScore(task, agent.agentId);
        if (skillScore < 0.3) continue;
      }
      
      const score = this.getLoadBalanceScore(agent.agentId);
      if (score < minWorkload) {
        minWorkload = score;
        bestAgent = agent.agentId;
      }
    }
    
    return bestAgent;
  }
  
  _roundRobin(task, agents) {
    if (!agents.length) return null;
    
    let attempts = 0;
    while (attempts < agents.length) {
      const agent = agents[this.roundRobinIndex % agents.length];
      this.roundRobinIndex++;
      
      if (task.requiredSkills.length > 0) {
        const skillScore = this.calculateSkillMatchScore(task, agent.agentId);
        if (skillScore >= 0.3) return agent.agentId;
      } else {
        return agent.agentId;
      }
      
      attempts++;
    }
    
    return agents[0].agentId;
  }
  
  _expertFirst(task, agents) {
    let bestAgent = null;
    let bestScore = -1;
    
    for (const agent of agents) {
      // Check expertise match
      const expertiseMatch = task.requiredSkills.some(skill =>
        agent.expertise.some(e => e.toLowerCase().includes(skill.toLowerCase()))
      );
      
      const skillScore = this.calculateSkillMatchScore(task, agent.agentId);
      const successScore = agent.successRate;
      
      // Expertise bonus
      if (expertiseMatch) score *= 1.5;
      
      const score = skillScore * 0.6 + successScore * 0.4 - agent.workload * 0.1;
      
      if (score > bestScore) {
        bestScore = score;
        bestAgent = agent.agentId;
      }
    }
    
    return bestAgent;
  }
  
  calculateSkillMatchScore(task, agentId) {
    const profile = this.agentProfiles.getProfile(agentId);
    if (!profile) return 0.0;
    
    if (!task.requiredSkills.length) return 1.0;
    
    const scores = task.requiredSkills.map(skill => profile.getSkillScore(skill));
    return scores.reduce((a, b) => a + b, 0) / scores.length;
  }
  
  getLoadBalanceScore(agentId) {
    const profile = this.agentProfiles.getProfile(agentId);
    if (!profile) return Infinity;
    return profile.workload;
  }
}

class TaskQueue {
  constructor(storagePath, agentProfiles, collabBus) {
    this.storagePath = storagePath;
    this.historyPath = path.join(path.dirname(storagePath), 'history.jsonl');
    this.agentProfiles = agentProfiles;
    this.collabBus = collabBus;
    this.assignmentEngine = new AssignmentEngine(agentProfiles);
    this.tasks = {};
    this._load();
  }
  
  async _load() {
    try {
      if (await fileExists(this.storagePath)) {
        const data = JSON.parse(await fs.readFile(this.storagePath, 'utf-8'));
        for (const [taskId, taskData] of Object.entries(data.tasks || {})) {
          this.tasks[taskId] = Task.fromDict(taskData);
        }
      }
    } catch (e) {
      // File doesn't exist or parse error
    }
  }
  
  async _save() {
    const data = {
      tasks: Object.fromEntries(
        Object.entries(this.tasks).map(([k, v]) => [k, v.toDict()])
      )
    };
    await fs.writeFile(this.storagePath, JSON.stringify(data, null, 2), 'utf-8');
  }
  
  async _appendHistory(task) {
    await fs.mkdir(path.dirname(this.historyPath), { recursive: true });
    await fs.appendFile(this.historyPath, JSON.stringify(task.toDict()) + '\n', 'utf-8');
  }
  
  async addTask(task) {
    if (!task.taskId) {
      task.taskId = crypto.createHash('md5')
        .update(`${new Date().toISOString()}${task.title}`)
        .digest('hex').slice(0, 12);
    }
    
    this.tasks[task.taskId] = task;
    await this._save();
    
    console.log(`✅ 创建任务: [${task.taskId}] ${task.title}`);
    console.log(`   技能要求: ${task.requiredSkills.join(', ') || '无'}`);
    console.log(`   优先级: ${task.priority}/10`);
    
    return task.taskId;
  }
  
  async assign(taskId, strategy = AssignmentStrategy.SKILL_MATCH) {
    const task = this.tasks[taskId];
    if (!task) {
      console.log(`❌ 任务不存在: ${taskId}`);
      return null;
    }
    
    if (task.status !== TaskStatus.PENDING) {
      console.log(`❌ 任务状态不允许分配: ${task.status}`);
      return null;
    }
    
    const agentId = this.assignmentEngine.findBestAgent(task, strategy);
    if (!agentId) {
      console.log(`❌ 没有可用的 Agent`);
      return null;
    }
    
    task.assignedTo = agentId;
    task.status = TaskStatus.ASSIGNED;
    
    await this.agentProfiles.updateWorkload(agentId, 1);
    await this._save();
    await this.collabBus.notifyTaskAssigned(taskId, agentId);
    
    console.log(`✅ 任务已分配: [${taskId}] → ${agentId}`);
    console.log(`   分配策略: ${strategy}`);
    
    return agentId;
  }
  
  getAgentTasks(agentId, status = null) {
    const result = [];
    for (const task of Object.values(this.tasks)) {
      if (task.assignedTo === agentId) {
        if (status === null || task.status === status) {
          result.push(task);
        }
      }
    }
    // Sort by priority
    result.sort((a, b) => b.priority - a.priority);
    return result;
  }
  
  async startTask(taskId, agentId) {
    const task = this.tasks[taskId];
    if (!task) {
      console.log(`❌ 任务不存在: ${taskId}`);
      return false;
    }
    
    if (task.assignedTo !== agentId) {
      console.log(`❌ 任务未分配给 ${agentId}`);
      return false;
    }
    
    if (task.status !== TaskStatus.ASSIGNED) {
      console.log(`❌ 任务状态不允许开始: ${task.status}`);
      return false;
    }
    
    task.status = TaskStatus.IN_PROGRESS;
    task.startedAt = new Date().toISOString();
    
    await this._save();
    console.log(`🚀 任务开始: [${taskId}] by ${agentId}`);
    return true;
  }
  
  async completeTask(taskId, agentId, result = {}) {
    const task = this.tasks[taskId];
    if (!task) {
      console.log(`❌ 任务不存在: ${taskId}`);
      return false;
    }
    
    if (task.assignedTo !== agentId) {
      console.log(`❌ 任务未分配给 ${agentId}`);
      return false;
    }
    
    task.status = TaskStatus.COMPLETED;
    task.completedAt = new Date().toISOString();
    task.result = result;
    
    await this.agentProfiles.updateWorkload(agentId, -1);
    await this.agentProfiles.recordTaskCompletion(agentId, taskId, true);
    await this._appendHistory(task);
    delete this.tasks[taskId];
    
    await this._save();
    await this.collabBus.notifyTaskCompleted(taskId, agentId, result);
    
    console.log(`✅ 任务完成: [${taskId}] by ${agentId}`);
    return true;
  }
  
  async failTask(taskId, agentId, error) {
    const task = this.tasks[taskId];
    if (!task) {
      console.log(`❌ 任务不存在: ${taskId}`);
      return false;
    }
    
    if (task.assignedTo !== agentId) {
      console.log(`❌ 任务未分配给 ${agentId}`);
      return false;
    }
    
    task.status = TaskStatus.FAILED;
    task.completedAt = new Date().toISOString();
    task.result = { error };
    
    await this.agentProfiles.updateWorkload(agentId, -1);
    await this.agentProfiles.recordTaskCompletion(agentId, taskId, false);
    await this._appendHistory(task);
    delete this.tasks[taskId];
    
    await this._save();
    console.log(`❌ 任务失败: [${taskId}] by ${agentId}`);
    console.log(`   错误: ${error}`);
    return true;
  }
  
  async handoff(taskId, fromAgent, toAgent, reason) {
    const task = this.tasks[taskId];
    if (!task) {
      console.log(`❌ 任务不存在: ${taskId}`);
      return false;
    }
    
    if (task.assignedTo !== fromAgent) {
      console.log(`❌ 任务未分配给 ${fromAgent}`);
      return false;
    }
    
    task.handoffHistory.push({
      from: fromAgent,
      to: toAgent,
      reason,
      timestamp: new Date().toISOString()
    });
    
    task.assignedTo = toAgent;
    
    await this.agentProfiles.updateWorkload(fromAgent, -1);
    await this.agentProfiles.updateWorkload(toAgent, 1);
    
    await this._save();
    await this.collabBus.notifyTaskHandoff(taskId, fromAgent, toAgent, reason);
    
    console.log(`🔄 任务移交: [${taskId}] ${fromAgent} → ${toAgent}`);
    console.log(`   原因: ${reason}`);
    return true;
  }
  
  getPendingTasks() {
    const result = Object.values(this.tasks).filter(t => t.status === TaskStatus.PENDING);
    result.sort((a, b) => b.priority - a.priority);
    return result;
  }
  
  getTaskStats() {
    const stats = {};
    for (const task of Object.values(this.tasks)) {
      const status = task.status;
      if (!stats[status]) stats[status] = 0;
      stats[status]++;
    }
    return stats;
  }
  
  listTasks(status = null) {
    let tasks = Object.values(this.tasks);
    if (status) {
      tasks = tasks.filter(t => t.status === status);
    }
    tasks.sort((a, b) => b.priority - a.priority);
    return tasks;
  }
}

// ========== Utilities ==========

async function fileExists(filePath) {
  try {
    await fs.access(filePath);
    return true;
  } catch {
    return false;
  }
}

// ========== CLI ==========

async function main() {
  const args = process.argv.slice(2);
  const command = args[0];
  
  if (!command) {
    console.log(`
Task Queue - 智能任务分配系统 v1.0

Usage:
    node task_queue.js add "title" --desc "描述" --skills "python,coding" --priority 7
    node task_queue.js assign <id> --strategy skill_match
    node task_queue.js start <id> --agent xiao-zhi
    node task_queue.js complete <id> --result '{"status":"success"}'
    node task_queue.js handoff <id> --from xiao-zhi --to xiao-liu --reason "需要飞书操作"
    node task_queue.js list --agent xiao-zhi
    node task_queue.js stats
`);
    process.exit(1);
  }
  
  const agentProfiles = new AgentProfileManager(PROFILES_FILE);
  const collabBus = new CollabBus(EVENTS_FILE);
  const taskQueue = new TaskQueue(STORAGE_FILE, agentProfiles, collabBus);
  
  switch (command) {
    case 'add': {
      const title = args.slice(1).join(' ') || args[1];
      const descIdx = args.indexOf('--desc');
      const skillsIdx = args.indexOf('--skills');
      const priorityIdx = args.indexOf('--priority');
      const byIdx = args.indexOf('--by');
      
      const task = new Task({
        title,
        description: descIdx !== -1 ? args[descIdx + 1] : '',
        requiredSkills: skillsIdx !== -1 ? args[skillsIdx + 1].split(',').map(s => s.trim()) : [],
        priority: priorityIdx !== -1 ? parseInt(args[priorityIdx + 1]) : 5,
        createdBy: byIdx !== -1 ? args[byIdx + 1] : null
      });
      
      await taskQueue.addTask(task);
      break;
    }
    
    case 'assign': {
      const taskId = args[1];
      const strategyIdx = args.indexOf('--strategy');
      const strategy = strategyIdx !== -1 ? args[strategyIdx + 1] : 'skill_match';
      
      if (!taskId) {
        console.log('❌ 请提供任务 ID');
        process.exit(1);
      }
      
      await taskQueue.assign(taskId, strategy);
      break;
    }
    
    case 'start': {
      const taskId = args[1];
      const agentIdx = args.indexOf('--agent');
      const agentId = agentIdx !== -1 ? args[agentIdx + 1] : 'xiao-zhi';
      
      if (!taskId) {
        console.log('❌ 请提供任务 ID');
        process.exit(1);
      }
      
      await taskQueue.startTask(taskId, agentId);
      break;
    }
    
    case 'complete': {
      const taskId = args[1];
      const resultIdx = args.indexOf('--result');
      const agentIdx = args.indexOf('--agent');
      const agentId = agentIdx !== -1 ? args[agentIdx + 1] : 'xiao-zhi';
      let result = {};
      
      if (resultIdx !== -1) {
        try {
          result = JSON.parse(args[resultIdx + 1]);
        } catch (e) {
          console.log('❌ 结果格式错误，请提供 JSON');
          process.exit(1);
        }
      }
      
      if (!taskId) {
        console.log('❌ 请提供任务 ID');
        process.exit(1);
      }
      
      await taskQueue.completeTask(taskId, agentId, result);
      break;
    }
    
    case 'handoff': {
      const taskId = args[1];
      const fromIdx = args.indexOf('--from');
      const toIdx = args.indexOf('--to');
      const reasonIdx = args.indexOf('--reason');
      
      if (!taskId || fromIdx === -1 || toIdx === -1) {
        console.log('❌ 请提供任务 ID, --from 和 --to');
        process.exit(1);
      }
      
      await taskQueue.handoff(
        taskId,
        args[fromIdx + 1],
        args[toIdx + 1],
        reasonIdx !== -1 ? args[reasonIdx + 1] : '未指定原因'
      );
      break;
    }
    
    case 'list': {
      const agentIdx = args.indexOf('--agent');
      const statusIdx = args.indexOf('--status');
      
      let tasks;
      if (agentIdx !== -1) {
        const status = statusIdx !== -1 ? args[statusIdx + 1] : null;
        tasks = taskQueue.getAgentTasks(args[agentIdx + 1], status);
      } else {
        const status = statusIdx !== -1 ? args[statusIdx + 1] : null;
        tasks = taskQueue.listTasks(status);
      }
      
      if (tasks.length === 0) {
        console.log('没有任务');
      } else {
        console.log(`📋 任务列表 (${tasks.length}):\n`);
        for (const task of tasks) {
          console.log(`  [${task.taskId}] ${task.title}`);
          console.log(`    状态: ${task.status} | 优先级: ${task.priority} | 分配给: ${task.assignedTo || '无'}`);
          console.log();
        }
      }
      break;
    }
    
    case 'stats': {
      const stats = taskQueue.getTaskStats();
      console.log('📊 任务统计:\n');
      for (const [status, count] of Object.entries(stats)) {
        console.log(`  ${status}: ${count}`);
      }
      console.log(`\n  总计: ${Object.values(stats).reduce((a, b) => a + b, 0)}`);
      
      console.log('\n👥 Agent 负载:\n');
      for (const agent of agentProfiles.getAllAgents()) {
        console.log(`  ${agent.name} (${agent.agentId}): ${(agent.workload * 100).toFixed(0)}%`);
      }
      break;
    }
    
    default:
      console.log(`❌ 未知命令: ${command}`);
      process.exit(1);
  }
}

// Run if executed directly
if (import.meta.url === `file://${process.argv[1]}`) {
  main().catch(console.error);
}

export {
  Task,
  TaskStatus,
  AgentProfile,
  AgentProfileManager,
  CollabBus,
  AssignmentEngine,
  AssignmentStrategy,
  TaskQueue
};

export default TaskQueue;
/**
 * Workflow Engine - SOP/DAG 混合工作流引擎 v1.0
 * 
 * 整合 MetaGPT 的工作流设计，支持：
 * - SOP（顺序执行）
 * - DAG（并行执行）
 * - 混合模式
 * 
 * Usage:
 *     import { Workflow, WorkflowEngine } from './system/workflow_engine.js';
 *     
 *     const workflow = new Workflow("software-dev", "hybrid");
 *     workflow.addStep({ id: "pm", agentId: "pm", action: "analyze" });
 *     workflow.addStep({ id: "dev", agentId: "dev", action: "code", dependsOn: ["pm"] });
 *     
 *     const engine = new WorkflowEngine(agents);
 *     const result = await engine.run(workflow, initialContext);
 */

// ============================================================
// Enums
// ============================================================

export const StepStatus = {
  PENDING: 'pending',
  RUNNING: 'running',
  COMPLETED: 'completed',
  FAILED: 'failed',
  SKIPPED: 'skipped',
};

export const WorkflowType = {
  SOP: 'sop',           // 顺序执行
  DAG: 'dag',           // 并行执行
  HYBRID: 'hybrid',     // 混合模式
};

// ============================================================
// Step
// ============================================================

export class Step {
  constructor({
    id,
    agentId,
    action,
    dependsOn = [],
    outputKey = null,
    condition = null,
    retry = 0,
    timeout = 300,
  }) {
    this.id = id;
    this.agentId = agentId;
    this.action = action;
    this.dependsOn = dependsOn;
    this.outputKey = outputKey;
    this.condition = condition;
    this.retry = retry;
    this.timeout = timeout;
    this.status = StepStatus.PENDING;
    this.result = null;
    this.error = null;
    this.startTime = null;
    this.endTime = null;
  }

  toJSON() {
    return {
      id: this.id,
      agentId: this.agentId,
      action: this.action,
      dependsOn: this.dependsOn,
      outputKey: this.outputKey,
      condition: this.condition,
      status: this.status,
    };
  }
}

// ============================================================
// Workflow
// ============================================================

export class Workflow {
  constructor(name, type = WorkflowType.HYBRID) {
    this.name = name;
    this.type = type;
    /** @type {Map<string, Step>} */
    this.steps = new Map();
    this.stepOrder = [];
  }

  /**
   * Add a step to the workflow
   * @param {Object} config
   * @returns {Workflow}
   */
  addStep(config) {
    const step = new Step({
      id: config.id,
      agentId: config.agentId,
      action: config.action,
      dependsOn: config.dependsOn || [],
      outputKey: config.outputKey || null,
      condition: config.condition || null,
      retry: config.retry || 0,
      timeout: config.timeout || 300,
    });

    this.steps.set(step.id, step);
    this.stepOrder.push(step.id);
    return this;
  }

  /**
   * Get dependencies for a step
   * @param {string} stepId
   * @returns {string[]}
   */
  getDependencies(stepId) {
    const step = this.steps.get(stepId);
    return step ? step.dependsOn : [];
  }

  /**
   * Get steps that depend on this step
   * @param {string} stepId
   * @returns {string[]}
   */
  getDependents(stepId) {
    const dependents = [];
    for (const step of this.steps.values()) {
      if (step.dependsOn.includes(stepId)) {
        dependents.push(step.id);
      }
    }
    return dependents;
  }

  /**
   * Topological sort, returns levels that can run in parallel
   * @returns {string[][]}
   */
  topologicalSort() {
    const inDegree = new Map();
    for (const stepId of this.steps.keys()) {
      inDegree.set(stepId, 0);
    }

    // Calculate in-degrees
    for (const step of this.steps.values()) {
      for (const dep of step.dependsOn) {
        if (this.steps.has(dep)) {
          inDegree.set(step.id, (inDegree.get(step.id) || 0) + 1);
        }
      }
    }

    // Level-based sorting
    /** @type {string[][]} */
    const levels = [];
    const remaining = new Set(this.steps.keys());

    while (remaining.size > 0) {
      // Find steps with in-degree 0
      const ready = [...remaining].filter(s => (inDegree.get(s) || 0) === 0);

      if (ready.length === 0) {
        // Cycle detected
        throw new Error(`工作流存在循环依赖: ${[...remaining].join(', ')}`);
      }

      levels.push(ready);

      // Remove executed steps and update in-degrees
      for (const stepId of ready) {
        remaining.delete(stepId);
        for (const dependent of this.getDependents(stepId)) {
          if (remaining.has(dependent)) {
            inDegree.set(dependent, (inDegree.get(dependent) || 0) - 1);
          }
        }
      }
    }

    return levels;
  }

  toJSON() {
    const stepsObj = {};
    for (const [id, step] of this.steps) {
      stepsObj[id] = step.toJSON();
    }
    return {
      name: this.name,
      type: this.type,
      steps: stepsObj,
    };
  }

  /**
   * Create workflow from JSON
   * @param {Object} data
   * @returns {Workflow}
   */
  static fromJSON(data) {
    const workflow = new Workflow(data.name, data.type || WorkflowType.HYBRID);
    for (const [stepId, stepData] of Object.entries(data.steps || {})) {
      workflow.addStep({
        id: stepId,
        agentId: stepData.agentId,
        action: stepData.action,
        dependsOn: stepData.dependsOn || [],
        outputKey: stepData.outputKey || null,
        condition: stepData.condition || null,
      });
    }
    return workflow;
  }
}

// ============================================================
// Environment
// ============================================================

export class Environment {
  constructor() {
    /** @type {Map<string, any>} */
    this.context = new Map();
    /** @type {Object[]} */
    this.history = [];
    /** @type {Map<string, {content: any, type: string, createdAt: string}>} */
    this.artifacts = new Map();
    this._lock = null; // Would use AsyncLock in production
  }

  /**
   * Put a value into context
   * @param {string} key
   * @param {any} value
   * @param {string} producer
   */
  put(key, value, producer = null) {
    this.context.set(key, value);
    this.history.push({
      action: 'put',
      key,
      producer,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Get a value from context
   * @param {string} key
   * @param {any} defaultValue
   * @returns {any}
   */
  get(key, defaultValue = undefined) {
    return this.context.has(key) ? this.context.get(key) : defaultValue;
  }

  /**
   * Get all context
   * @returns {Object}
   */
  getAll() {
    return Object.fromEntries(this.context);
  }

  /**
   * Add an artifact
   * @param {string} name
   * @param {any} content
   * @param {string} artifactType
   */
  addArtifact(name, content, artifactType) {
    this.artifacts.set(name, {
      content,
      type: artifactType,
      createdAt: new Date().toISOString(),
    });
  }

  /**
   * Get an artifact
   * @param {string} name
   * @returns {Object|null}
   */
  getArtifact(name) {
    return this.artifacts.get(name) || null;
  }

  /**
   * Publish a message (for agent communication)
   * @param {string} topic
   * @param {Object} message
   * @param {string} sender
   */
  publish(topic, message, sender) {
    this.history.push({
      action: 'publish',
      topic,
      message,
      sender,
      timestamp: new Date().toISOString(),
    });
  }

  toJSON() {
    return {
      context: Object.fromEntries(this.context),
      artifacts: Object.fromEntries(this.artifacts),
      history: this.history,
    };
  }
}

// ============================================================
// Workflow Engine
// ============================================================

export class WorkflowEngine {
  /**
   * @param {Map<string, any>|Object} agents - Agent instances
   * @param {number} maxWorkers - Max parallel workers
   */
  constructor(agents = {}, maxWorkers = 4) {
    this.agents = agents instanceof Map ? agents : new Map(Object.entries(agents));
    this.maxWorkers = maxWorkers;
    this.env = new Environment();
    /** @type {Object[]} */
    this.executionLog = [];
  }

  /**
   * Run a workflow
   * @param {Workflow} workflow
   * @param {Object} initialContext
   * @param {Function} onStepComplete
   * @returns {Promise<Object>}
   */
  async run(workflow, initialContext = null, onStepComplete = null) {
    // Initialize environment
    if (initialContext) {
      for (const [k, v] of Object.entries(initialContext)) {
        this.env.put(k, v, 'init');
      }
    }

    // Get execution levels
    let levels;
    try {
      levels = workflow.topologicalSort();
    } catch (e) {
      return {
        workflow: workflow.name,
        status: 'error',
        error: e.message,
        totalSteps: workflow.steps.size,
        completed: 0,
        failed: 0,
      };
    }

    let totalSteps = workflow.steps.size;
    let completed = 0;
    let failed = 0;

    console.log(`\n🚀 工作流启动: ${workflow.name}`);
    console.log(`📊 总步骤: ${totalSteps}, 并行层级: ${levels.length}\n`);

    // Execute level by level
    for (let levelIdx = 0; levelIdx < levels.length; levelIdx++) {
      const level = levels[levelIdx];
      console.log(`📍 层级 ${levelIdx + 1}: ${level.join(', ')}`);

      if (level.length === 1 || workflow.type === WorkflowType.SOP) {
        // Sequential execution
        for (const stepId of level) {
          const result = await this._executeStep(workflow.steps.get(stepId), onStepComplete);
          if (result.status === 'completed') {
            completed++;
          } else {
            failed++;
            if (workflow.type === WorkflowType.SOP) {
              // Stop on first failure in SOP mode
              break;
            }
          }
        }
      } else {
        // Parallel execution
        const batchSize = Math.min(level.length, this.maxWorkers);
        const batches = [];

        for (let i = 0; i < level.length; i += batchSize) {
          batches.push(level.slice(i, i + batchSize));
        }

        for (const batch of batches) {
          const promises = batch.map(stepId =>
            this._executeStep(workflow.steps.get(stepId), onStepComplete)
          );
          const results = await Promise.all(promises);

          for (const result of results) {
            if (result.status === 'completed') {
              completed++;
            } else {
              failed++;
            }
          }
        }
      }
    }

    // Generate report
    const report = {
      workflow: workflow.name,
      status: failed === 0 ? 'completed' : 'partial',
      totalSteps,
      completed,
      failed,
      environment: this.env.toJSON(),
      executionLog: this.executionLog,
    };

    console.log(`\n✅ 工作流完成: ${completed}/${totalSteps} 成功`);

    return report;
  }

  /**
   * Execute a single step
   * @param {Step} step
   * @param {Function} callback
   * @returns {Promise<Object>}
   */
  async _executeStep(step, callback = null) {
    console.log(`  ▶️  ${step.id} (${step.agentId}.${step.action})`);

    step.status = StepStatus.RUNNING;
    step.startTime = new Date();

    try {
      // Get agent
      const agent = this.agents.get(step.agentId);
      if (!agent) {
        throw new Error(`Agent not found: ${step.agentId}`);
      }

      // Build execution context
      const context = this.env.getAll();

      // Execute agent action
      let result;
      if (typeof agent[step.action] === 'function') {
        result = await agent[step.action](context);
      } else if (typeof agent === 'function') {
        result = await agent(step.action, context);
      } else {
        throw new Error(`Agent ${step.agentId} 无法执行 ${step.action}`);
      }

      // Store result
      if (step.outputKey) {
        this.env.put(step.outputKey, result, step.agentId);
      }

      step.result = result;
      step.status = StepStatus.COMPLETED;
      step.endTime = new Date();

      const duration = (step.endTime - step.startTime) / 1000;

      // Log execution
      this.executionLog.push({
        stepId: step.id,
        agentId: step.agentId,
        action: step.action,
        status: 'completed',
        duration,
        outputKey: step.outputKey,
      });

      console.log(`  ✅ ${step.id} 完成 (${duration.toFixed(2)}s)`);

      // Callback
      if (callback) {
        callback(step, result);
      }

      return { status: 'completed', result };
    } catch (e) {
      step.status = StepStatus.FAILED;
      step.error = e.message;
      step.endTime = new Date();

      const duration = (step.endTime - step.startTime) / 1000;

      this.executionLog.push({
        stepId: step.id,
        agentId: step.agentId,
        action: step.action,
        status: 'failed',
        error: e.message,
        duration,
      });

      console.log(`  ❌ ${step.id} 失败: ${e.message}`);

      // Retry
      if (step.retry > 0) {
        console.log(`  🔄 重试 ${step.id}...`);
        step.retry--;
        step.status = StepStatus.PENDING;
        return this._executeStep(step, callback);
      }

      return { status: 'failed', error: e.message };
    }
  }
}

// ============================================================
// Workflow Templates
// ============================================================

/**
 * Create a software development workflow
 * @returns {Workflow}
 */
export function createSoftwareDevWorkflow() {
  const workflow = new Workflow('software-development', WorkflowType.HYBRID);

  // PM analyzes requirements
  workflow.addStep({
    id: 'pm_analyze',
    agentId: 'pm',
    action: 'analyzeRequirements',
    outputKey: 'requirements',
  });

  // Architect designs system
  workflow.addStep({
    id: 'architect_design',
    agentId: 'architect',
    action: 'designSystem',
    dependsOn: ['pm_analyze'],
    outputKey: 'design',
  });

  // Frontend and backend develop in parallel
  workflow.addStep({
    id: 'frontend_code',
    agentId: 'frontend_engineer',
    action: 'implement',
    dependsOn: ['architect_design'],
    outputKey: 'frontend_code',
  });

  workflow.addStep({
    id: 'backend_code',
    agentId: 'backend_engineer',
    action: 'implement',
    dependsOn: ['architect_design'],
    outputKey: 'backend_code',
  });

  // QA tests
  workflow.addStep({
    id: 'qa_test',
    agentId: 'qa',
    action: 'test',
    dependsOn: ['frontend_code', 'backend_code'],
    outputKey: 'test_report',
  });

  // DevOps deploys
  workflow.addStep({
    id: 'deploy',
    agentId: 'devops',
    action: 'deploy',
    dependsOn: ['qa_test'],
    outputKey: 'deployment',
  });

  return workflow;
}

/**
 * Create a research workflow
 * @returns {Workflow}
 */
export function createResearchWorkflow() {
  const workflow = new Workflow('research', WorkflowType.DAG);

  // Data collection (parallel)
  workflow.addStep({
    id: 'collect_web',
    agentId: 'researcher',
    action: 'collectWebData',
    outputKey: 'web_data',
  });

  workflow.addStep({
    id: 'collect_api',
    agentId: 'researcher',
    action: 'collectApiData',
    outputKey: 'api_data',
  });

  // Data analysis (waits for collection)
  workflow.addStep({
    id: 'analyze',
    agentId: 'analyst',
    action: 'analyze',
    dependsOn: ['collect_web', 'collect_api'],
    outputKey: 'analysis',
  });

  // Generate report
  workflow.addStep({
    id: 'report',
    agentId: 'pm',
    action: 'writeReport',
    dependsOn: ['analyze'],
    outputKey: 'report',
  });

  return workflow;
}

/**
 * Create a code review workflow
 * @returns {Workflow}
 */
export function createCodeReviewWorkflow() {
  const workflow = new Workflow('code-review', WorkflowType.SOP);

  workflow.addStep({
    id: 'check_style',
    agentId: 'qa',
    action: 'checkCodeStyle',
    outputKey: 'style_report',
  });

  workflow.addStep({
    id: 'security_scan',
    agentId: 'security',
    action: 'scanSecurity',
    dependsOn: ['check_style'],
    outputKey: 'security_report',
  });

  workflow.addStep({
    id: 'review',
    agentId: 'architect',
    action: 'reviewCode',
    dependsOn: ['security_scan'],
    outputKey: 'review_comments',
  });

  return workflow;
}

