import { attributeMemoryScore, getAttributionPieChart, attributeQueryResults } from '../memory_attribution.js';
import { analyzeRetrievalPatterns, getRetrievalQualityScore } from '../trace_analyzer.js';

/**
 * Register debug tools with MCP server
 * @param {object} server - MCP server instance
 */
export function registerDebugTools(server) {
  // Tool: memory_replay_query - replay a historical query
  server.registerTool('memory_replay_query', {
    description: 'Replay a historical query and see its full retrieval pipeline trace. Like "git blame" for memory retrieval - trace exactly how results were retrieved.',
    inputSchema: z.object({
      queryId: z.string().describe('The trace query ID (format: qt-xxx). Use memory_trace_stats to find recent query IDs.'),
    }),
  }, async ({ queryId }) => {
    try {
      const result = await replayQuery(queryId);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify(result, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Replay error: ${err.message}` }], isError: true };
    }
  });

  // Tool: memory_trace_memory - show retrieval history for a specific memory
  server.registerTool('memory_trace_memory', {
    description: 'Show all queries that retrieved a specific memory and how it ranked. See if a memory is being consistently retrieved or is getting lost.',
    inputSchema: z.object({
      memoryId: z.string().describe('Memory ID to trace'),
    }),
  }, async ({ memoryId }) => {
    try {
      const result = replayMemory(memoryId);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify(result, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Trace error: ${err.message}` }], isError: true };
    }
  });

  // Tool: memory_explain_rank - explain why a memory ranked where it did
  server.registerTool('memory_explain_rank', {
    description: 'Explain why a memory ranked where it did. Shows which factors contributed to its score: BM25, vector similarity, entity boost, importance, recency, etc.',
    inputSchema: z.object({
      memoryId: z.string().describe('Memory ID to explain'),
      queryId: z.string().optional().describe('Optional specific query trace ID. Uses most recent if not provided.'),
    }),
  }, async ({ memoryId, queryId }) => {
    try {
      const result = explainMemoryRetrieval(memoryId);
      if (result.success) {
        // Also get pie chart
        const pieResult = getAttributionPieChart(memoryId, queryId);
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({
              ...result,
              pieChart: pieResult.pieChart,
              asciiChart: pieResult.asciiChart,
            }, null, 2),
          }],
        };
      }
      return { content: [{ type: 'text', text: JSON.stringify(result, null, 2) }] };
    } catch (err) {
      return { content: [{ type: 'text', text: `Explain error: ${err.message}` }], isError: true };
    }
  });

  // Tool: memory_trace_stats - overall retrieval quality stats
  server.registerTool('memory_trace_stats', {
    description: 'Get overall retrieval quality statistics. Shows patterns, biases, failing queries, and tuning suggestions based on all traced searches.',
    inputSchema: z.object({
      limit: z.number().optional().default(200).describe('Number of recent traces to analyze (default 200)'),
    }),
  }, async ({ limit }) => {
    try {
      const analysis = analyzeRetrievalPatterns(limit);
      const qualityScore = getRetrievalQualityScore(limit);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            qualityScore: `${qualityScore}/100`,
            ...analysis,
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Stats error: ${err.message}` }], isError: true };
    }
  });

  // Tool: memory_diff_queries - compare two query retrieval paths
  server.registerTool('memory_diff_queries', {
    description: 'Compare two query retrieval paths side by side. See what\'s different between two searches.',
    inputSchema: z.object({
      queryId1: z.string().describe('First query trace ID'),
      queryId2: z.string().describe('Second query trace ID'),
    }),
  }, async ({ queryId1, queryId2 }) => {
    try {
      const result = await diffQueries(queryId1, queryId2);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify(result, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Diff error: ${err.message}` }], isError: true };
    }
  });

  // Tool: memory_search_traces - find traces by query text
  server.registerTool('memory_search_traces', {
    description: 'Search through historical query traces by text. Find all traces that match a query substring.',
    inputSchema: z.object({
      query: z.string().describe('Query text to search for'),
      limit: z.number().optional().default(20).describe('Maximum results to return'),
    }),
  }, async ({ query, limit }) => {
    try {
      const traces = findTracesByQuery(query);
      const limited = traces.slice(0, limit).map(t => ({
        queryId: t.queryId,
        query: t.query,
        timestamp: t.timestamp,
        durationMs: t.durationMs,
        resultCount: t.finalRanking?.length || 0,
      }));
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            found: limited.length,
            total: traces.length,
            traces: limited,
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Search error: ${err.message}` }], isError: true };
    }
  });

  // Tool: memory_clear_traces - clear all traces (debug only)
  server.registerTool('memory_clear_traces', {
    description: 'Clear all retrieval traces. Use for debugging or to reset trace storage.',
    inputSchema: z.object({
      confirm: z.boolean().describe('Must be true to confirm clearing'),
    }),
  }, async ({ confirm }) => {
    if (!confirm) {
      return { content: [{ type: 'text', text: 'Set confirm: true to clear traces' }] };
    }
    try {
      clearAllTraces();
      return { content: [{ type: 'text', text: JSON.stringify({ success: true, message: 'All traces cleared' }) }] };
    } catch (err) {
      return { content: [{ type: 'text', text: `Clear error: ${err.message}` }], isError: true };
    }
  });
}

export default registerDebugTools;
/**
 * memory_decay - 记忆时效性智能衰减
 * 基于半衰期的置信度自动衰减系统
 */

import { getAllMemories, saveMemories } from '../storage.js';
import { log } from '../config.js';

const DECAY_RULES = {
  task: { halfLife: 7, rate: 0.1 },
  preference: { halfLife: 30, rate: 0.03 },
  project: { halfLife: 90, rate: 0.02 },
  event: { halfLife: 14, rate: 0.05 },
  fact: { halfLife: 365, rate: 0.005 },
  decision: { halfLife: 180, rate: 0.01 },
  default: { halfLife: 30, rate: 0.03 }
};

const CATEGORY_MAP = {
  task: 'task', todo: 'task', action: 'task',
  preference: 'preference', like: 'preference', habit: 'preference',
  project: 'project',
  event: 'event', meeting: 'event',
  fact: 'fact', knowledge: 'fact', info: 'fact',
  decision: 'decision', choice: 'decision', critical: 'decision',
  other: 'default', legacy: 'default', entity: 'fact', relation: 'fact'
};

function getDecayRule(category) {
  const type = CATEGORY_MAP[category] || 'default';
  return DECAY_RULES[type] || DECAY_RULES.default;
}

function calculateDecay(mem, currentTime) {
  const rule = getDecayRule(mem.category || 'other');
  const created = new Date(mem.created_at || Date.now()).getTime();
  const ageInDays = (currentTime - created) / (1000 * 60 * 60 * 24);
  
  // Exponential decay using half-life
  const importance = mem.importance ?? 0.5;
  const decayFactor = Math.pow(0.5, ageInDays / rule.halfLife);
  const newImportance = Math.max(0.1, importance * decayFactor);
  
  return {
    id: mem.id,
    original: importance,
    new: Math.round(newImportance * 1000) / 1000,
    age_days: Math.round(ageInDays * 10) / 10,
    category: mem.category
  };
}

export async function decayMemories({ apply = false } = {}) {
  const memories = await getAllMemories();
  const currentTime = Date.now();
  
  const decayed = memories.map(mem => calculateDecay(mem, currentTime));
  
  // Stats
  const stats = {
    total: memories.length,
    significantly_decayed: decayed.filter(d => d.new < d.original * 0.5).length,
    slightly_decayed: decayed.filter(d => d.new < d.original * 0.9 && d.new >= d.original * 0.5).length,
    unchanged: decayed.filter(d => d.new >= d.original * 0.9).length
  };
  
  if (apply) {
    const updated = memories.map(mem => {
      const d = decayed.find(x => x.id === mem.id);
      return { ...mem, importance: d.new };
    });
    saveMemories(updated);
    log('INFO', `Applied decay to ${memories.length} memories`);
  }
  
  return {
    content: [{
      type: 'text',
      text: JSON.stringify({ stats, decayed: decayed.slice(0, 20), applied: apply }, null, 2)
    }]
  };
}
/**
 * memory_dedup - 记忆去重检测
 * 检测相似记忆并可选合并
 */

import { getAllMemories, saveMemories } from '../storage.js';
import { simpleHash, levenshteinDistance } from '../utils/text.js';

export async function dedupMemories({ threshold = 0.85, dryRun = true }) {
  const memories = await getAllMemories();
  
  if (memories.length < 2) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({ message: '记忆少于2条，无需去重', count: memories.length }, null, 2)
      }]
    };
  }
  
  // Build hash index for quick candidate lookup
  const hashIndex = new Map();
  const duplicates = [];
  
  for (const mem of memories) {
    const hash = simpleHash(mem.text);
    if (!hashIndex.has(hash)) {
      hashIndex.set(hash, []);
    }
    hashIndex.get(hash).push(mem);
  }
  
  // Find duplicates via hash + Levenshtein
  const checked = new Set();
  
  for (const [hash, candidates] of hashIndex) {
    if (candidates.length > 1) {
      // Exact duplicates
      for (let i = 1; i < candidates.length; i++) {
        duplicates.push({
          type: 'exact',
          original: candidates[0],
          duplicate: candidates[i],
          similarity: 1.0
        });
        checked.add(candidates[i].id);
      }
    }
  }
  
  // Fuzzy matches (only if few exact dupes)
  if (duplicates.length < 3) {
    for (let i = 0; i < memories.length; i++) {
      for (let j = i + 1; j < memories.length; j++) {
        if (checked.has(memories[i].id) && checked.has(memories[j].id)) continue;
        
        const dist = levenshteinDistance(memories[i].text, memories[j].text);
        const maxLen = Math.max(memories[i].text.length, memories[j].text.length);
        const similarity = maxLen === 0 ? 0 : 1 - dist / maxLen;
        
        if (similarity >= threshold) {
          duplicates.push({
            type: 'fuzzy',
            original: memories[i],
            duplicate: memories[j],
            similarity: Math.round(similarity * 1000) / 1000
          });
          checked.add(memories[j].id);
        }
      }
    }
  }
  
  // Apply if not dry run
  if (!dryRun && duplicates.length > 0) {
    const idsToRemove = new Set(duplicates.map(d => d.duplicate.id));
    const kept = memories.filter(m => !idsToRemove.has(m.id));
    saveMemories(kept);
  }
  
  return {
    content: [{
      type: 'text',
      text: JSON.stringify({
        total_memories: memories.length,
        duplicates_found: duplicates.length,
        duplicates,
        action: dryRun ? 'dry_run' : 'applied'
      }, null, 2)
    }]
  };
}
/**
 * dedup_report.js - Dedup Report & Manual Merge Tools
 *
 * Tools:
 *   memory_dedup_full_scan → Scan all memories for semantic duplicates
 *   memory_dedup_merge     → Manually merge a pair of memories
 */

import { z } from 'zod';
import { findAllDuplicatePairs, loadDedupLog } from '../semantic_dedup.js';
import { applyDedup, STRATEGY_ABSORB, STRATEGY_MERGE, STRATEGY_KEEP_BOTH } from '../dedup_merger.js';
import { getMemory } from '../storage.js';

const dedupFullScanSchema = z.object({
  threshold: z.number().optional().default(0.85).describe('Minimum similarity threshold (0–1)'),
  topK: z.number().optional().default(50).describe('Maximum number of duplicate pairs to return'),
});

const dedupMergeSchema = z.object({
  memoryIdA: z.string().describe('ID of first memory'),
  memoryIdB: z.string().describe('ID of second memory'),
  similarity: z.number().optional().describe('Pre-computed similarity (if known, skips computation)'),
  autoMerge: z.boolean().optional().default(false).describe('If true, auto-apply the merge; if false, return suggestion'),
});

/**
 * memory_dedup_full_scan tool
 * Scans ALL memories for semantic duplicate pairs.
 */
export async function memoryDeduFullScan(args) {
  const parsed = dedupFullScanSchema.safeParse(args);
  if (!parsed.success) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({ error: 'Invalid args', details: parsed.error.format() }),
      }],
      isError: true,
    };
  }

  const { threshold, topK } = parsed.data;

  let result;
  try {
    result = await findAllDuplicatePairs({ threshold, maxPairs: topK });
  } catch (err) {
    return {
      content: [{ type: 'text', text: JSON.stringify({ error: `Scan failed: ${err.message}` }) }],
      isError: true,
    };
  }

  // Group by strategy
  const absorbPairs = result.pairs.filter(p => p.strategy === STRATEGY_ABSORB);
  const mergePairs = result.pairs.filter(p => p.strategy === STRATEGY_MERGE);
  const keepPairs = result.pairs.filter(p => p.strategy === STRATEGY_KEEP_BOTH);

  return {
    content: [{
      type: 'text',
      text: JSON.stringify({
        scan: 'full semantic dedup scan',
        stats: result.stats,
        summary: {
          absorbCandidates: absorbPairs.length,
          mergeCandidates: mergePairs.length,
          differentAspectPairs: keepPairs.length,
        },
        absorbPairs: absorbPairs.slice(0, 20),
        mergePairs: mergePairs.slice(0, 20),
        // don't show keep_both pairs in report — they're not actionable
        totalPairsShown: Math.min(result.pairs.length, topK),
        threshold,
      }, null, 2),
    }],
  };
}

/**
 * memory_dedup_merge tool
 * Manually merges two memories. If similarity not provided, computes it.
 */
export async function memoryDeduMerge(args) {
  const parsed = dedupMergeSchema.safeParse(args);
  if (!parsed.success) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({ error: 'Invalid args', details: parsed.error.format() }),
      }],
      isError: true,
    };
  }

  const { memoryIdA, memoryIdB, similarity, autoMerge } = parsed.data;

  const memA = getMemory(memoryIdA);
  const memB = getMemory(memoryIdB);

  if (!memA || !memB) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          error: 'Memory not found',
          found: { A: !!memA, B: !!memB },
          ids: { memoryIdA, memoryIdB },
        }),
      }],
      isError: true,
    };
  }

  // Compute similarity if not provided
  let sim = similarity;
  if (sim === undefined || sim === null) {
    const { cosineSimilarity } = await import('../semantic_dedup.js');
    const { getEmbeddingCached } = await import('../vector.js');
    try {
      const embA = await getEmbeddingCached(memA.text);
      const embB = await getEmbeddingCached(memB.text);
      if (embA && embB) {
        sim = cosineSimilarity(embA, embB);
      } else {
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({ error: 'Could not compute embeddings for one or both memories' }),
          }],
          isError: true,
        };
      }
    } catch (err) {
      return {
        content: [{ type: 'text', text: JSON.stringify({ error: `Embedding failed: ${err.message}` }) }],
        isError: true,
      };
    }
  }

  const result = applyDedup(memA, memB, sim, autoMerge);

  return {
    content: [{
      type: 'text',
      text: JSON.stringify({
        memoryIdA,
        memoryIdB,
        similarity: sim,
        ...result,
      }, null, 2),
    }],
  };
}

/**
 * memory_dedup_log tool
 * Returns the dedup merge history log.
 */
export async function memoryDeduLog() {
  try {
    const log = loadDedupLog();
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          merges: log.merges.slice(-50).reverse(),
          scans: log.scans.slice(-20).reverse(),
          totalMerges: log.merges.length,
          totalScans: log.scans.length,
        }, null, 2),
      }],
    };
  } catch (err) {
    return {
      content: [{ type: 'text', text: JSON.stringify({ error: `Failed to load log: ${err.message}` }) }],
      isError: true,
    };
  }
}

export default { memoryDeduFullScan, memoryDeduMerge, memoryDeduLog };
/**
 * Entity Tools - MCP tools for knowledge graph entity operations
 *
 * P0-2: Exposes entity graph operations as MCP tools
 *
 * Tools:
 * - memory_entity_extract: Extract entities from text (rule-based)
 * - memory_entity_link: Create a relation between two entities
 * - memory_entity_neighbors: Get neighbor entities of a given entity
 * - memory_entity_search: Graph-expanded search
 *
 * @module tools/entity_tools
 */

import { extractEntitiesRuleBased } from '../graph/entity.js';
import { loadGraph, addEntity, addRelation, getNeighbors, findEntityById, findEntity, getGraphStats } from '../graph/graph_store.js';
import { expandQueryWithGraph } from './graph_search.js';

/**
 * Extract entities from text using rule-based extraction.
 *
 * @param {string} text - Text to extract entities from
 * @returns {{ content: Array<{type: 'text', text: string}> }}
 */
export function memoryEntityExtractTool({ text }) {
  try {
    if (!text || !text.trim()) {
      return { content: [{ type: 'text', text: JSON.stringify({ count: 0, entities: [] }, null, 2) }] };
    }

    const entities = extractEntitiesRuleBased(text);

    // Add each entity to the graph store
    for (const e of entities) {
      addEntity({ name: e.name, type: e.type, description: null, memory_ids: [] });
    }

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          count: entities.length,
          entities: entities.map(e => ({
            name: e.name,
            type: e.type,
            method: e.method,
          })),
          graph_stats: getGraphStats(),
        }, null, 2),
      }],
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Entity extract error: ${err.message}` }], isError: true };
  }
}

/**
 * Create a relation between two entities.
 *
 * @param {object} params
 * @param {string} params.from - Source entity name or ID
 * @param {string} params.to - Target entity name or ID
 * @param {string} params.relation - Relation type (worked_with, related_to, etc.)
 * @param {number} [params.strength] - Relation strength/confidence 0-1 (default 0.8)
 * @returns {{ content: Array<{type: 'text', text: string}> }}
 */
export function memoryEntityLinkTool({ from, to, relation, strength = 0.8 }) {
  try {
    if (!from || !to || !relation) {
      return { content: [{ type: 'text', text: 'Error: from, to, and relation are required' }], isError: true };
    }

    const graph = loadGraph();

    // Resolve from entity
    let fromEntity = graph.entities.find(e => e.id === from || e.name === from);
    if (!fromEntity) {
      // Auto-create the entity if it doesn't exist
      fromEntity = addEntity({ name: from, type: 'other', description: null, memory_ids: [] });
    }

    // Resolve to entity
    let toEntity = graph.entities.find(e => e.id === to || e.name === to);
    if (!toEntity) {
      toEntity = addEntity({ name: to, type: 'other', description: null, memory_ids: [] });
    }

    // Add the relation
    const rel = addRelation({
      from: fromEntity.id,
      to: toEntity.id,
      relation,
      confidence: Math.min(1, Math.max(0, strength)),
      source: 'manual',
    });

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          success: true,
          relation: {
            id: rel.id,
            from: fromEntity.name,
            to: toEntity.name,
            relation: rel.relation,
            confidence: rel.confidence,
          },
        }, null, 2),
      }],
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Entity link error: ${err.message}` }], isError: true };
  }
}

/**
 * Get neighbor entities of a given entity.
 *
 * @param {object} params
 * @param {string} params.entity - Entity name or ID
 * @param {string} [params.relationType] - Filter by relation type
 * @returns {{ content: Array<{type: 'text', text: string}> }}
 */
export function memoryEntityNeighborsTool({ entity, relationType }) {
  try {
    if (!entity) {
      return { content: [{ type: 'text', text: 'Error: entity is required' }], isError: true };
    }

    const graph = loadGraph();

    // Resolve entity
    let entityObj = graph.entities.find(e => e.id === entity || e.name === entity);
    if (!entityObj) {
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            error: `Entity not found: ${entity}`,
            available_entities: graph.entities.slice(0, 20).map(e => ({ id: e.id, name: e.name, type: e.type })),
          }, null, 2),
        }],
      };
    }

    const neighbors = getNeighbors(entityObj.id, relationType || null);

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          entity: { id: entityObj.id, name: entityObj.name, type: entityObj.type, count: entityObj.count },
          neighbors: neighbors.map(n => ({
            id: n.entity.id,
            name: n.entity.name,
            type: n.entity.type,
            relation: n.relation,
            weight: n.weight,
          })),
          graph_stats: getGraphStats(),
        }, null, 2),
      }],
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Entity neighbors error: ${err.message}` }], isError: true };
  }
}

/**
 * Search using graph-expanded query (graph-enhanced search).
 *
 * @param {object} params
 * @param {string} params.query - Search query
 * @param {number} [params.topK] - Number of results (default 5)
 * @param {string} [params.scope] - Scope filter
 * @returns {{ content: Array<{type: 'text', text: string}> }}
 */
export async function memoryEntitySearchTool({ query, topK = 5, scope }) {
  try {
    if (!query) {
      return { content: [{ type: 'text', text: 'Error: query is required' }], isError: true };
    }

    // Expand query with graph
    const { expandedQuery, entities, expanded } = expandQueryWithGraph(query, 5);

    // Import the search pipeline
    const { hybridSearch } = await import('../fusion.js');
    const results = await hybridSearch(query, topK, 'hybrid', scope || null);

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          original_query: query,
          expanded_query: expanded ? expandedQuery : null,
          graph_expanded: expanded,
          graph_entities: entities.map(e => ({ name: e.name, type: e.type, graph_id: e.graphId })),
          count: results.length,
          results: results.map(r => ({
            id: r.memory.id,
            text: r.memory.text,
            category: r.memory.category,
            importance: r.memory.importance,
            score: Math.round(r.fusionScore * 1000) / 1000,
          })),
        }, null, 2),
      }],
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Entity search error: ${err.message}` }], isError: true };
  }
}
/**
 * Episode Tools - MCP tool definitions for episode management
 *
 * Provides tools:
 * - memory_episode_start: Start a new episode
 * - memory_episode_add: Add message to episode
 * - memory_episode_complete: Complete and summarize episode
 * - memory_episode_search: Search within episodes
 * - memory_episode_list: List episodes
 */

import { z } from 'zod';
import {
  startEpisode,
  addMessage,
  completeEpisode,
  archiveOldEpisodes,
  searchEpisodes,
  getEpisodeContext,
  episodeList,
  getEpisodeWithMessages,
  getEpisodeStats,
} from '../episode_manager.js';

import { getActiveEpisode, EPISODE_STATUS } from '../episode_store.js';

/**
 * Register episode tools with the MCP server
 * @param {object} server - MCP server instance
 */
export function registerEpisodeTools(server) {
  // ─── memory_episode_start ──────────────────────────────────────────────────

  server.registerTool('memory_episode_start', {
    description: 'Start a new conversation episode. An episode represents a complete conversation session that can be searched later.',
    inputSchema: z.object({
      sessionId: z.string().describe('Unique session identifier (e.g., user ID, conversation ID)'),
      participants: z.array(z.string()).optional().default([]).describe('List of participant names/IDs'),
      title: z.string().optional().describe('Optional title for the episode'),
      tags: z.array(z.string()).optional().default([]).describe('Optional tags'),
    }),
  }, async ({ sessionId, participants = [], title, tags = [] }) => {
    try {
      const episode = startEpisode(sessionId, participants, { title, tags });
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: true,
            episode: {
              id: episode.id,
              sessionId: episode.sessionId,
              state: episode.state,
              startTime: new Date(episode.startTime).toISOString(),
              participants: episode.participants,
              title: episode.title,
            },
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_add ─────────────────────────────────────────────────────

  server.registerTool('memory_episode_add', {
    description: 'Add a message to an active episode.',
    inputSchema: z.object({
      sessionId: z.string().describe('Session ID (to find active episode or create new)'),
      role: z.enum(['user', 'assistant', 'system']).describe('Message role'),
      content: z.string().describe('Message content'),
      messageId: z.string().optional().describe('Optional external message ID'),
      participant: z.string().optional().default('default').describe('Participant identifier'),
    }),
  }, async ({ sessionId, role, content, messageId, participant = 'default' }) => {
    try {
      const result = await addMessage(sessionId, role, content, messageId, {
        participant,
      });

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: result.added,
            episodeId: result.episodeId,
            messageCount: result.messageCount,
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_complete ────────────────────────────────────────────────

  server.registerTool('memory_episode_complete', {
    description: 'Complete an active episode and generate a summary. Also extracts decision memories.',
    inputSchema: z.object({
      episodeId: z.string().describe('Episode ID to complete'),
      summary: z.object({
        title: z.string().optional(),
        keyTopics: z.array(z.string()).optional(),
        decisions: z.array(z.string()).optional(),
        nextSteps: z.array(z.string()).optional(),
      }).optional().describe('Optional override summary data'),
    }),
  }, async ({ episodeId, summary }) => {
    try {
      const result = await completeEpisode(episodeId, summary || null);

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: true,
            episode: {
              id: result.episode.id,
              state: result.episode.state,
              endTime: result.episode.endTime ? new Date(result.episode.endTime).toISOString() : null,
            },
            summary: result.summary,
            decisionsExtracted: result.decisionMemories.length,
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_search ─────────────────────────────────────────────────

  server.registerTool('memory_episode_search', {
    description: 'Search within episode messages. Finds episodes containing specific content.',
    inputSchema: z.object({
      query: z.string().describe('Search query text'),
      limit: z.number().optional().default(10).describe('Maximum results'),
      state: z.enum(['ACTIVE', 'COMPLETED', 'ARCHIVED']).optional().describe('Filter by episode state'),
      includeArchived: z.boolean().optional().default(false).describe('Include archived episodes in search'),
    }),
  }, async ({ query, limit = 10, state, includeArchived = false }) => {
    try {
      const results = searchEpisodes(query, { limit, state, includeArchived });

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            query,
            count: results.length,
            results: results.map(r => ({
              episode: {
                id: r.episode.id,
                sessionId: r.episode.sessionId,
                state: r.episode.state,
                title: r.episode.title,
                keyTopics: r.episode.keyTopics,
                messageCount: r.episode.messageCount,
              },
              relevance: r.relevance,
              matchCount: r.matchCount,
              matchedMessages: r.matchedMessages.slice(0, 3).map(m => ({
                role: m.role,
                content: m.content?.slice(0, 100),
                timestamp: new Date(m.timestamp).toISOString(),
              })),
            })),
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_list ───────────────────────────────────────────────────

  server.registerTool('memory_episode_list', {
    description: 'List all episodes with optional filtering.',
    inputSchema: z.object({
      state: z.enum(['ACTIVE', 'COMPLETED', 'ARCHIVED']).optional().describe('Filter by episode state'),
      limit: z.number().optional().default(20).describe('Number of episodes to return'),
      offset: z.number().optional().default(0).describe('Offset for pagination'),
      includeArchived: z.boolean().optional().default(false).describe('Include archived episodes'),
    }),
  }, async ({ state, limit = 20, offset = 0, includeArchived = false }) => {
    try {
      const result = episodeList({ state, limit, offset, includeArchived });

      return {
        content: [{
          type: 'text',
          text: JSON.stringify(result, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_get ────────────────────────────────────────────────────

  server.registerTool('memory_episode_get', {
    description: 'Get full details of a specific episode including all messages.',
    inputSchema: z.object({
      episodeId: z.string().describe('Episode ID to retrieve'),
    }),
  }, async ({ episodeId }) => {
    try {
      const episode = getEpisodeWithMessages(episodeId);

      if (!episode) {
        return { content: [{ type: 'text', text: JSON.stringify({ error: 'Episode not found' }) }], isError: true };
      }

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            id: episode.id,
            sessionId: episode.sessionId,
            state: episode.state,
            startTime: episode.startTime ? new Date(episode.startTime).toISOString() : null,
            endTime: episode.endTime ? new Date(episode.endTime).toISOString() : null,
            lastActivity: episode.lastActivity ? new Date(episode.lastActivity).toISOString() : null,
            messageCount: episode.messageCount,
            participants: episode.participants,
            title: episode.title,
            summary: episode.summary,
            keyTopics: episode.keyTopics,
            decisions: episode.decisions,
            nextSteps: episode.nextSteps,
            tags: episode.tags,
            memoryIds: episode.memoryIds,
            messages: episode.messages?.map(m => ({
              role: m.role,
              content: m.content,
              timestamp: new Date(m.timestamp).toISOString(),
            })),
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_archive ────────────────────────────────────────────────

  server.registerTool('memory_episode_archive', {
    description: 'Archive old completed episodes (move to cold storage).',
    inputSchema: z.object({
      daysOld: z.number().optional().default(30).describe('Archive episodes older than this many days'),
    }),
  }, async ({ daysOld = 30 }) => {
    try {
      const count = archiveOldEpisodes(daysOld);

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: true,
            archived: count,
            message: `Archived ${count} episodes older than ${daysOld} days`,
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_stats ─────────────────────────────────────────────────

  server.registerTool('memory_episode_stats', {
    description: 'Get episode statistics.',
    inputSchema: z.object({}),
  }, async () => {
    try {
      const stats = getEpisodeStats();
      return {
        content: [{
          type: 'text',
          text: JSON.stringify(stats, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_episode_context ────────────────────────────────────────────────

  server.registerTool('memory_episode_context', {
    description: 'Get episode messages as context for a search query. Useful for "what did we discuss about X".',
    inputSchema: z.object({
      query: z.string().describe('Search query'),
      maxMessages: z.number().optional().default(10).describe('Max messages per episode'),
    }),
  }, async ({ query, maxMessages = 10 }) => {
    try {
      const context = await getEpisodeContext(query, maxMessages);

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            query,
            episodes: context.map(c => ({
              episodeId: c.episodeId,
              sessionId: c.sessionId,
              title: c.title,
              relevance: c.relevance,
              keyTopics: c.keyTopics,
              decisions: c.decisions,
              messages: c.messages.map(m => ({
                role: m.role,
                content: m.content?.slice(0, 150),
                relevance: m.relevance,
              })),
            })),
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });
}

export default { registerEpisodeTools };
/**
 * memory_export - 记忆导出工具
 * 支持 json / markdown / csv 格式
 */

import { getAllMemories } from '../storage.js';
import { writeFileSync } from 'fs';
import { join } from 'path';

const EXPORTS_DIR = join(process.env.HOME || '/root', '.openclaw/workspace/memory/exports');

export async function exportMemories({ format = 'json', output, category, minImportance }) {
  const memories = getAllMemories();
  
  // Filter
  let filtered = memories;
  if (category) {
    filtered = filtered.filter(m => m.category === category);
  }
  if (minImportance !== undefined) {
    filtered = filtered.filter(m => (m.importance || 0) >= minImportance);
  }
  
  let content;
  let filename;
  
  if (format === 'json') {
    content = JSON.stringify({ memories: filtered, count: filtered.length }, null, 2);
    filename = output || `memories_${Date.now()}.json`;
  } else if (format === 'markdown') {
    content = generateMarkdown(filtered);
    filename = output || `memories_${Date.now()}.md`;
  } else if (format === 'csv') {
    content = generateCSV(filtered);
    filename = output || `memories_${Date.now()}.csv`;
  } else {
    return { content: [{ type: 'text', text: `Unsupported format: ${format}` }], isError: true };
  }
  
  try {
    writeFileSync(filename, content, 'utf-8');
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          success: true,
          format,
          count: filtered.length,
          path: filename
        }, null, 2)
      }]
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `导出失败: ${err.message}` }], isError: true };
  }
}

function generateMarkdown(memories) {
  const byCategory = {};
  for (const mem of memories) {
    const cat = mem.category || '未分类';
    if (!byCategory[cat]) byCategory[cat] = [];
    byCategory[cat].push(mem);
  }
  
  let md = `# 记忆导出\n\n导出时间: ${new Date().toISOString()}\n总共: ${memories.length} 条记忆\n\n`;
  
  for (const [cat, items] of Object.entries(byCategory)) {
    md += `## ${cat}\n\n`;
    for (const mem of items) {
      md += `- **${mem.text.slice(0, 100)}** (重要性: ${mem.importance || 0.5})\n`;
      if (mem.tags && mem.tags.length) md += `  - 标签: ${mem.tags.join(', ')}\n`;
      md += `\n`;
    }
  }
  
  return md;
}

function generateCSV(memories) {
  const headers = ['id', 'text', 'category', 'importance', 'tags', 'created_at'];
  const rows = [headers.join(',')];
  
  for (const mem of memories) {
    const row = [
      mem.id || '',
      `"${(mem.text || '').replace(/"/g, '""')}"`,
      mem.category || '',
      mem.importance || 0.5,
      (mem.tags || []).join(';'),
      mem.created_at || ''
    ];
    rows.push(row.join(','));
  }
  
  return rows.join('\n');
}
/**
 * Feedback Learner - 反馈学习闭环 v7.0
 * 
 * Features:
 * - Track memory usage effectiveness
 * - Adjust importance based on feedback
 * - Record correction history
 * - Support active learning
 * 
 * Usage:
 *   node feedback_learner.js track <memory_id> <outcome>
 *   node feedback_learner.js adjust
 *   node feedback_learner.js corrections
 *   node feedback_learner.js learn <correction>
 *   node feedback_learner.js stats
 */

import fs from 'fs/promises';
import path from 'path';
import { fileURLToPath } from 'url';
import os from 'os';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// ========== Configuration ==========

const WORKSPACE = path.join(os.homedir(), '.openclaw', 'workspace');
const MEMORY_DIR = path.join(WORKSPACE, 'memory');
const FEEDBACK_DIR = path.join(MEMORY_DIR, 'feedback');

const IMPORTANCE_BOOST = 0.1;
const IMPORTANCE_DECAY = 0.1;
const MIN_IMPORTANCE = 0.1;
const MAX_IMPORTANCE = 1.0;

const FEEDBACK_LOG_FILE = path.join(FEEDBACK_DIR, 'feedback_log.jsonl');
const CORRECTIONS_FILE = path.join(FEEDBACK_DIR, 'corrections.json');
const IMPORTANCE_ADJUSTMENTS_FILE = path.join(FEEDBACK_DIR, 'importance_adjustments.json');

// Ensure directories exist
await fs.mkdir(FEEDBACK_DIR, { recursive: true });

// ========== Outcome Types ==========

const OUTCOME_HELPFUL = 'helpful';
const OUTCOME_IRRELEVANT = 'irrelevant';
const OUTCOME_WRONG = 'wrong';
const OUTCOME_OUTDATED = 'outdated';

// ========== Feedback Learner ==========

class FeedbackLearner {
  constructor() {
    this.feedbackLog = [];
    this.corrections = [];
    this.adjustments = {}; // memory_id -> adjustments
    this._load();
  }
  
  async _load() {
    try {
      if (await fileExists(FEEDBACK_LOG_FILE)) {
        const content = await fs.readFile(FEEDBACK_LOG_FILE, 'utf-8');
        const lines = content.split('\n').filter(l => l.trim());
        this.feedbackLog = lines.map(l => {
          try { return JSON.parse(l); }
          catch { return null; }
        }).filter(Boolean);
      }
      
      if (await fileExists(CORRECTIONS_FILE)) {
        this.corrections = JSON.parse(await fs.readFile(CORRECTIONS_FILE, 'utf-8'));
      }
      
      if (await fileExists(IMPORTANCE_ADJUSTMENTS_FILE)) {
        this.adjustments = JSON.parse(await fs.readFile(IMPORTANCE_ADJUSTMENTS_FILE, 'utf-8'));
      }
    } catch (e) {
      console.warn(`⚠️ 加载反馈数据失败: ${e.message}`);
    }
  }
  
  async _save() {
    try {
      const feedbackContent = this.feedbackLog.map(f => JSON.stringify(f)).join('\n');
      await fs.writeFile(FEEDBACK_LOG_FILE, feedbackContent, 'utf-8');
      await fs.writeFile(CORRECTIONS_FILE, JSON.stringify(this.corrections, null, 2), 'utf-8');
      await fs.writeFile(IMPORTANCE_ADJUSTMENTS_FILE, JSON.stringify(this.adjustments, null, 2), 'utf-8');
    } catch (e) {
      console.warn(`⚠️ 保存反馈数据失败: ${e.message}`);
    }
  }
  
  track(memoryId, outcome, context = null) {
    const feedback = {
      memory_id: memoryId,
      outcome,
      context: context ? context.slice(0, 200) : null,
      timestamp: new Date().toISOString()
    };
    
    this.feedbackLog.push(feedback);
    
    if (!(memoryId in this.adjustments)) {
      this.adjustments[memoryId] = [];
    }
    
    this.adjustments[memoryId].push({
      outcome,
      timestamp: feedback.timestamp
    });
    
    this._save();
    console.log(`📝 记录反馈: ${memoryId} -> ${outcome}`);
    
    return feedback;
  }
  
  adjustImportance(memories) {
    const adjustments = {};
    
    for (const mem of memories) {
      const memId = mem.id;
      if (!memId) continue;
      
      let currentImportance = parseFloat(mem.importance) || 0.5;
      const memAdjustments = this.adjustments[memId] || [];
      
      if (!memAdjustments.length) continue;
      
      // Get recent adjustments
      const recent = memAdjustments.filter(a => this._isRecent(a.timestamp));
      if (!recent.length) continue;
      
      // Count outcomes
      const outcomeCounts = {};
      for (const a of recent) {
        outcomeCounts[a.outcome] = (outcomeCounts[a.outcome] || 0) + 1;
      }
      
      // Adjust importance
      let newImportance = currentImportance;
      
      if (outcomeCounts[OUTCOME_HELPFUL] > 0) {
        newImportance = Math.min(MAX_IMPORTANCE, currentImportance + IMPORTANCE_BOOST * outcomeCounts[OUTCOME_HELPFUL]);
      }
      if (outcomeCounts[OUTCOME_IRRELEVANT] > 0) {
        newImportance = Math.max(MIN_IMPORTANCE, currentImportance - IMPORTANCE_DECAY * outcomeCounts[OUTCOME_IRRELEVANT]);
      }
      if (outcomeCounts[OUTCOME_WRONG] > 0 || outcomeCounts[OUTCOME_OUTDATED] > 0) {
        newImportance = Math.max(MIN_IMPORTANCE, currentImportance - IMPORTANCE_DECAY * 2);
      }
      
      if (newImportance !== currentImportance) {
        adjustments[memId] = {
          old: currentImportance,
          new: newImportance,
          delta: newImportance - currentImportance
        };
        mem.importance = newImportance;
      }
    }
    
    return adjustments;
  }
  
  _isRecent(timestamp) {
    if (!timestamp) return false;
    const ts = new Date(timestamp);
    const daysDiff = (Date.now() - ts.getTime()) / (1000 * 60 * 60 * 24);
    return daysDiff <= 7; // Within 7 days
  }
  
  learn(correction) {
    const entry = {
      id: `correction_${Date.now()}`,
      content: correction,
      learned_at: new Date().toISOString()
    };
    
    this.corrections.push(entry);
    this._save();
    console.log(`📚 学习修正: ${correction.slice(0, 50)}...`);
    
    return entry;
  }
  
  getCorrectionHistory(limit = 10) {
    return this.corrections.slice(-limit).reverse();
  }
  
  getFeedbackStats() {
    const stats = {
      total_feedback: this.feedbackLog.length,
      by_outcome: {},
      total_corrections: this.corrections.length,
      memories_with_feedback: Object.keys(this.adjustments).length
    };
    
    for (const feedback of this.feedbackLog) {
      const outcome = feedback.outcome;
      stats.by_outcome[outcome] = (stats.by_outcome[outcome] || 0) + 1;
    }
    
    return stats;
  }
  
  suggestForgetting(memories, threshold = 0.2) {
    const forgettable = [];
    
    for (const mem of memories) {
      const memId = mem.id;
      if (!memId) continue;
      
      const memAdjustments = this.adjustments[memId] || [];
      const recent = memAdjustments.filter(a => this._isRecent(a.timestamp));
      
      if (recent.length === 0) continue;
      
      // Check for repeated negative feedback
      const negativeCount = recent.filter(a => 
        a.outcome === OUTCOME_IRRELEVANT || 
        a.outcome === OUTCOME_WRONG || 
        a.outcome === OUTCOME_OUTDATED
      ).length;
      
      if (negativeCount >= 3) {
        forgettable.push({
          memory: mem,
          reason: 'repeated_negative_feedback',
          negative_count: negativeCount
        });
      }
    }
    
    return forgettable;
  }
  
  async loadMemories() {
    const memories = [];
    const files = (await fs.readdir(MEMORY_DIR)).filter(f => f.endsWith('.md'));
    
    for (const file of files) {
      const content = await fs.readFile(path.join(MEMORY_DIR, file), 'utf-8');
      const lines = content.split('\n');
      
      for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed || !trimmed.startsWith('-')) continue;
        
        const match = trimmed.match(/^- \[([^\]]+)\] \[([^\]]+)\] \[([^\]]+)\](?: \[I=([^\]]+)\])? (.+)$/);
        if (match) {
          const [, timestamp, category, scope, impStr, text] = match;
          memories.push({
            id: `mem_${memories.length}`,
            text,
            timestamp,
            category,
            scope,
            importance: impStr ? parseFloat(impStr) : 0.5
          });
        }
      }
    }
    
    return memories;
  }
  
  async saveMemories(memories) {
    // Group by date
    const byDate = {};
    
    for (const mem of memories) {
      const date = mem.timestamp?.slice(0, 10) || new Date().toISOString().slice(0, 10);
      if (!byDate[date]) byDate[date] = [];
      byDate[date].push(mem);
    }
    
    // Write each date file
    for (const [date, mems] of Object.entries(byDate)) {
      const file = path.join(MEMORY_DIR, `${date}.md`);
      const lines = mems.map(m => 
        `- [${m.timestamp}] [${m.category}] [${m.scope}] [I=${m.importance.toFixed(2)}] ${m.text}`
      ).join('\n') + '\n';
      
      try {
        const existing = await fileExists(file) ? await fs.readFile(file, 'utf-8') : '';
        // This is simplified - in production would preserve existing content
        await fs.writeFile(file, existing + lines, 'utf-8');
      } catch (e) {
        console.warn(`保存失败: ${file}: ${e.message}`);
      }
    }
  }
}

// ========== Utilities ==========

async function fileExists(filePath) {
  try {
    await fs.access(filePath);
    return true;
  } catch {
    return false;
  }
}

// ========== CLI ==========

async function main() {
  const args = process.argv.slice(2);
  const command = args[0];
  
  if (!command) {
    console.log(`
Feedback Learner - 反馈学习闭环 v7.0

Usage:
    node feedback_learner.js track <memory_id> <outcome>   # 记录使用效果
    node feedback_learner.js adjust                        # 调整重要性
    node feedback_learner.js corrections                    # 查看修正历史
    node feedback_learner.js learn <correction>            # 从修正中学习
    node feedback_learner.js stats                         # 统计
    node feedback_learner.js suggest                       # 建议遗忘
`);
    process.exit(1);
  }
  
  console.log('🚀 Feedback Learner v7.0...\n');
  
  const learner = new FeedbackLearner();
  
  switch (command) {
    case 'track': {
      const memoryId = args[1];
      const outcome = args[2];
      
      if (!memoryId || !outcome) {
        console.log('❌ 请提供 memory_id 和 outcome');
        console.log('   outcome 可选: helpful, irrelevant, wrong, outdated');
        process.exit(1);
      }
      
      learner.track(memoryId, outcome);
      break;
    }
    
    case 'adjust': {
      const memories = await learner.loadMemories();
      console.log(`📚 加载 ${memories.length} 条记忆`);
      
      const adjustments = learner.adjustImportance(memories);
      console.log(`\n📊 调整了 ${Object.keys(adjustments).length} 条记忆:`);
      
      for (const [id, adj] of Object.entries(adjustments)) {
        console.log(`  ${id}: ${adj.old.toFixed(2)} -> ${adj.new.toFixed(2)} (${adj.delta >= 0 ? '+' : ''}${adj.delta.toFixed(2)})`);
      }
      
      if (Object.keys(adjustments).length > 0) {
        await learner.saveMemories(memories);
        console.log('\n✅ 已保存调整后的记忆');
      }
      break;
    }
    
    case 'corrections': {
      const history = learner.getCorrectionHistory();
      console.log(`📜 修正历史 (${history.length}):\n`);
      
      for (const entry of history) {
        console.log(`[${entry.learned_at}] ${entry.content}`);
        console.log();
      }
      break;
    }
    
    case 'learn': {
      const correction = args.slice(1).join(' ');
      if (!correction) {
        console.log('❌ 请提供 correction 内容');
        process.exit(1);
      }
      
      learner.learn(correction);
      break;
    }
    
    case 'stats': {
      const stats = learner.getFeedbackStats();
      console.log('📊 统计:\n');
      console.log(`  总反馈: ${stats.total_feedback}`);
      console.log(`  修正数: ${stats.total_corrections}`);
      console.log(`  有反馈的记忆: ${stats.memories_with_feedback}`);
      console.log('\n  按结果类型:');
      for (const [outcome, count] of Object.entries(stats.by_outcome)) {
        console.log(`    ${outcome}: ${count}`);
      }
      break;
    }
    
    case 'suggest': {
      const memories = await learner.loadMemories();
      console.log(`📚 加载 ${memories.length} 条记忆`);
      
      const forgettable = learner.suggestForgetting(memories);
      console.log(`\n🗑️ 建议遗忘 (${forgettable.length}):\n`);
      
      for (const { memory, reason, negative_count } of forgettable) {
        console.log(`  - ${memory.text.slice(0, 50)}...`);
        console.log(`    原因: ${reason} (${negative_count}次负面反馈)`);
      }
      break;
    }
    
    default:
      console.log(`❌ 未知命令: ${command}`);
      process.exit(1);
  }
}

// Run if executed directly
if (import.meta.url === `file://${process.argv[1]}`) {
  main().catch(console.error);
}

export { FeedbackLearner, OUTCOME_HELPFUL, OUTCOME_IRRELEVANT, OUTCOME_WRONG, OUTCOME_OUTDATED };

export default FeedbackLearner;
/**
 * Git Notes - Cold layer Git-based persistence for memories
 *
 * P1-4: Backup memories to git notes for cold storage / versioning
 * Uses simple-git or direct git exec to manage notes
 *
 * Tools:
 * - memory_gitnotes_backup: Export memories to git notes
 * - memory_gitnotes_restore: Restore memories from git notes
 *
 * @module tools/git_notes
 */

import { execSync, exec } from 'child_process';
import { existsSync, mkdirSync, readFileSync, writeFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

// Resolve workspace from file URL
const __workspace = join(process.env.HOME || '/root', '.openclaw', 'workspace');
const MEMORY_DIR = join(__workspace, 'memory');
const NOTES_REF = 'refs/notes/memories';

function ensureDir(dir) {
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
}

/**
 * Run a git command in the workspace directory.
 * @param {string[]} args - Git arguments
 * @returns {string} stdout
 */
function gitExec(args) {
  const cmd = ['git', ...args].join(' ');
  try {
    return execSync(cmd, {
      cwd: __workspace,
      encoding: 'utf8',
      stdio: ['pipe', 'pipe', 'pipe'],
    }).trim();
  } catch (err) {
    throw new Error(`Git error: ${err.stderr || err.message}`);
  }
}

/**
 * Check if git repo exists
 */
function isGitRepo() {
  try {
    execSync('git rev-parse --git-dir', {
      cwd: __workspace,
      stdio: ['pipe', 'pipe', 'pipe'],
    });
    return true;
  } catch {
    return false;
  }
}

/**
 * Initialize git repo if needed
 */
function ensureGitRepo() {
  if (!isGitRepo()) {
    execSync('git init', { cwd: __workspace, stdio: 'pipe' });
    execSync('git config user.email "memory@agent.local"', { cwd: __workspace, stdio: 'pipe' });
    execSync('git config user.name "Memory Agent"', { cwd: __workspace, stdio: 'pipe' });
  }
}

/**
 * Serialize memories to a git-notes-compatible format
 * @param {object[]} memories - Array of memory objects
 * @param {string} scope - Scope to backup (or 'all')
 * @returns {string} JSON stringified memories
 */
function serializeMemories(memories, scope) {
  const data = {
    scope: scope || 'all',
    backed_up_at: new Date().toISOString(),
    count: memories.length,
    memories: memories.map(m => ({
      id: m.id,
      text: m.text,
      category: m.category,
      importance: m.importance,
      tags: m.tags || [],
      scope: m.scope || 'GLOBAL',
      created_at: m.created_at,
      updated_at: m.updated_at || m.created_at,
    })),
  };
  return JSON.stringify(data, null, 2);
}

/**
 * Backup memories to git notes
 * @param {string} [scope] - Scope to backup (USER/TEAM/AGENT/GLOBAL/all)
 * @returns {{ content: Array<{type: 'text', text: string}> }}
 */
export function memoryGitnotesBackupTool({ scope }) {
  try {
    ensureDir(MEMORY_DIR);
    ensureGitRepo();

    // Import storage to get memories
    let memories;
    try {
      const { getAllMemories } = require('../storage.js');
      memories = getAllMemories();
    } catch {
      return { content: [{ type: 'text', text: 'Error: storage not accessible' }], isError: true };
    }

    // Filter by scope if specified
    let filtered = memories;
    if (scope && scope !== 'all') {
      const norm = (s) => (s || 'GLOBAL').toUpperCase();
      filtered = memories.filter(m => norm(m.scope) === norm(scope.toUpperCase()));
    }

    // Serialize
    const payload = serializeMemories(filtered, scope || 'all');
    const messageFile = join(MEMORY_DIR, `.gitnotes_msg_${Date.now()}.tmp`);
    writeFileSync(messageFile, payload, 'utf8');

    // Write to git notes
    const noteContent = payload;
    // Use git notes add with -m flag
    try {
      gitExec(['notes', '--ref', NOTES_REF.replace('refs/notes/', ''), 'add', '-f', '-m', `Memory backup ${scope || 'all'} ${new Date().toISOString()}`]);
    } catch {
      // Fallback: write to a file and use git notes add -f -F
      const notePath = join(MEMORY_DIR, `memory_backup_${Date.now()}.json`);
      writeFileSync(notePath, noteContent, 'utf8');
      try {
        gitExec(['notes', '--ref', NOTES_REF.replace('refs/notes/', ''), 'add', '-f', '-F', notePath]);
      } catch {
        // Last resort: commit the file directly
        gitExec(['add', notePath]);
        gitExec(['commit', '-m', `Memory backup ${scope || 'all'} ${new Date().toISOString()}`]);
      }
    }

    // Commit notes if not already committed
    try {
      gitExec(['notes', '--ref', NOTES_REF.replace('refs/notes/', ''), 'append', '-m', `Backup: ${filtered.length} memories, scope=${scope || 'all'}`]);
    } catch {
      // Notes might already be committed, try append
      try {
        gitExec(['commit', '-m', `Memory backup ${new Date().toISOString()}`]);
      } catch {
        // Ignore
      }
    }

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          success: true,
          backed_up: filtered.length,
          scope: scope || 'all',
          notes_ref: NOTES_REF,
          backed_up_at: new Date().toISOString(),
        }, null, 2),
      }],
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Git notes backup error: ${err.message}` }], isError: true };
  }
}

/**
 * Restore memories from git notes
 * @param {string} [scope] - Scope to restore (or 'all')
 * @returns {{ content: Array<{type: 'text', text: string}> }}
 */
export function memoryGitnotesRestoreTool({ scope }) {
  try {
    if (!isGitRepo()) {
      return { content: [{ type: 'text', text: 'Error: not a git repository' }], isError: true };
    }

    // Get notes content
    let notesContent;
    try {
      notesContent = gitExec(['notes', '--ref', NOTES_REF.replace('refs/notes/', ''), 'show', 'HEAD']);
    } catch {
      // Try to get from last commit's note
      try {
        notesContent = gitExec(['notes', '-R', '--ref', NOTES_REF.replace('refs/notes/', ''), 'show']);
      } catch {
        return { content: [{ type: 'text', text: 'Error: no backup found in git notes' }], isError: true };
      }
    }

    let data;
    try {
      data = JSON.parse(notesContent);
    } catch {
      return { content: [{ type: 'text', text: 'Error: corrupted backup data in git notes' }], isError: true };
    }

    const memories = data.memories || [];

    // Filter by scope if specified
    let filtered = memories;
    if (scope && scope !== 'all') {
      filtered = memories.filter(m => (m.scope || 'GLOBAL').toUpperCase() === scope.toUpperCase());
    }

    // Restore to storage
    try {
      const { saveMemories } = require('../storage.js');
      const { getAllMemories } = require('../storage.js');
      const existing = getAllMemories();
      const existingIds = new Set(existing.map(m => m.id));

      let restored = 0;
      let skipped = 0;
      for (const mem of filtered) {
        if (!existingIds.has(mem.id)) {
          existing.push(mem);
          restored++;
        } else {
          skipped++;
        }
      }
      saveMemories(existing);

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: true,
            restored,
            skipped,
            scope: scope || 'all',
            backup_date: data.backed_up_at,
          }, null, 2),
        }],
      };
    } catch {
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: true,
            restored: 0,
            note: 'Storage write not available, showing backup contents',
            memories: filtered.slice(0, 10).map(m => ({
              id: m.id,
              text: m.text?.slice(0, 80),
              category: m.category,
              scope: m.scope,
            })),
            total_backed_up: filtered.length,
            backup_date: data.backed_up_at,
          }, null, 2),
        }],
      };
    }
  } catch (err) {
    return { content: [{ type: 'text', text: `Git notes restore error: ${err.message}` }], isError: true };
  }
}
/**
 * Graph Search - Knowledge Graph expanded search
 * Given a query, expands it with related entities from the knowledge graph,
 * then runs the expanded query through the normal search pipeline.
 *
 * @module tools/graph_search
 */

import { loadGraph } from '../graph/graph_store.js';
import { extractEntitiesRuleBased } from '../graph/entity.js';

/**
 * Expand a query by adding related entity names.
 * Finds entities in the query, then adds their neighbors' names.
 *
 * @param {string} query
 * @param {number} [maxExpand=5] - max entities to expand
 * @returns {{ expandedQuery: string, entities: Array, expanded: boolean }}
 */
export function expandQueryWithGraph(query, maxExpand = 5) {
  // 1. Extract entities from the query using rule-based extraction
  const queryEntities = extractEntitiesRuleBased(query);

  if (queryEntities.length === 0) {
    return { expandedQuery: query, entities: [], expanded: false };
  }

  // 2. Load the knowledge graph
  let graph;
  try {
    graph = loadGraph();
  } catch {
    return { expandedQuery: query, entities: queryEntities, expanded: false };
  }

  if (!graph || !graph.entities || graph.entities.length === 0) {
    return { expandedQuery: query, entities: queryEntities, expanded: false };
  }

  // 3. For each query entity, find neighbors and expand
  /** @type {string[]} */
  const expansionTerms = [];
  const processedEntities = [];

  for (const qe of queryEntities.slice(0, maxExpand)) {
    // Find entity in graph by name
    const graphEntity = graph.entities.find(
      e => e.name === qe.name && e.type === qe.type
    );

    if (!graphEntity) continue;

    processedEntities.push({
      ...qe,
      graphId: graphEntity.id,
      memory_ids: graphEntity.memory_ids || [],
    });

    // Get neighbors (related entities)
    const neighbors = [];
    for (const r of graph.relations || []) {
      if (r.from === graphEntity.id) {
        const neighbor = graph.entities.find(e => e.id === r.to);
        if (neighbor) neighbors.push({ entity: neighbor, relation: r.relation });
      }
      if (r.to === graphEntity.id && (r.relation === 'worked_with' || r.relation === 'related_to')) {
        const neighbor = graph.entities.find(e => e.id === r.from);
        if (neighbor) neighbors.push({ entity: neighbor, relation: r.relation });
      }
    }

    // Add neighbor names to expansion terms
    for (const { entity, relation } of neighbors.slice(0, 3)) {
      // Include the relation type as a hint
      if (relation === 'worked_with' || relation === 'related_to') {
        expansionTerms.push(entity.name);
      }
    }
  }

  // 4. Build expanded query
  const uniqueTerms = [...new Set(expansionTerms)];
  const expandedQuery = uniqueTerms.length > 0
    ? `${query} ${uniqueTerms.join(' ')}`
    : query;

  return {
    expandedQuery,
    entities: processedEntities,
    expanded: uniqueTerms.length > 0,
  };
}

/**
 * Get graph-enhanced search results.
 * First expands query via graph, then searches.
 *
 * @param {string} query
 * @param {object} options
 * @param {number} options.topK
 * @param {string} options.scope
 * @param {boolean} options.enableRerank
 * @param {boolean} options.enableMMR
 * @param {boolean} options.enableDecay
 * @param {number} options.fetchK
 * @param {boolean} options.enableGraphBoost
 * @returns {Promise<{ results: Array, expandedQuery: string, graphEntities: Array, expanded: boolean }>}
 */
export async function graphEnhancedSearch(query, options = {}) {
  const {
    topK = 10,
    scope = 'global',
    enableRerank = true,
    enableMMR = true,
    enableDecay = true,
    fetchK = 20,
    enableGraphBoost = true,
  } = options;

  // Step 1: Expand query with graph
  const { expandedQuery, entities: graphEntities, expanded } = expandQueryWithGraph(query, 5);

  // Step 2: Import and run the normal search pipeline
  const { search } = await import('../search.js');

  const results = await search(expandedQuery, {
    topK,
    scope,
    enableRerank,
    enableMMR,
    enableDecay,
    fetchK,
    reflectedBoost: true,
    // Pass graph-specific options
    enableGraphBoost,
    graphEntities: graphEntities.map(e => e.name),
  });

  return {
    results,
    expandedQuery,
    graphEntities,
    expanded,
  };
}

/**
 * MCP tool handler for memory_graph_search
 * @param {object} args
 * @returns {Promise<object>}
 */
export async function memoryGraphSearchTool(args) {
  const {
    query,
    topK = 5,
    scope = 'global',
    enableRerank = true,
    enableMMR = true,
    enableDecay = true,
    fetchK = 20,
  } = args;

  try {
    const { results, expandedQuery, graphEntities, expanded } = await graphEnhancedSearch(query, {
      topK,
      scope,
      enableRerank,
      enableMMR,
      enableDecay,
      fetchK,
      enableGraphBoost: true,
    });

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          query,
          expandedQuery: expanded ? expandedQuery : null,
          graphExpanded: expanded,
          graphEntitiesFound: graphEntities.map(e => ({
            name: e.name,
            type: e.type,
            relatedMemories: e.memory_ids?.length || 0,
          })),
          count: results.length,
          results: results.map(r => ({
            id: r.memory.id,
            text: r.memory.text,
            category: r.memory.category,
            importance: r.memory.importance,
            score: Math.round(r.score * 1000) / 1000,
            graphBoost: r.graphBoost || 0,
            highlight: r.highlight,
            created_at: new Date(r.memory.created_at).toISOString(),
          })),
        }, null, 2),
      }],
    };
  } catch (err) {
    return {
      content: [{ type: 'text', text: `Graph search error: ${err.message}` }],
      isError: true,
    };
  }
}
/**
 * Memory Health - 记忆健康度检测
 * 
 * 功能:
 * - 自动验证记忆
 * - 矛盾检测
 * - 过时检测
 * - 质量评分
 * - 自动修复功能
 * 
 * Ported from memory_health.py
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'fs';
import { join } from 'path';

const HOME = process.env.HOME || '/root';
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const VECTOR_DB_DIR = join(MEMORY_DIR, 'vector');
const ASSOCIATION_GRAPH_FILE = join(MEMORY_DIR, 'associations', 'graph.json');

// Auto-fix rules
const AUTO_FIX_RULES = {
  contradiction: {
    action: 'merge_or_flag',
    threshold: 0.7,
    auto_merge: false
  },
  outdated: {
    action: 'archive_or_update',
    threshold_days: 90,
    auto_archive: true
  },
  redundant: {
    action: 'compress',
    similarity_threshold: 0.85,
    auto_compress: true
  },
  orphaned: {
    action: 'link_or_delete',
    auto_delete: false
  }
};

// Conflict word pairs
const CONFLICT_PAIRS = [
  ['喜欢', '讨厌'], ['爱', '恨'], ['是', '不是'], ['可以', '不可以'],
  ['会', '不会'], ['有', '没有'], ['使用', '不使用'], ['采用', '不采用'],
  ['需要', '不需要'], ['想要', '不想要'], ['应该', '不应该']
];

// ============================================================
// MemoryHealthChecker
// ============================================================

export class MemoryHealthChecker {
  constructor() {
    this.vectorDbDir = VECTOR_DB_DIR;
    this.memories = [];
    this._loadMemories();
  }

  _loadMemories() {
    try {
      const { getAllMemories } = require('../storage.js');
      this.memories = getAllMemories();
    } catch {
      // fallback
      const memoryFile = join(MEMORY_DIR, 'memories.json');
      if (existsSync(memoryFile)) {
        try {
          const data = JSON.parse(readFileSync(memoryFile, 'utf-8'));
          this.memories = Array.isArray(data) ? data : (data.memories || []);
        } catch { /* ignore */ }
      }
    }
  }

  /**
   * Calculate health score
   * @returns {object}
   */
  calculateHealthScore() {
    const total = this.memories.length;
    if (total === 0) {
      return { score: 100, issues: 0, total: 0, details: {} };
    }

    const conflicts = this._detectContradictions();
    const outdated = this._detectOutdated();
    const redundant = this._detectRedundant();
    const orphaned = this._detectOrphaned();

    const issues = (
      conflicts.length * 10 +
      outdated.length * 3 +
      redundant.length * 2 +
      orphaned.length * 5
    );
    const score = Math.max(0, 100 - issues);

    return {
      score,
      total,
      conflicts: conflicts.length,
      outdated: outdated.length,
      redundant: redundant.length,
      orphaned: orphaned.length,
      details: {
        conflicts: conflicts.slice(0, 5).map(c => ({
          id1: c.memory1.id?.slice(0, 8),
          id2: c.memory2.id?.slice(0, 8),
          text1: (c.memory1.text || '').slice(0, 30),
          text2: (c.memory2.text || '').slice(0, 30)
        })),
        outdated: outdated.slice(0, 5).map(o => ({
          id: o.id?.slice(0, 8),
          text: (o.text || '').slice(0, 30),
          days_old: o.days_old || 0
        })),
        redundant: redundant.slice(0, 5).map(r => ({
          id1: r.memory1.id?.slice(0, 8),
          id2: r.memory2.id?.slice(0, 8),
          similarity: r.similarity || 0
        })),
        orphaned: orphaned.slice(0, 5).map(o => ({
          id: o.id?.slice(0, 8),
          text: (o.text || '').slice(0, 30)
        }))
      }
    };
  }

  /**
   * Auto-fix memory quality issues
   * @param {boolean} dryRun
   * @returns {Array<object>}
   */
  autoFix(dryRun = true) {
    const fixes = [];
    if (!this.memories.length) return fixes;

    // 1. Detect and process contradictory memories
    const contradictions = this._detectContradictions();
    fixes.push(...this._resolveContradictions(contradictions, dryRun));

    // 2. Detect and archive outdated
    const outdated = this._detectOutdated();
    fixes.push(...this._archiveOutdated(outdated, dryRun));

    // 3. Detect and compress redundant
    const redundant = this._detectRedundant();
    fixes.push(...this._compressRedundant(redundant, dryRun));

    // 4. Detect and handle orphaned
    const orphaned = this._detectOrphaned();
    fixes.push(...this._handleOrphaned(orphaned, dryRun));

    return fixes;
  }

  _detectContradictions() {
    const contradictions = [];
    for (let i = 0; i < this.memories.length; i++) {
      const m1 = this.memories[i];
      for (let j = i + 1; j < this.memories.length; j++) {
        const m2 = this.memories[j];
        if ((m1.category || '') !== (m2.category || '')) continue;

        const text1 = (m1.text || '').toLowerCase();
        const text2 = (m2.text || '').toLowerCase();

        for (const [word1, word2] of CONFLICT_PAIRS) {
          if (text1.includes(word1) && text2.includes(word2)) {
            if (this._areSimilarContexts(text1, text2, word1, word2)) {
              contradictions.push({
                memory1: m1,
                memory2: m2,
                conflict_type: `${word1} vs ${word2}`
              });
              break;
            }
          }
        }
      }
    }
    return contradictions;
  }

  _areSimilarContexts(text1, text2, word1, word2) {
    const getContext = (text, word, window = 10) => {
      const idx = text.indexOf(word);
      if (idx === -1) return '';
      const start = Math.max(0, idx - window);
      const end = Math.min(text.length, idx + word.length + window);
      return text.slice(start, end);
    };

    const ctx1 = getContext(text1, word1);
    const ctx2 = getContext(text2, word2);
    if (!ctx1 || !ctx2) return false;

    const words1 = new Set(ctx1.split(/\s+/));
    const words2 = new Set(ctx2.split(/\s+/));
    const common = new Set([...words1].filter(w => words2.has(w)));
    return common.size >= 2;
  }

  _detectOutdated() {
    const outdated = [];
    const thresholdDays = AUTO_FIX_RULES.outdated.threshold_days;
    const threshold = Date.now() - thresholdDays * 24 * 60 * 60 * 1000;

    for (const m of this.memories) {
      const ts = m.timestamp || m.created_at;
      if (!ts) continue;
      const tsMs = typeof ts === 'number' ? ts : new Date(ts).getTime();
      if (tsMs < threshold) {
        const daysOld = Math.floor((Date.now() - tsMs) / (24 * 60 * 60 * 1000));
        outdated.push({ ...m, days_old: daysOld });
      }
    }
    return outdated;
  }

  _detectRedundant() {
    const redundant = [];
    const threshold = AUTO_FIX_RULES.redundant.similarity_threshold;

    for (let i = 0; i < this.memories.length; i++) {
      const text1 = (this.memories[i].text || '').toLowerCase().trim();
      if (!text1) continue;
      for (let j = i + 1; j < this.memories.length; j++) {
        const text2 = (this.memories[j].text || '').toLowerCase().trim();
        if (!text2) continue;
        const sim = this._calculateSimilarity(text1, text2);
        if (sim >= threshold) {
          redundant.push({
            memory1: this.memories[i],
            memory2: this.memories[j],
            similarity: Math.round(sim * 1000) / 1000
          });
        }
      }
    }
    return redundant;
  }

  _calculateSimilarity(text1, text2) {
    if (!text1 || !text2) return 0;
    const words1 = new Set(text1.split(/\W+/).filter(Boolean));
    const words2 = new Set(text2.split(/\W+/).filter(Boolean));
    if (!words1.size || !words2.size) return 0;
    const intersection = new Set([...words1].filter(w => words2.has(w)));
    const union = new Set([...words1, ...words2]);
    return union.size > 0 ? intersection.size / union.size : 0;
  }

  _detectOrphaned() {
    const orphaned = [];
    const hasAssociation = new Set();

    if (existsSync(ASSOCIATION_GRAPH_FILE)) {
      try {
        const graph = JSON.parse(readFileSync(ASSOCIATION_GRAPH_FILE, 'utf-8'));
        const edges = graph.edges || {};
        for (const edge of Object.values(edges)) {
          if (edge.source) hasAssociation.add(edge.source);
          if (edge.target) hasAssociation.add(edge.target);
        }
      } catch { /* ignore */ }
    }

    for (const m of this.memories) {
      const memId = m.id || '';
      if (!hasAssociation.has(memId)) {
        orphaned.push(m);
      }
    }
    return orphaned;
  }

  _resolveContradictions(contradictions, dryRun) {
    const fixes = [];
    for (const conflict of contradictions) {
      fixes.push({
        type: 'contradiction',
        action: 'flag',
        dry_run: dryRun,
        memory1_id: conflict.memory1.id,
        memory2_id: conflict.memory2.id,
        conflict_type: conflict.conflict_type,
        message: `发现矛盾记忆 [${conflict.conflict_type}]，需要用户确认处理`
      });
    }
    return fixes;
  }

  _archiveOutdated(outdated, dryRun) {
    const fixes = [];
    for (const m of outdated.slice(0, 10)) {
      fixes.push({
        type: 'outdated',
        action: dryRun ? 'archive' : 'archived',
        dry_run: dryRun,
        memory_id: m.id,
        days_old: m.days_old || 0,
        message: dryRun
          ? `将归档过时记忆 (${m.days_old}天)`
          : `已归档过时记忆`
      });
    }
    return fixes;
  }

  _compressRedundant(redundant, dryRun) {
    const fixes = [];
    const seenIds = new Set();
    const unique = redundant.filter(r => {
      const id1 = r.memory1.id;
      const id2 = r.memory2.id;
      if (seenIds.has(id1) || seenIds.has(id2)) return false;
      seenIds.add(id1);
      seenIds.add(id2);
      return true;
    });

    for (const r of unique.slice(0, 10)) {
      fixes.push({
        type: 'redundant',
        action: dryRun ? 'compress' : 'compressed',
        dry_run: dryRun,
        memory1_id: r.memory1.id,
        memory2_id: r.memory2.id,
        similarity: r.similarity,
        message: `将合并冗余记忆 (相似度: ${r.similarity.toFixed(2)})`
      });
    }
    return fixes;
  }

  _handleOrphaned(orphaned, dryRun) {
    const fixes = [];
    for (const m of orphaned.slice(0, 10)) {
      fixes.push({
        type: 'orphaned',
        action: 'flag',
        dry_run: dryRun,
        memory_id: m.id,
        message: '发现孤立记忆，需要处理'
      });
    }
    return fixes;
  }
}

// ============================================================
// CLI Handler
// ============================================================

/**
 * @param {string} command
 * @param {object} args
 * @returns {object}
 */
export function cmdHealth(command, args = {}) {
  const checker = new MemoryHealthChecker();

  switch (command) {
    case 'report': {
      const health = checker.calculateHealthScore();
      const emoji = { contradiction: '❌', outdated: '⏰', redundant: '🔄', orphaned: '🔗' };
      return {
        type: 'text',
        text:
          `📊 健康度分数: ${health.score}/100\n` +
          `   总记忆数: ${health.total}\n\n` +
          `问题统计:\n` +
          `   ❌ 矛盾: ${health.conflicts} 条\n` +
          `   ⏰ 过时: ${health.outdated} 条\n` +
          `   🔄 冗余: ${health.redundant} 条\n` +
          `   🔗 孤立: ${health.orphaned} 条`
      };
    }

    case 'validate': {
      const total = checker.memories.length;
      const valid = checker.memories.filter(m =>
        (m.text || '').length >= 3 && m.category
      ).length;
      return {
        type: 'text',
        text: `验证结果:\n   有效: ${valid}/${total}`
      };
    }

    case 'conflicts': {
      const conflicts = checker._detectContradictions();
      const lines = [`发现 ${conflicts.length} 对矛盾记忆:`];
      for (const c of conflicts.slice(0, 5)) {
        lines.push(`\n❌ 矛盾 [${c.conflict_type}]:`);
        lines.push(`   1. [${c.memory1.id?.slice(0, 8)}] ${(c.memory1.text || '').slice(0, 50)}`);
        lines.push(`   2. [${c.memory2.id?.slice(0, 8)}] ${(c.memory2.text || '').slice(0, 50)}`);
      }
      return { type: 'text', text: lines.join('\n') };
    }

    case 'fix':
    case 'auto-fix': {
      const dryRun = !args.apply;
      const fixes = checker.autoFix(dryRun);
      if (fixes.length === 0) {
        return { type: 'text', text: '✅ 没有需要修复的问题' };
      }
      const byType = {};
      for (const f of fixes) {
        byType[f.type] = (byType[f.type] || 0) + 1;
      }
      const emoji = { contradiction: '❌', outdated: '⏰', redundant: '🔄', orphaned: '🔗' };
      const lines = [
        `🔧 自动修复模式: ${dryRun ? '预览' : '执行'}`,
        `📋 修复操作 (${fixes.length} 个):\n`
      ];
      for (const [t, count] of Object.entries(byType)) {
        lines.push(`   ${emoji[t] || '•'} ${t}: ${count} 条`);
      }
      if (dryRun) lines.push('\n💡 使用 --apply 参数执行修复');
      return { type: 'text', text: lines.join('\n') };
    }

    default:
      return { error: `未知命令: ${command}` };
  }
}

export default { MemoryHealthChecker, cmdHealth };
/**
 * identity_tools.js — MCP Tools for Identity Memory
 * Part of Feature: Identity Memory Type (v2.7.0)
 *
 * Implements MCP tools:
 * - memory_identity_extract: Extract identity/preference/habit from text
 * - memory_identity_update: Update identity memories with importance=0.9
 * - memory_identity_get: Get a summary of user's identity profile
 *
 * Extraction rules:
 * - "我喜欢/讨厌..." → preference/dislike
 * - "我是..." → identity
 * - "我习惯..." → habit
 * - "我需要..." → requirement
 */

import { addMemory, getAllMemories, updateMemory, getMemory } from '../storage.js';

// ============ Extraction Rules ============

/** @type {{ pattern: RegExp, type: string, label: string, subType?: string }[]} */
const IDENTITY_PATTERNS = [
  // Identity: "我是...", "我叫...", "我的职业是..."
  { pattern: /(?:^|[，、\n])我(?:是|叫|名字|职业|身份|角色)([^\n，。.!！]{2,50})/m, type: 'identity', label: '身份描述' },
  // Preference positive: "我喜欢...", "我爱...", "我偏好..."
  { pattern: /(?:^|[，、\n])我(?:喜欢|爱|偏好|欣赏|想|想要|愿意)([^\n，。.!！]{2,60})/m, type: 'preference', label: '喜好', subType: 'like' },
  // Preference negative: "我讨厌...", "我不喜欢...", "我厌恶..."
  { pattern: /(?:^|[，、\n])我(?:讨厌|厌恶|不喜欢|反感|排斥|烦)([^\n，。.!！]{2,60})/m, type: 'preference', label: '厌恶', subType: 'dislike' },
  // Habit: "我习惯...", "我通常...", "我经常..."
  { pattern: /(?:^|[，、\n])我(?:习惯|通常|经常|往往|总是|一般)([^\n，。.!！]{2,60})/m, type: 'habit', label: '习惯' },
  // Requirement: "我需要...", "我必须...", "我想要..."
  { pattern: /(?:^|[，、\n])我(?:需要|必须|得|想要|希望|要求)([^\n，。.!！]{2,60})/m, type: 'requirement', label: '需求' },
  // Skill: "我会...", "我能...", "我擅长..."
  { pattern: /(?:^|[，、\n])我(?:会|能|擅长|懂得|可以)([^\n，。.!！]{2,60})/m, type: 'skill', label: '技能' },
  // Goal: "我的目标是...", "我想..."
  { pattern: /(?:^|[，、\n])(?:我的)?目标(?:是|)([^\n，。.!！]{2,60})/m, type: 'goal', label: '目标' },
];

/**
 * Extract identity-related statements from text
 * @param {string} text
 * @returns {{ type: string, label: string, content: string, subType?: string }[]}
 */
export function extractIdentityStatements(text) {
  const results = [];
  for (const { pattern, type, label, subType } of IDENTITY_PATTERNS) {
    const matches = text.matchAll(new RegExp(pattern, 'gm'));
    for (const match of matches) {
      const content = (match[1] || '').trim();
      if (content.length >= 2) {
        results.push({
          type,
          label,
          content,
          subType: subType || null,
          fullMatch: match[0].trim(),
        });
      }
    }
  }
  return results;
}

/**
 * Get importance score based on identity type
 * Identity type always gets 0.9+, others get 0.9
 * @param {string} type
 * @returns {number}
 */
function getIdentityImportance(type) {
  if (type === 'identity') return 0.95;
  return 0.9;
}

// ============ MCP Tools ============

/**
 * Tool: memory_identity_extract
 * Extract identity/preference/habit/requirement from text
 */
export function memoryIdentityExtractTool({ text }) {
  try {
    if (!text || !text.trim()) {
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({ count: 0, extractions: [], summary: 'No text provided' }, null, 2),
        }],
      };
    }

    const extractions = extractIdentityStatements(text);

    // Deduplicate by content
    const seen = new Set();
    const unique = extractions.filter(e => {
      const key = `${e.type}:${e.content}`;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });

    // Group by type for summary
    const byType = {};
    for (const e of unique) {
      if (!byType[e.type]) byType[e.type] = [];
      byType[e.type].push(e.content);
    }

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          count: unique.length,
          extractions: unique.map(e => ({
            type: e.type,
            label: e.label,
            content: e.content,
            subType: e.subType,
            suggested_importance: getIdentityImportance(e.type),
          })),
          by_type: Object.fromEntries(
            Object.entries(byType).map(([k, v]) => [k, { count: v.length, samples: v.slice(0, 3) }])
          ),
        }, null, 2),
      }],
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Identity extract error: ${err.message}` }], isError: true };
  }
}

/**
 * Tool: memory_identity_update
 * Store extracted identity statements as high-priority memories
 * Always uses importance=0.9+
 */
export function memoryIdentityUpdateTool({ extractions }) {
  try {
    if (!extractions || !Array.isArray(extractions) || extractions.length === 0) {
      return {
        content: [{ type: 'text', text: JSON.stringify({ stored: 0, error: 'No extractions provided' }, null, 2) }],
        isError: true,
      };
    }

    const stored = [];
    const errors = [];

    for (const ex of extractions) {
      try {
        const content = ex.content || ex.text || '';
        const type = ex.type || 'identity';
        if (!content || content.length < 2) continue;

        const importance = ex.importance || getIdentityImportance(type);

        const mem = addMemory({
          text: content,
          category: type, // identity, preference, habit, requirement, skill, goal
          importance,
          tags: ['identity', ex.label || type, ...(ex.subType ? [ex.subType] : [])],
        });
        stored.push({ id: mem.id, type, content: content.slice(0, 50) });
      } catch (err) {
        errors.push({ extraction: ex, error: err.message });
      }
    }

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          success: true,
          stored: stored.length,
          memories: stored,
          errors: errors.length > 0 ? errors : undefined,
        }, null, 2),
      }],
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Identity update error: ${err.message}` }], isError: true };
  }
}

/**
 * Tool: memory_identity_get
 * Get a summary of the user's identity profile from stored identity memories
 */
export async function memoryIdentityGetTool({ type } = {}) {
  try {
    const allMemories = await getAllMemories();

    // Identity-related categories
    const identityCategories = ['identity', 'preference', 'habit', 'requirement', 'skill', 'goal'];

    let identityMemories;
    if (type) {
      identityMemories = allMemories.filter(m => m.category === type);
    } else {
      identityMemories = allMemories.filter(m => identityCategories.includes(m.category));
    }

    // Sort by importance desc, then by updated_at desc
    identityMemories.sort((a, b) => {
      if (b.importance !== a.importance) return b.importance - a.importance;
      return (b.updated_at || 0) - (a.updated_at || 0);
    });

    // Group by category
    const byCategory = {};
    for (const m of identityMemories) {
      if (!byCategory[m.category]) byCategory[m.category] = [];
      byCategory[m.category].push({
        id: m.id,
        text: m.text,
        importance: m.importance,
        tags: m.tags || [],
        updated_at: new Date(m.updated_at || m.created_at).toISOString(),
      });
    }

    // Build a readable summary
    const summaryParts = [];
    const categoryLabels = {
      identity: '👤 身份',
      preference: '❤️ 偏好/喜好',
      habit: '🔄 习惯',
      requirement: '📌 需求',
      skill: '💡 技能',
      goal: '🎯 目标',
    };

    for (const [cat, memories] of Object.entries(byCategory)) {
      const label = categoryLabels[cat] || cat;
      summaryParts.push(`\n## ${label} (${memories.length}条)`);
      for (const m of memories.slice(0, 10)) {
        summaryParts.push(`- ${m.text} [重要性:${Math.round(m.importance * 100)}%, ID:${m.id.slice(0, 12)}]`);
      }
    }

    const summary = summaryParts.length > 0
      ? summaryParts.join('\n')
      : '暂无身份信息记录。';

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          total: identityMemories.length,
          by_category: Object.fromEntries(
            Object.entries(byCategory).map(([k, v]) => [k, v.length])
          ),
          summary,
          memories: Object.fromEntries(
            Object.entries(byCategory).map(([k, v]) => [k, v.slice(0, 20)])
          ),
        }, null, 2),
      }],
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Identity get error: ${err.message}` }], isError: true };
  }
}

export default {
  memoryIdentityExtractTool,
  memoryIdentityUpdateTool,
  memoryIdentityGetTool,
};
/**
 * Memory Inference - 关联推理增强
 * 
 * 功能:
 * - 向量搜索 + 图谱路径扩展的联合推理
 * - 实体上下文链获取
 * - 智能缓存优化
 * 
 * Ported from memory_inference.py
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'fs';
import { join } from 'path';

const HOME = process.env.HOME || '/root';
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const VECTOR_DB_DIR = join(MEMORY_DIR, 'vector');
const ONTOLOGY_DIR = join(MEMORY_DIR, 'ontology');
const GRAPH_FILE = join(ONTOLOGY_DIR, 'graph.jsonl');

const OLLAMA_URL = process.env.OLLAMA_HOST || 'http://localhost:11434';
const OLLAMA_EMBED_MODEL = process.env.OLLAMA_EMBED_MODEL || 'nomic-embed-text:latest';
const CACHE_TTL = 300; // seconds

// Relation weights
const RELATION_WEIGHTS = {
  'participates_in': 1.0,
  'owns': 1.0,
  'depends_on': 0.9,
  'related_to': 0.8,
  'uses': 0.8,
  'prefers': 0.9,
  'works_on': 0.9,
  'manages': 0.9,
  'created': 0.85,
  'completed': 0.85,
  'updated': 0.7,
  'mentioned_in': 0.6
};

// Entity type priority
const ENTITY_PRIORITY = {
  'project': 1.0,
  'task': 0.95,
  'person': 0.9,
  'decision': 0.9,
  'preference': 0.85,
  'event': 0.8,
  'tool': 0.75,
  'fact': 0.7
};

// ============================================================
// CacheManager
// ============================================================

class CacheManager {
  constructor(ttlSeconds = 300) {
    this.cache = new Map();
    this.ttl = ttlSeconds * 1000;
  }

  _makeKey(...args) {
    return JSON.stringify({ args, time: Date.now() });
  }

  get(...args) {
    const key = this._makeKey(...args.slice(0, -1));
    if (this.cache.has(key)) {
      const entry = this.cache.get(key);
      if (Date.now() - entry.time < this.ttl) {
        return entry.data;
      }
      this.cache.delete(key);
    }
    return null;
  }

  set(data, ...args) {
    const key = this._makeKey(...args);
    this.cache.set(key, { data, time: Date.now() });
  }

  clear() {
    this.cache.clear();
  }

  stats() {
    const now = Date.now();
    let valid = 0;
    for (const entry of this.cache.values()) {
      if (now - entry.time < this.ttl) valid++;
    }
    return { total: this.cache.size, valid, expired: this.cache.size - valid };
  }
}

// ============================================================
// SimpleOntologyGraph
// ============================================================

class SimpleOntologyGraph {
  constructor(graphFile) {
    this.graphFile = graphFile;
    /** @type {Map<string, object>} */
    this.entities = new Map();
    /** @type {Array<object>} */
    this.relations = [];
    this._load();
  }

  _load() {
    if (!existsSync(this.graphFile)) return;
    try {
      const content = readFileSync(this.graphFile, 'utf-8');
      const lines = content.split('\n').filter(Boolean);
      for (const line of lines) {
        try {
          const data = JSON.parse(line);
          if (data.op === 'create') {
            const entity = data.entity || {};
            this.entities.set(entity.id, entity);
          } else if (data.op === 'relate') {
            this.relations.push({
              from: data.from,
              rel: data.rel,
              to: data.to,
              created: data.created
            });
          }
        } catch { /* skip */ }
      }
    } catch { /* ignore */ }
  }

  getEntity(entityId) {
    return this.entities.get(entityId) || null;
  }

  getRelationsFrom(entityId) {
    return this.relations.filter(r => r.from === entityId);
  }

  getRelationsTo(entityId) {
    return this.relations.filter(r => r.to === entityId);
  }

  traverse(startId, depth = 2) {
    const result = {
      center: this.entities.get(startId) || null,
      nodes: [],
      edges: []
    };

    if (!this.entities.has(startId)) return result;

    const visited = new Set([startId]);
    let frontier = [startId];

    for (let d = 0; d < depth; d++) {
      const newFrontier = [];
      for (const nodeId of frontier) {
        // Outgoing
        for (const rel of this.getRelationsFrom(nodeId)) {
          result.edges.push({ from: nodeId, rel: rel.rel, to: rel.to });
          if (this.entities.has(rel.to) && !visited.has(rel.to)) {
            visited.add(rel.to);
            newFrontier.push(rel.to);
            result.nodes.push(this.entities.get(rel.to));
          }
        }
        // Incoming
        for (const rel of this.getRelationsTo(nodeId)) {
          result.edges.push({ from: rel.from, rel: rel.rel, to: nodeId });
          if (this.entities.has(rel.from) && !visited.has(rel.from)) {
            visited.add(rel.from);
            newFrontier.push(rel.from);
            result.nodes.push(this.entities.get(rel.from));
          }
        }
      }
      frontier = newFrontier;
    }

    return result;
  }
}

// ============================================================
// MemoryInference
// ============================================================

export class MemoryInference {
  constructor(cacheTtl = 300) {
    this.cache = new CacheManager(cacheTtl);
    this.graph = new SimpleOntologyGraph(GRAPH_FILE);
    this.memories = this._loadMemories();
  }

  _loadMemories() {
    try {
      const { getAllMemories } = require('../storage.js');
      return getAllMemories();
    } catch {
      const memoryFile = join(MEMORY_DIR, 'memories.json');
      if (existsSync(memoryFile)) {
        try {
          const data = JSON.parse(readFileSync(memoryFile, 'utf-8'));
          return Array.isArray(data) ? data : (data.memories || []);
        } catch { /* ignore */ }
      }
      return [];
    }
  }

  async _getEmbedding(text) {
    try {
      const response = await fetch(`${OLLAMA_URL}/api/embeddings`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ model: OLLAMA_EMBED_MODEL, prompt: text }),
        signal: AbortSignal.timeout(10000)
      });
      if (response.ok) {
        const data = await response.json();
        return data.embedding || null;
      }
    } catch { /* ignore */ }
    return null;
  }

  async inferRelated(query, topK = 5, maxDepth = 2) {
    const cached = this.cache.get('inferRelated', query, topK, maxDepth);
    if (cached) return cached;

    const startTime = Date.now();

    // 1. Vector search (fallback to keyword)
    const vectorResults = this._vectorSearch(query, topK * 2);

    // 2. Graph expansion
    const graphExpansion = [];
    const seenEntityIds = new Set();
    for (const result of vectorResults) {
      const entityId = result.entityId ||
        (this.graph.entities.size > 0 ? this._findEntityId(result.text || '') : null);
      if (entityId && !seenEntityIds.has(entityId)) {
        seenEntityIds.add(entityId);
        const paths = this._expandFromEntity(entityId, maxDepth);
        graphExpansion.push(...paths);
      }
    }

    // 3. Merge results
    const merged = this._mergeResults(vectorResults, graphExpansion, topK);

    const result = {
      vector_results: vectorResults.slice(0, topK),
      graph_expansion: graphExpansion.slice(0, topK),
      merged,
      stats: {
        vector_count: vectorResults.length,
        expansion_count: graphExpansion.length,
        merged_count: merged.length,
        time_ms: Date.now() - startTime
      }
    };

    this.cache.set(result, 'inferRelated', query, topK, maxDepth);
    return result;
  }

  _vectorSearch(query, limit = 10) {
    const results = [];
    const queryLower = query.toLowerCase();
    const queryWords = new Set(queryLower.split(/\s+/));

    for (const mem of this.memories) {
      const text = mem.text || '';
      let score = 0;
      if (text.toLowerCase().includes(queryLower)) {
        score = 1.0;
      } else {
        const textWords = new Set(text.toLowerCase().split(/\s+/));
        const overlap = [...queryWords].filter(w => textWords.has(w)).length;
        score = overlap / Math.max(queryWords.size, 1);
      }
      if (score > 0.1) {
        results.push({
          id: mem.id,
          text,
          category: mem.category || 'unknown',
          importance: mem.importance || 0.5,
          score,
          source: 'keyword',
          entityId: null
        });
      }
    }

    results.sort((a, b) => b.score - a.score);
    return results.slice(0, limit);
  }

  _findEntityId(text) {
    if (!this.graph.entities.size) return null;
    const textLower = text.toLowerCase();
    for (const [id, entity] of this.graph.entities) {
      const props = entity.properties || {};
      const name = props.name || '';
      if (name && name.toLowerCase().includes(textLower.slice(0, 10))) {
        return id;
      }
    }
    return null;
  }

  _expandFromEntity(entityId, maxDepth = 2) {
    if (!this.graph.entities.size) return [];
    try {
      const result = this.graph.traverse(entityId, maxDepth);
      return (result.nodes || []).map(node => ({
        entity_id: node.id,
        type: node.type || 'unknown',
        name: (node.properties || {}).name || node.id,
        text: (node.properties || {}).description || '',
        weight: ENTITY_PRIORITY[node.type] || 0.5,
        source: 'graph_expansion',
        relation_depth: 1
      }));
    } catch {
      return [];
    }
  }

  _mergeResults(vectorResults, graphExpansion, topK) {
    const mergedMap = new Map();

    for (const r of vectorResults) {
      const key = r.text || '';
      mergedMap.set(key, {
        text: r.text,
        entity_id: r.entityId,
        category: r.category || 'unknown',
        importance: r.importance || 0.5,
        vector_score: r.score,
        graph_weight: 0,
        sources: ['vector']
      });
    }

    for (const r of graphExpansion) {
      const key = r.text || r.name || '';
      if (mergedMap.has(key)) {
        mergedMap.get(key).graph_weight = r.weight;
        mergedMap.get(key).sources.push('graph');
      } else {
        mergedMap.set(key, {
          text: r.text || r.name || '',
          entity_id: r.entity_id,
          type: r.type,
          category: r.type || 'unknown',
          importance: r.weight || 0.5,
          vector_score: 0,
          graph_weight: r.weight || 0.5,
          sources: ['graph']
        });
      }
    }

    const scored = [];
    for (const item of mergedMap.values()) {
      const vectorScore = Math.min(item.vector_score, 1);
      const combinedScore =
        vectorScore * 0.4 +
        item.graph_weight * 0.4 +
        item.importance * 0.2;
      scored.push({
        ...item,
        combined_score: Math.round(combinedScore * 1000) / 1000
      });
    }

    scored.sort((a, b) => b.combined_score - a.combined_score);
    return scored.slice(0, topK);
  }

  getContextChain(entityId, entityType = null) {
    const cached = this.cache.get('contextChain', entityId, entityType);
    if (cached) return cached;

    if (!this.graph.entities.size) return [];

    let entity = this.graph.getEntity(entityId);
    if (!entity) {
      entity = this._findEntityByName(entityId);
      if (entity) entityId = entity.id;
    }

    if (!entity) return [];

    const type = entityType || entity.type || 'unknown';
    let chain = [];

    if (type === 'project') chain = this._getProjectContext(entityId);
    else if (type === 'person') chain = this._getPersonContext(entityId);
    else if (type === 'task') chain = this._getTaskContext(entityId);
    else chain = this._getGenericContext(entityId);

    this.cache.set(chain, 'contextChain', entityId, entityType);
    return chain;
  }

  _findEntityByName(name) {
    if (!this.graph.entities.size) return null;
    const nameLower = name.toLowerCase();
    for (const entity of this.graph.entities.values()) {
      const props = entity.properties || {};
      const entityName = props.name || '';
      if (entityName.toLowerCase() === nameLower) return entity;
    }
    return null;
  }

  _getProjectContext(projectId) {
    const context = [];
    const project = this.graph.getEntity(projectId);
    if (project) {
      context.push({
        type: 'project',
        role: 'center',
        name: (project.properties || {}).name || projectId,
        status: (project.properties || {}).status || 'unknown'
      });
    }
    for (const rel of this.graph.getRelationsFrom(projectId)) {
      const person = this.graph.getEntity(rel.rel_to);
      if (person) {
        context.push({
          type: 'person',
          role: rel.rel || 'participant',
          name: (person.properties || {}).name || rel.rel_to
        });
      }
    }
    return context;
  }

  _getPersonContext(personId) {
    const context = [];
    const person = this.graph.getEntity(personId);
    if (person) {
      context.push({
        type: 'person',
        role: 'center',
        name: (person.properties || {}).name || personId
      });
    }
    for (const rel of this.graph.getRelationsFrom(personId)) {
      const target = this.graph.getEntity(rel.to);
      if (target) {
        context.push({
          type: target.type || 'unknown',
          role: rel.rel,
          name: (target.properties || {}).name || rel.to
        });
      }
    }
    return context;
  }

  _getTaskContext(taskId) {
    const context = [];
    const task = this.graph.getEntity(taskId);
    if (task) {
      context.push({
        type: 'task',
        role: 'center',
        name: (task.properties || {}).name || taskId,
        status: (task.properties || {}).status || 'unknown'
      });
    }
    return context;
  }

  _getGenericContext(entityId) {
    const context = [];
    const entity = this.graph.getEntity(entityId);
    if (entity) {
      context.push({
        type: entity.type || 'unknown',
        role: 'center',
        name: (entity.properties || {}).name || entityId
      });
    }
    return context;
  }

  getStats() {
    return {
      cache: this.cache.stats(),
      graph_entities: this.graph.entities.size,
      graph_relations: this.graph.relations.length,
      memories_loaded: this.memories.length
    };
  }
}

// ============================================================
// CLI Handler
// ============================================================

/**
 * @param {string} command
 * @param {object} args
 * @returns {Promise<object>}
 */
export async function cmdInference(command, args) {
  const inference = new MemoryInference(parseInt(args.cacheTtl) || 300);

  switch (command) {
    case 'search': {
      if (!args.query) return { error: '请提供查询内容' };
      const result = await inference.inferRelated(
        args.query,
        parseInt(args.limit) || 10,
        parseInt(args.depth) || 2
      );
      if (args.json) return { type: 'json', data: result };
      const lines = [
        `🔍 联合推理搜索: "${args.query}"`,
        `   向量结果: ${result.stats.vector_count} 条`,
        `   图谱扩展: ${result.stats.expansion_count} 条`,
        `   合并结果: ${result.stats.merged_count} 条`,
        `   耗时: ${result.stats.time_ms} ms\n`,
        `📊 Top 合并结果:`
      ];
      for (let i = 0; i < Math.min(5, result.merged.length); i++) {
        const item = result.merged[i];
        const sources = (item.sources || []).join('+');
        lines.push(`   ${i + 1}. [${sources}] ${(item.text || '').slice(0, 60)}... (score: ${item.combined_score.toFixed(3)})`);
      }
      return { type: 'text', text: lines.join('\n') };
    }

    case 'context':
    case 'chain': {
      if (!args.query) return { error: '请提供实体ID' };
      const chain = inference.getContextChain(args.query, args.type);
      if (args.json) return { type: 'json', data: chain };
      if (!chain.length) return { type: 'text', text: '未找到上下文信息' };
      const lines = [`📋 实体上下文链: ${args.query}\n`];
      const center = chain.find(c => c.role === 'center');
      if (center) {
        lines.push(`🎯 ${(center.type || 'Entity').toUpperCase()}: ${center.name}`);
        if (center.status) lines.push(`   状态: ${center.status}`);
        lines.push('');
      }
      const related = chain.filter(c => c.role !== 'center');
      if (related.length) {
        lines.push('🔗 关联信息:');
        for (const item of related) {
          lines.push(`   - [${item.type}/${item.role}] ${item.name}${item.status ? ` [${item.status}]` : ''}`);
        }
      }
      return { type: 'text', text: lines.join('\n') };
    }

    case 'related': {
      if (!args.query) return { error: '请提供查询内容' };
      const chain = inference.getContextChain(args.query, args.type);
      if (args.json) return { type: 'json', data: chain };
      return { type: 'text', text: JSON.stringify(chain, null, 2) };
    }

    case 'stats': {
      const stats = inference.getStats();
      if (args.json) return { type: 'json', data: stats };
      return {
        type: 'text',
        text: `📊 Memory Inference 引擎统计\n` +
          `   缓存: ${stats.cache.valid} 有效 / ${stats.cache.total} 总计\n` +
          `   图谱实体: ${stats.graph_entities}\n` +
          `   图谱关系: ${stats.graph_relations}\n` +
          `   加载记忆: ${stats.memories_loaded}`
      };
    }

    case 'cache-clear': {
      inference.cache.clear();
      return { type: 'text', text: '✅ 缓存已清空' };
    }

    default:
      return { error: `未知命令: ${command}` };
  }
}

export default { MemoryInference, cmdInference };
/**
 * memory_insights - 用户记忆洞察分析
 * 分析用户偏好、记忆热点、行为趋势
 */

import { getAllMemories } from '../storage.js';
import { Counter } from '../utils/counter.js';

const TOOLS = ['飞书', '微信', 'QQ', '钉钉', 'Slack', 'Notion', 'Obsidian', 'GitHub', 'OpenClaw'];
const PROJECT_PATTERNS = ['项目', '龙宫', '官网', '重构', '电商', 'MetaGPT', 'OpenClaw'];
const CATEGORY_KEYWORDS = {
  'preference': ['喜欢', '偏好', '决定', '选择', '使用'],
  'fact': ['事实', '知道', '了解', '认识'],
  'decision': ['决定', '决策', '选择', '方案'],
  'learning': ['学习', '学到了', '掌握了', '了解']
};

export async function analyzeInsights() {
  const memories = getAllMemories();
  
  if (memories.length === 0) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({ summary: '暂无记忆数据', count: 0 }, null, 2)
      }]
    };
  }
  
  // Category distribution
  const categoryStats = new Counter();
  const toolUsage = new Counter();
  const projectUsage = new Counter();
  const importanceScores = [];
  
  for (const mem of memories) {
    categoryStats.increment(mem.category || 'other');
    importanceScores.push(mem.importance || 0.5);
    
    const text = mem.text || '';
    for (const tool of TOOLS) {
      if (text.includes(tool)) toolUsage.increment(tool);
    }
    for (const proj of PROJECT_PATTERNS) {
      if (text.includes(proj)) projectUsage.increment(proj);
    }
  }
  
  // Calculate average importance
  const avgImportance = importanceScores.reduce((a, b) => a + b, 0) / importanceScores.length;
  
  // Memory growth over time (by month)
  const monthlyCount = new Counter();
  for (const mem of memories) {
    const ts = mem.created_at || mem.timestamp;
    if (ts) {
      const date = new Date(typeof ts === 'number' ? ts : ts);
      const month = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
      monthlyCount.increment(month);
    }
  }
  
  const result = {
    summary: {
      total_memories: memories.length,
      avg_importance: Math.round(avgImportance * 100) / 100,
      category_count: Object.keys(categoryStats.counts).length
    },
    category_distribution: categoryStats.top(5),
    top_tools: toolUsage.top(5),
    top_projects: projectUsage.top(5),
    monthly_growth: Object.entries(monthlyCount.counts)
      .sort(([a], [b]) => b.localeCompare(a))
      .slice(0, 6)
      .reduce((acc, [month, count]) => ({ ...acc, [month]: count }), {}),
    suggestions: generateSuggestions(categoryStats, toolUsage, avgImportance)
  };
  
  return {
    content: [{
      type: 'text',
      text: JSON.stringify(result, null, 2)
    }]
  };
}

function generateSuggestions(categoryStats, toolUsage, avgImportance) {
  const suggestions = [];
  
  if (avgImportance < 0.5) {
    suggestions.push('平均重要性偏低，建议关注更高价值的记忆');
  }
  
  if (categoryStats.counts['other'] > 5) {
    suggestions.push('有较多未分类记忆，建议使用 category 参数进行分类');
  }
  
  const topTool = toolUsage.top(1)[0];
  if (topTool) {
    suggestions.push(`你最常用 ${topTool[0]}，相关记忆最多`);
  }
  
  return suggestions;
}

