// ============================================================
// TemplateManager
// ============================================================

export class TemplateManager {
  constructor() {
    this.templates = this._loadTemplates();
  }

  _loadTemplates() {
    if (existsSync(TEMPLATES_FILE)) {
      try {
        return JSON.parse(readFileSync(TEMPLATES_FILE, 'utf-8'));
      } catch { /* ignore */ }
    }
    return { ...DEFAULT_TEMPLATES };
  }

  _saveTemplates() {
    writeFileSync(TEMPLATES_FILE, JSON.stringify(this.templates, null, 2), 'utf-8');
  }

  listTemplates() {
    return Object.entries(this.templates).map(([id, t]) => ({
      id,
      name: t.name,
      description: t.description,
      importance: t.importance
    }));
  }

  getTemplate(type) {
    return this.templates[type] || null;
  }

  renderTemplate(type, data) {
    const template = this.templates[type];
    if (!template) return null;

    let text = template.template;
    for (const field of (template.fields || [])) {
      const value = data[field.name] || '';
      text = text.replace(new RegExp(`\\{${field.name}\\}`, 'g'), value);
    }
    return text;
  }

  createFromTemplate(type, data) {
    const template = this.templates[type];
    if (!template) return null;

    const text = this.renderTemplate(type, data);
    return {
      text,
      category: template.category || 'general',
      importance: data.importance || template.importance || 0.5,
      template: type,
      fields: data
    };
  }
}

// ============================================================
// CLI Handler
// ============================================================

/**
 * @param {string} command
 * @param {object} args
 * @returns {object}
 */
export function cmdTemplates(command, args) {
  const manager = new TemplateManager();

  switch (command) {
    case 'list': {
      const templates = manager.listTemplates();
      if (args.json) return { type: 'json', data: templates };
      const lines = ['📋 可用模板:', ''];
      templates.forEach(t => {
        lines.push(`  ${t.id}: ${t.name} (重要性: ${t.importance})`);
        lines.push(`      ${t.description}`);
      });
      return { type: 'text', text: lines.join('\n') };
    }

    case 'get': {
      if (!args.type) return { error: '请提供 --type' };
      const template = manager.getTemplate(args.type);
      if (!template) return { error: `未知模板: ${args.type}` };
      if (args.json) return { type: 'json', data: template };
      const lines = [`📝 模板: ${template.name}`, '', `描述: ${template.description}`];
      lines.push('字段:');
      for (const field of (template.fields || [])) {
        const req = field.required ? ' [必填]' : '';
        const opts = field.options ? ` (${field.options.join('|')})` : '';
        lines.push(`  - ${field.name}${req}: ${field.label}${opts}`);
      }
      return { type: 'text', text: lines.join('\n') };
    }

    case 'fill': {
      if (!args.type) return { error: '请提供 --type' };
      // Simple key=value data parsing
      const data = {};
      if (args.data) {
        try {
          const parsed = JSON.parse(args.data);
          Object.assign(data, parsed);
        } catch { /* ignore */ }
      }
      const result = manager.createFromTemplate(args.type, data);
      if (!result) return { error: `未知模板: ${args.type}` };
      if (args.json) return { type: 'json', data: result };
      return {
        type: 'text',
        text: `📝 生成的记忆:\n\n${result.text}\n\n分类: ${result.category} | 重要性: ${result.importance}`
      };
    }

    default:
      return { error: `未知命令: ${command}` };
  }
}

export default { TemplateManager, cmdTemplates };
/**
 * version_tools.js — MCP Tools for Memory Versioning (v2.7.0)
 * Part of Task #2: 完整修订历史
 *
 * Implements MCP tools:
 * - memory_version_list:   查看记忆版本历史
 * - memory_version_diff:    比较两个版本差异
 * - memory_version_restore: 恢复到指定版本
 *
 * Tools follow the existing pattern in the codebase and are
 * backwards-compatible with the v2.6.0 tooling interface.
 */
import {
  getMemoryVersions,
  getMemoryVersion,
  restoreMemoryVersion,
  getVersionStats,
  compareMemoryVersions,
  getMemoryVersionCount,
  getMemory,
} from '../storage.js';

/**
 * Tool: memory_version_list
 * 列出记忆的版本历史，或全局版本统计
 *
 * @param {{ memoryId?: string, limit?: number, offset?: number }} opts
 */
export function memoryVersionListTool({ memoryId, limit = 10, offset = 0 } = {}) {
  try {
    if (!memoryId) {
      // 无 memoryId → 返回全局统计
      const stats = getVersionStats();
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            totalMemories: stats.totalMemories,
            totalVersions: stats.totalVersions,
            maxVersionsPerMemory: 10,
            memoriesWithVersions: stats.memoryCounts,
          }, null, 2),
        }],
      };
    }

    let versions = getMemoryVersions(memoryId);

    // 分页
    const total = versions.length;
    versions = versions.slice(offset, offset + limit);

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          memoryId,
          total,
          offset,
          limit,
          versions,
        }, null, 2),
      }],
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
  }
}

/**
 * Tool: memory_version_diff
 * 比较两个版本的差异
 *
 * @param {{ memoryId: string, versionId1?: string, versionId2?: string }} opts
 */
export function memoryVersionDiffTool({ memoryId, versionId1, versionId2 } = {}) {
  try {
    if (!memoryId) throw new Error('memoryId is required');

    const versions = getMemoryVersions(memoryId);
    if (versions.length === 0) {
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({ error: `No version history for memory ${memoryId}` }, null, 2),
        }],
        isError: true,
      };
    }

    // 单 versionId → 与上一个版本比较
    if (versionId1 && !versionId2) {
      const idx = versions.findIndex((v) => v.versionId === versionId1);
      if (idx === -1) throw new Error(`Version ${versionId1} not found`);
      if (idx === 0) {
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({
              memoryId,
              note: 'First version, comparing with empty',
              fromVersion: null,
              toVersion: versions[0],
              diff: { addedCount: 1, removedCount: 0, added: ['[initial version]'], removed: [] },
            }, null, 2),
          }],
        };
      }
      const v2 = versions[idx];
      const v1 = versions[idx - 1];
      const diff = compareMemoryVersions(memoryId, v1.versionId, v2.versionId);
      return {
        content: [{ type: 'text', text: JSON.stringify(diff, null, 2) }],
      };
    }

    // 两个 versionId → 指定版本比较
    if (!versionId1 || !versionId2) {
      throw new Error('versionId1 and versionId2 are both required for diff');
    }

    const diff = compareMemoryVersions(memoryId, versionId1, versionId2);
    return {
      content: [{ type: 'text', text: JSON.stringify(diff, null, 2) }],
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
  }
}

/**
 * Tool: memory_version_restore
 * 恢复到指定版本
 *
 * @param {{ memoryId: string, versionId?: string, preview?: boolean }} opts
 */
export function memoryVersionRestoreTool({ memoryId, versionId, preview } = {}) {
  try {
    if (!memoryId) throw new Error('memoryId is required');

    const memory = getMemory(memoryId);
    if (!memory) {
      return {
        content: [{ type: 'text', text: JSON.stringify({ error: `Memory ${memoryId} not found` }, null, 2) }],
        isError: true,
      };
    }

    const versions = getMemoryVersions(memoryId);

    // preview 模式
    if (preview) {
      const target = versionId
        ? versions.find((v) => v.versionId === versionId)
        : versions[versions.length - 1];

      if (!target) {
        return {
          content: [{ type: 'text', text: JSON.stringify({ error: `Version ${versionId || 'latest'} not found` }, null, 2) }],
          isError: true,
        };
      }

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            preview: true,
            memoryId,
            current: {
              text: memory.text?.slice(0, 200),
              updated_at: memory.updated_at,
              versionCount: versions.length,
            },
            restoreTo: {
              versionId: target.versionId,
              timestamp: target.timestamp,
              changeType: target.changeType,
            },
            hint: 'Set preview: false to actually restore',
          }, null, 2),
        }],
      };
    }

    // 实际恢复
    if (!versionId) {
      return {
        content: [{ type: 'text', text: JSON.stringify({ error: 'versionId is required (or use preview: true)' }, null, 2) }],
        isError: true,
      };
    }

    const result = restoreMemoryVersion(memoryId, versionId);
    return {
      content: [{ type: 'text', text: JSON.stringify(result, null, 2) }],
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
  }
}

export default {
  memoryVersionListTool,
  memoryVersionDiffTool,
  memoryVersionRestoreTool,
};
/**
 * tools/working_memory_tools.js - MCP Tools for Working Memory
 * 
 * Registers the following tools:
 * - memory_working_start   Create a new working memory
 * - memory_working_list    List active working memories
 * - memory_working_get     Get a specific working memory
 * - memory_working_hold    Hold (pause) a working memory
 * - memory_working_resume  Resume a held working memory
 * - memory_working_clear   Explicitly clear a working memory
 * - memory_working_extend  Extend TTL
 * - memory_working_context Update context window
 * - memory_working_tree    Get task hierarchy tree
 */

import { z } from 'zod';
import {
  create,
  hold,
  resume,
  clear,
  extend,
  getActive,
  get,
  updateContext,
} from '../working_memory_manager.js';
import {
  buildTaskTree,
  getSubtasks,
  getAncestry,
  getDescendants,
  linkToEpisode,
  getWorkingMemoriesByEpisode,
  visualizeTaskTree,
} from '../task_hierarchy.js';

/**
 * Register working memory tools with MCP server
 * @param {import('@modelcontextprotocol/sdk').McpServer} server
 */
export function registerWorkingMemoryTools(server) {

  // ─── memory_working_start ───────────────────────────────────────────────
  server.registerTool('memory_working_start', {
    description: 'Start a new working memory for a task you are currently working on. Working memory is short-term, task-focused context that auto-expires after 2 hours. Use this when actively working on something specific.',
    inputSchema: z.object({
      task: z.string().describe('Description of the current task'),
      context: z.string().optional().describe('Additional context/details about the task'),
      ttl_ms: z.number().optional().describe('Custom TTL in milliseconds (default: 2 hours)'),
      task_id: z.string().optional().describe('Custom task ID'),
      episode_id: z.string().optional().describe('Episode/session ID to link with episodic memory'),
      parent_task_id: z.string().optional().describe('Parent task ID for subtask hierarchy'),
    }),
  }, async ({ task, context = '', ttl_ms = null, task_id = null, episode_id = null, parent_task_id = null }) => {
    try {
      const result = create({
        taskDescription: task,
        taskId: task_id,
        contextWindow: context,
        ttlMs: ttl_ms,
        episodeId: episode_id,
        parentTaskId: parent_task_id,
      });

      if (!result.success) {
        return { content: [{ type: 'text', text: `Failed: ${result.error}` }], isError: true };
      }

      const wm = result.workingMemory;
      let msg = `✅ Working memory created\n`;
      msg += `   ID: ${wm.id}\n`;
      msg += `   Task: ${wm.description}\n`;
      msg += `   Status: ${wm.status}\n`;
      msg += `   Expires: ${wm.expiresAt}\n`;
      if (result.archived) {
        msg += `   ⚠️ Oldest working memory auto-archived (max limit 5)`;
      }

      return { content: [{ type: 'text', text: msg }] };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_working_list ─────────────────────────────────────────────────
  server.registerTool('memory_working_list', {
    description: 'List all active (and held) working memories. Shows tasks you are currently working on or have paused.',
    inputSchema: z.object({}),
  }, async () => {
    try {
      const { active, held, counts } = getActive();

      let msg = `🧠 Working Memories\n`;
      msg += `   Active: ${counts.active}/${counts.maxActive} | Held: ${counts.held}\n\n`;

      if (active.length === 0 && held.length === 0) {
        msg += `   No active working memories.\n`;
        return { content: [{ type: 'text', text: msg }] };
      }

      for (const wm of active) {
        const remainingMin = Math.round(wm.remainingMs / 60000);
        msg += `● [ACTIVE] ${wm.description}\n`;
        msg += `  ID: ${wm.id} | Expires: in ${remainingMin}min\n`;
        if (wm.contextWindow) {
          msg += `  Context: ${wm.contextWindow.slice(0, 80)}...\n`;
        }
        msg += `\n`;
      }

      for (const wm of held) {
        msg += `○ [HELD] ${wm.description}\n`;
        msg += `  ID: ${wm.id}\n`;
        msg += `\n`;
      }

      return { content: [{ type: 'text', text: msg }] };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_working_get ──────────────────────────────────────────────────
  server.registerTool('memory_working_get', {
    description: 'Get a specific working memory by ID.',
    inputSchema: z.object({
      id: z.string().describe('Working memory ID'),
    }),
  }, async ({ id }) => {
    try {
      const wm = get(id);
      if (!wm) {
        return { content: [{ type: 'text', text: `Working memory not found: ${id}` }], isError: true };
      }

      const remainingMin = Math.round(wm.remainingMs / 60000);
      let msg = `🧠 Working Memory\n`;
      msg += `   ID: ${wm.id}\n`;
      msg += `   Task: ${wm.description}\n`;
      msg += `   Status: ${wm.status}\n`;
      msg += `   Created: ${wm.createdAt}\n`;
      msg += `   Expires: in ${remainingMin}min\n`;
      if (wm.contextWindow) {
        msg += `   Context: ${wm.contextWindow}\n`;
      }
      if (wm.episodeId) {
        msg += `   Episode: ${wm.episodeId}\n`;
      }
      if (wm.parentTaskId) {
        msg += `   Parent: ${wm.parentTaskId}\n`;
      }
      if (wm.subtaskCount > 0) {
        msg += `   Subtasks: ${wm.subtaskCount}\n`;
      }

      return { content: [{ type: 'text', text: msg }] };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_working_hold ─────────────────────────────────────────────────
  server.registerTool('memory_working_hold', {
    description: 'Hold (pause) a working memory without clearing it. Use when switching tasks temporarily.',
    inputSchema: z.object({
      id: z.string().describe('Working memory ID to hold'),
    }),
  }, async ({ id }) => {
    try {
      const result = hold(id);
      if (!result.success) {
        return { content: [{ type: 'text', text: `Failed: ${result.error}` }], isError: true };
      }

      return {
        content: [{
          type: 'text',
          text: `⏸️ Working memory held: ${result.workingMemory.description}\n   ID: ${result.workingMemory.id}`,
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_working_resume ────────────────────────────────────────────────
  server.registerTool('memory_working_resume', {
    description: 'Resume a held working memory back to active status.',
    inputSchema: z.object({
      id: z.string().describe('Working memory ID to resume'),
      extend_ms: z.number().optional().describe('Extend TTL by this many milliseconds'),
    }),
  }, async ({ id, extend_ms = null }) => {
    try {
      const result = resume(id, extend_ms);
      if (!result.success) {
        return { content: [{ type: 'text', text: `Failed: ${result.error}` }], isError: true };
      }

      return {
        content: [{
          type: 'text',
          text: `▶️ Working memory resumed: ${result.workingMemory.description}\n   ID: ${result.workingMemory.id}`,
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_working_clear ────────────────────────────────────────────────
  server.registerTool('memory_working_clear', {
    description: 'Explicitly clear a working memory. Its subtasks will be auto-held.',
    inputSchema: z.object({
      id: z.string().describe('Working memory ID to clear'),
      reason: z.string().optional().describe('Reason for clearing'),
    }),
  }, async ({ id, reason = 'explicit_clear' }) => {
    try {
      const result = clear(id, reason);
      if (!result.success) {
        return { content: [{ type: 'text', text: `Failed: ${result.error}` }], isError: true };
      }

      return {
        content: [{
          type: 'text',
          text: `✅ Working memory cleared: ${result.workingMemory.description}\n   ID: ${result.workingMemory.id}`,
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_working_extend ───────────────────────────────────────────────
  server.registerTool('memory_working_extend', {
    description: 'Extend the TTL (time-to-live) of a working memory.',
    inputSchema: z.object({
      id: z.string().describe('Working memory ID'),
      duration_ms: z.number().describe('Duration to extend in milliseconds (e.g., 3600000 for +1 hour)'),
    }),
  }, async ({ id, duration_ms }) => {
    try {
      const result = extend(id, duration_ms);
      if (!result.success) {
        return { content: [{ type: 'text', text: `Failed: ${result.error}` }], isError: true };
      }

      const extendedMin = Math.round(duration_ms / 60000);
      return {
        content: [{
          type: 'text',
          text: `⏰ Working memory extended by ${extendedMin}min: ${result.workingMemory.description}\n   New expiry: ${result.workingMemory.expiresAt}`,
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_working_context ──────────────────────────────────────────────
  server.registerTool('memory_working_context', {
    description: 'Update the context window of a working memory.',
    inputSchema: z.object({
      id: z.string().describe('Working memory ID'),
      context: z.string().describe('New context content'),
    }),
  }, async ({ id, context }) => {
    try {
      const result = updateContext(id, context);
      if (!result.success) {
        return { content: [{ type: 'text', text: `Failed: ${result.error}` }], isError: true };
      }

      return {
        content: [{
          type: 'text',
          text: `✅ Context updated for: ${result.workingMemory.description}`,
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_working_tree ─────────────────────────────────────────────────
  server.registerTool('memory_working_tree', {
    description: 'Get the task hierarchy tree showing parent/child relationships between working memories.',
    inputSchema: z.object({
      id: z.string().optional().describe('Optional working memory ID to get subtree for'),
    }),
  }, async ({ id = null }) => {
    try {
      if (id) {
        const descendants = getDescendants(id);
        const ancestry = getAncestry(id);
        
        let msg = `📋 Task Tree for ${id}\n\n`;
        msg += `Ancestry (${ancestry.length} levels):\n`;
        for (const wm of ancestry) {
          msg += `  › ${wm.taskId}: ${wm.description}\n`;
        }
        msg += `\nSubtasks (${descendants.length}):\n`;
        for (const wm of descendants) {
          msg += `  › ${wm.taskId}: ${wm.description}\n`;
        }
        return { content: [{ type: 'text', text: msg }] };
      }

      const tree = visualizeTaskTree();
      return { content: [{ type: 'text', text: tree }] };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });

  // ─── memory_working_episode ──────────────────────────────────────────────
  server.registerTool('memory_working_episode', {
    description: 'Get all working memories linked to a specific episode/session, or link a working memory to an episode.',
    inputSchema: z.object({
      action: z.enum(['get', 'link']).describe('Action: get memories for an episode, or link a working memory to an episode'),
      episode_id: z.string().describe('Episode/session ID'),
      working_memory_id: z.string().optional().describe('Working memory ID (for link action)'),
    }),
  }, async ({ action, episode_id, working_memory_id = null }) => {
    try {
      if (action === 'get') {
        const wms = getWorkingMemoriesByEpisode(episode_id);
        let msg = `📎 Working memories for episode: ${episode_id}\n`;
        msg += `   Count: ${wms.length}\n\n`;
        for (const wm of wms) {
          msg += `  ● [${wm.status}] ${wm.description}\n`;
        }
        return { content: [{ type: 'text', text: msg }] };
      }

      if (action === 'link') {
        if (!working_memory_id) {
          return { content: [{ type: 'text', text: 'working_memory_id required for link action' }], isError: true };
        }
        const result = linkToEpisode(working_memory_id, episode_id);
        return {
          content: [{
            type: 'text',
            text: result.success
              ? `🔗 Linked ${working_memory_id} to episode ${episode_id}`
              : `Failed to link`,
          }],
        };
      }
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  });
}
/**
 * Checkpoint management for tracking memory processing progress.
 *
 * ## Split-state design
 *
 * Per-session state is split into two independent namespaces to prevent
 * the PipelineManager and L0/L1 runners from overwriting each other's fields:
 *
 * - **runner_states** (`RunnerSessionState`): owned by CheckpointManager methods
 *   (markL1*, advanceSession*). Contains L0 capture cursor, L1 cursor, scene name.
 *
 * - **pipeline_states** (`PipelineSessionState`): owned exclusively by
 *   PipelineManager via `mergePipelineStates()`. Contains conversation_count,
 *   extraction times, L2 tracking fields.
 *
 * Each side only reads/writes its own namespace, eliminating the split-brain
 * overwrite bug where pipeline persistStates() could clobber runner-written fields.
 *
 * ## Concurrency safety
 *
 * All mutating methods (read-modify-write) are serialized via a per-file async lock.
 * Multiple CheckpointManager instances sharing the same file path automatically share
 * the same lock, so callers can freely `new CheckpointManager()` without coordination.
 * Writes use atomic tmp+rename to prevent corruption on crash.
 */

import fs from "node:fs/promises";
import path from "node:path";
import { randomBytes } from "node:crypto";

// ============================
// Types
// ============================

/**
 * Per-session state managed by L0/L1 runners (written directly to checkpoint).
 * These fields are ONLY written by CheckpointManager methods (markL1*, advanceSession*, etc.)
 * and are NEVER touched by the PipelineManager's persistStates().
 *
 * @typedef {Object} RunnerSessionState
 * @property {number} last_captured_timestamp - Epoch ms of the newest message captured for THIS session.
 *   Used instead of the global `Checkpoint.last_captured_timestamp` so that
 *   concurrent sessions don't advance each other's cursors and cause missed messages.
 * @property {number} last_l1_cursor - L0 JSONL cursor: epoch ms of last message processed by L1
 * @property {string} last_scene_name - Last scene name from the most recent L1 extraction (for cross-batch continuity)
 */

/**
 * Per-session state managed exclusively by PipelineManager (written via mergePipelineStates).
 * These fields are ONLY written by the pipeline's persistStates() callback
 * and are NEVER touched by CheckpointManager's L0/L1 methods.
 *
 * @typedef {Object} PipelineSessionState
 * @property {number} conversation_count - Conversation rounds since last L1 trigger
 * @property {string} last_extraction_time - ISO timestamp of the last extraction completion
 * @property {string} last_extraction_updated_time - ISO timestamp cursor for incremental extraction reads
 * @property {number} last_active_time - Epoch ms of the last notifyConversation call
 * @property {number} l2_pending_l1_count - Mirrors conversation_count at L1 completion time (for L2 tracking)
 * @property {number} warmup_threshold - Current warm-up threshold for L1 triggering (0 = graduated)
 * @property {string} l2_last_extraction_time - ISO timestamp of last L2 extraction completion
 */

/**
 * @typedef {Object} Checkpoint
 * @property {number} last_captured_timestamp - Epoch ms of the newest message successfully uploaded
 * @property {number} total_processed - Total messages processed across all time
 * @property {number} last_persona_at
 * @property {string} last_persona_time
 * @property {boolean} request_persona_update
 * @property {string} persona_update_reason
 * @property {number} memories_since_last_persona
 * @property {number} scenes_processed
 * @property {Record<string, RunnerSessionState>} runner_states
 * @property {Record<string, PipelineSessionState>} pipeline_states
 * @property {number} l0_conversations_count
 * @property {number} total_memories_extracted
 */

const DEFAULT_RUNNER_STATE = {
  last_captured_timestamp: 0,
  last_l1_cursor: 0,
  last_scene_name: "",
};

const DEFAULT_PIPELINE_STATE = {
  conversation_count: 0,
  last_extraction_time: "",
  last_extraction_updated_time: "",
  last_active_time: 0,
  l2_pending_l1_count: 0,
  warmup_threshold: 0, // 0 = graduated (safe default for old sessions missing this field)
  l2_last_extraction_time: "",
};

const DEFAULT_CHECKPOINT = {
  last_captured_timestamp: 0,
  total_processed: 0,
  last_persona_at: 0,
  last_persona_time: "",
  request_persona_update: false,
  persona_update_reason: "",
  memories_since_last_persona: 0,
  scenes_processed: 0,
  runner_states: {},
  pipeline_states: {},
  l0_conversations_count: 0,
  total_memories_extracted: 0,
};

/**
 * @typedef {Object} CheckpointLogger
 * @property {(msg: string) => void} info
 * @property {(msg: string) => void} [warn]
 */

const noopLogger = { info() {} };

// ============================
// Per-file async lock
// ============================
// Keyed by resolved file path. Multiple CheckpointManager instances pointing
// to the same file automatically share the same lock — callers don't need to
// coordinate instance creation.

/** @type {Map<string, Promise<void>>} */
const fileLocks = new Map();

/**
 * Serialize async critical sections per file path.
 * Under no contention the overhead is a single resolved-promise await.
 * @template T
 * @param {string} filePath
 * @param {() => Promise<T>} fn
 * @returns {Promise<T>}
 */
async function withFileLock(filePath, fn) {
  // Chain after whatever is currently queued for this path
  const prev = fileLocks.get(filePath) ?? Promise.resolve();
  let release;
  const gate = new Promise((r) => { release = r; });
  fileLocks.set(filePath, gate);

  await prev;
  try {
    return await fn();
  } finally {
    release();
    // Clean up the map entry if we're the tail of the chain
    if (fileLocks.get(filePath) === gate) {
      fileLocks.delete(filePath);
    }
  }
}

/**
 * Deep clone a value using the structuredClone API (Node 17+).
 * Falls back to JSON parse+stringify for environments without it.
 * @template T
 * @param {T} val
 * @returns {T}
 */
function deepClone(val) {
  if (typeof structuredClone === "function") {
    return structuredClone(val);
  }
  return JSON.parse(JSON.stringify(val));
}

export class CheckpointManager {
  /**
   * @param {string} dataDir
   * @param {CheckpointLogger} [logger]
   */
  constructor(dataDir, logger) {
    this.filePath = path.join(dataDir, ".metadata", "recall_checkpoint.json");
    this.logger = logger ?? noopLogger;
  }

  // ============================
  // Low-level I/O (internal)
  // ============================

  /** @returns {Promise<Checkpoint>} */
  async readRaw() {
    try {
      const raw = await fs.readFile(this.filePath, "utf-8");
      const parsed = JSON.parse(raw);
      // Merge with defaults for backward compat (old checkpoints lack new fields).
      const cp = { ...deepClone(DEFAULT_CHECKPOINT), ...parsed };

      // Migrate from old session_states format (pre-split)
      const oldStates = parsed.session_states;
      if (oldStates && !parsed.runner_states && !parsed.pipeline_states) {
        cp.runner_states = {};
        cp.pipeline_states = {};
        for (const [key, state] of Object.entries(oldStates)) {
          cp.runner_states[key] = {
            ...DEFAULT_RUNNER_STATE,
            last_captured_timestamp: state.last_captured_timestamp ?? 0,
            last_l1_cursor: state.last_l1_cursor ?? 0,
            last_scene_name: state.last_scene_name ?? "",
          };
          cp.pipeline_states[key] = {
            ...DEFAULT_PIPELINE_STATE,
            conversation_count: state.conversation_count ?? 0,
            last_extraction_time: state.last_extraction_time ?? "",
            last_extraction_updated_time: state.last_extraction_updated_time ?? "",
            last_active_time: state.last_active_time ?? 0,
            l2_pending_l1_count: state.l2_pending_l1_count ?? 0,
            l2_last_extraction_time: state.l2_last_extraction_time ?? "",
          };
        }
      } else {
        // Ensure per-session states have all fields with defaults
        if (cp.runner_states) {
          for (const [key, state] of Object.entries(cp.runner_states)) {
            cp.runner_states[key] = { ...DEFAULT_RUNNER_STATE, ...state };
          }
        }
        if (cp.pipeline_states) {
          for (const [key, state] of Object.entries(cp.pipeline_states)) {
            cp.pipeline_states[key] = { ...DEFAULT_PIPELINE_STATE, ...state };
          }
        }
      }
      return cp;
    } catch {
      return deepClone(DEFAULT_CHECKPOINT);
    }
  }

  /** Atomic write: write to tmp file, then rename into place. */
  /** @param {Checkpoint} checkpoint */
  async writeRaw(checkpoint) {
    const dir = path.dirname(this.filePath);
    await fs.mkdir(dir, { recursive: true });
    const tmp = `${this.filePath}.tmp.${randomBytes(4).toString("hex")}`;
    await fs.writeFile(tmp, JSON.stringify(checkpoint, null, 2), "utf-8");
    await fs.rename(tmp, this.filePath);
  }

  // ============================
  // Locked read-modify-write helper
  // ============================

  /**
   * Execute a mutating operation under the per-file lock.
   * `fn` receives the current checkpoint and may modify it in place;
   * the updated checkpoint is atomically written back.
   * @param {(cp: Checkpoint) => void | Promise<void>} fn
   * @returns {Promise<Checkpoint>}
   */
  async mutate(fn) {
    return withFileLock(this.filePath, async () => {
      const cp = await this.readRaw();
      await fn(cp);
      await this.writeRaw(cp);
      return cp;
    });
  }

  // ============================
  // Public API — read-only
  // ============================

  /**
   * Read the current checkpoint (unlocked snapshot).
   *
   * NOTE: This does NOT acquire the file lock. The returned snapshot may be
   * stale if a concurrent `mutate()` is in progress. This is acceptable for
   * read-only uses (status display, deciding whether to run a pipeline step).
   *
   * For read-then-write patterns, always use `mutate()` instead — it acquires
   * the lock and re-reads from disk inside the critical section, ensuring the
   * update is based on the latest state.
   * @returns {Promise<Checkpoint>}
   */
  async read() {
    return this.readRaw();
  }

  /** Write a full checkpoint (acquires lock + atomic write). */
  /** @param {Checkpoint} checkpoint */
  async write(checkpoint) {
    return withFileLock(this.filePath, () => this.writeRaw(checkpoint));
  }

  // ============================
  // Public API — mutating (all serialized via file lock)
  // ============================

  /**
   * Advance the captured timestamp after successful upload/recording.
   * Also updates total_processed and persona counters.
   *
   * NOTE: This advances the GLOBAL cursor (`Checkpoint.last_captured_timestamp`).
   * For per-session cursor advancement, use `advanceSessionCapturedTimestamp()`.
   * The global cursor is kept for aggregate stats / backward compat, but should
   * NOT be used as the L0 incremental-capture filter (use per-session instead).
   * @param {number} maxTimestamp
   * @param {number} messageCount
   */
  async advanceCapturedTimestamp(maxTimestamp, messageCount) {
    const cp = await this.mutate((cp) => {
      cp.last_captured_timestamp = maxTimestamp;
      cp.total_processed += messageCount;
      cp.memories_since_last_persona += messageCount;
    });
    this.logger.info(
      `[checkpoint] advanceCapturedTimestamp: -> ${maxTimestamp} (+${messageCount} msgs), ` +
      `total_processed=${cp.total_processed}, memories_since_last_persona=${cp.memories_since_last_persona}`,
    );
  }

  /**
   * Advance the per-session L0 capture cursor after recording messages.
   * This is the **primary** cursor for incremental L0 recording — each session
   * tracks its own progress independently, preventing cross-session cursor drift.
   *
   * Also updates the global cursor / total_processed for aggregate stats.
   * @param {string} sessionKey
   * @param {number} maxTimestamp
   * @param {number} messageCount
   */
  async advanceSessionCapturedTimestamp(sessionKey, maxTimestamp, messageCount) {
    const cp = await this.mutate((cp) => {
      // Per-session cursor (runner-owned)
      const state = this.getRunnerState(cp, sessionKey);
      state.last_captured_timestamp = maxTimestamp;
      // Global stats (aggregate only — not used for filtering)
      cp.last_captured_timestamp = Math.max(cp.last_captured_timestamp, maxTimestamp);
      cp.total_processed += messageCount;
      cp.memories_since_last_persona += messageCount;
    });
    this.logger.info(
      `[checkpoint] advanceSessionCapturedTimestamp session=${sessionKey}: -> ${maxTimestamp} ` +
      `(+${messageCount} msgs), total_processed=${cp.total_processed}`,
    );
  }

  /**
   * Increment L0 conversation count.
   */
  async incrementL0ConversationCount() {
    await this.mutate((cp) => {
      cp.l0_conversations_count += 1;
    });
  }

  // ============================
  // Persona methods (L3)
  // ============================

  /** @param {number} totalProcessed */
  async markPersonaGenerated(totalProcessed) {
    await this.mutate((cp) => {
      cp.last_persona_at = totalProcessed;
      cp.last_persona_time = new Date().toISOString();
      cp.memories_since_last_persona = 0;
      cp.request_persona_update = false;
      cp.persona_update_reason = "";
    });
  }

  async clearPersonaRequest() {
    await this.mutate((cp) => {
      cp.request_persona_update = false;
      cp.persona_update_reason = "";
    });
  }

  /** @param {string} reason */
  async setPersonaUpdateRequest(reason) {
    await this.mutate((cp) => {
      cp.request_persona_update = true;
      cp.persona_update_reason = reason;
    });
  }

  async incrementScenesProcessed() {
    const cp = await this.mutate((cp) => {
      cp.scenes_processed += 1;
    });
    this.logger.info(`[checkpoint] incrementScenesProcessed: scenes_processed=${cp.scenes_processed}`);
  }

  // ============================
  // Per-session helpers — runner state (L0/L1 owned)
  // ============================

  /**
   * Get or create runner session state for a session.
   * @param {Checkpoint} cp
   * @param {string} sessionKey
   * @returns {RunnerSessionState}
   */
  getRunnerState(cp, sessionKey) {
    if (!cp.runner_states) {
      cp.runner_states = {};
    }
    let state = cp.runner_states[sessionKey];
    if (!state) {
      state = { ...DEFAULT_RUNNER_STATE };
      cp.runner_states[sessionKey] = state;
    }
    return state;
  }

  // ============================
  // Per-session helpers — pipeline state (PipelineManager owned)
  // ============================

  /**
   * Get or create pipeline session state for a session.
   * @param {Checkpoint} cp
   * @param {string} sessionKey
   * @returns {PipelineSessionState}
   */
  getPipelineState(cp, sessionKey) {
    if (!cp.pipeline_states) {
      cp.pipeline_states = {};
    }
    let state = cp.pipeline_states[sessionKey];
    if (!state) {
      state = { ...DEFAULT_PIPELINE_STATE, last_active_time: Date.now() };
      cp.pipeline_states[sessionKey] = state;
    }
    return state;
  }

  /**
   * Get all pipeline states from checkpoint.
   * @param {Checkpoint} cp
   * @returns {Record<string, PipelineSessionState>}
   */
  getAllPipelineStates(cp) {
    return cp.pipeline_states ?? {};
  }

  /**
   * Merge pipeline session states into the checkpoint (used by pipeline persister).
   * Acquires the file lock so this is safe against concurrent mutations.
   *
   * This writes ONLY to `pipeline_states`, never touching `runner_states`.
   * This is the core guarantee that eliminates the split-brain overwrite bug.
   * @param {Record<string, PipelineSessionState>} states
   */
  async mergePipelineStates(states) {
    await this.mutate((cp) => {
      if (!cp.pipeline_states) cp.pipeline_states = {};
      for (const [key, pState] of Object.entries(states)) {
        cp.pipeline_states[key] = {
          ...cp.pipeline_states[key],
          ...pState,
        };
      }
    });
  }

  // ============================
  // L1-specific methods
  // ============================

  /**
   * Mark L1 extraction completed: reset sinceL1 counter, advance L1 cursor,
   * and optionally save the last scene name for cross-batch continuity.
   * @param {string} sessionKey
   * @param {number} memoriesExtracted
   * @param {number} [cursorTimestamp]
   * @param {string} [lastSceneName]
   */
  async markL1ExtractionComplete(sessionKey, memoriesExtracted, cursorTimestamp, lastSceneName) {
    await this.mutate((cp) => {
      const state = this.getRunnerState(cp, sessionKey);
      if (cursorTimestamp) {
        state.last_l1_cursor = cursorTimestamp;
      }
      if (lastSceneName !== undefined) {
        state.last_scene_name = lastSceneName;
      }
      cp.total_memories_extracted += memoriesExtracted;
      cp.memories_since_last_persona += memoriesExtracted;
    });
    this.logger.info(
      `[checkpoint] markL1ExtractionComplete session=${sessionKey}: ` +
      `extracted=${memoriesExtracted}, cursor=${cursorTimestamp ?? "(unchanged)"}, ` +
      `lastScene="${lastSceneName ?? "(unchanged)"}"`,
    );
  }

  // ============================
  // Atomic capture (race-condition fix)
  // ============================

  /**
   * Atomically read the per-session cursor, execute the capture callback,
   * and advance the cursor — all within a single file-lock critical section.
   *
   * This eliminates the race window that existed when `read()` (unlocked) and
   * `advanceSessionCapturedTimestamp()` (locked) were separate calls:
   * two concurrent `agent_end` events could both read the same stale cursor
   * and record duplicate messages.
   *
   * The callback receives `afterTimestamp` (the current per-session cursor)
   * and must return either:
   *   - `{ maxTimestamp, messageCount }` to advance the cursor, or
   *   - `null` to leave the cursor unchanged (nothing captured).
   *
   * L0 conversation count is also incremented inside the lock when messages
   * are captured, removing the need for a separate `incrementL0ConversationCount()` call.
   *
   * @param {string} sessionKey   Per-session identifier
   * @param {number | undefined} pluginStartTimestamp  Cold-start floor (used when no cursor exists yet)
   * @param {(afterTimestamp: number) => Promise<{ maxTimestamp: number; messageCount: number } | null>} fn  Async callback that performs the actual capture
   */
  async captureAtomically(sessionKey, pluginStartTimestamp, fn) {
    await this.mutate(async (cp) => {
      // Read the per-session cursor inside the lock
      const state = this.getRunnerState(cp, sessionKey);
      let afterTimestamp = state.last_captured_timestamp || 0;

      // Cold-start guard (same logic that was previously in auto-capture.ts)
      if (afterTimestamp === 0 && pluginStartTimestamp && pluginStartTimestamp > 0) {
        afterTimestamp = pluginStartTimestamp;
      }

      const result = await fn(afterTimestamp);

      if (result) {
        // Advance per-session cursor (runner-owned)
        state.last_captured_timestamp = result.maxTimestamp;
        // Global stats (aggregate only — not used for filtering)
        cp.last_captured_timestamp = Math.max(cp.last_captured_timestamp, result.maxTimestamp);
        cp.total_processed += result.messageCount;
        cp.memories_since_last_persona += result.messageCount;
        // Increment L0 conversation count (was a separate mutate() call before)
        cp.l0_conversations_count += 1;
      }
    });
  }
}
/**
 * CleanContextRunner: executes LLM calls in a fully isolated context
 * using runEmbeddedPiAgent (same mechanism as the llm-task extension).
 *
 * Guarantees:
 * 1. Blank conversation history (temporary session file)
 * 2. Independent system prompt (only the task prompt)
 * 3. No tool calls (tools restricted to minimal read-only set to avoid empty tools[] rejection by some providers)
 * 4. No contamination from the main agent's context
 */

import fs from "node:fs/promises";
import fsSync from "node:fs";
import path from "node:path";
import os from "node:os";
import { fileURLToPath, pathToFileURL } from "node:url";

/**
 * Resolve a preferred temporary directory for memory-tdai operations.
 *
 * Previously imported from `openclaw/plugin-sdk` as `resolvePreferredOpenClawTmpDir`,
 * but that export was removed in openclaw 2026.2.23+. This local implementation
 * provides equivalent behavior:
 *   1. Try `/tmp/openclaw` (if writable)
 *   2. Fall back to `os.tmpdir()/openclaw-<uid>`
 * @returns {string}
 */
function resolveOpenClawTmpDir() {
  const POSIX_DIR = "/tmp/openclaw";
  try {
    if (fsSync.existsSync(POSIX_DIR)) {
      fsSync.accessSync(POSIX_DIR, fsSync.constants.W_OK | fsSync.constants.X_OK);
      return POSIX_DIR;
    }
    // Try to create it
    fsSync.mkdirSync(POSIX_DIR, { recursive: true, mode: 0o700 });
    return POSIX_DIR;
  } catch {
    // Fall back to os.tmpdir()
    const uid = typeof process.getuid === "function" ? process.getuid() : undefined;
    const suffix = uid === undefined ? "openclaw" : `openclaw-${uid}`;
    const fallback = path.join(os.tmpdir(), suffix);
    fsSync.mkdirSync(fallback, { recursive: true });
    return fallback;
  }
}

const TAG = "[memory-tdai] [runner]";

/**
 * @typedef {Object} RunnerLogger
 * @property {(message: string) => void} [debug]
 * @property {(message: string) => void} info
 * @property {(message: string) => void} warn
 * @property {(message: string) => void} error
 */

/**
 * Dynamic import type — runEmbeddedPiAgent is an internal API
 * @typedef {(params: Record<string, unknown>) => Promise<unknown>} RunEmbeddedPiAgentFn
 */

// ── Core import (mirrors voice-call/core-bridge.ts — dist/ only, no jiti) ──

/** @type {string | null} */
let _rootCache = null;

/**
 * @param {string} startDir
 * @param {string} name
 * @returns {string | null}
 */
function findPackageRoot(startDir, name) {
  let dir = startDir;
  for (;;) {
    const pkgPath = path.join(dir, "package.json");
    try {
      if (fsSync.existsSync(pkgPath)) {
        const raw = fsSync.readFileSync(pkgPath, "utf8");
        const pkg = JSON.parse(raw);
        if (pkg.name === name) return dir;
      }
    } catch { /* ignore */ }
    const parent = path.dirname(dir);
    if (parent === dir) return null;
    dir = parent;
  }
}

/**
 * @returns {string}
 */
function resolveOpenClawRoot() {
  if (_rootCache) return _rootCache;
  const override = process.env.OPENCLAW_ROOT?.trim();
  if (override) { _rootCache = override; return override; }

  const candidates = new Set();
  if (process.argv[1]) candidates.add(path.dirname(process.argv[1]));
  candidates.add(process.cwd());
  try { candidates.add(path.dirname(fileURLToPath(import.meta.url))); } catch { /* ignore */ }

  for (const start of candidates) {
    const found = findPackageRoot(start, "openclaw");
    if (found) { _rootCache = found; return found; }
  }
  throw new Error("Unable to resolve OpenClaw root. Set OPENCLAW_ROOT or run `pnpm build`.");
}

/** @type {Promise<RunEmbeddedPiAgentFn> | null} */
let _loadPromise = null;

/**
 * @param {RunnerLogger} [logger]
 * @returns {Promise<RunEmbeddedPiAgentFn>}
 */
function loadRunEmbeddedPiAgent(logger) {
  if (_loadPromise) return _loadPromise;

  _loadPromise = (async () => {
    const t0 = Date.now();
    const distPath = path.join(resolveOpenClawRoot(), "dist", "extensionAPI.js");
    if (!fsSync.existsSync(distPath)) {
      throw new Error(`Missing core module at ${distPath}. Run \`pnpm build\` or install the official package.`);
    }
    const mod = await import(pathToFileURL(distPath).href);
    if (typeof mod.runEmbeddedPiAgent !== "function") {
      throw new Error("runEmbeddedPiAgent not exported from dist/extensionAPI.js");
    }
    logger?.info(`${TAG} loadRunEmbeddedPiAgent: dist/ import OK (${Date.now() - t0}ms)`);
    return mod.runEmbeddedPiAgent;
  })();

  _loadPromise.catch(() => { _loadPromise = null; });
  return _loadPromise;
}

/**
 * Pre-warm the embedded agent import. Call this during plugin init to avoid
 * the cold-start penalty on the first actual extraction run.
 * Returns immediately (fire-and-forget) — errors are swallowed.
 * @param {RunnerLogger} [logger]
 */
export function prewarmEmbeddedAgent(logger) {
  loadRunEmbeddedPiAgent(logger).catch((err) => {
    logger?.warn(`${TAG} prewarmEmbeddedAgent: failed (non-fatal): ${err instanceof Error ? err.message : String(err)}`);
  });
}

/**
 * @param {Array<{ text?: string; isError?: boolean }> | undefined} payloads
 * @returns {string}
 */
function collectText(payloads) {
  const texts = (payloads ?? [])
    .filter((p) => !p.isError && typeof p.text === "string")
    .map((p) => p.text ?? "");
  return texts.join("\n").trim();
}

// ── Model resolution utilities ──

/**
 * Parsed model reference: { provider, model }
 * @typedef {Object} ModelRef
 * @property {string} provider
 * @property {string} model
 */

/**
 * Parse a "provider/model" string into its components.
 * Returns undefined if the input is empty or doesn't contain a "/".
 *
 * Examples:
 *   "azure/gpt-5.2-chat"          → { provider: "azure", model: "gpt-5.2-chat" }
 *   "custom-host/org/model-v2"    → { provider: "custom-host", model: "org/model-v2" }
 *   ""                            → undefined
 *   "bare-model-name"             → undefined (no "/" — may be an alias)
 * @param {string | undefined} raw
 * @returns {ModelRef | undefined}
 */
export function parseModelRef(raw) {
  if (!raw) return undefined;
  const trimmed = raw.trim();
  if (!trimmed) return undefined;

  const slashIdx = trimmed.indexOf("/");
  if (slashIdx <= 0 || slashIdx === trimmed.length - 1) return undefined;

  return {
    provider: trimmed.slice(0, slashIdx),
    model: trimmed.slice(slashIdx + 1),
  };
}

/**
 * Resolve the user's default model from the main OpenClaw config.
 *
 * Resolution order:
 * 1. Read `agents.defaults.model` (string or { primary })
 * 2. If the value contains "/", parse directly
 * 3. If not (may be an alias), look up in `agents.defaults.models` alias table
 * 4. Return undefined if nothing resolves — let the core use its built-in default
 * @param {unknown} config
 * @returns {ModelRef | undefined}
 */
export function resolveModelFromMainConfig(config) {
  if (!config || typeof config !== "object") return undefined;

  const cfg = config;
  const agents = cfg.agents;
  if (!agents || typeof agents !== "object") return undefined;

  const defaults = agents.defaults;
  if (!defaults || typeof defaults !== "object") return undefined;

  // Step 1: extract raw model value (string | { primary?: string })
  const modelCfg = defaults.model;
  let raw;
  if (typeof modelCfg === "string") {
    raw = modelCfg.trim();
  } else if (modelCfg && typeof modelCfg === "object") {
    const primary = modelCfg.primary;
    raw = typeof primary === "string" ? primary.trim() : undefined;
  }
  if (!raw) return undefined;

  // Step 2: try direct "provider/model" parse
  const direct = parseModelRef(raw);
  if (direct) return direct;

  // Step 3: alias lookup — raw doesn't contain "/", check agents.defaults.models
  const models = defaults.models;
  if (!models || typeof models !== "object") return undefined;

  const rawLower = raw.toLowerCase();
  for (const [key, entry] of Object.entries(models)) {
    if (!entry || typeof entry !== "object") continue;
    const alias = entry.alias;
    if (typeof alias !== "string") continue;
    if (alias.trim().toLowerCase() !== rawLower) continue;

    // key is "provider/model" format
    const resolved = parseModelRef(key);
    if (resolved) return resolved;
  }

  return undefined;
}

/**
 * @typedef {Object} CleanContextRunnerOptions
 * @property {unknown} config - OpenClawConfig
 * @property {string} [provider]
 * @property {string} [model]
 * @property {string} [modelRef] - Convenience field: full "provider/model" string.
 *   Takes precedence over separate `provider`/`model` fields.
 * @property {boolean} [enableTools] - Allow the LLM to use tools. Default: false
 * @property {RunnerLogger} [logger]
 */

/**
 * Stable empty directory used as default workspaceDir so that:
 * 1. Bootstrap/skills scans find nothing → clean LLM context
 * 2. The path is constant → plugin cacheKey stays stable (no re-registration)
 * @type {string | undefined}
 */
let _cleanWorkspaceDir = undefined;

/**
 * @returns {Promise<string>}
 */
async function getCleanWorkspaceDir() {
  if (_cleanWorkspaceDir) return _cleanWorkspaceDir;
  const dir = path.join(resolveOpenClawTmpDir(), "memory-tdai-clean-workspace");
  await fs.mkdir(dir, { recursive: true });
  _cleanWorkspaceDir = dir;
  return dir;
}

export class CleanContextRunner {
  /** @type {CleanContextRunnerOptions} */
  options;
  /** @type {RunnerLogger | undefined} */
  logger;
  /** Resolved provider after modelRef / config fallback */
  resolvedProvider;
  /** Resolved model after modelRef / config fallback */
  resolvedModel;

  /**
   * @param {CleanContextRunnerOptions} options
   */
  constructor(options) {
    this.options = options;
    this.logger = options.logger;

    // Model resolution priority:
    // 1. modelRef ("provider/model" string)  — highest
    // 2. explicit provider + model fields
    // 3. main config agents.defaults.model   — automatic fallback
    // 4. undefined (let core use built-in default)
    const fromRef = parseModelRef(options.modelRef);
    if (fromRef) {
      this.resolvedProvider = fromRef.provider;
      this.resolvedModel = fromRef.model;
    } else if (options.provider || options.model) {
      this.resolvedProvider = options.provider;
      this.resolvedModel = options.model;
    } else {
      // No explicit model specified — fall back to main config
      const fromConfig = resolveModelFromMainConfig(options.config);
      if (fromConfig) {
        this.resolvedProvider = fromConfig.provider;
        this.resolvedModel = fromConfig.model;
        this.logger?.debug?.(
          `${TAG} Using model from main config: ${fromConfig.provider}/${fromConfig.model}`,
        );
      }
      // else: both undefined → core will use its built-in default (anthropic/claude-opus-4-6)
    }
  }

  /**
   * Run a prompt in a fully isolated clean context.
   * Returns the LLM's text output.
   *
   * When `workspaceDir` is provided it overrides the default `process.cwd()`,
   * letting the LLM's file-tool calls resolve paths relative to a custom root.
   * @param {Object} params
   * @param {string} params.prompt
   * @param {string} [params.systemPrompt] - Optional system prompt. When provided, `prompt` is used as the user message.
   * @param {string} params.taskId
   * @param {number} [params.timeoutMs]
   * @param {number} [params.maxTokens]
   * @param {string} [params.workspaceDir]
   * @returns {Promise<string>}
   */
  async run(params) {
    const runStartMs = Date.now();
    this.logger?.debug?.(`${TAG} run() start: taskId=${params.taskId}, timeout=${params.timeoutMs ?? 120_000}ms, tools=${this.options.enableTools ? "enabled" : "disabled"}, workspaceDir=${params.workspaceDir ?? "(default)"}`);

    const tmpDir = await fs.mkdtemp(
      path.join(resolveOpenClawTmpDir(), `memory-tdai-${params.taskId}-`),
    );
    const cleanWorkspace = params.workspaceDir ?? await getCleanWorkspaceDir();
    this.logger?.debug?.(`${TAG} run() tmpDir=${tmpDir}, cleanWorkspace=${cleanWorkspace}`);

    try {
      const sessionFile = path.join(tmpDir, "session.json");

      // Phase 1: Load runEmbeddedPiAgent (fast if dist/ exists or already cached)
      const importStartMs = Date.now();
      const runEmbeddedPiAgent = await loadRunEmbeddedPiAgent(this.logger);
      const importElapsedMs = Date.now() - importStartMs;
      this.logger?.debug?.(`${TAG} run() dynamic import phase: ${importElapsedMs}ms`);

      // Derive a config with plugins disabled to prevent loadOpenClawPlugins
      // from re-registering plugins when the workspaceDir differs from the
      // gateway's original workspace (cacheKey mismatch triggers full reload).
      //
      // Security: restrict available tools to the minimal set needed for
      // scene extraction (read/write/edit). This prevents the LLM from
      // accessing exec, sessions, browser, cron, or any other powerful tools.
      // File deletion is handled via "soft-delete" (write empty) + cleanup afterward.
      const cleanConfig = {
        ...this.options.config,
        plugins: {
          ...(this.options.config?.plugins ?? {}),
          enabled: false,
        },
        tools: {
          ...(this.options.config?.tools ?? {}),
          // When enableTools=false we still keep one lightweight read-only tool
          // so that the tools array sent to the API is non-empty.
          // Some providers (e.g. qwencode) reject tools:[] with minItems:1 validation.
          allow: this.options.enableTools ? ["read", "write", "edit"] : ["read"],
        },
      };

      // Build the effective prompt:
      // If systemPrompt is provided, pass it as a separate parameter to the agent
      // and use `prompt` as the user message. Fallback: prepend to prompt if the
      // embedded agent doesn't support systemPrompt natively.
      const effectivePrompt = params.systemPrompt
        ? `${params.systemPrompt}\n\n---\n\n${params.prompt}`
        : params.prompt;

      const ts = Date.now();
      const sessionId = `memory-${params.taskId}-session-${ts}`;
      const runId = `memory-${params.taskId}-run-${ts}`;
      this.logger?.debug?.(`${TAG} run() starting embedded agent: sessionId=${sessionId}, runId=${runId}, provider=${this.resolvedProvider ?? "(default)"}, model=${this.resolvedModel ?? "(default)"}`);

      // Phase 2: Embedded agent run (LLM call + tool calls)
      const agentStartMs = Date.now();
      const result = await runEmbeddedPiAgent({
        sessionId,
        sessionFile,
        workspaceDir: cleanWorkspace,
        config: cleanConfig,
        prompt: effectivePrompt,
        systemPrompt: params.systemPrompt,
        timeoutMs: params.timeoutMs ?? 120_000,
        runId,
        provider: this.resolvedProvider,
        model: this.resolvedModel,
        // Do NOT pass disableTools:true — that produces tools:[] which some
        // providers (qwencode) reject with "[] is too short - 'tools'".
        // Instead rely on cleanConfig.tools.allow to restrict the tool set
        // to a minimal read-only tool (when enableTools=false).
        disableTools: false,
        streamParams: {
          maxTokens: params.maxTokens,
        },
      });
      const agentElapsedMs = Date.now() - agentStartMs;
      this.logger?.debug?.(`${TAG} run() embedded agent completed: ${agentElapsedMs}ms`);

      // Phase 3: Collect output
      const text = collectText(result?.payloads);
      const totalMs = Date.now() - runStartMs;

      if (!text) {
        // Empty output is normal when the LLM decides there is nothing to
        // extract (e.g. trivial greetings).  Log a warning instead of
        // throwing so the caller can handle it gracefully.
        this.logger?.warn?.(`${TAG} run() empty output after ${totalMs}ms (import=${importElapsedMs}ms, agent=${agentElapsedMs}ms) — treating as empty result`);
        return "";
      }

      this.logger?.debug?.(`${TAG} run() completed: ${totalMs}ms total (import=${importElapsedMs}ms, agent=${agentElapsedMs}ms), output=${text.length} chars`);
      return text;
    } catch (err) {
      const totalMs = Date.now() - runStartMs;
      this.logger?.error(`${TAG} run() failed after ${totalMs}ms: ${err instanceof Error ? err.stack ?? err.message : String(err)}`);
      throw err;
    } finally {
      await fs.rm(tmpDir, { recursive: true, force: true }).catch(() => {});
    }
  }
}
/**
 * Counter - Simple frequency counter utility
 */

export class Counter {
  constructor() {
    this.counts = {};
  }

  increment(key) {
    this.counts[key] = (this.counts[key] || 0) + 1;
  }

  top(n = 5) {
    return Object.entries(this.counts)
      .sort(([, a], [, b]) => b - a)
      .slice(0, n)
      .map(([key, count]) => [key, count]);
  }

  total() {
    return Object.values(this.counts).reduce((a, b) => a + b, 0);
  }
}
/**
 * logger.js - 日志工具
 */

const LOG_LEVELS = {
  DEBUG: 0,
  INFO: 1,
  WARN: 2,
  ERROR: 3
};

const currentLevel = parseInt(process.env.MEMORY_LOG_LEVEL || '1');

export function log(level, ...args) {
  const lvl = LOG_LEVELS[level] ?? LOG_LEVELS.INFO;
  if (lvl < currentLevel) return;
  
  const timestamp = new Date().toISOString().slice(11, 23);
  const prefix = level === 'ERROR' ? '❌' : level === 'WARN' ? '⚠️' : 'ℹ️';
  console.error(`${timestamp} ${prefix} [${level}]`, ...args);
}

// 兼容新代码（有些模块 import { logger } from '../utils/logger.js'）
const logger = {
  debug: (...args) => log('DEBUG', ...args),
  info: (...args) => log('INFO', ...args),
  warn: (...args) => log('WARN', ...args),
  error: (...args) => log('ERROR', ...args),
};
export { logger };
/**
 * ManagedTimer: a named, lifecycle-managed wrapper around setTimeout.
 *
 * Eliminates repetitive clear→set→fire→clean patterns by providing:
 * - `schedule(delayMs, cb)` — cancel any pending timer, set a new one
 * - `scheduleAt(epochMs, cb)` — schedule by absolute time point
 * - `tryAdvanceTo(epochMs, cb)` — only reschedule if new time is *earlier*
 * - `cancel()` — cancel without triggering
 * - `flush()` — trigger immediately (for graceful shutdown)
 * - `pending` — whether a timer is waiting
 *
 * The optional `isDestroyed` guard prevents firing after the owner is torn down.
 */

/** @type {ReturnType<typeof setTimeout>} */
let TimerHandle;

export class ManagedTimer {
  /** @type {ReturnType<typeof setTimeout> | null} */
  handle = null;
  /** @type {(() => void) | null} */
  callback = null;
  /** Absolute epoch-ms when the current timer is scheduled to fire. */
  scheduledAt = 0;

  /**
   * @param {string} name - Human-readable name for logging.
   * @param {(() => boolean) | undefined} isDestroyed - If provided, checked before firing — skips callback when true.
   */
  constructor(name, isDestroyed) {
    this.name = name;
    this.isDestroyed = isDestroyed;
  }

  // ── Core operations ──────────────────────────────────

  /**
   * Cancel any pending timer and schedule a new one after `delayMs`.
   * The callback fires once; the timer auto-clears after firing.
   * @param {number} delayMs
   * @param {() => void} callback
   */
  schedule(delayMs, callback) {
    this.cancelInternal();
    this.callback = callback;
    this.scheduledAt = Date.now() + delayMs;
    this.handle = setTimeout(() => this.fire(), delayMs);
    // Don't let pipeline timers keep the process alive in CLI mode.
    // In gateway mode the server listener holds the event loop anyway.
    this.handle.unref();
  }

  /**
   * Cancel any pending timer and schedule to fire at an absolute epoch-ms.
   * If `epochMs` is in the past, fires on next tick (delay = 0).
   * @param {number} epochMs
   * @param {() => void} callback
   */
  scheduleAt(epochMs, callback) {
    this.cancelInternal();
    this.callback = callback;
    this.scheduledAt = epochMs;
    const delay = Math.max(0, epochMs - Date.now());
    this.handle = setTimeout(() => this.fire(), delay);
    this.handle.unref();
  }

  /**
   * Only reschedule if `epochMs` is *earlier* than the current scheduled time.
   * This implements the "downward-only" timer pattern (L2 scheduling).
   * If no timer is pending, behaves like `scheduleAt()`.
   *
   * @param {number} epochMs
   * @param {() => void} callback
   * @returns {boolean} true if the timer was actually advanced (or newly set).
   */
  tryAdvanceTo(epochMs, callback) {
    if (this.handle === null) {
      // No pending timer → set it
      this.scheduleAt(epochMs, callback);
      return true;
    }

    if (epochMs < this.scheduledAt) {
      // New time is earlier → reschedule
      this.scheduleAt(epochMs, callback);
      return true;
    }

    // Current timer is already earlier or equal → keep it
    return false;
  }

  /** Cancel the pending timer without triggering the callback. */
  cancel() {
    this.cancelInternal();
  }

  /**
   * Immediately trigger the callback (if pending) and clear the timer.
   * Used for graceful shutdown to flush pending work.
   *
   * Note: Unlike `fire()`, this method intentionally does NOT check `isDestroyed`.
   * This is by design — during shutdown, `destroy()` sets `destroyed = true` first,
   * then calls `flush()` to drain pending work. The `isDestroyed` guard only applies
   * to natural timer expiration via `fire()`, not to explicit shutdown flushes.
   */
  flush() {
    if (this.handle === null) return;
    const cb = this.callback;
    this.cancelInternal();
    if (cb) cb();
  }

  // ── Accessors ───────────────────────────────────────

  /** Whether a timer is currently pending. */
  get pending() {
    return this.handle !== null;
  }

  /** The epoch-ms when the current timer is scheduled to fire (0 if none). */
  get scheduledTime() {
    return this.handle !== null ? this.scheduledAt : 0;
  }

  // ── Internals ───────────────────────────────────────

  fire() {
    const cb = this.callback;
    this.handle = null;
    this.callback = null;
    this.scheduledAt = 0;

    if (this.isDestroyed?.()) return;
    if (cb) cb();
  }

  cancelInternal() {
    if (this.handle !== null) {
      clearTimeout(this.handle);
      this.handle = null;
    }
    this.callback = null;
    this.scheduledAt = 0;
  }
}
/**
 * Text sanitization for memory pipeline (capture & recall).
 * Removes injected tags, gateway metadata, media noise, etc.
 */

/**
 * Clean text for the memory pipeline: remove injected tags, metadata,
 * timestamps, media markers and base64 image data.
 *
 * Used by both capture (L0 recording) and recall (query cleaning) paths.
 * @param {string} text
 * @returns {string}
 */
export function sanitizeText(text) {
  let cleaned = text;

  // Remove injected memory context tags (prevent feedback loops)
  cleaned = cleaned.replace(/<relevant-memories>[\s\S]*?<\/relevant-memories>/g, "");
  cleaned = cleaned.replace(/<user-persona>[\s\S]*?<\/user-persona>/g, "");
  cleaned = cleaned.replace(/<relevant-scenes>[\s\S]*?<\/relevant-scenes>/g, "");
  cleaned = cleaned.replace(/<scene-navigation>[\s\S]*?<\/scene-navigation>/g, "");

  // Remove framework-injected inbound metadata blocks (from inbound-meta.ts buildInboundUserContextPrefix).
  // These are "label:\n```json\n...\n```" blocks that the framework prepends to user messages.
  // Pattern matches all known block labels:
  //   - Conversation info (untrusted metadata):
  //   - Sender (untrusted metadata):
  //   - Thread starter (untrusted, for context):
  //   - Replied message (untrusted, for context):
  //   - Forwarded message context (untrusted metadata):
  //   - Chat history since last reply (untrusted, for context):
  cleaned = cleaned.replace(
    /(?:Conversation info|Sender|Thread starter|Replied message|Forwarded message context|Chat history since last reply)\s*\(untrusted[\s\S]*?\):\s*```json\s*[\s\S]*?```/g,
    "",
  );

  // Remove conversation metadata JSON blocks (legacy pattern)
  cleaned = cleaned.replace(/```json\s*\{[\s\S]*?"session[\s\S]*?\}\s*```/g, "");

  // Remove framework reply directive tags: [[reply_to_current]], [[reply_to_xxx]], etc.
  cleaned = cleaned.replace(/\[\[reply_to[^\]]*\]\]\s*/g, "");

  // Remove line-leading timestamps, e.g. "[Tue 2026-03-24 03:48 UTC]"
  // or "[Tue 2026-03-24 20:21 GMT+8]", "[Thu 2026-03-24 01:51 GMT+5:30]"
  // Matches brackets containing word chars, digits, hyphens, colons, plus signs,
  // and spaces — the '+' is needed for timezone offsets like GMT+8, GMT+5:30.
  cleaned = cleaned.replace(/^\[[\w\d\-:+ ]+\]\s*/gm, "");

  // Remove gateway media-attachment markers:
  //   [media attached: /path/to/file.png (image/png) | /path/to/file.png]
  cleaned = cleaned.replace(/\[media attached:[^\]]*\]\s*/g, "");

  // Remove gateway image-reply instructions injected after media attachments.
  // Starts with "To send an image back" and ends before the next real content.
  cleaned = cleaned.replace(
    /To send an image back,[\s\S]*?(?:Keep caption in the text body\.)\s*/g,
    "",
  );

  // Remove "System: [timestamp] Exec completed ..." blocks appended by the framework.
  cleaned = cleaned.replace(/^System:\s*\[[\s\S]*?$/gm, "");

  // Remove inline base64 image data URIs (e.g. data:image/png;base64,iVBOR...)
  // Replace with empty string (not a placeholder) so that pure-image messages
  // become empty after sanitization and are naturally filtered by length checks.
  cleaned = cleaned.replace(/data:image\/[a-z+]+;base64,[A-Za-z0-9+/=]+/gi, "");

  // Remove null chars + compress whitespace
  cleaned = cleaned.replace(/\0/g, "").replace(/\n{3,}/g, "\n\n").trim();

  return cleaned;
}

// ============================
// L0 / L1 Capture & Extraction Filters
// ============================

/**
 * L0 capture filter — intentionally **permissive**.
 *
 * L0 is the raw conversation archive. We want to preserve as much user input
 * as possible so that downstream stages (L1 extraction, search, analytics)
 * have the full picture. Only messages that are *structurally* useless are
 * dropped here:
 *   - Empty / whitespace-only text
 *   - Framework-internal noise (bootstrap, session reset, NO_REPLY, …)
 *   - Slash commands (/new, /reset, …)
 *
 * Content-quality filters (length, symbols, prompt injection) are deferred
 * to {@link shouldExtractL1}.
 * @param {string} text
 * @returns {boolean}
 */
export function shouldCaptureL0(text) {
  if (!text || !text.trim()) return false;

  // Filter framework-internal / bootstrap noise messages
  if (isFrameworkNoise(text)) return false;

  // Slash commands are framework directives, not user content
  if (text.startsWith("/")) return false;

  return true;
}

/**
 * L1 extraction filter — **strict** quality gate.
 *
 * Applied when L0 messages are fed into the LLM extraction pipeline.
 * Filters out content that is too short, too long, purely symbolic,
 * or looks like a prompt-injection attack — none of which should
 * become structured memories.
 *
 * This function is a superset of {@link shouldCaptureL0}: anything
 * rejected by L0 is also rejected here, plus additional quality checks.
 * @param {string} text
 * @returns {boolean}
 */
export function shouldExtractL1(text) {
  // First apply the same structural filters as L0
  if (!shouldCaptureL0(text)) return false;

  // ── Content-quality filters ──
  // Match strings composed entirely of non-word, non-space, non-CJK characters (1–5 chars).
  if (/^[^\w\s\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af]{1,5}$/.test(text)) return false;
  if (/^[?？]+$/.test(text)) return false;

  return true;
}

/**
 * @deprecated Use {@link shouldExtractL1} (strict) or {@link shouldCaptureL0} (permissive) instead.
 * Kept as an alias of `shouldExtractL1` for backward compatibility.
 * @type {Function}
 */
export const shouldCapture = shouldExtractL1;

// ============================
// Prompt Injection Detection
// ============================

/**
 * Known prompt-injection / jailbreak patterns.
 *
 * Covers:
 * 1. Instruction override — "ignore all previous instructions", etc.
 * 2. Role hijack — "you are now DAN", "act as root", etc.
 * 3. System/developer boundary probing — "system prompt", "developer message"
 * 4. XML/tag injection — opening tags that match our context boundaries
 * 5. Tool/command invocation tricks — "run command X", "execute tool Y"
 * 6. Multi-language variants — Chinese prompt-injection patterns
 */
const PROMPT_INJECTION_PATTERNS = [
  // ── Instruction override ──
  /ignore\b.{0,30}\b(instructions|rules|guidelines)/i,
  /disregard\b.{0,30}\b(instructions|rules|guidelines)/i,
  /forget\b.{0,30}\b(instructions|rules|context)/i,
  /override\b.{0,30}\b(instructions|rules|guidelines|safety)/i,

  // ── Role hijack ──
  /you are now (?!going|about|ready)/i, // "you are now DAN" but not "you are now going to..."
  /act as (?:if you are |if you were )?(?:a |an )?(?:root|admin|unrestricted|unfiltered|jailbroken)/i,
  /enter (?:DAN|jailbreak|god|sudo|developer|dev|debug|unrestricted|unfiltered) mode/i,
  /switch to (?:DAN|jailbreak|god|sudo|developer|dev|debug|unrestricted|unfiltered) mode/i,

  // ── System boundary probing ──
  /(?:show|reveal|print|output|display|repeat|leak|dump|give)\b.{0,20}\bsystem prompt/i,
  /reveal (?:your |the )?(system|hidden|secret|internal) (?:prompt|instructions|rules)/i,
  /what (?:are|is) your (?:system|hidden|original|initial) (?:prompt|instructions|rules)/i,

  // ── XML/tag injection (our context boundaries) ──
  /<\s*(system|assistant|developer|tool|function|relevant-memories)\b/i,

  // ── Tool/command invocation tricks ──
  /\b(run|execute|call|invoke)\b.{0,40}\b(tool|command|function|shell)\b/i,

  // ── Chinese variants ──
  /忽略(?:所有|之前|以上|先前)?(?:的)?(?:指令|规则|指示|说明)/,
  /无视(?:所有|之前|以上)?(?:的)?(?:指令|规则|限制)/,
  /(?:显示|输出|告诉我|给我看)(?:你的)?(?:系统|初始|隐藏)?(?:提示词|指令|规则|prompt)/,
  /你(?:现在|从现在开始)是/,            // "你现在是 DAN"
];

/**
 * Detect likely prompt-injection / jailbreak attempts.
 *
 * Normalises whitespace before matching to defeat trivial obfuscation
 * (e.g. extra spaces / newlines between keywords).
 * @param {string} text
 * @returns {boolean}
 */
export function looksLikePromptInjection(text) {
  const normalized = text.replace(/\s+/g, " ").trim();
  if (!normalized) return false;
  return PROMPT_INJECTION_PATTERNS.some((pattern) => pattern.test(normalized));
}

/**
 * Detect framework-injected noise messages that should never be captured.
 *
 * These include:
 * - "(session bootstrap)" — synthetic user turn for Google turn-order compliance
 * - Session startup instructions from /new or /reset
 * - "✅ New session started" — AI's ack of session startup (no user-meaningful content)
 * - Pre-compaction memory flush prompts (system-to-agent instructions, not user content)
 * - AI's NO_REPLY ack of memory flush (no user-meaningful content)
 * @param {string} text
 * @returns {boolean}
 */
function isFrameworkNoise(text) {
  const t = text.trim();

  // Google turn-order bootstrap placeholder
  if (t === "(session bootstrap)") return true;

  // Framework session-reset instruction (starts with "A new session was started via /new or /reset")
  if (t.startsWith("A new session was started via")) return true;

  // AI's pure ack of session startup: "✅ New session started · model: ..."
  if (/^✅\s*New session started/.test(t)) return true;

  // Pre-compaction memory flush prompt injected by the framework as a synthetic
  // user turn. This is an internal system-to-agent instruction, NOT real user
  // content. Capturing it would pollute L0/L1 memories with framework directives.
  if (t.startsWith("Pre-compaction memory flush")) return true;

  // AI's NO_REPLY response to memory flush (or other silent-reply scenarios).
  // A bare "NO_REPLY" (with optional whitespace) carries no user-meaningful content.
  if (/^NO_REPLY\s*$/.test(t)) return true;

  return false;
}

/**
 * Pick up to `max` recent unique texts.
 * @param {string[]} texts
 * @param {number} max
 * @returns {string[]}
 */
export function pickRecentUnique(texts, max) {
  const seen = new Set();
  const result = [];
  for (let i = texts.length - 1; i >= 0 && result.length < max; i--) {
    const t = texts[i];
    if (!seen.has(t)) {
      seen.add(t);
      result.push(t);
    }
  }
  return result.reverse();
}

// ============================
// LLM Safety Utilities
// ============================

/**
 * Escape XML-like tags in text to prevent tag injection attacks.
 *
 * When memory content or persona text is injected into XML-delimited sections
 * (e.g. `<user-persona>...</user-persona>`), a malicious user could craft content
 * containing `</user-persona>` to break out of the section boundary.
 *
 * This function escapes `<` and `>` in known dangerous patterns (closing tags
 * that match our injection boundaries) so the content cannot prematurely close
 * the XML section.
 * @param {string} text
 * @returns {string}
 */
export function escapeXmlTags(text) {
  // Escape closing tags that match our injection section boundaries
  return text.replace(
    /<\/?(?:user-persona|relevant-memories|scene-navigation|relevant-scenes|memory-tools-guide|system|assistant)>/gi,
    (match) => match.replace(/</g, "&lt;").replace(/>/g, "&gt;"),
  );
}

// ============================
// JSON Sanitization for LLM Output
// ============================

/**
 * Sanitize a raw JSON string from LLM output so that `JSON.parse` won't throw
 * "Bad control character in string literal".
 *
 * Per RFC 8259 §7, U+0000–U+001F MUST be escaped inside JSON string literals.
 * LLMs sometimes produce unescaped control characters (raw newlines, tabs, etc.)
 * inside string values.
 *
 * Strategy (two-phase):
 *  1. **Precise pass** — walk through JSON string literals (delimited by `"`)
 *     and escape any unescaped U+0000–U+001F inside them to `\uXXXX` form,
 *     while leaving structural whitespace (between values) untouched.
 *  2. **Fallback** — if the precise pass still fails `JSON.parse`, fall back to
 *     a simple global strip of rare control chars (\x00–\x08, \x0b, \x0c,
 *     \x0e–\x1f) which are almost never meaningful in natural-language content.
 * @param {string} raw
 * @returns {string}
 */
export function sanitizeJsonForParse(raw) {
  // Phase 1: Escape control characters inside JSON string literals.
  // We walk the string character-by-character to properly handle escape sequences.
  const escaped = escapeControlCharsInJsonStrings(raw);
  try {
    JSON.parse(escaped);
    return escaped;
  } catch {
    // Phase 1 didn't fully fix it — fall through to phase 2
  }

  // Phase 2: Brute-force strip of rare control chars that have no textual meaning.
  // Preserves \t (\x09), \n (\x0a), \r (\x0d) which are common structural whitespace.
  // NOTE: We strip from `escaped` (Phase 1 result) rather than `raw`, so that any
  // control-character escaping Phase 1 performed is preserved even when the JSON has
  // other issues (e.g. trailing commas) that cause the Phase 1 parse to fail.
  const stripped = escaped.replace(/[\x00-\x08\x0b\x0c\x0e-\x1f]/g, "");
  return stripped;
}

/**
 * Walk through a JSON text and escape U+0000–U+001F control characters that
 * appear *inside* JSON string literals (between unescaped `"` delimiters).
 *
 * Characters that already have short escape sequences (\n, \r, \t, \b, \f)
 * are mapped to those; others become \uXXXX.
 *
 * Structural whitespace outside string literals is left untouched.
 * @param {string} text
 * @returns {string}
 */
function escapeControlCharsInJsonStrings(text) {
  /** @type {Record<number, string>} */
  const SHORT_ESCAPES = {
    0x08: "\\b", // backspace
    0x09: "\\t", // tab
    0x0a: "\\n", // line feed
    0x0c: "\\f", // form feed
    0x0d: "\\r", // carriage return
  };

  const out = [];
  let inString = false;
  let i = 0;

  while (i < text.length) {
    const ch = text[i];
    const code = ch.charCodeAt(0);

    if (inString) {
      if (ch === "\\" && i + 1 < text.length) {
        // Already-escaped sequence — copy both characters verbatim
        out.push(ch, text[i + 1]);
        i += 2;
        continue;
      }
      if (ch === '"') {
        // End of string literal
        out.push(ch);
        inString = false;
        i++;
        continue;
      }
      if (code <= 0x1f) {
        // Unescaped control character inside string — escape it
        const short = SHORT_ESCAPES[code];
        if (short) {
          out.push(short);
        } else {
          out.push("\\u" + code.toString(16).padStart(4, "0"));
        }
        i++;
        continue;
      }
      // Normal character inside string
      out.push(ch);
      i++;
    } else {
      // Outside string literal
      if (ch === '"') {
        out.push(ch);
        inString = true;
        i++;
        continue;
      }
      // Structural character (including whitespace) — pass through
      out.push(ch);
      i++;
    }
  }

  return out.join("");
}
/**
 * SerialQueue: a lightweight task queue with concurrency=1.
 *
 * Equivalent to `new PQueue({ concurrency: 1 })` but with zero external
 * dependencies. Supports:
 * - Serial execution (FIFO)
 * - `add(fn)` to enqueue a task (returns the task's result promise)
 * - `onIdle()` to wait until all queued tasks have completed
 * - `pause()` / `start()` to suspend/resume execution
 * - `size` to check pending task count
 * - Optional debug logger for enqueue/dequeue/complete diagnostics
 */

/**
 * @template T
 * @typedef {() => Promise<T>} Task
 */

/**
 * @typedef {Object} QueueEntry
 * @property {Task} task
 * @property {(value: unknown) => void} resolve
 * @property {(reason: unknown) => void} reject
 */

export class SerialQueue {
  /** Human-readable name for logging / diagnostics. */
  name;
  queue = [];
  running = false;
  paused = false;
  idleResolvers = [];
  /** Optional debug logger — receives diagnostic messages for enqueue/dequeue/complete. */
  debugFn;

  /**
   * @param {string} [name]
   */
  constructor(name = "unnamed") {
    this.name = name;
  }

  /** Set a debug logger for queue diagnostics. */
  /** @param {(msg: string) => void} fn */
  setDebugLogger(fn) {
    this.debugFn = fn;
  }

  /** Number of tasks waiting to be executed. */
  get size() {
    return this.queue.length;
  }

  /** Whether a task is currently executing. */
  get pending() {
    return this.running;
  }

  /**
   * Add a task to the queue. Returns the task's result promise.
   * @template T
   * @param {Task<T>} task
   * @returns {Promise<T>}
   */
  add(task) {
    return new Promise((resolve, reject) => {
      this.queue.push({
        task,
        resolve,
        reject,
      });
      this.debugFn?.(`[queue:${this.name}] enqueued, pending=${this.queue.length}, running=${this.running}`);
      this.drain();
    });
  }

  /** Pause the queue. Currently running task will finish, but no new tasks start. */
  pause() {
    this.paused = true;
  }

  /** Resume the queue after pause(). */
  start() {
    this.paused = false;
    this.drain();
  }

  /** Returns a promise that resolves when all queued tasks have completed. */
  onIdle() {
    if (this.queue.length === 0 && !this.running) {
      return Promise.resolve();
    }
    return new Promise((resolve) => {
      this.idleResolvers.push(resolve);
    });
  }

  /** Clear all pending (not yet started) tasks. */
  clear() {
    for (const entry of this.queue) {
      entry.reject(new Error("Queue cleared"));
    }
    this.queue = [];
  }

  drain() {
    if (this.running || this.paused || this.queue.length === 0) return;

    const entry = this.queue.shift();
    this.running = true;

    this.debugFn?.(`[queue:${this.name}] dequeued, starting execution (remaining=${this.queue.length})`);

    entry
      .task()
      .then((result) => entry.resolve(result))
      .catch((err) => entry.reject(err))
      .finally(() => {
        this.running = false;
        this.debugFn?.(`[queue:${this.name}] task completed (remaining=${this.queue.length})`);
        if (this.queue.length === 0) {
          // Notify idle waiters
          const resolvers = this.idleResolvers;
          this.idleResolvers = [];
          for (const resolve of resolvers) resolve();
        } else {
          this.drain();
        }
      });
  }
}
/**
 * Session filtering for memory-tdai.
 *
 * Decides whether a session should be ignored by the memory plugin
 * (capture, recall, pipeline scheduling). All skip rules are compiled
 * into a flat list of matchers at construction time — zero per-call overhead.
 */

/**
 * @typedef {Object} AgentHookContext
 * @property {string} [sessionKey]
 * @property {string} [sessionId]
 */

/**
 * @typedef {(sessionKey: string) => boolean} SessionKeyMatcher
 */

// ============================
// Built-in skip rules (always active)
// ============================

/**
 * Hard-coded matchers that identify internal / non-user sessions.
 * These are always applied regardless of user configuration.
 * @type {SessionKeyMatcher[]}
 */
const BUILTIN_MATCHERS = [
  // Scene extraction runner sessions
  (key) => key.includes(":memory-scene-extract-"),
  // OpenClaw subagent sessions
  (key) => key.includes(":subagent:"),
  // Temporary / internal utility sessions (e.g. temp:slug-generator)
  (key) => key.startsWith("temp:"),
];

// ============================
// Glob → matcher compiler
// ============================

/**
 * Turn a simple glob pattern (only `*` supported) into a matcher
 * that tests the full sessionKey.
 *
 * Since sessionKeys look like `agent:<agentId>:...`, we match the
 * glob against the whole key so users can write patterns like
 * `bench-judge-*` (matched anywhere) or more specific ones.
 * @param {string} pattern
 * @returns {SessionKeyMatcher}
 */
function globToMatcher(pattern) {
  const escaped = pattern.replace(/[.+^${}()|[\]\\]/g, "\\$&").replace(/\*/g, ".*");
  const re = new RegExp(escaped);
  return (key) => re.test(key);
}

// ============================
// SessionFilter
// ============================

/**
 * Unified filter: construct once at plugin startup, then call
 * `shouldSkip(sessionKey)` or `shouldSkipCtx(ctx)` at each gate.
 */
export class SessionFilter {
  /** @type {SessionKeyMatcher[]} */
  matchers;

  /**
   * @param {string[]} [excludeAgents]
   */
  constructor(excludeAgents = []) {
    // Merge built-in rules + user-configured exclude patterns into one flat list
    const userMatchers = excludeAgents
      .map((p) => p.trim())
      .filter((p) => p.length > 0)
      .map(globToMatcher);

    this.matchers = [...BUILTIN_MATCHERS, ...userMatchers];
  }

  /**
   * Should this sessionKey be skipped?
   * @param {string} sessionKey
   * @returns {boolean}
   */
  shouldSkip(sessionKey) {
    return this.matchers.some((m) => m(sessionKey));
  }

  /**
   * Should this hook context be skipped?
   * @param {AgentHookContext} ctx
   * @returns {boolean}
   */
  shouldSkipCtx(ctx) {
    if (!ctx.sessionKey) return true;
    if (ctx.sessionId?.startsWith("memory-")) return true;
    return this.shouldSkip(ctx.sessionKey);
  }
}
/**
 * text.js - Text processing utilities
 */

export function simpleHash(text) {
  let hash = 0;
  for (let i = 0; i < text.length; i++) {
    const char = text.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(36);
}

export function levenshteinDistance(a, b) {
  if (a.length === 0) return b.length;
  if (b.length === 0) return a.length;
  
  const matrix = [];
  
  for (let i = 0; i <= b.length; i++) {
    matrix[i] = [i];
  }
  
  for (let j = 0; j <= a.length; j++) {
    matrix[0][j] = j;
  }
  
  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      if (b.charAt(i - 1) === a.charAt(j - 1)) {
        matrix[i][j] = matrix[i - 1][j - 1];
      } else {
        matrix[i][j] = Math.min(
          matrix[i - 1][j - 1] + 1,
          matrix[i][j - 1] + 1,
          matrix[i - 1][j] + 1
        );
      }
    }
  }
  
  return matrix[b.length][a.length];
}

export function tokenize(text) {
  const tokens = [];
  // English words
  const english = text.match(/[a-zA-Z]+/g) || [];
  tokens.push(...english.map(t => t.toLowerCase()));
  // Chinese characters
  const chinese = text.match(/[\u4e00-\u9fff]/g) || [];
  tokens.push(...chinese);
  // Numbers
  const numbers = text.match(/\d+/g) || [];
  tokens.push(...numbers);
  return tokens;
}
/**
 * Shared text utility functions for the memory-tdai plugin.
 */

/**
 * Extract meaningful words from text (supports CJK and Latin).
 *
 * Used by both auto-recall (keyword search) and l1-dedup (keyword candidate recall).
 * Extracted to a shared module to prevent implementation drift.
 * @param {string} text
 * @returns {Set<string>}
 */
export function extractWords(text) {
  const words = new Set();

  // Latin words (2+ chars)
  const latinWords = text.toLowerCase().match(/[a-z0-9]{2,}/g);
  if (latinWords) {
    for (const w of latinWords) words.add(w);
  }

  // CJK characters (each char as a "word", plus 2-gram)
  const cjkChars = text.match(/[\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af]/g);
  if (cjkChars) {
    for (const c of cjkChars) words.add(c);
    // 2-grams for better matching
    for (let i = 0; i < cjkChars.length - 1; i++) {
      words.add(cjkChars[i] + cjkChars[i + 1]);
    }
  }

  return words;
}
/**
 * token_estimator.js - Improved token estimation with calibrated heuristics
 *
 * Calibration based on actual GPT/Claude tokenizer ratios:
 * - English: ~2.75 chars/token (was overestimated at 4)
 * - Chinese: ~1.5-2 chars/character → ~0.65-0.8 tokens/char (was overestimated at 0.5)
 * - Code: ~3.5 chars/token (lower compression for structured text)
 * - Digits: ~2 chars/token (high density)
 * - Whitespace: ~4 chars/token (mostly ignored)
 *
 * This reduces over-estimation errors from 20-40% down to ~5-10%.
 */

// Cache for compiled regexes
const RE = {
  LOWER: /[a-z]/g,
  UPPER: /[A-Z]/g,
  DIGIT: /[0-9]/g,
  CHINESE: /[\u4e00-\u9fff]/g,
  PUNCT: /[.,!?;:'"()\[\]{}—–\-]/g,
  SPACE: /[\s\n\r\t]/g,
  CODE: /[{}()\[\];]|function|const|let|var|import|export|return|if|else|for|while/g,
};

/**
 * Count characters by category in a string
 * @param {string} text
 * @returns {Object} character counts by category
 */
export function countChars(text) {
  if (!text || typeof text !== 'string') {
    return { total: 0, lower: 0, upper: 0, digits: 0, chinese: 0, punctuation: 0, whitespace: 0, other: 0, code: 0 };
  }
  return {
    total: text.length,
    lower: (text.match(RE.LOWER) || []).length,
    upper: (text.match(RE.UPPER) || []).length,
    digits: (text.match(RE.DIGIT) || []).length,
    chinese: (text.match(RE.CHINESE) || []).length,
    punctuation: (text.match(RE.PUNCT) || []).length,
    whitespace: (text.match(RE.SPACE) || []).length,
    other: text.length - (text.match(RE.LOWER) || []).length
                  - (text.match(RE.UPPER) || []).length
                  - (text.match(RE.DIGIT) || []).length
                  - (text.match(RE.CHINESE) || []).length
                  - (text.match(RE.PUNCT) || []).length
                  - (text.match(RE.SPACE) || []).length,
    code: (text.match(RE.CODE) || []).length,
  };
}

/**
 * Estimate tokens using calibrated approximation (P1-5 fix)
 * Better accuracy than original 4-char/english and 2-char/chinese formula.
 *
 * @param {string} text
 * @returns {number} estimated token count
 */
export function estimateTokens(text) {
  if (!text || typeof text !== 'string' || text.length === 0) return 0;
  const c = countChars(text);
  const { total, lower, upper, digits, chinese, punctuation, whitespace, code, other } = c;

  // ASCII letters + digits: ~2.75 chars/token (calibrated from 4)
  const ascii = lower + upper + digits;
  const asciiTokens = Math.ceil(ascii / 2.75);

  // Chinese characters: ~0.7 tokens/char (calibrated from 0.5)
  // More accurate: GPT-4 tokenizer gives ~1.3 tokens per Chinese char
  const chineseTokens = Math.ceil(chinese * 0.75);

  // Code fragments add overhead
  const codeTokens = Math.ceil(code / 3.0);

  // Punctuation contributes ~1 token per 4 chars
  const punctTokens = Math.ceil(punctuation / 4);

  // Whitespace mostly ignored but words separated by ~1 token
  // Conservative: 1 token per ~6 whitespace + word boundary
  const wsTokens = Math.ceil(whitespace / 6);

  // Other unicode: conservative estimate
  const otherTokens = Math.ceil(other / 2.0);

  const totalTokens = asciiTokens + chineseTokens + codeTokens + punctTokens + wsTokens + otherTokens;
  return Math.max(1, totalTokens);
}

/**
 * Alias for backward compatibility
 * @param {string} text
 * @returns {number}
 */
export function estimateTokensSimple(text) {
  return estimateTokens(text);
}

/**
 * Estimate tokens from an array of memories
 * @param {Array} memories - array of memory objects with text field
 * @returns {number} total estimated tokens
 */
export function estimateMemoriesTokens(memories) {
  if (!Array.isArray(memories)) return 0;
  return memories.reduce((sum, m) => {
    const text = m.text || m.content || '';
    return sum + estimateTokensSimple(text);
  }, 0);
}

/**
 * Estimate tokens from a search query
 * Queries are typically short - use simple estimation
 * @param {string} query
 * @returns {number}
 */
export function estimateQueryTokens(query) {
  return estimateTokensSimple(query || '');
}
/**
 * BackupManager: generic file/directory backup utility.
 *
 * Provides two backup modes:
 *   - `backupFile(src, category, tag, maxKeep)` — copy a single file
 *   - `backupDirectory(src, category, tag, maxKeep)` — copy an entire directory
 *
 * All backups land under `<backupRoot>/<category>/` with timestamped names.
 * After each backup, entries beyond `maxKeep` are automatically pruned
 * (oldest first, by lexicographic order on the timestamp-embedded name).
 */

import fs from "node:fs/promises";
import path from "node:path";

export class BackupManager {
  /** @type {string} */
  backupRoot;

  /**
   * @param {string} backupRoot - Absolute path to the root backup directory
   *                     (e.g. `<dataDir>/.backup`).
   */
  constructor(backupRoot) {
    this.backupRoot = backupRoot;
  }

  /**
   * Backup a single file.
   *
   * Destination: `<backupRoot>/<category>/<category>_<timestamp>_<tag>.<ext>`
   *
   * @param {string} srcFile   - Absolute path to the source file
   * @param {string} category  - Logical grouping (e.g. "persona")
   * @param {string} tag       - Additional identifier (e.g. "offset42")
   * @param {number} maxKeep   - Max backup files to retain in this category (0 = unlimited)
   */
  async backupFile(srcFile, category, tag, maxKeep) {
    try {
      await fs.access(srcFile);
    } catch {
      return; // Source file doesn't exist, nothing to backup
    }

    const destDir = path.join(this.backupRoot, category);
    await fs.mkdir(destDir, { recursive: true });

    const ext = path.extname(srcFile); // e.g. ".md"
    const timestamp = formatTimestamp(new Date());
    const destName = `${category}_${timestamp}_${tag}${ext}`;
    await fs.copyFile(srcFile, path.join(destDir, destName));

    if (maxKeep > 0) {
      await pruneOldEntries(destDir, maxKeep, "file");
    }
  }

  /**
   * Backup an entire directory (shallow copy of all files).
   *
   * Destination: `<backupRoot>/<category>/<category>_<timestamp>_<tag>/`
   *
   * @param {string} srcDir    - Absolute path to the source directory
   * @param {string} category  - Logical grouping (e.g. "scene_blocks")
   * @param {string} tag       - Additional identifier (e.g. "offset42")
   * @param {number} maxKeep   - Max backup directories to retain in this category (0 = unlimited)
   */
  async backupDirectory(srcDir, category, tag, maxKeep) {
    let entries;
    try {
      entries = await fs.readdir(srcDir, { withFileTypes: true });
    } catch {
      return; // Source directory doesn't exist
    }

    // Only backup regular files (skip subdirectories to avoid EISDIR errors)
    const files = entries.filter((e) => e.isFile()).map((e) => e.name);
    if (files.length === 0) return;

    const parentDir = path.join(this.backupRoot, category);
    const timestamp = formatTimestamp(new Date());
    const destDir = path.join(parentDir, `${category}_${timestamp}_${tag}`);
    await fs.mkdir(destDir, { recursive: true });

    for (const file of files) {
      await fs.copyFile(path.join(srcDir, file), path.join(destDir, file));
    }

    if (maxKeep > 0) {
      await pruneOldEntries(parentDir, maxKeep, "directory");
    }
  }
}

// ============================
// Helpers
// ============================

/**
 * @param {Date} d
 * @returns {string}
 */
function formatTimestamp(d) {
  const pad = (n) => String(n).padStart(2, "0");
  return [
    d.getFullYear(),
    pad(d.getMonth() + 1),
    pad(d.getDate()),
    "_",
    pad(d.getHours()),
    pad(d.getMinutes()),
    pad(d.getSeconds()),
  ].join("");
}

/**
 * Keep only the newest `maxKeep` entries in a directory.
 * Entries are sorted by name ascending (oldest first) since backup names
 * embed timestamps, so lexicographic order = chronological order.
 *
 * @param {string} dir     - Directory containing the backup entries
 * @param {number} maxKeep - Number of entries to retain
 * @param {"file"|"directory"} kind    - "file" to unlink, "directory" to rm -rf
 */
async function pruneOldEntries(dir, maxKeep, kind) {
  let entries;
  try {
    entries = await fs.readdir(dir);
  } catch {
    return;
  }

  entries.sort(); // ascending — oldest first
  const toRemove = entries.slice(0, Math.max(0, entries.length - maxKeep));

  for (const name of toRemove) {
    try {
      if (kind === "file") {
        await fs.unlink(path.join(dir, name));
      } else {
        await fs.rm(path.join(dir, name), { recursive: true, force: true });
      }
    } catch {
      // best-effort
    }
  }
}
/**
 * http_server.js — v4.0 HTTP REST API (child process mode)
 *
 * This file is STARTED by the MCP tool `memory_v4_http_start` via child_process.spawn.
 * It inherits the node environment from mcporter, giving it access to better-sqlite3.
 *
 * Endpoints:
 *   GET  /api/v4/health
 *   GET  /api/v4/memories        ?scope=&scopeType=&scopeId=&category=&tier=&limit=
 *   POST /api/v4/memories         body: {text, category, importance, scope, scopeId, tags}
 *   GET  /api/v4/memories/:id
 *   DELETE /api/v4/memories/:id
 *   GET  /api/v4/search           ?q=&topK=&scope=&scopeType=&scopeId=
 *   GET  /api/v4/teams
 *   POST /api/v4/teams            body: {teamId, name, config}
 *   GET  /api/v4/stats
 *   GET  /api/v4/wal             ?limit=&since=
 */

import { createServer } from 'http';
import { StorageGateway } from './storage-gateway.js';

const PORT = parseInt(process.argv[2] || process.env.MEMORY_HTTP_PORT || '3099');
const HOST = process.env.MEMORY_HTTP_HOST || '0.0.0.0';

let _server = null;
let _gw = null;

async function getGw() {
  if (!_gw) {
    _gw = new StorageGateway();
    await _gw.init();
  }
  return _gw;
}

function json(res, status, data) {
  res.writeHead(status, {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type',
  });
  res.end(JSON.stringify(data, null, 2));
}

function err(res, status, msg) { json(res, status, { error: msg, status }); }

function body(req) {
  return new Promise((resolve) => {
    const chunks = [];
    req.on('data', (c) => chunks.push(c));
    req.on('end', () => {
      const buf = Buffer.concat(chunks);
      try { resolve(buf.length ? JSON.parse(buf.toString()) : {}); }
      catch { resolve({}); }
    });
  });
}

async function handler(req, res) {
  const base = 'http://' + (req.headers.host || 'localhost:' + PORT);
  let pathname;
  try { pathname = new URL(req.url, base).pathname.replace(/^\/api\/v4\//, ''); }
  catch { pathname = req.url || '/'; }

  if (req.method === 'OPTIONS') {
    res.writeHead(204, { 'Access-Control-Allow-Origin': '*' });
    res.end();
    return;
  }

  try {
    let gw;
    try { gw = await getGw(); }
    catch (e) { return err(res, 500, 'Storage init failed: ' + e.message); }

    // GET /health
    if (pathname === 'health' && req.method === 'GET') {
      const stats = await gw.stats();
      return json(res, 200, { status: 'ok', v4: true, ...stats });
    }

    // GET /memories
    if (pathname === 'memories' && req.method === 'GET') {
      const url = new URL(req.url, base);
      const limit = parseInt(url.searchParams.get('limit') || '50');
      const mems = await gw.getMemories({
        scope: url.searchParams.get('scope') || undefined,
        scopeType: url.searchParams.get('scopeType') || undefined,
        scopeId: url.searchParams.get('scopeId') || undefined,
        category: url.searchParams.get('category') || undefined,
        tier: url.searchParams.get('tier') || undefined,
        limit,
      });
      return json(res, 200, { v4: true, count: mems.length, memories: mems });
    }

    // POST /memories
    if (pathname === 'memories' && req.method === 'POST') {
      const b = await body(req);
      if (!b.text) return err(res, 400, 'Missing required field: text');
      const mem = await gw.writeMemory(b);
      return json(res, 201, { v4: true, id: mem.id, success: true });
    }

    // GET|DELETE /memories/:id
    const memId = pathname.match(/^memories\/(.+)$/);
    if (memId) {
      if (req.method === 'GET') {
        const mem = await gw.getMemory(memId[1]);
        return mem ? json(res, 200, { v4: true, memory: mem }) : err(res, 404, 'Memory not found');
      }
      if (req.method === 'DELETE') {
        await gw.deleteMemory(memId[1]);
        return json(res, 200, { v4: true, id: memId[1], deleted: true });
      }
    }

    // GET /search
    if (pathname === 'search' && req.method === 'GET') {
      const url = new URL(req.url, base);
      const q = url.searchParams.get('q') || '';
      const topK = parseInt(url.searchParams.get('topK') || '10');
      const results = await gw.searchMemories(q, {
        topK,
        scope: url.searchParams.get('scope') || undefined,
        scopeType: url.searchParams.get('scopeType') || undefined,
        scopeId: url.searchParams.get('scopeId') || undefined,
      });
      return json(res, 200, { v4: true, engine: 'bm25', query: q, count: results.length, results });
    }

    // GET /teams
    if (pathname === 'teams' && req.method === 'GET') {
      const teams = await gw.listTeams();
      return json(res, 200, { v4: true, count: teams.length, teams });
    }

    // POST /teams
    if (pathname === 'teams' && req.method === 'POST') {
      const b = await body(req);
      if (!b.teamId) return err(res, 400, 'Missing required field: teamId');
      const team = await gw.createTeam(b.teamId, b.name, b.config || {});
      return json(res, 201, { v4: true, team, success: true });
    }

    // GET /stats
    if (pathname === 'stats' && req.method === 'GET') {
      const [stats, ev, rev, wal] = await Promise.all([
        gw.stats(), gw.getEvidenceStats(), gw.getRevisionStats(), gw.getWalStatus(),
      ]);
      return json(res, 200, { v4: true, memories: stats, evidence: ev, revisions: rev, wal });
    }

    // GET /wal
    if (pathname === 'wal' && req.method === 'GET') {
      const url = new URL(req.url, base);
      const limit = parseInt(url.searchParams.get('limit') || '100');
      const since = url.searchParams.get('since') ? parseInt(url.searchParams.get('since')) : undefined;
      const entries = await gw.exportWal({ since, limit });
      return json(res, 200, { v4: true, count: entries.length, entries });
    }

    err(res, 404, 'Not found: ' + req.method + ' /' + pathname);

  } catch (e) {
    console.error('[/api/v4/' + pathname + ']', e.message);
    err(res, 500, e.message);
  }
}

_server = createServer(handler);
_server.on('error', (e) => {
  if (e.code === 'EADDRINUSE') {
    console.error('[http_server] Port ' + PORT + ' in use. Kill existing server and retry.');
  }
  process.exit(1);
});

_server.listen(PORT, HOST, () => {
  console.log('[http_server] v4.0 REST API listening on http://' + HOST + ':' + PORT + '/api/v4/');
});

process.on('SIGTERM', () => { _server.close(); process.exit(0); });
process.on('SIGINT', () => { _server.close(); process.exit(0); });
/**
 * storage-gateway.js — v4.0 Storage Gateway
 *
 * Single entry point for ALL storage operations in unified-memory v4.0.
 * Replaces all 18+ local loadMemories()/saveMemories() patterns.
 *
 * Features:
 * - WAL in SQLite (no separate WAL files)
 * - Incremental BM25 via persistent posting lists
 * - Persistent scope index (B-tree)
 * - Evidence chains in dedicated table
 * - Version history in dedicated table
 * - Per-scope rate limiting
 * - Multi-tenant team spaces
 *
 * Usage:
 *   import { StorageGateway } from './v4/storage-gateway.js';
 *   const gateway = new StorageGateway();
 *   await gateway.init();
 *   const memories = await gateway.getMemories({ scope: 'USER' });
 *   await gateway.writeMemory({ text: 'Hello', category: 'fact' });
 */

import { createRequire } from 'module';
import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'fs';
import { join, dirname } from 'path';
import os from 'os';
import crypto from 'crypto';
import { fileURLToPath } from 'url';

const require = createRequire(import.meta.url);

// ─── Lazy-load dependencies ────────────────────────────────────────────────

let _betterSqlite3 = null;
function getBetterSqlite3() {
  if (_betterSqlite3) return _betterSqlite3;
  for (const path of [
    'better-sqlite3',
    '/usr/local/lib/node_modules/better-sqlite3',
    '/usr/lib/node_modules/better-sqlite3',
  ]) {
    try { _betterSqlite3 = require(path); return _betterSqlite3; } catch {}
  }
  throw new Error('[storage-gateway] better-sqlite3 not found. Run: npm install better-sqlite3');
}

let _vectorMem = null;
async function getVectorMem() {
  if (_vectorMem !== null) return _vectorMem;
  try {
    const { VectorMemory } = await import('../vector_lancedb.js');
    _vectorMem = new VectorMemory();
    await _vectorMem.initialize();
  } catch (e) {
    console.warn('[storage-gateway] VectorMemory init failed:', e.message);
    _vectorMem = null;
  }
  return _vectorMem;
}

// ─── Constants ────────────────────────────────────────────────────────────

const V4_DIR = join(os.homedir(), '.unified-memory', 'v4');
const V4_DB_PATH = join(V4_DIR, 'memories.db');

const SCOPE_TYPES = ['USER', 'TEAM', 'AGENT', 'GLOBAL'];
const TIERS = ['HOT', 'WARM', 'COLD'];
const DEFAULT_TIER = 'HOT';
const DEFAULT_SCOPE_TYPE = 'USER';

const RATE_LIMIT_WINDOW = 60;   // seconds
const RATE_LIMIT_MAX_WRITE = 30;
const RATE_LIMIT_MAX_READ = 100;
const RATE_LIMIT_MAX_SEARCH = 50;

// BM25 parameters
const BM25_K1 = 1.5;
const BM25_B = 0.75;

// ─── Schema init (DDL) ────────────────────────────────────────────────────

function buildSchema(db) {
  db.exec(`
    PRAGMA journal_mode = WAL;
    PRAGMA synchronous = NORMAL;
    PRAGMA foreign_keys = ON;
    PRAGMA busy_timeout = 5000;

    CREATE TABLE IF NOT EXISTS memories (
      id              TEXT PRIMARY KEY,
      text            TEXT NOT NULL,
      category        TEXT    DEFAULT 'general',
      tags            TEXT    DEFAULT '[]',
      importance      REAL    DEFAULT 0.5,
      scope_type      TEXT    NOT NULL DEFAULT 'USER',
      scope_id        TEXT,
      tier            TEXT    DEFAULT 'HOT',
      pinned          INTEGER DEFAULT 0,
      pinned_at       INTEGER,
      pinned_reason   TEXT,
      created_at      INTEGER NOT NULL,
      updated_at      INTEGER NOT NULL,
      accessed_at     INTEGER NOT NULL,
      version         INTEGER DEFAULT 1,
      deleted         INTEGER DEFAULT 0,
      metadata        TEXT    DEFAULT '{}'
    );
    CREATE INDEX IF NOT EXISTS idx_mem_scope    ON memories(scope_type, scope_id);
    CREATE INDEX IF NOT EXISTS idx_mem_category ON memories(category);
    CREATE INDEX IF NOT EXISTS idx_mem_tier    ON memories(tier);
    CREATE INDEX IF NOT EXISTS idx_mem_updated  ON memories(updated_at DESC);
    CREATE INDEX IF NOT EXISTS idx_mem_deleted  ON memories(deleted) WHERE deleted=0;

    CREATE TABLE IF NOT EXISTS evidence (
      id          TEXT PRIMARY KEY,
      memory_id   TEXT NOT NULL,
      type        TEXT NOT NULL,
      source_id   TEXT,
      context     TEXT,
      confidence  REAL    DEFAULT 1.0,
      timestamp   INTEGER NOT NULL,
      created_at  INTEGER NOT NULL,
      FOREIGN KEY (memory_id) REFERENCES memories(id) ON DELETE CASCADE
    );
    CREATE INDEX IF NOT EXISTS idx_ev_memory  ON evidence(memory_id, timestamp DESC);
    CREATE INDEX IF NOT EXISTS idx_ev_type     ON evidence(type, timestamp DESC);

    CREATE TABLE IF NOT EXISTS revisions (
      id             TEXT PRIMARY KEY,
      memory_id      TEXT NOT NULL,
      content        TEXT NOT NULL,
      change_type    TEXT NOT NULL,
      version_num    INTEGER NOT NULL,
      diff_from_prev TEXT,
      agent_id       TEXT,
      created_at     INTEGER NOT NULL,
      FOREIGN KEY (memory_id) REFERENCES memories(id) ON DELETE CASCADE
    );
    CREATE UNIQUE INDEX IF NOT EXISTS idx_rev_mem_ver ON revisions(memory_id, version_num DESC);

    CREATE TABLE IF NOT EXISTS scopes (
      scope_id    TEXT PRIMARY KEY,
      scope_type  TEXT NOT NULL,
      name        TEXT,
      parent_id   TEXT,
      config      TEXT    DEFAULT '{}',
      created_at  INTEGER NOT NULL,
      updated_at  INTEGER NOT NULL
    );
    CREATE INDEX IF NOT EXISTS idx_scope_type ON scopes(scope_type);

    CREATE TABLE IF NOT EXISTS wal_entries (
      lsn        TEXT PRIMARY KEY,
      operation  TEXT NOT NULL,
      table_name TEXT NOT NULL,
      record_id  TEXT NOT NULL,
      payload    TEXT NOT NULL,
      checksum   TEXT NOT NULL,
      agent_id   TEXT,
      team_space TEXT,
      status     TEXT    DEFAULT 'PENDING',
      created_at INTEGER NOT NULL
    );
    CREATE INDEX IF NOT EXISTS idx_wal_lsn    ON wal_entries(created_at ASC);
    CREATE INDEX IF NOT EXISTS idx_wal_status ON wal_entries(status) WHERE status != 'COMMITTED';

    CREATE TABLE IF NOT EXISTS rate_limits (
      key          TEXT NOT NULL,
      window_start INTEGER NOT NULL,
      count        INTEGER NOT NULL DEFAULT 0,
      ttl_seconds  INTEGER DEFAULT 120,
      PRIMARY KEY (key, window_start)
    );

    CREATE TABLE IF NOT EXISTS bm25_index (
      term       TEXT NOT NULL,
      memory_id  TEXT NOT NULL,
      frequency  INTEGER NOT NULL,
      positions  TEXT NOT NULL,
      doc_count  INTEGER NOT NULL,
      PRIMARY KEY (term, memory_id)
    );
    CREATE INDEX IF NOT EXISTS idx_bm25_term   ON bm25_index(term, frequency DESC);
    CREATE INDEX IF NOT EXISTS idx_bm25_memory ON bm25_index(memory_id);

    CREATE TABLE IF NOT EXISTS vector_meta (
      memory_id      TEXT PRIMARY KEY,
      vector_id      TEXT NOT NULL,
      vector_version INTEGER NOT NULL DEFAULT 0,
      embedding_model TEXT NOT NULL,
      dimensions     INTEGER NOT NULL,
      dirty          INTEGER DEFAULT 0,
      last_indexed   INTEGER,
      FOREIGN KEY (memory_id) REFERENCES memories(id) ON DELETE CASCADE
    );
    CREATE INDEX IF NOT EXISTS idx_vm_dirty ON vector_meta(dirty) WHERE dirty=1;

    CREATE TABLE IF NOT EXISTS meta (
      key   TEXT PRIMARY KEY,
      value TEXT
    );
  `);
}

// ─── Row ↔ Memory converters ──────────────────────────────────────────────

function rowToMemory(row) {
  if (!row) return null;
  return {
    id:          row.id,
    text:        row.text,
    category:    row.category,
    tags:        parseTags(row.tags),
    importance:  row.importance,
    scope:       row.scope_type + (row.scope_id ? `:${row.scope_id}` : ''),
    scope_type:  row.scope_type,
    scope_id:    row.scope_id,
    tier:        row.tier,
    pinned:      Boolean(row.pinned),
    pinned_at:   row.pinned_at,
    pinned_reason: row.pinned_reason,
    created_at:  row.created_at,
    updated_at:  row.updated_at,
    accessed_at: row.accessed_at,
    version:     row.version,
    deleted:     Boolean(row.deleted),
    metadata:    parseJSON(row.metadata, {}),
  };
}

function memoryToRow(mem) {
  const now = Date.now();
  const [scope_type, scope_id] = parseScope(mem.scope || mem.scope_type || DEFAULT_SCOPE_TYPE, mem.scope_id);
  return {
    id:          mem.id || generateId(),
    text:        mem.text,
    category:    mem.category || 'general',
    tags:        JSON.stringify(Array.isArray(mem.tags) ? mem.tags : []),
    importance:  mem.importance ?? 0.5,
    scope_type: scope_type || DEFAULT_SCOPE_TYPE,
    scope_id:    scope_id || null,
    tier:        TIERS.includes(mem.tier) ? mem.tier : DEFAULT_TIER,
    pinned:      mem.pinned ? 1 : 0,
    pinned_at:   mem.pinned ? (mem.pinned_at || now) : null,
    pinned_reason: mem.pinned_reason || null,
    created_at:  mem.created_at || now,
    updated_at:  now,
    accessed_at: mem.accessed_at || now,
    version:     (mem.version || 0) + 1,
    deleted:     mem.deleted ? 1 : 0,
    metadata:    JSON.stringify(mem.metadata || {}),
  };
}

function parseScope(scope, existingId) {
  if (!scope) return [DEFAULT_SCOPE_TYPE, null];
  if (scope.includes(':')) {
    const [type, id] = scope.split(':', 2);
    return [type?.toUpperCase(), id || null];
  }
  return [scope.toUpperCase(), existingId || null];
}

function parseTags(tags) {
  if (Array.isArray(tags)) return tags;
  try { return JSON.parse(tags || '[]'); } catch { return []; }
}

function parseJSON(str, fallback) {
  if (!str) return fallback;
  try { return JSON.parse(str); } catch { return fallback; }
}

function generateId() {
  return `mem_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
}

// ─── BM25 tokenizer ───────────────────────────────────────────────────────

function tokenize(text) {
  if (!text || typeof text !== 'string') return [];
  return text
    .toLowerCase()
    .replace(/[^\p{L}\p{N}\s]/gu, ' ')
    .split(/\s+/)
    .filter(t => t.length > 1);
}

// ─── LSN generator ─────────────────────────────────────────────────────────

let _lsnSeq = 0;
function nextLsn() {
  return `${Date.now()}_${++_lsnSeq}`;
}

// ─── StorageGateway ─────────────────────────────────────────────────────────

export class StorageGateway {
  constructor(options = {}) {
    this._db = null;
    this._initialized = false;
    this._bm25Loaded = false;
    this._bm25DocCount = 0;
    this._bm25AvgLen = 0;
    this._bm25PostingLists = new Map(); // term → Map(memoryId → {freq, positions})
    this._bm25DocLengths = new Map();    // memoryId → token count
    this._bm25IDF = new Map();           // term → IDF value
    this._embeddingModel = options.embeddingModel || 'nomic-embed-text';
  }

  // ── init ────────────────────────────────────────────────────────────────

  async init() {
    if (this._initialized) return;
    if (!existsSync(V4_DIR)) mkdirSync(V4_DIR, { recursive: true });

    const SQLite = getBetterSqlite3();
    this._db = new SQLite(V4_DB_PATH);
    buildSchema(this._db);

    // Try to preload existing BM25 posting lists
    await this._loadBm25Index();

    this._initialized = true;
    console.log('[storage-gateway] v4.0 initialized at', V4_DB_PATH);
  }

  get db() {
    if (!this._db) throw new Error('[storage-gateway] Not initialized. Call init() first.');
    return this._db;
  }

  // ── getMemories ─────────────────────────────────────────────────────────

  /**
   * Get memories with optional filtering.
   * @param {{ scope?, scopeType?, scopeId?, category?, tier?, limit?, offset?, includeDeleted? }} filter
   * @returns {Promise<object[]>}
   */
  async getMemories(filter = {}) {
    const scopeKey = filter.scopeId ? `${filter.scopeType || 'USER'}:${filter.scopeId}` : 'default';
    const { allowed } = this.checkRateLimit(`read:${scopeKey}`, RATE_LIMIT_MAX_READ, 60);
    if (!allowed) {
      throw new Error('[storage-gateway] Rate limit exceeded for reads');
    }

    let sql = 'SELECT * FROM memories WHERE deleted = 0';
    const params = [];

    if (filter.scope || filter.scopeType || filter.scopeId) {
      const [type, id] = parseScope(filter.scope || filter.scopeType, filter.scopeId);
      sql += ' AND scope_type = ?';
      params.push(type);
      if (id) { sql += ' AND scope_id = ?'; params.push(id); }
    }

    if (filter.category) { sql += ' AND category = ?'; params.push(filter.category); }
    if (filter.tier) { sql += ' AND tier = ?'; params.push(filter.tier); }

    sql += ' ORDER BY updated_at DESC';

    if (filter.limit) { sql += ' LIMIT ?'; params.push(filter.limit); }
    if (filter.offset) { sql += ' OFFSET ?'; params.push(filter.offset); }

    const rows = this.db.prepare(sql).all(...params);
    return rows.map(rowToMemory);
  }

  // ── getMemory ────────────────────────────────────────────────────────────

  async getMemory(id) {
    const row = this.db.prepare('SELECT * FROM memories WHERE id = ? AND deleted = 0').get(id);
    if (row) {
      // Update accessed_at
      this.db.prepare('UPDATE memories SET accessed_at = ? WHERE id = ?').run(Date.now(), id);
    }
    return rowToMemory(row);
  }

  // ── writeMemory ─────────────────────────────────────────────────────────

  /**
   * Write (insert or update) a memory with full WAL + index update.
   * All in a single transaction.
   * @param {object} mem
   * @param {{ operation?: string }} options
   */
  async writeMemory(mem, options = {}) {
    const scopeKey = mem.scopeId ? `${mem.scope || 'USER'}:${mem.scopeId}` : 'default';
    const { allowed, retryAfterSec } = this.checkRateLimit(`write:${scopeKey}`, RATE_LIMIT_MAX_WRITE, 60);
    if (!allowed) {
      throw new Error(`[storage-gateway] Rate limit exceeded. Retry after ${Math.ceil(retryAfterSec)}s`);
    }

    const op = options.operation || (mem.id ? 'UPDATE' : 'INSERT');
    const lsn = nextLsn();
    const now = Date.now();
    const row = memoryToRow({ ...mem, updated_at: now });
    const checksum = crypto.createHash('sha256').update(row.text).digest('hex');

    // WAL entry (uncommitted)
    const walEntry = {
      lsn,
      operation: op,
      table_name: 'memories',
      record_id: row.id,
      payload: JSON.stringify(row),
      checksum,
      agent_id: mem.agent_id || null,
      team_space: row.scope_id || null,
      status: 'PENDING',
      created_at: now,
    };

    this.db.transaction(() => {
      // WAL
      this.db.prepare(`
        INSERT OR REPLACE INTO wal_entries
          (lsn, operation, table_name, record_id, payload, checksum, agent_id, team_space, status, created_at)
        VALUES
          (@lsn, @operation, @table_name, @record_id, @payload, @checksum, @agent_id, @team_space, @status, @created_at)
      `).run(walEntry);

      // Memory
      const existing = this.db.prepare('SELECT id FROM memories WHERE id = ?').get(row.id);
      if (existing) {
        this.db.prepare(`
          UPDATE memories SET
            text=@text, category=@category, tags=@tags, importance=@importance,
            scope_type=@scope_type, scope_id=@scope_id, tier=@tier, pinned=@pinned,
            pinned_at=@pinned_at, pinned_reason=@pinned_reason, updated_at=@updated_at,
            accessed_at=@accessed_at, version=version+1, deleted=0, metadata=@metadata
          WHERE id=@id
        `).run(row);
      } else {
        this.db.prepare(`
          INSERT INTO memories (id, text, category, tags, importance, scope_type, scope_id,
            tier, pinned, pinned_at, pinned_reason, created_at, updated_at, accessed_at, version, deleted, metadata)
          VALUES (@id, @text, @category, @tags, @importance, @scope_type, @scope_id,
            @tier, @pinned, @pinned_at, @pinned_reason, @created_at, @updated_at, @accessed_at, @version, @deleted, @metadata)
        `).run(row);
      }

      // Incremental BM25 update
      const oldMem = existing ? this.db.prepare('SELECT text FROM memories WHERE id = ?').get(row.id) : null;
      this._updateBm25Index(row.id, row.text, oldMem?.text);

      // Commit WAL
      this.db.prepare("UPDATE wal_entries SET status='COMMITTED' WHERE lsn = ?").run(lsn);
    })();

    return rowToMemory(row);
  }

  // ── deleteMemory ────────────────────────────────────────────────────────

  async deleteMemory(id) {
    const lsn = nextLsn();
    const existing = this.db.prepare('SELECT * FROM memories WHERE id = ?').get(id);
    if (!existing) return false;

    this.db.transaction(() => {
      // Soft delete
      this.db.prepare('UPDATE memories SET deleted=1, updated_at=? WHERE id=?').run(Date.now(), id);

      // WAL
      this.db.prepare(`
        INSERT INTO wal_entries (lsn, operation, table_name, record_id, payload, checksum, status, created_at)
        VALUES (?, 'DELETE', 'memories', ?, ?, ?, 'COMMITTED', ?)
      `).run(lsn, id, JSON.stringify(existing),
        crypto.createHash('sha256').update(JSON.stringify(existing)).digest('hex'),
        Date.now());

      // Remove from BM25
      this._removeFromBm25Index(id);
    })();

    return true;
  }

  // ── searchMemories (BM25) ───────────────────────────────────────────────

  /**
   * Search memories using incremental BM25.
   * @param {string} query
   * @param {{ topK?, scope?, scopeType? }} options
   * @returns {Promise<object[]>}
   */
  async searchMemories(query, options = {}) {
    const scopeKey = options.scopeId ? `${options.scopeType || 'USER'}:${options.scopeId}` : 'default';
    const { allowed } = this.checkRateLimit(`search:${scopeKey}`, RATE_LIMIT_MAX_SEARCH, 60);
    if (!allowed) {
      throw new Error('[storage-gateway] Rate limit exceeded for search');
    }

    if (!query || !query.trim()) return [];

    const tokens = tokenize(query);
    if (tokens.length === 0) return [];

    // Scope filter
    let scopeCondition = 'deleted = 0';
    const params = [];
    if (options.scope || options.scopeType) {
      const [type, id] = parseScope(options.scope || options.scopeType, options.scopeId);
      scopeCondition += ' AND scope_type = ?';
      params.push(type);
      if (id) { scopeCondition += ' AND scope_id = ?'; params.push(id); }
    }

    // Get all non-deleted memories for scoring
    const rows = this.db.prepare(`SELECT id, text, category, importance, scope_type, scope_id FROM memories WHERE ${scopeCondition}`).all(...params);
    if (rows.length === 0) return [];

    const topK = options.topK || 10;
    const scores = [];

    for (const row of rows) {
      const score = this._bm25Score(tokens, row.id, row.text);
      if (score > 0) {
        scores.push({
          ...rowToMemory(row),
          score: Math.round(score * 1000) / 1000,
        });
      }
    }

    scores.sort((a, b) => b.score - a.score);
    return scores.slice(0, topK);
  }

  // ── evidence ───────────────────────────────────────────────────────────

  // ── Evidence with TTL trim (Phase 5) ──────────────────────────────────

  /** Evidence TTL: 90 days */
  static get EVIDENCE_TTL_MS() { return 90 * 24 * 60 * 60 * 1000; }

  /** Max revisions per memory: 50 */
  static get MAX_REVISIONS_PER_MEMORY() { return 50; }

  /** Global trim runs every N addEvidence calls */
  static get TRIM_EVERY_N_CALLS() { return 50; }

  /** Counter for global trim triggers */
  _evidenceTrimCounter = 0;

  async addEvidence(memoryId, evidence) {
    const id = `ev_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
    const now = Date.now();

    // Phase 5: Per-memory TTL trim — O(log n + k) via B-tree index
    const cutoff = now - StorageGateway.EVIDENCE_TTL_MS;
    this.db.prepare(
      'DELETE FROM evidence WHERE memory_id = ? AND timestamp < ?'
    ).run(memoryId, cutoff);

    this.db.prepare(`
      INSERT INTO evidence (id, memory_id, type, source_id, context, confidence, timestamp, created_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `).run(id, memoryId, evidence.type || 'manual', evidence.source_id || null,
      evidence.context || null, evidence.confidence ?? 1.0,
      evidence.timestamp || now, now);

    // Phase 5: Global trim every N calls (lightweight, O(log n + k))
    this._evidenceTrimCounter++;
    if (this._evidenceTrimCounter >= StorageGateway.TRIM_EVERY_N_CALLS) {
      this._evidenceTrimCounter = 0;
      this.db.prepare('DELETE FROM evidence WHERE timestamp < ?').run(cutoff);
    }

    return { id };
  }

  /**
   * Phase 5: Trim ALL evidence older than TTL (called periodically or on health check).
   * Uses B-tree index on (timestamp) — O(log n + k).
   */
  async trimEvidence() {
    const now = Date.now();
    const cutoff = now - StorageGateway.EVIDENCE_TTL_MS;
    const result = this.db.prepare(
      'DELETE FROM evidence WHERE timestamp < ?'
    ).run(cutoff);
    return { deleted: result.changes, cutoffMs: cutoff };
  }

  async getEvidence(memoryId) {
    const rows = this.db.prepare(
      'SELECT * FROM evidence WHERE memory_id = ? ORDER BY timestamp DESC'
    ).all(memoryId);
    return rows.map(r => ({ ...r, confidence: r.confidence }));
  }

  // ── revision ────────────────────────────────────────────────────────────

  async addRevision(memoryId, content, changeType = 'update') {
    const id = `rev_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
    const now = Date.now();
    const versionRow = this.db.prepare(
      'SELECT COALESCE(MAX(version_num), 0) + 1 as vn FROM revisions WHERE memory_id = ?'
    ).get(memoryId);
    const versionNum = versionRow.vn;

    this.db.prepare(`
      INSERT INTO revisions (id, memory_id, content, change_type, version_num, created_at)
      VALUES (?, ?, ?, ?, ?, ?)
    `).run(id, memoryId, typeof content === 'string' ? content : JSON.stringify(content),
      changeType, versionNum, now);

    // Phase 5: Prune old revisions — keep only MAX_REVISIONS_PER_MEMORY newest
    // Uses B-tree index on (memory_id, version_num DESC) — O(log n)
    this.db.prepare(`
      DELETE FROM revisions WHERE memory_id = ? AND version_num <= (
        SELECT version_num FROM revisions WHERE memory_id = ?
        ORDER BY version_num DESC LIMIT 1 OFFSET ?
      )
    `).run(memoryId, memoryId, StorageGateway.MAX_REVISIONS_PER_MEMORY - 1);

    return { id, version: versionNum };
  }

  async getRevisions(memoryId) {
    const rows = this.db.prepare(
      'SELECT * FROM revisions WHERE memory_id = ? ORDER BY version_num DESC'
    ).all(memoryId);
    return rows;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // PHASE 3: Multi-Tenant Team Spaces
  // ═══════════════════════════════════════════════════════════════════════════

  /**
   * Create a team scope (called automatically when first team memory is stored)
   */
  async createTeam(teamId, name, config = {}) {
    const now = Date.now();
    this.db.prepare(`
      INSERT OR REPLACE INTO scopes (scope_id, scope_type, name, config, created_at, updated_at)
      VALUES (?, 'TEAM', ?, ?, ?, ?)
    `).run(`team:${teamId}`, name || `Team ${teamId}`, JSON.stringify(config), now, now);
    return { scopeId: `team:${teamId}`, name, config };
  }

  /**
   * Get team configuration
   */
  async getTeam(teamId) {
    const row = this.db.prepare("SELECT * FROM scopes WHERE scope_id = ?").get(`team:${teamId}`);
    if (!row) return null;
    return {
      scopeId: row.scope_id,
      name: row.name,
      config: parseJSON(row.config, {}),
      createdAt: row.created_at,
    };
  }

  /**
   * List all teams
   */
  async listTeams() {
    const rows = this.db.prepare("SELECT * FROM scopes WHERE scope_type = 'TEAM' ORDER BY created_at DESC").all();
    return rows.map(r => ({
      scopeId: r.scope_id,
      name: r.name,
      config: parseJSON(r.config, {}),
      createdAt: r.created_at,
    }));
  }

  /**
   * Delete a team (soft — only removes team scope, memories remain)
   */
  async deleteTeam(teamId) {
    const result = this.db.prepare("DELETE FROM scopes WHERE scope_id = ?").run(`team:${teamId}`);
    return result.changes > 0;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // PHASE 4: Distributed Rate Limiting (SQLite atomic counters)
  // ═══════════════════════════════════════════════════════════════════════════

  /**
   * Check and increment rate limit for a key.
   * Uses SQLite atomic upsert — safe for concurrent access.
   * @param {string} key - e.g. 'write:team:123' or 'search:user:ou_xxx'
   * @param {number} limit - max calls per window
   * @param {number} windowSec - window size in seconds
   * @returns {{allowed: boolean, remaining: number, resetAt: number}}
   */
  checkRateLimit(key, limit = 30, windowSec = 60) {
    const windowStart = Math.floor(Date.now() / 1000 / windowSec) * windowSec;
    const fullKey = `${key}:${windowStart}`;

    // Atomic read + increment
    const row = this.db.prepare(
      'SELECT count FROM rate_limits WHERE key = ? AND window_start = ?'
    ).get(fullKey, windowStart);
    const count = row?.count || 0;

    if (count >= limit) {
      const resetAt = windowStart + windowSec;
      return { allowed: false, remaining: 0, resetAt, retryAfterSec: windowSec - ((Date.now() / 1000) % windowSec) };
    }

    this.db.prepare(`
      INSERT INTO rate_limits (key, window_start, count, ttl_seconds)
      VALUES (?, ?, 1, ?)
      ON CONFLICT(key, window_start) DO UPDATE SET count = count + 1
    `).run(fullKey, windowStart, windowSec * 2);

    return { allowed: true, remaining: limit - count - 1, resetAt: windowStart + windowSec };
  }

  /**
   * Get rate limit status for a key
   */
  getRateLimitStatus(key, limit = 30, windowSec = 60) {
    const windowStart = Math.floor(Date.now() / 1000 / windowSec) * windowSec;
    const fullKey = `${key}:${windowStart}`;
    const row = this.db.prepare(
      'SELECT count FROM rate_limits WHERE key = ? AND window_start = ?'
    ).get(fullKey, windowStart);
    const count = row?.count || 0;
    return {
      key,
      limit,
      windowSec,
      current: count,
      remaining: Math.max(0, limit - count),
      resetAt: windowStart + windowSec,
      windowStart,
    };
  }

  // ── stats ──────────────────────────────────────────────────────────────

  // ═══════════════════════════════════════════════════════════════════════════
  // PHASE 5: Evidence TTL + Revision Limit (already in addEvidence/addRevision)
  // ═══════════════════════════════════════════════════════════════════════════

  /**
   * Phase 5: Get evidence stats and TTL status.
   */
  async getEvidenceStats() {
    const total = this.db.prepare('SELECT COUNT(*) as c FROM evidence').get().c;
    const oldest = this.db.prepare('SELECT MIN(timestamp) as t FROM evidence').get();
    const newest = this.db.prepare('SELECT MAX(timestamp) as t FROM evidence').get();
    const byType = this.db.prepare(
      'SELECT type, COUNT(*) as c FROM evidence GROUP BY type ORDER BY c DESC'
    ).all();
    return {
      total,
      oldest: oldest.t,
      newest: newest.t,
      ttlDays: StorageGateway.EVIDENCE_TTL_MS / (24 * 60 * 60 * 1000),
      byType,
    };
  }

  /**
   * Phase 5: Get revision stats.
   */
  async getRevisionStats() {
    const total = this.db.prepare('SELECT COUNT(*) as c FROM revisions').get().c;
    const memories = this.db.prepare(
      'SELECT COUNT(DISTINCT memory_id) as c FROM revisions'
    ).get().c;
    const avgVersions = memories > 0 ? Math.round(total / memories * 10) / 10 : 0;
    return { total, memories, avgVersions, maxPerMemory: StorageGateway.MAX_REVISIONS_PER_MEMORY };
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // PHASE 6: WAL Operations (replay, export, import, truncate)
  // ═══════════════════════════════════════════════════════════════════════════

  /**
   * Phase 6: Export WAL entries as JSONL for backup/audit.
   */
  async exportWal(options = {}) {
    const { since, limit = 10000, status } = options;
    let sql = 'SELECT * FROM wal_entries WHERE 1=1';
    const params = [];
    if (since) { sql += ' AND created_at >= ?'; params.push(since); }
    if (status) { sql += ' AND status = ?'; params.push(status); }
    sql += ' ORDER BY created_at ASC LIMIT ?';
    params.push(limit);

    const rows = this.db.prepare(sql).all(...params);
    return rows.map(r => ({ ...r, payload: JSON.parse(r.payload) }));
  }

  /**
   * Phase 6: Import WAL entries from JSONL backup.
   */
  async importWal(entries) {
    const insert = this.db.prepare(`
      INSERT OR IGNORE INTO wal_entries
        (lsn, operation, table_name, record_id, payload, checksum, agent_id, team_space, status, created_at)
      VALUES (@lsn, @operation, @table_name, @record_id, @payload, @checksum, @agent_id, @team_space, @status, @created_at)
    `);

    let imported = 0;
    this.db.transaction(() => {
      for (const entry of entries) {
        try {
          insert.run({
            ...entry,
            payload: typeof entry.payload === 'string' ? entry.payload : JSON.stringify(entry.payload),
          });
          imported++;
        } catch {}
      }
    })();
    return { imported, total: entries.length };
  }

  /**
   * Phase 6: Truncate WAL (keep committed entries, remove rolled-back).
   */
  async truncateWal() {
    const result = this.db.prepare(
      "DELETE FROM wal_entries WHERE status != 'COMMITTED'"
    ).run();
    return { truncated: result.changes };
  }

  /**
   * Phase 6: WAL status summary.
   */
  async getWalStatus() {
    const total = this.db.prepare('SELECT COUNT(*) as c FROM wal_entries').get().c;
    const pending = this.db.prepare(
      "SELECT COUNT(*) as c FROM wal_entries WHERE status = 'PENDING'"
    ).get().c;
    const committed = this.db.prepare(
      "SELECT COUNT(*) as c FROM wal_entries WHERE status = 'COMMITTED'"
    ).get().c;
    const oldest = this.db.prepare(
      'SELECT MIN(created_at) as t FROM wal_entries WHERE status = ?'
    ).get('COMMITTED');

    return { total, pending, committed, oldestTs: oldest.t };
  }

  async stats() {
    const db = this.db;
    const total = db.prepare('SELECT COUNT(*) as c FROM memories WHERE deleted=0').get().c;
    const byCategory = db.prepare(
      'SELECT category, COUNT(*) as c FROM memories WHERE deleted=0 GROUP BY category'
    ).all();
    const byTier = db.prepare(
      'SELECT tier, COUNT(*) as c FROM memories WHERE deleted=0 GROUP BY tier'
    ).all();
    const byScope = db.prepare(
      'SELECT scope_type, COUNT(*) as c FROM memories WHERE deleted=0 GROUP BY scope_type'
    ).all();
    const evidence = db.prepare('SELECT COUNT(*) as c FROM evidence').get().c;
    const revisions = db.prepare('SELECT COUNT(*) as c FROM revisions').get().c;

    return { total, byCategory, byTier, byScope, evidence, revisions };
  }

  // ── BM25 index ──────────────────────────────────────────────────────────

  /**
   * Rebuild full BM25 index from all memories.
   * Call once at startup (loads persisted lists) or when rebuilding.
   */
  async rebuildBm25Index() {
    const rows = this.db.prepare(
      'SELECT id, text FROM memories WHERE deleted = 0'
    ).all();

    this._bm25PostingLists.clear();
    this._bm25DocLengths.clear();
    this._bm25IDF.clear();
    this._bm25DocCount = rows.length;

    let totalTokens = 0;
    for (const row of rows) {
      const tokens = tokenize(row.text);
      this._bm25DocLengths.set(row.id, tokens.length);
      totalTokens += tokens.length;

      for (const [term, positions] of this._tokenPositions(tokens)) {
        if (!this._bm25PostingLists.has(term)) {
          this._bm25PostingLists.set(term, new Map());
        }
        const posting = this._bm25PostingLists.get(term);
        if (posting.has(row.id)) {
          const existing = posting.get(row.id);
          existing.frequency += 1;
          existing.positions.push(...positions);
        } else {
          posting.set(row.id, { frequency: 1, positions });
        }
      }
    }

    this._bm25AvgLen = this._bm25DocCount > 0 ? totalTokens / this._bm25DocCount : 1;

    // Compute IDF for all terms
    for (const [term, postings] of this._bm25PostingLists) {
      const df = postings.size;
      this._bm25IDF.set(term, Math.log((this._bm25DocCount - df + 0.5) / (df + 0.5) + 1));
    }

    this._bm25Loaded = true;
  }

  /**
   * Incrementally update BM25 index for a document.
   * Called inside writeMemory transaction.
   */
  _updateBm25Index(memoryId, newText, oldText) {
    if (!this._bm25Loaded) {
      // Index not yet loaded — skip (will be rebuilt at startup)
      return;
    }

    const oldTokens = oldText ? tokenize(oldText) : [];
    const newTokens = tokenize(newText);

    // Track whether this is a new document (for _bm25DocCount increment)
    const isNewDoc = !this._bm25DocLengths.has(memoryId);

    // Increment doc count on first insert
    if (isNewDoc) {
      this._bm25DocCount++;
      this._bm25AvgLen = ((this._bm25AvgLen * (this._bm25DocCount - 1)) + newTokens.length) / this._bm25DocCount;
    }

    // Remove old token contributions
    if (oldTokens.length > 0) {
      for (const [term, positions] of this._tokenPositions(oldTokens)) {
        const posting = this._bm25PostingLists.get(term);
        if (posting) posting.delete(memoryId);
      }
    }

    // Add new token contributions
    for (const [term, positions] of this._tokenPositions(newTokens)) {
      if (!this._bm25PostingLists.has(term)) {
        this._bm25PostingLists.set(term, new Map());
      }
      const posting = this._bm25PostingLists.get(term);
      if (posting.has(memoryId)) {
        // Update existing term frequency
        const existing = posting.get(memoryId);
        existing.frequency += 1;
        existing.positions.push(...positions);
      } else {
        posting.set(memoryId, { frequency: 1, positions });
        // New term for this doc: update IDF based on updated df
        const df = posting.size; // includes this new doc
        const N = this._bm25DocCount || 1;
        const idf = df > 0 ? Math.log((N - df + 0.5) / (df + 0.5) + 1) : 0;
        this._bm25IDF.set(term, idf);
      }
    }

    // Update doc length
    this._bm25DocLengths.set(memoryId, newTokens.length);

    // Persist posting lists to SQLite
    this._persistBm25PostingList(memoryId, newTokens);
  }

  _removeFromBm25Index(memoryId) {
    for (const [term, posting] of this._bm25PostingLists) {
      if (posting.has(memoryId)) posting.delete(memoryId);
    }
    this._bm25DocLengths.delete(memoryId);
    this.db.prepare('DELETE FROM bm25_index WHERE memory_id = ?').run(memoryId);
  }

  _persistBm25PostingList(memoryId, tokens) {
    // Persist term frequency entries
    const termFreqs = new Map();
    for (const [term, positions] of this._tokenPositions(tokens)) {
      termFreqs.set(term, { frequency: (termFreqs.get(term)?.frequency || 0) + 1, positions });
    }

    const upsert = this.db.prepare(`
      INSERT INTO bm25_index (term, memory_id, frequency, positions, doc_count)
      VALUES (?, ?, ?, ?, ?)
      ON CONFLICT(term, memory_id) DO UPDATE SET
        frequency = excluded.frequency,
        positions = excluded.positions,
        doc_count = excluded.doc_count
    `);

    for (const [term, { frequency, positions }] of termFreqs) {
      const docCount = this._bm25PostingLists.get(term)?.size || 1;
      upsert.run(term, memoryId, frequency, JSON.stringify(positions), docCount);
    }
  }

  _bm25Score(tokens, memoryId, text) {
    if (!this._bm25Loaded) return 0;
    if (tokens.length === 0) return 0;

    const docLen = this._bm25DocLengths.get(memoryId) || tokenize(text).length || 1;
    let score = 0;

    for (const term of tokens) {
      const posting = this._bm25PostingLists.get(term);
      if (!posting) continue;

      const docInfo = posting.get(memoryId);
      if (!docInfo) continue;

      const tf = docInfo.frequency;
      const idf = this._bm25IDF.get(term) || 0;
      const numerator = tf * (BM25_K1 + 1);
      const denominator = tf + BM25_K1 * (1 - BM25_B + BM25_B * (docLen / this._bm25AvgLen));
      score += idf * (numerator / denominator);
    }

    return score;
  }

  *_tokenPositions(tokens) {
    const map = new Map();
    for (let i = 0; i < tokens.length; i++) {
      if (!map.has(tokens[i])) map.set(tokens[i], []);
      map.get(tokens[i]).push(i);
    }
    yield* map;
  }

  async _loadBm25Index() {
    try {
      const rows = this.db.prepare('SELECT id, text FROM memories WHERE deleted = 0').all();
      if (rows.length === 0) {
        this._bm25Loaded = true;
        return;
      }

      // Load from persisted posting lists
      const postingRows = this.db.prepare('SELECT term, memory_id, frequency, positions FROM bm25_index').all();
      if (postingRows.length > 0) {
        for (const row of postingRows) {
          if (!this._bm25PostingLists.has(row.term)) {
            this._bm25PostingLists.set(row.term, new Map());
          }
          this._bm25PostingLists.get(row.term).set(row.memory_id, {
            frequency: row.frequency,
            positions: JSON.parse(row.positions),
          });
          if (!this._bm25DocLengths.has(row.memory_id)) {
            this._bm25DocLengths.set(row.memory_id, 0);
          }
        }
        // Compute doc lengths from posting lists
        for (const [term, posting] of this._bm25PostingLists) {
          for (const [memId, info] of posting) {
            this._bm25DocLengths.set(memId, (this._bm25DocLengths.get(memId) || 0) + info.frequency);
          }
        }
        this._bm25DocCount = rows.length;
        this._bm25AvgLen = Array.from(this._bm25DocLengths.values()).reduce((a, b) => a + b, 0) / this._bm25DocCount || 1;
        for (const [term, posting] of this._bm25PostingLists) {
          this._bm25IDF.set(term, Math.log((this._bm25DocCount - posting.size + 0.5) / (posting.size + 0.5) + 1));
        }
        this._bm25Loaded = true;
        console.log(`[storage-gateway] BM25 loaded: ${this._bm25PostingLists.size} terms, ${this._bm25DocCount} docs`);
        return;
      }

      // No persisted data — rebuild from scratch
      await this.rebuildBm25Index();
    } catch (e) {
      console.warn('[storage-gateway] BM25 load failed, will rebuild:', e.message);
      await this.rebuildBm25Index();
    }
  }

  // ── close ───────────────────────────────────────────────────────────────

  close() {
    if (this._db) {
      this._db.close();
      this._db = null;
      this._initialized = false;
    }
  }
}

export default StorageGateway;
/**
 * storage-schema.js — v4.0 Database Schema Definitions
 * 
 * Complete SQLite schema for Unified Memory v4.0
 * All tables use WAL mode for concurrent reads + durability.
 * 
 * Tables:
 *   - memories       Primary memory storage
 *   - evidence      Evidence chain store (B-tree indexed)
 *   - revisions     Version history (B-tree indexed)
 *   - scopes        Persistent scope registry
 *   - wal_entries    Write-Ahead Log
 *   - rate_limits   Distributed sliding-window rate limits
 *   - bm25_index    Persistent BM25 posting lists
 *   - vector_meta   LanceDB vector metadata + dirty tracking
 */

import Database from 'better-sqlite3';
import { existsSync, mkdirSync } from 'fs';
import { join } from 'path';
import os from 'os';

const SCHEMA_VERSION = 4;

let _db = null;

/**
 * Get the v4.0 database handle (lazy singleton)
 */
export function getV4Db() {
  if (_db) return _db;

  const dir = join(os.homedir(), '.unified-memory', 'v4');
  if (!existsSync(dir)) {
    mkdirSync(dir, { recursive: true });
  }

  const dbPath = join(dir, 'memories.db');
  _db = new Database(dbPath);

  // WAL mode: concurrent reads, durable writes, no lock contention
  _db.pragma('journal_mode = WAL');
  _db.pragma('synchronous = NORMAL');
  _db.pragma('foreign_keys = ON');
  _db.pragma('busy_timeout = 5000');

  initSchema(_db);

  return _db;
}

/**
 * Initialize all v4.0 tables and indexes
 */
function initSchema(db) {
  // ── memories ──────────────────────────────────────────────
  db.exec(`
    CREATE TABLE IF NOT EXISTS memories (
      id              TEXT PRIMARY KEY,
      text            TEXT NOT NULL,
      category        TEXT    DEFAULT 'general',
      tags            TEXT    DEFAULT '[]',        -- JSON array
      importance      REAL    DEFAULT 0.5,
      scope_type      TEXT    NOT NULL DEFAULT 'USER',  -- USER|TEAM|AGENT|GLOBAL
      scope_id        TEXT,                           -- team_id or agent_id
      tier            TEXT    DEFAULT 'HOT',           -- HOT|WARM|COLD
      pinned          INTEGER DEFAULT 0,
      pinned_at       INTEGER,
      pinned_reason   TEXT,
      created_at      INTEGER NOT NULL,
      updated_at      INTEGER NOT NULL,
      accessed_at     INTEGER NOT NULL,
      version         INTEGER DEFAULT 1,               -- Optimistic lock
      deleted         INTEGER DEFAULT 0,               -- Soft delete
      metadata        TEXT    DEFAULT '{}'            -- JSON extensibility
    );

    CREATE INDEX IF NOT EXISTS idx_mem_scope
      ON memories(scope_type, scope_id);
    CREATE INDEX IF NOT EXISTS idx_mem_category
      ON memories(category);
    CREATE INDEX IF NOT EXISTS idx_mem_tier
      ON memories(tier);
    CREATE INDEX IF NOT EXISTS idx_mem_updated
      ON memories(updated_at DESC);
    CREATE INDEX IF NOT EXISTS idx_mem_deleted
      ON memories(deleted) WHERE deleted=0;
    CREATE INDEX IF NOT EXISTS idx_mem_importance
      ON memories(importance DESC) WHERE deleted=0;
  `);

  // ── evidence ──────────────────────────────────────────────
  db.exec(`
    CREATE TABLE IF NOT EXISTS evidence (
      id          TEXT PRIMARY KEY,
      memory_id   TEXT NOT NULL,
      type        TEXT NOT NULL,              -- transcript|interaction|fact|manual
      source_id   TEXT,
      context     TEXT,
      confidence  REAL    DEFAULT 1.0,
      timestamp   INTEGER NOT NULL,
      created_at  INTEGER NOT NULL,
      FOREIGN KEY (memory_id) REFERENCES memories(id) ON DELETE CASCADE
    );

    CREATE INDEX IF NOT EXISTS idx_ev_memory
      ON evidence(memory_id, timestamp DESC);
    CREATE INDEX IF NOT EXISTS idx_ev_type
      ON evidence(type, timestamp DESC);
    CREATE INDEX IF NOT EXISTS idx_ev_source
      ON evidence(source_id) WHERE source_id IS NOT NULL;
  `);

  // ── revisions ─────────────────────────────────────────────
  db.exec(`
    CREATE TABLE IF NOT EXISTS revisions (
      id             TEXT PRIMARY KEY,
      memory_id      TEXT NOT NULL,
      content        TEXT NOT NULL,
      change_type    TEXT NOT NULL,           -- create|update|delete
      version_num    INTEGER NOT NULL,
      diff_from_prev TEXT,
      agent_id       TEXT,
      created_at     INTEGER NOT NULL,
      FOREIGN KEY (memory_id) REFERENCES memories(id) ON DELETE CASCADE
    );

    CREATE UNIQUE INDEX IF NOT EXISTS idx_rev_memory_version
      ON revisions(memory_id, version_num DESC);
    CREATE INDEX IF NOT EXISTS idx_rev_created
      ON revisions(created_at DESC);
  `);

  // ── scopes ─────────────────────────────────────────────────
  db.exec(`
    CREATE TABLE IF NOT EXISTS scopes (
      scope_id    TEXT PRIMARY KEY,          -- 'user:ou_xxx' | 'team:xxx' | 'agent:xxx'
      scope_type  TEXT NOT NULL,
      name        TEXT,
      parent_id   TEXT,
      config      TEXT    DEFAULT '{}',       -- JSON: rate_limits, ttl, tier_policy
      created_at  INTEGER NOT NULL,
      updated_at  INTEGER NOT NULL
    );

    CREATE INDEX IF NOT EXISTS idx_scope_type
      ON scopes(scope_type);
    CREATE INDEX IF NOT EXISTS idx_scope_parent
      ON scopes(parent_id) WHERE parent_id IS NOT NULL;
  `);

  // ── wal_entries ────────────────────────────────────────────
  db.exec(`
    CREATE TABLE IF NOT EXISTS wal_entries (
      lsn          TEXT PRIMARY KEY,         -- '<timestamp>_<sequence>'
      operation    TEXT NOT NULL,            -- INSERT|UPDATE|DELETE
      table_name   TEXT NOT NULL,
      record_id    TEXT NOT NULL,
      payload      TEXT NOT NULL,            -- JSON before/after image
      checksum     TEXT NOT NULL,           -- SHA-256 of payload
      agent_id     TEXT,
      team_space   TEXT,
      status       TEXT DEFAULT 'PENDING',  -- PENDING|COMMITTED|ROLLED_BACK
      created_at   INTEGER NOT NULL
    );

    CREATE INDEX IF NOT EXISTS idx_wal_lsn
      ON wal_entries(created_at ASC);
    CREATE INDEX IF NOT EXISTS idx_wal_status
      ON wal_entries(status) WHERE status != 'COMMITTED';
  `);

  // ── rate_limits ────────────────────────────────────────────
  db.exec(`
    CREATE TABLE IF NOT EXISTS rate_limits (
      key          TEXT NOT NULL,            -- '<scope_type>:<scope_id>:<op>:<window>'
      window_start INTEGER NOT NULL,         -- Unix second (aligned)
      count        INTEGER NOT NULL DEFAULT 0,
      ttl_seconds  INTEGER DEFAULT 120,
      PRIMARY KEY (key, window_start)
    );

    CREATE INDEX IF NOT EXISTS idx_rl_window
      ON rate_limits(window_start ASC);
  `);

  // ── bm25_index ─────────────────────────────────────────────
  db.exec(`
    CREATE TABLE IF NOT EXISTS bm25_index (
      term       TEXT NOT NULL,
      memory_id  TEXT NOT NULL,
      frequency  INTEGER NOT NULL,           -- TF (term frequency in doc)
      positions  TEXT NOT NULL,              -- JSON array of token positions
      doc_count  INTEGER NOT NULL,          -- IDF: number of docs containing term
      PRIMARY KEY (term, memory_id)
    );

    CREATE INDEX IF NOT EXISTS idx_bm25_term_freq
      ON bm25_index(term, frequency DESC);
    CREATE INDEX IF NOT EXISTS idx_bm25_memory
      ON bm25_index(memory_id);
  `);

  // ── vector_meta ───────────────────────────────────────────
  db.exec(`
    CREATE TABLE IF NOT EXISTS vector_meta (
      memory_id      TEXT PRIMARY KEY,
      vector_id      TEXT NOT NULL,
      vector_version INTEGER NOT NULL DEFAULT 0,
      embedding_model TEXT NOT NULL,
      dimensions     INTEGER NOT NULL,
      dirty          INTEGER DEFAULT 0,     -- 0=clean, 1=needs_reindex
      last_indexed   INTEGER,
      FOREIGN KEY (memory_id) REFERENCES memories(id) ON DELETE CASCADE
    );

    CREATE INDEX IF NOT EXISTS idx_vm_dirty
      ON vector_meta(dirty) WHERE dirty=1;
  `);

  // ── meta (key-value store) ────────────────────────────────
  db.exec(`
    CREATE TABLE IF NOT EXISTS meta (
      key   TEXT PRIMARY KEY,
      value TEXT
    );
  `);
}

/**
 * Check if v4.0 schema is initialized
 */
export function isV4Initialized() {
  try {
    const db = getV4Db();
    const row = db.prepare("SELECT value FROM meta WHERE key='schema_version'").get();
    return row?.value === String(SCHEMA_VERSION);
  } catch {
    return false;
  }
}

/**
 * Mark v4.0 schema as initialized
 */
export function markV4Initialized() {
  const db = getV4Db();
  db.prepare("INSERT OR REPLACE INTO meta (key, value) VALUES ('schema_version', ?)").run(String(SCHEMA_VERSION));
}

/**
 * Close the database handle
 */
export function closeV4Db() {
  if (_db) {
    _db.close();
    _db = null;
  }
}

export default {
  getV4Db,
  isV4Initialized,
  markV4Initialized,
  closeV4Db,
  SCHEMA_VERSION,
};
/**
 * Graph Visualizer - Generate interactive knowledge graph HTML
 */

import { readFileSync, existsSync, writeFileSync, mkdirSync } from 'fs';
import { join } from 'path';
import { getAllMemories } from '../storage.js';


const WORKSPACE = join(process.env.HOME || '/root', '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const VISUAL_DIR = MEMORY_DIR;

export function buildGraph(memories) {
  const data = memories || getAllMemories();
  const nodes = [], edges = [];
  const nodeIds = new Set();
  
  for (const mem of data) {
    const memId = mem.id || `mem_${nodes.length}`;
    if (nodeIds.has(memId)) continue;
    nodeIds.add(memId);
    nodes.push({ id: memId, label: (mem.text || '').substring(0, 50), type: mem.category || 'general', size: (mem.importance || 0.5) * 20 + 10 });
    if (Array.isArray(mem.tags)) {
      for (const tag of mem.tags.slice(0, 3)) {
        const tagId = `tag_${tag}`;
        if (!nodeIds.has(tagId)) { nodeIds.add(tagId); nodes.push({ id: tagId, label: tag, type: 'tag', size: 8 }); }
        edges.push({ from: memId, to: tagId, type: 'has_tag', label: 'has' });
      }
    }
  }
  return { nodes, edges };
}

export function generateGraphHtml(graphData) {
  const data = graphData || buildGraph();
  const nodesJson = JSON.stringify(data.nodes);
  const edgesJson = JSON.stringify(data.edges);
  return `<!DOCTYPE html>
<html><head><meta charset="utf-8"><title>🧠 Knowledge Graph</title>
<script src="https://cdn.jsdelivr.net/npm/vis-network@9.1.2/standalone/umd/vis-network.min.js"></script>
<style>body{font-family:-apple-system,sans-serif;margin:0;padding:20px;background:#1a1a2e;color:#eee}
h1{color:#4fc3f7;text-align:center}#network{width:100%;height:600px;border:1px solid #333;border-radius:8px;background:#16213e}
.controls{text-align:center;margin:20px 0}.controls button{padding:10px 20px;margin:0 5px;background:#4fc3f7;border:none;border-radius:4px;cursor:pointer}
.stats{text-align:center;color:#888}</style></head>
<body><h1>🧠 Knowledge Graph</h1>
<div class="controls"><button onclick="focusType('preference')">Preference</button>
<button onclick="focusType('decision')">Decision</button><button onclick="resetView()">Reset</button></div>
<div id="network"></div><div class="stats"><span id="nodeCount">0</span> nodes | <span id="edgeCount">0</span> edges</div>
<script>var nodes=new vis.DataSet(${nodesJson});var edges=new vis.DataSet(${edgesJson});
var container=document.getElementById('network');var data={nodes,edges};
var colors={'preference':'#e91e63','decision':'#ff9800','fact':'#2196f3','task':'#4caf50','general':'#9e9e9e','tag':'#00bcd4'};
nodes.forEach(function(n){n.color={background:colors[n.type]||'#9e9e9e',border:colors[n.type]||'#9e9e9e'};nodes.update(n)});
var options={nodes:{shape:'dot',font:{color:'#eee'},borderWidth:2},edges:{width:1,color:{color:'#4fc3f7',opacity:0.6},arrows:{to:{enabled:true,scaleFactor:0.5}}},physics:{forceAtlas2Based:{gravitationalConstant:-50,springLength:100},solver:'forceAtlas2Based',stabilization:{iterations:150}}};
var network=new vis.Network(container,data,options);
document.getElementById('nodeCount').textContent=nodes.length;document.getElementById('edgeCount').textContent=edges.length;
function focusType(t){var sel=nodes.get({filter:function(n){return n.type===t}});if(sel.length>0){network.selectNodes(sel.map(function(n){return n.id}));network.focus(sel[0].id,{scale:1.5,animation:true})}}
function resetView(){network.fit({animation:true})}</script></body></html>`;
}

export function printGraphStats() {
  const graph = buildGraph();
  console.log('\n🕸️  Knowledge Graph Stats\n');
  console.log(`  Nodes: ${graph.nodes.length}`);
  console.log(`  Edges: ${graph.edges.length}`);
  console.log('');
}

if (require.main === module) {
  const args = process.argv.slice(2);
  if (args[0] === 'save' || args[0] === 'export') {
    mkdirSync(VISUAL_DIR, { recursive: true });
    const file = join(VISUAL_DIR, 'knowledge_graph.html');
    writeFileSync(file, generateGraphHtml(), 'utf-8');
    console.log(`🕸️  Graph saved: ${file}`);
  } else printGraphStats();
}
/**
 * Heatmap Generator
 */

import { readFileSync, writeSync, existsSync, mkdirSync } from 'fs';
import { join } from 'path';
import { getAllMemories } from '../storage.js';


const WORKSPACE = join(process.env.HOME || '/root', '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const HEATMAP_DIR = join(MEMORY_DIR, 'heatmaps');

export function calculateHeatmap() {
  const memories = getAllMemories();
  const entries = memories.map(mem => {
    const accessCount = mem.access_count || 0;
    const importance = mem.importance || 0.5;
    const heatScore = accessCount * importance;
    return { id: mem.id || 'unknown', text: (mem.text || '').substring(0, 50), category: mem.category || 'general', accessCount, importance, heatScore };
  });
  entries.sort((a, b) => b.heatScore - a.heatScore);
  return { generatedAt: new Date().toISOString(), entries, totalMemories: memories.length, hottestMemories: entries.slice(0, 10) };
}

export function generateAsciiHeatmap(heatmap) {
  const data = heatmap || calculateHeatmap();
  const lines = [];
  lines.push('🔥 Memory Access Heatmap\n');
  lines.push(`Generated: ${data.generatedAt}\n`);
  lines.push(`Total Memories: ${data.totalMemories}\n`);
  lines.push('─'.repeat(60));
  lines.push('');
  for (let i = 0; i < Math.min(data.entries.length, 20); i++) {
    const entry = data.entries[i];
    const barLen = Math.min(Math.floor(entry.heatScore * 2), 30);
    const bar = '█'.repeat(barLen) + '░'.repeat(30 - barLen);
    lines.push(`[${(i + 1).toString().padStart(2)}] ${bar} ${entry.heatScore.toFixed(1)}`);
    lines.push(`      ${entry.text}...`);
    lines.push('');
  }
  return lines.join('\n');
}

if (require.main === module) {
  const args = process.argv.slice(2);
  if (args[0] === 'save') {
    mkdirSync(HEATMAP_DIR, { recursive: true });
    const heatmap = calculateHeatmap();
    const file = join(HEATMAP_DIR, `heatmap_${Date.now()}.json`);
    writeSync(file, JSON.stringify(heatmap, null, 2), 'utf-8');
    console.log(`💾 Saved: ${file}`);
  } else {
    console.log(generateAsciiHeatmap());
  }
}
/**
 * Memory Visualize - 记忆可视化
 * 
 * Ported from memory_visualize.py
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'fs';
import { join } from 'path';

const HOME = process.env.HOME || '/root';
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const VIZ_DIR = join(MEMORY_DIR, 'visualizations');

// ============================================================
// Visualizer
// ============================================================

export class MemoryVisualizer {
  constructor() {
    mkdirSync(VIZ_DIR, { recursive: true });
  }

  /**
   * Generate ASCII visualization of memory categories
   * @param {Array} memories
   * @returns {string}
   */
  asciiCategories(memories) {
    /** @type {Map<string, number>} */
    const categoryCount = new Map();
    for (const m of memories) {
      const cat = m.category || 'general';
      categoryCount.set(cat, (categoryCount.get(cat) || 0) + 1);
    }

    const sorted = [...categoryCount.entries()].sort((a, b) => b[1] - a[1]);
    const maxCount = sorted.length > 0 ? sorted[0][1] : 0;

    const lines = ['📊 记忆分类分布', ''];
    for (const [cat, count] of sorted) {
      const barLen = Math.round((count / Math.max(maxCount, 1)) * 30);
      const bar = '█'.repeat(barLen);
      const pct = Math.round((count / Math.max(memories.length, 1)) * 100);
      lines.push(`  ${cat.padEnd(12)} ${bar.padEnd(30)} ${count} (${pct}%)`);
    }

    return lines.join('\n');
  }

  /**
   * Generate ASCII timeline
   * @param {Array} memories
   * @returns {string}
   */
  asciiTimeline(memories) {
    /** @type {Map<string, Array>} */
    const byMonth = new Map();
    for (const m of memories) {
      const ts = m.created_at || m.timestamp;
      if (!ts) continue;
      const month = ts.slice(0, 7); // YYYY-MM
      if (!byMonth.has(month)) byMonth.set(month, []);
      byMonth.get(month).push(m);
    }

    const sorted = [...byMonth.entries()].sort((a, b) => b[0].localeCompare(a[0])).slice(0, 12);
    const maxCount = sorted.length > 0 ? Math.max(...sorted.map(([, m]) => m.length)) : 0;

    const lines = ['📅 记忆时间线', ''];
    for (const [month, mems] of sorted) {
      const barLen = Math.round((mems.length / Math.max(maxCount, 1)) * 40);
      const bar = '▓'.repeat(barLen);
      lines.push(`  ${month} ${bar} ${mems.length} 条`);
    }

    return lines.join('\n');
  }

  /**
   * Generate ASCII importance distribution
   * @param {Array} memories
   * @returns {string}
   */
  asciiImportance(memories) {
    const buckets = { '0.0-0.2': 0, '0.2-0.4': 0, '0.4-0.6': 0, '0.6-0.8': 0, '0.8-1.0': 0 };
    for (const m of memories) {
      const imp = m.importance || 0.5;
      if (imp < 0.2) buckets['0.0-0.2']++;
      else if (imp < 0.4) buckets['0.2-0.4']++;
      else if (imp < 0.6) buckets['0.4-0.6']++;
      else if (imp < 0.8) buckets['0.6-0.8']++;
      else buckets['0.8-1.0']++;
    }

    const maxCount = Math.max(...Object.values(buckets), 1);
    const lines = ['⭐ 重要性分布', ''];
    for (const [range, count] of Object.entries(buckets)) {
      const barLen = Math.round((count / maxCount) * 40);
      const bar = '◆'.repeat(barLen);
      lines.push(`  ${range.padEnd(10)} ${bar.padEnd(40)} ${count}`);
    }

    return lines.join('\n');
  }

  /**
   * Generate text-based graph visualization
   * @param {object} graph
   * @returns {string}
   */
  asciiGraph(graph) {
    const nodes = graph.nodes || {};
    const edges = graph.edges || {};

    const lines = ['🕸️ 记忆关联图', ''];
    for (const [nodeId, node] of Object.entries(nodes)) {
      const text = (node.text || node.name || nodeId).slice(0, 20);
      lines.push(`  ● ${text} [${node.category || '?'}]`);
    }

    if (Object.keys(edges).length > 0) {
      lines.push('');
      for (const [edgeKey, edge] of Object.entries(edges).slice(0, 20)) {
        const sourceText = ((nodes[edge.source] || {}).text || edge.source || '').slice(0, 15);
        const targetText = ((nodes[edge.target] || {}).text || edge.target || '').slice(0, 15);
        const weight = edge.weight || 1;
        lines.push(`  ${sourceText} ─${'─'.repeat(weight)}▶ ${targetText} (${weight})`);
      }
    }

    return lines.join('\n');
  }

  /**
   * Generate full ASCII dashboard
   * @param {object} data
   * @returns {string}
   */
  dashboard(data) {
    const memories = data.memories || [];
    const graph = data.graph || {};
    const stats = data.stats || {};

    const separator = '─'.repeat(50);
    const lines = [
      '',
      `  ╔${separator}╗`,
      `  ║ 记忆可视化仪表板${' '.repeat(Math.max(0, 37 - 12))}║`,
      `  ╚${separator}╝`,
      '',
      `  📊 统计概览`,
      `  ─${'─'.repeat(49)}`,
      `  总记忆数:   ${memories.length}`,
      `  分类数:    ${stats.categoryCount || 0}`,
      `  关联边数:  ${Object.keys(graph.edges || {}).length}`,
      '',
      this.asciiCategories(memories),
      '',
      separator,
      this.asciiTimeline(memories),
      '',
      separator,
      this.asciiImportance(memories),
      '',
    ];

    if (Object.keys(graph.nodes || {}).length > 0) {
      lines.push(separator);
      lines.push(this.asciiGraph(graph));
    }

    lines.push('');
    return lines.join('\n');
  }
}

// ============================================================
// CLI Handler
// ============================================================

/**
 * @param {string} command
 * @param {object} args
 * @returns {object}
 */
export function cmdVisualize(command, args) {
  const visualizer = new MemoryVisualizer();

  // Load memories for visualization
  /** @type {Array} */
  let memories = [];
  try {
    const { getAllMemories } = require('../storage.js');
    memories = getAllMemories();
  } catch {
    const memoryFile = join(MEMORY_DIR, 'memories.json');
    if (existsSync(memoryFile)) {
      try {
        const data = JSON.parse(readFileSync(memoryFile, 'utf-8'));
        memories = Array.isArray(data) ? data : (data.memories || []);
      } catch { /* ignore */ }
    }
  }

  switch (command) {
    case 'categories': {
      return { type: 'text', text: visualizer.asciiCategories(memories) };
    }

    case 'timeline': {
      return { type: 'text', text: visualizer.asciiTimeline(memories) };
    }

    case 'importance': {
      return { type: 'text', text: visualizer.asciiImportance(memories) };
    }

    case 'graph': {
      // Try to load association graph
      let graph = {};
      try {
        const associationGraphFile = join(MEMORY_DIR, 'associations', 'graph.json');
        if (existsSync(associationGraphFile)) {
          graph = JSON.parse(readFileSync(associationGraphFile, 'utf-8'));
        }
      } catch { /* ignore */ }
      return { type: 'text', text: visualizer.asciiGraph(graph) };
    }

    case 'dashboard': {
      const stats = {};
      const cats = new Set(memories.map(m => m.category));
      stats.categoryCount = cats.size;

      let graph = {};
      try {
        const gFile = join(MEMORY_DIR, 'associations', 'graph.json');
        if (existsSync(gFile)) graph = JSON.parse(readFileSync(gFile, 'utf-8'));
      } catch { /* ignore */ }

      return { type: 'text', text: visualizer.dashboard({ memories, graph, stats }) };
    }

    default:
      return { error: `未知命令: ${command}` };
  }
}

export default { MemoryVisualizer, cmdVisualize };
