const HOME = homedir();
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const MEMORY_FILE = join(WORKSPACE, 'memory', 'memories.json');
const VECTOR_DB_DIR = join(HOME, '.unified-memory', 'vector.lance');
