/**
 * Base Extractor - 多模态提取器基类
 * 
 * 为不同类型的文件（PDF、图片、视频等）提供统一的内容提取接口
 * 
 * 功能：
 * - extract(file): 提取文件内容
 * - 支持多种文件格式
 * - 统一的输出格式
 */

import { log } from '../logger.js';
import { config } from '../config.js';
import { extname } from 'path';

// ─── 提取器状态 ───────────────────────────────────────────────────────────────
const ExtractorStatus = {
  READY: 'ready',
  EXTRACTING: 'extracting',
  ERROR: 'error',
  DISABLED: 'disabled',
};

// ─── 支持的文件类型 ───────────────────────────────────────────────────────────
const FILE_TYPES = {
  // 文档类型
  pdf: 'document',
  doc: 'document',
  docx: 'document',
  txt: 'text',
  md: 'text',
  
  // 图片类型
  jpg: 'image',
  jpeg: 'image',
  png: 'image',
  gif: 'image',
  webp: 'image',
  
  // 音频类型
  mp3: 'audio',
  wav: 'audio',
  m4a: 'audio',
  
  // 视频类型
  mp4: 'video',
  avi: 'video',
  mov: 'video',
  mkv: 'video',
};

// ─── BaseExtractor 基类 ────────────────────────────────────────────────────────

/**
 * 多模态提取器基类
 * 所有具体提取器应继承此类
 */
export class BaseExtractor {
  /**
   * @param {object} options
   * @param {string} options.name - 提取器名称
   * @param {string} options.type - 提取器类型（pdf, ocr, video 等）
   * @param {Array<string>} options.supportedFormats - 支持的文件格式
   */
  constructor(options = {}) {
    this.name = options.name || 'base-extractor';
    this.type = options.type || 'base';
    this.supportedFormats = options.supportedFormats || [];
    this.status = ExtractorStatus.READY;
    
    // 统计信息
    this.stats = {
      totalExtractions: 0,
      totalFiles: 0,
      totalErrors: 0,
      totalBytes: 0,
    };
  }
  
  /**
   * 检查是否支持指定文件格式
   * @param {string} filePath - 文件路径
   * @returns {boolean}
   */
  supports(filePath) {
    const ext = extname(filePath).slice(1).toLowerCase();
    return this.supportedFormats.includes(ext);
  }
  
  /**
   * 提取文件内容
   * @param {string} filePath - 文件路径
   * @param {object} [options] - 提取选项
   * @returns {Promise<{ content: string, metadata: object }>}
   */
  async extract(filePath, options = {}) {
    log('info', `[${this.name}] Extracting: ${filePath}`);
    
    const startTime = Date.now();
    this.status = ExtractorStatus.EXTRACTING;
    
    try {
      // 检查是否支持
      if (!this.supports(filePath)) {
        throw new Error(`Unsupported file format: ${filePath}`);
      }
      
      // 调用子类实现
      const result = await this._doExtract(filePath, options);
      
      // 更新统计
      this.stats.totalExtractions++;
      this.stats.totalFiles++;
      this.status = ExtractorStatus.READY;
      
      const duration = Date.now() - startTime;
      log('info', `[${this.name}] Extraction complete: ${duration}ms`);
      
      return {
        content: result.content || '',
        metadata: {
          source: filePath,
          extractor: this.name,
          extractorType: this.type,
          extractedAt: new Date().toISOString(),
          duration,
          ...result.metadata,
        },
      };
    } catch (e) {
      this.status = ExtractorStatus.ERROR;
      this.stats.totalErrors++;
      
      log('error', `[${this.name}] Extraction failed: ${e.message}`);
      
      throw e;
    }
  }
  
  /**
   * 实际提取逻辑（子类重写）
   */
  async _doExtract(filePath, options = {}) {
    throw new Error('Subclass must implement _doExtract()');
  }
  
  /**
   * 批量提取
   * @param {Array<string>} filePaths - 文件路径列表
   * @param {object} [options] - 提取选项
   * @returns {Promise<Array>}
   */
  async extractBatch(filePaths, options = {}) {
    const results = [];
    
    for (const filePath of filePaths) {
      try {
        const result = await this.extract(filePath, options);
        results.push(result);
      } catch (e) {
        results.push({
          error: e.message,
          source: filePath,
        });
      }
    }
    
    return results;
  }
  
  /**
   * 获取文件类型
   */
  getFileType(filePath) {
    const ext = extname(filePath).slice(1).toLowerCase();
    return FILE_TYPES[ext] || 'unknown';
  }
  
  /**
   * 获取提取器状态
   */
  getStatus() {
    return {
      name: this.name,
      type: this.type,
      status: this.status,
      supportedFormats: this.supportedFormats,
      stats: { ...this.stats },
    };
  }
  
  /**
   * 销毁提取器
   */
  async destroy() {
    this.status = ExtractorStatus.DISABLED;
    log('info', `[${this.name}] Extractor destroyed`);
  }
}

// ─── 文本提取器（简单实现）────────────────────────────────────────────────────

/**
 * 文本文件提取器
 */
export class TextExtractor extends BaseExtractor {
  constructor(options = {}) {
    super({
      name: 'text-extractor',
      type: 'text',
      supportedFormats: ['txt', 'md', 'markdown', 'json', 'yaml', 'yml', 'csv'],
      ...options,
    });
  }
  
  async _doExtract(filePath, options = {}) {
    const { readFile } = await import('fs/promises');
    const content = await readFile(filePath, 'utf-8');
    
    return {
      content,
      metadata: {
        fileType: this.getFileType(filePath),
        size: Buffer.byteLength(content, 'utf-8'),
      },
    };
  }
}

export default BaseExtractor;
/**
 * Extractors - 多模态提取器模块入口
 * 
 * 提供不同类型文件内容提取器的统一导出和管理
 * 
 * 支持的提取器（未来扩展）：
 * - PDFExtractor: PDF 文档提取
 * - OCRExtractor: 图片 OCR 提取
 * - VideoExtractor: 视频帧提取 + OCR
 * - AudioExtractor: 音频转文字（Whisper）
 */

import { BaseExtractor, TextExtractor } from './base.js';

// ─── 提取器注册表 ───────────────────────────────────────────────────────────────
const extractorRegistry = new Map();

/**
 * 注册提取器
 */
export function registerExtractor(name, ExtractorClass) {
  extractorRegistry.set(name, ExtractorClass);
}

/**
 * 创建提取器实例
 */
export function createExtractor(name, options = {}) {
  const ExtractorClass = extractorRegistry.get(name);
  
  if (!ExtractorClass) {
    throw new Error(`Unknown extractor: ${name}`);
  }
  
  return new ExtractorClass(options);
}

/**
 * 获取适合文件的提取器
 */
export function getExtractorForFile(filePath, options = {}) {
  for (const [name, ExtractorClass] of extractorRegistry) {
    const extractor = new ExtractorClass(options);
    if (extractor.supports(filePath)) {
      return extractor;
    }
  }
  
  return null;
}

/**
 * 自动提取文件内容
 */
export async function autoExtract(filePath, options = {}) {
  const extractor = getExtractorForFile(filePath, options);
  
  if (!extractor) {
    throw new Error(`No extractor found for file: ${filePath}`);
  }
  
  return extractor.extract(filePath, options);
}

/**
 * 获取所有已注册的提取器
 */
export function listExtractors() {
  return [...extractorRegistry.keys()];
}

// ─── 注册默认提取器 ───────────────────────────────────────────────────────────
registerExtractor('text', TextExtractor);

// ─── 导出 ────────────────────────────────────────────────────────────────────

export { BaseExtractor, TextExtractor } from './base.js';

export default {
  BaseExtractor,
  TextExtractor,
  registerExtractor,
  createExtractor,
  getExtractorForFile,
  autoExtract,
  listExtractors,
};
/**
 * Cases Memory Handler - 案例型记忆处理器
 */

import { logger } from '../logger.js';

export const cases = {
  name: 'cases',
  description: '处理案例、经验、教训',
  
  /**
   * 从文本中提取案例
   */
  async extract(text, context = {}) {
    logger.debug(`[CasesHandler] 提取案例: ${text.substring(0, 100)}...`);
    
    // 提取案例结构
    const caseStructure = this.extractCaseStructure(text);
    
    // 提取关键事件
    const keyEvents = this.extractKeyEvents(text);
    
    // 提取经验教训
    const lessonsLearned = this.extractLessonsLearned(text);
    
    // 提取成功因素
    const successFactors = this.extractSuccessFactors(text);
    
    // 提取失败原因
    const failureReasons = this.extractFailureReasons(text);
    
    // 提取可复用点
    const reusablePoints = this.extractReusablePoints(text);
    
    return {
      caseStructure,
      keyEvents,
      lessonsLearned,
      successFactors,
      failureReasons,
      reusablePoints,
      confidence: this.calculateConfidence(text, caseStructure, lessonsLearned),
      metadata: {
        extractionMethod: 'hybrid',
        timestamp: Date.now(),
        textLength: text.length
      }
    };
  },
  
  /**
   * 提取案例结构
   */
  extractCaseStructure(text) {
    const structure = {
      hasBackground: false,
      hasProblem: false,
      hasSolution: false,
      hasResult: false,
      sections: []
    };
    
    // 检查案例结构关键词
    const structureKeywords = {
      background: ['背景', '情况', '环境', '起初', '原来', 'background'],
      problem: ['问题', '挑战', '困难', '遇到', '面临', 'problem', 'challenge'],
      solution: ['解决', '方案', '方法', '措施', '做法', 'solution', 'approach'],
      result: ['结果', '效果', '成果', '成效', 'outcome', 'result']
    };
    
    for (const [section, keywords] of Object.entries(structureKeywords)) {
      for (const keyword of keywords) {
        if (text.includes(keyword)) {
          structure[`has${section.charAt(0).toUpperCase() + section.slice(1)}`] = true;
          structure.sections.push({
            type: section,
            keyword: keyword,
            confidence: 0.7
          });
          break;
        }
      }
    }
    
    // 计算结构完整性
    const completeness = Object.values(structure).filter(v => v === true).length / 4;
    structure.completeness = completeness;
    
    return structure;
  },
  
  /**
   * 提取关键事件
   */
  extractKeyEvents(text) {
    const events = [];
    
    // 事件关键词
    const eventKeywords = [
      '发生', '出现', '遇到', '发现', '意识到', '决定',
      'occurred', 'happened', 'encountered', 'discovered', 'decided'
    ];
    
    // 时间标记
    const timeMarkers = [
      '首先', '然后', '接着', '之后', '最后', '最终',
      'first', 'then', 'next', 'after', 'finally'
    ];
    
    // 分句
    const sentences = text.split(/[。！？；\.\?!;]/).filter(s => s.trim());
    
    for (const sentence of sentences) {
      // 检查事件关键词
      for (const keyword of eventKeywords) {
        if (sentence.includes(keyword)) {
          events.push({
            text: sentence.trim(),
            keyword: keyword,
            type: 'event',
            confidence: 0.7
          });
          break;
        }
      }
      
      // 检查时间标记
      for (const marker of timeMarkers) {
        if (sentence.includes(marker)) {
          events.push({
            text: sentence.trim(),
            marker: marker,
            type: 'sequence',
            confidence: 0.6
          });
          break;
        }
      }
    }
    
    return events;
  },
  
  /**
   * 提取经验教训
   */
  extractLessonsLearned(text) {
    const lessons = [];
    
    // 教训关键词
    const lessonKeywords = [
      '教训', '经验', '学到', '明白', '认识到', '意识到',
      'lesson', 'experience', 'learned', 'realized', 'understood'
    ];
    
    // 教训模式
    const lessonPatterns = [
      /(.+)教训[是为：:]\s*(.+)/,
      /从(.+)中学到[了的是]\s*(.+)/,
      /(.+)让[我我们]明白[了的是]\s*(.+)/,
      /经验[是为：:]\s*(.+)/
    ];
    
    // 检查关键词
    for (const keyword of lessonKeywords) {
      if (text.includes(keyword)) {
        const context = this.extractContext(text, keyword, 30);
        lessons.push({
          keyword: keyword,
          context: context,
          type: 'lesson',
          confidence: 0.8
        });
      }
    }
    
    // 检查模式
    for (const pattern of lessonPatterns) {
      const match = text.match(pattern);
      if (match) {
        lessons.push({
          pattern: pattern.source,
          fullMatch: match[0],
          content: match[2] || match[1],
          type: 'structured_lesson',
          confidence: 0.9
        });
      }
    }
    
    return lessons;
  },
  
  /**
   * 提取成功因素
   */
  extractSuccessFactors(text) {
    const factors = [];
    
    // 成功关键词
    const successKeywords = [
      '成功', '有效', '关键', '重要', '得益于', '归功于',
      'success', 'effective', 'key', 'important', 'thanks to'
    ];
    
    for (const keyword of successKeywords) {
      if (text.includes(keyword)) {
        const context = this.extractContext(text, keyword, 25);
        factors.push({
          keyword: keyword,
          context: context,
          type: 'success_factor',
          confidence: 0.7
        });
      }
    }
    
    return factors;
  },
  
  /**
   * 提取失败原因
   */
  extractFailureReasons(text) {
    const reasons = [];
    
    // 失败关键词
    const failureKeywords = [
      '失败', '错误', '问题', '缺陷', '不足', '原因',
      'failed', 'error', 'mistake', 'problem', 'issue', 'reason'
    ];
    
    for (const keyword of failureKeywords) {
      if (text.includes(keyword)) {
        const context = this.extractContext(text, keyword, 25);
        reasons.push({
          keyword: keyword,
          context: context,
          type: 'failure_reason',
          confidence: 0.7
        });
      }
    }
    
    return reasons;
  },
  
  /**
   * 提取可复用点
   */
  extractReusablePoints(text) {
    const points = [];
    
    // 可复用关键词
    const reusableKeywords = [
      '可以', '建议', '推荐', '值得', '参考', '借鉴',
      'can', 'suggest', 'recommend', 'worth', 'reference'
    ];
    
    for (const keyword of reusableKeywords) {
      if (text.includes(keyword)) {
        const context = this.extractContext(text, keyword, 25);
        points.push({
          keyword: keyword,
          context: context,
          type: 'reusable',
          confidence: 0.6
        });
      }
    }
    
    return points;
  },
  
  /**
   * 提取上下文
   */
  extractContext(text, targetWord, windowSize = 20) {
    const index = text.indexOf(targetWord);
    if (index === -1) return '';
    
    const start = Math.max(0, index - windowSize);
    const end = Math.min(text.length, index + targetWord.length + windowSize);
    
    return text.substring(start, end);
  },
  
  /**
   * 计算置信度
   */
  calculateConfidence(text, caseStructure, lessonsLearned) {
    let confidence = 0.3;
    
    // 基于结构完整性
    confidence += caseStructure.completeness * 0.3;
    
    // 基于经验教训
    if (lessonsLearned.length > 0) {
      confidence += Math.min(lessonsLearned.length * 0.15, 0.3);
    }
    
    // 基于案例关键词
    const casePattern = /案例|经验|教训|故事|经历/;
    if (casePattern.test(text)) {
      confidence += 0.2;
    }
    
    return Math.min(Math.max(confidence, 0.1), 1.0);
  },
  
  /**
   * 验证案例
   */
  async validate(caseMemory, context = {}) {
    const validation = {
      isValid: true,
      confidence: 0.5,
      issues: [],
      suggestions: []
    };
    
    if (!caseMemory.text || caseMemory.text.length < 50) {
      validation.isValid = false;
      validation.issues.push('案例描述太短');
      validation.confidence *= 0.5;
    }
    
    const structure = caseMemory.extracted?.caseStructure;
    if (structure && structure.completeness < 0.5) {
      validation.issues.push('案例结构不完整');
      validation.suggestions.push('建议包含背景、问题、解决方案和结果');
      validation.confidence *= 0.8;
    }
    
    const hasLessons = caseMemory.extracted?.lessonsLearned?.length > 0;
    if (!hasLessons) {
      validation.suggestions.push('建议添加经验教训总结');
    }
    
    return validation;
  },
  
  /**
   * 合并相似案例
   */
  async mergeSimilar(case1, case2, context = {}) {
    const merged = {
      text: `${case1.text}\n\n---\n\n${case2.text}`,
      extracted: {
        ...case1.extracted,
        ...case2.extracted,
        keyEvents: [...(case1.extracted?.keyEvents || []), ...(case2.extracted?.keyEvents || [])],
        lessonsLearned: [...(case1.extracted?.lessonsLearned || []), ...(case2.extracted?.lessonsLearned || [])]
      },
      importance: Math.max(case1.importance || 0.5, case2.importance || 0.5),
      timestamp: Math.max(case1.timestamp || Date.now(), case2.timestamp || Date.now()),
      metadata: {
        ...case1.metadata,
        ...case2.metadata,
        mergedFrom: [case1.id, case2.id],
        mergedAt: Date.now()
      }
    };
    
    return merged;
  }
};

