/**
 * Smart Extractor - LLM-powered memory extraction from raw text
 * 6 categories: preference, fact, decision, entity, reflection, other
 * 8-second timeout, Jaccard dedup against existing memories
 */
const CATEGORIES = ['preference', 'fact', 'decision', 'entity', 'reflection', 'other'];
const EXTRACT_PROMPT = `You are a memory analysis assistant. Extract structured memories from the following text.

For each memory, identify:
1. **category**: one of [preference, fact, decision, entity, reflection, other]
2. **text**: concise summary (within 100 chars)
3. **importance**: 0.0-1.0 (how important this memory is)

Categories:
- preference: user likes/dislikes, habits, communication style
- fact: verifiable information, dates, names, events
- decision: choices made, conclusions reached, agreements
- entity: people, products, tools, services mentioned
- reflection: lessons learned, self-awareness, growth insights
- other: anything that doesn't fit above

Return JSON array:
[{"category":"preference","text":"user prefers concise communication","importance":0.8},...]

Text to analyze:
`;

const SUMMARY_PROMPT = `Summarize the following text into a concise memory (max 100 chars):
`;

/**
 * Call LLM to extract memories from text
 * @param {string} text - Raw text to analyze
 * @param {Function} llmCall - LLM API function (text → response text)
 * @param {number} [timeoutMs=8000]
 * @returns {Promise<Array>}
 */
export async function extractMemories(text, llmCall, timeoutMs = 8000) {
  if (!text || !text.trim()) return [];
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const response = await llmCall(text, { prompt: EXTRACT_PROMPT, signal: controller.signal });
    clearTimeout(timer);
    let parsed = typeof response === 'string' ? JSON.parse(response) : response;
    if (!Array.isArray(parsed)) parsed = [];
    return parsed
      .filter(m => m.text && CATEGORIES.includes(m.category))
      .map(m => ({
        category: m.category,
        text: String(m.text).slice(0, 200),
        importance: Math.max(0, Math.min(1, parseFloat(m.importance) || 0.5)),
        extractedFrom: 'llm',
        createdAt: Date.now(),
      }));
  } catch (e) {
    clearTimeout(timer);
    if (e.name === 'AbortError') throw new Error('LLM extraction timeout');
    // Fallback: treat as single 'other' memory
    return [{
      category: 'other',
      text: String(text).slice(0, 200),
      importance: 0.3,
      extractedFrom: 'fallback',
      createdAt: Date.now(),
    }];
  }
}

/**
 * Batch extract from multiple texts
 * @param {string[]} texts
 * @param {Function} llmCall
 * @param {Function} [onProgress]
 */
export async function batchExtract(texts, llmCall, onProgress) {
  const results = [];
  for (let i = 0; i < texts.length; i++) {
    const extracted = await extractMemories(texts[i], llmCall);
    results.push(...extracted);
    if (onProgress) onProgress(i + 1, texts.length);
  }
  return results;
}

export default { extractMemories, batchExtract, CATEGORIES };
/**
 * RRF (Reciprocal Rank Fusion) - 混合 BM25 和向量搜索结果
 *
 * v3.0: 使用 vector_lancedb.js (LanceDB 持久化存储 + Ollama HTTP embedding)
 *       替代旧的 vector.js (Transformers.js 本地模型，每次都重新 embed 全量数据)
 * v3.1: 加入 rerank() 多信号重排 (keyword/entity/importance/recency/scope)
 */

import { config } from './config.js';
import { bm25Search } from './bm25.js';
import { vectorSearch } from './vector_lancedb.js';
import { rerank } from './rerank.js';

/**
 * Reciprocal Rank Fusion
 * @param {Array<{memory: object, score: number}>[]} resultLists
 * @param {number} [k=60]
 * @returns {Array<{memory: object, fusionScore: number, highlight: string}>}
 */
function reciprocalRankFusion(resultLists, k = 60) {
  const scores = new Map();

  for (const results of resultLists) {
    for (let i = 0; i < results.length; i++) {
      const mem = results[i].memory;
      const memId = mem.id;
      const rank = i + 1;
      const rrfScore = 1 / (k + rank);

      if (scores.has(memId)) {
        scores.get(memId).fusionScore += rrfScore;
      } else {
        scores.set(memId, {
          memory: mem,
          fusionScore: rrfScore,
          highlight: results[i].highlight || mem.text?.slice(0, 150),
        });
      }
    }
  }

  return Array.from(scores.values()).sort((a, b) => b.fusionScore - a.fusionScore);
}

/**
 * Hybrid search: BM25 + Vector with RRF fusion
 *
 * @param {string} query
 * @param {number} [topK=10]
 * @param {string} [mode='hybrid'] - 'hybrid', 'bm25', 'vector'
 * @param {string} [scope=null] - AGENT, USER, TEAM, GLOBAL
 * @returns {Promise<Array>}
 */
export async function hybridSearch(query, topK = 10, mode = 'hybrid', scope = null) {
  const k = config.rrfK || 60;
  const vectorEnabled = config.vectorEngine !== 'none';

  if (mode === 'bm25') {
    const results = bm25Search(query, topK * 2, scope);
    const mapped = results.map((r, i) => ({
      memory: r.memory,
      fusionScore: 1 / (k + i + 1),
      highlight: r.highlight,
      bm25Score: r.score,
    }));
    return rerank(query, mapped, { topK });
  }

  if (mode === 'vector') {
    if (!vectorEnabled) {
      // Fall back to BM25 when vector is disabled
      return hybridSearch(query, topK, 'bm25', scope);
    }
    const results = await vectorSearch(query, topK * 2, scope);
    const mapped = results.map((r, i) => ({
      memory: r.memory,
      fusionScore: 1 / (k + i + 1),
      highlight: r.highlight,
      vectorScore: r.score,
    }));
    return rerank(query, mapped, { topK });
  }

  // Hybrid: BM25 + Vector RRF (or BM25-only when vector disabled)
  let bm25Results, vectorResults;
  if (vectorEnabled) {
    [bm25Results, vectorResults] = await Promise.all([
      bm25Search(query, topK * 2, scope),
      vectorSearch(query, topK * 2, scope),
    ]);
  } else {
    bm25Results = bm25Search(query, topK * 2, scope);
    vectorResults = [];
  }

  const fused = reciprocalRankFusion([bm25Results, vectorResults], k);
  const preRerank = fused.slice(0, topK).map((r) => ({
    ...r,
    highlight: r.highlight || r.memory.text?.slice(0, 150),
  }));

  // v3.1: Re-rank using keyword overlap, entity match, recency, importance, scope
  const reranked = rerank(query, preRerank, { topK });
  // Normalize: use score (alias of rerankScore) for consistent API
  return reranked.map(r => ({
    ...r,
    score: r.rerankScore ?? r.score ?? r.fusionScore,
    fusionScore: r.fusionScore ?? r.score,
  }));
}
/**
 * git_notes.js - Enhanced Git Notes Integration for Permanent Knowledge Storage
 *
 * Stores decisions, learnings, and context as git notes attached to commits.
 * Branch-aware: tracks which branch notes were created on.
 *
 * Data structure stored in notes/refs:
 * {
 *   commit: string,
 *   category: 'decision' | 'learning' | 'context',
 *   content: string,
 *   branch: string,
 *   created_at: string,
 *   tags: string[]
 * }
 *
 * @module git_notes
 */

import { execSync, exec } from 'child_process';
import { existsSync } from 'fs';
import { join } from 'path';
import { fileURLToPath } from 'url';

const __dirname = join(fileURLToPath(import.meta.url), '..');
const WORKSPACE = process.env.HOME || '/root';

// ============================================================================
// Types
// ============================================================================

/**
 * @typedef {Object} GitNote
 * @property {string} commit
 * @property {string} category  // 'decision', 'learning', 'context'
 * @property {string} content
 * @property {string} branch
 * @property {string} created_at
 * @property {string[]} tags
 */

// ============================================================================
// Git Helpers
// ============================================================================

/**
 * Run a git command, return stdout or throw
 * @param {string[]} args
 * @param {string} [cwd]
 * @returns {string}
 */
function gitExec(args, cwd = WORKSPACE) {
  const cmd = ['git', ...args];
  try {
    return execSync(cmd.join(' '), {
      cwd,
      encoding: 'utf8',
      stdio: ['pipe', 'pipe', 'pipe'],
    }).trim();
  } catch (err) {
    throw new Error(`Git error: ${err.stderr || err.message}`);
  }
}

/**
 * Check if we're in a git repo
 * @returns {boolean}
 */
function isGitRepo(cwd = WORKSPACE) {
  try {
    execSync('git rev-parse --git-dir', { cwd, stdio: 'pipe' });
    return true;
  } catch {
    return false;
  }
}

/**
 * Get current branch name
 * @param {string} [cwd]
 * @returns {string}
 */
function getCurrentBranch(cwd = WORKSPACE) {
  try {
    return gitExec(['branch', '--show-current'], cwd);
  } catch {
    return 'unknown';
  }
}

/**
 * Get the default notes ref name (without "refs/notes/")
 */
const NOTES_REF = 'memory';

// ============================================================================
// Note Serialization
// ============================================================================

/**
 * Build a structured note object
 * @param {string} commitHash
 * @param {string} content
 * @param {string} [category]
 * @param {string[]} [tags]
 * @returns {GitNote}
 */
function buildNote(commitHash, content, category = 'context', tags = []) {
  return {
    commit: commitHash,
    category,
    content,
    branch: getCurrentBranch(),
    created_at: new Date().toISOString(),
    tags,
  };
}

/**
 * Serialize a GitNote to string for storing in git note
 * @param {GitNote} note
 * @returns {string}
 */
function serializeNote(note) {
  return JSON.stringify(note);
}

/**
 * Deserialize a note from git note content
 * @param {string} raw
 * @returns {GitNote|null}
 */
function deserializeNote(raw) {
  try {
    const note = JSON.parse(raw);
    if (!note.commit || !note.content) return null;
    return note;
  } catch {
    return null;
  }
}

// ============================================================================
// Core Git Notes Operations
// ============================================================================

/**
 * Add a decision note to a commit
 * @param {string} commitHash - Target commit hash (or 'HEAD' for current)
 * @param {string} decision - Decision text
 * @param {string} [category='decision'] - Category: decision, learning, context
 * @returns {Promise<string>} - The commit hash the note was attached to
 */
export async function addDecisionNote(commitHash, decision, category = 'decision') {
  if (!isGitRepo()) {
    throw new Error('Not a git repository');
  }

  const note = buildNote(commitHash, decision, category);
  const noteContent = serializeNote(note);

  // Use git notes add with -m flag for inline content
  try {
    gitExec(['notes', '--ref', NOTES_REF, 'add', commitHash, '-f', '-m', noteContent]);
  } catch (err) {
    // If note already exists and -f didn't work, try removing first
    try {
      gitExec(['notes', '--ref', NOTES_REF, 'remove', commitHash]);
    } catch {
      // Ignore remove errors
    }
    gitExec(['notes', '--ref', NOTES_REF, 'add', commitHash, '-m', noteContent]);
  }

  return commitHash;
}

/**
 * Show the note attached to a commit
 * @param {string} commitHash
 * @returns {Promise<string|null>} - Note content or null if no note
 */
export async function showNote(commitHash) {
  if (!isGitRepo()) {
    return null;
  }

  try {
    const raw = gitExec(['notes', '--ref', NOTES_REF, 'show', commitHash]);
    const note = deserializeNote(raw);
    return note ? note.content : raw;
  } catch {
    return null;
  }
}

/**
 * List all notes, optionally filtered by category
 * @param {{ category?: string, limit?: number }} [options]
 * @returns {Promise<Array<{commit: string, note: string, category?: string, created_at: string}>>}
 */
export async function listNotes(options = {}) {
  const { category, limit = 100 } = options;

  if (!isGitRepo()) {
    return [];
  }

  try {
    // Get list of all commits that have notes
    const output = gitExec(['notes', '--ref', NOTES_REF, 'list']);
    if (!output) return [];

    const lines = output.split('\n').filter(Boolean).slice(0, limit);
    const results = [];

    for (const line of lines) {
      // Format: "<commit hash>\n<note content>"
      const parts = line.split(/\s+/);
      const commitHash = parts[0];

      try {
        const raw = gitExec(['notes', '--ref', NOTES_REF, 'show', commitHash]);
        const note = deserializeNote(raw);

        if (note) {
          // Filter by category if specified
          if (category && note.category !== category) continue;

          results.push({
            commit: note.commit,
            note: note.content,
            category: note.category,
            created_at: note.created_at,
            branch: note.branch,
            tags: note.tags || [],
          });
        } else {
          // Raw note (no structured format)
          results.push({
            commit: commitHash,
            note: raw,
            created_at: new Date().toISOString(),
          });
        }
      } catch {
        // Skip commits with unreadable notes
      }
    }

    return results;
  } catch {
    return [];
  }
}

/**
 * Add a tag to an existing note on a commit
 * @param {string} commitHash
 * @param {string} tag
 * @returns {Promise<void>}
 */
export async function tagNote(commitHash, tag) {
  if (!isGitRepo()) {
    throw new Error('Not a git repository');
  }

  // Get existing note
  let note;
  try {
    const raw = gitExec(['notes', '--ref', NOTES_REF, 'show', commitHash]);
    note = deserializeNote(raw);
  } catch {
    throw new Error(`No note found on commit ${commitHash}`);
  }

  if (!note) {
    throw new Error(`No structured note found on commit ${commitHash}`);
  }

  // Add tag if not already present
  if (!note.tags) note.tags = [];
  if (!note.tags.includes(tag)) {
    note.tags.push(tag);
  }

  // Update the note
  const noteContent = serializeNote(note);
  try {
    gitExec(['notes', '--ref', NOTES_REF, 'remove', commitHash]);
  } catch {
    // Ignore
  }
  gitExec(['notes', '--ref', NOTES_REF, 'add', commitHash, '-m', noteContent]);
}

/**
 * Get all notes grouped by branch
 * @returns {Promise<Array<{branch: string, notes: GitNote[]}>>}
 */
export async function getBranchNotes() {
  if (!isGitRepo()) {
    return [];
  }

  const allNotes = await listNotes({ limit: 500 });
  const branchMap = new Map();

  for (const note of allNotes) {
    const branch = note.branch || 'unknown';
    if (!branchMap.has(branch)) {
      branchMap.set(branch, []);
    }
    branchMap.get(branch).push(note);
  }

  return Array.from(branchMap.entries()).map(([branch, notes]) => ({
    branch,
    notes,
  }));
}

/**
 * Search notes content for a query string
 * @param {string} query
 * @returns {Promise<GitNote[]>}
 */
export async function searchNotes(query) {
  if (!isGitRepo()) {
    return [];
  }

  const allNotes = await listNotes({ limit: 500 });
  const lowerQuery = query.toLowerCase();

  return allNotes.filter(note => {
    const contentMatch = note.note?.toLowerCase().includes(lowerQuery);
    const tagMatch = note.tags?.some(t => t.toLowerCase().includes(lowerQuery));
    const categoryMatch = note.category?.toLowerCase().includes(lowerQuery);
    return contentMatch || tagMatch || categoryMatch;
  });
}

// ============================================================================
// MCP Tool Handler
// ============================================================================

/**
 * Handle memory_git_notes MCP tool calls
 * @param {object} args
 * @param {string} [args.action] - add|show|list|tag|branch_notes|search
 * @param {string} [args.commit_hash] - Commit hash (for add|show|tag)
 * @param {string} [args.decision] - Decision text (for add)
 * @param {string} [args.category] - Category (for add, default: decision)
 * @param {string} [args.tag] - Tag to add (for tag action)
 * @param {string} [args.query] - Search query (for search action)
 * @param {number} [args.limit] - Max results (for list, default: 100)
 * @returns {Promise<{content: Array<{type: string, text: string}>, isError?: boolean}>}
 */
export async function memoryGitNotesTool(args) {
  const { action } = args;

  try {
    // Handle non-async actions first
    if (!isGitRepo()) {
      return {
        content: [{ type: 'text', text: JSON.stringify({ error: 'Not a git repository', hint: 'Initialize git in the workspace to use git notes' }) }],
        isError: true,
      };
    }

    switch (action) {
      case 'add': {
        if (!args.commit_hash) {
          return { content: [{ type: 'text', text: 'Error: commit_hash is required for add action' }], isError: true };
        }
        if (!args.decision) {
          return { content: [{ type: 'text', text: 'Error: decision is required for add action' }], isError: true };
        }
        const commitHash = await addDecisionNote(args.commit_hash, args.decision, args.category || 'decision');
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({
              success: true,
              commit: commitHash,
              category: args.category || 'decision',
              branch: getCurrentBranch(),
              created_at: new Date().toISOString(),
            }),
          }],
        };
      }

      case 'show': {
        if (!args.commit_hash) {
          return { content: [{ type: 'text', text: 'Error: commit_hash is required for show action' }], isError: true };
        }
        const note = await showNote(args.commit_hash);
        if (!note) {
          return { content: [{ type: 'text', text: JSON.stringify({ commit: args.commit_hash, note: null, message: 'No note found on this commit' }) }] };
        }
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({
              commit: args.commit_hash,
              note,
              category: 'context',
              branch: getCurrentBranch(),
            }),
          }],
        };
      }

      case 'list': {
        const notes = await listNotes({ category: args.category, limit: args.limit || 100 });
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({
              count: notes.length,
              current_branch: getCurrentBranch(),
              notes,
            }, null, 2),
          }],
        };
      }

      case 'tag': {
        if (!args.commit_hash) {
          return { content: [{ type: 'text', text: 'Error: commit_hash is required for tag action' }], isError: true };
        }
        if (!args.tag) {
          return { content: [{ type: 'text', text: 'Error: tag is required for tag action' }], isError: true };
        }
        await tagNote(args.commit_hash, args.tag);
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({
              success: true,
              commit: args.commit_hash,
              tag: args.tag,
              message: `Tag '${args.tag}' added to note on ${args.commit_hash}`,
            }),
          }],
        };
      }

      case 'branch_notes': {
        const branchNotes = await getBranchNotes();
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({
              current_branch: getCurrentBranch(),
              branches: branchNotes,
            }, null, 2),
          }],
        };
      }

      case 'search': {
        if (!args.query) {
          return { content: [{ type: 'text', text: 'Error: query is required for search action' }], isError: true };
        }
        const results = await searchNotes(args.query);
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({
              query: args.query,
              count: results.length,
              results,
            }, null, 2),
          }],
        };
      }

      default:
        return {
          content: [{ type: 'text', text: `Error: Unknown action '${action}'. Valid actions: add, show, list, tag, branch_notes, search` }],
          isError: true,
        };
    }
  } catch (err) {
    return { content: [{ type: 'text', text: `Git notes error [${action}]: ${err.message}` }], isError: true };
  }
}

export default { memoryGitNotesTool };
/**
 * importance_scorer.js - Dynamic importance scoring based on multiple signals
 *
 * Combines multiple signals into a final importance score (0-1):
 *   - Static importance (user-provided at store time)
 *   - Utility score (usageCount / retrievalCount — how often memory is actually used)
 *   - Recency boost (memories from last 7 days get +0.1)
 *   - Reference boost (memories frequently cited by other memories get +0.1)
 *   - Category weight boost (PREFERENCE=0.2, FACT=0.15, DECISION=0.25, others=0.1)
 *
 * Formula:
 *   finalImportance =
 *     (static * 0.3) +
 *     (utility * 0.4) +
 *     (recency * 0.1) +
 *     (reference * 0.1) +
 *     (categoryWeight * 0.1)
 *
 * All components are 0-1 range; final clamped to [0, 1].
 */

import { config } from './config.js';
import { getUsageStats, getUsageStatsBulk } from './usage_tracker.js';

// ─── Default weights (can be overridden via config) ───────────────────────────

const DEFAULT_WEIGHTS = {
  static: 0.3,
  utility: 0.4,
  recency: 0.1,
  reference: 0.1,
  category: 0.1,
};

// ─── Category base weights ───────────────────────────────────────────────────

const CATEGORY_BASE_WEIGHTS = {
  preference: 0.2,
  decision: 0.25,
  fact: 0.15,
  entity: 0.1,
  reflection: 0.1,
  other: 0.1,
};

// ─── Recency window in ms (7 days) ─────────────────────────────────────────
const RECENCY_WINDOW_MS = 7 * 24 * 60 * 60 * 1000;

// ─── Reference counting (cross-memory citations) ─────────────────────────────
// We track how many other memories reference each memory via a simple
// in-memory map. Updated by storage.js when memories are stored/linked.

/** @type {Map<string, number>} memoryId -> reference count */
const referenceCounts = new Map();

/**
 * Increment the reference count for a target memory.
 * Called when one memory references another (e.g., in reflection/lessons).
 * @param {string} memoryId
 * @param {number} [delta=1]
 */
export function incrementReference(memoryId, delta = 1) {
  const current = referenceCounts.get(memoryId) || 0;
  referenceCounts.set(memoryId, current + delta);
}

/**
 * Get the reference count for a memory.
 * @param {string} memoryId
 * @returns {number}
 */
export function getReferenceCount(memoryId) {
  return referenceCounts.get(memoryId) || 0;
}

// ─── Component calculators ─────────────────────────────────────────────────

/**
 * Get the recency signal for a memory.
 * @param {object} memory - Memory object with created_at field
 * @returns {number} 0-1; 1 if created within last 7 days, 0 otherwise
 */
function getRecencySignal(memory) {
  const age = Date.now() - (memory.created_at || memory.timestamp || Date.now());
  return age <= RECENCY_WINDOW_MS ? 1 : 0;
}

/**
 * Get the reference signal for a memory.
 * Reference boost is 1 if memory has been cited by >= 2 other memories.
 * @param {string} memoryId
 * @returns {number} 0-1
 */
function getReferenceSignal(memoryId) {
  const count = referenceCounts.get(memoryId) || 0;
  return count >= 2 ? 1 : (count >= 1 ? 0.5 : 0);
}

/**
 * Get the category weight signal.
 * @param {string} category
 * @returns {number} 0-1
 */
function getCategorySignal(category) {
  const base = CATEGORY_BASE_WEIGHTS[category?.toLowerCase()] ?? CATEGORY_BASE_WEIGHTS.other;
  return base; // Already 0-1 scaled
}

/**
 * Get the utility score from usage stats.
 * @param {object|null} usageStats
 * @returns {number} 0-1
 */
function getUtilitySignal(usageStats) {
  if (!usageStats) return 0;
  // utilityScore is precomputed as usageCount/retrievalCount
  return typeof usageStats.utilityScore === 'number'
    ? usageStats.utilityScore
    : 0;
}

/**
 * Get the manual boost signal.
 * @param {object|null} usageStats
 * @returns {number} 0-1
 */
function getManualBoostSignal(usageStats) {
  if (!usageStats) return 0;
  return typeof usageStats.manualBoost === 'number' ? usageStats.manualBoost : 0;
}

// ─── Main scorer ────────────────────────────────────────────────────────────

/**
 * Get the dynamic importance score for a single memory.
 *
 * @param {object} memory - Memory object with: id, importance (static), category, created_at
 * @param {object} [usageStats] - Optional pre-fetched usage stats
 * @returns {{ finalImportance: number, breakdown: object }}
 */
export function scoreMemory(memory, usageStats = null) {
  const weights = config.importanceWeights || DEFAULT_WEIGHTS;

  // 1. Static importance (user-provided at store time)
  const staticImportance = typeof memory.importance === 'number'
    ? Math.max(0, Math.min(1, memory.importance))
    : 0.5;

  // 2. Utility signal (from usage tracker)
  const stats = usageStats !== null ? usageStats : getUsageStats(memory.id);
  const utility = getUtilitySignal(stats);

  // 3. Recency signal
  const recency = getRecencySignal(memory);

  // 4. Reference signal
  const reference = getReferenceSignal(memory.id);

  // 5. Category weight signal
  const categoryWeight = getCategorySignal(memory.category);

  // 6. Manual boost (override/additive)
  const manualBoost = getManualBoostSignal(stats);

  // Final formula
  const raw = (
    (staticImportance * weights.static) +
    (utility * weights.utility) +
    (recency * weights.recency) +
    (reference * weights.reference) +
    (categoryWeight * weights.category)
  );

  // Apply manual boost additively after formula, then clamp
  const withBoost = Math.max(0, Math.min(1, raw + manualBoost * 0.1));

  return {
    finalImportance: withBoost,
    breakdown: {
      static: {
        value: staticImportance,
        weight: weights.static,
        contribution: staticImportance * weights.static,
      },
      utility: {
        value: utility,
        weight: weights.utility,
        contribution: utility * weights.utility,
        retrievalCount: stats?.retrievalCount || 0,
        usageCount: stats?.usageCount || 0,
      },
      recency: {
        value: recency,
        weight: weights.recency,
        contribution: recency * weights.recency,
        ageDays: memory.created_at
          ? Math.round((Date.now() - memory.created_at) / (24 * 60 * 60 * 1000))
          : null,
      },
      reference: {
        value: reference,
        weight: weights.reference,
        contribution: reference * weights.reference,
        referenceCount: referenceCounts.get(memory.id) || 0,
      },
      category: {
        value: categoryWeight,
        weight: weights.category,
        contribution: categoryWeight * weights.category,
        category: memory.category,
      },
      manualBoost: {
        value: manualBoost,
        contribution: manualBoost * 0.1,
      },
      rawScore: Math.round(raw * 1000) / 1000,
      finalScore: Math.round(withBoost * 1000) / 1000,
    },
  };
}

/**
 * Score multiple memories efficiently (batch).
 * @param {object[]} memories - Array of memory objects
 * @returns {Map<string, { finalImportance: number, breakdown: object }>}
 */
export function scoreMemories(memories) {
  const memoryIds = memories.map(m => m.id);
  const statsMap = getUsageStatsBulk(memoryIds);
  const weights = config.importanceWeights || DEFAULT_WEIGHTS;

  const results = new Map();
  for (const memory of memories) {
    const stats = statsMap.get(memory.id) || null;
    results.set(memory.id, scoreMemory(memory, stats));
  }
  return results;
}

/**
 * Get importance boost factor for search pipeline.
 * Returns: (dynamicImportance - 0.5) * 0.4
 * This is used to boost RRF scores: boostedScore = rrfScore * (1 + importanceBoost)
 *
 * @param {string} memoryId
 * @param {number} [staticImportance=0.5]
 * @param {string} [category='other']
 * @param {number} [createdAt]
 * @returns {number} boost factor (can be negative)
 */
export function getImportanceBoost(memoryId, staticImportance = 0.5, category = 'other', createdAt = null) {
  const stats = getUsageStats(memoryId);
  const { finalImportance } = scoreMemory(
    { id: memoryId, importance: staticImportance, category, created_at: createdAt },
    stats
  );
  const boost = (finalImportance - 0.5) * 0.4;
  return boost;
}

/**
 * Explain why a memory has its current importance score.
 * Returns a human-readable breakdown.
 *
 * @param {object} memory - Memory object
 * @returns {object} breakdown object
 */
export function explainImportance(memory) {
  const stats = getUsageStats(memory.id);
  const { finalImportance, breakdown } = scoreMemory(memory, stats);
  return {
    memoryId: memory.id,
    finalImportance: Math.round(finalImportance * 1000) / 1000,
    breakdown,
    usageStats: stats ? {
      retrievalCount: stats.retrievalCount,
      usageCount: stats.usageCount,
      utilityScore: Math.round((stats.utilityScore || 0) * 1000) / 1000,
      lastRetrieved: stats.lastRetrieved ? new Date(stats.lastRetrieved).toISOString() : null,
      lastUsed: stats.lastUsed ? new Date(stats.lastUsed).toISOString() : null,
    } : null,
  };
}
