/**
 * Intent Router - classify query type and routing strategy
 * Returns null → skip retrieval; returns strategy object → proceed
 */
export const INTENT_TYPES = {
  FACT: 'fact',       // who/when/where/what questions
  PREFERENCE: 'preference', // likes/dislikes
  DECISION: 'decision',   // why/why not/why chose
  ENTITY: 'entity',      // tell me about X
  REFLECTION: 'reflection', // lessons/learned/growth
  RECALL: 'recall',       // remember/past/earlier
  METRIC: 'metric',       // stats/numbers/counts
  SKIP: 'skip',           // non-retrieval
};

const ROUTING_RULES = [
  // FACT patterns
  { pattern: /^(who|what|when|where|which)\s+(is|are|was|were|do|does|did|have|has)\s+/i, intent: 'fact' },
  { pattern: /\?$/, intent: 'fact' },
  // PREFERENCE patterns
  { pattern: /(prefer|like|hate|dislike|enjoy|avoid|love|cannot\s+stand)/i, intent: 'preference' },
  // DECISION patterns
  { pattern: /(decide|chose|choose|decision|reason|because|why\s+(did|didn|not))/i, intent: 'decision' },
  // ENTITY patterns
  { pattern: /^tell\s+me\s+about/i, intent: 'entity' },
  { pattern: /^(who\s+is|what\s+is|explain|describe)\s+.{0,30}$/i, intent: 'entity' },
  // REFLECTION patterns
  { pattern: /(learn|lesson|reflect|realize|discover|understand bett)/i, intent: 'reflection' },
  // RECALL patterns (force retrieval)
  { pattern: /(remember|recall|earlier|before|previously|once|曾|记得|之前)/i, intent: 'recall' },
  // METRIC patterns
  { pattern: /(how\s+many|how\s+much|count|total|number\s+of|stats?)/i, intent: 'metric' },
  // SKIP patterns
  { pattern: /^(ok|okay|thanks?|bye|good|great|yes|no|好|好的|再见)/i, intent: 'skip' },
  { pattern: /^[\p{Emoji_Presentation}\p{Extended_Pictographic}]$/u, intent: 'skip' },
];

/**
 * Route a search query to appropriate retrieval strategy
 * @param {string} query
 * @returns {{ intent: string, categories: string[], skip: boolean, strategy: object } | null}
 */
export function routeSearch(query) {
  const q = String(query || '').trim();
  if (!q) return { intent: 'skip', skip: true, categories: [], strategy: {} };

  // Check skip patterns first
  for (const rule of ROUTING_RULES) {
    if (rule.pattern.test(q) && rule.intent === 'skip') {
      return { intent: 'skip', skip: true, categories: [], strategy: {} };
    }
  }

  // Determine primary intent
  let primaryIntent = 'other';
  const matchedCategories = [];

  for (const rule of ROUTING_RULES) {
    if (rule.pattern.test(q)) {
      if (rule.intent !== 'skip') {
        primaryIntent = rule.intent;
        matchedCategories.push(rule.intent);
      }
    }
  }

  // Force recall always needs retrieval
  if (primaryIntent === 'skip' && /(remember|recall|earlier|曾|记得)/i.test(q)) {
    return {
      intent: 'recall',
      skip: false,
      categories: ['preference', 'fact', 'decision', 'entity', 'reflection'],
      strategy: { boostRecent: true, expandScope: true },
    };
  }

  if (primaryIntent === 'skip') {
    return { intent: 'skip', skip: true, categories: [], strategy: {} };
  }

  // Build category filter based on intent
  const categoryMap = {
    fact: ['fact', 'entity'],
    preference: ['preference'],
    decision: ['decision', 'fact'],
    entity: ['entity', 'fact'],
    reflection: ['reflection', 'decision'],
    recall: ['preference', 'fact', 'decision', 'entity', 'reflection'],
    metric: ['fact', 'preference'],
    other: ['preference', 'fact', 'decision', 'entity', 'reflection', 'other'],
  };

  return {
    intent: primaryIntent,
    skip: false,
    categories: categoryMap[primaryIntent] || categoryMap.other,
    strategy: {
      boostRecent: primaryIntent === 'recall',
      expandScope: primaryIntent === 'recall',
    },
  };
}

export default { routeSearch, getCategoryWeights, INTENT_TYPES };

export function getCategoryWeights(intent) {
  const defaults = { preference: 0.3, decision: 0.25, entity: 0.2, fact: 0.15, recent: 0.2, project: 0.25 };
  const map = new Map();
  if (intent === 'general' || !intent) {
    Object.entries(defaults).forEach(([k, v]) => map.set(k, v));
  } else {
    Object.entries(defaults).forEach(([k, v]) => map.set(k, v * 0.5));
    map.set(intent, 0.8);
  }
  return map;
}
/**
 * Lane Manager Enhanced - Deep Memory Lane Integration
 * Complete lane-based memory management with advanced features
 * 
 * Storage: ~/.openclaw/workspace/memory/lanes.json
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const HOME = process.env.HOME || '/root';
const MEMORY_DIR = join(HOME, '.openclaw', 'workspace', 'memory');
const LANES_FILE = join(MEMORY_DIR, 'lanes.json');

// Ensure memory directory exists
if (!existsSync(MEMORY_DIR)) {
  mkdirSync(MEMORY_DIR, { recursive: true });
}

// ============================================================================
// Types
// ============================================================================

/**
 * @typedef {Object} Lane
 * @property {string} name - Lane name (unique identifier)
 * @property {string} description - Lane description
 * @property {boolean} isActive - Whether this is the current active lane
 * @property {number} memoryCount - Number of memories in this lane
 * @property {string} createdAt - ISO timestamp of creation
 * @property {string|null} archivedAt - ISO timestamp when archived, null if not archived
 * @property {string[]} tags - Lane tags
 * @property {Object} metadata - Additional metadata
 */

/**
 * @typedef {Object} Memory
 * @property {string} id - Memory unique ID
 * @property {string} text - Memory content
 * @property {string} lane - Lane this memory belongs to
 * @property {string} category - Memory category
 * @property {number} importance - Importance score 0-1
 * @property {string[]} tags - Tags
 * @property {string} created_at - ISO timestamp
 * @property {string} transcript_id - Source transcript ID
 * @property {number} message_index - Message index in transcript
 */

// ============================================================================
// Default Lanes
// ============================================================================

const DEFAULT_LANES = [
  {
    name: 'primary',
    description: 'Main conversation lane',
    isActive: true,
    memoryCount: 0,
    createdAt: new Date().toISOString(),
    archivedAt: null,
    tags: ['main', 'conversation'],
    metadata: {}
  },
  {
    name: 'task',
    description: 'Current task focus',
    isActive: false,
    memoryCount: 0,
    createdAt: new Date().toISOString(),
    archivedAt: null,
    tags: ['task', 'active'],
    metadata: {}
  },
  {
    name: 'background',
    description: 'Long-running investigations',
    isActive: false,
    memoryCount: 0,
    createdAt: new Date().toISOString(),
    archivedAt: null,
    tags: ['investigation', 'long-term'],
    metadata: {}
  },
  {
    name: 'archive',
    description: 'Completed/archived threads',
    isActive: false,
    memoryCount: 0,
    createdAt: new Date().toISOString(),
    archivedAt: null,
    tags: ['archive', 'completed'],
    metadata: {}
  }
];

// ============================================================================
// Core Functions
// ============================================================================

/**
 * Load lanes from file
 */
function loadLanes() {
  if (!existsSync(LANES_FILE)) {
    saveLanes({ lanes: DEFAULT_LANES, active_lane: 'primary' });
    return { lanes: DEFAULT_LANES, active_lane: 'primary' };
  }
  
  const data = readFileSync(LANES_FILE, 'utf-8');
  return JSON.parse(data);
}

/**
 * Save lanes to file
 */
function saveLanes(data) {
  mkdirSync(dirname(LANES_FILE), { recursive: true });
  writeFileSync(LANES_FILE, JSON.stringify(data, null, 2), 'utf-8');
}

/**
 * Create a new lane
 */
export function createLane(name, description = '', tags = [], metadata = {}) {
  const lanesData = loadLanes();
  
  if (lanesData.lanes.some(l => l.name === name)) {
    throw new Error(`Lane '${name}' already exists`);
  }
  
  // Deactivate other lanes
  lanesData.lanes.forEach(lane => {
    lane.isActive = lane.name === lanesData.active_lane;
  });
  
  const newLane = {
    name,
    description,
    isActive: true,
    memoryCount: 0,
    createdAt: new Date().toISOString(),
    archivedAt: null,
    tags,
    metadata
  };
  
  lanesData.lanes.push(newLane);
  lanesData.active_lane = name;
  
  saveLanes(lanesData);
  return newLane;
}

/**
 * Switch to a lane
 */
export function switchLane(name) {
  const lanesData = loadLanes();
  const lane = lanesData.lanes.find(l => l.name === name);
  
  if (!lane) {
    throw new Error(`Lane '${name}' not found`);
  }
  
  // Deactivate other lanes
  lanesData.lanes.forEach(lane => {
    lane.isActive = false;
  });
  
  lane.isActive = true;
  lanesData.active_lane = name;
  
  saveLanes(lanesData);
  return lane;
}

/**
 * Get current active lane
 */
export function getCurrentLane() {
  const lanesData = loadLanes();
  return lanesData.lanes.find(l => l.name === lanesData.active_lane);
}

/**
 * List all lanes
 */
export function listLanes(includeArchived = false) {
  const lanesData = loadLanes();
  const lanes = includeArchived 
    ? lanesData.lanes 
    : lanesData.lanes.filter(l => !l.archivedAt);
  
  return lanes.map(lane => ({
    ...lane,
    memoryCount: lane.memoryCount || 0
  }));
}

/**
 * Move a memory between lanes
 */
export function moveMemory(memoryId, fromLane, toLane) {
  const lanesData = loadLanes();
  
  // Update memory counts
  const fromLaneObj = lanesData.lanes.find(l => l.name === fromLane);
  const toLaneObj = lanesData.lanes.find(l => l.name === toLane);
  
  if (fromLaneObj) fromLaneObj.memoryCount = Math.max(0, fromLaneObj.memoryCount - 1);
  if (toLaneObj) toLaneObj.memoryCount++;
  
  saveLanes(lanesData);
  
  return {
    success: true,
    memory_id: memoryId,
    from_lane: fromLane,
    to_lane: toLane
  };
}

/**
 * Archive a lane
 */
export function archiveLane(name) {
  const lanesData = loadLanes();
  const lane = lanesData.lanes.find(l => l.name === name);
  
  if (!lane) {
    throw new Error(`Lane '${name}' not found`);
  }
  
  lane.archivedAt = new Date().toISOString();
  lane.isActive = false;
  
  // Activate another lane if current is archived
  if (lanesData.active_lane === name) {
    const activeLane = lanesData.lanes.find(l => l.name !== name && !l.archivedAt);
    if (activeLane) {
      activeLane.isActive = true;
      lanesData.active_lane = name;
    }
  }
  
  saveLanes(lanesData);
  return lane;
}

/**
 * Get memories in a lane
 */
export function getLaneMemories(laneName) {
  // In a real implementation, this would query the memory store
  // For now, return metadata about the lane
  const lanesData = loadLanes();
  const lane = lanesData.lanes.find(l => l.name === laneName);
  
  return {
    lane: lane,
    memories: [], // Would be populated from memory store
    count: lane?.memoryCount || 0
  };
}

/**
 * Get lane statistics
 */
export function getLaneStats() {
  const lanesData = loadLanes();
  
  const totalMemories = lanesData.lanes.reduce((sum, lane) => sum + (lane.memoryCount || 0), 0);
  const activeLane = lanesData.lanes.find(l => l.name === lanesData.active_lane);
  
  return {
    total_lanes: lanesData.lanes.length,
    active_lane: activeLane?.name,
    total_memories: totalMemories,
    lanes: lanesData.lanes.map(lane => ({
      name: lane.name,
      memory_count: lane.memoryCount || 0,
      is_active: lane.name === lanesData.active_lane,
      is_archived: !!lane.archivedAt
    }))
  };
}

/**
 * Merge memories from one lane to another
 */
export function mergeLane(fromLane, toLane) {
  const lanesData = loadLanes();
  
  const fromLaneObj = lanesData.lanes.find(l => l.name === fromLane);
  const toLaneObj = lanesData.lanes.find(l => l.name === toLane);
  
  if (!fromLaneObj || !toLaneObj) {
    throw new Error('One or both lanes not found');
  }
  
  // Move memories
  toLaneObj.memoryCount = (toLaneObj.memoryCount || 0) + (fromLaneObj.memoryCount || 0);
  
  // Archive source lane
  fromLaneObj.archivedAt = new Date().toISOString();
  
  saveLanes(lanesData);
  
  return {
    success: true,
    merged_from: fromLane,
    merged_to: toLane,
    memory_count: toLaneObj.memoryCount
  };
}

/**
 * Delete a lane (after archiving)
 */
export function deleteLane(name) {
  const lanesData = loadLanes();
  lanesData.lanes = lanesData.lanes.filter(l => l.name !== name);
  saveLanes(lanesData);
  
  return { success: true, deleted: name };
}

/**
 * Get lane history
 */
export function getLaneHistory(laneName) {
  // In a real implementation, this would track lane changes
  return {
    lane: laneName,
    history: [] // Would be populated from history store
  };
}

/**
 * Lane memory tool - unified interface
 */
export function memoryLanesTool(action, params = {}) {
  try {
    switch (action) {
      case 'create':
        return createLane(params.lane_name, params.description, params.tags, params.metadata);
      
      case 'switch':
        return switchLane(params.lane_name);
      
      case 'current':
        return getCurrentLane();
      
      case 'list':
        return listLanes(params.include_archived);
      
      case 'move':
        return moveMemory(params.memory_id, params.from_lane, params.to_lane);
      
      case 'archive':
        return archiveLane(params.lane_name);
      
      case 'memories':
        return getLaneMemories(params.lane_name);
      
      case 'stats':
        return getLaneStats();
      
      case 'merge':
        return mergeLane(params.from_lane, params.to_lane);
      
      case 'delete':
        return deleteLane(params.lane_name);
      
      default:
        throw new Error(`Unknown action: ${action}`);
    }
  } catch (error) {
    return {
      success: false,
      error: error.message,
      action
    };
  }
}
/**
 * lanes_manager.js - Parallel Memory Lanes
 *
 * Multiple parallel "swim lanes" for different memory contexts.
 * Inspired by Smart Memory's memory lanes concept.
 *
 * Lanes:
 *   - primary: Main conversation lane
 *   - task: Current task focus
 *   - background: Long-running investigations
 *   - archive: Completed/archived threads
 *   - Custom lanes are configurable
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const HOME = process.env.HOME || '/root';
const MEMORY_DIR = join(HOME, '.openclaw', 'workspace', 'memory');
const LANES_FILE = join(MEMORY_DIR, 'lanes.json');

// Ensure memory directory exists
if (!existsSync(MEMORY_DIR)) {
  mkdirSync(MEMORY_DIR, { recursive: true });
}

// ============================================================================
// Types
// ============================================================================

/**
 * @typedef {Object} Lane
 * @property {string} name - Lane name (unique identifier)
 * @property {string} description - Lane description
 * @property {boolean} isActive - Whether this is the current active lane
 * @property {number} memoryCount - Number of memories in this lane
 * @property {string} createdAt - ISO timestamp of creation
 * @property {string|null} archivedAt - ISO timestamp when archived, null if not archived
 */

/**
 * @typedef {Object} Memory
 * @property {string} id - Memory unique ID
 * @property {string} text - Memory content
 * @property {string} lane - Lane this memory belongs to
 * @property {string} category - Memory category
 * @property {number} importance - Importance score 0-1
 * @property {string[]} tags - Tags
 * @property {string} created_at - ISO timestamp
 */

// ============================================================================
// Default Lanes
// ============================================================================

const DEFAULT_LANES = [
  {
    name: 'primary',
    description: 'Main conversation lane',
    isActive: true,
    memoryCount: 0,
    createdAt: new Date().toISOString(),
    archivedAt: null,
  },
  {
    name: 'task',
    description: 'Current task focus',
    isActive: false,
    memoryCount: 0,
    createdAt: new Date().toISOString(),
    archivedAt: null,
  },
  {
    name: 'background',
    description: 'Long-running investigations',
    isActive: false,
    memoryCount: 0,
    createdAt: new Date().toISOString(),
    archivedAt: null,
  },
  {
    name: 'archive',
    description: 'Completed/archived threads',
    isActive: false,
    memoryCount: 0,
    createdAt: new Date().toISOString(),
    archivedAt: null,
  },
];

// ============================================================================
// Storage Helpers
// ============================================================================

/**
 * Load lanes data from lanes.json
 * @returns {object}
 */
function loadLanesData() {
  try {
    if (!existsSync(LANES_FILE)) {
      return getDefaultLanesData();
    }
    const content = readFileSync(LANES_FILE, 'utf-8');
    const data = JSON.parse(content);
    return data;
  } catch (err) {
    console.error(`[lanes] Failed to load: ${err.message}`);
    return getDefaultLanesData();
  }
}

/**
 * Save lanes data to lanes.json
 * @param {object} data
 */
function saveLanesData(data) {
  try {
    writeFileSync(LANES_FILE, JSON.stringify(data, null, 2), 'utf-8');
  } catch (err) {
    console.error(`[lanes] Failed to save: ${err.message}`);
  }
}

/**
 * Get default lanes data structure
 * @returns {object}
 */
function getDefaultLanesData() {
  return {
    lanes: DEFAULT_LANES.map(l => ({ ...l })),
    memories: {},  // memoryId -> { lane, memoryId, addedAt }
    version: '1.0.0',
    updatedAt: new Date().toISOString(),
  };
}

/**
 * Recalculate memoryCount for all lanes based on memories map
 * @param {object} data
 */
function recalcMemoryCounts(data) {
  const counts = {};
  for (const [memId, memInfo] of Object.entries(data.memories || {})) {
    const lane = memInfo.lane;
    counts[lane] = (counts[lane] || 0) + 1;
  }
  for (const lane of data.lanes) {
    lane.memoryCount = counts[lane.name] || 0;
  }
}

// ============================================================================
// Lane Operations
// ============================================================================

/**
 * Create a new lane
 * @param {string} name - Lane name
 * @param {string} [description] - Lane description
 * @returns {Promise<Lane>}
 */
export async function createLane(name, description = '') {
  const data = loadLanesData();

  // Check if lane already exists
  const existing = data.lanes.find(l => l.name === name);
  if (existing) {
    throw new Error(`Lane '${name}' already exists`);
  }

  const lane = {
    name,
    description,
    isActive: false,
    memoryCount: 0,
    createdAt: new Date().toISOString(),
    archivedAt: null,
  };

  data.lanes.push(lane);
  data.updatedAt = new Date().toISOString();
  saveLanesData(data);

  return lane;
}

/**
 * Switch active lane
 * @param {string} laneName - Lane to switch to
 * @returns {Promise<void>}
 */
export async function switchLane(laneName) {
  const data = loadLanesData();

  const targetLane = data.lanes.find(l => l.name === laneName);
  if (!targetLane) {
    throw new Error(`Lane '${laneName}' not found`);
  }

  if (targetLane.archivedAt) {
    throw new Error(`Cannot switch to archived lane '${laneName}'`);
  }

  // Deactivate all lanes, activate target
  for (const lane of data.lanes) {
    lane.isActive = lane.name === laneName;
  }

  data.updatedAt = new Date().toISOString();
  saveLanesData(data);
}

/**
 * Get the current active lane
 * @returns {Promise<Lane|null>}
 */
export async function getCurrentLane() {
  const data = loadLanesData();
  recalcMemoryCounts(data);
  const active = data.lanes.find(l => l.isActive) || null;
  return active;
}

/**
 * List all lanes
 * @returns {Promise<Lane[]>}
 */
export async function listLanes() {
  const data = loadLanesData();
  recalcMemoryCounts(data);
  return data.lanes;
}

/**
 * Move a memory to a different lane
 * @param {string} memoryId - Memory ID to move
 * @param {string} laneName - Target lane name
 * @returns {Promise<void>}
 */
export async function moveToLane(memoryId, laneName) {
  const data = loadLanesData();

  // Verify target lane exists and is not archived
  const targetLane = data.lanes.find(l => l.name === laneName);
  if (!targetLane) {
    throw new Error(`Lane '${laneName}' not found`);
  }
  if (targetLane.archivedAt) {
    throw new Error(`Cannot move memory to archived lane '${laneName}'`);
  }

  // Check if memory exists in memories map
  const memInfo = data.memories[memoryId];
  if (!memInfo) {
    throw new Error(`Memory '${memoryId}' not found in any lane`);
  }

  // Update the memory's lane
  const oldLane = memInfo.lane;
  memInfo.lane = laneName;
  memInfo.movedAt = new Date().toISOString();

  data.updatedAt = new Date().toISOString();
  saveLanesData(data);
}

/**
 * Archive a lane and all its contents
 * @param {string} laneName - Lane to archive
 * @returns {Promise<void>}
 */
export async function archiveLane(laneName) {
  const data = loadLanesData();

  const lane = data.lanes.find(l => l.name === laneName);
  if (!lane) {
    throw new Error(`Lane '${laneName}' not found`);
  }

  if (lane.name === 'primary') {
    throw new Error(`Cannot archive the primary lane`);
  }

  if (lane.archivedAt) {
    throw new Error(`Lane '${laneName}' is already archived`);
  }

  // Archive the lane
  lane.archivedAt = new Date().toISOString();
  lane.isActive = false;

  // If this was the active lane, switch to primary
  if (lane.isActive) {
    const primaryLane = data.lanes.find(l => l.name === 'primary');
    if (primaryLane) {
      for (const l of data.lanes) {
        l.isActive = l.name === 'primary';
      }
    }
  }

  data.updatedAt = new Date().toISOString();
  saveLanesData(data);
}

/**
 * Get memories in a specific lane
 * @param {string} laneName - Lane name
 * @returns {Promise<Memory[]>}
 */
export async function getLaneMemories(laneName) {
  const data = loadLanesData();

  const lane = data.lanes.find(l => l.name === laneName);
  if (!lane) {
    throw new Error(`Lane '${laneName}' not found`);
  }

  // Get memory IDs in this lane
  const memoryIds = [];
  for (const [memId, memInfo] of Object.entries(data.memories || {})) {
    if (memInfo.lane === laneName) {
      memoryIds.push(memId);
    }
  }

  return memoryIds;
}

// ============================================================================
// Memory-Lane Association (for use by storage.js / other modules)
// ============================================================================

/**
 * Add a memory to a lane (called when storing new memory)
 * @param {string} memoryId - Memory ID
 * @param {string} [laneName] - Lane name (defaults to current active lane)
 * @returns {Promise<void>}
 */
export async function addMemoryToLane(memoryId, laneName = null) {
  const data = loadLanesData();

  // Default to current active lane if not specified
  if (!laneName) {
    const active = data.lanes.find(l => l.isActive);
    laneName = active ? active.name : 'primary';
  }

  // Verify lane exists
  const lane = data.lanes.find(l => l.name === laneName);
  if (!lane) {
    throw new Error(`Lane '${laneName}' not found`);
  }

  // Add memory to lane
  data.memories[memoryId] = {
    lane: laneName,
    memoryId,
    addedAt: new Date().toISOString(),
  };

  data.updatedAt = new Date().toISOString();
  saveLanesData(data);
}

/**
 * Remove a memory from its lane (called when deleting memory)
 * @param {string} memoryId - Memory ID to remove
 * @returns {Promise<void>}
 */
export async function removeMemoryFromLane(memoryId) {
  const data = loadLanesData();

  if (data.memories[memoryId]) {
    delete data.memories[memoryId];
    data.updatedAt = new Date().toISOString();
    saveLanesData(data);
  }
}

/**
 * Get which lane a memory belongs to
 * @param {string} memoryId - Memory ID
 * @returns {Promise<string|null>} Lane name or null if not found
 */
export async function getMemoryLane(memoryId) {
  const data = loadLanesData();
  const memInfo = data.memories[memoryId];
  return memInfo ? memInfo.lane : null;
}

/**
 * Get the lane assignment data (for inspection/debugging)
 * @returns {Promise<object>}
 */
export async function getLanesData() {
  return loadLanesData();
}

// ============================================================================
// MCP Tool Handler
// ============================================================================

/**
 * Handle memory_lanes MCP tool calls
 * @param {object} args
 * @param {string} [args.action]
 * @param {string} [args.name]
 * @param {string} [args.description]
 * @param {string} [args.lane_name]
 * @param {string} [args.memory_id]
 * @returns {Promise<{content: Array<{type: string, text: string}>, isError?: boolean}>}
 */
export async function memoryLanesTool(args) {
  const { action } = args;

  try {
    switch (action) {
      case 'create': {
        if (!args.name) {
          return { content: [{ type: 'text', text: 'Error: name is required' }], isError: true };
        }
        const lane = await createLane(args.name, args.description || '');
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({ success: true, lane }),
          }],
        };
      }

      case 'switch': {
        const laneName = args.name || args.lane_name;
        if (!laneName) {
          return { content: [{ type: 'text', text: 'Error: lane_name is required' }], isError: true };
        }
        await switchLane(laneName);
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({ success: true, message: `Switched to lane '${laneName}'` }),
          }],
        };
      }

      case 'current': {
        const lane = await getCurrentLane();
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({ current: lane }),
          }],
        };
      }

      case 'list': {
        const lanes = await listLanes();
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({ count: lanes.length, lanes }),
          }],
        };
      }

      case 'move': {
        if (!args.memory_id) {
          return { content: [{ type: 'text', text: 'Error: memory_id is required' }], isError: true };
        }
        const moveToLaneName = args.name || args.lane_name;
        if (!moveToLaneName) {
          return { content: [{ type: 'text', text: 'Error: lane_name is required' }], isError: true };
        }
        await moveToLane(args.memory_id, moveToLaneName);
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({ success: true, message: `Memory '${args.memory_id}' moved to lane '${moveToLaneName}'` }),
          }],
        };
      }

      case 'archive': {
        const archiveLaneName = args.name || args.lane_name;
        if (!archiveLaneName) {
          return { content: [{ type: 'text', text: 'Error: lane_name is required' }], isError: true };
        }
        await archiveLane(archiveLaneName);
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({ success: true, message: `Lane '${archiveLaneName}' archived` }),
          }],
        };
      }

      case 'memories': {
        const memLaneName = args.name || args.lane_name;
        if (!memLaneName) {
          return { content: [{ type: 'text', text: 'Error: lane_name is required' }], isError: true };
        }
        const memoryIds = await getLaneMemories(memLaneName);
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({ lane: memLaneName, count: memoryIds.length, memoryIds }),
          }],
        };
      }

      case 'data': {
        // Debug: return raw lanes data
        const data = await getLanesData();
        return {
          content: [{
            type: 'text',
            text: JSON.stringify(data, null, 2),
          }],
        };
      }

      default:
        return {
          content: [{ type: 'text', text: `Error: Unknown action '${action}'. Valid actions: create, switch, current, list, move, archive, memories, data` }],
          isError: true,
        };
    }
  } catch (err) {
    return { content: [{ type: 'text', text: `Lanes error: ${err.message}` }], isError: true };
  }
}

export default { memoryLanesTool };
/**
 * lesson.js — Lesson System MCP Adapter + Recall Tracking
 * 
 * Thin wrapper around lessons.js storage with added recall tracking.
 * - lessons.json: shared lesson storage (same format as lessons.js)
 * - lesson_access_log.json: tracks recall_count per lesson
 * 
 * MCP tool: memory_lessons (extract/recall/list/stats/delete/touch/candidates)
 */
import { readFileSync, writeFileSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const WORKSPACE = process.env.OPENCLAW_WORKSPACE_DIR ?? join(process.env.HOME ?? '/root', '.openclaw', 'workspace');
const SKILL_DIR = join(WORKSPACE, 'memory');
const LESSONS_FILE  = join(SKILL_DIR, 'lessons.json');
const ACCESS_FILE   = join(SKILL_DIR, 'lesson_access_log.json');

const LESSON_CANDIDATE_THRESHOLD = 5;
const MAX_LESSONS = 200;
const MAX_BODY_CHARS = 500;
const MAX_TITLE_CHARS = 120;

let lessonsCache = null, accessLogCache = null;

const load = (f, fallback) => {
  if (!existsSync(f)) return fallback;
  try { return JSON.parse(readFileSync(f, 'utf8')); } catch { return fallback; }
};
const save = (f, data) => {
  try { writeFileSync(f, JSON.stringify(data, null, 2), 'utf8'); } catch (e) { console.error('[lesson]', e.message); }
};

// Fixed: lessons.json is {lessons:[],version,lastUpdated}, not plain array
function getLessons() {
  if (lessonsCache !== null) return lessonsCache;
  const store = load(LESSONS_FILE, { lessons: [], version: '1.0', lastUpdated: Date.now() });
  lessonsCache = store.lessons || [];
  return lessonsCache;
}
function putLessons(lessons) {
  lessonsCache = lessons;
  save(LESSONS_FILE, { lessons, version: '1.0', lastUpdated: Date.now() });
}

function getLog() {
  if (accessLogCache !== null) return accessLogCache;
  accessLogCache = load(ACCESS_FILE, {});
  return accessLogCache;
}
function putLog(log) {
  accessLogCache = log;
  save(ACCESS_FILE, log);
}

/** Touch a lesson (increment its recall count) */
export function touchLesson(lessonId) {
  const log = getLog();
  if (!log[lessonId]) {
    log[lessonId] = { recall_count: 1, last_recall: Date.now(), created_at: Date.now() };
  } else {
    log[lessonId].recall_count++;
    log[lessonId].last_recall = Date.now();
  }
  putLog(log);
}

function generateId() {
  return `les_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`;
}

/** Create or update a lesson */
function upsertLesson(id, fields) {
  const lessons = getLessons();
  const idx = lessons.findIndex(l => l.id === id);
  const updated = { ...fields, id, updated_at: Date.now(), recall_count: idx >= 0 ? (lessons[idx].recall_count ?? 0) : 0 };
  if (idx >= 0) lessons[idx] = updated;
  else lessons.unshift(updated);
  if (lessons.length > MAX_LESSONS) lessons.splice(MAX_LESSONS);
  putLessons(lessons);
  return updated;
}

/** Search lessons by text similarity + recency boost */
export function recallLessons(query, { limit = 5 } = {}) {
  const lessons = getLessons();
  const qWords = new Set(query.toLowerCase().split(/\s+/).filter(w => w.length > 2));
  if (!qWords.size) return lessons.slice(0, limit).map(l => ({ ...l, match_score: 1.0 }));

  const scored = lessons.map(l => {
    const all = new Set([...(l.title || ''), ...(l.text || ''), ...(l.tags || [])].join(' ').toLowerCase().split(/\s+/).filter(w => w.length > 2));
    const inter = [...qWords].filter(w => all.has(w)).length;
    const union = new Set([...qWords, ...all]).size;
    const score = union === 0 ? 0 : inter / union;
    return { ...l, match_score: Math.min(score + Math.log1p(l.recall_count ?? 0) * 0.05, 1.0) };
  });
  return scored.filter(l => l.match_score > 0).sort((a, b) => b.match_score - a.match_score).slice(0, limit);
}

/** Memories recalled >= threshold but no lesson yet */
export function getLessonCandidates() {
  const log = getLog();
  return Object.entries(log)
    .filter(([, e]) => e.recall_count >= LESSON_CANDIDATE_THRESHOLD)
    .map(([memory_id, e]) => ({ memory_id, recall_count: e.recall_count, last_recall: e.last_recall }))
    .sort((a, b) => b.recall_count - a.recall_count);
}

export function lessonStats() {
  const lessons = getLessons(), log = getLog();
  const totalRecalls = Object.values(log).reduce((s, e) => s + (e.recall_count ?? 0), 0);
  const tagCounts = {};
  for (const l of lessons) for (const t of l.tags ?? []) tagCounts[t] = (tagCounts[t] ?? 0) + 1;
  const topTags = Object.entries(tagCounts).sort((a, b) => b[1] - a[1]).slice(0, 10).map(([tag, count]) => ({ tag, count }));
  const rc = lessons.map(l => l.recall_count ?? 0);
  return {
    total_lessons: lessons.length,
    total_recalls: totalRecalls,
    top_tags: topTags,
    lesson_candidates: getLessonCandidates().length,
    by_recall: {
      total: lessons.length,
      never_recalled: rc.filter(c => c === 0).length,
      one_to_five:   rc.filter(c => c >= 1 && c <= 5).length,
      six_to_ten:    rc.filter(c => c >= 6 && c <= 10).length,
      above_ten:     rc.filter(c => c > 10).length,
      total_recalls: totalRecalls,
    },
  };
}

// ===== MCP Tool: memory_lessons =====
export function memoryLessonsTool({ action, memory_id, title, body, tags, query, lesson_id, limit, tag } = {}) {
  try {
    switch (action) {
      case 'extract': {
        if (!title || !body) throw new Error('title and body required');
        const lesson = upsertLesson(generateId(), {
          text: String(body).slice(0, MAX_BODY_CHARS),
          title: String(title).slice(0, MAX_TITLE_CHARS),
          type: 'general',
          tags: Array.isArray(tags) ? tags.slice(0, 20) : [],
          source_memory: memory_id ?? null,
          created_at: Date.now(),
        });
        return { content: [{ type: 'text', text: JSON.stringify(lesson, null, 2) }] };
      }

      case 'recall': {
        if (!query) throw new Error('query required');
        const results = recallLessons(query, { limit: limit ?? 5 });
        for (const r of results) touchLesson(r.id);
        return { content: [{ type: 'text', text: JSON.stringify({ count: results.length, lessons: results }, null, 2) }] };
      }

      case 'list': {
        const all = getLessons();
        const filtered = tag ? all.filter(l => l.tags?.includes(tag)) : all;
        return { content: [{ type: 'text', text: JSON.stringify({ count: filtered.length, lessons: filtered.slice(0, limit ?? 50) }, null, 2) }] };
      }

      case 'stats':
        return { content: [{ type: 'text', text: JSON.stringify({ ...lessonStats(), top_candidates: getLessonCandidates().slice(0, 5) }, null, 2) }] };

      case 'delete': {
        if (!lesson_id) throw new Error('lesson_id required');
        const lessons2 = getLessons().filter(l => l.id !== lesson_id);
        putLessons(lessons2);
        return { content: [{ type: 'text', text: JSON.stringify({ success: true }, null, 2) }] };
      }

      case 'touch': {
        if (!lesson_id) throw new Error('lesson_id required');
        touchLesson(lesson_id);
        return { content: [{ type: 'text', text: JSON.stringify({ success: true }, null, 2) }] };
      }

      case 'candidates':
        return { content: [{ type: 'text', text: JSON.stringify({ count: getLessonCandidates().length, candidates: getLessonCandidates() }, null, 2) }] };

      default:
        return { content: [{ type: 'text', text: JSON.stringify({ error: `Unknown action: ${action}`, hint: 'extract/recall/list/stats/delete/touch/candidates' }, null, 2) }], isError: true };
    }
  } catch (err) {
    return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
  }
}
/**
 * Lessons System v1.0
 * 
 * 从错误、纠正、最佳实践中自动学习。
 * 存储在 memories.json 的 `lessons` 数组中（与普通记忆分开）。
 * 
 * 核心功能：
 * 1. 记录错误模式（error patterns）
 * 2. 记录用户纠正（user corrections）
 * 3. 记录最佳实践（best practices）
 * 4. 语义搜索 lessons（基于 BM25 + 简单关键词）
 * 5. 按类型/主题过滤
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { createHash } from 'crypto';

const __dirname = dirname(fileURLToPath(import.meta.url));

// ============ Config ============

const LESSONS_FILE = join(__dirname, '..', '..', '..', 'memory', 'lessons.json');

const LESSON_CONFIG = {
  maxLessons: 500,          // 最多存储 lessons 数量
  dedupWindow: 20,         // 往前比较多少条记忆去重
  similarityThreshold: 0.72, // Jaccard 相似度阈值（超过则认为是重复）
  autoTag: true,
};

// Lesson types
const LESSON_TYPES = {
  ERROR: 'error',           // 命令/工具/代码错误
  CORRECTION: 'correction', // 用户纠正（"不对，应该是..."）
  BEST_PRACTICE: 'best_practice', // 发现的最佳实践
  PITFALL: 'pitfall',       // 踩坑记录
  PATTERN: 'pattern',       // 发现的模式
  TOOL_CHANGE: 'tool_change', // 工具/API 变化
};

// ============ Storage ============

function getLessonsStore() {
  if (!existsSync(LESSONS_FILE)) {
    return { lessons: [], version: '1.0', lastUpdated: Date.now() };
  }
  try {
    return JSON.parse(readFileSync(LESSONS_FILE, 'utf-8'));
  } catch {
    return { lessons: [], version: '1.0', lastUpdated: Date.now() };
  }
}

function saveLessonsStore(store) {
  try {
    const dir = join(__dirname, '..', '..', 'memory');
    mkdirSync(dir, { recursive: true });
    writeFileSync(LESSONS_FILE, JSON.stringify(store, null, 2), 'utf-8');
  } catch (e) {
    console.warn('[lessons] save failed:', e.message);
  }
}

// ============ Recall Tracking (lesson_access_log.json) ============

const ACCESS_FILE = join(__dirname, '..', '..', '..', 'memory', 'lesson_access_log.json');
let accessLogCache = null;

function getAccessLog() {
  if (accessLogCache !== null) return accessLogCache;
  if (!existsSync(ACCESS_FILE)) { accessLogCache = {}; return accessLogCache; }
  try { accessLogCache = JSON.parse(readFileSync(ACCESS_FILE, 'utf-8')); } catch { accessLogCache = {}; }
  return accessLogCache;
}
function saveAccessLog(log) {
  accessLogCache = log;
  try { writeFileSync(ACCESS_FILE, JSON.stringify(log, null, 2), 'utf-8'); } catch (e) { console.warn('[lessons] access log save failed:', e.message); }
}

/** Increment recall count for a lesson (call when lesson is retrieved) */
export function touchLesson(lessonId) {
  const log = getAccessLog();
  const now = Date.now();
  if (!log[lessonId]) log[lessonId] = { recall_count: 0, last_recall: 0, created_at: now };
  log[lessonId].recall_count++;
  log[lessonId].last_recall = now;
  saveAccessLog(log);
}

/** Memories recalled >= 5x but not yet turned into a lesson */
export function getLessonCandidates() {
  // Cross-ref access log with lessons — memories recalled often but no lesson yet
  // For now return recall stats per lesson ID
  const log = getAccessLog();
  const store = getLessonsStore();
  const lessonIds = new Set(store.lessons.map(l => l.id));
  return Object.entries(log)
    .filter(([id]) => !lessonIds.has(id) && log[id].recall_count >= 5)
    .map(([memory_id, e]) => ({ memory_id, recall_count: e.recall_count, last_recall: e.last_recall }))
    .sort((a, b) => b.recall_count - a.recall_count);
}

// ============ Core Utilities ============

function jaccardSimilarity(a, b) {
  if (!a || !b) return 0;
  const setA = new Set(a.toLowerCase().split(/\s+/).filter(Boolean));
  const setB = new Set(b.toLowerCase().split(/\s+/).filter(Boolean));
  const intersection = [...setA].filter(x => setB.has(x));
  const union = new Set([...setA, ...setB]);
  return union.size === 0 ? 0 : intersection.length / union.size;
}

function tokenize(text) {
  if (!text) return [];
  return text.toLowerCase()
    .replace(/[^\w\u4e00-\u9fff\s]/g, ' ')
    .split(/\s+/)
    .filter(t => t.length >= 2);
}

function hashText(text) {
  return createHash('sha256').update(text).digest('hex').slice(0, 16);
}

/**
 * Detect if text contains a user correction pattern
 */
function isCorrection(text) {
  const patterns = [
    /^不对/,
    /不对[:：]/,
    /错了/,
    /错误[:：]/,
    /应该[:：]/,
    /不是[:：]/,
    /改用/,
    /要用/,
    /要用的是/,
    /不对，我之前/,
    /我说的是/,
    /看清楚[:：]/,
    /错了，要/,
    /\bWRONG\b/i,
    /\bincorrect\b/i,
    /\bnot right\b/i,
    /这是错的/,
    /不对，应该是/,
  ];
  return patterns.some(p => p.test(text.trim()));
}

/**
 * Detect if text describes an error
 */
function isError(text) {
  const patterns = [
    /error|exception|failed|failure/i,
    /错误|异常|失败/i,
    /\bError\b|\bException\b/i,
    /command.*fail|工具.*失败/i,
    /SyntaxError|ReferenceError|TypeError|RuntimeError/i,
    /permission denied|no such file|not found/i,
    /找不到|权限|不存在|报错/i,
  ];
  return patterns.some(p => p.test(text));
}

/**
 * Detect if text describes a best practice
 */
function isBestPractice(text) {
  const patterns = [
    /better.*approach|better.*way|best practice|recommended/i,
    /更好的|最佳实践|推荐|建议使用|应该用/,
    /更优|更高效|更简洁|更好/i,
    /\bTIP\b|\bPRO TIP\b/i,
    /\bPro tip\b/i,
  ];
  return patterns.some(p => p.test(text));
}

/**
 * Detect if text describes a pitfall
 */
function isPitfall(text) {
  const patterns = [
    /\bwatch out\b|\bcaution\b|\bcareful\b|\btrap\b/i,
    /小心|注意|陷阱|坑|别/,
    /不要.*会|避免.*问题/i,
    /容易出错|经常踩坑|新手容易/,
    /\bDONT\b|\bAVOID\b/i,
  ];
  return patterns.some(p => p.test(text));
}

/**
 * Auto-detect lesson type from text content
 */
function detectLessonType(text) {
  if (isCorrection(text)) return LESSON_TYPES.CORRECTION;
  if (isPitfall(text)) return LESSON_TYPES.PITFALL;
  if (isBestPractice(text)) return LESSON_TYPES.BEST_PRACTICE;
  if (isError(text)) return LESSON_TYPES.ERROR;
  return LESSON_TYPES.PATTERN;
}

/**
 * Extract the "wrong" and "correct" parts from a correction
 */
function extractCorrectionPair(text) {
  const patterns = [
    /(不对|错了|应该)[:：]?\s*(.+)/i,
    /不是[:：]\s*(.+)\s*，?\s*(?:而?是|应该|要用)[:：]\s*(.+)/i,
    /(wrong|incorrect|not)[:：]\s*(.+)/i,
  ];
  
  for (const p of patterns) {
    const match = text.match(p);
    if (match) {
      return { wrong: match[2] || match[1], correct: match[3] || '' };
    }
  }
  return { wrong: text, correct: '' };
}

// ============ Lesson Storage ============

/**
 * Add a lesson to the store
 * @param {object} lesson - { text, type, wrong?, correct?, context?, tags?, importance? }
 * @returns {object|null} - the stored lesson or null if duplicate
 */
export function addLesson(lesson) {
  const store = getLessonsStore();
  const now = Date.now();
  const text = lesson.text?.trim();
  
  if (!text || text.length < 5) return null;
  
  // Deduplication: check against recent lessons
  const recent = store.lessons.slice(-LESSON_CONFIG.dedupWindow);
  for (const existing of recent) {
    const sim = jaccardSimilarity(text, existing.text);
    if (sim > LESSON_CONFIG.similarityThreshold) {
      // Update access stats on duplicate
      existing.last_access = now;
      existing.access_count = (existing.access_count || 0) + 1;
      saveLessonsStore(store);
      return null;
    }
  }
  
  const newLesson = {
    id: `les_${now}_${hashText(text).slice(0, 6)}`,
    text,
    type: lesson.type || detectLessonType(text),
    wrong: lesson.wrong || null,
    correct: lesson.correct || null,
    context: lesson.context || null,
    tags: lesson.tags || [],
    importance: lesson.importance ?? 0.75,
    created_at: now,
    updated_at: now,
    last_access: now,
    access_count: 1,
    version: '1.0',
  };
  
  store.lessons.push(newLesson);
  
  // Trim if over max
  if (store.lessons.length > LESSON_CONFIG.maxLessons) {
    store.lessons = store.lessons.slice(-LESSON_CONFIG.maxLessons);
  }
  
  store.lastUpdated = now;
  saveLessonsStore(store);
  
  console.log(`[lessons] Added: [${newLesson.type}] "${text.slice(0,40)}..."`);
  return newLesson;
}

/**
 * Add a lesson by type automatically detected
 * @param {string} text - lesson content
 * @param {object} options - { wrong?, correct?, context?, tags?, importance? }
 */
export function storeLesson(text, options = {}) {
  return addLesson({ text, ...options });
}

/**
 * Add an error lesson
 */
export function storeError(errorText, fix = null, context = null) {
  return addLesson({
    text: errorText,
    type: LESSON_TYPES.ERROR,
    correct: fix,
    context,
  });
}

/**
 * Add a user correction lesson
 */
export function storeCorrection(wrong, correct, context = null) {
  return addLesson({
    text: `纠正: ${wrong} → ${correct}`,
    type: LESSON_TYPES.CORRECTION,
    wrong,
    correct,
    context,
    importance: 0.9, // corrections are high importance
  });
}

/**
 * Add a best practice lesson
 */
export function storeBestPractice(practice, context = null) {
  return addLesson({
    text: practice,
    type: LESSON_TYPES.BEST_PRACTICE,
    context,
    importance: 0.8,
  });
}

/**
 * Add a pitfall lesson
 */
export function storePitfall(pitfall, solution = null, context = null) {
  return addLesson({
    text: pitfall,
    type: LESSON_TYPES.PITFALL,
    correct: solution,
    context,
    importance: 0.85,
  });
}

// ============ Lesson Search ============

/**
 * Simple keyword + pattern search for lessons
 * @param {string} query
 * @param {object} options - { type?, topK?, includeWrong? }
 * @returns {Array}
 */
export function searchLessons(query, options = {}) {
  const { type, topK = 5, includeWrong = false } = options;
  
  const store = getLessonsStore();
  let lessons = store.lessons;
  
  // Filter by type if specified
  if (type && LESSON_TYPES[type]) {
    lessons = lessons.filter(l => l.type === type);
  }
  
  if (!query || query.trim().length === 0) {
    // Return recent lessons
    return lessons
      .sort((a, b) => b.created_at - a.created_at)
      .slice(0, topK);
  }
  
  const queryTokens = tokenize(query);
  const scored = lessons.map(lesson => {
    const text = includeWrong && lesson.wrong
      ? `${lesson.text} ${lesson.wrong} ${lesson.correct || ''}`
      : lesson.text;
    const lessonTokens = tokenize(text);
    
    // Simple overlap scoring
    const overlap = queryTokens.filter(t => lessonTokens.includes(t)).length;
    const bonus = lessonTokens.some(t => queryTokens.includes(t)) ? 0.1 : 0;
    const importanceBonus = (lesson.importance || 0.5) * 0.2;
    
    return {
      ...lesson,
      score: overlap + bonus + importanceBonus,
    };
  });
  
  const results = scored
    .filter(l => l.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, topK);

  // Track each lesson recall
  for (const lesson of results) touchLesson(lesson.id);

  return results;
}

/**
 * Get recent lessons by type
 */
export function getRecentLessons(type = null, limit = 5) {
  const store = getLessonsStore();
  let lessons = store.lessons;
  if (type && LESSON_TYPES[type]) {
    lessons = lessons.filter(l => l.type === type);
  }
  return lessons
    .sort((a, b) => b.created_at - a.created_at)
    .slice(0, limit);
}

/**
 * Get lesson statistics (now includes recall tracking from access log)
 */
export function getLessonStats() {
  const store = getLessonsStore();
  const log = getAccessLog();
  const totalRecalls = Object.values(log).reduce((s, e) => s + (e.recall_count ?? 0), 0);
  const byType = {};
  for (const type of Object.values(LESSON_TYPES)) {
    byType[type] = store.lessons.filter(l => l.type === type).length;
  }
  const rc = store.lessons.map(l => log[l.id]?.recall_count ?? 0);
  return {
    total: store.lessons.length,
    total_recalls: totalRecalls,
    byType,
    by_recall: {
      never_recalled: rc.filter(c => c === 0).length,
      one_to_five:    rc.filter(c => c >= 1 && c <= 5).length,
      six_to_ten:     rc.filter(c => c >= 6 && c <= 10).length,
      above_ten:      rc.filter(c => c > 10).length,
    },
    lesson_candidates: getLessonCandidates().length,
    lastUpdated: store.lastUpdated,
  };
}

/**
 * Clear all lessons (for testing)
 */
export function clearLessons() {
  const store = { lessons: [], version: '1.0', lastUpdated: Date.now() };
  saveLessonsStore(store);
  return true;
}

/**
 * Format a lesson for injection into prompt
 */
export function formatLessonForPrompt(lesson) {
  const lines = [`[${lesson.type}] ${lesson.text}`];
  if (lesson.correct) {
    lines.push(`  ✓ ${lesson.correct}`);
  }
  if (lesson.wrong) {
    lines.push(`  ✗ ${lesson.wrong}`);
  }
  if (lesson.context) {
    lines.push(`  → ${lesson.context}`);
  }
  return lines.join('\n');
}

/**
 * Format multiple lessons for prompt injection
 */
export function formatLessonsForPrompt(lessons) {
  if (lessons.length === 0) return '';
  const formatted = lessons.map(l => `  - ${formatLessonForPrompt(l)}`).join('\n');
  return `\n[Relevant Lessons - avoid repeating past mistakes]\n${formatted}\n[/Lessons]\n`;
}

// ============ Lesson Detection (for hook integration) ============

/**
 * Detect and auto-capture lessons from a message
 * Returns detected lessons (doesn't auto-store to avoid noise)
 */
export function detectLessons(text) {
  const detections = [];
  
  // Check for correction patterns
  if (isCorrection(text)) {
    const pair = extractCorrectionPair(text);
    detections.push({
      type: LESSON_TYPES.CORRECTION,
      text,
      wrong: pair.wrong,
      correct: pair.correct,
      auto: true,
    });
  }
  
  // Check for error patterns
  if (isError(text)) {
    detections.push({
      type: LESSON_TYPES.ERROR,
      text,
      auto: true,
    });
  }
  
  // Check for best practice
  if (isBestPractice(text)) {
    detections.push({
      type: LESSON_TYPES.BEST_PRACTICE,
      text,
      auto: true,
    });
  }
  
  // Check for pitfall
  if (isPitfall(text)) {
    detections.push({
      type: LESSON_TYPES.PITFALL,
      text,
      auto: true,
    });
  }
  
  return detections;
}

// ============ QMD Integration ============

/**
 * Search local documents via QMD CLI
 * @param {string} query
 * @param {number} topK
 * @returns {Array} - { path, snippet, score }
 */
export async function searchDocuments(query, topK = 3) {
  try {
    const { execSync } = await import('child_process');
    
    // Use qmd search (BM25 only, no embedding needed)
    const result = execSync(
      `qmd search "${query.replace(/"/g, '\\"')}" --limit ${topK} 2>/dev/null`,
      { encoding: 'utf-8', timeout: 10000 }
    );
    
    const lines = result.split('\n').filter(l => l.trim() && !l.startsWith('Warning'));
    
    return lines.slice(0, topK).map(line => {
      // Try to extract path and snippet from qmd output
      const pathMatch = line.match(/^\[(.+?)\]|(https?:\/\/\S+)|(\/.+?):/);
      const path = pathMatch ? (pathMatch[1] || pathMatch[2] || pathMatch[3] || line.split(':')[0]) : line.split(':')[0];
      const snippet = line.includes(':') ? line.split(':').slice(1).join(':').trim() : line;
      
      return {
        path: path.slice(0, 100),
        snippet: snippet.slice(0, 150),
        score: 1.0,
      };
    }).filter(r => r.path);
  } catch (e) {
    // QMD not available or failed
    return [];
  }
}

/**
 * Search QMD with embeddings (hybrid search)
 * Falls back to BM25-only if embeddings not ready
 */
export async function searchDocumentsHybrid(query, topK = 3) {
  try {
    const { execSync } = await import('child_process');
    
    const result = execSync(
      `qmd query "${query.replace(/"/g, '\\"')}" --limit ${topK} 2>/dev/null`,
      { encoding: 'utf-8', timeout: 15000 }
    );
    
    const lines = result.split('\n').filter(l => l.trim() && !l.startsWith('Warning'));
    
    return lines.slice(0, topK).map(line => {
      const pathMatch = line.match(/^\[(.+?)\]|(https?:\/\/\S+)|(\/.+?):/);
      const path = pathMatch ? (pathMatch[1] || pathMatch[2] || pathMatch[3] || line.split(':')[0]) : line.split(':')[0];
      const snippet = line.includes(':') ? line.split(':').slice(1).join(':').trim() : line;
      
      return {
        path: path.slice(0, 100),
        snippet: snippet.slice(0, 150),
        score: 1.0,
      };
    }).filter(r => r.path);
  } catch {
    // Fallback to BM25 search
    return searchDocuments(query, topK);
  }
}

export {
  LESSON_TYPES,
  LESSON_CONFIG,
  isCorrection,
  isError,
  isBestPractice,
  isPitfall,
  detectLessonType,
};
/**
 * local_embedding.js — 本地 Embedding 服务
 * 
 * 移植自 memory-tencentdb 的 LocalEmbeddingService
 * 使用 node-llama-cpp + GGUF 模型实现完全离线的向量嵌入
 * 
 * 特性:
 * - 完全离线，无需任何 API
 * - 默认使用 embeddinggemma-300m (300MB, 768 维)
 * - 后台预热，不阻塞主线程
 * - 自动截断超长文本
 * - L2 归一化输出
 */

import { log } from './logger.js';

// ─── 常量 ───────────────────────────────────────────────────────────────────

/** 默认模型: Google embeddinggemma-300m Q8_0 量化 (~300MB) */
const DEFAULT_LOCAL_MODEL = 'hf:ggml-org/embeddinggemma-300m-qat-q8_0-GGUF/embeddinggemma-300m-qat-Q8_0.gguf';

/** embeddinggemma-300m 输出 768 维向量 */
const LOCAL_DIMENSIONS = 768;

/** 最大输入字符数 (embeddinggemma-300m 有 256 token 限制) */
const LOCAL_MAX_INPUT_CHARS = 512;

// ─── 错误类 ─────────────────────────────────────────────────────────────────

/**
 * 本地 Embedding 模型未就绪错误
 */
export class EmbeddingNotReadyError extends Error {
  constructor(message) {
    super(message || 'Local embedding model is not ready yet (still downloading or loading)');
    this.name = 'EmbeddingNotReadyError';
  }
}

// ─── 工具函数 ───────────────────────────────────────────────────────────────

/**
 * 清理 NaN/Inf 值并进行 L2 归一化
 */
function sanitizeAndNormalize(vec) {
  const arr = Array.from(vec).map(v => (Number.isFinite(v) ? v : 0));
  const magnitude = Math.sqrt(arr.reduce((sum, v) => sum + v * v, 0));
  if (magnitude < 1e-10) {
    return new Float32Array(arr);
  }
  return new Float32Array(arr.map(v => v / magnitude));
}

// ─── 本地 Embedding 服务类 ─────────────────────────────────────────────────

/**
 * 本地 Embedding 服务 (node-llama-cpp)
 * 
 * 初始化状态机:
 * - idle: 未启动
 * - initializing: 模型下载/加载中
 * - ready: 模型已加载，可以服务请求
 * - failed: 初始化失败
 */
export class LocalEmbeddingService {
  constructor(config = {}, logger) {
    this.modelPath = config.modelPath?.trim() || DEFAULT_LOCAL_MODEL;
    this.modelCacheDir = config.modelCacheDir?.trim() || undefined;
    this.logger = logger || { info: console.log, warn: console.warn, error: console.error, debug: () => {} };
    
    // 初始化状态
    this.initState = 'idle';
    this.initPromise = null;
    this.initError = null;
    this.embeddingContext = null;
    
    // 统计
    this.stats = {
      totalEmbeddings: 0,
      totalTexts: 0,
      errors: 0,
    };
  }
  
  /**
   * 获取向量维度
   */
  getDimensions() {
    return LOCAL_DIMENSIONS;
  }
  
  /**
   * 获取 Provider 信息
   */
  getProviderInfo() {
    return { provider: 'local', model: this.modelPath };
  }
  
  /**
   * 模型是否就绪
   */
  isReady() {
    return this.initState === 'ready' && this.embeddingContext !== null;
  }
  
  /**
   * 获取状态
   */
  getStatus() {
    return {
      state: this.initState,
      model: this.modelPath,
      dimensions: LOCAL_DIMENSIONS,
      ready: this.isReady(),
      error: this.initError?.message || null,
      stats: this.stats,
    };
  }
  
  /**
   * 启动后台预热: 下载模型（如需要）并加载到内存
   * 不阻塞调用者，立即返回
   * 可以安全多次调用（幂等）
   */
  startWarmup() {
    if (this.initState === 'initializing' || this.initState === 'ready') {
      return; // 已在进行中或已完成
    }
    
    log.info(`[LocalEmbedding] Starting background warmup for model: ${this.modelPath}`);
    this.initState = 'initializing';
    this.initError = null;
    
    this.initPromise = this._doInitialize()
      .then(() => {
        this.initState = 'ready';
        log.info('[LocalEmbedding] Background warmup complete — local embedding ready');
      })
      .catch(err => {
        this.initState = 'failed';
        this.initError = err instanceof Error ? err : new Error(String(err));
        log.error(`[LocalEmbedding] Background warmup failed: ${this.initError.message}`);
      });
  }
  
  /**
   * 获取单个文本的 Embedding
   * @throws {EmbeddingNotReadyError} 如果模型未就绪
   */
  async embed(text) {
    this._assertReady();
    const truncated = this._truncateInput(text);
    
    try {
      const embedding = await this.embeddingContext.getEmbeddingFor(truncated);
      this.stats.totalEmbeddings += 1;
      this.stats.totalTexts += 1;
      return sanitizeAndNormalize(embedding.vector);
    } catch (err) {
      this.stats.errors += 1;
      throw err;
    }
  }
  
  /**
   * 批量获取 Embedding
   * @throws {EmbeddingNotReadyError} 如果模型未就绪
   */
  async embedBatch(texts) {
    if (texts.length === 0) return [];
    this._assertReady();
    
    const results = [];
    for (const text of texts) {
      const truncated = this._truncateInput(text);
      const embedding = await this.embeddingContext.getEmbeddingFor(truncated);
      results.push(sanitizeAndNormalize(embedding.vector));
    }
    
    this.stats.totalEmbeddings += 1;
    this.stats.totalTexts += texts.length;
    
    return results;
  }
  
  /**
   * 释放资源
   */
  close() {
    if (this.embeddingContext) {
      try {
        const ctx = this.embeddingContext;
        if (typeof ctx.dispose === 'function') {
          ctx.dispose();
        }
      } catch {
        // 尽力清理
      }
      this.embeddingContext = null;
      this.initPromise = null;
      this.initState = 'idle';
      this.initError = null;
      log.info('[LocalEmbedding] Resources released');
    }
  }
  
  /**
   * 等待预热完成
   */
  async waitForReady() {
    if (this.initPromise) {
      await this.initPromise;
    }
  }
  
  // ─── 内部方法 ─────────────────────────────────────────────────────────────
  
  /**
   * 断言模型已就绪
   */
  _assertReady() {
    if (this.initState === 'ready' && this.embeddingContext) {
      return;
    }
    
    if (this.initState === 'failed') {
      throw new EmbeddingNotReadyError(
        `Local embedding model initialization failed: ${this.initError?.message || 'unknown error'}. Call startWarmup() to retry.`
      );
    }
    
    if (this.initState === 'initializing') {
      throw new EmbeddingNotReadyError(
        'Local embedding model is still loading (download/initialization in progress). Please try again later.'
      );
    }
    
    // "idle" — startWarmup() 从未被调用
    throw new EmbeddingNotReadyError(
      'Local embedding model warmup has not been started. Call startWarmup() first.'
    );
  }
  
  /**
   * 截断输入文本以适应模型上下文窗口
   */
  _truncateInput(text) {
    if (text.length <= LOCAL_MAX_INPUT_CHARS) return text;
    log.debug(`[LocalEmbedding] Input truncated from ${text.length} to ${LOCAL_MAX_INPUT_CHARS} chars`);
    return text.slice(0, LOCAL_MAX_INPUT_CHARS);
  }
  
  /**
   * 内部: 执行实际的模型下载 + 加载
   */
  async _doInitialize() {
    let model = undefined;
    
    try {
      log.debug('[LocalEmbedding] Loading node-llama-cpp...');
      
      // 动态导入 — node-llama-cpp 是可选依赖
      const { getLlama, resolveModelFile, LlamaLogLevel } = await import('node-llama-cpp').catch(() => {
        throw new Error('node-llama-cpp is not installed. Run: npm install node-llama-cpp');
      });
      
      const llama = await getLlama({ logLevel: LlamaLogLevel.error });
      log.debug('[LocalEmbedding] Llama instance created');
      
      const resolvedPath = await resolveModelFile(this.modelPath, this.modelCacheDir);
      log.debug(`[LocalEmbedding] Model resolved: ${resolvedPath}`);
      
      model = await llama.loadModel({ modelPath: resolvedPath });
      log.debug('[LocalEmbedding] Model loaded, creating embedding context...');
      
      this.embeddingContext = await model.createEmbeddingContext();
      log.info(`[LocalEmbedding] Ready (model=${this.modelPath}, dims=${LOCAL_DIMENSIONS})`);
      
    } catch (err) {
      // 清理部分初始化的资源
      if (model?.dispose) {
        try { model.dispose(); } catch { /* 尽力清理 */ }
      }
      this.embeddingContext = null;
      throw err;
    }
  }
}

