/**
 * Structured Logger v1.0
 * 输出 JSON 格式日志，支持 levels: debug/info/warn/error
 * 日志输出到：stdout + 文件（config.logDir/mcp-{date}.log）
 */

import { appendFileSync, existsSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

export const LOG_LEVELS = { debug: 0, info: 1, warn: 2, error: 3 };

export class StructuredLogger {
  constructor(context = {}) {
    this.context = context;
    this.minLevel = LOG_LEVELS[process.env.LOG_LEVEL || 'info'];
    this._logDir = this._ensureLogDir();
  }

  _ensureLogDir() {
    const __dirname = dirname(fileURLToPath(import.meta.url));
    const HOME = process.env.HOME || '/root';
    const LOG_DIR = join(HOME, '.openclaw', 'workspace', 'memory', 'logs');
    if (!existsSync(LOG_DIR)) {
      mkdirSync(LOG_DIR, { recursive: true });
    }
    return LOG_DIR;
  }

  _format(level, msg, data = {}) {
    return JSON.stringify({
      ts: new Date().toISOString(),
      level,
      msg,
      pid: process.pid,
      ...this.context,
      ...data,
    });
  }

  _write(level, formatted) {
    const logFile = join(this._logDir, `mcp-${new Date().toISOString().slice(0, 10)}.log`);
    try {
      appendFileSync(logFile, formatted + '\n');
    } catch { }
    if (level === 'error' || level === 'warn') {
      console.error(formatted);
    } else {
      console.log(formatted);
    }
  }

  debug(msg, data) { if (this.minLevel <= 0) this._write('debug', this._format('debug', msg, data)); }
  info(msg, data) { if (this.minLevel <= 1) this._write('info', this._format('info', msg, data)); }
  warn(msg, data) { if (this.minLevel <= 2) this._write('warn', this._format('warn', msg, data)); }
  error(msg, data) { if (this.minLevel <= 3) this._write('error', this._format('error', msg, data)); }
}

let globalLogger = null;

export function getLogger(context = {}) {
  if (!globalLogger) {
    globalLogger = new StructuredLogger(context);
  }
  return globalLogger;
}

// 便捷函数
export const log = {
  debug: (msg, data) => getLogger().debug(msg, data),
  info: (msg, data) => getLogger().info(msg, data),
  warn: (msg, data) => getLogger().warn(msg, data),
  error: (msg, data) => getLogger().error(msg, data),
};

// 兼容旧代码（有些模块 import { logger } from '../logger.js'）
export const logger = getLogger();
/**
 * manager.js - 统一记忆管理 v2.0
 * 
 * 整合功能:
 * - 记忆去重与合并
 * - 重要性衰减
 * - 记忆清理
 * - 统计报告
 * - 健康检查
 * 
 * 协调各个独立工具
 */

import { getAllMemories, saveMemories, loadMemories } from './storage.js';
import { config, log } from './utils/logger.js';
import { readFileSync, writeFileSync, existsSync, mkdirSync, readdirSync, statSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

// 衰减配置
const DECAY_HALF_LIFE = 30;       // 30天半衰期
const DECAY_MIN_IMPORTANCE = 0.1; // 最低重要性

const HOME = process.env.HOME || '/root';
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const MEMORY_DIR = join(WORKSPACE, 'memory');
const VECTOR_DB_DIR = join(MEMORY_DIR, 'vector');
const SNAPSHOT_DIR = join(MEMORY_DIR, 'snapshots');

// ============================================================
// 工具函数
// ============================================================

/**
 * 文本相似度（简单 Jaccard）
 * @param {string} s1
 * @param {string} s2
 * @returns {number}
 */
function textSimilarity(s1, s2) {
  const set1 = new Set(s1);
  const set2 = new Set(s2);
  const intersection = new Set([...set1].filter(x => set2.has(x)));
  const union = new Set([...set1, ...set2]);
  return union.size === 0 ? 0 : intersection.size / union.size;
}

// ============================================================
// 去重
// ============================================================

/**
 * 查找相似记忆对
 * @param {Array<object>} memories
 * @param {number} [threshold=0.85]
 * @returns {Array<{keep: object, remove: object, similarity: number}>}
 */
export function findDuplicates(memories, threshold = 0.85) {
  log('INFO', '开始查找重复记忆...');

  /** @type {Array<{keep: object, remove: object, similarity: number}>} */
  const duplicates = [];

  // 按类别分组
  /** @type {Map<string, Array<{idx: number, mem: object}>>} */
  const byCategory = new Map();
  for (let i = 0; i < memories.length; i++) {
    const cat = memories[i].category || 'general';
    if (!byCategory.has(cat)) {
      byCategory.set(cat, []);
    }
    byCategory.get(cat).push({ idx: i, mem: memories[i] });
  }

  // 检查每个类别内的重复
  for (const [category, items] of byCategory) {
    if (items.length < 2) continue;

    for (let i = 0; i < items.length; i++) {
      for (let j = i + 1; j < items.length; j++) {
        const m1 = items[i].mem;
        const m2 = items[j].mem;

        const sim = textSimilarity(m1.text || m1.content || '', m2.text || m2.content || '');

        if (sim > 0.6) {
          // 保留重要性更高的
          const [keep, remove] = m1.importance >= m2.importance
            ? [items[i], items[j]]
            : [items[j], items[i]];

          duplicates.push({
            keep: memories[keep.idx],
            remove: memories[remove.idx],
            similarity: sim
          });
        }
      }
    }
  }

  return duplicates;
}

/**
 * 执行去重
 * @param {object} args - { dryRun: boolean }
 * @returns {Promise<object>}
 */
export async function cmdDedup(args = { dryRun: true }) {
  const { dryRun = true } = args;
  const memories = getAllMemories();

  if (memories.length < 2) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({ message: '记忆少于2条，无需去重', count: memories.length }, null, 2)
      }]
    };
  }

  const duplicates = findDuplicates(memories);

  if (duplicates.length === 0) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({ message: '没有发现重复记忆', count: memories.length }, null, 2)
      }]
    };
  }

  // 执行删除（非 dry run）
  if (!dryRun) {
    const removeIds = new Set(duplicates.map(d => d.remove.id));
    const kept = memories.filter(m => !removeIds.has(m.id));
    saveMemories(kept);
  }

  return {
    content: [{
      type: 'text',
      text: JSON.stringify({
        message: dryRun
          ? `发现 ${duplicates.length} 对重复记忆（预览模式）`
          : `已删除 ${duplicates.length} 条重复记忆`,
        total_memories: memories.length,
        duplicates_found: duplicates.length,
        duplicates: duplicates.slice(0, 10),
        action: dryRun ? 'preview' : 'applied'
      }, null, 2)
    }]
  };
}

// ============================================================
// 衰减
// ============================================================

/**
 * 应用重要性衰减
 * @param {object} args - { dryRun: boolean }
 * @returns {Promise<object>}
 */
export async function cmdDecay(args = { dryRun: true }) {
  const { dryRun = true } = args;
  const memories = getAllMemories();

  if (memories.length === 0) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({ message: '没有记忆需要衰减' }, null, 2)
      }]
    };
  }

  const now = Date.now();
  /** @type {Array<{memory: object, old_importance: number, new_importance: number, days_old: number}>} */
  const decayed = [];

  for (const m of memories) {
    const createdAt = m.created_at || m.timestamp;
    if (!createdAt) continue;

    const daysOld = Math.floor((now - createdAt) / (1000 * 60 * 60 * 24));

    // 指数衰减
    const decayFactor = Math.pow(0.5, daysOld / DECAY_HALF_LIFE);
    const newImportance = Math.max(DECAY_MIN_IMPORTANCE, (m.importance || 0.5) * decayFactor);

    if (newImportance < (m.importance || 0.5) - 0.05) {
      decayed.push({
        memory: m,
        old_importance: m.importance || 0.5,
        new_importance: Math.round(newImportance * 100) / 100,
        days_old: daysOld
      });
    }
  }

  if (decayed.length === 0) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({ message: '没有需要衰减的记忆' }, null, 2)
      }]
    };
  }

  // 执行更新（非 dry run）
  if (!dryRun) {
    for (const d of decayed) {
      const mem = memories.find(m => m.id === d.memory.id);
      if (mem) {
        mem.importance = d.new_importance;
        mem.updated_at = now;
      }
    }
    saveMemories(memories);
  }

  return {
    content: [{
      type: 'text',
      text: JSON.stringify({
        message: dryRun
          ? `需要衰减 ${decayed.length} 条记忆（预览模式）`
          : `已更新 ${decayed.length} 条记忆的重要性`,
        total_memories: memories.length,
        decayed_count: decayed.length,
        samples: decayed.slice(0, 10),
        action: dryRun ? 'preview' : 'applied'
      }, null, 2)
    }]
  };
}

// ============================================================
// 清理
// ============================================================

/**
 * 清理过期记忆文件
 * @param {object} args - { days: number, dryRun: boolean }
 * @returns {Promise<object>}
 */
export async function cmdClean(args = { days: 30, dryRun: true }) {
  const { days = 30, dryRun = true } = args;
  const cutoff = Date.now() - days * 24 * 60 * 60 * 1000;

  if (!existsSync(SNAPSHOT_DIR)) {
    mkdirSync(SNAPSHOT_DIR, { recursive: true });
  }

  /** @type {Array<{file: string, date: Date}>} */
  const toClean = [];

  try {
    const files = readdirSync(MEMORY_DIR);
    for (const file of files) {
      if (!file.endsWith('.md')) continue;
      
      // 跳过特殊目录和文件
      if (file === 'snapshots' || file === 'vector_cache') continue;
      
      const filePath = join(MEMORY_DIR, file);
      const stats = statSync(filePath);
      
      // 检查是否是文件（非目录）
      if (!stats.isFile()) continue;
      
      // 解析日期
      const dateStr = file.replace('.md', '');
      const fileDate = new Date(dateStr);
      
      if (!isNaN(fileDate.getTime()) && fileDate.getTime() < cutoff) {
        toClean.push({ file, date: fileDate });
      }
    }
  } catch (e) {
    log('WARN', '清理时读取目录失败:', e.message);
  }

  if (toClean.length === 0) {
    return {
      content: [{
        type: 'text',
        text: JSON.stringify({ message: `没有需要清理的记忆 (保留 ${days} 天)` }, null, 2)
      }]
    };
  }

  // 执行清理（非 dry run）
  if (!dryRun) {
    const { moveFile } = await import('./storage.js').catch(() => ({ moveFile: null }));
    for (const { file } of toClean) {
      try {
        // 简单移动到 snapshots 目录
        const src = join(MEMORY_DIR, file);
        const dst = join(SNAPSHOT_DIR, file);
        const { copyFileSync, unlinkSync } = await import('fs');
        copyFileSync(src, dst);
        unlinkSync(src);
      } catch (e) {
        log('WARN', `移动文件失败 ${file}:`, e.message);
      }
    }
  }

  return {
    content: [{
      type: 'text',
      text: JSON.stringify({
        message: dryRun
          ? `发现 ${toClean.length} 个过期文件（预览模式）`
          : `已移动 ${toClean.length} 个文件到 snapshots`,
        files: toClean.map(f => ({ file: f.file, date: f.date.toISOString().slice(0, 10) })),
        action: dryRun ? 'preview' : 'applied'
      }, null, 2)
    }]
  };
}

// ============================================================
// 统计
// ============================================================

/**
 * 显示统计报告
 * @param {object} args
 * @returns {Promise<object>}
 */
export async function cmdStats(args = {}) {
  const memories = getAllMemories();

  // 基本统计
  const byCategory = new Map();
  let totalImportance = 0;

  for (const m of memories) {
    const cat = m.category || 'general';
    byCategory.set(cat, (byCategory.get(cat) || 0) + 1);
    totalImportance += m.importance || 0.5;
  }

  // 标签统计
  const tagCounts = new Map();
  for (const m of memories) {
    for (const tag of m.tags || []) {
      tagCounts.set(tag, (tagCounts.get(tag) || 0) + 1);
    }
  }

  // 重要性分布
  const high = memories.filter(m => (m.importance || 0.5) > 0.6).length;
  const medium = memories.filter(m => {
    const imp = m.importance || 0.5;
    return imp >= 0.3 && imp <= 0.6;
  }).length;
  const low = memories.filter(m => (m.importance || 0.5) < 0.3).length;

  // 向量数据库检查
  let vectorCount = 0;
  try {
    const vectorCacheFile = join(VECTOR_DB_DIR, 'vectors.json');
    if (existsSync(vectorCacheFile)) {
      const data = JSON.parse(readFileSync(vectorCacheFile, 'utf8'));
      vectorCount = Array.isArray(data) ? data.length : (data.vectors?.length || 0);
    }
  } catch {
    // 向量数据库可能未初始化
  }

  return {
    content: [{
      type: 'text',
      text: JSON.stringify({
        summary: {
          total_memories: memories.length,
          avg_importance: memories.length > 0 ? Math.round(totalImportance / memories.length * 100) / 100 : 0
        },
        by_category: Object.fromEntries(byCategory),
        by_tag: Object.fromEntries([...tagCounts.entries()].slice(0, 20)),
        importance_distribution: {
          high: high,
          medium: medium,
          low: low
        },
        vector_database: {
          count: vectorCount,
          coverage: memories.length > 0 ? Math.round(vectorCount / memories.length * 100) + '%' : '0%'
        }
      }, null, 2)
    }]
  };
}

// ============================================================
// 健康检查
// ============================================================

/**
 * 健康检查
 * @param {object} args
 * @returns {Promise<object>}
 */
export async function cmdHealth(args = {}) {
  /** @type {string[]} */
  const issues = [];
  const memories = getAllMemories();

  // 1. 检查向量覆盖率
  let vectorCount = 0;
  try {
    const vectorCacheFile = join(VECTOR_DB_DIR, 'vectors.json');
    if (existsSync(vectorCacheFile)) {
      const data = JSON.parse(readFileSync(vectorCacheFile, 'utf8'));
      vectorCount = Array.isArray(data) ? data.length : (data.vectors?.length || 0);
    }
  } catch {
    issues.push('向量数据库未初始化');
  }

  if (memories.length > 0) {
    const coverage = vectorCount / memories.length;
    if (coverage < 0.8) {
      issues.push(`向量覆盖率低: ${Math.round(coverage * 100)}% (${vectorCount}/${memories.length})`);
    }
  }

  // 2. 检查分类一致性
  const standardCategories = new Set(['profile', 'preferences', 'entities', 'events', 'cases', 'patterns', 'fact', 'learning', 'decision']);
  const categories = new Set(memories.map(m => m.category).filter(Boolean));
  const nonStandard = [...categories].filter(c => !standardCategories.has(c) && !c.startsWith('T='));
  if (nonStandard.length > 0) {
    issues.push(`非标准分类: ${nonStandard.join(', ')}`);
  }

  // 3. 检查过期记忆（超过90天）
  const oldCutoff = Date.now() - 90 * 24 * 60 * 60 * 1000;
  const oldMemories = memories.filter(m => {
    const created = m.created_at || m.timestamp;
    return created && created < oldCutoff;
  });
  if (oldMemories.length > 0) {
    issues.push(`超过90天的记忆: ${oldMemories.length} 条`);
  }

  // 4. 检查低重要性记忆
  const lowImportance = memories.filter(m => (m.importance || 0.5) < 0.2);
  if (lowImportance.length > 0) {
    issues.push(`低重要性记忆 (<0.2): ${lowImportance.length} 条`);
  }

  return {
    content: [{
      type: 'text',
      text: JSON.stringify({
        status: issues.length === 0 ? 'healthy' : 'issues_found',
        issue_count: issues.length,
        issues,
        recommendations: issues.length > 0
          ? [
              '运行 manager.cmdDedup({ dryRun: false }) 进行去重',
              '运行 manager.cmdDecay({ dryRun: false }) 应用衰减',
              '运行 manager.cmdClean({ days: 30, dryRun: false }) 清理过期'
            ]
          : []
      }, null, 2)
    }]
  };
}

// ============================================================
// 主入口
// ============================================================

/**
 * 统一管理命令（协调所有工具）
 * @param {object} args - { command: 'dedup'|'decay'|'clean'|'stats'|'health', ... }
 * @returns {Promise<object>}
 */
export async function cmdManager(args = {}) {
  const { command, ...rest } = args;

  switch (command) {
    case 'dedup':
      return cmdDedup(rest);
    case 'decay':
      return cmdDecay(rest);
    case 'clean':
      return cmdClean(rest);
    case 'stats':
      return cmdStats(rest);
    case 'health':
      return cmdHealth(rest);
    default:
      // Run all checks
      const [dedupResult, decayResult, statsResult, healthResult] = await Promise.all([
        cmdDedup({ dryRun: true }),
        cmdDecay({ dryRun: true }),
        cmdStats({}),
        cmdHealth({})
      ]);

      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            message: 'Memory Manager 完整报告',
            dedup: JSON.parse(dedupResult.content[0].text),
            decay: JSON.parse(decayResult.content[0].text),
            stats: JSON.parse(statsResult.content[0].text),
            health: JSON.parse(healthResult.content[0].text)
          }, null, 2)
        }]
      };
  }
}

export default {
  findDuplicates,
  cmdDedup,
  cmdDecay,
  cmdClean,
  cmdStats,
  cmdHealth,
  cmdManager
};/**
 * memory-cleaner.js — 本地数据清理器
 * 
 * 借鉴 memory-tencentdb 的 LocalMemoryCleaner 实现：
 * - 按 retentionDays 保留天数清理 L0/L1 数据
 * - 每日定时清理（默认 03:00）
 * - 支持向量数据库清理
 * - 自然日保留策略
 */

import fs from 'fs/promises';
import path from 'path';
import { log } from './logger.js';

// ─── 配置 ───────────────────────────────────────────────────────────────────

const DEFAULT_CONFIG = {
  retentionDays: 0,           // 保留天数，0 = 禁用清理
  cleanTime: '03:00',         // 每日清理时间 (HH:mm)
  allowAggressiveCleanup: false, // 是否允许 1-2 天的高风险清理
  l0Dir: 'conversations',     // L0 目录名
  l1Dir: 'records',           // L1 目录名
};

// ─── 清理器类 ─────────────────────────────────────────────────────────────

export class LocalMemoryCleaner {
  constructor(options = {}) {
    this.config = { ...DEFAULT_CONFIG, ...options };
    this.baseDir = options.baseDir || process.env.MEMORY_DIR || './memory';
    this.timer = null;
    this.destroyed = false;
    this.vectorStore = options.vectorStore || null;
    
    // 统计
    this.stats = {
      lastRun: null,
      totalRuns: 0,
      totalFilesDeleted: 0,
      totalRecordsDeleted: 0,
    };
  }
  
  /**
   * 设置向量存储实例
   */
  setVectorStore(vectorStore) {
    this.vectorStore = vectorStore;
  }
  
  /**
   * 启动清理器
   */
  start() {
    if (this.destroyed) return;
    
    const { retentionDays, cleanTime } = this.config;
    
    if (!(retentionDays > 0)) {
      log('info', `[MemoryCleaner] Disabled: retentionDays=${retentionDays}`);
      return;
    }
    
    // 验证 retentionDays
    if (retentionDays < 3 && !this.config.allowAggressiveCleanup) {
      log('warn', `[MemoryCleaner] retentionDays < 3 requires allowAggressiveCleanup=true`);
      return;
    }
    
    log('info', `[MemoryCleaner] Enabled: retentionDays=${retentionDays}, cleanTime=${cleanTime}`);
    
    this.scheduleNext();
  }
  
  /**
   * 停止清理器
   */
  destroy() {
    if (this.destroyed) return;
    this.destroyed = true;
    
    if (this.timer) {
      clearTimeout(this.timer);
      this.timer = null;
    }
    
    log('info', '[MemoryCleaner] Stopped');
  }
  
  /**
   * 手动执行一次清理
   */
  async runOnce(nowMs = Date.now()) {
    if (this.destroyed) return;
    
    const { retentionDays } = this.config;
    if (!(retentionDays > 0)) {
      log('debug', `[MemoryCleaner] Skip: retentionDays=${retentionDays}`);
      return;
    }
    
    const cutoffMs = this.computeCutoffMs(nowMs, retentionDays);
    const cutoffDate = new Date(cutoffMs).toISOString().split('T')[0];
    
    log('info', `[MemoryCleaner] Running cleanup: cutoff=${cutoffDate}, retentionDays=${retentionDays}`);
    
    const results = {
      l0: { scanned: 0, deleted: 0, failed: 0 },
      l1: { scanned: 0, deleted: 0, failed: 0 },
      vector: { l0Deleted: 0, l1Deleted: 0 },
    };
    
    // 清理 L0 目录
    const l0Dir = path.join(this.baseDir, this.config.l0Dir);
    const l0Result = await this.cleanDirectory(l0Dir, cutoffMs);
    results.l0 = l0Result;
    
    // 清理 L1 目录
    const l1Dir = path.join(this.baseDir, this.config.l1Dir);
    const l1Result = await this.cleanDirectory(l1Dir, cutoffMs);
    results.l1 = l1Result;
    
    // 清理向量数据库
    if (this.vectorStore) {
      try {
        const cutoffIso = new Date(cutoffMs).toISOString();
        
        // 删除过期的 L0 记录
        if (this.vectorStore.deleteL0ExpiredByRecordedAt) {
          results.vector.l0Deleted = this.vectorStore.deleteL0ExpiredByRecordedAt(cutoffIso);
        }
        
        // 删除过期的 L1 记录
        if (this.vectorStore.deleteL1ExpiredByUpdatedTime) {
          results.vector.l1Deleted = this.vectorStore.deleteL1ExpiredByUpdatedTime(cutoffIso);
        }
        
        log('info', `[MemoryCleaner] Vector cleanup: l0Deleted=${results.vector.l0Deleted}, l1Deleted=${results.vector.l1Deleted}`);
      } catch (err) {
        log('error', `[MemoryCleaner] Vector cleanup failed: ${err.message}`);
      }
    }
    
    // 更新统计
    this.stats.lastRun = new Date().toISOString();
    this.stats.totalRuns += 1;
    this.stats.totalFilesDeleted += results.l0.deleted + results.l1.deleted;
    this.stats.totalRecordsDeleted += results.vector.l0Deleted + results.vector.l1Deleted;
    
    log('info', `[MemoryCleaner] Cleanup done: l0=${results.l0.deleted} files, l1=${results.l1.deleted} files, vector=${results.vector.l0Deleted + results.vector.l1Deleted} records`);
    
    return results;
  }
  
  /**
   * 获取清理器状态
   */
  getStatus() {
    return {
      enabled: this.config.retentionDays > 0,
      config: this.config,
      stats: this.stats,
      nextRun: this.timer ? new Date(this.nextRunTime).toISOString() : null,
    };
  }
  
  /**
   * 更新配置
   */
  updateConfig(newConfig) {
    Object.assign(this.config, newConfig);
    
    // 重新调度
    if (this.timer) {
      clearTimeout(this.timer);
      this.timer = null;
    }
    
    if (this.config.retentionDays > 0) {
      this.scheduleNext();
    }
  }
  
  // ─── 内部方法 ─────────────────────────────────────────────────────────────
  
  /**
   * 清理单个目录
   */
  async cleanDirectory(dirPath, cutoffMs) {
    const result = { scanned: 0, deleted: 0, failed: 0 };
    
    try {
      const entries = await fs.readdir(dirPath, { withFileTypes: true });
      
      for (const entry of entries) {
        if (!entry.isFile()) continue;
        if (!this.isJsonLikeFile(entry.name)) continue;
        
        result.scanned += 1;
        
        // 提取日期分片
        const shard = this.extractShardDate(entry.name);
        if (!shard) {
          log('debug', `[MemoryCleaner] Skip non-shard file: ${entry.name}`);
          continue;
        }
        
        // 检查是否过期
        const dayEndMs = this.localDayEndMs(shard.year, shard.month, shard.day);
        if (dayEndMs < cutoffMs) {
          const filePath = path.join(dirPath, entry.name);
          try {
            await fs.unlink(filePath);
            result.deleted += 1;
            log('info', `[MemoryCleaner] Deleted: ${filePath}`);
          } catch (err) {
            result.failed += 1;
            log('warn', `[MemoryCleaner] Failed to delete ${filePath}: ${err.message}`);
          }
        }
      }
    } catch (err) {
      if (err.code !== 'ENOENT') {
        log('warn', `[MemoryCleaner] Directory scan failed: ${dirPath} - ${err.message}`);
      }
    }
    
    return result;
  }
  
  /**
   * 调度下一次清理
   */
  scheduleNext() {
    const nowMs = Date.now();
    const nextMs = this.nextRunAt(this.config.cleanTime, nowMs);
    const delayMs = Math.max(0, nextMs - nowMs);
    
    this.nextRunTime = nextMs;
    
    log('info', `[MemoryCleaner] Scheduled: nextRun=${new Date(nextMs).toISOString()}, delay=${Math.round(delayMs / 1000 / 60)}min`);
    
    this.timer = setTimeout(async () => {
      if (this.destroyed) return;
      
      log('info', `[MemoryCleaner] Timer fired at ${new Date().toISOString()}`);
      
      try {
        await this.runOnce();
      } catch (err) {
        log('error', `[MemoryCleaner] Cleanup failed: ${err.message}`);
      }
      
      // 重新调度
      if (!this.destroyed) {
        this.scheduleNext();
      }
    }, delayMs);
  }
  
  /**
   * 计算截止时间（自然日策略）
   */
  computeCutoffMs(nowMs, retentionDays) {
    const now = new Date(nowMs);
    const keepStart = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0, 0);
    keepStart.setDate(keepStart.getDate() - (retentionDays - 1));
    return keepStart.getTime();
  }
  
  /**
   * 计算下一次运行时间
   */
  nextRunAt(cleanTime, nowMs) {
    const [hour, minute] = cleanTime.split(':').map(Number);
    
    const now = new Date(nowMs);
    const next = new Date(nowMs);
    next.setHours(hour, minute, 0, 0);
    
    if (next.getTime() <= now.getTime()) {
      next.setDate(next.getDate() + 1);
    }
    
    return next.getTime();
  }
  
  /**
   * 提取文件名中的日期分片
   */
  extractShardDate(fileName) {
    // 支持格式: YYYY-MM-DD.jsonl | YYYY-MM-DD.json
    const m = /^(\d{4})-(\d{2})-(\d{2})\.(?:jsonl|json)$/.exec(fileName);
    if (!m) return null;
    
    const year = Number(m[1]);
    const month = Number(m[2]);
    const day = Number(m[3]);
    
    // 验证日期有效性
    const probe = new Date(year, month - 1, day);
    if (
      probe.getFullYear() !== year ||
      probe.getMonth() !== month - 1 ||
      probe.getDate() !== day
    ) {
      return null;
    }
    
    return { year, month, day };
  }
  
  /**
   * 计算本地日期的结束时间（毫秒）
   */
  localDayEndMs(year, month, day) {
    return new Date(year, month - 1, day, 23, 59, 59, 999).getTime();
  }
  
  /**
   * 检查是否是 JSON 文件
   */
  isJsonLikeFile(name) {
    return name.endsWith('.jsonl') || name.endsWith('.json');
  }
}

// ─── 单例实例 ─────────────────────────────────────────────────────────────

let cleanerInstance = null;

export function getCleaner(options) {
  if (!cleanerInstance) {
    cleanerInstance = new LocalMemoryCleaner(options);
  }
  return cleanerInstance;
}

export function initCleaner(options) {
  if (cleanerInstance) {
    cleanerInstance.destroy();
  }
  cleanerInstance = new LocalMemoryCleaner(options);
  return cleanerInstance;
}
/**
 * Memory System - 统一入口 (Complete)
 * 
 * Features:
 * - Hierarchical Cache (MemoryHierarchy)
 * - Knowledge Merging (KnowledgeMerger)
 * - Predictive Loading (PredictiveLoader)
 * - Confidence Validation (ConfidenceValidator)
 * - Feedback Learning (FeedbackLearner)
 * - Smart Forget (SmartForgetter)
 * - Auto Extraction (AutoExtractor)
 * - Quality Metrics (MemoryQuality)
 * - Multi-Agent Perspective (v0.4.1)
 * 
 * Usage:
 *   node memory.js status                 # System status
 *   node memory.js store "content" [--agent xiao-zhi]  # Store memory
 *   node memory.js search "query" [--agent xiao-zhi]  # Search
 *   node memory.js stats                  # Detailed stats
 */

import fs from 'fs/promises';
import path from 'path';
import { fileURLToPath } from 'url';
import os from 'os';
import crypto from 'crypto';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// ========== Configuration ==========

const WORKSPACE = path.join(os.homedir(), '.openclaw', 'workspace');
const MEMORY_DIR = path.join(WORKSPACE, 'memory');
const VECTOR_DB_DIR = path.join(MEMORY_DIR, 'vector');
const MEMORY_FILE = path.join(MEMORY_DIR, 'memories.json');

// Try importing existing Node.js modules
let Hierarchy, Merger, Predictor, Validator, Learner, Forgetter;
try {
  const hierarchyModule = await import('./core/hierarchy.js').catch(() => null);
  const mergerModule = await import('./graph/knowledge_merger.js').catch(() => null);
  const predictorModule = await import('./tools/predict.js').catch(() => null);
  const validatorModule = await import('./quality/confidence.js').catch(() => null);
  const learnerModule = await import('./tools/feedback_learner.js').catch(() => null);
  const forgetterModule = await import('./quality/smart_forgetter.js').catch(() => null);
  
  Hierarchy = hierarchyModule?.MemoryHierarchy;
  Merger = mergerModule?.KnowledgeMerger;
  Predictor = predictorModule?.PredictiveLoader;
  Validator = validatorModule?.ConfidenceValidator;
  Learner = learnerModule?.FeedbackLearner;
  Forgetter = forgetterModule?.SmartForgetter;
} catch (e) {
  // Modules not available, use simplified versions
}

// ========== Simple Implementations (Fallback) ==========

class SimpleHierarchy {
  constructor() {
    this.L1 = [];
    this.L2 = [];
    this.L3 = [];
    this.maxL1 = 50;
    this.maxL2 = 200;
  }
  
  rebuildFromMemories(memories) {
    // Sort by importance and redistribute
    const sorted = [...memories].sort((a, b) => (b.importance || 0.5) - (a.importance || 0.5));
    this.L1 = sorted.slice(0, this.maxL1);
    this.L2 = sorted.slice(this.maxL1, this.maxL1 + this.maxL2);
    this.L3 = sorted.slice(this.maxL1 + this.maxL2);
  }
  
  getContext(query, maxMemories = 10) {
    const results = [...this.L1, ...this.L2, ...this.L3].slice(0, maxMemories);
    return results;
  }
  
  stats() {
    return {
      L1_hot: { count: this.L1.length, max_size: this.maxL1, avg_importance: this._avgImportance(this.L1) },
      L2_warm: { count: this.L2.length, max_size: this.maxL2, avg_importance: this._avgImportance(this.L2) },
      L3_cold: { count: this.L3.length, avg_importance: this._avgImportance(this.L3) }
    };
  }
  
  _avgImportance(items) {
    if (!items.length) return 0;
    return items.reduce((sum, m) => sum + (m.importance || 0.5), 0) / items.length;
  }
}

class SimpleMerger {
  constructor() {
    this.blocks = [];
  }
  
  mergeAll(memories) {
    // Simple grouping by category
    const byCategory = {};
    for (const mem of memories) {
      const cat = mem.category || 'other';
      if (!byCategory[cat]) byCategory[cat] = [];
      byCategory[cat].push(mem);
    }
    
    this.blocks = Object.entries(byCategory).map(([cat, items]) => ({
      category: cat,
      count: items.length,
      items
    }));
    
    return this.blocks;
  }
  
  stats() {
    return {
      total_knowledge_blocks: this.blocks.length,
      estimated_tokens_saved: this.blocks.reduce((sum, b) => sum + (b.count - 1) * 50, 0)
    };
  }
}

