/**
 * organize.js - Automatic Memory Organization
 * 
 * Implements automatic memory tiering and compression.
 * Moves memories between HOT/WARM/COLD tiers based on activity.
 * 
 * Inspired by Memory Tiering's automatic organization
 */

import { writeFileSync, readFileSync, existsSync, mkdirSync, readdirSync, statSync } from 'fs';
import { join } from 'path';

const HOME = process.env.HOME || '/root';
const MEMORY_DIR = join(HOME, '.openclaw', 'workspace', 'memory');
const HOT_DIR = join(MEMORY_DIR, 'hot');
const WARM_DIR = join(MEMORY_DIR, 'warm');
const COLD_DIR = join(MEMORY_DIR, 'cold');

// Ensure directories exist
[HOT_DIR, WARM_DIR, COLD_DIR].forEach(dir => {
  if (!existsSync(dir)) {
    mkdirSync(dir, { recursive: true });
  }
});

// Tier configuration
const TIER_CONFIG = {
  hot: {
    maxAge: 7 * 24 * 60 * 60 * 1000, // 7 days
    maxSize: 10, // max memories
    compressionRatio: 0.5 // compress to 50%
  },
  warm: {
    maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
    maxSize: 50,
    compressionRatio: 0.3
  },
  cold: {
    maxAge: 365 * 24 * 60 * 60 * 1000, // 365 days
    maxSize: 1000,
    compressionRatio: 0.1
  }
};

/**
 * Memory tier structure:
 * {
 *   id: string,
 *   text: string,
 *   category: string,
 *   importance: number,
 *   scope: string,
 *   tags: string[],
 *   tier: 'hot' | 'warm' | 'cold',
 *   createdAt: number,
 *   lastAccessed: number,
 *   accessCount: number,
 *   compressed: boolean
 * }
 */

/**
 * Determine target tier based on memory age and importance
 */
function determineTargetTier(memory) {
  const now = Date.now();
  const age = now - memory.createdAt;
  const lastAccessAge = now - memory.lastAccessed;

  // Hot: recently created and recently accessed, high importance
  if (age < TIER_CONFIG.hot.maxAge && 
      lastAccessAge < TIER_CONFIG.hot.maxAge && 
      memory.importance >= 0.7) {
    return 'hot';
  }

  // Warm: moderate age or moderate importance
  if (age < TIER_CONFIG.warm.maxAge && memory.importance >= 0.4) {
    return 'warm';
  }

  // Cold: old or low importance
  return 'cold';
}

/**
 * Compress memory content
 */
function compressMemory(memory, ratio) {
  if (memory.compressed) {
    return memory;
  }

  // Simple compression: summarize if too long
  const maxChars = Math.floor(memory.text.length * ratio);
  
  if (memory.text.length > maxChars) {
    return {
      ...memory,
      text: memory.text.substring(0, maxChars) + '...',
      compressed: true,
      originalLength: memory.text.length
    };
  }

  return memory;
}

/**
 * Move memory to target tier
 */
function moveMemory(memory, targetTier) {
  const sourceDir = join(MEMORY_DIR, memory.tier || 'hot');
  const targetDir = join(MEMORY_DIR, targetTier);
  
  const sourceFile = join(sourceDir, `${memory.id}.json`);
  const targetFile = join(targetDir, `${memory.id}.json`);

  // Compress if needed
  const config = TIER_CONFIG[targetTier];
  const compressedMemory = compressMemory(memory, config.compressionRatio);
  compressedMemory.tier = targetTier;
  compressedMemory.lastMoved = Date.now();

  // Write to new location
  writeFileSync(targetFile, JSON.stringify(compressedMemory, null, 2));

  // Remove from old location
  if (existsSync(sourceFile)) {
    // Don't delete, just mark as moved
    const movedFile = sourceFile + '.moved';
    writeFileSync(movedFile, JSON.stringify({
      movedFrom: sourceFile,
      movedTo: targetFile,
      movedAt: Date.now()
    }));
  }

  return compressedMemory;
}

/**
 * Organize all memories based on tier rules
 */
export function organizeMemories() {
  const organized = {
    hot: { moved: 0, compressed: 0 },
    warm: { moved: 0, compressed: 0 },
    cold: { moved: 0, compressed: 0 }
  };

  // Process each tier
  ['hot', 'warm', 'cold'].forEach(sourceTier => {
    const tierDir = join(MEMORY_DIR, sourceTier);
    
    if (!existsSync(tierDir)) return;

    const files = readdirSync(tierDir).filter(f => f.endsWith('.json'));

    for (const file of files) {
      try {
        const content = readFileSync(join(tierDir, file), 'utf-8');
        const memory = JSON.parse(content);

        const targetTier = determineTargetTier(memory);

        if (targetTier !== sourceTier) {
          moveMemory(memory, targetTier);
          organized[sourceTier].moved++;
          organized[targetTier].moved++;

          if (memory.text.length > TIER_CONFIG[targetTier].maxSize * 100) {
            organized[targetTier].compressed++;
          }
        }
      } catch (err) {
        console.error(`[Organize] Error processing ${file}: ${err.message}`);
      }
    }
  });

  return organized;
}

/**
 * Compress old memories in a specific tier
 */
export function compressTier(tier) {
  const tierDir = join(MEMORY_DIR, tier);
  
  if (!existsSync(tierDir)) {
    return { compressed: 0, errors: 0 };
  }

  const files = readdirSync(tierDir).filter(f => f.endsWith('.json'));
  const config = TIER_CONFIG[tier];
  let compressed = 0;
  let errors = 0;

  for (const file of files) {
    try {
      const content = readFileSync(join(tierDir, file), 'utf-8');
      const memory = JSON.parse(content);

      // Compress old memories
      const age = Date.now() - memory.createdAt;
      if (age > config.maxAge / 2 && !memory.compressed) {
        const compressedMemory = compressMemory(memory, config.compressionRatio);
        writeFileSync(join(tierDir, file), JSON.stringify(compressedMemory, null, 2));
        compressed++;
      }
    } catch (err) {
      console.error(`[Organize] Error compressing ${file}: ${err.message}`);
      errors++;
    }
  }

  return { compressed, errors };
}

/**
 * Archive memories older than threshold
 */
export function archiveOldMemories(thresholdDays = 365) {
  const threshold = Date.now() - thresholdDays * 24 * 60 * 60 * 1000;
  const archived = [];

  ['hot', 'warm', 'cold'].forEach(tier => {
    const tierDir = join(MEMORY_DIR, tier);
    
    if (!existsSync(tierDir)) return;

    const files = readdirSync(tierDir).filter(f => f.endsWith('.json'));

    for (const file of files) {
      try {
        const content = readFileSync(join(tierDir, file), 'utf-8');
        const memory = JSON.parse(content);

        if (memory.createdAt < threshold) {
          const archiveDir = join(MEMORY_DIR, 'archive', new Date(memory.createdAt).toISOString().split('T')[0]);
          mkdirSync(archiveDir, { recursive: true });
          
          const archiveFile = join(archiveDir, file);
          writeFileSync(archiveFile, JSON.stringify(memory, null, 2));
          archived.push(memory.id);
        }
      } catch (err) {
        console.error(`[Organize] Error archiving ${file}: ${err.message}`);
      }
    }
  });

  return { archived: archived.length, ids: archived };
}

/**
 * Get tier statistics
 */
export function getTierStats() {
  const stats = {};

  ['hot', 'warm', 'cold'].forEach(tier => {
    const tierDir = join(MEMORY_DIR, tier);
    
    if (!existsSync(tierDir)) {
      stats[tier] = { count: 0, totalSize: 0 };
      return;
    }

    const files = readdirSync(tierDir).filter(f => f.endsWith('.json'));
    let totalSize = 0;

    for (const file of files) {
      try {
        const content = readFileSync(join(tierDir, file), 'utf-8');
        totalSize += Buffer.byteLength(content, 'utf-8');
      } catch (err) {
        // Skip invalid files
      }
    }

    stats[tier] = {
      count: files.length,
      totalSize
    };
  });

  return stats;
}

/**
 * Full organization run
 */
export function fullOrganize() {
  const organizeResult = organizeMemories();
  const compressResult = {
    hot: compressTier('hot'),
    warm: compressTier('warm'),
    cold: compressTier('cold')
  };
  const archiveResult = archiveOldMemories(365);
  const stats = getTierStats();

  return {
    organize: organizeResult,
    compress: compressResult,
    archive: archiveResult,
    stats
  };
}
/**
 * pipeline_scheduler.js — 自动调度管线
 * 
 * 实现 memory-tencentdb 风格的自动调度：
 * - L0 → L1: 每 N 轮对话后触发
 * - L1 → L2: L1 完成后延迟触发
 * - L2 → L3: 每 M 条新记忆触发
 * 
 * 四层管线架构：
 * L0 (对话录制) → transcript_first.js
 * L1 (记忆提取) → extract.js
 * L2 (场景归纳) → scene_block.js
 * L3 (用户画像) → profile.js
 */

import { log } from './logger.js';
import { config } from './config.js';

// ─── 配置 ───────────────────────────────────────────────────────────────────

const DEFAULT_CONFIG = {
  enabled: true,
  everyNConversations: 5,      // 每 N 轮对话触发 L1
  enableWarmup: true,          // Warm-up 模式: 1→2→4→8→...→N
  l1IdleTimeoutSeconds: 60,    // 用户停止对话后多久触发 L1
  l2DelayAfterL1Seconds: 90,   // L1 完成后延迟多久触发 L2
  l2MinIntervalSeconds: 300,   // 同一 session 两次 L2 的最小间隔
  l2MaxIntervalSeconds: 1800,  // 活跃 session 的 L2 最大轮询间隔
  sessionActiveWindowHours: 24, // 超过此时间不活跃的 session 停止 L2 轮询
  l3TriggerEveryN: 50,         // 每 N 条新记忆触发 L3
};

// ─── 管线调度器 ─────────────────────────────────────────────────────────────

class PipelineScheduler {
  constructor(options = {}) {
    this.config = { ...DEFAULT_CONFIG, ...options };
    
    // Session 状态
    this.sessionCounters = new Map();      // sessionId -> counter
    this.sessionLastActive = new Map();    // sessionId -> timestamp
    this.sessionL1Pending = new Map();     // sessionId -> timeoutId
    this.sessionL2Pending = new Map();     // sessionId -> timeoutId
    
    // L3 计数器
    this.l3Counter = 0;
    
    // L2 时间追踪
    this.lastL2Time = 0;
    
    // 统计
    this.stats = {
      l1Executions: 0,
      l2Executions: 0,
      l3Executions: 0,
      memoriesExtracted: 0,
      scenesGenerated: 0,
    };
    
    log.info('[PipelineScheduler] Initialized with config:', this.config);
  }
  
  // ─── 对话结束处理 ─────────────────────────────────────────────────────────
  
  /**
   * 记录对话结束，触发管线检查
   * @param {string} sessionId - 会话 ID
   * @param {string} [scope='USER'] - 范围
   */
  async onConversationEnd(sessionId, scope = 'USER') {
    if (!this.config.enabled) {
      log.debug('[PipelineScheduler] Pipeline disabled, skipping');
      return;
    }
    
    // 更新计数器
    const counter = (this.sessionCounters.get(sessionId) || 0) + 1;
    this.sessionCounters.set(sessionId, counter);
    this.sessionLastActive.set(sessionId, Date.now());
    
    log.info(`[PipelineScheduler] Conversation end for session ${sessionId}, counter: ${counter}`);
    
    // 检查是否触发 L1
    const effectiveN = this.getEffectiveN(sessionId);
    if (counter % effectiveN === 0) {
      log.info(`[PipelineScheduler] Triggering L1 for session ${sessionId} (counter ${counter} % ${effectiveN} = 0)`);
      await this.scheduleL1(sessionId, scope);
    }
  }
  
  /**
   * 获取有效的 N 值（Warm-up 模式）
   */
  getEffectiveN(sessionId) {
    if (!this.config.enableWarmup) {
      return this.config.everyNConversations;
    }
    
    // Warm-up: 1 → 2 → 4 → 8 → ... → N
    const counter = this.sessionCounters.get(sessionId) || 0;
    const maxN = this.config.everyNConversations;
    
    // 找到最大的 2^k <= counter 且 2^k <= maxN
    let effectiveN = 1;
    while (effectiveN * 2 <= counter && effectiveN * 2 <= maxN) {
      effectiveN *= 2;
    }
    
    return Math.max(1, Math.min(effectiveN, maxN));
  }
  
  // ─── L1 调度 ───────────────────────────────────────────────────────────────
  
  /**
   * 调度 L1 提取
   */
  async scheduleL1(sessionId, scope = 'USER') {
    // 取消之前的待处理 L1
    const existingTimeout = this.sessionL1Pending.get(sessionId);
    if (existingTimeout) {
      clearTimeout(existingTimeout);
    }
    
    log.info(`[PipelineScheduler] Scheduling L1 for session ${sessionId} in ${this.config.l1IdleTimeoutSeconds}s`);
    
    // 延迟执行（等待用户停止对话）
    const timeoutId = setTimeout(async () => {
      await this.executeL1WithRetry(sessionId, scope);
    }, this.config.l1IdleTimeoutSeconds * 1000);
    
    this.sessionL1Pending.set(sessionId, timeoutId);
  }
  
  /**
   * 执行 L1（带重试）
   */
  async executeL1WithRetry(sessionId, scope, retries = 3) {
    // 检查是否仍在活跃
    const lastActive = this.sessionLastActive.get(sessionId) || 0;
    const idleTime = Date.now() - lastActive;
    
    if (idleTime < this.config.l1IdleTimeoutSeconds * 1000) {
      log.info(`[PipelineScheduler] Session ${sessionId} still active, rescheduling L1`);
      await this.scheduleL1(sessionId, scope);
      return;
    }
    
    try {
      await this.executeL1(sessionId, scope);
    } catch (err) {
      log.error(`[PipelineScheduler] L1 execution failed:`, err);
      
      if (retries > 0) {
        log.info(`[PipelineScheduler] Retrying L1 (${retries} retries left)`);
        await new Promise(resolve => setTimeout(resolve, 5000));
        await this.executeL1WithRetry(sessionId, scope, retries - 1);
      }
    }
  }
  
  /**
   * 执行 L1 提取
   */
  async executeL1(sessionId, scope = 'USER') {
    log.info(`[PipelineScheduler] Executing L1 for session ${sessionId}`);
    
    try {
      // 动态导入避免循环依赖
      const { extractMemories } = await import('./extract.js');
      const memories = await extractMemories({ sessionId, scope });
      
      this.stats.l1Executions++;
      this.stats.memoriesExtracted += memories?.length || 0;
      
      // 更新 L3 计数器
      this.l3Counter += memories?.length || 0;
      
      log.info(`[PipelineScheduler] L1 completed: ${memories?.length || 0} memories extracted`);
      
      // 调度 L2
      setTimeout(() => this.scheduleL2(sessionId, scope), 
        this.config.l2DelayAfterL1Seconds * 1000);
      
      // 检查是否触发 L3
      if (this.l3Counter >= this.config.l3TriggerEveryN) {
        log.info(`[PipelineScheduler] L3 threshold reached (${this.l3Counter} >= ${this.config.l3TriggerEveryN})`);
        await this.scheduleL3(scope);
        this.l3Counter = 0;
      }
      
      return memories;
    } catch (err) {
      log.error(`[PipelineScheduler] L1 execution error:`, err);
      throw err;
    }
  }
  
  // ─── L2 调度 ───────────────────────────────────────────────────────────────
  
  /**
   * 调度 L2 场景归纳
   */
  async scheduleL2(sessionId, scope = 'USER') {
    // 检查最小间隔
    const elapsed = Date.now() - this.lastL2Time;
    
    if (elapsed < this.config.l2MinIntervalSeconds * 1000) {
      log.info(`[PipelineScheduler] L2 skipped: too soon (${Math.round(elapsed / 1000)}s < ${this.config.l2MinIntervalSeconds}s)`);
      return;
    }
    
    // 检查 session 是否仍活跃
    const lastActive = this.sessionLastActive.get(sessionId) || 0;
    const sessionAge = Date.now() - lastActive;
    
    if (sessionAge > this.config.sessionActiveWindowHours * 60 * 60 * 1000) {
      log.info(`[PipelineScheduler] L2 skipped: session inactive for ${Math.round(sessionAge / 1000 / 60)} minutes`);
      return;
    }
    
    log.info(`[PipelineScheduler] Executing L2 for session ${sessionId}`);
    
    try {
      await this.executeL2(scope);
    } catch (err) {
      log.error(`[PipelineScheduler] L2 execution error:`, err);
    }
  }
  
  /**
   * 执行 L2 场景归纳
   */
  async executeL2(scope = 'USER') {
    log.info(`[PipelineScheduler] Executing L2 for scope ${scope}`);
    
    try {
      const { inductScenes } = await import('./scene_block.js');
      const scenes = await inductScenes({ scope });
      
      this.stats.l2Executions++;
      this.stats.scenesGenerated += scenes?.length || 0;
      this.lastL2Time = Date.now();
      
      log.info(`[PipelineScheduler] L2 completed: ${scenes?.length || 0} scenes generated`);
      
      return scenes;
    } catch (err) {
      log.error(`[PipelineScheduler] L2 execution error:`, err);
      throw err;
    }
  }
  
  // ─── L3 调度 ───────────────────────────────────────────────────────────────
  
  /**
   * 调度 L3 用户画像更新
   */
  async scheduleL3(scope = 'USER') {
    log.info(`[PipelineScheduler] Scheduling L3 for scope ${scope}`);
    await this.executeL3(scope);
  }
  
  /**
   * 执行 L3 用户画像更新
   */
  async executeL3(scope = 'USER') {
    log.info(`[PipelineScheduler] Executing L3 for scope ${scope}`);
    
    try {
      const { getProfile, updateProfile } = await import('./profile.js');
      
      // 获取并更新画像
      const profile = await getProfile({ scope });
      
      this.stats.l3Executions++;
      
      log.info(`[PipelineScheduler] L3 completed: profile updated`);
      
      return profile;
    } catch (err) {
      log.error(`[PipelineScheduler] L3 execution error:`, err);
      throw err;
    }
  }
  
  // ─── 手动触发 ─────────────────────────────────────────────────────────────
  
  /**
   * 手动触发管线阶段
   */
  async trigger(stage, sessionId, scope = 'USER') {
    switch (stage) {
      case 'L1':
        return await this.executeL1(sessionId, scope);
      case 'L2':
        return await this.executeL2(scope);
      case 'L3':
        return await this.executeL3(scope);
      default:
        throw new Error(`Unknown stage: ${stage}`);
    }
  }
  
  // ─── 状态查询 ─────────────────────────────────────────────────────────────
  
  /**
   * 获取调度器状态
   */
  getStatus() {
    return {
      enabled: this.config.enabled,
      config: this.config,
      sessions: {
        active: this.sessionCounters.size,
        counters: Object.fromEntries(this.sessionCounters),
      },
      l3Counter: this.l3Counter,
      lastL2Time: this.lastL2Time,
      stats: this.stats,
    };
  }
  
  /**
   * 重置统计
   */
  resetStats() {
    this.stats = {
      l1Executions: 0,
      l2Executions: 0,
      l3Executions: 0,
      memoriesExtracted: 0,
      scenesGenerated: 0,
    };
  }
  
  /**
   * 更新配置
   */
  updateConfig(newConfig) {
    this.config = { ...this.config, ...newConfig };
    log.info('[PipelineScheduler] Config updated:', this.config);
  }
}

// ─── 单例实例 ───────────────────────────────────────────────────────────────

export const scheduler = new PipelineScheduler();

// ─── 便捷函数 ───────────────────────────────────────────────────────────────

export async function onConversationEnd(sessionId, scope = 'USER') {
  return await scheduler.onConversationEnd(sessionId, scope);
}

export async function triggerPipeline(stage, sessionId, scope = 'USER') {
  return await scheduler.trigger(stage, sessionId, scope);
}

export function getPipelineStatus() {
  return scheduler.getStatus();
}

export default scheduler;
/**
 * preference_extractor.js — Auto-extract Preferences from Conversation History
 * Part of Feature #10: Structured Preference Slots
 * 
 * Analyzes conversation history to infer user preferences with confidence scoring.
 * Signals: explicit statements ("I prefer..."), implicit patterns, behavioral signals.
 */
import { getPreferencesFlat, createSlotEntry, SOURCE_TYPES, SLOT_DEFINITIONS } from './preference_slots_schema.js';

/**
 * Explicit preference patterns (regex-based signal detection)
 */
const EXPLICIT_PATTERNS = {
  language: [
    /\b(please?\s+)?(speak|write|respond|answer)\s+(in\s+)?(english|chinese|中文|英文)\b/gi,
    /\b(i\s+prefer|i\s+like|i\s+want)\s+.*\s+(english|chinese|中文|英文)\b/gi,
    /\b(用|用中文|英文|中文说)\b/gi,
  ],
  communication_style: [
    /\b(i\s+prefer|i\s+like)\s+(concise|brief|short|detailed|verbose|comprehensive)\b/gi,
    /\b(简明|简洁|详细|简短|扼要)\b/gi,
    /\b(can\s+you\s+)?(keep\s+it\s+)?(short|brief|concise|detailed)\b/gi,
    /\b不要\s+(太\s+)?(长|详细|啰嗦)/gi,
  ],
  response_length: [
    /\b(keep\s+it\s+)?(short|brief|quick|one\s+liner|two\s+liner)\b/gi,
    /\b(详细|全面|深入|简略|简短)\s+(说明|介绍|回答)/gi,
    /\b(give\s+me\s+)?(a\s+brief|a\s+short|a\s+detailed)\b/gi,
  ],
  timezone: [
    /\b(i'm\s+in|i\s+am\s+in|位于|在)([\w\/]+)\b/gi,
    /\b(my\s+timezone|time\s+zone)\s*[:\-]?\s*([\w\/+0-9:]+)/gi,
    /\bUTC([+\-]?\d{1,2})/gi,
  ],
  notification_preference: [
    /\b(don't\s+)?notify?\s+(me\s+)?(too\s+much|every|all|unless|important)\b/gi,
    /\b(少|不要|别)\s+(打扰|通知|提醒)/gi,
    /\bonly\s+(important|critical|urgent)\s+(alerts|notifications|reminders)\b/gi,
  ],
  formality_level: [
    /\b(i\s+prefer|i\s+like)\s+(formal|casual|friendly|professional)\b/gi,
    /\b(正式|随意|专业|朋友式)\s+(交流|对话|沟通)/gi,
  ],
};

/**
 * Implicit behavioral signals
 */
const BEHAVIORAL_SIGNALS = {
  interests: {
    pattern: /\b(project|code|build|develop|test|deploy|api|database|frontend|backend)\b/gi,
    boost: 0.1,
  },
  goals: {
    pattern: /\b(finish|complete|achieve|goal|target|deadline|launch|release)\b/gi,
    boost: 0.1,
  },
};

/**
 * Language detection helpers
 */
function detectLanguage(text) {
  const chineseChars = (text.match(/[\u4e00-\u9fa5]/g) || []).length;
  const englishWords = (text.match(/[a-zA-Z]{3,}/g) || []).length;
  const total = chineseChars + englishWords;
  if (total === 0) return 'en';
  return chineseChars / total > 0.3 ? 'zh' : 'en';
}

/**
 * Extract explicit preferences from a single message
 */
function extractExplicitFromMessage(text) {
  const results = {};
  
  for (const [slotName, patterns] of Object.entries(EXPLICIT_PATTERNS)) {
    for (const pattern of patterns) {
      const match = text.match(pattern);
      if (match) {
        let value = null;
        // Extract value from pattern groups or keyword
        const matched = match[0];
        if (slotName === 'language') {
          if (/chinese|中文|中文说/.test(matched)) value = 'zh';
          else if (/english|英文/.test(matched)) value = 'en';
        } else if (slotName === 'communication_style') {
          if (/concise|brief|short|简明|简洁|简短/.test(matched)) value = 'concise';
          else if (/detailed|verbose|详细/.test(matched)) value = 'detailed';
        } else if (slotName === 'response_length') {
          if (/short|brief|quick|简略|简短/.test(matched)) value = 'short';
          else if (/detailed|comprehensive|详细|全面/.test(matched)) value = 'long';
        } else if (slotName === 'timezone') {
          const tzMatch = matched.match(/(UTC)?([+\-]?\d{1,2})/);
          if (tzMatch) {
            const offset = parseInt(tzMatch[2]);
            value = `UTC${offset >= 0 ? '+' : ''}${offset}`;
          }
        } else if (slotName === 'notification_preference') {
          if (/don't\s+notify|少|不要|别.*提醒|别.*打扰/.test(matched)) value = 'minimal';
          else if (/only\s+important|仅.*重要/.test(matched)) value = 'minimal';
        } else if (slotName === 'formality_level') {
          if (/formal|正式/.test(matched)) value = 'formal';
          else if (/casual|随意|朋友/.test(matched)) value = 'casual';
        }
        
        if (value) {
          results[slotName] = {
            value,
            confidence: 0.9,
            source: SOURCE_TYPES.EXPLICIT,
            signal: matched,
          };
          break;
        }
      }
    }
  }
  
  return results;
}

/**
 * Detect implicit patterns from message
 */
function detectImplicitPatterns(text) {
  const results = {};
  const lang = detectLanguage(text);
  
  // Language implicit signal
  if (lang === 'zh') {
    results.language = { value: 'zh', confidence: 0.7, source: SOURCE_TYPES.INFERRED };
  } else {
    results.language = { value: 'en', confidence: 0.6, source: SOURCE_TYPES.INFERRED };
  }
  
  // Message length signal
  const wordCount = text.split(/\s+/).length;
  if (wordCount < 20) {
    results.communication_style = { value: 'concise', confidence: 0.6, source: SOURCE_TYPES.INFERRED };
  } else if (wordCount > 100) {
    results.communication_style = { value: 'detailed', confidence: 0.6, source: SOURCE_TYPES.INFERRED };
    results.response_length = { value: 'long', confidence: 0.6, source: SOURCE_TYPES.INFERRED };
  }
  
  // Behavioral signals
  for (const [slotName, signal] of Object.entries(BEHAVIORAL_SIGNALS)) {
    const matches = text.match(signal.pattern);
    if (matches && matches.length >= 2) {
      if (!results[slotName]) {
        results[slotName] = {
          value: [],
          confidence: Math.min(0.9, signal.boost * matches.length),
          source: SOURCE_TYPES.INFERRED,
        };
      }
      if (Array.isArray(results[slotName].value)) {
        results[slotName].value.push(...matches.slice(0, 3));
      }
    }
  }
  
  return results;
}

/**
 * Extract preferences from a batch of messages (conversation history)
 * @param {Array<{text: string, role?: string, timestamp?: number}>} messages
 * @returns {Object} Extracted preferences with confidence scores
 */
export function extractPreferencesFromHistory(messages) {
  const extracted = {};
  const messageCount = messages.length;
  
  for (const msg of messages) {
    const text = msg.text || msg.content || '';
    if (!text || text.length < 3) continue;
    
    // Explicit extraction (highest priority)
    const explicit = extractExplicitFromMessage(text);
    for (const [slotName, data] of Object.entries(explicit)) {
      if (!extracted[slotName] || data.confidence > (extracted[slotName].confidence || 0)) {
        extracted[slotName] = createSlotEntry(data.value, data.source, data.confidence);
      }
    }
    
    // Implicit extraction
    const implicit = detectImplicitPatterns(text);
    for (const [slotName, data] of Object.entries(implicit)) {
      if (!extracted[slotName] || data.confidence > (extracted[slotName].confidence || 0)) {
        // For arrays, merge values
        if (Array.isArray(data.value) && Array.isArray(extracted[slotName]?.value)) {
          const merged = [...new Set([...extracted[slotName].value, ...data.value])];
          extracted[slotName] = createSlotEntry(merged, data.source, data.confidence);
        } else if (!extracted[slotName]) {
          extracted[slotName] = createSlotEntry(data.value, data.source, data.confidence);
        }
      }
    }
  }
  
  // Boost confidence if multiple signals across messages
  for (const [slotName, entry] of Object.entries(extracted)) {
    if (entry.confidence < 0.9 && messageCount > 3) {
      entry.confidence = Math.min(0.85, entry.confidence + 0.05 * Math.log(messageCount));
    }
    entry.lastUpdated = Date.now();
  }
  
  return extracted;
}

/**
 * Merge extracted preferences with existing preferences
 * Higher confidence wins, explicit > inferred > historical
 */
export function mergeExtractedPreferences(existing, extracted) {
  const merged = { ...existing };
  
  for (const [slotName, newEntry] of Object.entries(extracted)) {
    const existingEntry = merged[slotName];
    
    // Higher confidence wins
    if (!existingEntry || newEntry.confidence > existingEntry.confidence) {
      merged[slotName] = newEntry;
    }
    // Same confidence: explicit > inferred > historical
    else if (newEntry.confidence === existingEntry.confidence) {
      const sourcePriority = { explicit: 3, inferred: 2, historical: 1 };
      if ((sourcePriority[newEntry.source] || 0) > (sourcePriority[existingEntry.source] || 0)) {
        merged[slotName] = newEntry;
      }
    }
  }
  
  return merged;
}

export default {
  extractExplicitFromMessage,
  detectImplicitPatterns,
  extractPreferencesFromHistory,
  mergeExtractedPreferences,
  detectLanguage,
};
/**
 * preference_injector.js — Inject Preferences as Search Context
 * Part of Feature #10: Structured Preference Slots
 * 
 * Loads relevant preferences before search and formats them as context additions.
 */
import { loadPreferences, getPreferencesFlat, getSlotValue, SOURCE_TYPES } from './preference_slots_schema.js';

/**
 * Query context relevance mapping
 * Maps query keywords to relevant preference slots
 */
const QUERY_SLOT_RELEVANCE = {
  // Time-related queries need timezone
  time: ['timezone', 'working_hours'],
  schedule: ['timezone', 'working_hours'],
  meeting: ['timezone', 'working_hours'],
  when: ['timezone', 'working_hours'],
  // Language/communication queries
  language: ['language', 'communication_style'],
  write: ['language', 'communication_style', 'formality_level'],
  explain: ['communication_style', 'response_length'],
  describe: ['communication_style', 'response_length'],
  // Detail/complexity queries
  detail: ['response_length', 'communication_style'],
  brief: ['response_length', 'communication_style'],
  short: ['response_length', 'communication_style'],
  comprehensive: ['response_length'],
  // Tool/platform queries
  tool: ['preferred_tools'],
  platform: ['preferred_tools'],
  use: ['preferred_tools', 'interests'],
  // Goal-oriented queries
  goal: ['goals'],
  achieve: ['goals'],
  finish: ['goals'],
  project: ['goals', 'interests'],
  deadline: ['goals', 'working_hours'],
};

/**
 * Determine which slots are relevant to a query
 */
function getRelevantSlots(query) {
  const q = query.toLowerCase();
  const relevant = new Set();
  
  for (const [keyword, slots] of Object.entries(QUERY_SLOT_RELEVANCE)) {
    if (q.includes(keyword)) {
      slots.forEach(s => relevant.add(s));
    }
  }
  
  // Always include some general slots
  relevant.add('language');
  relevant.add('communication_style');
  
  return Array.from(relevant);
}

/**
 * Format a single preference as context text
 */
function formatSlotContext(slotName, entry) {
  if (entry.value === null || entry.value === undefined) return null;
  
  const def = getSlotDefinition(slotName);
  const confidence = Math.round(entry.confidence * 100);
  const source = entry.source;
  
  if (Array.isArray(entry.value) && entry.value.length === 0) return null;
  
  if (slotName === 'working_hours') {
    const { start, end, days } = entry.value;
    const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    const activeDays = Array.isArray(days) ? days.map(d => dayNames[d] || d).join(', ') : ' weekdays';
    return `[Preference] Working hours: ${start}–${end} on ${activeDays} (confidence: ${confidence}%, source: ${source})`;
  }
  
  if (Array.isArray(entry.value)) {
    if (entry.value.length === 0) return null;
    return `[Preference] ${slotName}: ${entry.value.slice(0, 5).join(', ')} (confidence: ${confidence}%, source: ${source})`;
  }
  
  return `[Preference] ${slotName}: ${entry.value} (confidence: ${confidence}%, source: ${source})`;
}

/**
 * Get slot definition by name
 */
function getSlotDefinition(slotName) {
  const defs = {
    communication_style: { options: ['concise', 'balanced', 'detailed', 'verbose'] },
    language: { options: ['zh', 'en', 'zh-CN', 'en-US', 'bilingual'] },
    timezone: {},
    response_length: { options: ['short', 'medium', 'long', 'comprehensive'] },
    working_hours: {},
    interests: {},
    goals: {},
    constraints: {},
    preferred_tools: {},
    notification_preference: { options: ['silent', 'minimal', 'normal', 'detailed'] },
    formality_level: { options: ['formal', 'semi-formal', 'casual', 'friendly'] },
  };
  return defs[slotName] || {};
}

/**
 * Main injection function: load relevant preferences for a query
 * @param {string} query - The search query
 * @returns {{ preferences: Object, contextAdditions: string[], relevantSlots: string[] }}
 */
export function injectPreferences(query) {
  const preferences = loadPreferences();
  const relevantSlots = getRelevantSlots(query);
  const contextAdditions = [];
  
  const relevantPrefs = {};
  
  for (const slotName of relevantSlots) {
    const entry = preferences[slotName];
    if (!entry) continue;
    
    const value = entry.value;
    if (value === null || value === undefined) continue;
    if (Array.isArray(value) && value.length === 0) continue;
    
    relevantPrefs[slotName] = entry;
    
    const contextText = formatSlotContext(slotName, entry);
    if (contextText) {
      contextAdditions.push(contextText);
    }
  }
  
  return {
    preferences: relevantPrefs,
    contextAdditions,
    relevantSlots,
    allPreferences: getPreferencesFlat(preferences),
  };
}

/**
 * Build a full context string from all preferences
 */
export function buildFullContextString(preferences) {
  const lines = [];
  lines.push('## User Preferences');
  
  const prioritySlots = ['language', 'communication_style', 'timezone', 'response_length', 'formality_level'];
  
  for (const slotName of prioritySlots) {
    const entry = preferences[slotName];
    if (entry && entry.value !== null && entry.value !== undefined) {
      const ctx = formatSlotContext(slotName, entry);
      if (ctx) lines.push(ctx.replace(/^\[Preference\]\s*/, ''));
    }
  }
  
  // Add arrays
  const arraySlots = ['interests', 'goals', 'constraints', 'preferred_tools'];
  for (const slotName of arraySlots) {
    const entry = preferences[slotName];
    if (entry && Array.isArray(entry.value) && entry.value.length > 0) {
      lines.push(`${slotName}: ${entry.value.slice(0, 5).join(', ')}`);
    }
  }
  
  if (lines.length === 1) return '';
  return lines.join('\n');
}

/**
 * Calculate a preference-based boost multiplier for search results
 */
export function getPreferenceBoostFactor(preferences, category) {
  let boost = 1.0;
  
  const language = preferences.language?.value;
  const style = preferences.communication_style?.value;
  
  // Language alignment
  if (language === 'zh' && category === 'fact') boost *= 1.1;
  if (language === 'en' && category === 'fact') boost *= 1.05;
  
  // Style alignment
  if (style === 'concise' && category === 'fact') boost *= 1.1;
  if (style === 'detailed' && category === 'learning') boost *= 1.1;
  
  return Math.min(boost, 1.5);
}

export default {
  injectPreferences,
  buildFullContextString,
  getPreferenceBoostFactor,
  getRelevantSlots,
};
/**
 * preference_memory_bridge.js — Bidirectional Sync Between Slots and PREFERENCE Memories
 * Part of Feature #10: Structured Preference Slots
 * 
 * Syncs preference slots to/from PREFERENCE category memories for persistence
 * and cross-feature compatibility with the existing memory system.
 */
import { loadPreferences, getSlotValue, updateSlotValue, createSlotEntry, SOURCE_TYPES, persistPreferences } from './preference_slots_schema.js';
import { getAllMemories, addMemory, updateMemory, deleteMemory } from './storage.js';

/**
 * Memory type constant for preference memories
 */
const PREFERENCE_MEMORY_TYPE = 'preference';

/**
 * Extract slot name from memory ID
 */
function memoryIdToSlot(memoryId) {
  return memoryId.replace(/^preference_/, '');
}

/**
 * Create memory ID from slot name
 */
function slotToMemoryId(slotName) {
  return `preference_${slotName}`;
}

/**
 * Convert a slot entry to a memory object
 */
function slotToMemory(slotName, entry) {
  return {
    id: slotToMemoryId(slotName),
    text: formatSlotAsMemoryText(slotName, entry),
    category: PREFERENCE_MEMORY_TYPE,
    importance: entry.confidence,
    tags: [entry.source, slotName],
    created_at: entry.lastUpdated,
  };
}

/**
 * Format slot entry as searchable memory text
 */
function formatSlotAsMemoryText(slotName, entry) {
  const value = entry.value;
  
  if (Array.isArray(value)) {
    return `Preference ${slotName}: ${value.join(', ')} (source: ${entry.source}, confidence: ${entry.confidence})`;
  }
  
  if (typeof value === 'object' && value !== null) {
    return `Preference ${slotName}: ${JSON.stringify(value)} (source: ${entry.source}, confidence: ${entry.confidence})`;
  }
  
  return `Preference ${slotName}: ${value} (source: ${entry.source}, confidence: ${entry.confidence})`;
}

/**
 * Parse memory text back to slot entry
 */
function memoryTextToEntry(text) {
  // Pattern: "Preference slotname: value (source: x, confidence: 0.x)"
  const match = text.match(/^Preference (\w+): (.+?) \(source: (\w+), confidence: ([\d.]+)\)$/);
  if (!match) return null;
  
  const [, slotName, valueStr, source, confidenceStr] = match;
  let value = valueStr;
  
  // Try to parse as JSON array/object
  if (valueStr.startsWith('[') || valueStr.startsWith('{')) {
    try { value = JSON.parse(valueStr); } catch { /* use raw string */ }
  }
  
  return createSlotEntry(value, source, parseFloat(confidenceStr));
}

/**
 * Push all current slot values as PREFERENCE memories
 */
export async function syncSlotsToMemories() {
  const preferences = loadPreferences();
  const results = { synced: 0, failed: 0 };
  
  for (const [slotName, entry] of Object.entries(preferences)) {
    try {
      const memory = slotToMemory(slotName, entry);
      const existing = getAllMemories().find(m => m.id === memory.id);
      
      if (existing) {
        // Update existing
        const { updateMemory: um } = await import('./storage.js');
        // We need the storage module's functions - check if update supports partial
        existing.text = memory.text;
        existing.importance = memory.importance;
        existing.tags = memory.tags;
        existing.updated_at = Date.now();
        um(existing); // storage.updateMemory might need full object
      } else {
        await addMemory(memory);
      }
      results.synced++;
    } catch (err) {
      console.error(`[bridge] Failed to sync slot ${slotName}:`, err.message);
      results.failed++;
    }
  }
  
  return results;
}

/**
 * Pull PREFERENCE memories and update slots
 */
export async function syncMemoriesToSlots() {
  const allMemories = getAllMemories();
  const prefMemories = allMemories.filter(m => m.category === PREFERENCE_MEMORY_TYPE);
  
  const preferences = loadPreferences();
  let updated = 0;
  
  for (const mem of prefMemories) {
    const slotName = memoryIdToSlot(mem.id);
    if (!slotName) continue;
    
    const entry = memoryTextToEntry(mem.text);
    if (!entry) continue;
    
    // Only update if newer (higher lastUpdated)
    const existing = preferences[slotName];
    if (!existing || entry.lastUpdated > existing.lastUpdated) {
      preferences[slotName] = entry;
      updated++;
    }
  }
  
  if (updated > 0) {
    persistPreferences(preferences);
  }
  
  return { updated, total: prefMemories.length };
}

/**
 * Bidirectional sync: merge both directions, highest confidence wins
 */
export async function bidirectionalSync() {
  // First pull from memories to detect any newer values
  const pullResult = await syncMemoriesToSlots();
  
  // Then push current state back to memories
  const pushResult = await syncSlotsToMemories();
  
  return {
    pulled: pullResult,
    pushed: pushResult,
  };
}

/**
 * Get a preference as a memory-compatible object
 */
export function getPreferenceAsMemory(slotName) {
  const preferences = loadPreferences();
  const entry = preferences[slotName];
  if (!entry) return null;
  return slotToMemory(slotName, entry);
}

/**
 * Check if a memory is a preference memory
 */
export function isPreferenceMemory(memory) {
  return memory?.category === PREFERENCE_MEMORY_TYPE || memory?.id?.startsWith('preference_');
}

/**
 * Export all preferences as memories array
 */
export function exportAllAsMemories() {
  const preferences = loadPreferences();
  const memories = [];
  
  for (const [slotName, entry] of Object.entries(preferences)) {
    memories.push(slotToMemory(slotName, entry));
  }
  
  return memories;
}

/**
 * Get sync status between slots and memories
 */
export function getSyncStatus() {
  const preferences = loadPreferences();
  const allMemories = getAllMemories();
  const prefMemories = allMemories.filter(m => isPreferenceMemory(m));
  
  const slotNames = Object.keys(preferences);
  const memoryIds = new Set(prefMemories.map(m => m.id));
  
  const inSync = slotNames.filter(s => memoryIds.has(slotToMemoryId(s))).length;
  const missingInMemory = slotNames.filter(s => !memoryIds.has(slotToMemoryId(s))).length;
  const orphanedInMemory = prefMemories.filter(m => !slotNames.includes(memoryIdToSlot(m.id))).length;
  
  return {
    totalSlots: slotNames.length,
    totalPrefMemories: prefMemories.length,
    inSync,
    missingInMemory,
    orphanedInMemory,
    needsSync: missingInMemory > 0 || orphanedInMemory > 0,
  };
}

export default {
  syncSlotsToMemories,
  syncMemoriesToSlots,
  bidirectionalSync,
  getPreferenceAsMemory,
  isPreferenceMemory,
  exportAllAsMemories,
  getSyncStatus,
  slotToMemoryId,
  memoryIdToSlot,
};
/**
 * preference_slots.js — Structured Preference Slots for unified-memory v1.2
 * Provides typed key-value user preferences that boost relevant memories in search.
 * MCP tool: memory_preference_slots (get/update/merge/reset/delete/stats)
 */
import { readFileSync, writeFileSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const WORKSPACE = process.env.OPENCLAW_WORKSPACE_DIR ?? join(process.env.HOME ?? '/root', '.openclaw', 'workspace');
const SKILL_DIR = join(WORKSPACE, 'memory');
const SLOTS_FILE = join(SKILL_DIR, 'preference_slots.json');

const DEFAULT_SLOTS = {
  communication_style: { value: 'balanced',  type: 'string', updated_at: Date.now() },
  timezone:             { value: 'Asia/Shanghai', type: 'string', updated_at: Date.now() },
  language:             { value: 'zh',        type: 'string', updated_at: Date.now() },
  response_length:      { value: 'medium',    type: 'string', updated_at: Date.now() },
  formality_level:      { value: 'semi-formal', type: 'string', updated_at: Date.now() },
  notification_level:   { value: 'normal',    type: 'string', updated_at: Date.now() },
};

let slotsCache = null;

function loadSlots() {
  if (slotsCache) return slotsCache;
  if (!existsSync(SLOTS_FILE)) { slotsCache = { ...DEFAULT_SLOTS }; persist(slotsCache); return slotsCache; }
  try { slotsCache = { ...DEFAULT_SLOTS, ...JSON.parse(readFileSync(SLOTS_FILE, 'utf8')) }; }
  catch { slotsCache = { ...DEFAULT_SLOTS }; }
  return slotsCache;
}

function persist(slots) {
  try { writeFileSync(SLOTS_FILE, JSON.stringify(slots, null, 2), 'utf8'); }
  catch (err) { console.error('[preference_slots] persist error:', err.message); }
}

export function getSlots() {
  return Object.fromEntries(Object.entries(loadSlots()).map(([k, v]) => [k, v.value]));
}

export function getSlot(key) { return loadSlots()[key]?.value ?? null; }

export function updateSlot(key, value) {
  const slots = loadSlots();
  slots[key] = { value: String(value), type: 'string', updated_at: Date.now() };
  persist(slots);
  return { success: true, slot: { key, ...slots[key] } };
}

export function mergeSlots(updates) {
  const slots = loadSlots();
  let count = 0;
  for (const [key, value] of Object.entries(updates)) {
    slots[key] = { value: String(value), type: 'string', updated_at: Date.now() };
    count++;
  }
  persist(slots);
  return { success: true, updated: count };
}

export function resetSlots() { slotsCache = { ...DEFAULT_SLOTS }; persist(slotsCache); return { success: true }; }

export function deleteSlot(key) {
  const slots = loadSlots();
  if (key in DEFAULT_SLOTS) slots[key] = { ...DEFAULT_SLOTS[key] };
  else delete slots[key];
  persist(slots);
  return { success: true };
}

/** Boost score [0.5 – 2.0] based on preference–memory alignment */
export function getPreferenceBoost(query, category = '', tags = []) {
  const slots = loadSlots();
  const q = query.toLowerCase();
  let b = 1.0;
  if (slots.language?.value === 'zh' && /[\u4e00-\u9fa5]/.test(q)) b *= 1.15;
  if (slots.language?.value === 'en' && !/[\u4e00-\u9fa5]/.test(q)) b *= 1.15;
  if (slots.communication_style?.value === 'concise' && q.length < 40) b *= 1.1;
  if (slots.communication_style?.value === 'detailed' && q.length > 80) b *= 1.1;
  const catSlot = { preference: 'communication_style', fact: 'timezone', decision: 'language', entity: 'language', reflection: 'formality_level' };
  if (catSlot[category] && slots[catSlot[category]]) b *= 1.05;
  const preferred = tags.filter(t => [slots.communication_style?.value, slots.language?.value, slots.timezone?.value].includes(t));
  if (preferred.length > 0) b *= 1 + preferred.length * 0.05;
  return Math.min(b, 2.0);
}

export function memoryPreferenceSlotsTool({ action, key, value, slots: slotMap } = {}) {
  try {
    switch (action) {
      case 'get':    return { content: [{ type: 'text', text: JSON.stringify({ success: true, slots: getSlots() }, null, 2) }] };
      case 'update': if (!key) throw new Error('key required'); return { content: [{ type: 'text', text: JSON.stringify(updateSlot(key, value), null, 2) }] };
      case 'merge':  if (!slotMap) throw new Error('slots object required'); return { content: [{ type: 'text', text: JSON.stringify(mergeSlots(slotMap), null, 2) }] };
      case 'delete': if (!key) throw new Error('key required'); return { content: [{ type: 'text', text: JSON.stringify(deleteSlot(key), null, 2) }] };
      case 'reset':  return { content: [{ type: 'text', text: JSON.stringify(resetSlots(), null, 2) }] };
      case 'stats': {
        const s = loadSlots();
        return { content: [{ type: 'text', text: JSON.stringify({ total: Object.keys(s).length, defaults: Object.keys(DEFAULT_SLOTS).length, slots: s }, null, 2) }] };
      }
      default:
        return { content: [{ type: 'text', text: JSON.stringify({ error: `Unknown action: ${action}`, hint: 'get/update/merge/delete/reset/stats' }, null, 2) }], isError: true };
    }
  } catch (err) { return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true }; }
}

export default { getSlots, getSlot, updateSlot, mergeSlots, resetSlots, deleteSlot, getPreferenceBoost, memoryPreferenceSlotsTool };
/**
 * preference_slots_schema.js — Preference Slots Schema Definition
 * Part of Feature #10: Structured Preference Slots for unified-memory
 * 
 * Defines standard preference slots with typed schemas, confidence scoring,
 * and source attribution (explicit/inferred/historical).
 */
import { readFileSync, writeFileSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const WORKSPACE = process.env.OPENCLAW_WORKSPACE_DIR ?? join(process.env.HOME ?? '/root', '.openclaw', 'workspace');
const PREFERENCES_FILE = join(WORKSPACE, 'memory', 'preferences.json');

/**
 * Standard slot definitions with type, default, and validation
 */
export const SLOT_DEFINITIONS = {
  communication_style: {
    type: 'string',
    default: 'balanced',
    options: ['concise', 'balanced', 'detailed', 'verbose'],
    description: 'How verbose and structured should responses be',
  },
  language: {
    type: 'string',
    default: 'zh',
    options: ['zh', 'en', 'zh-CN', 'en-US', 'bilingual'],
    description: 'Preferred language for responses',
  },
  timezone: {
    type: 'string',
    default: 'Asia/Shanghai',
    description: 'User timezone for time-aware features',
  },
  response_length: {
    type: 'string',
    default: 'medium',
    options: ['short', 'medium', 'long', 'comprehensive'],
    description: 'Preferred response length',
  },
  working_hours: {
    type: 'object',
    default: { start: '09:00', end: '18:00', days: [1, 2, 3, 4, 5] },
    description: 'User working hours (24h format, 0=Sunday)',
  },
  interests: {
    type: 'array',
    default: [],
    itemType: 'string',
    description: 'User interest topics',
  },
  goals: {
    type: 'array',
    default: [],
    itemType: 'string',
    description: 'User goals and objectives',
  },
  constraints: {
    type: 'array',
    default: [],
    itemType: 'string',
    description: 'User constraints and limitations',
  },
  preferred_tools: {
    type: 'array',
    default: [],
    itemType: 'string',
    description: 'Preferred tools and platforms',
  },
  notification_preference: {
    type: 'string',
    default: 'normal',
    options: ['silent', 'minimal', 'normal', 'detailed'],
    description: 'How much notification detail is preferred',
  },
  formality_level: {
    type: 'string',
    default: 'semi-formal',
    options: ['formal', 'semi-formal', 'casual', 'friendly'],
    description: 'Formality level of communication',
  },
};

/**
 * Source types for slot attribution
 */
export const SOURCE_TYPES = {
  EXPLICIT: 'explicit',      // User directly stated
  INFERRED: 'inferred',      // Derived from behavior patterns
  HISTORICAL: 'historical',  // From past memory content
};

/**
 * Create an empty slot entry with metadata
 */
export function createSlotEntry(value, source = SOURCE_TYPES.INFERRED, confidence = 0.5) {
  return {
    value,
    confidence: Math.min(1, Math.max(0, confidence)),
    source,
    lastUpdated: Date.now(),
  };
}

/**
 * Load all preferences from disk
 */
export function loadPreferences() {
  if (!existsSync(PREFERENCES_FILE)) {
    const defaults = getDefaultPreferences();
    persistPreferences(defaults);
    return defaults;
  }
  try {
    const data = JSON.parse(readFileSync(PREFERENCES_FILE, 'utf8'));
    return validateAndMerge(data);
  } catch (err) {
    console.error('[preference_slots_schema] Load error:', err.message);
    return getDefaultPreferences();
  }
}

/**
 * Validate and merge loaded data with schema defaults
 */
export function validateAndMerge(data) {
  const defaults = getDefaultPreferences();
  const validated = {};
  
  for (const [slotName, def] of Object.entries(SLOT_DEFINITIONS)) {
    if (data[slotName] !== undefined) {
      validated[slotName] = {
        ...createSlotEntry(def.default),
        ...data[slotName],
      };
      // Type coercion
      if (def.type === 'array' && !Array.isArray(validated[slotName].value)) {
        validated[slotName].value = def.default;
      }
    } else {
      validated[slotName] = createSlotEntry(def.default, SOURCE_TYPES.HISTORICAL, 0.5);
    }
  }
  return validated;
}

/**
 * Get default preferences from slot definitions
 */
export function getDefaultPreferences() {
  const prefs = {};
  for (const [slotName, def] of Object.entries(SLOT_DEFINITIONS)) {
    prefs[slotName] = createSlotEntry(def.default, SOURCE_TYPES.HISTORICAL, 0.5);
  }
  return prefs;
}

/**
 * Persist preferences to disk
 */
export function persistPreferences(prefs) {
  try {
    const dir = join(WORKSPACE, 'memory');
    if (!existsSync(dir)) {
      mkdirSync(dir, { recursive: true });
    }
    writeFileSync(PREFERENCES_FILE, JSON.stringify(prefs, null, 2), 'utf8');
  } catch (err) {
    console.error('[preference_slots_schema] Persist error:', err.message);
  }
}

/**
 * Get a single slot value (unpacked from slot entry)
 */
export function getSlotValue(preferences, slotName) {
  return preferences[slotName]?.value ?? null;
}

/**
 * Get slot entry with full metadata
 */
export function getSlotEntry(preferences, slotName) {
  return preferences[slotName] ?? null;
}

/**
 * Update a single slot
 */
export function updateSlotValue(preferences, slotName, value, source = SOURCE_TYPES.EXPLICIT, confidence = 0.9) {
  const def = SLOT_DEFINITIONS[slotName];
  if (!def) throw new Error(`Unknown slot: ${slotName}`);
  
  // Validate value
  if (def.options && !def.options.includes(value)) {
    throw new Error(`Invalid value for ${slotName}: ${value}. Options: ${def.options.join(', ')}`);
  }
  
  preferences[slotName] = createSlotEntry(value, source, confidence);
  return preferences[slotName];
}

/**
 * Get all slot names
 */
export function getSlotNames() {
  return Object.keys(SLOT_DEFINITIONS);
}

/**
 * Get slot definition
 */
export function getSlotDefinition(slotName) {
  return SLOT_DEFINITIONS[slotName] ?? null;
}

/**
 * Get preferences as simple key-value map (for injection)
 */
export function getPreferencesFlat(preferences) {
  const flat = {};
  for (const [slotName, entry] of Object.entries(preferences)) {
    flat[slotName] = entry.value;
  }
  return flat;
}

export default {
  SLOT_DEFINITIONS,
  SOURCE_TYPES,
  createSlotEntry,
  loadPreferences,
  validateAndMerge,
  getDefaultPreferences,
  persistPreferences,
  getSlotValue,
  getSlotEntry,
  updateSlotValue,
  getSlotNames,
  getSlotDefinition,
  getPreferencesFlat,
};
/**
 * Proactive Memory Manager v1.0
 * Unified management of proactive recall and proactive care
 * Periodic checks, active injection
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join } from 'path';
import { getAllMemories } from './storage.js';
import { predictRecall } from './core/proactive_recall.js';
import { runCheck as runProactiveCare } from './core/proactive_care.js';
import { autoDegrade } from './quality.js';
import { runLifecycle, autoMigrateTiers } from './tier.js';
import { saveMemories } from './storage.js';

const LIFECYCLE_STATE_FILE = join(process.env.HOME || '/root', '.unified-memory', 'lifecycle_state.json');
const DAILY_MIGRATION_INTERVAL_MS = 24 * 60 * 60 * 1000; // 24 hours

function loadOperationCount() {
  try {
    if (existsSync(LIFECYCLE_STATE_FILE)) {
      const data = JSON.parse(readFileSync(LIFECYCLE_STATE_FILE, 'utf8'));
      return {
        count: typeof data.operationCount === 'number' ? data.operationCount : 0,
        lastDailyMigration: data.lastDailyMigration || 0,
      };
    }
  } catch { /* ignore */ }
  return { count: 0, lastDailyMigration: 0 };
}

function saveOperationCount(count, lastDailyMigration) {
  try {
    const dir = join(process.env.HOME || '/root', '.unified-memory');
    if (!existsSync(dir)) {
      mkdirSync(dir, { recursive: true });
    }
    writeFileSync(LIFECYCLE_STATE_FILE, JSON.stringify({ operationCount: count, lastDailyMigration }, null, 2), 'utf8');
  } catch (e) {
    console.error('[ProactiveManager] failed to persist state:', e.message);
  }
}

export class ProactiveManager {
  constructor(intervalMs = 300000) { // Default 5 minutes
    this.intervalMs = intervalMs;
    this.timer = null;
    this.lastRecallResults = [];
    this.lastCareResults = null;
    const state = loadOperationCount();
    this.operationCount = state.count;
    this.lastDailyMigration = state.lastDailyMigration;
  }

  start() {
    if (this.timer) return;
    this.timer = setInterval(() => this.tick(), this.intervalMs);
    console.log(`[ProactiveManager] started, interval=${this.intervalMs}ms`);
  }

  stop() {
    if (this.timer) {
      clearInterval(this.timer);
      this.timer = null;
    }
  }

  async tick() {
    try {
      // 1. Run proactive care (status detection)
      this.lastCareResults = await runProactiveCare();

      // 2. Predict memories that need recall
      const recent = this._getRecentContext();
      this.lastRecallResults = predictRecall(recent);

      // 3. Auto-degrade low-quality memories to COLD tier
      this.lastDegradeResult = autoDegrade({ threshold: 0.15, batchSize: 50 });

      // 4. Lifecycle: every 100 operations, run lifecycle management
      this.operationCount++;
      if (this.operationCount % 100 === 0) {
        console.log(`[ProactiveManager] operationCount=${this.operationCount}, triggering lifecycle...`);
        this.lastLifecycleResult = runLifecycle();
        saveOperationCount(this.operationCount, this.lastDailyMigration);
      }

      // 5. Daily tier migration: check every tick if 24h has passed
      const now = Date.now();
      if (now - this.lastDailyMigration >= DAILY_MIGRATION_INTERVAL_MS) {
        console.log('[ProactiveManager] Running daily tier migration...');
        try {
          const memories = getAllMemories();
          const result = autoMigrateTiers(memories, { dryRun: false });
          if (result.changes.length > 0) {
            saveMemories(result.memories);
            console.log(`[ProactiveManager] Tier migration: ${result.changes.length} memories moved`);
          }
          this.lastDailyMigration = now;
          this.lastMigrationResult = result;
          saveOperationCount(this.operationCount, this.lastDailyMigration);
        } catch (e) {
          console.error('[ProactiveManager] Daily migration error:', e.message);
        }
      }

      return {
        care: this.lastCareResults,
        recall: this.lastRecallResults.slice(0, 5),
        degrade: this.lastDegradeResult,
        lifecycle: this.lastLifecycleResult || null,
        migration: this.lastMigrationResult || null,
        ts: Date.now(),
      };
    } catch (e) {
      console.error('[ProactiveManager] tick error:', e.message);
    }
  }

  _getRecentContext() {
    // Extract context from recent memories
    const memories = getAllMemories();
    const recent = memories
      .sort((a, b) => (b.updated_at || 0) - (a.updated_at || 0))
      .slice(0, 10)
      .map(m => m.text)
      .join(' ');
    return recent;
  }

  getStatus() {
    return {
      running: !!this.timer,
      intervalMs: this.intervalMs,
      lastCare: this.lastCareResults,
      lastRecallCount: this.lastRecallResults.length,
      recallPredictions: this.lastRecallResults.slice(0, 3),
      lastDegrade: this.lastDegradeResult || null,
      lastMigrationCount: this.lastMigrationResult?.changes?.length || 0,
      lastMigrationTs: this.lastMigrationResult ? Date.now() : null,
    };
  }

  // Manual trigger once
  async trigger() {
    return this.tick();
  }
}

// Global instance
let globalManager = null;

export function getProactiveManager() {
  if (!globalManager) {
    globalManager = new ProactiveManager();
  }
  return globalManager;
}
/**
 * Proactive Scheduler v1.0
 * Cron-based scheduler for proactive recall using setInterval
 * Schedule types: periodic (every N minutes), time_based (HH:MM), event_based (keywords)
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join } from 'path';

const WORKSPACE = join(process.env.HOME || '/root', '.openclaw', 'workspace');
const SCHEDULE_FILE = join(WORKSPACE, 'memory', 'proactive_schedules.json');

// ─── Storage ──────────────────────────────────────────────────────────────────

function ensureDir() {
  const dir = join(WORKSPACE, 'memory');
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
}

export function loadSchedules() {
  ensureDir();
  if (!existsSync(SCHEDULE_FILE)) return [];
  try { return JSON.parse(readFileSync(SCHEDULE_FILE, 'utf-8')); }
  catch { return []; }
}

export function saveSchedules(schedules) {
  ensureDir();
  writeFileSync(SCHEDULE_FILE, JSON.stringify(schedules, null, 2), 'utf-8');
}

export function addSchedule(schedule) {
  const schedules = loadSchedules();
  schedules.push(schedule);
  saveSchedules(schedules);
  return schedule;
}

export function removeSchedule(id) {
  const schedules = loadSchedules();
  const idx = schedules.findIndex(s => s.id === id);
  if (idx === -1) return false;
  schedules.splice(idx, 1);
  saveSchedules(schedules);
  return true;
}

export function updateSchedule(id, patch) {
  const schedules = loadSchedules();
  const idx = schedules.findIndex(s => s.id === id);
  if (idx === -1) return null;
  schedules[idx] = { ...schedules[idx], ...patch };
  saveSchedules(schedules);
  return schedules[idx];
}

// ─── Time Helpers ─────────────────────────────────────────────────────────────

function getCurrentHHMM() {
  const now = new Date();
  return `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;
}

// ─── Scheduler Engine ─────────────────────────────────────────────────────────

export class ProactiveScheduler {
  constructor() {
    this.timers = new Map(); // scheduleId -> intervalId
    this.enabled = false;
    this._tickInterval = null;
    /** @type {import('./recall_trigger.js')} */
    this.recallTrigger = null;
  }

  setRecallTrigger(rt) {
    this.recallTrigger = rt;
  }

  start() {
    if (this.enabled) return;
    this.enabled = true;

    // Master tick every 60 seconds for time-based checks
    this._tickInterval = setInterval(() => this._onTick(), 60_000);
    this._onTick(); // immediate first run

    // Setup periodic schedules
    const schedules = loadSchedules();
    for (const sched of schedules) {
      if (sched.enabled) this._startSchedule(sched);
    }

    console.log('[ProactiveScheduler] started');
  }

  stop() {
    if (!this.enabled) return;
    this.enabled = false;
    if (this._tickInterval) {
      clearInterval(this._tickInterval);
      this._tickInterval = null;
    }
    for (const tid of this.timers.values()) {
      clearInterval(tid);
    }
    this.timers.clear();
    console.log('[ProactiveScheduler] stopped');
  }

  _startSchedule(sched) {
    if (this.timers.has(sched.id)) return;

    if (sched.type === 'periodic') {
      const ms = (sched.config.intervalMinutes || 30) * 60_000;
      const tid = setInterval(() => this._firePeriodic(sched), ms);
      this.timers.set(sched.id, tid);
    }
    // time_based and event_based handled in _onTick
  }

  _stopSchedule(schedId) {
    const tid = this.timers.get(schedId);
    if (tid !== undefined) {
      clearInterval(tid);
      this.timers.delete(schedId);
    }
  }

  _firePeriodic(sched) {
    if (!this.recallTrigger) return;
    try {
      this.recallTrigger.fireRecall(sched);
    } catch (e) {
      console.error(`[ProactiveScheduler] fire error for ${sched.id}:`, e.message);
    }
  }

  async _onTick() {
    if (!this.recallTrigger) return;
    const now = new Date();
    const schedules = loadSchedules();

    for (const sched of schedules) {
      if (!sched.enabled) continue;

      if (sched.type === 'time_based') {
        const currentHHMM = getCurrentHHMM();
        const lastFired = sched.lastFired
          ? new Date(sched.lastFired).toTimeString().slice(0, 5)
          : '';

        for (const t of sched.config.times || []) {
          if (t === currentHHMM && t !== lastFired) {
            try {
              await this.recallTrigger.fireRecall(sched);
              updateSchedule(sched.id, { lastFired: now.toISOString() });
            } catch (e) {
              console.error(`[ProactiveScheduler] time_based fire error:`, e.message);
            }
            break;
          }
        }
      }
    }
  }

  /** Called by heartbeat hook */
  async onHeartbeat(context) {
    if (!this.recallTrigger) return [];
    const schedules = loadSchedules();
    const results = [];

    for (const sched of schedules) {
      if (!sched.enabled || sched.type !== 'event_based') continue;
      const { keywords = [], categories = [] } = sched.config;

      let matched = false;
      const ctxLower = (context || '').toLowerCase();

      if (keywords.length > 0) {
        matched = keywords.some(k => ctxLower.includes(k.toLowerCase()));
      }
      if (!matched && categories.length > 0) {
        // categories checked against memory context
        matched = categories.some(c => ctxLower.includes(c.toLowerCase()));
      }

      if (matched) {
        try {
          const result = await this.recallTrigger.fireRecall(sched);
          results.push(result);
        } catch (e) {
          console.error(`[ProactiveScheduler] event_based fire error:`, e.message);
        }
      }
    }

    return results;
  }

  add(sched) {
    addSchedule(sched);
    if (sched.enabled && sched.type === 'periodic') {
      this._startSchedule(sched);
    }
  }

  remove(id) {
    this._stopSchedule(id);
    removeSchedule(id);
  }

  list() {
    return loadSchedules();
  }

  enable(id) {
    const sched = updateSchedule(id, { enabled: true });
    if (sched) this._startSchedule(sched);
    return sched;
  }

  disable(id) {
    this._stopSchedule(id);
    return updateSchedule(id, { enabled: false });
  }
}

// Singleton
let _scheduler = null;

export function getProactiveScheduler() {
  if (!_scheduler) _scheduler = new ProactiveScheduler();
  return _scheduler;
}
/**
 * profile.js — Profile Aggregator for Unified Memory
 * 
 * 实现 SuperMemory 风格的 User Profile 抽象：
 * - static: 长期稳定事实 + 偏好
 * - dynamic: 近期上下文 + 进行中的工作
 * 
 * 核心逻辑：
 * 1. 搜索某 scope 下所有 fact/preference/identity 类记忆
 * 2. 按实体分组，检测矛盾（同实体多版本）
 * 3. 按访问频率和时间分离 static vs dynamic
 * 4. 聚合返回结构化 profile
 */

import { getAllMemories } from './storage.js';
import { search } from './search.js';
import { extractEntities } from './graph/entity.js';
import { config } from './config.js';
import { log } from './logger.js';

const DEFAULT_STATIC_DAYS = 30;        // 超过 30 天无访问 → static
const DEFAULT_ACCESS_THRESHOLD = 3;   // 过去 7 天访问 ≥3 次 → dynamic
const RECENCY_WINDOW_DAYS = 7;         // 近期窗口

// ─── 实体类型黑名单：这些实体的记忆通常偏 dynamic ───────────────────────────────
const DYNAMIC_ENTITY_KEYWORDS = [
  'project', '任务', '工作', '当前', '最近', '进行中',
  'issue', 'bug', 'todo', 'roadmap', 'sprint',
];

// ─── Static 类 category/type ──────────────────────────────────────────────────
const STATIC_CATEGORIES = new Set(['preference', 'identity', 'habit', 'goal', 'skill']);
const FACT_CATEGORIES = new Set(['fact', 'decision']);

// ─── 工具函数 ────────────────────────────────────────────────────────────────

/**
 * 判断实体名是否暗示 dynamic 内容
 */
function isLikelyDynamic(entityName) {
  const lower = (entityName || '').toLowerCase();
  return DYNAMIC_ENTITY_KEYWORDS.some(kw => lower.includes(kw));
}

/**
 * 计算记忆"新鲜度"：0=完全陈旧，1=最近频繁访问
 */
function computeFreshness(mem) {
  const now = Date.now();
  const created = mem.created || now;
  const lastAccessed = mem.lastAccessed || mem.touchTime || created;
  
  const ageDays = (now - lastAccessed) / (24 * 60 * 60 * 1000);
  const accessCount = mem.accessCount || 1;
  
  // Weibull-ish 衰减：7天内频繁访问 → 高新鲜度
  const ageScore = Math.exp(-ageDays / RECENCY_WINDOW_DAYS);
  const accessScore = Math.min(1, (accessCount - 1) / 5); // 0-5次访问映射到 0-1
  
  return Math.min(1, ageScore * 0.7 + accessScore * 0.3);
}

/**
 * 合并语义相似的记忆文本（简单的关键词重叠检测）
 */
function findSimilarClusters(memories) {
  const clusters = [];
  const used = new Set();
  
  for (const mem of memories) {
    if (used.has(mem.id)) continue;
    
    const cluster = [mem];
    used.add(mem.id);
    
    const words = new Set(
      (mem.text || '')
        .toLowerCase()
        .replace(/[^\w\s]/g, ' ')
        .split(/\s+/)
        .filter(w => w.length > 2)
    );
    
    for (const other of memories) {
      if (used.has(other.id)) continue;
      const otherWords = new Set(
        (other.text || '')
          .toLowerCase()
          .replace(/[^\w\s]/g, ' ')
          .split(/\s+/)
          .filter(w => w.length > 2)
      );
      
      // Jaccard 相似度
      const intersection = [...words].filter(w => otherWords.has(w)).length;
      const union = new Set([...words, ...otherWords]).size;
      const similarity = union > 0 ? intersection / union : 0;
      
      if (similarity > 0.4) {
        cluster.push(other);
        used.add(other.id);
      }
    }
    
    clusters.push(cluster);
  }
  
  return clusters;
}

// ─── 核心 Profile 聚合 ──────────────────────────────────────────────────────

/**
 * 获取指定 scope 的用户 profile
 * 
 * @param {object} options
 * @param {string} [options.scope='user'] - 'agent' | 'user' | 'team' | 'global'
 * @param {string} [options.containerTag] - 项目标签（lane）
 * @param {string} [options.entityFilter] - 只返回某实体的 profile
 * @param {number} [options.staticDays] - 超过 N 天无访问视为 static
 * @param {number} [options.limit=100] - 最大记忆数量
 * @param {object} [options.llm] - 可选 LLM client，用于压缩
 * @returns {Promise<Profile>}
 */
export async function getProfile({
  scope = 'user',
  containerTag = null,
  entityFilter = null,
  staticDays = DEFAULT_STATIC_DAYS,
  limit = 100,
  llm = null,
} = {}) {
  const staticThresholdMs = staticDays * 24 * 60 * 60 * 1000;
  const now = Date.now();
  
  // ── Step 1: 搜索相关记忆 ──────────────────────────────────────────────────
  let allMemories = [];
  
  try {
    // 优先用 search engine（混合搜索 + BM25）
    const searchResults = await search('', {
      scope,
      categories: ['fact', 'preference', 'identity', 'habit', 'goal', 'skill', 'decision'],
      limit,
    });
    
    // search 可能返回 rank 或直接返回 memory 对象
    allMemories = searchResults.map(r => r.memory || r).filter(Boolean);
  } catch (e) {
    // fallback 到 storage 直接读取
    log('WARN', `[profile] search failed: ${e.message}, using getAllMemories`);
    const raw = await getAllMemories({ scope, category: ['fact', 'preference', 'identity'] });
    allMemories = raw.memories || [];
  }
  
  // 按 containerTag 过滤
  if (containerTag) {
    allMemories = allMemories.filter(m => 
      m.containerTag === containerTag || m.tags?.includes(containerTag)
    );
  }
  
  // ── Step 2: 实体分组 ──────────────────────────────────────────────────────
  const entityGroups = new Map(); // entityName → { entity, memories: [] }
  
  for (const mem of allMemories) {
    const text = mem.text || '';
    let entities = [];
    
    try {
      entities = extractEntities(text) || [];
    } catch (e) {
      // entity extraction 失败时用关键词兜底
      const personMatches = text.match(/@(\S+)/g) || [];
      const hashMatches = text.match(/#(\S+)/g) || [];
      entities = [
        ...personMatches.map(m => ({ name: m.slice(1), type: 'person' })),
        ...hashMatches.map(m => ({ name: m.slice(1), type: 'topic' })),
      ];
    }
    
    const primaryEntity = entities[0]?.name || '_anonymous';
    
    // entityFilter 过滤
    if (entityFilter && !primaryEntity.toLowerCase().includes(entityFilter.toLowerCase())) {
      continue;
    }
    
    if (!entityGroups.has(primaryEntity)) {
      entityGroups.set(primaryEntity, {
        entity: primaryEntity,
        entityType: entities[0]?.type || 'unknown',
        memories: [],
      });
    }
    entityGroups.get(primaryEntity).memories.push(mem);
  }
  
  // ── Step 3: 分离 static vs dynamic ──────────────────────────────────────
  const staticFacts = [];
  const dynamicFacts = [];
  
  for (const [entityName, group] of entityGroups) {
    // 实体名暗示 dynamic（如 project、进行中）
    const likelyDynamic = isLikelyDynamic(entityName);
    
    // 按时间排序，最新的在前
    const sorted = [...group.memories].sort((a, b) => {
      const aTime = b.lastAccessed || b.touchTime || b.created || 0;
      const bTime = a.lastAccessed || a.touchTime || a.created || 0;
      return bTime - aTime;
    });
    
    const latest = sorted[0];
    const age = now - (latest.lastAccessed || latest.touchTime || latest.created || now);
    
    if (likelyDynamic) {
      // 这类实体默认 dynamic
      dynamicFacts.push(...sorted);
    } else if (age >= staticThresholdMs && latest.accessCount >= DEFAULT_ACCESS_THRESHOLD) {
      // 老记忆但频繁访问 → dynamic（反复查看说明还在变化）
      dynamicFacts.push(...sorted);
    } else if (age >= staticThresholdMs) {
      // 长期稳定 → static
      staticFacts.push(latest);
    } else {
      // 新记忆 → dynamic
      dynamicFacts.push(...sorted);
    }
  }
  
  // ── Step 4: 偏好类全部进 static ──────────────────────────────────────────
  const preferenceMemories = allMemories.filter(m => STATIC_CATEGORIES.has(m.category));
  for (const p of preferenceMemories) {
    if (!staticFacts.find(s => s.id === p.id)) {
      staticFacts.push(p);
    }
  }
  
  // ── Step 5: 相似记忆合并 ──────────────────────────────────────────────────
  const mergedStatic = mergeSimilar(staticFacts);
  const mergedDynamic = mergeSimilar(dynamicFacts);
  
  // ── Step 6: 生成摘要 ──────────────────────────────────────────────────────
  let summary = '';
  if (llm && (mergedStatic.length > 10 || mergedDynamic.length > 5)) {
    try {
      summary = await compressProfileWithLLM(mergedStatic, mergedDynamic, llm);
    } catch (e) {
      log('WARN', `[profile] LLM compression failed: ${e.message}`);
    }
  }
  
  // ── Step 7: 计算置信度 ───────────────────────────────────────────────────
  const confidence = calculateConfidence(
    allMemories.length,
    mergedStatic.length,
    mergedDynamic.length
  );
  
  return {
    // 核心字段：SuperMemory 风格
    static: mergedStatic.map(m => m.text || m.content),
    dynamic: mergedDynamic.map(m => m.text || m.content),
    
    // 附加信息
    summary: summary || null,
    confidence,
    
    // 统计
    memoryCount: {
      total: allMemories.length,
      static: mergedStatic.length,
      dynamic: mergedDynamic.length,
    },
    
    // 按实体分类的 profile（可选，方便调试）
    byEntity: entityFilter ? null : Object.fromEntries(
      [...entityGroups.entries()].map(([name, g]) => [
        name,
        {
          type: g.entityType,
          count: g.memories.length,
          latestText: g.memories[0]?.text,
          isStatic: !dynamicFacts.find(d => d.id === g.memories[0]?.id),
        },
      ])
    ),
    
    lastUpdated: now,
    scope,
    containerTag,
  };
}

/**
 * 合并语义相似的记忆（simple Jaccard-based clustering）
 */
function mergeSimilar(memories) {
  const clusters = findSimilarClusters(memories);
  
  // 每个 cluster 取 importance 最高的一条
  return clusters.map(cluster => {
    cluster.sort((a, b) => (b.importance || 0.5) - (a.importance || 0.5));
    return cluster[0];
  });
}

/**
 * 置信度计算
 */
function calculateConfidence(total, staticCount, dynamicCount) {
  if (total === 0) return 0;
  
  // 覆盖度：记忆越多越可信（50 条满）
  const coverage = Math.min(1, total / 50);
  
  // 平衡度：static/dynamic 不要一边倒
  const totalClassified = staticCount + dynamicCount;
  const balance = totalClassified > 0
    ? 1 - Math.abs(staticCount - dynamicCount) / totalClassified
    : 0;
  
  // 组合
  const raw = coverage * 0.6 + balance * 0.4;
  return Math.round(Math.min(1, raw) * 100) / 100;
}

/**
 * 用 LLM 压缩超长的 profile（>20 条时触发）
 */
async function compressProfileWithLLM(staticFacts, dynamicFacts, llm) {
  const staticTexts = staticFacts.map(m => `- ${m.text}`).join('\n');
  const dynamicTexts = dynamicFacts.map(m => `- ${m.text}`).join('\n');
  
  const prompt = `你是记忆摘要助手。把下面的记忆压缩成简洁的摘要，保留关键信息。

STATIC（长期事实）:
${staticTexts}

DYNAMIC（近期上下文）:
${dynamicTexts}

输出 JSON：
{
  "static_summary": "一句话总结用户的长期特征",
  "dynamic_summary": "一句话总结用户最近在做什么",
}
`;

  const response = await llm.generate(prompt, null, null, { max_tokens: 200 });
  const content = typeof response === 'string' ? response : response.content;
  
  try {
    // 尝试解析 JSON
    const match = content.match(/\{[\s\S]*\}/);
    if (match) {
      return JSON.parse(match[0]);
    }
  } catch {
    // 解析失败返回原文
  }
  
  return content.slice(0, 500);
}

// ─── 批量 Profile（多用户/多 agent）────────────────────────────────────────

/**
 * 获取团队或所有 agent 的 profiles
 * @param {object} options
 * @param {string} options.scope
 * @returns {Promise<Map<string, Profile>>}
 */
export async function getTeamProfiles(scope = 'team') {
  const allMemories = await getAllMemories({ scope, limit: 500 });
  const memories = allMemories.memories || allMemories;
  
  // 按 creator/user 分组
  const byOwner = new Map();
  for (const mem of memories) {
    const owner = mem.creator || mem.userId || '_unknown';
    if (!byOwner.has(owner)) byOwner.set(owner, []);
    byOwner.get(owner).push(mem);
  }
  
  const results = new Map();
  for (const [owner, ownerMemories] of byOwner) {
    const profile = await getProfile({ scope, limit: 50 });
    profile.owner = owner;
    results.set(owner, profile);
  }
  
  return results;
}

// ─── 导出默认工具函数 ───────────────────────────────────────────────────────

export default { getProfile, getTeamProfiles };
/**
 * qmd_integration.js — QMD as optional vector search backend for unified-memory
 * P1-1: Deep QMD integration
 * 
 * Allows unified-memory to use QMD as a search backend via:
 * - Direct CLI invocation (/usr/local/bin/qmd)
 * - HTTP API (qmd's built-in REST server on unix socket or port)
 * 
 * When VECTOR_ENGINE=qmd, all vector search routes through this module.
 * qmd config: ~/.qmd/config.toml
 */

import { spawn } from 'child_process';
import { existsSync } from 'fs';
import { join } from 'path';
import { createRequire } from 'module';
import { getAllMemories, addMemory } from './storage.js';

const req = createRequire(import.meta.url);
const HOME = process.env.HOME || '/root';
const QMD_CLI = '/usr/local/bin/qmd';
const QMD_CONFIG = join(HOME, '.qmd', 'config.toml');
const MEMORY_DIR = join(HOME, '.openclaw', 'workspace', 'memory');

// ============================================================
// QMD CLI helpers
// ============================================================

function execQMD(args, timeoutMs = 10000) {
  return new Promise((resolve, reject) => {
    if (!existsSync(QMD_CLI)) {
      reject(new Error(`QMD CLI not found at ${QMD_CLI}`));
      return;
    }

    const timer = setTimeout(() => {
      try { proc.kill(); } catch { /* ignore */ }
      reject(new Error(`QMD timed out after ${timeoutMs}ms`));
    }, timeoutMs);

    const proc = spawn(QMD_CLI, args, {
      cwd: MEMORY_DIR,
      env: { ...process.env, PATH: '/usr/local/bin:/usr/bin:/bin:/root/.local/bin' }
    });

    let stdout = '';
    let stderr = '';

    proc.stdout.on('data', d => stdout += d.toString());
    proc.stderr.on('data', d => stderr += d.toString());

    proc.on('close', code => {
      clearTimeout(timer);
      if (code === 0) {
        resolve(stdout);
      } else {
        reject(new Error(`QMD exited ${code}: ${stderr || stdout}`.slice(0, 300)));
      }
    });

    proc.on('error', err => {
      clearTimeout(timer);
      reject(err);
    });
  });
}

async function isQMDAvailable() {
  try {
    await execQMD(['--version'], 5000);
    return true;
  } catch {
    return false;
  }
}

// ============================================================
// Tokenizer (shared with qmd_search.js)
// ============================================================

function tokenize(text) {
  const tokens = [];
  const english = (text.match(/[a-zA-Z]+/g) || []).map(t => t.toLowerCase());
  tokens.push(...english);
  const chinese = (text.match(/[\u4e00-\u9fff]/g) || []);
  tokens.push(...chinese);
  const numbers = (text.match(/\d+/g) || []);
  tokens.push(...numbers);
  return tokens;
}

// ============================================================
// Core: QMD as vector search backend
// ============================================================

/**
 * Check if QMD is configured as the active vector engine
 */
export function isQMDEngine() {
  return (process.env.VECTOR_ENGINE || '').toLowerCase() === 'qmd';
}

/**
 * Get QMD engine status
 */
export async function getQMDEngineStatus() {
  const available = await isQMDAvailable();
  const memories = getAllMemories();
  const configExists = existsSync(QMD_CONFIG);

  return {
    engine: 'qmd',
    available,
    config_path: QMD_CONFIG,
    config_exists: configExists,
    qmd_cli: QMD_CLI,
    memory_count: memories.length,
    active: isQMDEngine(),
  };
}

/**
 * Search using QMD — returns unified-memory formatted results
 * Maps QMD's output format to unified-memory's memory format
 * @param {string} query
 * @param {object} options
 * @returns {Promise<Array>}
 */
export async function qmdEngineSearch(query, options = {}) {
  const { topK = 5, mode = 'hybrid', scope } = options;

  const allResults = [];

  // 1. QMD CLI search (BM25)
  try {
    const raw = await execQMD(['search', query, '-n', String(topK * 3), '--json']);
    const parsed = JSON.parse(raw);
    const docs = Array.isArray(parsed) ? parsed : (parsed.files || []);

    for (const item of docs) {
      allResults.push({
        id: item.docid || item.file || '',
        text: (item.snippet || '').replace(/^@@.*@@\n/, '').slice(0, 400),
        fullText: item.snippet || '',
        score: item.score || 0,
        category: 'local_file',
        mode: 'bm25',
        source: 'qmd',
        path: item.file || '',
        title: item.title || (item.file || '').split('/').pop() || '',
      });
    }
  } catch (err) {
    console.error('[qmd_engine] QMD CLI search failed:', err.message);
  }

  // 2. Memory store search (BM25 fallback when QMD unavailable)
  try {
    const memories = getAllMemories();
    const queryTokens = tokenize(query);

    // Optional scope filter
    let filteredMemories = memories;
    if (scope) {
      const scopeUpper = scope.toUpperCase();
      filteredMemories = memories.filter(m =>
        (m.scope || 'USER').toUpperCase() === scopeUpper ||
        (m.scope || 'USER').toUpperCase() === 'GLOBAL'
      );
    }

    let maxScore = 0;
    for (const mem of filteredMemories) {
      const text = mem.text || '';
      const memTokens = tokenize(text);

      let score = 0;
      for (const qt of queryTokens) {
        if (text.toLowerCase().includes(qt.toLowerCase())) {
          score += 1;
        }
        for (const mt of memTokens) {
          if (mt.includes(qt) || qt.includes(mt)) {
            score += 0.5;
          }
        }
      }

      if (score > 0) {
        if (score > maxScore) maxScore = score;
        allResults.push({
          id: mem.id,
          text: text.slice(0, 400),
          fullText: text,
          score: score,
          category: mem.category || 'memory',
          mode: 'keyword',
          source: 'memory',
          memory: mem,
        });
      }
    }

    // Normalize memory scores to 0-1
    if (maxScore > 0) {
      for (const r of allResults) {
        if (r.source === 'memory') {
          r.score = r.score / maxScore;
        }
      }
    }
  } catch (err) {
    console.error('[qmd_engine] Memory search failed:', err.message);
  }

  // Normalize QMD scores (they're already ~0-1 from BM25)
  const maxQmd = Math.max(...allResults.filter(r => r.source === 'qmd').map(r => r.score), 0.01);
  for (const r of allResults) {
    if (r.source === 'qmd') {
      r.score = r.score / maxQmd;
    }
  }

  // Sort by score descending
  allResults.sort((a, b) => b.score - a.score);
  return allResults.slice(0, topK);
}

/**
 * Vector search via QMD's semantic search pipeline
 * Falls back to BM25 if semantic not available
 * @param {string} query
 * @param {object} options
 * @returns {Promise<Array>}
 */
export async function qmdVectorSearch(query, options = {}) {
  const { topK = 5 } = options;

  // Try QMD's semantic search if available
  try {
    const raw = await execQMD(['search', query, '-n', String(topK * 4), '--json', '--mode', 'semantic']);
    const parsed = JSON.parse(raw);
    if (parsed && parsed.length > 0) {
      return parsed.slice(0, topK).map(item => ({
        id: item.docid || item.file || '',
        path: item.file || '',
        title: item.title || '',
        snippet: (item.snippet || '').replace(/^@@.*@@\n/, '').slice(0, 400),
        score: item.score || 0,
        source: 'qmd_semantic',
        mode: 'semantic',
      }));
    }
  } catch {
    // Semantic mode not available — fall back to BM25
  }

  // Fallback to BM25 search
  return qmdEngineSearch(query, { topK, mode: 'bm25' });
}

/**
 * Unified entry point: routes to QMD or built-in based on VECTOR_ENGINE env
 * @param {string} query
 * @param {object} options
 * @returns {Promise<Array>}
 */
export async function vectorSearch(query, options = {}) {
  if (isQMDEngine()) {
    return qmdEngineSearch(query, options);
  }
  // If not QMD engine, delegate to existing qmd_search.js
  const { qmdSearch: qmdCliSearch } = await import('./tools/qmd_search.js');
  return qmdCliSearch(query, { ...options, mode: options.mode || 'hybrid' });
}

/**
 * Ingest a memory into QMD's index (via qmd add)
 * @param {object} memory - unified-memory memory object
 */
export async function ingestMemoryToQMD(memory) {
  try {
    const text = memory.text || '';
    if (!text.trim()) return;

    // Write memory to a temp file and add to QMD
    const { writeFileSync, unlinkSync, mkdtempSync } = await import('fs');
    const { join } = await import('path');
    const { randomBytes } = await import('crypto');

    const tmpDir = mkdtempSync(join(HOME, '.tmp-qmd-ingest-'));
    const tmpFile = join(tmpDir, `mem-${memory.id}.md`);

    // Format as markdown with metadata
    const content = [
      `---
id: ${memory.id}
category: ${memory.category || 'general'}
scope: ${memory.scope || 'USER'}
importance: ${memory.importance || 0.5}
tags: ${Array.isArray(memory.tags) ? memory.tags.join(', ') : ''}
created: ${new Date(memory.created_at).toISOString()}
---
${text}`,
    ].join('\n');

    writeFileSync(tmpFile, content, 'utf8');

    await execQMD(['add', tmpFile], 10000).catch(() => {});

    try { unlinkSync(tmpFile); } catch { /* ignore */ }
    try { unlinkSync(tmpDir); } catch { /* ignore */ }
  } catch (err) {
    console.error('[qmd_engine] Ingest failed:', err.message);
  }
}

export default {
  isQMDEngine,
  getQMDEngineStatus,
  qmdEngineSearch,
  qmdVectorSearch,
  vectorSearch,
  ingestMemoryToQMD,
};
/**
 * Memory Quality Scoring & Auto-Degradation v1.0
 * Scores memories 0-1 based on multi-factor analysis
 * Auto-degrades memories below threshold to COLD tier or archive
 * Designed to be called periodically by proactive_manager
 */

import { getAllMemories, saveMemories } from './storage.js';
import { assignTiers } from './tier.js';

// ─── Quality Scoring ─────────────────────────────────────────────────────────

/**
 * Multi-factor quality score (0-1) for a memory.
 * Higher = more valuable, should be kept in HOT/WARM.
 * Lower = candidate for COLD tier or archival.
 *
 * Factors:
 *   - importance (0-1): user-supplied importance weight
 *   - access_count: how many times accessed (recency-weighted)
 *   - recency: age in days (exponential decay, half-life 30d)
 *   - reflection_count: how many times memory was reflected/insightful
 *   - accuracy_feedback: helpful (+) vs wrong/outdated (-) signals
 *
 * @param {object} memory
 * @returns {number} score 0-1
 */
export function qualityScore(memory) {
  if (!memory) return 0;

  let score = 0.0;

  // 1. Base importance weight (user-supplied, 0-1)
  const importance = typeof memory.importance === 'number'
    ? Math.max(0, Math.min(1, memory.importance))
    : 0.5;
  score += importance * 0.35;          // up to +0.35

  // 2. Access frequency bonus (logarithmic, max +0.15 at 20+ accesses)
  const accessCount = typeof memory.access_count === 'number' ? memory.access_count : 0;
  if (accessCount > 0) {
    score += Math.min(0.15, Math.log1p(accessCount) * 0.05);
  }

  // 3. Recency bonus (exponential decay, half-life 30 days, max +0.20)
  const ageMs = Date.now() - (memory.created_at || Date.now());
  const ageDays = ageMs / (1000 * 60 * 60 * 24);
  const recencyBonus = Math.exp(-ageDays / 30) * 0.20;
  score += recencyBonus;

  // 4. Reflection / insightful flag (max +0.15 at 3+ reflections)
  const reflectionCount = typeof memory.reflection_count === 'number'
    ? memory.reflection_count
    : (memory.insightful ? 1 : 0);
  if (reflectionCount > 0) {
    score += Math.min(0.15, reflectionCount * 0.05);
  }

  // 5. Accuracy feedback signal (max +0.15 helpful, -0.20 wrong/outdated)
  const feedbackScore = getFeedbackScore(memory);
  score += feedbackScore;

  // 6. Category-specific boosts
  if (memory.category === 'preference' || memory.category === 'decision') {
    score += 0.05;  // decisions and preferences are high-value
  }

  return Math.max(0.0, Math.min(1.0, score));
}

/**
 * Extract numeric feedback signal from a memory's feedback history.
 * Memory.feedbackHistory: Array<{ outcome: 'helpful'|'irrelevant'|'wrong'|'outdated', ts: number }>
 * @param {object} memory
 * @returns {number} bonus in [-0.20, +0.15] range
 */
function getFeedbackScore(memory) {
  const history = memory.feedbackHistory || [];
  if (history.length === 0) return 0;

  let signal = 0;
  for (const fb of history) {
    if (fb.outcome === 'helpful') signal += 0.03;
    else if (fb.outcome === 'irrelevant') signal -= 0.01;
    else if (fb.outcome === 'wrong') signal -= 0.05;
    else if (fb.outcome === 'outdated') signal -= 0.04;
  }
  return Math.max(-0.20, Math.min(0.15, signal));
}

// ─── Auto-Degradation ────────────────────────────────────────────────────────

const DEGRADE_THRESHOLD = 0.15;   // below this score → COLD / archive
const DEGRADE_BATCH = 50;         // process up to this many per tick

/**
 * Auto-degrade memories below the quality threshold.
 * Moves them to the COLD tier (for archival).
 *
 * Called periodically by proactive_manager.tick().
 *
 * @param {object} [options]
 * @param {number} [options.threshold] - quality threshold (default 0.15)
 * @param {number} [options.batchSize] - max memories to process per call (default 50)
 * @param {boolean} [options.dryRun] - if true, only return what would happen (default false)
 * @returns {{ degraded: Array, archived: Array, preserved: Array, dryRun: boolean }}
 */
export function autoDegrade(options = {}) {
  const {
    threshold = DEGRADE_THRESHOLD,
    batchSize = DEGRADE_BATCH,
    dryRun = false,
  } = options;

  const memories = getAllMemories();
  const scored = memories.map(m => ({
    memory: m,
    score: qualityScore(m),
  }));

  const degraded = [];
  const preserved = [];

  for (const item of scored) {
    if (item.score < threshold) {
      degraded.push(item);
    } else {
      preserved.push(item);
    }
  }

  // Sort degraded by score ascending (worst first)
  degraded.sort((a, b) => a.score - b.score);
  const toProcess = degraded.slice(0, batchSize);

  if (dryRun || toProcess.length === 0) {
    return {
      degraded: toProcess.map(d => d.memory.id),
      archived: [],
      preserved: preserved.map(p => p.memory.id),
      dryRun,
      threshold,
      processed: toProcess.length,
      message: dryRun
        ? `Dry run: ${toProcess.length} memories would be degraded (below ${threshold})`
        : `No memories to degrade (threshold=${threshold})`,
    };
  }

  // Apply tier reassignment: degraded → COLD
  const memoriesToDegrade = toProcess.map(d => d.memory);

  // Tag degraded memories for COLD tier
  const updatedMemories = memories.map(m => {
    const degradedItem = memoriesToDegrade.find(d => d.id === m.id);
    if (degradedItem) {
      return {
        ...m,
        tier: 'COLD',
        degraded_at: Date.now(),
        degraded_score: qualityScore(degradedItem),
      };
    }
    return m;
  });

  saveMemories(updatedMemories);

  return {
    degraded: memoriesToDegrade.map(m => m.id),
    archived: [],          // archive slot for future cold-tier compression
    preserved: preserved.map(p => p.memory.id),
    dryRun: false,
    threshold,
    processed: memoriesToDegrade.length,
    message: `Degraded ${memoriesToDegrade.length} memories to COLD tier (below threshold ${threshold})`,
  };
}

/**
 * Score all memories and return them sorted by quality (worst first).
 * Useful for inspection and tuning.
 *
 * @param {number} [topK] - return topK worst memories (default all)
 * @returns {Array<{ memory: object, score: number, factors: object }>}
 */
export function scoreAllMemories(topK = null) {
  const memories = getAllMemories();
  const scored = memories.map(m => {
    const score = qualityScore(m);
    const factors = {
      importance: typeof m.importance === 'number' ? m.importance : 0.5,
      accessCount: typeof m.access_count === 'number' ? m.access_count : 0,
      ageDays: Math.round((Date.now() - (m.created_at || Date.now())) / (1000 * 60 * 60 * 24)),
      reflectionCount: typeof m.reflection_count === 'number' ? m.reflection_count : (m.insightful ? 1 : 0),
      feedbackCount: (m.feedbackHistory || []).length,
      category: m.category || 'unknown',
    };
    return { memory: m, score, factors };
  });

  scored.sort((a, b) => a.score - b.score);

  if (topK !== null) return scored.slice(0, topK);
  return scored;
}

export default { qualityScore, autoDegrade, scoreAllMemories };
/**
 * Simple sliding window rate limiter for tool calls
 * P2-7: prevents burst of tool calls from overwhelming the system
 */

// Sliding window: max calls per key over time window
const callLog = new Map(); // key -> timestamp[]

export const RATE_LIMIT_WINDOW_MS = 10000; // 10 seconds
export const RATE_LIMIT_MAX_CALLS = 30;   // max calls per window per key

/**
 * Check if a call is allowed under rate limit
 * @param {string} key - identifier for the caller (session, agent, etc.)
 * @returns {{allowed: boolean, retryAfter: number|null}}
 */
export function checkRateLimit(key = 'default') {
  const now = Date.now();
  const windowStart = now - RATE_LIMIT_WINDOW_MS;
  
  // Clean old entries and count recent calls
  const timestamps = callLog.get(key) || [];
  const recent = timestamps.filter(t => t > windowStart);
  
  if (recent.length >= RATE_LIMIT_MAX_CALLS) {
    // Calculate when the oldest call in window will expire
    const oldest = Math.min(...recent);
    const retryAfter = Math.ceil((oldest + RATE_LIMIT_WINDOW_MS - now) / 1000);
    return { allowed: false, retryAfter: Math.max(1, retryAfter) };
  }
  
  recent.push(now);
  callLog.set(key, recent);
  return { allowed: true, retryAfter: null };
}

/**
 * Get current rate limit status for a key
 */
export function getRateLimitStatus(key = 'default') {
  const now = Date.now();
  const windowStart = now - RATE_LIMIT_WINDOW_MS;
  const timestamps = callLog.get(key) || [];
  const recent = timestamps.filter(t => t > windowStart);
  return {
    count: recent.length,
    limit: RATE_LIMIT_MAX_CALLS,
    remaining: Math.max(0, RATE_LIMIT_MAX_CALLS - recent.length),
    windowMs: RATE_LIMIT_WINDOW_MS,
  };
}

/**
 * Clean up expired entries (call periodically to prevent memory leak)
 */
export function cleanupRateLimit() {
  const now = Date.now();
  const windowStart = now - RATE_LIMIT_WINDOW_MS;
  for (const [key, timestamps] of callLog.entries()) {
    const recent = timestamps.filter(t => t > windowStart);
    if (recent.length === 0) {
      callLog.delete(key);
    } else {
      callLog.set(key, recent);
    }
  }
}
/**
 * Recall Trigger v1.0
 * Evaluates schedules and fires recall events
 */

import { getAllMemories } from './storage.js';
import { predictRecall } from './core/proactive_recall.js';
import { getLogger } from './logger.js';

const log = getLogger('recall_trigger');

/**
 * @typedef {Object} RecallPayload
 * @property {string} scheduleId
 * @property {string} scheduleName
 * @property {string} type
 * @property {object[]} memories
 * @property {string} summary
 * @property {string} triggeredAt
 */

/**
 * @typedef {Object} Schedule
 * @property {string} id
 * @property {string} name
 * @property {string} type
 * @property {object} config
 */

export class RecallTrigger {
  constructor() {
    /** @type {Map<string,string>} scheduleId -> lastNotificationHHMM */
    this._firedToday = new Map();
  }

  /**
   * Evaluate all active schedules (for heartbeat or manual trigger)
   * @param {object} [context] - optional context string
   * @returns {Promise<RecallPayload[]>}
   */
  async checkRecalls(context = '') {
    const results = [];
    // event_based are evaluated by the scheduler's onHeartbeat
    // This method is for a full manual sweep
    return results;
  }

  /**
   * Fire a single recall schedule
   * @param {Schedule} schedule
   * @returns {Promise<RecallPayload>}
   */
  async fireRecall(schedule) {
    const memories = getAllMemories();
    const recallResults = predictRecall(schedule.config.query || schedule.name || 'general');

    const topMemories = recallResults.slice(0, 5).map(r => ({
      id: r.memory?.id || r.memory?.id || 'unknown',
      text: r.memory?.text || '',
      category: r.memory?.category || 'unknown',
      importance: r.memory?.importance || 0.5,
      relevance: r.relevance || 0,
      reason: r.reason || '',
    }));

    const summary = this._summarize(topMemories, schedule);

    /** @type {RecallPayload} */
    const payload = {
      scheduleId: schedule.id,
      scheduleName: schedule.name,
      type: schedule.type,
      memories: topMemories,
      summary,
      triggeredAt: new Date().toISOString(),
    };

    log.info(`[RecallTrigger] fired schedule=${schedule.name} type=${schedule.type} count=${topMemories.length}`);

    return payload;
  }

  /**
   * Check if a schedule already fired today at the same time slot
   * Prevents duplicate firings for time_based schedules
   * @param {string} scheduleId
   * @returns {boolean}
   */
  hasFiredToday(scheduleId) {
    const today = new Date().toDateString();
    const last = this._firedToday.get(scheduleId);
    if (last !== today) {
      this._firedToday.set(scheduleId, today);
      return false;
    }
    return true;
  }

  _summarize(memories, schedule) {
    if (!memories.length) {
      return `Proactive recall "${schedule.name}" triggered — no matching memories found.`;
    }

    const categoryGroups = {};
    for (const m of memories) {
      const cat = m.category || 'unknown';
      if (!categoryGroups[cat]) categoryGroups[cat] = [];
      categoryGroups[cat].push(m);
    }

    const parts = [];
    for (const [cat, items] of Object.entries(categoryGroups)) {
      const count = items.length;
      const total = memories.length;
      const pct = Math.round((count / total) * 100);
      parts.push(`${count} ${cat} (${pct}%)`);
    }

    const avgImportance = memories.reduce((s, m) => s + (m.importance || 0), 0) / memories.length;

    return (
      `Recall "${schedule.name}" [${schedule.type}] → ` +
      `${memories.length} memories: ${parts.join(', ')}. ` +
      `Avg importance: ${avgImportance.toFixed(2)}.`
    );
  }

  /**
   * Build notification text from a recall payload
   * @param {RecallPayload} payload
   * @returns {string}
   */
  static formatNotification(payload) {
    const lines = [
      `🔔 **Proactive Recall: ${payload.scheduleName}**`,
      `Type: ${payload.type} | Triggered: ${new Date(payload.triggeredAt).toLocaleString()}`,
      '',
      `**Summary:** ${payload.summary}`,
      '',
      `**Top Memories (${payload.memories.length}):**`,
    ];

    for (const m of payload.memories.slice(0, 5)) {
      const snippet = (m.text || '').substring(0, 80).replace(/\n/g, ' ');
      lines.push(`• [${m.category}] ${snippet}… (imp: ${(m.importance || 0).toFixed(2)})`);
    }

    return lines.join('\n');
  }
}

// Singleton
let _trigger = null;

export function getRecallTrigger() {
  if (!_trigger) _trigger = new RecallTrigger();
  return _trigger;
}
/**
 * Self-Improvement / Reflection System
 * Records learning from failures and successes into .learnings/
 * LRN entries: positive lessons
 * ERR entries: mistakes and corrections
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import crypto from 'crypto';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const LEARNINGS_DIR = path.join(__dirname, '..', '.learnings');
const LEARNINGS_FILE = path.join(LEARNINGS_DIR, 'learnings.md');
const ERRORS_FILE = path.join(LEARNINGS_DIR, 'errors.md');

function ensureLearningsDir() {
  if (!fs.existsSync(LEARNINGS_DIR)) fs.mkdirSync(LEARNINGS_DIR, { recursive: true });
}
function readFile(p) {
  try { return fs.readFileSync(p, 'utf8'); } catch { return ''; }
}
function writeFile(p, content) {
  ensureLearningsDir();
  fs.writeFileSync(p, content, 'utf8');
}

let _seq = 0;
function nextId(prefix = 'LRN') {
  const d = new Date();
  _seq++;
  return `${prefix}-${d.getFullYear()}${String(d.getMonth()+1).padStart(2,'0')}${String(d.getDate()).padStart(2,'0')}-${String(_seq).padStart(3,'0')}`;
}

/**
 * Add a learning entry (success pattern / best practice)
 * @param {string} text
 * @param {string} [category]
 * @param {object} [metadata]
 */
export function addLearning(text, category = 'general', metadata = {}) {
  const id = nextId('LRN');
  const entry = { id, type: 'LRN', category, text, metadata, createdAt: new Date().toISOString() };
  const content = readFile(LEARNINGS_FILE);
  const newContent = content
    ? content.trimEnd() + '\n' + JSON.stringify(entry)
    : JSON.stringify(entry);
  writeFile(LEARNINGS_FILE, newContent + '\n');
  return entry;
}

/**
 * Add an error entry (failure / mistake to avoid)
 * @param {string} text
 * @param {string} [errorType]
 * @param {object} [metadata]
 */
export function addError(text, errorType = 'unknown', metadata = {}) {
  const id = nextId('ERR');
  const entry = { id, type: 'ERR', category: errorType, text, metadata, createdAt: new Date().toISOString() };
  const content = readFile(ERRORS_FILE);
  const newContent = content
    ? content.trimEnd() + '\n' + JSON.stringify(entry)
    : JSON.stringify(entry);
  writeFile(ERRORS_FILE, newContent + '\n');
  return entry;
}

/**
 * Get all learnings
 * @returns {Array}
 */
export function getLearnings() {
  const content = readFile(LEARNINGS_FILE);
  if (!content.trim()) return [];
  return content.trim().split('\n').filter(Boolean).map(l => { try { return JSON.parse(l); } catch { return null; } }).filter(Boolean);
}

/**
 * Get all errors
 * @returns {Array}
 */
export function getErrors() {
  const content = readFile(ERRORS_FILE);
  if (!content.trim()) return [];
  return content.trim().split('\n').filter(Boolean).map(l => { try { return JSON.parse(l); } catch { return null; } }).filter(Boolean);
}

/**
 * Get stats summary
 */
export function getStats() {
  const learnings = getLearnings();
  const errors = getErrors();
  return {
    learnings: learnings.length,
    errors: errors.length,
    categories: [...new Set([...learnings.map(l=>l.category), ...errors.map(e=>e.category)])],
  };
}

/**
 * Auto-record a retrieval failure
 * @param {string} query
 * @param {string} [reason]
 */
export function recordRetrievalFailure(query, reason = 'no_results') {
  return addError(`Retrieval failure for query: "${query}" | reason: ${reason}`, 'retrieval_failure', { query });
}

/**
 * Auto-record a storage failure
 * @param {string} text
 * @param {string} [error]
 */
export function recordStorageFailure(text, error = 'unknown') {
  return addError(`Storage failure: "${text?.slice(0,50)}..." | error: ${error}`, 'storage_failure', { text: text?.slice(0, 100) });
}

export default { addLearning, addError, getLearnings, getErrors, getStats, recordRetrievalFailure, recordStorageFailure };
/**
 * Reminder Scheduler v1.0
 * Proactive reminder mechanism
 * Supports: one-time reminders, recurring reminders, memory TTL-based auto reminders
 */

import { getAllMemories } from './storage.js';

let log = console;
try {
  const { log: importedLog } = await import('./logger.js');
  log = importedLog;
} catch {
  // Use console if logger not available
}

export class ReminderScheduler {
  constructor() {
    this.reminders = new Map(); // id -> { id, text, dueAt, repeat, callback, type }
    this.timer = null;
    this.tickMs = 30000; // Check every 30 seconds
  }

  add(reminder) {
    const id = `rem_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`;
    this.reminders.set(id, { id, ...reminder, createdAt: Date.now() });
    return id;
  }

  addTTLReminder(memoryId, text, ttlHours = 24) {
    // TTL-based auto reminder for memories
    return this.add({
      type: 'ttl',
      memoryId,
      text,
      dueAt: Date.now() + ttlHours * 3600 * 1000,
      repeat: null,
    });
  }

  addRecurringReminder(text, intervalHours = 24) {
    // Recurring reminder (e.g., daily review)
    return this.add({
      type: 'recurring',
      text,
      dueAt: Date.now() + intervalHours * 3600 * 1000,
      repeat: intervalHours * 3600 * 1000,
    });
  }

  due() {
    const now = Date.now();
    return [...this.reminders.values()].filter(r => r.dueAt <= now);
  }

  async tick() {
    const due = this.due();
    for (const reminder of due) {
      try {
        // Trigger callback if registered
        if (reminder.callback) {
          await reminder.callback(reminder);
        }
        // Re-schedule if recurring
        if (reminder.repeat) {
          reminder.dueAt = Date.now() + reminder.repeat;
        } else {
          this.reminders.delete(reminder.id);
        }
      } catch (e) {
        console.error('[ReminderScheduler] trigger error:', e.message);
      }
    }
  }

  start() {
    if (this.timer) return;
    this.timer = setInterval(() => this.tick(), this.tickMs);
  }

  stop() {
    if (this.timer) {
      clearInterval(this.timer);
      this.timer = null;
    }
  }

  list() {
    return [...this.reminders.values()];
  }

  cancel(id) {
    return this.reminders.delete(id);
  }
}

let globalScheduler = null;

export function getReminderScheduler() {
  if (!globalScheduler) {
    globalScheduler = new ReminderScheduler();
  }
  return globalScheduler;
}
/**
 * Reranker - Multi-signal reranking for memory retrieval
 * 
 * v3.1: Adds multi-signal rule-based rerank to complement the existing LlmReranker.
 * Multi-signal rerank uses: keyword overlap, entity match, recency, importance, scope, category.
 * 
 * Original LlmReranker (LLM-based cross-encoder) is preserved alongside.
 */

import { config } from './config.js';

// ============ LlmReranker (original - preserved) ============

function getLlmProvider() {
  const providers = config.llmProviders || [];
  return providers.find(p => p.name === 'ollama') || providers[0] || {
    baseURL: process.env.OLLAMA_HOST || 'http://localhost:11434',
    model: 'qwen2.5:7b',
    apiKey: null,
  };
}

export class LlmReranker {
  constructor(llmUrl = null, model = null) {
    const defaultProvider = getLlmProvider();
    this.llmUrl = llmUrl || defaultProvider.baseURL;
    this.model = model || defaultProvider.model;
    this.initialized = true;
  }

  async rerank(query, documents, topK = 5) {
    if (!documents || documents.length === 0) return [];
    if (documents.length === 1) return documents.slice(0, topK);

    const scored = await Promise.all(documents.map(async (doc) => {
      const text = doc.memory?.text || doc.memory?.content || '';
      if (!text) return { ...doc, rerankScore: doc.score || 0 };
      
      const prompt = `Query: ${query}\nDocument: ${text.slice(0, 500)}\nScore 1-10 how relevant is this document to the query. Reply only with the number:`;
      
      let rerankScore = doc.score || 0;
      try {
        const controller = new AbortController();
        const timer = setTimeout(() => controller.abort(), 3000);
        const res = await fetch(`${this.llmUrl}/api/generate`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ model: this.model, prompt, stream: false, options: { num_predict: 8 } }),
          signal: controller.signal,
        });
        clearTimeout(timer);
        if (res.ok) {
          const json = await res.json();
          const match = json.response?.match(/\d+/);
          if (match) rerankScore = parseInt(match[0]) / 10;
        }
      } catch { /* fallback */ }
      
      return { ...doc, rerankScore };
    }));

    return scored
      .sort((a, b) => b.rerankScore - a.rerankScore)
      .slice(0, topK);
  }
}

export function keywordRerank(query, documents, topK = 5) {
  const queryWords = query.toLowerCase().split(/\s+/).filter(w => w.length > 2);
  if (queryWords.length === 0) return documents.slice(0, topK);

  return documents
    .map(doc => {
      const text = (doc.memory?.text || doc.memory?.content || '').toLowerCase();
      const matches = queryWords.filter(w => text.includes(w)).length;
      return { ...doc, rerankScore: (doc.score || 0) + matches * 0.1 };
    })
    .sort((a, b) => b.rerankScore - a.rerankScore)
    .slice(0, topK);
}

// ============ Multi-Signal Rerank (v3.1 new) ============

const RERANK_CONFIG = {
  topK: 5,
  keywordWeight: 0.25,
  entityWeight: 0.20,
  importanceWeight: 0.15,
  recencyWeight: 0.15,
  scopeWeight: 0.15,
  categoryWeight: 0.10,
  recencyDays: 7,
};

const CATEGORY_PRIORITY = {
  identity: 5, preference: 4, decision: 3, skill: 3, goal: 3,
  reflection: 2, entity: 2, fact: 1, general: 0, conversation: -1,
};

const SCOPE_PRIORITY = { USER: 4, TEAM: 3, AGENT: 2, GLOBAL: 1, '': 4 };

function tokenize(text) {
  if (!text) return new Set();
  return new Set(text.toLowerCase().split(/[\s,.!?;:()\[\]{}'"-]+/).filter(t => t.length >= 2));
}

function overlapFraction(setA, setB) {
  if (!setA.size || !setB.size) return 0;
  return [...setA].filter(x => setB.has(x)).length / setA.size;
}

function detectEntities(text) {
  if (!text) return [];
  const entities = [];
  const patterns = [
    /\b(Claude|OpenAI|GPT|MiniMax|DeepSeek|Ollama|LanceDB|BM25|Elasticsearch)\b/gi,
    /\b(飞书|Lark|钉钉|微信|Discord|Telegram|Slack|Signal)\b/gi,
    /\b(MCP|API|REST|GraphQL|gRPC|WebSocket|SSE)\b/gi,
    /\b(macOS|Linux|Windows|Docker|Kubernetes)\b/gi,
    /\b(ou_[a-z0-9]+|oc_[a-z0-9]+|mem_[^\s,]+)\b/gi,
  ];
  for (const p of patterns) { let m; while ((m = p.exec(text)) !== null) entities.push(m[1] || m[0]); }
  return [...new Set(entities)];
}

function recencyScore(mem) {
  const ts = mem.updated_at || mem.created_at;
  if (!ts) return 0.0;
  const updatedAt = typeof ts === 'string' ? new Date(ts).getTime() : ts;
  if (isNaN(updatedAt)) return 0.0;
  const daysDiff = (Date.now() - updatedAt) / (1000 * 60 * 60 * 24);
  return daysDiff <= RERANK_CONFIG.recencyDays ? 1.0 : Math.max(0, 1 - (daysDiff / 365));
}

function temporalValidity(mem) {
  if (!mem.valid_to) return 1.0;
  const vt = typeof mem.valid_to === 'string' ? new Date(mem.valid_to).getTime() : mem.valid_to;
  return Date.now() <= vt ? 1.0 : 0.0;
}

/**
 * Multi-signal rule-based reranking
 * Combines: keyword overlap, entity match, recency, importance, scope, category
 * 
 * @param {string} query
 * @param {Array} candidates - {memory, fusionScore?, bm25Score?, vectorScore?}[]
 * @param {object} options - {topK}
 * @returns {Array} reranked results
 */
export function rerank(query, candidates, options = {}) {
  const { topK = RERANK_CONFIG.topK } = options;
  
  if (!candidates || candidates.length === 0) return [];
  if (candidates.length === 1) {
    return [{ ...candidates[0], rerankScore: candidates[0].fusionScore || candidates[0].vectorScore || 0 }];
  }

  const queryTokens = tokenize(query);
  const queryEntities = detectEntities(query);

  const reranked = candidates.map(candidate => {
    const mem = candidate.memory;
    const text = mem.text || '';
    const contentTokens = tokenize(text);
    const contentEntities = detectEntities(text);

    const keywordScore = overlapFraction(queryTokens, contentTokens);
    const entityScore = overlapFraction(new Set(queryEntities), new Set(contentEntities));
    const importanceScore = mem.importance || 0.5;
    const recency = recencyScore(mem);
    const temporal = temporalValidity(mem);
    const categoryPriority = (CATEGORY_PRIORITY[mem.category] ?? 0) / 5;
    const scopePriority = (SCOPE_PRIORITY[mem.scope || ''] ?? 4) / 4;
    const vectorScore = candidate.vectorScore || candidate.score || 0;
    const bm25Score = candidate.bm25Score ? Math.min(1, candidate.bm25Score / 10) : 0;

    const rerankScore = (
      keywordScore * RERANK_CONFIG.keywordWeight +
      entityScore * RERANK_CONFIG.entityWeight +
      importanceScore * RERANK_CONFIG.importanceWeight +
      recency * RERANK_CONFIG.recencyWeight +
      categoryPriority * RERANK_CONFIG.categoryWeight +
      scopePriority * RERANK_CONFIG.scopeWeight +
      vectorScore * 0.5 +
      bm25Score * 0.3 +
      temporal * 0.05
    );

    return {
      ...candidate,
      rerankScore: Math.min(1, Math.max(0, rerankScore)),
      signals: { keywordScore, entityScore, importanceScore, recency, categoryPriority, scopePriority },
    };
  });

  reranked.sort((a, b) => {
    if (b.rerankScore !== a.rerankScore) return b.rerankScore - a.rerankScore;
    return (b.memory.importance || 0.5) - (a.memory.importance || 0.5);
  });

  return reranked.slice(0, topK);
}
/**
 * Retrieval Tracer v1.0 - Memory Replay Debugger (Feature #8)
 * 
 * Records every step of the search pipeline for each query.
 * Like `git blame` for memory retrieval - trace exactly how a memory was retrieved.
 * 
 * Data logged per query:
 *   { queryId, query, timestamp, pipelineSteps[], results[], finalRanking[], durationMs }
 * 
 * Each step record:
 *   { stepName, input, output, score, reasoning }
 * 
 * Storage: ~/.openclaw/workspace/memory/retrieval_traces.json (rolling window, last 1000)
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { config } from './config.js';

const __dirname = dirname(fileURLToPath(import.meta.url));
const TRACES_FILE = join(config.memoryDir, 'retrieval_traces.json');

// In-memory cache for ultra-fast reads during replay
let _traceCache = null;
let _cacheExpiry = 0;
const CACHE_TTL_MS = 5000; // 5 second cache

// Per-memory index: memoryId → [{ queryId, rank, score, timestamp }]
let _memoryIndex = new Map();

// Global query counter for IDs
let _queryCounter = 0;

/**
 * Load all traces from disk (with caching)
 * @returns {Array}
 */
function loadTraces() {
  const now = Date.now();
  if (_traceCache && now < _cacheExpiry) {
    return _traceCache;
  }
  
  if (!existsSync(TRACES_FILE)) {
    _traceCache = [];
    _cacheExpiry = now + CACHE_TTL_MS;
    return [];
  }
  
  try {
    const raw = readFileSync(TRACES_FILE, 'utf-8');
    _traceCache = JSON.parse(raw);
    _cacheExpiry = now + CACHE_TTL_MS;
    return _traceCache;
  } catch {
    _traceCache = [];
    _cacheExpiry = now + CACHE_TTL_MS;
    return [];
  }
}

/**
 * Persist traces to disk
 * @param {Array} traces
 */
function saveTraces(traces) {
  try {
    const dir = dirname(TRACES_FILE);
    if (!existsSync(dir)) {
      mkdirSync(dir, { recursive: true });
    }
    // Rolling window: keep only last maxTraces
    const trimmed = traces.slice(-config.maxTraces);
    writeFileSync(TRACES_FILE, JSON.stringify(trimmed, null, 2), 'utf-8');
    _traceCache = trimmed;
    _cacheExpiry = 0; // invalidate cache
  } catch (err) {
    console.error('[retrieval_tracer] saveTraces failed:', err.message);
  }
}

/**
 * Generate a unique query trace ID
 * @returns {string}
 */
export function generateQueryId() {
  _queryCounter++;
  return `qt-${Date.now().toString(36)}-${_queryCounter.toString(36).padStart(4, '0')}`;
}

/**
 * Start a new retrieval trace session
 * @param {string} query 
 * @param {object} options - { scope, mode, topK, enableRerank, enableMMR, enableDecay }
 * @returns {object} - trace context
 */
export function startRetrievalTrace(query, options = {}) {
  if (!config.traceRetrieval) {
    return null;
  }
  
  const queryId = generateQueryId();
  const startTime = Date.now();
  
  return {
    queryId,
    query,
    timestamp: new Date().toISOString(),
    options: { ...options },
    pipelineSteps: [],
    startTime,
    _active: true,
  };
}

/**
 * Record a pipeline step
 * @param {object} traceCtx - trace context from startRetrievalTrace
 * @param {string} stepName - e.g., 'bm25_search', 'vector_search', 'mmr', 'rerank'
 * @param {object} input - what went into this step
 * @param {object} output - what came out
 * @param {number} score - score if applicable
 * @param {string} reasoning - why this step did what it did
 */
export function recordPipelineStep(traceCtx, stepName, input, output, score = null, reasoning = '') {
  if (!traceCtx || !traceCtx._active) return;
  
  const step = {
    stepName,
    input: sanitizeForTrace(input),
    output: sanitizeForTrace(output),
    score,
    reasoning,
    timestamp: Date.now(),
    durationMs: Date.now() - traceCtx.startTime,
  };
  
  traceCtx.pipelineSteps.push(step);
}

/**
 * Record BM25 step
 * @param {object} traceCtx
 * @param {string} query
 * @param {Array} candidates - BM25 results
 * @param {number} topK
 */
export function traceBm25Step(traceCtx, query, candidates, topK) {
  const topResults = candidates.slice(0, topK);
  recordPipelineStep(traceCtx, 'bm25_search', 
    { query, topK, totalCandidates: candidates.length },
    { 
      results: topResults.map((r, i) => ({
        memoryId: r.memory?.id,
        text: r.memory?.text?.slice(0, 80),
        score: r.score,
        rank: i + 1,
      })),
      count: topResults.length,
    },
    topResults[0]?.score,
    `BM25 keyword matching: found ${candidates.length} candidates, returned top ${topResults.length}`
  );
}

/**
 * Record Vector search step
 * @param {object} traceCtx
 * @param {string} query
 * @param {Array} candidates
 * @param {number} topK
 */
export function traceVectorStep(traceCtx, query, candidates, topK) {
  const topResults = candidates.slice(0, topK);
  recordPipelineStep(traceCtx, 'vector_search',
    { query, topK, totalCandidates: candidates.length },
    {
      results: topResults.map((r, i) => ({
        memoryId: r.memory?.id,
        text: r.memory?.text?.slice(0, 80),
        score: r.score,
        rank: i + 1,
      })),
      count: topResults.length,
    },
    topResults[0]?.score,
    `Vector similarity search: found ${candidates.length} candidates, returned top ${topResults.length}`
  );
}

/**
 * Record merge/fusion step
 * @param {object} traceCtx
 * @param {Array} candidates - merged candidates
 * @param {string} mode - 'hybrid', 'bm25', 'vector'
 */
export function traceMergeStep(traceCtx, candidates, mode = 'hybrid') {
  recordPipelineStep(traceCtx, 'merge_candidates',
    { mode, candidateCount: candidates.length },
    {
      candidates: candidates.slice(0, 10).map((c, i) => ({
        memoryId: c.memory?.id,
        bm25Score: c.bm25Score,
        vectorScore: c.vectorScore,
        score: c.score,
        rank: i + 1,
      })),
    },
    candidates[0]?.score,
    `Merged BM25 + vector candidates using ${mode} mode`
  );
}

/**
 * Record rerank step
 * @param {object} traceCtx
 * @param {Array} before - before reranking
 * @param {Array} after - after reranking
 * @param {string} method - 'keyword', 'llm', 'cross-encoder'
 */
export function traceRerankStep(traceCtx, before, after, method = 'keyword') {
  const topChanges = [];
  for (let i = 0; i < Math.min(5, after.length); i++) {
    const newId = after[i]?.memory?.id;
    const oldRank = before.findIndex(b => b.memory?.id === newId);
    topChanges.push({
      memoryId: newId,
      text: after[i]?.memory?.text?.slice(0, 60),
      oldRank: oldRank >= 0 ? oldRank + 1 : 'new',
      newRank: i + 1,
      score: after[i]?.score,
    });
  }
  
  recordPipelineStep(traceCtx, 'rerank',
    { method, inputCount: before.length },
    { 
      topChanges,
      outputCount: after.length,
    },
    after[0]?.score,
    `Reranked using ${method}: top result ${before[0]?.memory?.id === after[0]?.memory?.id ? 'unchanged' : 'changed'}`
  );
}

/**
 * Record MMR/diversity step
 * @param {object} traceCtx
 * @param {Array} before
 * @param {Array} after
 * @param {number} lambda
 */
export function traceMmrStep(traceCtx, before, after, lambda = 0.5) {
  const removed = before.filter(b => !after.find(a => a.memory?.id === b.memory?.id));
  recordPipelineStep(traceCtx, 'mmr_diversity',
    { lambda, inputCount: before.length, outputCount: after.length },
    {
      selected: after.slice(0, 5).map((a, i) => ({
        memoryId: a.memory?.id,
        text: a.memory?.text?.slice(0, 60),
        rank: i + 1,
      })),
      removed: removed.slice(0, 3).map(r => ({
        memoryId: r.memory?.id,
        text: r.memory?.text?.slice(0, 60),
        reason: 'diversity deduplication',
      })),
    },
    after[0]?.score,
    `MMR diversity (λ=${lambda}): selected ${after.length} from ${before.length}, removed ${removed.length} for diversity`
  );
}

/**
 * Record decay step
 * @param {object} traceCtx
 * @param {Array} before
 * @param {Array} after
 * @param {number} halfLifeDays
 * @param {number} maxBoost
 */
export function traceDecayStep(traceCtx, before, after, halfLifeDays = 30, maxBoost = 0.3) {
  const boosted = after.filter(a => (a.decay ?? 1) > 1);
  recordPipelineStep(traceCtx, 'time_decay',
    { halfLifeDays, maxBoost, inputCount: before.length },
    {
      boosted: boosted.slice(0, 5).map(b => ({
        memoryId: b.memory?.id,
        ageDays: b.ageDays,
        decayFactor: b.decay,
        scoreBefore: before.find(p => p.memory?.id === b.memory?.id)?.score,
        scoreAfter: b.score,
      })),
    },
    after[0]?.score,
    `Weibull time decay (halfLife=${halfLifeDays}d): ${boosted.length} memories boosted for recency`
  );
}

/**
 * Record entity/graph boost step
 * @param {object} traceCtx
 * @param {Array} before
 * @param {Array} after
 * @param {Array} entityNames
 */
export function traceEntityBoostStep(traceCtx, before, after, entityNames = []) {
  const boosted = after.filter(a => (a.graphBoost ?? 1) > 1);
  recordPipelineStep(traceCtx, 'entity_boost',
    { entities: entityNames, inputCount: before.length },
    {
      boosted: boosted.slice(0, 5).map(b => ({
        memoryId: b.memory?.id,
        graphBoost: b.graphBoost,
        scoreBefore: before.find(p => p.memory?.id === b.memory?.id)?.score,
        scoreAfter: b.score,
      })),
    },
    after[0]?.score,
    `Entity boost for [${entityNames.join(', ')}]: ${boosted.length} memories boosted`
  );
}

/**
 * Record importance boost step
 * @param {object} traceCtx
 * @param {Array} before
 * @param {Array} after
 */
export function traceImportanceBoostStep(traceCtx, before, after) {
  const boosted = after.filter(a => (a.importanceBoost ?? 0) > 0);
  recordPipelineStep(traceCtx, 'importance_boost',
    { inputCount: before.length },
    {
      boosted: boosted.slice(0, 5).map(b => ({
        memoryId: b.memory?.id,
        importanceBoost: b.importanceBoost,
        dynamicImportance: b.dynamicImportance,
        scoreBefore: before.find(p => p.memory?.id === b.memory?.id)?.score,
        scoreAfter: b.score,
      })),
    },
    after[0]?.score,
    `Importance boost: ${boosted.length} memories boosted based on usage patterns`
  );
}

/**
 * Record final ranking
 * @param {object} traceCtx
 * @param {Array} results
 */
export function recordFinalRanking(traceCtx, results) {
  if (!traceCtx || !traceCtx._active) return;
  
  const durationMs = Date.now() - traceCtx.startTime;
  
  recordPipelineStep(traceCtx, 'final_ranking',
    { resultCount: results.length },
    {
      ranking: results.slice(0, 10).map((r, i) => ({
        memoryId: r.memory?.id,
        text: r.memory?.text?.slice(0, 80),
        score: r.score,
        bm25Score: r.bm25Score,
        vectorScore: r.vectorScore,
        rank: i + 1,
        category: r.memory?.category,
      })),
    },
    results[0]?.score,
    `Final ranking complete: ${results.length} results in ${durationMs}ms`
  );
  
  traceCtx.finalRanking = results.slice(0, 20).map((r, i) => ({
    memoryId: r.memory?.id,
    text: r.memory?.text?.slice(0, 80),
    score: r.score,
    rank: i + 1,
  }));
  traceCtx.durationMs = durationMs;
  traceCtx._active = false;
}

/**
 * Finalize and persist a trace
 * @param {object} traceCtx
 */
export function finalizeTrace(traceCtx) {
  if (!traceCtx) return;
  
  // Mark as inactive
  traceCtx._active = false;
  
  if (!config.traceRetrieval) return;
  
  const traces = loadTraces();
  traces.push({
    queryId: traceCtx.queryId,
    query: traceCtx.query,
    timestamp: traceCtx.timestamp,
    options: traceCtx.options,
    pipelineSteps: traceCtx.pipelineSteps,
    finalRanking: traceCtx.finalRanking || [],
    durationMs: traceCtx.durationMs || Date.now() - traceCtx.startTime,
  });
  
  // Update per-memory index
  if (traceCtx.finalRanking) {
    for (const item of traceCtx.finalRanking) {
      if (!item.memoryId) continue;
      const idx = _memoryIndex.get(item.memoryId) || [];
      idx.push({
        queryId: traceCtx.queryId,
        rank: item.rank,
        score: item.score,
        timestamp: traceCtx.timestamp,
      });
      _memoryIndex.set(item.memoryId, idx);
    }
  }
  
  saveTraces(traces);
}

/**
 * Get all traces
 * @param {number} limit
 * @returns {Array}
 */
export function getAllTraces(limit = 100) {
  const traces = loadTraces();
  return traces.slice(-limit);
}

/**
 * Get a specific trace by query ID
 * @param {string} queryId
 * @returns {object|null}
 */
export function getTraceById(queryId) {
  const traces = loadTraces();
  return traces.find(t => t.queryId === queryId) || null;
}

/**
 * Get retrieval history for a specific memory
 * @param {string} memoryId
 * @returns {Array}
 */
export function getMemoryRetrievalHistory(memoryId) {
  const traces = loadTraces();
  const history = [];
  
  for (const trace of traces) {
    if (!trace.finalRanking) continue;
    const entry = trace.finalRanking.find(r => r.memoryId === memoryId);
    if (entry) {
      history.push({
        queryId: trace.queryId,
        query: trace.query,
        timestamp: trace.timestamp,
        rank: entry.rank,
        score: entry.score,
        durationMs: trace.durationMs,
      });
    }
  }
  
  return history.sort((a, b) => b.timestamp.localeCompare(a.timestamp));
}

/**
 * Get memory index stats
 * @returns {object}
 */
export function getMemoryIndexStats() {
  const traces = loadTraces();
  return {
    totalTraces: traces.length,
    indexedMemories: _memoryIndex.size,
    oldestTrace: traces[0]?.timestamp || null,
    newestTrace: traces[traces.length - 1]?.timestamp || null,
  };
}

/**
 * Sanitize data for tracing (avoid serializing circular refs, too-large data)
 * @param {any} data
 * @returns {any}
 */
function sanitizeForTrace(data) {
  if (data === null || data === undefined) return null;
  if (typeof data === 'string') return data.slice(0, 500);
  if (typeof data === 'number' || typeof data === 'boolean') return data;
  if (Array.isArray(data)) {
    return data.slice(0, 50).map(sanitizeForTrace);
  }
  if (typeof data === 'object') {
    const safe = {};
    for (const [k, v] of Object.entries(data)) {
      if (k === 'memory' && v && typeof v === 'object') {
        safe[k] = { id: v.id, text: String(v.text || '').slice(0, 100), category: v.category };
      } else {
        safe[k] = sanitizeForTrace(v);
      }
    }
    return safe;
  }
  return String(data).slice(0, 200);
}

/**
 * Clear all traces
 */
export function clearAllTraces() {
  _traceCache = [];
  _memoryIndex.clear();
  try {
    if (existsSync(TRACES_FILE)) {
      writeFileSync(TRACES_FILE, '[]', 'utf-8');
    }
  } catch (err) {
    console.error('[retrieval_tracer] clearAllTraces failed:', err.message);
  }
}

/**
 * Get traces matching a query substring
 * @param {string} querySubstr
 * @returns {Array}
 */
export function searchTraces(querySubstr) {
  const traces = loadTraces();
  const q = querySubstr.toLowerCase();
  return traces.filter(t => t.query.toLowerCase().includes(q));
}
/**
 * Revision Manager - Memory Version Conflict Detection & Resolution
 * Tracks memory changes over time, detects conflicts, and resolves them.
 * 
 * Storage: ~/.openclaw/workspace/memory/revisions.json
 */

import fs from 'fs/promises';
import path from 'path';
import crypto from 'crypto';
import { fileURLToPath } from 'url';
import { z } from 'zod';
import { config } from './config.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Storage path
const REVISIONS_FILE = path.join(config.memoryDir, 'revisions.json');

// ============ Types ============

/**
 * @typedef {Object} MemoryRevision
 * @property {string} memory_id
 * @property {number} version
 * @property {string} content
 * @property {string} previous_content
 * @property {'created'|'updated'|'deleted'} change_type
 * @property {string} changed_at
 * @property {string} changed_by
 * @property {string} [commit_hash]
 */

/**
 * @typedef {Object} ConflictReport
 * @property {boolean} has_conflict
 * @property {string} memory_id
 * @property {MemoryRevision} local_version
 * @property {MemoryRevision} remote_version
 * @property {'local'|'remote'|'merged'|'manual'} [resolution]
 * @property {string} [merged_content]
 */

/**
 * @typedef {'last-write-wins'|'local-wins'|'remote-wins'|'manual'} UpdatePolicy
 */

// ============ Storage Helpers ============

async function loadRevisions() {
  try {
    const data = await fs.readFile(REVISIONS_FILE, 'utf-8');
    return JSON.parse(data);
  } catch {
    // Auto-create if not exists
    await saveRevisions({ revisions: [], conflicts: [], pending_merges: [] });
    return { revisions: [], conflicts: [], pending_merges: [] };
  }
}

async function saveRevisions(data) {
  await fs.mkdir(path.dirname(REVISIONS_FILE), { recursive: true });
  await fs.writeFile(REVISIONS_FILE, JSON.stringify(data, null, 2), 'utf-8');
}

function generateId() {
  return crypto.randomBytes(8).toString('hex');
}

// ============ Core Functions ============

/**
 * Record a new revision for a memory change.
 * Every memory change creates a new revision entry.
 */
export async function recordRevision(memoryId, newContent, changeType, changedBy = 'unknown', commitHash = null) {
  const store = await loadRevisions();
  
  // Get existing revisions for this memory
  const existing = store.revisions.filter(r => r.memory_id === memoryId);
  const latestVersion = existing.length > 0 ? Math.max(...existing.map(r => r.version)) : 0;
  const previousContent = existing.length > 0 
    ? (existing.find(r => r.version === latestVersion)?.content || '')
    : '';
  
  const revision = {
    memory_id: memoryId,
    version: latestVersion + 1,
    content: newContent,
    previous_content: previousContent,
    change_type: changeType,
    changed_at: new Date().toISOString(),
    changed_by: changedBy,
    commit_hash: commitHash || null,
    revision_id: generateId(),
  };
  
  store.revisions.push(revision);
  await saveRevisions(store);
  
  return revision;
}

/**
 * Get revision history for a specific memory.
 * Returns revisions sorted by version descending (newest first).
 */
export async function getRevisions(memoryId, limit = 50) {
  const store = await loadRevisions();
  const revisions = store.revisions
    .filter(r => r.memory_id === memoryId)
    .sort((a, b) => b.version - a.version)
    .slice(0, limit);
  
  return revisions;
}

/**
 * Detect conflicts between local and remote versions.
 * Compares content and version numbers to identify divergent changes.
 */
export async function detectConflict(memoryId, localContent, remoteVersion) {
  const store = await loadRevisions();
  const existing = store.revisions
    .filter(r => r.memory_id === memoryId)
    .sort((a, b) => b.version - a.version);
  
  const localLatest = existing[0];
  
  // No local history = no conflict possible
  if (!localLatest) {
    return {
      has_conflict: false,
      memory_id: memoryId,
      local_version: null,
      remote_version: remoteVersion,
      resolution: 'remote',
    };
  }
  
  // Check if local and remote have diverged
  const hasConflict = localLatest.content !== remoteVersion.content && 
                     localLatest.version !== remoteVersion.version;
  
  if (hasConflict) {
    const conflict = {
      memory_id: memoryId,
      has_conflict: true,
      local_version: localLatest,
      remote_version: remoteVersion,
      detected_at: new Date().toISOString(),
    };
    
    // Store pending conflict
    const existingConflict = store.conflicts.findIndex(c => c.memory_id === memoryId && !c.resolution);
    if (existingConflict >= 0) {
      store.conflicts[existingConflict] = conflict;
    } else {
      store.conflicts.push(conflict);
    }
    await saveRevisions(store);
    
    return conflict;
  }
  
  return {
    has_conflict: false,
    memory_id: memoryId,
    local_version: localLatest,
    remote_version: remoteVersion,
  };
}

/**
 * Resolve a detected conflict with a chosen strategy.
 */
export async function resolveConflict(memoryId, resolution, mergedContent = null) {
  const store = await loadRevisions();
  const conflictIdx = store.conflicts.findIndex(c => c.memory_id === memoryId);
  
  if (conflictIdx < 0) {
    throw new Error(`No pending conflict found for memory ${memoryId}`);
  }
  
  const conflict = store.conflicts[conflictIdx];
  
  // Determine final content based on resolution
  let finalContent;
  switch (resolution) {
    case 'local':
      finalContent = conflict.local_version.content;
      break;
    case 'remote':
      finalContent = conflict.remote_version.content;
      break;
    case 'merged':
      if (!mergedContent) throw new Error('Merged content required for merged resolution');
      finalContent = mergedContent;
      break;
    case 'manual':
      // Mark for manual resolution (keep conflict pending)
      conflict.resolution = 'manual';
      store.conflicts[conflictIdx] = conflict;
      await saveRevisions(store);
      return;
    default:
      throw new Error(`Unknown resolution: ${resolution}`);
  }
  
  // Record resolution
  conflict.resolution = resolution;
  conflict.merged_content = finalContent;
  conflict.resolved_at = new Date().toISOString();
  store.conflicts[conflictIdx] = conflict;
  
  // Create a new revision with resolved content
  await recordRevision(
    memoryId,
    finalContent,
    'updated',
    'conflict-resolver',
    null
  );
  
  await saveRevisions(store);
}

/**
 * Generate a diff between two versions of a memory.
 * Returns a simple unified diff format.
 */
export async function diffRevisions(memoryId, v1, v2) {
  const store = await loadRevisions();
  const rev1 = store.revisions.find(r => r.memory_id === memoryId && r.version === v1);
  const rev2 = store.revisions.find(r => r.memory_id === memoryId && r.version === v2);
  
  if (!rev1 || !rev2) {
    throw new Error(`Revision not found: v1=${v1}, v2=${v2}`);
  }
  
  const oldLines = rev1.content.split('\n');
  const newLines = rev2.content.split('\n');
  
  // Simple line-by-line diff
  const diff = [];
  diff.push(`--- Version ${v1} (${rev1.changed_at})`);
  diff.push(`+++ Version ${v2} (${rev2.changed_at})`);
  
  const maxLines = Math.max(oldLines.length, newLines.length);
  for (let i = 0; i < maxLines; i++) {
    const oldLine = oldLines[i] ?? '';
    const newLine = newLines[i] ?? '';
    
    if (oldLine === newLine) {
      diff.push(`  ${oldLine}`);
    } else {
      if (oldLines[i] !== undefined) diff.push(`- ${oldLine}`);
      if (newLines[i] !== undefined) diff.push(`+ ${newLine}`);
    }
  }
  
  return diff.join('\n');
}

/**
 * Auto-merge two sets of revisions.
 * Uses update policy to resolve conflicts automatically when possible.
 */
export async function autoMerge(localRevisions, remoteRevisions, policy = 'last-write-wins') {
  if (!localRevisions || localRevisions.length === 0) {
    return {
      success: true,
      merged: remoteRevisions,
      conflicts: [],
      policy,
    };
  }
  
  if (!remoteRevisions || remoteRevisions.length === 0) {
    return {
      success: true,
      merged: localRevisions,
      conflicts: [],
      policy,
    };
  }
  
  const merged = [];
  const conflicts = [];
  
  // Group by memory_id
  const localByMemory = {};
  const remoteByMemory = {};
  
  for (const rev of localRevisions) {
    if (!localByMemory[rev.memory_id]) localByMemory[rev.memory_id] = [];
    localByMemory[rev.memory_id].push(rev);
  }
  
  for (const rev of remoteRevisions) {
    if (!remoteByMemory[rev.memory_id]) remoteByMemory[rev.memory_id] = [];
    remoteByMemory[rev.memory_id].push(rev);
  }
  
  // Get all memory IDs
  const allMemoryIds = new Set([...Object.keys(localByMemory), ...Object.keys(remoteByMemory)]);
  
  for (const memoryId of allMemoryIds) {
    const local = localByMemory[memoryId] || [];
    const remote = remoteByMemory[memoryId] || [];
    
    const localLatest = local.sort((a, b) => b.version - a.version)[0];
    const remoteLatest = remote.sort((a, b) => b.version - a.version)[0];
    
    if (!localLatest) {
      // Only remote exists
      merged.push(...remote);
    } else if (!remoteLatest) {
      // Only local exists
      merged.push(...local);
    } else {
      // Both exist - check for conflict
      const hasConflict = localLatest.content !== remoteLatest.content;
      
      if (!hasConflict) {
        // No conflict - take the latest
        merged.push(localLatest.version >= remoteLatest.version ? localLatest : remoteLatest);
      } else {
        // Conflict detected - apply policy
        let winner;
        
        switch (policy) {
          case 'last-write-wins':
            winner = new Date(localLatest.changed_at) > new Date(remoteLatest.changed_at) 
              ? localLatest 
              : remoteLatest;
            break;
          case 'local-wins':
            winner = localLatest;
            break;
          case 'remote-wins':
            winner = remoteLatest;
            break;
          case 'manual':
            // Mark for manual resolution
            conflicts.push({
              memory_id: memoryId,
              local_version: localLatest,
              remote_version: remoteLatest,
              resolution: 'manual',
            });
            // Store conflict
            const store = await loadRevisions();
            store.conflicts.push({
              memory_id: memoryId,
              has_conflict: true,
              local_version: localLatest,
              remote_version: remoteLatest,
              detected_at: new Date().toISOString(),
              resolution: 'manual',
            });
            await saveRevisions(store);
            continue;
          default:
            throw new Error(`Unknown policy: ${policy}`);
        }
        
        merged.push(winner);
      }
    }
  }
  
  return {
    success: conflicts.length === 0,
    merged,
    conflicts,
    policy,
  };
}

/**
 * Get all pending conflicts.
 */
export async function getPendingConflicts() {
  const store = await loadRevisions();
  return store.conflicts.filter(c => !c.resolution || c.resolution === 'manual');
}

/**
 * Get a specific revision by memory ID and version.
 */
export async function getRevision(memoryId, version) {
  const store = await loadRevisions();
  return store.revisions.find(r => r.memory_id === memoryId && r.version === version) || null;
}

// ============ MCP Tool Handlers ============

export const memoryRevisionHandlers = {
  /**
   * record - Record a new memory revision
   */
  record: async ({ memory_id, content, change_type, changed_by, commit_hash }) => {
    try {
      const revision = await recordRevision(memory_id, content, change_type, changed_by, commit_hash);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: true,
            revision,
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  },

  /**
   * history - Get revision history for a memory
   */
  history: async ({ memory_id, limit }) => {
    try {
      const revisions = await getRevisions(memory_id, limit);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            memory_id,
            count: revisions.length,
            revisions,
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  },

  /**
   * diff - Get diff between two versions
   */
  diff: async ({ memory_id, v1, v2 }) => {
    try {
      const diffResult = await diffRevisions(memory_id, v1, v2);
      return {
        content: [{
          type: 'text',
          text: diffResult,
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  },

  /**
   * detect_conflict - Detect conflicts between local and remote
   */
  detect_conflict: async ({ memory_id, local_content, remote_version }) => {
    try {
      const report = await detectConflict(memory_id, local_content, remote_version);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify(report, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  },

  /**
   * resolve - Resolve a detected conflict
   */
  resolve: async ({ memory_id, resolution, merged_content }) => {
    try {
      await resolveConflict(memory_id, resolution, merged_content);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            success: true,
            memory_id,
            resolution,
          }),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  },

  /**
   * auto_merge - Auto-merge local and remote revisions
   */
  auto_merge: async ({ local_revisions, remote_revisions, policy }) => {
    try {
      const result = await autoMerge(local_revisions, remote_revisions, policy);
      return {
        content: [{
          type: 'text',
          text: JSON.stringify(result, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  },

  /**
   * pending_conflicts - List all pending conflicts
   */
  pending_conflicts: async () => {
    try {
      const conflicts = await getPendingConflicts();
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            count: conflicts.length,
            conflicts,
          }, null, 2),
        }],
      };
    } catch (err) {
      return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
    }
  },
};

// ============ Tool Registration ============

export function registerRevisionTools(server) {
  server.registerTool('memory_revision', {
    description: 'Memory revision management - record changes, detect conflicts, resolve merges, and view version history.',
    inputSchema: z.object({
      action: z.enum(['record', 'history', 'diff', 'detect_conflict', 'resolve', 'auto_merge', 'pending_conflicts']),
      memory_id: z.string().optional(),
      content: z.string().optional(),
      change_type: z.enum(['created', 'updated', 'deleted']).optional(),
      changed_by: z.string().optional().default('unknown'),
      commit_hash: z.string().optional(),
      limit: z.number().optional().default(50),
      v1: z.number().optional(),
      v2: z.number().optional(),
      local_content: z.string().optional(),
      remote_version: z.any().optional(),
      resolution: z.enum(['local', 'remote', 'merged', 'manual']).optional(),
      merged_content: z.string().optional(),
      local_revisions: z.array(z.any()).optional(),
      remote_revisions: z.array(z.any()).optional(),
      policy: z.enum(['last-write-wins', 'local-wins', 'remote-wins', 'manual']).optional().default('last-write-wins'),
    }),
  }, async (args) => {
    const handler = memoryRevisionHandlers[args.action];
    if (!handler) {
      return { content: [{ type: 'text', text: `Unknown action: ${args.action}` }], isError: true };
    }
    return handler(args);
  });
}
/**
 * Revision Manager Enhanced - Memory Version Lifecycle Management
 * Complete revision lifecycle with stages, conflict detection, and resolution
 * 
 * Storage: ~/.openclaw/workspace/memory/revisions.json
 */

import fs from 'fs/promises';
import path from 'path';
import crypto from 'crypto';
import { fileURLToPath } from 'url';
import { z } from 'zod';
import { config } from './config.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Storage path
const REVISIONS_FILE = path.join(config.memoryDir, 'revisions.json');

// ============ Types ============

/**
 * @typedef {Object} MemoryRevision
 * @property {string} memory_id
 * @property {number} version
 * @property {string} content
 * @property {string} previous_content
 * @property {'created'|'updated'|'deleted'} change_type
 * @property {string} changed_at
 * @property {string} changed_by
 * @property {string} [commit_hash]
 * @property {string} [lifecycle_stage] // draft, review, approved, archived
 */

/**
 * @typedef {Object} ConflictReport
 * @property {boolean} has_conflict
 * @property {string} memory_id
 * @property {MemoryRevision} local_version
 * @property {MemoryRevision} remote_version
 * @property {'local'|'remote'|'merged'|'manual'} [resolution]
 * @property {string} [merged_content]
 */

// ============ Storage Helpers ============

async function loadRevisions() {
  try {
    const data = await fs.readFile(REVISIONS_FILE, 'utf-8');
    return JSON.parse(data);
  } catch {
    await saveRevisions({ revisions: [], conflicts: [], history: [] });
    return { revisions: [], conflicts: [], history: [] };
  }
}

async function saveRevisions(data) {
  await fs.mkdir(path.dirname(REVISIONS_FILE), { recursive: true });
  await fs.writeFile(REVISIONS_FILE, JSON.stringify(data, null, 2), 'utf-8');
}

function generateId() {
  return crypto.randomBytes(8).toString('hex');
}

// ============ Core Functions ============

/**
 * Record a new revision with lifecycle stage
 */
export async function recordRevision(memoryId, newContent, changeType, changedBy = 'unknown', commitHash = null, lifecycleStage = 'approved') {
  const store = await loadRevisions();
  
  const memoryRevisions = store.revisions.filter(r => r.memory_id === memoryId);
  const latestVersion = memoryRevisions.length > 0 
    ? Math.max(...memoryRevisions.map(r => r.version)) 
    : 0;
  
  const previousContent = memoryRevisions.length > 0 
    ? memoryRevisions[memoryRevisions.length - 1].content 
    : null;
  
  const revision = {
    memory_id: memoryId,
    version: latestVersion + 1,
    content: newContent,
    previous_content: previousContent,
    change_type: changeType,
    changed_at: new Date().toISOString(),
    changed_by: changedBy,
    commit_hash: commitHash,
    lifecycle_stage: lifecycleStage
  };
  
  store.revisions.push(revision);
  
  // Check for conflicts
  if (changeType === 'updated' && memoryRevisions.length > 0) {
    const latest = memoryRevisions[memoryRevisions.length - 1];
    if (latest.content !== newContent && latest.changed_by !== changedBy) {
      const conflict = {
        id: generateId(),
        memory_id: memoryId,
        local_version: { ...latest, changed_by: 'local' },
        remote_version: { ...revision, changed_by: changedBy },
        created_at: new Date().toISOString(),
        resolution: null
      };
      store.conflicts.push(conflict);
    }
  }
  
  // Log to history
  store.history.push({
    action: 'revision_created',
    memory_id: memoryId,
    version: revision.version,
    timestamp: revision.changed_at
  });
  
  await saveRevisions(store);
  return revision;
}

/**
 * Get all revisions for a memory
 */
export async function getRevisions(memoryId) {
  const store = await loadRevisions();
  return store.revisions
    .filter(r => r.memory_id === memoryId)
    .sort((a, b) => a.version - b.version);
}

/**
 * Get current content (latest revision)
 */
export async function getCurrentContent(memoryId) {
  const revisions = await getRevisions(memoryId);
  return revisions.length > 0 ? revisions[revisions.length - 1].content : null;
}

/**
 * Get revision history with metadata
 */
export async function getRevisionHistory(memoryId) {
  const revisions = await getRevisions(memoryId);
  
  return revisions.map((rev, index) => ({
    version: rev.version,
    change_type: rev.change_type,
    changed_at: rev.changed_at,
    changed_by: rev.changed_by,
    commit_hash: rev.commit_hash,
    lifecycle_stage: rev.lifecycle_stage,
    content_preview: rev.content.substring(0, 100) + (rev.content.length > 100 ? '...' : ''),
    has_previous: index > 0,
    previous_version: index > 0 ? revisions[index - 1].version : null
  }));
}

/**
 * Detect conflicts
 */
export function detectConflicts(localContent, remoteContent, localVersion, remoteVersion) {
  if (localContent === remoteContent) {
    return { has_conflict: false };
  }
  
  return {
    has_conflict: true,
    local_version: localVersion,
    remote_version: remoteVersion,
    local_content: localContent,
    remote_content: remoteContent
  };
}

/**
 * Auto-merge with last-write-wins
 */
export function autoMerge(localContent, remoteContent, localTimestamp, remoteTimestamp) {
  const localDate = new Date(localTimestamp);
  const remoteDate = new Date(remoteTimestamp);
  
  return remoteDate > localDate ? remoteContent : localContent;
}

/**
 * Resolve conflict manually
 */
export async function resolveConflict(conflictId, resolution, mergedContent = null) {
  const store = await loadRevisions();
  const conflict = store.conflicts.find(c => c.id === conflictId);
  
  if (!conflict) {
    return { success: false, error: 'Conflict not found' };
  }
  
  conflict.resolution = resolution;
  if (mergedContent) {
    conflict.merged_content = mergedContent;
  }
  
  store.conflicts = store.conflicts.filter(c => c.id !== conflictId);
  await saveRevisions(store);
  return { success: true, conflict };
}

/**
 * Get pending conflicts
 */
export async function getPendingConflicts() {
  const store = await loadRevisions();
  return store.conflicts.filter(c => !c.resolution);
}

/**
 * Get conflict history
 */
export async function getConflictHistory() {
  const store = await loadRevisions();
  return store.conflicts
    .filter(c => c.resolution)
    .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
}

/**
 * Auto-merge pending conflicts
 */
export async function autoMergePendingConflicts() {
  const store = await loadRevisions();
  const pending = store.conflicts.filter(c => !c.resolution);
  
  const merged = [];
  const failed = [];
  
  for (const conflict of pending) {
    try {
      const mergedContent = autoMerge(
        conflict.local_version.content,
        conflict.remote_version.content,
        conflict.local_version.changed_at,
        conflict.remote_version.changed_at
      );
      
      conflict.resolution = 'merged';
      conflict.merged_content = mergedContent;
      merged.push(conflict);
    } catch (err) {
      failed.push({ conflict, error: err.message });
    }
  }
  
  await saveRevisions(store);
  return { merged: merged.length, failed: failed.length };
}

/**
 * Get revision statistics
 */
export async function getRevisionStats() {
  const store = await loadRevisions();
  
  const totalRevisions = store.revisions.length;
  const uniqueMemories = new Set(store.revisions.map(r => r.memory_id)).size;
  const totalConflicts = store.conflicts.length;
  const resolvedConflicts = store.conflicts.filter(c => c.resolution).length;
  
  return {
    total_revisions,
    unique_memories,
    avg_revisions_per_memory: uniqueMemories > 0 ? totalRevisions / uniqueMemories : 0,
    total_conflicts,
    resolved_conflicts,
    pending_conflicts: totalConflicts - resolvedConflicts,
    conflict_resolution_rate: totalConflicts > 0 ? (resolvedConflicts / totalConflicts) * 100 : 0
  };
}

/**
 * Archive old revisions
 */
export async function archiveOldRevisions(memoryId, keepLast = 10) {
  const store = await loadRevisions();
  const memoryRevisions = store.revisions.filter(r => r.memory_id === memoryId);
  
  if (memoryRevisions.length <= keepLast) {
    return { archived: 0 };
  }
  
  memoryRevisions.sort((a, b) => a.version - b.version);
  const toArchive = memoryRevisions.slice(0, memoryRevisions.length - keepLast);
  const toKeep = memoryRevisions.slice(memoryRevisions.length - keepLast);
  
  store.revisions = store.revisions.filter(r => !toArchive.includes(r));
  await saveRevisions(store);
  return { archived: toArchive.length, kept: toKeep.length };
}

/**
 * Rollback to specific version
 */
export async function rollbackToVersion(memoryId, targetVersion) {
  const revisions = await getRevisions(memoryId);
  const targetRevision = revisions.find(r => r.version === targetVersion);
  
  if (!targetRevision) {
    return { success: false, error: 'Version not found' };
  }
  
  await recordRevision(
    memoryId,
    targetRevision.content,
    'updated',
    'rollback',
    `rollback_to_v${targetVersion}`
  );
  
  return {
    success: true,
    rolled_back_to: targetVersion,
    previous_version: revisions.length,
    new_version: revisions.length + 1
  };
}

/**
 * Get diff between two versions
 */
export function getDiff(version1, version2, content1, content2) {
  const lines1 = content1.split('\n');
  const lines2 = content2.split('\n');
  
  const diff = [];
  const maxLength = Math.max(lines1.length, lines2.length);
  
  for (let i = 0; i < maxLength; i++) {
    const line1 = lines1[i] || '';
    const line2 = lines2[i] || '';
    
    if (line1 !== line2) {
      diff.push({
        line: i + 1,
        old: line1,
        new: line2
      });
    }
  }
  
  return diff;
}

/**
 * Get revisions by lifecycle stage
 */
export async function getRevisionsByStage(lifecycleStage) {
  const store = await loadRevisions();
  return store.revisions.filter(r => r.lifecycle_stage === lifecycleStage);
}

/**
 * Update lifecycle stage
 */
export async function updateLifecycleStage(memoryId, version, newStage) {
  const store = await loadRevisions();
  const revision = store.revisions.find(
    r => r.memory_id === memoryId && r.version === version
  );
  
  if (!revision) {
    return { success: false, error: 'Revision not found' };
  }
  
  revision.lifecycle_stage = newStage;
  await saveRevisions(store);
  return { success: true, revision };
}

/**
 * Get lifecycle summary
 */
export async function getLifecycleSummary() {
  const store = await loadRevisions();
  const stages = {};
  
  store.revisions.forEach(r => {
    stages[r.lifecycle_stage] = (stages[r.lifecycle_stage] || 0) + 1;
  });
  
  return {
    total: store.revisions.length,
    by_stage: stages,
    pending_conflicts: store.conflicts.filter(c => !c.resolution).length
  };
}
/**
 * rollback_manager.js — Rollback Operations Manager
 * Part of Feature #11: Semantic Versioning
 * 
 * High-level rollback API: rollback to specific version, undo changes, rollback all.
 */
import { restoreVersion as restoreMemoryVersion, getVersions, getVersion, getVersionCount, getVersionStats } from './memory_diff.js';
import { deleteVersions } from './version_store.js';
import { getMemory, getAllMemories, updateMemory } from './storage.js';

/**
 * Rollback a single memory to a specific version
 */
export async function rollback(memoryId, versionId) {
  try {
    const currentMemory = getMemory(memoryId);
    if (!currentMemory) {
      throw new Error(`Memory ${memoryId} not found`);
    }
    
    const version = getVersion(memoryId, versionId);
    if (!version) {
      throw new Error(`Version ${versionId} not found`);
    }
    
    // Perform rollback
    const result = restoreMemoryVersion(memoryId, versionId);
    
    return {
      success: true,
      action: 'rollback',
      memoryId,
      ...result,
    };
  } catch (err) {
    return {
      success: false,
      error: err.message,
    };
  }
}

/**
 * Rollback all memories to a specific version (by timestamp)
 */
export async function rollbackAll(targetTimestamp) {
  const results = {
    success: [],
    failed: [],
    timestamp: targetTimestamp,
  };
  
  const allMemories = getAllMemories();
  const store = await import('./version_store.js');
  const versionStore = store.loadVersionStore();
  
  for (const memory of allMemories) {
    const versions = versionStore[memory.id]?.versions || [];
    
    // Find version at or before target timestamp
    const targetVersion = versions
      .filter(v => v.timestamp <= targetTimestamp)
      .sort((a, b) => b.timestamp - a.timestamp)[0];
    
    if (targetVersion) {
      try {
        await rollback(memory.id, targetVersion.versionId);
        results.success.push(memory.id);
      } catch (err) {
        results.failed.push({ memoryId: memory.id, error: err.message });
      }
    } else {
      results.failed.push({ memoryId: memory.id, error: 'No version at or before target timestamp' });
    }
  }
  
  return results;
}

/**
 * Undo last change to a memory (rollback to previous version)
 */
export async function undoLastChange(memoryId) {
  const versions = getVersions(memoryId);
  
  if (versions.length < 2) {
    return {
      success: false,
      error: 'No previous version to undo to',
    };
  }
  
  // Second to last version is the "current" one before last change
  const lastVersion = versions[versions.length - 1];
  const previousVersion = versions[versions.length - 2];
  
  return await rollback(memoryId, previousVersion.versionId);
}

/**
 * Get rollback candidates (memories with multiple versions)
 */
export function getRollbackCandidates() {
  const stats = getVersionStats();
  const candidates = [];
  
  for (const [memoryId, count] of Object.entries(stats.memoryCounts)) {
    if (count >= 2) {
      const memory = getMemory(memoryId);
      candidates.push({
        memoryId,
        currentText: memory?.text?.substring(0, 100) || '',
        versionCount: count,
      });
    }
  }
  
  return candidates;
}

/**
 * Batch rollback multiple memories
 */
export async function batchRollback(operations) {
  const results = {
    success: [],
    failed: [],
  };
  
  for (const op of operations) {
    const { memoryId, versionId } = op;
    const result = await rollback(memoryId, versionId);
    
    if (result.success) {
      results.success.push(memoryId);
    } else {
      results.failed.push({ memoryId, error: result.error });
    }
  }
  
  return results;
}

/**
 * Clear version history for a memory
 */
export function clearVersionHistory(memoryId) {
  try {
    deleteVersions(memoryId);
    return { success: true, memoryId };
  } catch (err) {
    return { success: false, error: err.message };
  }
}

/**
 * Get rollback preview (what would happen if rolled back)
 */
export function getRollbackPreview(memoryId, versionId) {
  const currentMemory = getMemory(memoryId);
  const version = getVersion(memoryId, versionId);
  
  if (!currentMemory || !version) {
    return null;
  }
  
  return {
    memoryId,
    current: {
      text: currentMemory.text?.substring(0, 200),
      updatedAt: currentMemory.updated_at,
    },
    restoreTo: {
      versionId: version.versionId,
      text: version.content?.text?.substring(0, 200),
      timestamp: version.timestamp,
    },
    willChange: currentMemory.text !== version.content?.text,
  };
}

export default {
  rollback,
  rollbackAll,
  undoLastChange,
  getRollbackCandidates,
  batchRollback,
  clearVersionHistory,
  getRollbackPreview,
};
/**
 * scene_block.js — L2 Scene Block Inductor
 * 
 * 从 L1 记忆中自动归纳场景块：
 * - 按时间窗口聚类相关记忆
 * - 提取场景主题、关键实体、行动项
 * - 生成 Markdown 格式的场景块
 * 
 * Inspired by memory-tencentdb L2 Scene Induction
 */

import { getAllMemories, getMemory } from './storage.js';
import { search } from './search.js';
import { config, llmCall } from './config.js';
import { log } from './logger.js';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

// ─── 配置 ───────────────────────────────────────────────────────────────────

const DEFAULT_CONFIG = {
  sceneWindowHours: 24,        // 场景时间窗口
  minMemoriesPerScene: 3,      // 最少记忆数
  maxScenes: 20,               // 最大场景数
  similarityThreshold: 0.4,    // 相似度阈值
  sceneDir: 'scene_blocks',    // 场景块目录
};

// ─── 场景块结构 ─────────────────────────────────────────────────────────────

/**
 * @typedef {Object} SceneBlock
 * @property {string} id - scene_xxx
 * @property {string} title - 场景标题
 * @property {string} summary - 摘要
 * @property {string[]} entities - 关键实体
 * @property {string[]} actions - 行动项
 * @property {string[]} memoryIds - 关联记忆 ID
 * @property {{start: number, end: number}} timeRange - 时间范围
 * @property {string[]} tags - 标签
 * @property {number} created - 创建时间
 * @property {number} updated - 更新时间
 * @property {string} scope - 范围
 */

// ─── 核心函数 ───────────────────────────────────────────────────────────────

/**
 * 从记忆中归纳场景块
 * @param {Object} options
 * @param {string} [options.scope='USER']
 * @param {{start?: number, end?: number}} [options.timeRange]
 * @param {number} [options.minMemories=3]
 * @param {number} [options.maxScenes=20]
 * @returns {Promise<SceneBlock[]>}
 */
export async function inductScenes(options = {}) {
  const {
    scope = 'USER',
    timeRange,
    minMemories = DEFAULT_CONFIG.minMemoriesPerScene,
    maxScenes = DEFAULT_CONFIG.maxScenes,
  } = options;

  log.info(`[SceneBlock] Starting scene induction for scope ${scope}`);

  // 1. 获取相关记忆
  const memories = await getMemoriesForSceneInduction(scope, timeRange);
  log.info(`[SceneBlock] Found ${memories.length} memories for induction`);

  if (memories.length < minMemories) {
    log.warn(`[SceneBlock] Not enough memories (${memories.length} < ${minMemories})`);
    return [];
  }

  // 2. 按时间窗口聚类
  const clusters = clusterByTimeWindow(memories, DEFAULT_CONFIG.sceneWindowHours);
  log.info(`[SceneBlock] Clustered into ${clusters.length} groups`);

  // 3. 对每个聚类生成场景块
  const scenes = [];
  for (const cluster of clusters) {
    if (cluster.length < minMemories) continue;

    const scene = await generateSceneBlock(cluster, scope);
    if (scene) {
      scenes.push(scene);
      log.info(`[SceneBlock] Generated scene: ${scene.title}`);
    }

    if (scenes.length >= maxScenes) break;
  }

  // 4. 保存场景块
  await saveSceneBlocks(scenes, scope);

  log.info(`[SceneBlock] Inducted ${scenes.length} scenes`);
  return scenes;
}

/**
 * 获取用于场景归纳的记忆
 */
async function getMemoriesForSceneInduction(scope, timeRange) {
  const allMemories = await getAllMemories();
  
  let filtered = allMemories.filter(m => {
    // 范围过滤
    if (m.scope && m.scope !== scope) return false;
    
    // 时间过滤
    if (timeRange) {
      if (timeRange.start && m.created < timeRange.start) return false;
      if (timeRange.end && m.created > timeRange.end) return false;
    }
    
    return true;
  });

  // 按时间排序
  filtered.sort((a, b) => (a.created || 0) - (b.created || 0));
  
  return filtered;
}

/**
 * 按时间窗口聚类记忆
 */
function clusterByTimeWindow(memories, windowHours) {
  if (memories.length === 0) return [];

  const windowMs = windowHours * 60 * 60 * 1000;
  const clusters = [];
  let currentCluster = [memories[0]];
  let windowStart = memories[0].created || Date.now();

  for (let i = 1; i < memories.length; i++) {
    const mem = memories[i];
    const memTime = mem.created || Date.now();
    const windowEnd = windowStart + windowMs;

    if (memTime <= windowEnd) {
      currentCluster.push(mem);
    } else {
      if (currentCluster.length >= DEFAULT_CONFIG.minMemoriesPerScene) {
        clusters.push(currentCluster);
      }
      currentCluster = [mem];
      windowStart = memTime;
    }
  }

  // 处理最后一个聚类
  if (currentCluster.length >= DEFAULT_CONFIG.minMemoriesPerScene) {
    clusters.push(currentCluster);
  }

  return clusters;
}

/**
 * 使用 LLM 生成场景块
 */
async function generateSceneBlock(memories, scope) {
  const memoryTexts = memories.map(m => {
    const category = m.category || 'general';
    const text = m.text || '';
    const time = new Date(m.created || Date.now()).toLocaleString('zh-CN');
    return `[${time}][${category}] ${text}`;
  }).join('\n');

  const prompt = `从以下记忆中归纳一个场景块：

${memoryTexts}

请输出 JSON 格式（不要包含 markdown 代码块）：
{
  "title": "场景标题（简短，5-10字）",
  "summary": "场景摘要（1-2句话，描述主要内容和目标）",
  "entities": ["关键实体1", "关键实体2", "关键实体3"],
  "actions": ["行动项1", "行动项2"],
  "tags": ["标签1", "标签2"]
}`;

  try {
    const response = await llmCall(prompt);
    
    // 清理响应（移除可能的 markdown 代码块）
    let cleaned = response.trim();
    if (cleaned.startsWith('```')) {
      cleaned = cleaned.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
    }
    
    const parsed = JSON.parse(cleaned);
    
    return {
      id: `scene_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      title: parsed.title || '未命名场景',
      summary: parsed.summary || '',
      entities: parsed.entities || [],
      actions: parsed.actions || [],
      memoryIds: memories.map(m => m.id),
      timeRange: {
        start: Math.min(...memories.map(m => m.created || Date.now())),
        end: Math.max(...memories.map(m => m.created || Date.now())),
      },
      tags: parsed.tags || [],
      created: Date.now(),
      updated: Date.now(),
      scope,
    };
  } catch (err) {
    log.error('[SceneBlock] Failed to parse scene block:', err);
    
    // 降级：生成简单场景块
    return {
      id: `scene_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      title: `场景 ${new Date().toLocaleDateString('zh-CN')}`,
      summary: memories.map(m => m.text).join('; ').substring(0, 200),
      entities: [],
      actions: [],
      memoryIds: memories.map(m => m.id),
      timeRange: {
        start: Math.min(...memories.map(m => m.created || Date.now())),
        end: Math.max(...memories.map(m => m.created || Date.now())),
      },
      tags: [],
      created: Date.now(),
      updated: Date.now(),
      scope,
    };
  }
}

// ─── 场景块存储 ─────────────────────────────────────────────────────────────

/**
 * 获取场景块目录
 */
function getSceneDir(scope) {
  const baseDir = config.storage?.path || path.join(process.env.OPENCLAW_WORKSPACE_DIR || '~/.openclaw/workspace', 'memory');
  const sceneDir = path.join(baseDir, DEFAULT_CONFIG.sceneDir, scope);
  
  // 确保目录存在
  if (!fs.existsSync(sceneDir)) {
    fs.mkdirSync(sceneDir, { recursive: true });
  }
  
  return sceneDir;
}

/**
 * 保存场景块
 */
async function saveSceneBlocks(scenes, scope) {
  const sceneDir = getSceneDir(scope);
  
  for (const scene of scenes) {
    const filePath = path.join(sceneDir, `${scene.id}.json`);
    fs.writeFileSync(filePath, JSON.stringify(scene, null, 2), 'utf-8');
    
    // 同时生成 Markdown 文件
    const mdPath = path.join(sceneDir, `${scene.id}.md`);
    const mdContent = generateSceneMarkdown(scene);
    fs.writeFileSync(mdPath, mdContent, 'utf-8');
  }
  
  // 更新场景索引
  await updateSceneIndex(scenes, scope);
}

/**
 * 生成场景 Markdown
 */
function generateSceneMarkdown(scene) {
  return `# ${scene.title}

**摘要**: ${scene.summary}

**时间范围**: ${new Date(scene.timeRange.start).toLocaleString('zh-CN')} - ${new Date(scene.timeRange.end).toLocaleString('zh-CN')}

## 关键实体

${scene.entities.map(e => `- ${e}`).join('\n') || '无'}

## 行动项

${scene.actions.map(a => `- [ ] ${a}`).join('\n') || '无'}

## 标签

${scene.tags.map(t => '#' + t).join(' ') || '无'}

## 关联记忆

${scene.memoryIds.map(id => `- ${id}`).join('\n')}

---
*创建时间: ${new Date(scene.created).toLocaleString('zh-CN')}*
`;
}

/**
 * 更新场景索引
 */
async function updateSceneIndex(scenes, scope) {
  const sceneDir = getSceneDir(scope);
  const indexPath = path.join(sceneDir, 'index.json');
  
  let index = { scenes: [], updated: 0 };
  
  // 读取现有索引
  if (fs.existsSync(indexPath)) {
    try {
      index = JSON.parse(fs.readFileSync(indexPath, 'utf-8'));
    } catch (err) {
      log.warn('[SceneBlock] Failed to read index, creating new one');
    }
  }
  
  // 合并新场景
  const existingIds = new Set(index.scenes.map(s => s.id));
  for (const scene of scenes) {
    if (!existingIds.has(scene.id)) {
      index.scenes.push({
        id: scene.id,
        title: scene.title,
        summary: scene.summary,
        tags: scene.tags,
        timeRange: scene.timeRange,
        created: scene.created,
      });
    }
  }
  
  // 按时间排序
  index.scenes.sort((a, b) => (b.created || 0) - (a.created || 0));
  
  // 限制数量
  if (index.scenes.length > DEFAULT_CONFIG.maxScenes * 2) {
    index.scenes = index.scenes.slice(0, DEFAULT_CONFIG.maxScenes * 2);
  }
  
  index.updated = Date.now();
  
  fs.writeFileSync(indexPath, JSON.stringify(index, null, 2), 'utf-8');
}

// ─── 场景块查询 ─────────────────────────────────────────────────────────────

/**
 * 列出场景块
 */
export async function listSceneBlocks(scope = 'USER', limit = 20) {
  const sceneDir = getSceneDir(scope);
  const indexPath = path.join(sceneDir, 'index.json');
  
  if (!fs.existsSync(indexPath)) {
    return [];
  }
  
  try {
    const index = JSON.parse(fs.readFileSync(indexPath, 'utf-8'));
    return index.scenes.slice(0, limit);
  } catch (err) {
    log.error('[SceneBlock] Failed to read index:', err);
    return [];
  }
}

/**
 * 获取场景块详情
 */
export async function getSceneBlock(sceneId, scope = 'USER') {
  const sceneDir = getSceneDir(scope);
  const filePath = path.join(sceneDir, '\${sceneId}.json');
  
  if (!fs.existsSync(filePath)) {
    return null;
  }
  
  try {
    return JSON.parse(fs.readFileSync(filePath, 'utf-8'));
  } catch (err) {
    log.error('[SceneBlock] Failed to read scene:', err);
    return null;
  }
}

/**
 * 删除场景块
 */
export async function deleteSceneBlock(sceneId, scope = 'USER') {
  const sceneDir = getSceneDir(scope);
  
  // 删除 JSON 和 Markdown 文件
  const jsonPath = path.join(sceneDir, '\${sceneId}.json');
  const mdPath = path.join(sceneDir, '\${sceneId}.md');
  
  if (fs.existsSync(jsonPath)) fs.unlinkSync(jsonPath);
  if (fs.existsSync(mdPath)) fs.unlinkSync(mdPath);
  
  // 更新索引
  const indexPath = path.join(sceneDir, 'index.json');
  if (fs.existsSync(indexPath)) {
    try {
      const index = JSON.parse(fs.readFileSync(indexPath, 'utf-8'));
      index.scenes = index.scenes.filter(s => s.id !== sceneId);
      index.updated = Date.now();
      fs.writeFileSync(indexPath, JSON.stringify(index, null, 2), 'utf-8');
    } catch (err) {
      log.error('[SceneBlock] Failed to update index:', err);
    }
  }
  
  return true;
}

/**
 * 搜索场景块
 */
export async function searchSceneBlocks(query, scope = 'USER', limit = 10) {
  const scenes = await listSceneBlocks(scope, 100);
  
  const queryLower = query.toLowerCase();
  
  // 简单关键词匹配
  const matched = scenes.filter(scene => {
    const titleMatch = scene.title.toLowerCase().includes(queryLower);
    const summaryMatch = scene.summary.toLowerCase().includes(queryLower);
    const tagMatch = scene.tags.some(t => t.toLowerCase().includes(queryLower));
    
    return titleMatch || summaryMatch || tagMatch;
  });
  
  return matched.slice(0, limit);
}

/**
 * 获取场景统计
 */
export async function getSceneStats(scope = 'USER') {
  const scenes = await listSceneBlocks(scope, 1000);
  
  return {
    total: scenes.length,
    tags: [...new Set(scenes.flatMap(s => s.tags))],
    timeRange: scenes.length > 0 ? {
      start: Math.min(...scenes.map(s => s.timeRange?.start || 0)),
      end: Math.max(...scenes.map(s => s.timeRange?.end || 0)),
    } : null,
  };
}

// ─── 导出 ───────────────────────────────────────────────────────────────────

export default {
  inductScenes,
  listSceneBlocks,
  getSceneBlock,
  deleteSceneBlock,
  searchSceneBlocks,
  getSceneStats,
};
/**
 * Scope Isolation - AGENT/USER/TEAM/GLOBAL四级隔离
 * Filter memories by scope level + team namespace isolation
 *
 * Team isolation model:
 * - Each team has its own memory namespace prefixed with `team:{team_id}:`
 * - TEAM-scope memories belong to a specific team (stored with team_id)
 * - Cross-team (shared) memories use explicit GLOBAL scope
 * - USER and AGENT scopes are personal to a user/agent and never cross-team
 */

export const SCOPE_LEVELS = ['AGENT', 'USER', 'TEAM', 'GLOBAL'];
export const SCOPE_HIERARCHY = { AGENT: 0, USER: 1, TEAM: 2, GLOBAL: 3 };

// ============ Team Namespace Registry ============

/** @type {Map<string, { name: string, created_at: number, memoryCount: number }>} */
const teamRegistry = new Map();

/** Current active team context (thread-local via global) */
const TEAM_CONTEXT = {
  current: null, // team_id or null for no-team
};

// ============ Agent Context (for AGENT-scope isolation) ============

/** Current active agent context */
const AGENT_CONTEXT = {
  current: null, // agent_id string or null
};

/**
 * Set current agent context for memory operations
 * Call this at the start of each agent session
 * @param {string|null} agentId
 */
export function setCurrentAgentId(agentId) {
  AGENT_CONTEXT.current = agentId || null;
}

/**
 * Get current agent context
 * @returns {string|null}
 */
export function getCurrentAgentId() {
  return AGENT_CONTEXT.current;
}

/**
 * Switch agent context (returns previous)
 * @param {string|null} agentId
 * @returns {string|null} previous agent_id
 */
export function switchAgentId(agentId) {
  const prev = AGENT_CONTEXT.current;
  AGENT_CONTEXT.current = agentId || null;
  return prev;
}

/**
 * Normalize a scope string to SCOPE_LEVELS
 * @param {string} scope
 * @returns {string}
 */
export function normalizeScope(scope) {
  if (!scope) return 'GLOBAL';
  const upper = scope.toUpperCase();
  return SCOPE_LEVELS.includes(upper) ? upper : 'GLOBAL';
}

/**
 * Get effective scope for a scope string
 * @param {string} scope
 * @returns {string}
 */
export function getEffectiveScope(scope) {
  return normalizeScope(scope);
}

/**
 * Filter memories by scope level (with agent_id isolation for AGENT scope)
 * 
 * Scope hierarchy: AGENT(0) < USER(1) < TEAM(2) < GLOBAL(3)
 * Standard rule: memory.scope >= target.scope (more specific can see broader)
 * 
 * AGENT scope EXCEPTION: agent_id isolation - AGENT scope returns ONLY
 * memories belonging to the current agent, regardless of hierarchy.
 * This ensures agent memories are completely private.
 * 
 * @param {Array} memories
 * @param {string} scope
 * @returns {Array}
 */
export function filterByScope(memories, scope) {
  const target = normalizeScope(scope);
  const targetLevel = SCOPE_HIERARCHY[target];
  const currentAgentId = AGENT_CONTEXT.current;
  
  // AGENT scope: strict agent_id isolation - only return current agent's memories
  // This is the key difference from other scopes - AGENT memories are completely private
  if (target === 'AGENT') {
    return memories.filter(m => {
      const mScope = normalizeScope(m.scope || 'GLOBAL');
      if (mScope !== 'AGENT') return false;
      // Same agent check
      if (currentAgentId && m.agent_id && m.agent_id !== currentAgentId) {
        return false;
      }
      return true;
    });
  }
  
  // Non-AGENT scopes: standard hierarchy (memory >= target means memory is same-or-broader)
  return memories.filter(m => {
    const mScope = normalizeScope(m.scope || 'GLOBAL');
    const mLevel = SCOPE_HIERARCHY[mScope];
    return mLevel >= targetLevel;
  });
}

/**
 * Check if a memory matches a scope
 * @param {object} memory
 * @param {string} scope
 * @returns {boolean}
 */
export function matchesScope(memory, scope) {
  const target = normalizeScope(scope);
  const mScope = normalizeScope(memory.scope || 'GLOBAL');
  
  // AGENT scope: also check agent_id isolation
  if (mScope === 'AGENT' && target === 'AGENT') {
    const currentAgentId = getCurrentAgentId();
    if (currentAgentId && memory.agent_id && memory.agent_id !== currentAgentId) {
      return false; // different agent, can't see each other's AGENT memories
    }
  }
  
  return SCOPE_HIERARCHY[mScope] >= SCOPE_HIERARCHY[target];
}

// ============ Team Namespace Functions ============

/**
 * Create a new team namespace
 * @param {string} teamId  - Unique team identifier (e.g. 'engineering', 'product-team-a')
 * @param {string} name    - Human-readable team name
 * @returns {{ teamId: string, name: string, created_at: number }}
 */
export function createTeamNamespace(teamId, name = '') {
  const id = teamId.replace(/[^a-zA-Z0-9_-]/g, '_').toLowerCase();
  const now = Date.now();
  teamRegistry.set(id, {
    name: name || id,
    created_at: now,
    memoryCount: 0,
  });
  return { teamId: id, name: name || id, created_at: now };
}

/**
 * Delete a team namespace (archives memories)
 * @param {string} teamId
 * @returns {boolean}
 */
export function deleteTeamNamespace(teamId) {
  return teamRegistry.delete(teamId);
}

/**
 * List all registered teams
 * @returns {Array<{ teamId: string, name: string, created_at: number }>}
 */
export function listTeams() {
  return Array.from(teamRegistry.entries()).map(([id, info]) => ({
    teamId: id,
    name: info.name,
    created_at: info.created_at,
  }));
}

/**
 * Set current team context for memory operations
 * @param {string|null} teamId  - team_id or null to clear
 */
export function setCurrentTeam(teamId) {
  TEAM_CONTEXT.current = teamId || null;
}

/**
 * Get current team context
 * @returns {string|null}
 */
export function getCurrentTeam() {
  return TEAM_CONTEXT.current;
}

/**
 * Switch to a different team context (returns previous)
 * @param {string|null} teamId
 * @returns {string|null} previous team_id
 */
export function switchTeam(teamId) {
  const prev = TEAM_CONTEXT.current;
  TEAM_CONTEXT.current = teamId || null;
  return prev;
}

/**
 * Get the team prefix for memory IDs
 * @param {string|null} teamId
 * @returns {string}
 */
export function getTeamPrefix(teamId) {
  if (!teamId) return '';
  return `team:${teamId}:`;
}

/**
 * Check if a memory belongs to a specific team
 * @param {object} memory
 * @param {string} teamId
 * @returns {boolean}
 */
export function memoryBelongsToTeam(memory, teamId) {
  if (!teamId) return false;
  // TEAM-scope memories store team_id explicitly
  if (memory.team_id && memory.team_id === teamId) return true;
  // Also check id prefix for backward compat
  const prefix = getTeamPrefix(teamId);
  return memory.id && memory.id.startsWith(prefix);
}

/**
 * Filter memories for the current team context + agent context
 * TEAM-scope: only memories belonging to current team
 * USER-scope: personal memories (no team filter)
 * AGENT-scope: only memories belonging to current agent_id
 * GLOBAL-scope: all memories
 * @param {Array} memories
 * @param {string} scope
 * @returns {Array}
 */
export function filterByTeamAndScope(memories, scope = 'TEAM') {
  const teamId = TEAM_CONTEXT.current;
  const agentId = AGENT_CONTEXT.current;

  // GLOBAL: no team/agent filtering needed
  if (scope === 'GLOBAL') {
    return memories;
  }

  return memories.filter(m => {
    const mScope = normalizeScope(m.scope || 'GLOBAL');

    // For TEAM scope: only return memories that belong to current team
    if (mScope === 'TEAM') {
      if (!teamId) return false; // No team context, can't see TEAM memories
      return memoryBelongsToTeam(m, teamId);
    }

    // AGENT scope: strict agent_id isolation - never visible to non-AGENT scopes
    if (mScope === 'AGENT') {
      if (scope === 'AGENT') {
        if (!agentId) return false;
        if (m.agent_id && m.agent_id !== agentId) return false;
        return true;
      }
      return false; // AGENT memories are NEVER visible to USER/TEAM/GLOBAL
    }

    // USER scope: no agent filtering (personal, not tied to specific agent)
    if (mScope === 'USER') {
      return true;
    }

    // Fallback: no filtering
    return true;
  });
}

/**
 * List memories for a specific team (ignores current context)
 * @param {Array} memories
 * @param {string} teamId
 * @returns {Array}
 */
export function listTeamMemories(memories, teamId) {
  if (!teamId) return [];
  return memories.filter(m => memoryBelongsToTeam(m, teamId));
}

/**
 * Get memory namespace key for storage
 * @param {string|null} teamId
 * @returns {string}
 */
export function getMemoryNamespace(teamId) {
  return teamId ? `team:${teamId}` : 'default';
}

/**
 * Tag a memory object with team context before storage
 * @param {object} memory
 * @param {string|null} teamId
 * @returns {object} memory with team_id set
 */
export function tagWithTeam(memory, teamId) {
  if (!teamId) return memory;
  return {
    ...memory,
    team_id: teamId,
    id: (memory.id && !memory.id.startsWith('team:'))
      ? `team:${teamId}:${memory.id}`
      : memory.id,
  };
}

/**
 * Extract team_id from a memory id prefix
 * @param {string} id
 * @returns {string|null}
 */
export function extractTeamFromId(id) {
  const match = id.match(/^team:([^:]+):/);
  return match ? match[1] : null;
}

export default {
  SCOPE_LEVELS,
  SCOPE_HIERARCHY,
  normalizeScope,
  getEffectiveScope,
  filterByScope,
  matchesScope,
  createTeamNamespace,
  deleteTeamNamespace,
  listTeams,
  setCurrentTeam,
  getCurrentTeam,
  switchTeam,
  getTeamPrefix,
  memoryBelongsToTeam,
  filterByTeamAndScope,
  listTeamMemories,
  getMemoryNamespace,
  tagWithTeam,
  extractTeamFromId,
  setCurrentAgentId,
  getCurrentAgentId,
  switchAgentId,
};

// Helper: returns scope order for sorting (lower = more specific)
export function getScopeOrder(scope) {
  return SCOPE_HIERARCHY[normalizeScope(scope)] ?? 999;
}
/**
 * Core Search Pipeline v3.1
 * Full integration: Adaptive skip → Intent routing → BM25 → Vector → Rerank → MMR → Decay → Category weighting → Scope
 * 
 * Complete retrieval chain:
 * 1. shouldSkipRetrieval() - skip meaningless queries (adaptive.js)
 * 2. routeSearch() - intent analysis, returns null = skip (intent.js)
 * 3. Scope filter + category filter based on intent weights
 * 4. BM25 search - fast keyword match
 * 5. Vector search - semantic similarity (LanceDB)
 * 6. LLM/keyword rerank - cross-encoder re-scoring
 * 7. MMR - diversity deduplication
 * 8. Weibull decay - time-weighted boosting
 * 9. Category weights from intent signal
 * 10. RRF fusion - merge BM25 + vector ranked lists
 */

import { shouldSkipRetrieval } from './adaptive.js';
import { routeSearch, getCategoryWeights } from './intent.js';
import { embedCache, EmbedCache } from './embed_cache.js';
import { bm25Search } from './bm25.js';
import { vectorSearch } from './vector.js';
import { keywordRerank, LlmReranker } from './rerank.js';
import { mmrSelect } from './mmr.js';
import { applyDecayBoost } from './decay.js';
import { filterByScope, getScopeOrder } from './scope.js';
import { filterByQuality } from './noise.js';
import { qualityScore } from './quality.js';
import { config } from './config.js';
import { loadMemories } from './storage.js';
import { MemoryAssociation } from './core/association.js';

// Intent patterns that trigger knowledge-graph association search
const ASSOCIATION_PATTERNS = [
  /^(what|哪些|什么).*(relat|关联|相关|联系)/i,
  /(relat|关联|相关|联系).*(to|到|于)/i,
  /^tell\s+me\s+about/i,
  /^(who\s+is|what\s+is|explain|describe)\s+.{0,30}$/i,
  /(remember|recall|earlier|before|曾|记得|之前).*related/i,
  /^(关联|相关记忆|相关联系)/i,
];

function isAssociationQuery(query) {
  const q = String(query || '').trim();
  // Check explicit patterns
  for (const p of ASSOCIATION_PATTERNS) {
    if (p.test(q)) return true;
  }
  // Also trigger for entity-type queries (tell me about X, who is X)
  const intent = routeSearch(q);
  if (intent && intent.intent === 'entity') return true;
  return false;
}

/**
 * Knowledge graph association search via MemoryAssociation
 * Uses vector similarity, co-occurrence, and tag correlation
 * @param {string} query
 * @param {number} topK
 * @returns {Promise<Array>}
 */
export async function knowledgeGraphSearch(query, topK = 5) {
  try {
    const association = new MemoryAssociation();
    const results = await association.relatedToQuery(query, topK);
    return results.map((r, i) => ({
      memory: r.memory,
      score: r.score,
      reasons: r.reasons,
      rank: i + 1,
      highlight: (r.memory.text || '').slice(0, 150),
      source: 'knowledge_graph',
    }));
  } catch (err) {
    // Graceful fallback - return empty on error
    console.error('[knowledgeGraphSearch] error:', err.message);
    return [];
  }
}

// Global embedding cache instance (shared across calls)
const embedCacheInstance = new EmbedCache(256, 30);
let llmReranker = null;

function getReranker() {
  if (!llmReranker) {
    llmReranker = new LlmReranker();
  }
  return llmReranker;
}

/**
 * Apply category weights to candidates based on intent signal
 * @param {Array} candidates 
 * @param {Map} categoryWeights 
 * @returns {Array}
 */
function applyCategoryWeights(candidates, categoryWeights) {
  if (!categoryWeights || categoryWeights.size === 0) return candidates;

  return candidates.map(c => {
    const cat = c.memory?.category || 'other';
    const weight = categoryWeights.get(cat) ?? 0.2;
    return {
      ...c,
      categoryWeight: weight,
      score: (c.score ?? (c.bm25Score ?? 0) + (c.vectorScore ?? 0)) * weight,
    };
  });
}

/**
 * Apply reflection/insightful boost to candidates.
 * Memories that have been reflected (insightful flag or reflection_count > 0)
 * receive a multiplicative score boost, stacking with existing relevance scores.
 *
 * @param {Array} candidates
 * @param {number} [boostFactor=0.15] - max boost multiplier added to score
 * @returns {Array}
 */
function applyReflectionBoost(candidates, boostFactor = 0.15) {
  return candidates.map(c => {
    const reflectionCount = c.memory?.reflection_count || 0;
    const insightful = c.memory?.insightful === true;
    if (!insightful && reflectionCount === 0) return c;

    // Cap boost at reflectionCount=3 (max boost reached)
    const boost = Math.min(reflectionCount, 3) * (boostFactor / 3);
    const originalScore = c.score ?? (c.bm25Score ?? 0) + (c.vectorScore ?? 0);
    return {
      ...c,
      reflectionBoost: boost,
      score: originalScore + boost,
    };
  });
}

/**
 * Main search pipeline v3.2
 * @param {string} query
 * @param {object} options
 * @param {number} options.topK - final results to return (default 10)
 * @param {string} options.scope - AGENT|USER|TEAM|GLOBAL (default GLOBAL)
 * @param {boolean} options.enableRerank - use LLM rerank (default true)
 * @param {boolean} options.enableMMR - use MMR diversity (default true)
 * @param {boolean} options.enableDecay - apply Weibull time decay (default true)
 * @param {boolean} options.reflectedBoost - boost reflected/insightful memories (default true)
 * @param {number} options.fetchK - candidates to fetch before MMR (default 20)
 * @param {string} options.mode - 'hybrid'|'bm25'|'vector' (default hybrid)
 * @returns {Promise<Array>}
 */
export async function search(query, options = {}) {
  const {
    topK = 10,
    scope = 'global',
    enableRerank = true,
    enableMMR = true,
    enableDecay = true,
    fetchK = 20,
    mode = 'hybrid',
    reflectedBoost = true,
  } = options;

  // === 1. Adaptive Skip ===
  if (shouldSkipRetrieval(query)) {
    return [];
  }

  // === 2. Intent Routing ===
  const intent = routeSearch(query);
  if (!intent) {
    return [];  // Query classified as skip (l0, non-specific)
  }

  // === 2b. Knowledge Graph Association Search (optional path for entity/relation queries) ===
  let kgResults = [];
  if (isAssociationQuery(query)) {
    try {
      kgResults = await knowledgeGraphSearch(query, fetchK);
      // Touch KG results so they count as accessed
      for (const r of kgResults) {
        if (r.memory?.id) {
          // Mark as touched via storage
          const { touchMemory } = await import('./storage.js');
          touchMemory(r.memory.id);
        }
      }
    } catch (err) {
      console.warn('[search] KG path failed, falling back to standard search:', err.message);
    }
  }

  // === 3. Load memories + Scope filter ===
  const allMemories = loadMemories();
  
  // Apply scope filter
  const scopeOrder = getScopeOrder(scope);
  let memories = [];
  for (const s of scopeOrder) {
    const filtered = filterByScope(allMemories, s);
    memories.push(...filtered);
  }

  // Apply noise filter (remove low-quality entries)
  memories = filterByQuality(memories);

  // Deduplicate by id
  const seen = new Set();
  memories = memories.filter(m => {
    if (seen.has(m.id)) return false;
    seen.add(m.id);
    return true;
  });

  if (memories.length === 0) return [];

  // === 4. BM25 Search (returns scored results) ===
  const bm25Results = bm25Search(query, fetchK * 2);

  // === 5. Vector Search ===
  const vectorResults = await vectorSearch(query, fetchK * 2);

  // === 6. Merge candidates ===
  const candidateMap = new Map();
  for (const r of bm25Results) {
    candidateMap.set(r.memory.id, { memory: r.memory, bm25Score: r.score ?? 0, vectorScore: 0, _bm25Rank: bm25Results.indexOf(r) });
  }
  for (const r of vectorResults) {
    const existing = candidateMap.get(r.memory.id);
    if (existing) {
      existing.vectorScore = r.score ?? 0;
    } else {
      candidateMap.set(r.memory.id, { memory: r.memory, bm25Score: 0, vectorScore: r.score ?? 0, _vectorRank: vectorResults.indexOf(r) });
    }
  }

  let candidates = Array.from(candidateMap.values());

  // === 6b. Inject KG association results into candidate pool ===
  if (kgResults.length > 0) {
    for (const kg of kgResults) {
      const existing = candidateMap.get(kg.memory.id);
      if (existing) {
        // Boost existing candidate with KG signal
        existing.score = (existing.score ?? 0) + (kg.score ?? 0) * 0.4;
        existing.kgScore = kg.score ?? 0;
        existing.kgReasons = kg.reasons ?? [];
      } else {
        // New candidate discovered via KG path only
        candidateMap.set(kg.memory.id, {
          memory: kg.memory,
          bm25Score: 0,
          vectorScore: 0,
          score: kg.score ?? 0,
          kgScore: kg.score ?? 0,
          kgReasons: kg.reasons ?? [],
          source: 'knowledge_graph',
        });
      }
    }
    candidates = Array.from(candidateMap.values());
  }

  // === 7. Rerank (optional) ===
  if (enableRerank) {
    try {
      const reranker = getReranker();
      candidates = await reranker.rerank(query, candidates, fetchK);
    } catch {
      candidates = keywordRerank(query, candidates, fetchK);
    }
  }

  // === 8. MMR Diversity (optional) ===
  if (enableMMR) {
    candidates = await mmrSelect(candidates, query, 0.5, fetchK, topK * 2);
  } else {
    candidates.sort((a, b) => ((b.bm25Score + b.vectorScore) - (a.bm25Score + a.vectorScore)));
    candidates = candidates.slice(0, fetchK);
  }

  // === 9. Weibull Time Decay (optional) ===
  if (enableDecay) {
    candidates = applyDecayBoost(candidates, 30, 0.3);
  }

  // === 10. Apply category weights from intent ===
  const categoryWeights = getCategoryWeights(intent);
  candidates = applyCategoryWeights(candidates, categoryWeights);

  // === 10b. Reflection / Insightful Boost ===
  // Memories that have been reflected (marked as insightful) get a relevance boost
  if (options.reflectedBoost !== false) {
    candidates = applyReflectionBoost(candidates);
  }

  // === 11. Build final results with RRF-like score ===
  const finalResults = candidates.slice(0, topK).map((c, i) => ({
    memory: c.memory,
    score: c.score ?? (c.bm25Score ?? 0) + (c.vectorScore ?? 0),
    bm25Score: c.bm25Score,
    vectorScore: c.vectorScore,
    fusionScore: c.fusionScore,
    rerankScore: c.rerankScore,
    decay: c.decay,
    categoryWeight: c.categoryWeight,
    reflectionBoost: c.reflectionBoost || 0,
    intentLabel: intent.label,
    ageDays: c.ageDays,
    rank: i + 1,
    highlight: c.highlight || c.memory.text?.slice(0, 150),
  }));

  return finalResults;
}

/**
 * Quick BM25-only search (no vector)
 */
export async function searchBm25(query, options = {}) {
  if (shouldSkipRetrieval(query)) return [];
  const intent = routeSearch(query);
  if (!intent) return [];

  const { topK = 10, scope = 'global' } = options;
  const allMemories = await loadMemories();
  const scopeOrder = getScopeOrder(scope);
  let memories = [];
  for (const s of scopeOrder) {
    memories.push(...filterByScope(allMemories, s));
  }
  memories = filterByQuality(memories);

  const results = bm25Search(query, topK);
  return results.slice(0, topK).map((r, i) => ({
    memory: r.memory,
    score: r.score,
    bm25Score: r.score,
    rank: i + 1,
    highlight: r.highlight,
  }));
}

/**
 * Get embedding cache stats
 */
export function getCacheStats() {
  return embedCache.getStats();
}
/**
 * semantic_dedup.js - Semantic Deduplication using Embeddings
 *
 * Given a new memory, find semantically similar existing memories using
 * cosine similarity on embedding vectors. Uses Ollama embeddings via
 * the existing embedding infrastructure.
 *
 * Thresholds:
 *   > 0.95 → Absorb (near-identical)
 *   0.85–0.95 → Merge candidate
 *   < 0.85 → Keep both
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'fs';
import { join } from 'path';
import { getEmbeddingCached } from './vector.js';
import { getAllMemories, getAllMemoriesRaw } from './storage.js';
import { config } from './config.js';

// ─── Configurable thresholds ────────────────────────────────────────────────
export const DEFAULT_SIMILARITY_THRESHOLD = 0.85;
export const ABSORB_THRESHOLD = 0.95;      // >0.95 → silently absorb
export const MERGE_THRESHOLD = 0.85;       // 0.85–0.95 → ask/merge
export const MIN_SCORE = 0.10;             // Minimum similarity to even report

// ─── Dedup log path ────────────────────────────────────────────────────────
export const DEDUP_LOG_PATH = join(config.memoryDir, 'dedup_log.json');

function ensureDedupLog() {
  const dir = config.memoryDir;
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
  if (!existsSync(DEDUP_LOG_PATH)) {
    writeFileSync(DEDUP_LOG_PATH, JSON.stringify({ merges: [], scans: [] }, null, 2));
  }
}

/**
 * Compute cosine similarity between two vectors.
 * @param {number[]} a
 * @param {number[]} b
 * @returns {number}
 */
export function cosineSimilarity(a, b) {
  if (!a || !b || a.length !== b.length) return 0;
  let dot = 0, normA = 0, normB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  if (normA === 0 || normB === 0) return 0;
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

/**
 * Load dedup log from disk.
 * @returns {{ merges: object[], scans: object[] }}
 */
export function loadDedupLog() {
  ensureDedupLog();
  try {
    return JSON.parse(readFileSync(DEDUP_LOG_PATH, 'utf8'));
  } catch {
    return { merges: [], scans: [] };
  }
}

/**
 * Append an entry to the dedup log.
 * @param {'merge'|'absorb'|'scan'} type
 * @param {object} entry
 */
export function appendDedupLog(type, entry) {
  ensureDedupLog();
  try {
    const log = loadDedupLog();
    const timestamp = new Date().toISOString();
    if (type === 'merge' || type === 'absorb') {
      log.merges.push({ ...entry, timestamp });
    } else {
      log.scans.push({ ...entry, timestamp });
    }
    writeFileSync(DEDUP_LOG_PATH, JSON.stringify(log, null, 2));
  } catch (err) {
    console.warn('[semantic_dedup] Failed to write dedup log:', err.message);
  }
}

/**
 * Get a memory's embedding. Uses cached file if available, otherwise generates.
 * Embeddings are cached under config.vectorCacheDir keyed by text hash.
 *
 * @param {object} memory - Memory object with `text` field
 * @returns {Promise<number[]|null>}
 */
async function getMemoryEmbedding(memory) {
  if (!memory || !memory.text) return null;
  try {
    return await getEmbeddingCached(memory.text);
  } catch (err) {
    console.warn(`[semantic_dedup] Embedding failed for ${memory.id}:`, err.message);
    return null;
  }
}

/**
 * Find duplicate candidates for a given text/memory against all stored memories.
 *
 * @param {object} newMemory - Memory object with `id` and `text`
 * @param {object} opts
 * @param {number} opts.threshold - Minimum similarity to return (default 0.85)
 * @param {number} opts.topK - Max candidates to return (default 10)
 * @returns {Promise<Array<{ memory: object, similarity: number }>>}
 */
export async function findDuplicateCandidates(newMemory, opts = {}) {
  const { threshold = DEFAULT_SIMILARITY_THRESHOLD, topK = 10 } = opts;

  if (!newMemory || !newMemory.text) {
    return [];
  }

  const existingMemories = (await getAllMemories()).filter(m => m.id !== newMemory.id);
  if (existingMemories.length === 0) return [];

  // Embed the new memory once
  const newEmbedding = await getMemoryEmbedding(newMemory);
  if (!newEmbedding) {
    console.warn('[semantic_dedup] Could not generate embedding for new memory');
    return [];
  }

  const candidates = [];

  // Compare against all existing memories
  // Process in batches to avoid hammering the embedding API
  const BATCH_SIZE = 20;
  for (let i = 0; i < existingMemories.length; i += BATCH_SIZE) {
    const batch = existingMemories.slice(i, i + BATCH_SIZE);
    await Promise.all(batch.map(async (existing) => {
      if (!existing.text) return;
      try {
        const existingEmbedding = await getMemoryEmbedding(existing);
        if (!existingEmbedding) return;
        const sim = cosineSimilarity(newEmbedding, existingEmbedding);
        if (sim >= threshold) {
          candidates.push({ memory: existing, similarity: sim });
        }
      } catch (err) {
        // Skip individual comparison failures
      }
    }));
  }

  // Sort by similarity descending, take topK
  candidates.sort((a, b) => b.similarity - a.similarity);
  return candidates.slice(0, topK);
}

/**
 * Classify a similarity score into a merge strategy.
 * @param {number} similarity - Cosine similarity 0–1
 * @returns {'absorb'|'merge'|'keep_both'}
 */
export function classifySimilarity(similarity) {
  if (similarity > ABSORB_THRESHOLD) return 'absorb';
  if (similarity >= MERGE_THRESHOLD) return 'merge';
  return 'keep_both';
}

/**
 * Determine merge strategy for a pair of memories.
 * @param {number} similarity
 * @returns {{ strategy: string, reason: string }}
 */
export function getMergeStrategy(similarity) {
  const strategy = classifySimilarity(similarity);
  const reasons = {
    absorb: `Similarity ${(similarity * 100).toFixed(1)}% > ${(ABSORB_THRESHOLD * 100).toFixed(0)}%: near-identical, keep older`,
    merge: `Similarity ${(similarity * 100).toFixed(1)}% in [${(MERGE_THRESHOLD * 100).toFixed(0)}%–${(ABSORB_THRESHOLD * 100).toFixed(0)}%]: merge unique details`,
    keep_both: `Similarity ${(similarity * 100).toFixed(1)}% < ${(MERGE_THRESHOLD * 100).toFixed(0)}%: different aspects, keep both`,
  };
  return { strategy, reason: reasons[strategy] };
}

/**
 * Full semantic scan: find all duplicate pairs across all memories.
 * Used by memory_dedup_full_scan tool.
 *
 * @param {object} opts
 * @param {number} opts.threshold - Minimum similarity (default 0.85)
 * @param {number} opts.maxPairs - Max pairs to return (default 100)
 * @returns {Promise<{ pairs: Array, stats: object }>}
 */
export async function findAllDuplicatePairs(opts = {}) {
  const { threshold = DEFAULT_SIMILARITY_THRESHOLD, maxPairs = 100 } = opts;

  const memories = getAllMemoriesRaw();
  if (memories.length < 2) {
    return { pairs: [], stats: { total: 0, pairsFound: 0 } };
  }

  // Generate embeddings for all memories
  const embeddingMap = new Map(); // id → embedding

  await Promise.all(memories.map(async (mem) => {
    if (!mem.text) return;
    const emb = await getMemoryEmbedding(mem);
    if (emb) embeddingMap.set(mem.id, emb);
  }));

  const pairs = [];
  const seen = new Set();

  for (let i = 0; i < memories.length; i++) {
    const memA = memories[i];
    const embA = embeddingMap.get(memA.id);
    if (!embA) continue;

    for (let j = i + 1; j < memories.length; j++) {
      const memB = memories[j];
      const embB = embeddingMap.get(memB.id);
      if (!embB) continue;

      const sim = cosineSimilarity(embA, embB);
      if (sim >= threshold) {
        const key = [memA.id, memB.id].sort().join('__');
        if (!seen.has(key)) {
          seen.add(key);
          const { strategy, reason } = getMergeStrategy(sim);
          pairs.push({
            memoryA: { id: memA.id, text: memA.text.slice(0, 100), category: memA.category, created_at: memA.created_at },
            memoryB: { id: memB.id, text: memB.text.slice(0, 100), category: memB.category, created_at: memB.created_at },
            similarity: Math.round(sim * 10000) / 10000,
            strategy,
            reason,
          });
          if (pairs.length >= maxPairs) break;
        }
      }
    }
    if (pairs.length >= maxPairs) break;
  }

  // Sort by similarity descending
  pairs.sort((a, b) => b.similarity - a.similarity);

  const absorbCount = pairs.filter(p => p.strategy === 'absorb').length;
  const mergeCount = pairs.filter(p => p.strategy === 'merge').length;

  return {
    pairs,
    stats: {
      total: memories.length,
      pairsFound: pairs.length,
      absorbCandidates: absorbCount,
      mergeCandidates: mergeCount,
      threshold,
    },
  };
}

export default {
  cosineSimilarity,
  findDuplicateCandidates,
  findAllDuplicatePairs,
  classifySimilarity,
  getMergeStrategy,
  loadDedupLog,
  appendDedupLog,
  DEFAULT_SIMILARITY_THRESHOLD,
  ABSORB_THRESHOLD,
  MERGE_THRESHOLD,
};
/**
 * session_state.js - Session State RAM Layer
 * 
 * Manages SESSION-STATE.md at workspace root (survives compaction).
 * Provides hot RAM layer for current task context, key decisions, and pending actions.
 * Inspired by Elite Longterm Memory's session state approach.
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const HOME = process.env.HOME || '/root';
const WORKSPACE = join(HOME, '.openclaw', 'workspace');
const SESSION_STATE_FILE = join(WORKSPACE, 'SESSION-STATE.md');

// Ensure workspace directory exists
if (!existsSync(WORKSPACE)) {
  mkdirSync(WORKSPACE, { recursive: true });
}

// ============================================================================
// Types
// ============================================================================

/**
 * @typedef {Object} SessionAction
 * @property {string} text
 * @property {boolean} done
 * @property {string} created_at
 */

/**
 * @typedef {Object} SessionState
 * @property {string|null} task
 * @property {Record<string, string>} context
 * @property {SessionAction[]} actions
 * @property {string} updated_at
 */

// ============================================================================
// Markdown Serialization
// ============================================================================

/**
 * Serialize SessionState to markdown format
 * @param {SessionState} state
 * @returns {string}
 */
function serializeMarkdown(state) {
  const lines = ['# SESSION-STATE.md', ''];
  
  lines.push('## Current Task');
  lines.push(state.task || '_No active task_');
  lines.push('');
  
  lines.push('## Key Context');
  if (Object.keys(state.context).length === 0) {
    lines.push('_No context recorded_');
  } else {
    for (const [key, value] of Object.entries(state.context)) {
      lines.push(`- ${key}: ${value}`);
    }
  }
  lines.push('');
  
  lines.push('## Pending Actions');
  if (state.actions.length === 0) {
    lines.push('_No pending actions_');
  } else {
    for (const action of state.actions) {
      const checkbox = action.done ? '[x]' : '[ ]';
      lines.push(`- ${checkbox} ${action.text}`);
    }
  }
  lines.push('');
  
  return lines.join('\n');
}

/**
 * Parse markdown format to SessionState
 * @param {string} content
 * @returns {SessionState}
 */
function parseMarkdown(content) {
  const state = {
    task: null,
    context: {},
    actions: [],
    updated_at: new Date().toISOString(),
  };
  
  if (!content || !content.trim()) return state;
  
  const lines = content.split('\n');
  let currentSection = null;
  
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const trimmed = line.trim();
    
    // Detect section headers
    if (trimmed === '## Current Task') {
      currentSection = 'task';
      continue;
    }
    if (trimmed === '## Key Context') {
      currentSection = 'context';
      continue;
    }
    if (trimmed === '## Pending Actions') {
      currentSection = 'actions';
      continue;
    }
    
    // Skip empty lines and non-content
    if (!trimmed || trimmed === '# SESSION-STATE.md') continue;
    
    if (currentSection === 'task') {
      if (trimmed !== '_No active task_') {
        state.task = trimmed;
      }
    } else if (currentSection === 'context') {
      // Parse: "- key: value"
      const match = trimmed.match(/^-\s+(.+?):\s+(.+)$/);
      if (match) {
        state.context[match[1]] = match[2];
      }
    } else if (currentSection === 'actions') {
      // Parse: "- [x] action text" or "- [ ] action text"
      const actionMatch = trimmed.match(/^-\s+\[([ x])\]\s+(.+)$/);
      if (actionMatch) {
        state.actions.push({
          done: actionMatch[1] === 'x',
          text: actionMatch[2],
          created_at: state.updated_at,
        });
      }
    }
  }
  
  return state;
}

// ============================================================================
// File Operations
// ============================================================================

/**
 * Load session state from SESSION-STATE.md
 * @returns {SessionState}
 */
function loadState() {
  try {
    if (!existsSync(SESSION_STATE_FILE)) {
      return getDefaultState();
    }
    const content = readFileSync(SESSION_STATE_FILE, 'utf-8');
    return parseMarkdown(content);
  } catch (err) {
    console.error(`[session_state] Failed to load: ${err.message}`);
    return getDefaultState();
  }
}

/**
 * Save session state to SESSION-STATE.md
 * @param {SessionState} state
 */
function saveState(state) {
  try {
    state.updated_at = new Date().toISOString();
    const content = serializeMarkdown(state);
    writeFileSync(SESSION_STATE_FILE, content, 'utf-8');
  } catch (err) {
    console.error(`[session_state] Failed to save: ${err.message}`);
  }
}

/**
 * Get default empty state
 * @returns {SessionState}
 */
function getDefaultState() {
  return {
    task: null,
    context: {},
    actions: [],
    updated_at: new Date().toISOString(),
  };
}

// ============================================================================
// Public API
// ============================================================================

/**
 * Update the current task
 * @param {string} task
 */
export function setCurrentTask(task) {
  const state = loadState();
  state.task = task;
  saveState(state);
}

/**
 * Add a key-context pair to the context section
 * @param {string} key
 * @param {string} value
 */
export function addContext(key, value) {
  const state = loadState();
  state.context[key] = value;
  saveState(state);
}

/**
 * Add a pending action
 * @param {string} action
 */
export function addAction(action) {
  const state = loadState();
  state.actions.push({
    text: action,
    done: false,
    created_at: new Date().toISOString(),
  });
  saveState(state);
}

/**
 * Mark an action as complete (matches by text content)
 * @param {string} actionText
 * @returns {boolean} true if found and marked done
 */
export function completeAction(actionText) {
  const state = loadState();
  const normalizedSearch = actionText.trim().toLowerCase();
  
  const action = state.actions.find(a => 
    a.text.toLowerCase() === normalizedSearch ||
    a.text.toLowerCase().includes(normalizedSearch) ||
    normalizedSearch.includes(a.text.toLowerCase())
  );
  
  if (action) {
    action.done = true;
    saveState(state);
    return true;
  }
  return false;
}

/**
 * Read and return the current session state
 * @returns {SessionState}
 */
export function getSessionState() {
  return loadState();
}

/**
 * Clear all session state (reset to defaults)
 */
export function clearState() {
  saveState(getDefaultState());
}

// ============================================================================
// MCP Tool Handler
// ============================================================================

/**
 * Handle memory_session MCP tool calls
 * @param {object} args
 * @param {string} [args.action]
 * @param {string} [args.task]
 * @param {string} [args.key]
 * @param {string} [args.value]
 * @param {string} [args.action_text]
 * @returns {Promise<{content: Array<{type: string, text: string}>, isError?: boolean}>}
 */
export async function memorySessionTool(args) {
  const { action } = args;
  
  try {
    switch (action) {
      case 'get': {
        const state = getSessionState();
        return {
          content: [{
            type: 'text',
            text: JSON.stringify(state, null, 2),
          }],
        };
      }
      
      case 'set_task': {
        if (!args.task) {
          return { content: [{ type: 'text', text: 'Error: task is required' }], isError: true };
        }
        setCurrentTask(args.task);
        return { content: [{ type: 'text', text: JSON.stringify({ success: true, task: args.task }) }] };
      }
      
      case 'add_context': {
        if (!args.key) {
          return { content: [{ type: 'text', text: 'Error: key is required' }], isError: true };
        }
        if (!args.value) {
          return { content: [{ type: 'text', text: 'Error: value is required' }], isError: true };
        }
        addContext(args.key, args.value);
        return { content: [{ type: 'text', text: JSON.stringify({ success: true, key: args.key, value: args.value }) }] };
      }
      
      case 'add_action': {
        if (!args.action_text) {
          return { content: [{ type: 'text', text: 'Error: action_text is required' }], isError: true };
        }
        addAction(args.action_text);
        return { content: [{ type: 'text', text: JSON.stringify({ success: true, action: args.action_text }) }] };
      }
      
      case 'complete_action': {
        if (!args.action_text) {
          return { content: [{ type: 'text', text: 'Error: action_text is required' }], isError: true };
        }
        const found = completeAction(args.action_text);
        return {
          content: [{
            type: 'text',
            text: JSON.stringify({ success: found, action_text: args.action_text, message: found ? 'Action marked as done' : 'Action not found' }),
          }],
        };
      }
      
      case 'clear': {
        clearState();
        return { content: [{ type: 'text', text: JSON.stringify({ success: true, message: 'Session state cleared' }) }] };
      }
      
      default:
        return {
          content: [{ type: 'text', text: `Error: Unknown action '${action}'. Valid actions: get, set_task, add_context, add_action, complete_action, clear` }],
          isError: true,
        };
    }
  } catch (err) {
    return { content: [{ type: 'text', text: `Session state error: ${err.message}` }], isError: true };
  }
}

export default { memorySessionTool };
import { readFileSync, writeFileSync, existsSync, mkdirSync, unlinkSync } from 'fs';
import { readFile, writeFile, rename } from 'fs/promises';
import { join } from 'path';
import { config } from './config.js';
import { acquireLockSync, releaseLockSync, initWalStorage, logWriteOp } from './storage_lock.js';
import { logOp, readWal, closeWal } from './wal.js';
import {
  getCurrentTeam,
  filterByTeamAndScope,
  normalizeScope,
  getCurrentAgentId,
} from './scope.js';
import { getTransactionManager } from './transaction-manager.js';

// v4 StorageGateway proxy (unified backend for sqlite mode)
let _v4Gw = null;
async function getV4Gw() {
  if (!_v4Gw) {
    const { StorageGateway } = await import('./v4/storage-gateway.js');
    _v4Gw = new StorageGateway();
    await _v4Gw.init();
  }
  return _v4Gw;
}

// ===== Storage Mode Selection =====
const STORAGE_MODE = process.env.STORAGE_MODE || 'json';

// Lazy-load SQLite backend (only when STORAGE_MODE=sqlite)
let _sqliteBackend = null;
async function getSqliteBackend() {
  if (_sqliteBackend) return _sqliteBackend;
  try {
    _sqliteBackend = await import('./storage_sqlite.js');
    return _sqliteBackend;
  } catch (e) {
    console.warn('[storage] SQLite backend unavailable:', e.message);
    return null;
  }
}

/**
 * Check if SQLite backend is active
 */
function isSqliteMode() {
  return STORAGE_MODE === 'sqlite';
}

// Lazy import to avoid circular deps and to handle missing Ollama gracefully
let _vectorMem = null;
async function getVectorMem() {
  if (!_vectorMem) {
    try {
      const { VectorMemory } = await import('./vector_lancedb.js');
      _vectorMem = new VectorMemory();
      await _vectorMem.initialize();
    } catch (e) {
      console.warn('[storage] VectorMemory init failed:', e.message);
      return null;
    }
  }
  return _vectorMem;
}

/**
 * @typedef {import('./types.js').Memory} Memory
 */

/** @type {Map<string, Memory[]>} */
const memoryCache = new Map();
let cacheDirty = false;

// ─── Write-Behind Buffer (P0-3) ──────────────────────────────────────────────
const WRITE_BEHIND_DELAY_MS = 500;
let _writeTimer = null;
let _pendingMemories = null;

/**
 * Flush any pending write immediately (called by timer or on shutdown)
 */
async function _flushPendingWrite() {
  if (!_pendingMemories) return;
  const memories = _pendingMemories;
  _pendingMemories = null;
  _writeTimer = null;
  // Direct write for JSON mode (no debounce timer, immediate flush)
  const lockPath = config.memoryFile;
  acquireLockSync(lockPath);
  try {
    if (global._walInit) {
      logWriteOp({ type: 'save', count: memories.length });
    }
    const data = JSON.stringify(memories, null, 2);
    const tmpPath = `${lockPath}.tmp.${process.pid}.${Date.now()}`;
    
    // 使用 fsync 保证数据持久化
    await writeFile(tmpPath, data, 'utf8');
    
    // 确保数据写入磁盘
    const fs = await import('fs');
    const fd = await fs.promises.open(tmpPath, 'r+');
    try {
      await fd.sync();
    } finally {
      await fd.close();
    }
    
    // 原子性重命名
    await rename(tmpPath, lockPath);
    
    // 确保目标文件也同步到磁盘
    const targetFd = await fs.promises.open(lockPath, 'r+');
    try {
      await targetFd.sync();
    } finally {
      await targetFd.close();
    }
    
  } catch (err) {
    console.error('[storage] Write-behind flush failed:', err.message);
  } finally {
    try { releaseLockSync(lockPath); } catch { /* ignore */ }
  }
  memoryCache.set('all', memories);
  cacheDirty = false;
}

/**
 * Actual save logic (async, multi-process safe via rename)
 */
async function _doSaveMemories(memories) {
  const lockPath = config.memoryFile;
  // Multi-process safe: use flock lock + atomic rename
  acquireLockSync(lockPath);
  let released = false;
  try {
    if (global._walInit) {
      logWriteOp({ type: 'save', count: memories.length });
    }
    const data = JSON.stringify(memories, null, 2);
    // Atomic write: temp file + rename (crash-safe, no partial files)
    const tmpPath = `${lockPath}.tmp.${process.pid}.${Date.now()}`;
    await writeFile(tmpPath, data, 'utf8');
    await rename(tmpPath, lockPath);
  } catch (err) {
    console.error('[storage] Write-behind flush failed:', err.message);
  } finally {
    try { releaseLockSync(lockPath); } catch { /* ignore */ }
  }
  memoryCache.set('all', memories);
  cacheDirty = false;
}

/**
 * @returns {Memory[]}
 */
export async function loadMemories() {
  // Clear any pending write-behind writes before reading from disk.
  // If a crash occurred, the pending write is lost and we reload from disk.
  if (_writeTimer) { clearTimeout(_writeTimer); _writeTimer = null; }
  _pendingMemories = null;
  // SQLite backend path
  if (isSqliteMode()) {
    const gw = await getV4Gw();
    const mems = await gw.getMemories({ limit: 100000 });
    memoryCache.set('all', mems);
    return mems;
  }

  // JSON backend (default)
  if (!existsSync(config.memoryFile)) {
    return [];
  }
  try {
    const data = JSON.parse(readFileSync(config.memoryFile, 'utf8'));
    return Array.isArray(data) ? data : (data.memories || []);
  } catch {
    return [];
  }
}

/**
 * Save memories to disk (write-behind: queues write and flushes after debounce)
 * @param {Memory[]} memories
 */
export async function saveMemories(memories) {
  // SQLite backend
  if (isSqliteMode()) {
    // writeMemory handles WAL internally; no need to call gw multiple times
    // For bulk save, just return (memories already in DB via addMemory/updateMemory)
    return;
  }

  // Initialize WAL on first call
  if (!global._walInit) {
    try {
      initWalStorage();
      global._walInit = true;
    } catch { /* WAL init failure is non-fatal */ }
  }

  memoryCache.set('all', memories);
  cacheDirty = false;

  // Write-behind: debounce 500ms to reduce I/O under load
  _pendingMemories = memories;
  if (_writeTimer) clearTimeout(_writeTimer);
  _writeTimer = setTimeout(() => {
    _flushPendingWrite().catch(err => console.error('[storage] flush error:', err.message));
  }, WRITE_BEHIND_DELAY_MS);
}

/**
 * Force immediate flush of pending writes (call before shutdown or critical ops)
 */
export async function flushPendingWrites() {
  if (_writeTimer) {
    clearTimeout(_writeTimer);
    _writeTimer = null;
  }
  if (_pendingMemories) {
    await _flushPendingWrite();
  }
}

/**
 * Get all memories (with caching)
 * Optionally filter by team+scope context.
 * @param {object} opts
 * @param {string} [opts.scope='GLOBAL']  - Scope level for filtering
 * @param {boolean} [opts.applyTeamFilter=true] - Whether to apply current team context
 * @returns {Memory[]}
 */
// Normalized memory cache (survives across calls)
let _normalizedCache = null;

export async function getAllMemories(opts = {}) {
  if (isSqliteMode()) {
    const gw = await getV4Gw();
    return gw.getMemories({ ...opts, limit: opts.limit || 10000 });
  }
  const { scope = 'GLOBAL', applyTeamFilter = false } = opts;
  if (!memoryCache.has('all')) {
    memoryCache.set('all', await loadMemories());
    _normalizedCache = null; // reset normalized cache on reload
  }
  // Normalize: support both 'content' (import format) and 'text' field
  // Cache normalized result to avoid re-mapping on every call
  if (!_normalizedCache) {
    _normalizedCache = memoryCache.get('all').map((m) => ({
      ...m,
      text: m.text || m.content || '',
      created_at: m.created_at || (m.timestamp ? new Date(m.timestamp).getTime() : Date.now()),
    }));
  }
  let memories = _normalizedCache;

  // Apply team+scope filtering when requested
  if (applyTeamFilter) {
    const teamId = getCurrentTeam();
    memories = filterByTeamAndScope(memories, scope);
  }

  return memories;
}

// Sync access to raw (non-normalized) memories - for internal use only
export function getAllMemoriesRaw() {
  return memoryCache.get('all') || [];
}

/**
 * Invalidate cache
 */
export function invalidateCache() {
  memoryCache.delete('all');
}

/**
 * Add a new memory
 * @param {Omit<Memory, 'id' | 'created_at' | 'updated_at' | 'access_count' | 'last_access'>} mem
 * @returns {Memory}
 */
export async function addMemory(mem) {
  if (isSqliteMode()) {
    const gw = await getV4Gw();
    return gw.writeMemory({
      text: mem.text,
      category: mem.category || 'general',
      importance: mem.importance || 0.5,
      scope: mem.scope,
      scopeId: mem.scopeId,
      tags: mem.tags,
    });
  }

  const now = Date.now();

  // v3.2: Auto-tag with agent_id if in AGENT scope
  const scope = mem.scope || 'USER';
  const agentId = scope === 'AGENT' ? mem.agent_id || getCurrentAgentId() : null;

  /** @type {Memory} */
  const newMem = {
    id: `mem_${now}_${Math.random().toString(36).slice(2, 8)}`,
    text: mem.text,
    category: mem.category || 'general',
    importance: mem.importance || 0.5,
    tags: mem.tags || [],
    scope,
    ...(agentId ? { agent_id: agentId } : {}),
    created_at: now,
    updated_at: now,
    access_count: 0,
    last_access: now,
  };

  // JSON backend
  const memories = await getAllMemories();
  memories.push(newMem);

  // WAL: log individual add op before save (crash recovery = replay add)
  if (global._walInit) {
    logWriteOp({ type: 'add', memory: newMem });
  }

  // 使用原子事务管理器保证双写一致性
  const txManager = getTransactionManager();
  const transactionId = await txManager.beginTransaction();
  
  try {
    // 阶段1：准备 JSON 写入
    await txManager.prepareJsonWrite(transactionId, newMem);
    
    // 阶段2：准备向量写入（如果有 embedding）
    const vectorMem = await getVectorMem();
    if (vectorMem && mem.embedding) {
      await txManager.prepareVectorWrite(transactionId, newMem, mem.embedding);
    }
    
    // 阶段3：提交事务 - 原子性写入两个存储
    await saveMemories(memories);
    
    // 阶段4：执行向量写入（在事务保护下）
    if (vectorMem && mem.embedding) {
      try {
        await vectorMem.upsert({
          id: newMem.id,
          text: newMem.text,
          embedding: mem.embedding,
          created_at: now,
        });
      } catch (vectorError) {
        console.error(`[storage] Vector upsert failed for memory ${newMem.id}:`, vectorError.message);
        // 向量写入失败，需要回滚 JSON 写入
        const currentMemories = await getAllMemories();
        const updatedMemories = currentMemories.filter(m => m.id !== newMem.id);
        await saveMemories(updatedMemories);
        throw new Error(`Vector store write failed: ${vectorError.message}`);
      }
    }
    
    // 阶段5：提交事务
    await txManager.commitTransaction(transactionId);
    
  } catch (error) {
    // 事务失败，回滚
    console.error(`[storage] Atomic write failed for memory ${newMem.id}:`, error.message);
    
    // 从内存缓存中移除（如果已添加）
    const currentMemories = await getAllMemories();
    const updatedMemories = currentMemories.filter(m => m.id !== newMem.id);
    await saveMemories(updatedMemories);
    
    // 回滚事务
    await txManager.rollbackTransaction(transactionId, error);
    
    throw new Error(`Failed to write memory atomically: ${error.message}`);
  }

  return newMem;
}

/**
 * Delete a memory by id
 * @param {string} id
 * @returns {boolean}
 */
export async function deleteMemory(id) {
  if (isSqliteMode()) {
    const gw = await getV4Gw();
    return gw.deleteMemory(id);
  }

  // JSON backend
  const memories = await getAllMemories();
  const idx = memories.findIndex((m) => m.id === id);
  if (idx === -1) return false;
  memories.splice(idx, 1);

  // WAL: log individual delete op before save
  if (global._walInit) {
    logWriteOp({ type: 'delete', memory_id: id });
  }

  await saveMemories(memories);

  // Sync delete to LanceDB vector store
  getVectorMem().then(vm => {
    if (vm) vm.delete(id).catch(e => console.warn('[storage→LanceDB] delete failed:', e.message));
  }).catch(() => {});

  return true;
}

/**
 * Permanently forget a memory (for lifecycle/forgetting mechanism).
 * Triggers when significance < 0.05.
 * - Removes from memory store
 * - Removes from vector index cache (by text hash)
 * - Logs WAL "FORGET" operation
 * @param {string} memoryId
 * @returns {boolean}
 */
export function forget(memoryId) {
  const memories = getAllMemoriesRaw();
  const mem = memories.find((m) => m.id === memoryId);
  if (!mem) return false;

  // Remove from vector cache if text is available
  if (mem.text) {
    try {
      const hash = hashTextForCache(mem.text);
      const cacheFile = join(config.vectorCacheDir, `${hash}.json`);
      if (existsSync(cacheFile)) {
        unlinkSync(cacheFile);
      }
    } catch { /* ignore cache cleanup errors */ }
  }

  // Remove from in-memory memories list
  const idx = memories.findIndex((m) => m.id === memoryId);
  if (idx !== -1) memories.splice(idx, 1);

  // WAL: log FORGET op (significance = importance field)
  if (global._walInit) {
    logWriteOp({ type: 'FORGET', memory_id: memoryId, significance: mem.importance });
  }

  saveMemories(memories);
  return true;
}

/**
 * Hash text to match vector cache key format (same as vector.js getEmbeddingCached)
 * @param {string} text
 * @returns {string}
 */
function hashTextForCache(text) {
  let hash = 0;
  for (let i = 0; i < text.length; i++) {
    const char = text.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(36);
}

/**
 * Get a memory by id
 * @param {string} id
 * @returns {Memory|undefined}
 */
export async function getMemory(id) {
  if (isSqliteMode()) {
    const gw = await getV4Gw();
    return gw.getMemory(id);
  }
  const memories = await getAllMemories();
  return memories.find((m) => m.id === id);
}

/**
 * Update access stats
 * @param {string} id
 */
export async function updateMemory(updatedMem) {
  if (isSqliteMode()) {
    const gw = await getV4Gw();
    const existing = await gw.getMemory(updatedMem.id);
    if (!existing) return false;
    // StorageGateway.writeMemory acts as upsert
    return gw.writeMemory({
      text: updatedMem.text ?? existing.text,
      category: updatedMem.category ?? existing.category,
      importance: updatedMem.importance ?? existing.importance,
      scope: updatedMem.scope ?? existing.scope_type,
      scopeId: updatedMem.scopeId ?? existing.scope_id,
      tags: updatedMem.tags ?? existing.tags,
      id: updatedMem.id,
    });
  }
  const memories = await getAllMemories();
  const idx = memories.findIndex((m) => m.id === updatedMem.id);
  if (idx === -1) return false;
  const oldMemory = { ...memories[idx] }; // 保存旧版本用于创建 diff
  memories[idx] = { ...memories[idx], ...updatedMem };
  await saveMemories(memories);
  // v2.7.0: 每次更新自动创建版本记录
  createMemoryVersion(updatedMem.id, memories[idx], oldMemory, 'update');

  // P1-6: Sync text changes to vector store (old embedding is cleaned up by upsert's delete)
  if (updatedMem.text !== undefined) {
    getVectorMem().then(vm => {
      if (vm) vm.upsert({
        id: updatedMem.id,
        text: updatedMem.text,
        category: memories[idx].category,
        scope: memories[idx].scope,
        importance: memories[idx].importance,
        created_at: memories[idx].created_at,
      }).catch(e => console.warn('[storage→LanceDB] update upsert failed:', e.message));
    }).catch(() => {});
  }
  return true;
}

export function touchMemory(id) {
  if (isSqliteMode()) {
    const backend = _sqliteBackend || null;
    if (backend) {
      backend.touchMemoryById(id);
      return;
    }
  }
  const memories = getAllMemoriesRaw();
  const mem = memories.find((m) => m.id === id);
  if (mem) {
    mem.access_count = (mem.access_count || 0) + 1;
    mem.last_access = Date.now();
    // WAL: log access op (for quality scoring / access tracking in recovery)
    if (global._walInit) {
      logWriteOp({ type: 'access', memory_id: id });
    }
    saveMemories(memories);
  }
}

// ============================================================
// v3.4: PIN 记忆系统 — 重要记忆永不丢失
// ============================================================

const PIN_REASON_MAX = 200; // reason 最大长度

/**
 * 锁定一条记忆（不被压缩/删除）
 * @param {string} id
 * @param {string} reason 锁定原因
 * @returns {boolean}
 */
export function pinMemory(id, reason = '') {
  if (isSqliteMode()) {
    const backend = _sqliteBackend || null;
    if (backend) {
      const pinned = backend.pinMemoryById(id, reason);
      if (pinned) { getAllMemories().then(data => { memoryCache.set('all', data); _normalizedCache = null; }); }
      return pinned;
    }
  }
  const memories = getAllMemoriesRaw();
  const mem = memories.find(m => m.id === id);
  if (!mem) return false;
  mem.pinned = true;
  mem.pinnedAt = Date.now();
  mem.pinnedReason = String(reason).slice(0, PIN_REASON_MAX);
  if (global._walInit) {
    logWriteOp({ type: 'pin', memory_id: id, reason: mem.pinnedReason });
  }
  saveMemories(memories);
  return true;
}

/**
 * 解锁一条记忆
 * @param {string} id
 * @returns {boolean}
 */
export function unpinMemory(id) {
  if (isSqliteMode()) {
    const backend = _sqliteBackend || null;
    if (backend) {
      const unpinned = backend.unpinMemoryById(id);
      if (unpinned) { getAllMemories().then(data => { memoryCache.set('all', data); _normalizedCache = null; }); }
      return unpinned;
    }
  }
  const memories = getAllMemoriesRaw();
  const mem = memories.find(m => m.id === id);
  if (!mem) return false;
  mem.pinned = false;
  mem.pinnedAt = null;
  mem.pinnedReason = null;
  if (global._walInit) {
    logWriteOp({ type: 'unpin', memory_id: id });
  }
  saveMemories(memories);
  return true;
}

/**
 * 获取所有 PIN 记忆
 * @returns {Array}
 */
export function getPinnedMemories() {
  if (isSqliteMode()) {
    const backend = _sqliteBackend || null;
    if (backend) return backend.getPinnedMemories();
  }
  return getAllMemoriesRaw().filter(m => m.pinned);
}

// ============================================================
// v2.7.0: 完整修订历史 (Version History) — 增量 diff 存储
// ============================================================
// 注意：readFileSync/writeFileSync/existsSync/mkdirSync 已在上方导入

const WORKSPACE = process.env.OPENCLAW_WORKSPACE_DIR ?? join(process.env.HOME ?? '/root', '.openclaw', 'workspace');
const VERSIONS_FILE = join(WORKSPACE, 'memory', 'memory_versions.json');
const MAX_VERSIONS = 10; // 保留最近 10 个版本
const VERSIONS_WRITE_DELAY_MS = 500;
let _versionsTimer = null;
let _pendingVersionStore = null;

/** 加载版本存储 */
export function loadVersionStore() {
  // Clear any pending version store write before reading
  if (_versionsTimer) { clearTimeout(_versionsTimer); _versionsTimer = null; }
  _pendingVersionStore = null;
  if (!existsSync(VERSIONS_FILE)) {
    return {};
  }
  try {
    return JSON.parse(readFileSync(VERSIONS_FILE, 'utf8'));
  } catch (err) {
    console.error('[storage:versions] Load error:', err.message);
    return {};
  }
}

/** 持久化版本存储 (write-behind, debounced) */
function persistVersionStore(store) {
  _pendingVersionStore = store;
  if (_versionsTimer) clearTimeout(_versionsTimer);
  _versionsTimer = setTimeout(() => {
    _flushVersionStore().catch(err => console.error('[storage:versions] flush error:', err.message));
  }, VERSIONS_WRITE_DELAY_MS);
}

async function _flushVersionStore() {
  if (!_pendingVersionStore) return;
  const store = _pendingVersionStore;
  _pendingVersionStore = null;
  _versionsTimer = null;
  try {
    const dir = join(WORKSPACE, 'memory');
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    const tmpPath = `${VERSIONS_FILE}.tmp.${process.pid}.${Date.now()}`;
    await writeFile(tmpPath, JSON.stringify(store, null, 2), 'utf8');
    await rename(tmpPath, VERSIONS_FILE);
  } catch (err) {
    console.error('[storage:versions] Persist error:', err.message);
  }
}

/** Flush pending version store writes */
export async function flushVersionStore() {
  if (_versionsTimer) { clearTimeout(_versionsTimer); _versionsTimer = null; }
  if (_pendingVersionStore) await _flushVersionStore();
}

/** 生成版本 ID */
function genVersionId() {
  return `v_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
}

/**
 * 计算两个内容的增量 diff（行级 diff，无外部依赖）
 * @param {any} oldContent
 * @param {any} newContent
 * @returns {{ added: string[], removed: string[], addedCount: number, removedCount: number }}
 */
function computeDiff(oldContent, newContent) {
  const oldText = typeof oldContent === 'string' ? oldContent : JSON.stringify(oldContent, null, 2);
  const newText = typeof newContent === 'string' ? newContent : JSON.stringify(newContent, null, 2);

  const oldLines = oldText.split('\n');
  const newLines = newText.split('\n');

  const oldSet = new Set(oldLines);
  const newSet = new Set(newLines);

  const diff = { added: [], removed: [] };
  for (const line of newLines) {
    if (!oldSet.has(line)) diff.added.push(line);
  }
  for (const line of oldLines) {
    if (!newSet.has(line)) diff.removed.push(line);
  }
  diff.addedCount = diff.added.length;
  diff.removedCount = diff.removed.length;
  return diff;
}

/**
 * 创建记忆版本的快照（完整内容，用于最终重建）
 * @param {string} memoryId
 * @param {object} newMemory 更新后的完整记忆
 * @param {object|null} oldMemory 更新前的完整记忆（可选）
 * @param {'update'|'create'|'restore'} changeType
 */
function createMemoryVersion(memoryId, newMemory, oldMemory = null, changeType = 'update') {
  const store = loadVersionStore();

  if (!store[memoryId]) {
    store[memoryId] = { versions: [] };
  }

  const versions = store[memoryId].versions;
  const latest = versions[versions.length - 1];

  // 计算与上一个版本的增量 diff
  let diffFromPrev = null;
  if (latest && oldMemory) {
    diffFromPrev = computeDiff(latest.content, newMemory);
  } else if (!latest && newMemory) {
    diffFromPrev = computeDiff({}, newMemory);
  }

  const version = {
    versionId: genVersionId(),
    content: { ...newMemory }, // 完整快照（简化实现，不依赖 jsondiffpatch）
    timestamp: Date.now(),
    changeType,
    diffFromPrev,
  };

  versions.push(version);

  // 保留最近 MAX_VERSIONS 个版本
  if (versions.length > MAX_VERSIONS) {
    versions.splice(0, versions.length - MAX_VERSIONS);
  }

  persistVersionStore(store);
  return version;
}

/**
 * 获取记忆的所有版本历史（摘要列表）
 * @param {string} memoryId
 * @returns {Array<{versionId: string, timestamp: number, changeType: string, diffFromPrev: object|null}>}
 */
export function getMemoryVersions(memoryId) {
  const store = loadVersionStore();
  const data = store[memoryId];
  if (!data) return [];
  return data.versions.map((v) => ({
    versionId: v.versionId,
    timestamp: v.timestamp,
    changeType: v.changeType,
    diffFromPrev: v.diffFromPrev
      ? { addedCount: v.diffFromPrev.addedCount, removedCount: v.diffFromPrev.removedCount }
      : null,
  }));
}

/**
 * 获取指定版本详情
 * @param {string} memoryId
 * @param {string} versionId
 * @returns {object|null}
 */
export function getMemoryVersion(memoryId, versionId) {
  const store = loadVersionStore();
  const data = store[memoryId];
  if (!data) return null;
  return data.versions.find((v) => v.versionId === versionId) || null;
}

/**
 * 恢复到指定版本
 * @param {string} memoryId
 * @param {string} versionId
 * @returns {{ success: boolean, restoredTo?: object, error?: string }}
 */
export function restoreMemoryVersion(memoryId, versionId) {
  const memories = getAllMemoriesRaw();
  const memIdx = memories.findIndex((m) => m.id === memoryId);
  if (memIdx === -1) {
    return { success: false, error: `Memory ${memoryId} not found` };
  }

  const store = loadVersionStore();
  const data = store[memoryId];
  if (!data) {
    return { success: false, error: `No version history for ${memoryId}` };
  }

  const version = data.versions.find((v) => v.versionId === versionId);
  if (!version) {
    return { success: false, error: `Version ${versionId} not found` };
  }

  const oldMemory = { ...memories[memIdx] };

  // 用旧版本内容覆盖当前记忆
  const restoredMemory = {
    ...memories[memIdx],
    ...version.content,
    updated_at: Date.now(),
  };
  memories[memIdx] = restoredMemory;
  saveMemories(memories);

  // 在版本历史中记录本次恢复操作
  createMemoryVersion(memoryId, restoredMemory, oldMemory, 'restore');

  return {
    success: true,
    restoredTo: { versionId: version.versionId, timestamp: version.timestamp },
    changeType: version.changeType,
  };
}

/**
 * 获取版本统计
 * @returns {{ totalVersions: number, totalMemories: number, memoryCounts: object }}
 */
export function getVersionStats() {
  const store = loadVersionStore();
  let totalVersions = 0;
  const counts = {};
  for (const [memoryId, data] of Object.entries(store)) {
    counts[memoryId] = data.versions.length;
    totalVersions += data.versions.length;
  }
  return {
    totalVersions,
    totalMemories: Object.keys(store).length,
    memoryCounts: counts,
  };
}

/**
 * 比较两个版本的差异
 * @param {string} memoryId
 * @param {string} versionId1
 * @param {string} versionId2
 * @returns {object}
 */
export function compareMemoryVersions(memoryId, versionId1, versionId2) {
  const v1 = getMemoryVersion(memoryId, versionId1);
  const v2 = getMemoryVersion(memoryId, versionId2);
  if (!v1 || !v2) {
    throw new Error('One or both versions not found');
  }
  const diff = computeDiff(v1.content, v2.content);
  return {
    memoryId,
    fromVersion: { versionId: v1.versionId, timestamp: v1.timestamp },
    toVersion: { versionId: v2.versionId, timestamp: v2.timestamp },
    diff,
  };
}

/**
 * 获取版本总数
 * @param {string} memoryId
 * @returns {number}
 */
export function getMemoryVersionCount(memoryId) {
  const store = loadVersionStore();
  return store[memoryId]?.versions.length || 0;
}

export default {
  loadMemories,
  saveMemories,
  getAllMemories,
  invalidateCache,
  addMemory,
  deleteMemory,
  forget,
  getMemory,
  updateMemory,
  touchMemory,
  // v2.7.0 版本历史
  getMemoryVersions,
  getMemoryVersion,
  restoreMemoryVersion,
  getVersionStats,
  compareMemoryVersions,
  getMemoryVersionCount,
  loadVersionStore,
};
/**
 * Storage Concurrency Lock + WAL Integration v2.0
 * 文件锁机制：flock-style write lock，防止并发写冲突
 * WAL机制：每次写操作先记日志再应用，支持crash恢复
 *
 * v2.0 升级：
 * - flock 文件锁（多进程安全，进程退出/crash自动释放）
 * - WAL fsync 确保落盘
 * - WAL 同步写 walWriteSync()
 * - 脏读检测 checkVersion()
 * - PID 竞态检测（启动时检查 storage.lock）
 */

import * as fs from 'fs';
import { writeFileSync, readFileSync, existsSync, unlinkSync, renameSync, mkdirSync, openSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { execSync, spawn } from 'child_process';

const __dirname = dirname(fileURLToPath(import.meta.url));
const LOCK_FILE_SUFFIX = '.lock';
const WAL_DIR = join(__dirname, '..', 'wal');
const STORAGE_LOCK_FILE = join(process.env.HOME || '/root', '.unified-memory', 'storage.lock');

// ─── PID 竞态检测 ──────────────────────────────────────────────────────────

/**
 * 检查 PID 进程是否还在运行
 * @param {number} pid
 * @returns {boolean}
 */
function isPidAlive(pid) {
  try {
    execSync(`kill -0 ${pid} 2>/dev/null`, { stdio: 'ignore' });
    return true;
  } catch {
    return false;
  }
}

/**
 * 初始化 PID 竞态检测（flock-based, atomic）
 * 使用 flock 尝试获取 storage.lock 的独占锁。
 * 如果锁被占用（另一个进程持有），检测到并退出。
 * 如果获取成功，立即释放（只做检测，不需要持有）。
 */
function initPidLock() {
  const dir = dirname(STORAGE_LOCK_FILE);
  if (!existsSync(dir)) {
    mkdirSync(dir, { recursive: true });
  }

  // Use flock -n (non-blocking) to try to acquire lock without waiting
  // If we get the lock immediately, it means no other process holds it
  // If we can't get it, another process is running
  const flockResult = execSync(
    `flock -x -n "${STORAGE_LOCK_FILE}" -c "echo $$" 2>/dev/null`,
    { stdio: 'pipe', timeout: 5 }
  );
  
  if (flockResult?.status === 0) {
    // We got the lock - another process was holding it, we're the duplicate
    try {
      execSync(`flock -x -w 1 "${STORAGE_LOCK_FILE}" -c "echo locked"`, { stdio: 'ignore', timeout: 2 });
    } catch { /* timeout, lock still held */ }
    console.error(`[storage_lock] FATAL: Another process is holding storage.lock. Exiting.`);
    console.error(`[storage_lock] If no other instance is running, delete ${STORAGE_LOCK_FILE}`);
    process.exit(1);
  }
  
  // We got the lock immediately - we're the first instance, keep it
  // Write PID for debugging (flock handles the real locking)
  writeFileSync(STORAGE_LOCK_FILE, JSON.stringify({ pid: process.pid, ts: Date.now() }), 'utf8');
}

/**
 * 释放 PID 锁（正常退出时调用）
 */
function releasePidLock() {
  try {
    if (existsSync(STORAGE_LOCK_FILE)) {
      const data = JSON.parse(readFileSync(STORAGE_LOCK_FILE, 'utf8'));
      if (data.pid === process.pid) {
        unlinkSync(STORAGE_LOCK_FILE);
      }
    }
  } catch { /* ignore */ }
}

// 启动时注册 PID 锁
initPidLock();

// 正常退出时释放锁（process.on('exit') 同步执行）
process.on('exit', () => {
  releasePidLock();
});

// ─── flock 文件锁实现（进程级） ────────────────────────────────────────────

const LOCK_TIMEOUT_MS = 30_000; // 30 秒锁超时

/**
 * 同步获取文件锁（真正的多进程安全 flock 锁）
 * 使用 flock -x 阻塞等待，超时则抛错
 * P1-7: flock(1) provides atomic exclusive lock acquisition.
 * Lock is automatically released when process exits (crash-safe).
 * @param {string} filePath
 * @param {number} timeoutMs
 */
export function acquireLockSync(filePath, timeoutMs = LOCK_TIMEOUT_MS) {
  const lockPath = filePath + LOCK_FILE_SUFFIX;

  // flock -x: 阻塞直到获取锁（或超时）
  // flock 在进程退出时自动释放锁（即使 crash）
  try {
    execSync(`flock -x -w ${Math.ceil(timeoutMs / 1000)} "${lockPath}" -c "echo locked"`, {
      stdio: 'ignore',
      timeout: timeoutMs / 1000 + 1,
    });
  } catch (e) {
    if (e.status === 127) {
      throw new Error(`[storage_lock] flock command not found`);
    }
    // flock 超时（exit code 1）或失败
    throw new Error(`[storage_lock] Lock timeout for ${filePath} after ${timeoutMs}ms`);
  }

  // 锁已获取，写入 PID 记录（调试用，flock 本身已保证原子性）
  writeFileSync(lockPath, JSON.stringify({ pid: process.pid, ts: Date.now() }), 'utf8');
}

/**
 * 同步释放文件锁
 * @param {string} filePath
 */
export function releaseLockSync(filePath) {
  const lockPath = filePath + LOCK_FILE_SUFFIX;
  try {
    if (existsSync(lockPath)) {
      const data = JSON.parse(readFileSync(lockPath, 'utf8'));
      if (data.pid === process.pid) {
        unlinkSync(lockPath);
      }
    }
  } catch { /* ignore */ }
}

/**
 * flock 同步锁（阻塞式，多进程安全）
 * @param {string} filePath
 * @param {number} timeoutMs
 */
export function flockSync(filePath, timeoutMs = LOCK_TIMEOUT_MS) {
  const lockPath = filePath + LOCK_FILE_SUFFIX;

  // 使用 flock -w timeout 获取独占锁（阻塞直到获得或超时）
  try {
    execSync(`flock -x -w ${Math.ceil(timeoutMs / 1000)} "${lockPath}" -c "echo locked"`, {
      stdio: 'ignore',
      timeout: Math.ceil(timeoutMs / 1000) + 1,
    });
  } catch (e) {
    if (e.status === 127) {
      throw new Error(`[storage_lock] flock command not found`);
    }
    throw new Error(`[storage_lock] flockSync timeout for ${filePath} after ${timeoutMs}ms`);
  }

  // 写入 PID 信息（供调试/手动清理）
  writeFileSync(lockPath, JSON.stringify({ pid: process.pid, ts: Date.now() }), 'utf8');
}

function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

// ─── WAL 集成 ──────────────────────────────────────────────────────────────

let walFd = null;
let walRunId = null;
let walPath = null;

function ensureWalDir() {
  if (!existsSync(WAL_DIR)) mkdirSync(WAL_DIR, { recursive: true });
}

/**
 * 初始化 WAL 存储
 * @param {string} [runId]
 */
export function initWalStorage(runId) {
  ensureWalDir();
  walRunId = runId || `store-${Date.now()}`;
  walPath = join(WAL_DIR, `${walRunId}.wal.jsonl`);
  walFd = openSync(walPath, 'a');
  // Cleanup: delete all other WAL files older than current runId (crash recovery only needs the latest)
  try {
    const currentBase = walRunId;
    for (const f of readdirSync(WAL_DIR)) {
      if (f.endsWith('.wal.jsonl') && !f.startsWith(currentBase)) {
        unlinkSync(join(WAL_DIR, f));
      }
    }
  } catch { /* cleanup errors non-fatal */ }
}

/**
 * 记录写操作到 WAL（异步，不保证 fsync）
 * @param {object} op
 */
export function logWriteOp(op) {
  if (!walFd) return;
  const entry = JSON.stringify({ ...op, ts: Date.now() }) + '\n';
  const buf = Buffer.from(entry, 'utf8');
  fs.writeSync(walFd, buf);
}

/**
 * 记录写操作到 WAL（同步版本，fsync 确保落盘）
 * @param {object} op
 */
export function walWriteSync(op) {
  if (!walFd) return;
  const entry = JSON.stringify({ ...op, ts: Date.now() }) + '\n';
  const buf = Buffer.from(entry, 'utf8');
  fs.writeSync(walFd, buf);
  // 确保数据落盘（fsync）
  fs.fsyncSync(walFd);
}

/**
 * 获取当前 WAL 文件描述符
 */
export function getWalFd() {
  return walFd;
}

/**
 * 获取 WAL 目录
 */
export function getWalDir() {
  return WAL_DIR;
}

// ─── 脏读检测 ──────────────────────────────────────────────────────────────

// 记录每个 memory 的期望版本（由 withLock 调用方设置）
const expectedVersions = new Map();

/**
 * 设置期望的 memory 版本（脏读检测用）
 * @param {string} memoryId
 * @param {number} version
 */
export function setExpectedVersion(memoryId, version) {
  expectedVersions.set(memoryId, version);
}

/**
 * 检查 memory 版本是否符合预期
 * 如果 version 不符合预期，记录 warning 但不阻塞
 * @param {string} memoryId
 * @param {number} expectedVersion
 * @param {object} memory - 被读取的 memory 对象
 * @returns {boolean} true=版本一致，false=脏读
 */
export function checkVersion(memoryId, expectedVersion, memory) {
  if (!memory || memory.version === undefined) return true;

  const actual = memory.version;
  if (actual !== expectedVersion) {
    console.warn(`[storage_lock] ⚠️ 脏读检测: memory "${memoryId}" expected version ${expectedVersion}, got ${actual}`);
    return false;
  }
  return true;
}

/**
 * 获取期望版本
 * @param {string} memoryId
 * @returns {number|undefined}
 */
export function getExpectedVersion(memoryId) {
  return expectedVersions.get(memoryId);
}

/**
 * 清除期望版本
 * @param {string} memoryId
 */
export function clearExpectedVersion(memoryId) {
  expectedVersions.delete(memoryId);
}

// ─── 原子写入 ──────────────────────────────────────────────────────────────

/**
 * 原子保存（锁 + WAL + rename）
 * @param {string} filePath
 * @param {string} data
 * @param {object|null} walOp
 */
export async function atomicSave(filePath, data, walOp = null) {
  await acquireLock(filePath);
  try {
    if (walOp) walWriteSync(walOp); // 使用同步版本确保 fsync
    const tmpPath = `${filePath}.tmp.${process.pid}`;
    writeFileSync(tmpPath, data, 'utf8');
    renameSync(tmpPath, filePath);
  } finally {
    releaseLock(filePath);
  }
}

// ─── WAL Recovery ──────────────────────────────────────────────────────────

/**
 * 从 WAL 文件恢复数据
 * 读取 wal/*.wal.jsonl，按时间顺序重放 add/delete 操作
 * @param {string[]} walFiles - WAL 文件列表
 * @param {string} targetFile - 目标数据文件路径
 * @param {object[]} memories - 当前内存中的数据
 * @returns {object[]} 恢复后的 memories
 */
export function recoverFromWAL(walFiles, targetFile, memories) {
  const memMap = new Map(memories.map(m => [m.id, m]));

  for (const walFile of walFiles) {
    try {
      const lines = readFileSync(join(WAL_DIR, walFile), 'utf8')
        .trim().split('\n').filter(Boolean);

      for (const line of lines) {
        const op = JSON.parse(line);
        const { type, memory, memory_id: delId } = op;

        if (type === 'add' && memory) {
          memMap.set(memory.id, memory);
        } else if (type === 'delete' && delId) {
          memMap.delete(delId);
        }
      }
    } catch { /* skip corrupted WAL files */ }
  }

  return Array.from(memMap.values());
}
/**
 * SQLite Storage Backend for unified-memory
 * Uses better-sqlite3 (synchronous API, ideal for embedded/CLI use)
 * Implements the same interface as JSON storage: readMemories / writeMemories / appendMemory
 * Supports concurrent writes via WAL mode
 * 
 * P0-2: Optimistic locking via version field on all write operations.
 * Storage path: ~/.unified-memory/memories.db
 * Env: STORAGE_MODE=json|sqlite (default: json)
 */

import { createRequire } from 'module';
import { existsSync, mkdirSync } from 'fs';
import { join } from 'path';
import os from 'os';

// Load better-sqlite3 via createRequire (available globally from @tobilu/qmd dependency)
const req = createRequire(import.meta.url);
let Database;
try {
  Database = req('better-sqlite3');
} catch {
  // Try global path fallback
  try {
    Database = req('/usr/local/lib/node_modules/@tobilu/qmd/node_modules/better-sqlite3');
  } catch {
    Database = null;
  }
}

const DB_PATH = join(os.homedir(), '.unified-memory', 'memories.db');

// Lazy-initialized database handle
let _db = null;

function getDb() {
  if (_db) return _db;

  if (!Database) {
    throw new Error('[storage_sqlite] better-sqlite3 not available. Install it or ensure it is in NODE_PATH.');
  }

  const dir = join(os.homedir(), '.unified-memory');
  if (!existsSync(dir)) {
    mkdirSync(dir, { recursive: true });
  }

  _db = new Database(DB_PATH);

  // Enable WAL mode for better concurrent write performance
  _db.pragma('journal_mode = WAL');
  _db.pragma('synchronous = NORMAL');
  _db.pragma('foreign_keys = ON');

  // Create schema — v2 adds `version` column for optimistic locking
  _db.exec(`
    CREATE TABLE IF NOT EXISTS memories (
      id          TEXT PRIMARY KEY,
      text        TEXT NOT NULL,
      category    TEXT NOT NULL DEFAULT 'general',
      importance  REAL NOT NULL DEFAULT 0.5,
      tags        TEXT NOT NULL DEFAULT '[]',
      scope       TEXT NOT NULL DEFAULT 'USER',
      pinned      INTEGER NOT NULL DEFAULT 0,
      pinned_at   INTEGER,
      pinned_reason TEXT,
      created_at  INTEGER NOT NULL,
      updated_at  INTEGER NOT NULL,
      access_count INTEGER NOT NULL DEFAULT 0,
      last_access INTEGER,
      embedding   TEXT,
      agent_id    TEXT,
      source      TEXT DEFAULT 'manual',
      version     INTEGER NOT NULL DEFAULT 0
    );

    CREATE INDEX IF NOT EXISTS idx_memories_category ON memories(category);
    CREATE INDEX IF NOT EXISTS idx_memories_importance ON memories(importance);
    CREATE INDEX IF NOT EXISTS idx_memories_created_at ON memories(created_at);
    CREATE INDEX IF NOT EXISTS idx_memories_scope ON memories(scope);
    CREATE INDEX IF NOT EXISTS idx_memories_pinned ON memories(pinned);
  `);

  // Migrate: add version column if it doesn't exist (existing DBs before v2)
  try {
    _db.exec("ALTER TABLE memories ADD COLUMN version INTEGER NOT NULL DEFAULT 0");
  } catch {
    // Column already exists — ignore
  }

  return _db;
}

// ============================================================
// Public API — mirrors JSON storage interface
// ============================================================

/**
 * Read all memories from SQLite
 * @returns {Array} memories
 */
export function readMemories() {
  const db = getDb();
  const rows = db.prepare(`
    SELECT id, text, category, importance, tags, scope, pinned, pinned_at,
           pinned_reason, created_at, updated_at, access_count, last_access,
           embedding, agent_id, source, version
    FROM memories
    ORDER BY created_at ASC
  `).all();

  return rows.map(rowToMemory);
}

/**
 * Write ALL memories (full overwrite — replaces entire table)
 * Used by saveMemories() to do atomic full-sync writes
 * @param {Array} memories
 */
export function writeMemories(memories) {
  const db = getDb();

  // Use transaction for atomicity
  const writeTx = db.transaction(() => {
    // Clear existing
    db.prepare('DELETE FROM memories').run();

    if (memories.length === 0) return;

    const insert = db.prepare(`
      INSERT INTO memories (
        id, text, category, importance, tags, scope, pinned, pinned_at,
        pinned_reason, created_at, updated_at, access_count, last_access,
        embedding, agent_id, source, version
      ) VALUES (
        @id, @text, @category, @importance, @tags, @scope, @pinned, @pinned_at,
        @pinned_reason, @created_at, @updated_at, @access_count, @last_access,
        @embedding, @agent_id, @source, @version
      )
    `);

    for (const mem of memories) {
      insert.run(memoryToRow(mem));
    }
  });

  writeTx();
}

/**
 * Append a single memory to SQLite (insert-only, used for real-time adds)
 * @param {object} mem - memory object
 * @returns {object} the inserted memory
 */
export function appendMemory(mem) {
  const db = getDb();
  const insert = db.prepare(`
    INSERT INTO memories (
      id, text, category, importance, tags, scope, pinned, pinned_at,
      pinned_reason, created_at, updated_at, access_count, last_access,
      embedding, agent_id, source, version
    ) VALUES (
      @id, @text, @category, @importance, @tags, @scope, @pinned, @pinned_at,
      @pinned_reason, @created_at, @updated_at, @access_count, @last_access,
      @embedding, @agent_id, @source, @version
    )
  `);

  insert.run(memoryToRow(mem));
  return mem;
}

/**
 * Update a memory by id (standard — no version check)
 * @param {string} id
 * @param {object} updates - partial memory fields
 * @returns {boolean} success
 */
export function updateMemoryById(id, updates) {
  const db = getDb();

  // Build dynamic SET clause
  const allowedFields = [
    'text', 'category', 'importance', 'tags', 'scope', 'pinned',
    'pinned_at', 'pinned_reason', 'access_count', 'last_access', 'updated_at', 'embedding'
  ];

  const sets = [];
  const params = { id };

  for (const field of allowedFields) {
    if (field in updates) {
      const colName = fieldToColumn(field);
      sets.push(`${colName} = @${field}`);
      params[field] = field === 'tags' ? JSON.stringify(updates[field])
        : field === 'pinned' ? (updates[field] ? 1 : 0)
        : updates[field];
    }
  }

  if (sets.length === 0) return false;

  params.updated_at = Date.now();
  sets.push('updated_at = @updated_at');

  const sql = `UPDATE memories SET ${sets.join(', ')} WHERE id = @id`;
  const result = db.prepare(sql).run(params);
  return result.changes > 0;
}

/**
 * P0-2: Optimistic-lock update.
 * Updates only if the current version matches expectedVersion.
 * Returns { success: true } on success, or { conflict: true, memory_id, current_version, your_version }.
 * @param {string} id
 * @param {object} updates - partial memory fields
 * @param {number} expectedVersion - the version the caller expects
 * @returns {{ success: boolean } | { conflict: true, memory_id: string, current_version: number, your_version: number }}
 */
export function updateMemoryByIdOptimistic(id, updates, expectedVersion) {
  const db = getDb();

  const allowedFields = [
    'text', 'category', 'importance', 'tags', 'scope', 'pinned',
    'pinned_at', 'pinned_reason', 'access_count', 'last_access', 'embedding'
  ];

  const sets = [];
  const params = { id, expectedVersion };

  for (const field of allowedFields) {
    if (field in updates) {
      const colName = fieldToColumn(field);
      sets.push(`${colName} = @${field}`);
      params[field] = field === 'tags' ? JSON.stringify(updates[field])
        : field === 'pinned' ? (updates[field] ? 1 : 0)
        : updates[field];
    }
  }

  if (sets.length === 0) return { success: false };

  params.updated_at = Date.now();
  sets.push('updated_at = @updated_at');
  sets.push('version = version + 1');

  const sql = `UPDATE memories SET ${sets.join(', ')} WHERE id = @id AND version = @expectedVersion`;
  const result = db.prepare(sql).run(params);

  if (result.changes === 0) {
    // Either row doesn't exist or version mismatch — fetch current version
    const row = db.prepare('SELECT version FROM memories WHERE id = ?').get(id);
    const currentVersion = row ? row.version : null;
    return {
      conflict: true,
      memory_id: id,
      current_version: currentVersion,
      your_version: expectedVersion,
    };
  }

  return { success: true };
}

/**
 * P0-2: Optimistic-lock delete.
 * Deletes only if the current version matches expectedVersion.
 * @param {string} id
 * @param {number} expectedVersion
 * @returns {{ success: boolean } | { conflict: true, memory_id: string, current_version: number, your_version: number }}
 */
export function deleteMemoryByIdOptimistic(id, expectedVersion) {
  const db = getDb();
  const result = db.prepare(
    'DELETE FROM memories WHERE id = ? AND version = ?'
  ).run(id, expectedVersion);

  if (result.changes === 0) {
    const row = db.prepare('SELECT version FROM memories WHERE id = ?').get(id);
    const currentVersion = row ? row.version : null;
    return {
      conflict: true,
      memory_id: id,
      current_version: currentVersion,
      your_version: expectedVersion,
    };
  }

  return { success: true };
}

/**
 * Delete a memory by id (standard — no version check)
 * @param {string} id
 * @returns {boolean} success
 */
export function deleteMemoryById(id) {
  const db = getDb();
  const result = db.prepare('DELETE FROM memories WHERE id = ?').run(id);
  return result.changes > 0;
}

/**
 * Get a single memory by id
 * @param {string} id
 * @returns {object|null}
 */
export function getMemoryById(id) {
  const db = getDb();
  const row = db.prepare('SELECT * FROM memories WHERE id = ?').get(id);
  return row ? rowToMemory(row) : null;
}

/**
 * Touch a memory (increment access_count, update last_access)
 * @param {string} id
 */
export function touchMemoryById(id) {
  const db = getDb();
  db.prepare(`
    UPDATE memories
    SET access_count = access_count + 1, last_access = @now, updated_at = @now
    WHERE id = @id
  `).run({ id, now: Date.now() });
}

/**
 * Get pinned memories
 * @returns {Array}
 */
export function getPinnedMemories() {
  const db = getDb();
  const rows = db.prepare('SELECT * FROM memories WHERE pinned = 1 ORDER BY created_at ASC').all();
  return rows.map(rowToMemory);
}

/**
 * Pin a memory
 * @param {string} id
 * @param {string} reason
 * @returns {boolean}
 */
export function pinMemoryById(id, reason = '') {
  const db = getDb();
  const result = db.prepare(`
    UPDATE memories SET pinned = 1, pinned_at = @now, pinned_reason = @reason, updated_at = @now
    WHERE id = @id
  `).run({ id, now: Date.now(), reason: String(reason).slice(0, 200) });
  return result.changes > 0;
}

/**
 * Unpin a memory
 * @param {string} id
 * @returns {boolean}
 */
export function unpinMemoryById(id) {
  const db = getDb();
  const result = db.prepare(`
    UPDATE memories SET pinned = 0, pinned_at = NULL, pinned_reason = NULL, updated_at = @now
    WHERE id = @id
  `).run({ id, now: Date.now() });
  return result.changes > 0;
}

/**
 * Get memory count
 * @returns {number}
 */
export function getMemoryCount() {
  const db = getDb();
  const row = db.prepare('SELECT COUNT(*) as count FROM memories').get();
  return row.count;
}

/**
 * Get DB path
 * @returns {string}
 */
export function getDbPath() {
  return DB_PATH;
}

/**
 * Close database connection (for graceful shutdown)
 */
export function closeDb() {
  if (_db) {
    _db.close();
    _db = null;
  }
}

// ============================================================
// Internal helpers
// ============================================================

/**
 * Map memory object to SQLite row
 */
function memoryToRow(mem) {
  return {
    id: mem.id,
    text: mem.text || '',
    category: mem.category || 'general',
    importance: mem.importance ?? 0.5,
    tags: JSON.stringify(Array.isArray(mem.tags) ? mem.tags : []),
    scope: mem.scope || 'USER',
    pinned: mem.pinned ? 1 : 0,
    pinned_at: mem.pinnedAt || null,
    pinned_reason: mem.pinnedReason || null,
    created_at: mem.created_at || Date.now(),
    updated_at: mem.updated_at || Date.now(),
    access_count: mem.access_count || 0,
    last_access: mem.last_access || null,
    embedding: mem.embedding ? JSON.stringify(mem.embedding) : null,
    agent_id: mem.agent_id || null,
    source: mem.source || 'manual',
    version: mem.version ?? 0,
  };
}

/**
 * Map SQLite row to memory object
 */
function rowToMemory(row) {
  return {
    id: row.id,
    text: row.text,
    category: row.category,
    importance: row.importance,
    tags: parseTags(row.tags),
    scope: row.scope,
    pinned: row.pinned === 1,
    pinnedAt: row.pinned_at || null,
    pinnedReason: row.pinned_reason || null,
    created_at: row.created_at,
    updated_at: row.updated_at,
    access_count: row.access_count,
    last_access: row.last_access || null,
    ...(row.embedding ? { embedding: JSON.parse(row.embedding) } : {}),
    ...(row.agent_id ? { agent_id: row.agent_id } : {}),
    source: row.source,
    version: row.version ?? 0,
  };
}

/**
 * Parse tags from JSON string or array
 */
function parseTags(tags) {
  if (Array.isArray(tags)) return tags;
  if (typeof tags === 'string') {
    try { return JSON.parse(tags); } catch { return []; }
  }
  return [];
}

/**
 * Map memory field name to column name
 */
function fieldToColumn(field) {
  const map = {
    pinnedAt: 'pinned_at',
    pinnedReason: 'pinned_reason',
    access_count: 'access_count',
    last_access: 'last_access',
    created_at: 'created_at',
    updated_at: 'updated_at',
    agent_id: 'agent_id',
  };
  return map[field] || field;
}

export default {
  readMemories,
  writeMemories,
  appendMemory,
  updateMemoryById,
  updateMemoryByIdOptimistic,
  deleteMemoryById,
  deleteMemoryByIdOptimistic,
  getMemoryById,
  touchMemoryById,
  getPinnedMemories,
  pinMemoryById,
  unpinMemoryById,
  getMemoryCount,
  getDbPath,
  closeDb,
};
/**
 * sync_incremental.js — Cross-device incremental sync for unified-memory
 * P2-2: Incremental Sync
 * 
 * Based on collab/cloud.js infrastructure.
 * - Records every write as a sync_log entry: {op, memory_id, timestamp, checksum}
 * - Push: exports local delta to remote (WebDAV / S3 / local)
 * - Pull: imports remote delta, merges with local (timestamp + checksum conflict resolution)
 * 
 * Storage: ~/.unified-memory/sync/
 */

import { createRequire } from 'module';
import { existsSync, readFileSync, writeFileSync, mkdirSync, appendFileSync, unlinkSync, readdirSync, statSync } from 'fs';
import { join, dirname } from 'path';
import { createHash } from 'crypto';
import { fileURLToPath } from 'url';

const req = createRequire(import.meta.url);
const __dirname = dirname(fileURLToPath(import.meta.url));
const HOME = process.env.HOME || '/root';
const SYNC_DIR = join(HOME, '.unified-memory', 'sync');
const SYNC_LOG_FILE = join(SYNC_DIR, 'sync_log.jsonl');
const SYNC_STATE_FILE = join(SYNC_DIR, 'sync_state.json');
const MEMORY_DIR = join(HOME, '.openclaw', 'workspace', 'memory');

// ============================================================
// Checksum utility
// ============================================================

function checksumMemory(mem) {
  const content = JSON.stringify({
    id: mem.id,
    text: mem.text,
    category: mem.category,
    importance: mem.importance,
    tags: mem.tags,
    scope: mem.scope,
  });
  return createHash('sha256').update(content).digest('hex').slice(0, 16);
}

// ============================================================
// Sync log management
// ============================================================

function ensureSyncDir() {
  if (!existsSync(SYNC_DIR)) {
    mkdirSync(SYNC_DIR, { recursive: true });
  }
}

function loadSyncLog(limit = 1000) {
  ensureSyncDir();
  if (!existsSync(SYNC_LOG_FILE)) return [];
  try {
    const lines = readFileSync(SYNC_LOG_FILE, 'utf-8').split('\n').filter(Boolean);
    return lines.slice(-limit).map(line => {
      try { return JSON.parse(line); } catch { return null; }
    }).filter(Boolean);
  } catch {
    return [];
  }
}

function appendSyncLog(op, memoryId, mem = null) {
  ensureSyncDir();
  const entry = {
    op,           // 'upsert' | 'delete'
    memory_id: memoryId,
    timestamp: Date.now(),
    checksum: mem ? checksumMemory(mem) : null,
  };
  appendFileSync(SYNC_LOG_FILE, JSON.stringify(entry) + '\n', 'utf-8');
  return entry;
}

/**
 * Get last sync timestamp from state file
 */
function getLastSyncTime(scope = 'default') {
  if (!existsSync(SYNC_STATE_FILE)) return null;
  try {
    const state = JSON.parse(readFileSync(SYNC_STATE_FILE, 'utf-8'));
    return state[scope]?.last_sync_at || null;
  } catch {
    return null;
  }
}

/**
 * Update last sync timestamp
 */
function setLastSyncTime(scope, timestamp = Date.now()) {
  ensureSyncDir();
  let state = {};
  if (existsSync(SYNC_STATE_FILE)) {
    try { state = JSON.parse(readFileSync(SYNC_STATE_FILE, 'utf-8')); } catch { /* ignore */ }
  }
  if (!state[scope]) state[scope] = {};
  state[scope].last_sync_at = timestamp;
  writeFileSync(SYNC_STATE_FILE, JSON.stringify(state, null, 2), 'utf-8');
}

// ============================================================
// Storage backends
// ============================================================

/**
 * Local filesystem sync provider (reads from memory store directly)
 */
class LocalSyncProvider {
  constructor(backupPath) {
    this.backupPath = backupPath || join(HOME, '.unified-memory', 'sync_backup');
    this.type = 'local';
  }

  async push(delta, remotePath = 'delta.json') {
    try {
      mkdirSync(this.backupPath, { recursive: true });
      const remoteFull = join(this.backupPath, remotePath);
      writeFileSync(remoteFull, JSON.stringify(delta, null, 2), 'utf-8');
      return { success: true, path: remoteFull };
    } catch (err) {
      return { success: false, error: err.message };
    }
  }

  async pull(remotePath = 'delta.json') {
    try {
      const remoteFull = join(this.backupPath, remotePath);
      if (!existsSync(remoteFull)) return { success: false, error: 'No remote delta found' };
      const data = JSON.parse(readFileSync(remoteFull, 'utf-8'));
      return { success: true, data };
    } catch (err) {
      return { success: false, error: err.message };
    }
  }

  async listDeltas() {
    try {
      if (!existsSync(this.backupPath)) return [];
      const files = readdirSync(this.backupPath).filter(f => f.endsWith('.json'));
      return files.map(f => {
        const stat = statSync(join(this.backupPath, f));
        return { name: f, modified: stat.mtime.toISOString(), size: stat.size };
      });
    } catch {
      return [];
    }
  }
}

/**
 * WebDAV sync provider
 */
class WebDAVSyncProvider {
  constructor(config = {}) {
    this.url = config.url || '';
    this.username = config.username || '';
    this.password = config.password || '';
    this.remotePath = config.path || '/memory_backup';
    this.type = 'webdav';
  }

  async push(delta, remotePath = 'delta.json') {
    try {
      const fullUrl = `${this.url}${this.remotePath}/${remotePath}`;
      const body = JSON.stringify(delta, null, 2);
      const resp = await fetch(fullUrl, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          ...(this.username ? { 'Authorization': `Basic ${Buffer.from(`${this.username}:${this.password}`).toString('base64')}` } : {}),
        },
        body,
        signal: AbortSignal.timeout(30000),
      });
      if (!resp.ok) throw new Error(`WebDAV ${resp.status} ${resp.statusText}`);
      return { success: true, url: fullUrl };
    } catch (err) {
      return { success: false, error: err.message };
    }
  }

  async pull(remotePath = 'delta.json') {
    try {
      const fullUrl = `${this.url}${this.remotePath}/${remotePath}`;
      const resp = await fetch(fullUrl, {
        method: 'GET',
        headers: {
          'Accept': 'application/json',
          ...(this.username ? { 'Authorization': `Basic ${Buffer.from(`${this.username}:${this.password}`).toString('base64')}` } : {}),
        },
        signal: AbortSignal.timeout(30000),
      });
      if (resp.status === 404) return { success: false, error: 'Not found' };
      if (!resp.ok) throw new Error(`WebDAV ${resp.status}`);
      const text = await resp.text();
      return { success: true, data: JSON.parse(text) };
    } catch (err) {
      return { success: false, error: err.message };
    }
  }

  async listDeltas() {
    return []; // WebDAV PROPFIND out of scope
  }
}

// ============================================================
// Merge / conflict resolution
// ============================================================

/**
 * Resolve conflict between local and remote entry.
 * Strategy: latest timestamp wins by default.
 * Optionally use `source` priority: explicit > inferred > historical.
 * @param {object} local
 * @param {object} remote
 * @param {string} strategy - 'timestamp' | 'source_priority'
 */
function resolveConflict(local, remote, strategy = 'timestamp') {
  if (strategy === 'timestamp') {
    return (remote.timestamp || 0) > (local.timestamp || 0) ? remote : local;
  }
  // source_priority: explicit > inferred > historical
  const priority = { explicit: 3, inferred: 2, historical: 1 };
  const remoteP = priority[remote.source] || 0;
  const localP = priority[local.source] || 0;
  if (remoteP !== localP) return remoteP > localP ? remote : local;
  // Same priority: latest timestamp wins
  return (remote.timestamp || 0) > (local.timestamp || 0) ? remote : local;
}

// ============================================================
// Public sync API
// ============================================================

/**
 * Record a sync log entry for a write operation.
 * Call this after every add/update/delete in storage.js.
 * @param {string} op - 'upsert' | 'delete'
 * @param {object} memory - the memory object (for upsert)
 */
export function recordSyncOp(op, memory = null) {
  try {
    const memoryId = memory?.id || null;
    if (!memoryId) return;
    return appendSyncLog(op, memoryId, memory);
  } catch (err) {
    console.error('[sync_incremental] recordSyncOp failed:', err.message);
  }
}

/**
 * Push local delta to remote.
 * Returns { success, delta, stats }
 * @param {object} options
 * @param {string} options.providerType - 'local' | 'webdav'
 * @param {object} options.providerConfig - provider-specific config
 * @param {string} options.scope - sync scope identifier
 */
export async function syncPush({ providerType = 'local', providerConfig = {}, scope = 'default' } = {}) {
  try {
    const provider = providerType === 'webdav'
      ? new WebDAVSyncProvider(providerConfig)
      : new LocalSyncProvider(providerConfig);

    const since = getLastSyncTime(scope);
    const logEntries = loadSyncLog(10000);

    // Build delta: only entries since last sync
    const deltaEntries = since
      ? logEntries.filter(e => e.timestamp > since)
      : logEntries;

    if (deltaEntries.length === 0) {
      setLastSyncTime(scope);
      return { success: true, pushed: 0, message: 'No delta to push' };
    }

    // Attach memory data for upsert entries
    const { getAllMemories } = await import('./storage.js');
    const memories = await getAllMemories();
    const memoryMap = new Map(memories.map(m => [m.id, m]));

    const delta = {
      scope,
      generated_at: Date.now(),
      entries: deltaEntries.map(e => ({
        ...e,
        memory: e.op === 'upsert' ? memoryMap.get(e.memory_id) : null,
      })),
    };

    const remotePath = `delta_${scope}_${Date.now()}.json`;
    const result = await provider.push(delta, remotePath);

    if (result.success) {
      setLastSyncTime(scope);
      return {
        success: true,
        pushed: deltaEntries.length,
        remote_path: result.path || result.url || remotePath,
        delta_id: remotePath,
      };
    } else {
      return { success: false, error: result.error };
    }
  } catch (err) {
    return { success: false, error: err.message };
  }
}

/**
 * Pull remote delta and merge with local.
 * @param {object} options
 * @param {string} options.providerType
 * @param {object} options.providerConfig
 * @param {string} options.remotePath - specific delta file to pull (optional)
 * @param {string} options.scope
 * @param {string} options.conflictStrategy - 'timestamp' | 'source_priority'
 */
export async function syncPull({ providerType = 'local', providerConfig = {}, remotePath, scope = 'default', conflictStrategy = 'timestamp' } = {}) {
  try {
    const provider = providerType === 'webdav'
      ? new WebDAVSyncProvider(providerConfig)
      : new LocalSyncProvider(providerConfig);

    // If remotePath specified, pull that specific delta; otherwise find latest
    let result;
    if (remotePath) {
      result = await provider.pull(remotePath);
    } else {
      // Find latest delta for this scope
      const deltas = await provider.listDeltas();
      const scopeDeltas = deltas.filter(f => f.name.includes(`_${scope}_`)).sort((a, b) =>
        new Date(b.modified) - new Date(a.modified)
      );
      if (scopeDeltas.length === 0) {
        return { success: true, merged: 0, message: 'No remote delta found' };
      }
      result = await provider.pull(scopeDeltas[0].name);
    }

    if (!result.success) {
      return { success: false, error: result.error };
    }

    const { data: delta } = result;
    if (!delta?.entries?.length) {
      return { success: true, merged: 0, message: 'Empty delta' };
    }

    // Load current local memories and sync log
    const { getAllMemories, saveMemories } = await import('./storage.js');
    let localMemories = await getAllMemories();
    const localMap = new Map(localMemories.map(m => [m.id, m]));
    let merged = 0;
    let conflicts = 0;

    for (const entry of delta.entries) {
      const { op, memory_id, timestamp, checksum, memory: remoteMem } = entry;

      if (op === 'upsert' && remoteMem) {
        const local = localMap.get(memory_id);
        if (!local) {
          // New memory from remote — add
          localMemories.push(remoteMem);
          localMap.set(memory_id, remoteMem);
          merged++;
        } else {
          // Conflict resolution
          const localEntry = { timestamp: local.updated_at, source: local.source || 'historical', memory: local };
          const remoteEntry = { timestamp, source: remoteMem.source || 'historical', memory: remoteMem };
          const winner = resolveConflict(localEntry, remoteEntry, conflictStrategy);

          if (winner.memory.id === remoteMem.id) {
            // Remote wins — update local
            const idx = localMemories.findIndex(m => m.id === memory_id);
            if (idx !== -1) localMemories[idx] = remoteMem;
            localMap.set(memory_id, remoteMem);
          }
          conflicts++;
        }
      } else if (op === 'delete') {
        const idx = localMemories.findIndex(m => m.id === memory_id);
        if (idx !== -1) {
          localMemories.splice(idx, 1);
          localMap.delete(memory_id);
          merged++;
        }
      }
    }

    saveMemories(localMemories);
    setLastSyncTime(scope);

    return {
      success: true,
      merged,
      conflicts,
      delta_entries: delta.entries.length,
    };
  } catch (err) {
    return { success: false, error: err.message };
  }
}

/**
 * Get sync status
 */
export function syncStatus({ scope = 'default' } = {}) {
  const lastSync = getLastSyncTime(scope);
  const logEntries = loadSyncLog(10);
  const recentOps = logEntries.slice(-10);

  return {
    scope,
    last_sync_at: lastSync ? new Date(lastSync).toISOString() : null,
    pending_ops: logEntries.filter(e => !lastSync || e.timestamp > lastSync).length,
    recent_ops: recentOps.map(e => ({
      op: e.op,
      memory_id: e.memory_id,
      timestamp: new Date(e.timestamp).toISOString(),
    })),
    sync_log: SYNC_LOG_FILE,
    sync_state: SYNC_STATE_FILE,
  };
}

/**
 * MCP tool: memory_sync
 */
export function memorySyncTool({ action, providerType, providerConfig, remotePath, scope, conflictStrategy, ttlSeconds } = {}) {
  try {
    if (action === 'status') {
      const status = syncStatus({ scope: scope || 'default' });
      return { content: [{ type: 'text', text: JSON.stringify(status, null, 2) }] };
    }

    if (action === 'push') {
      if (providerType === 'webdav' && !providerConfig?.url) {
        return { content: [{ type: 'text', text: '{"error": "webdav provider requires url in providerConfig"}' }], isError: true };
      }
      return syncPush({
        providerType: providerType || 'local',
        providerConfig: providerConfig || {},
        scope: scope || 'default',
      }).then(result => {
        return { content: [{ type: 'text', text: JSON.stringify(result, null, 2) }] };
      }).catch(err => {
        return { content: [{ type: 'text', text: `Sync push error: ${err.message}` }], isError: true };
      });
    }

    if (action === 'pull') {
      return syncPull({
        providerType: providerType || 'local',
        providerConfig: providerConfig || {},
        remotePath,
        scope: scope || 'default',
        conflictStrategy: conflictStrategy || 'timestamp',
      }).then(result => {
        return { content: [{ type: 'text', text: JSON.stringify(result, null, 2) }] };
      }).catch(err => {
        return { content: [{ type: 'text', text: `Sync pull error: ${err.message}` }], isError: true };
      });
    }

    return {
      content: [{ type: 'text', text: '{"error": "Unknown action. Use: status, push, pull"}' }],
      isError: true,
    };
  } catch (err) {
    return { content: [{ type: 'text', text: `Sync error: ${err.message}` }], isError: true };
  }
}

export default {
  recordSyncOp,
  syncPush,
  syncPull,
  syncStatus,
  memorySyncTool,
};
/**
 * sync_watcher.js - File System Watcher for Memory Sync
 * 
 * Watches ~/.openclaw/workspace/memory/memories.json for changes
 * and triggers sync events with debouncing.
 * 
 * Events emitted:
 *   - sync:triggered  { type: 'add'|'change'|'unlink', timestamp, stats }
 *   - sync:conflict   { conflicts, timestamp }
 *   - sync:completed  { synced_peers, timestamp, duration_ms }
 *   - watcher:error   { error }
 */

import { watch } from 'fs';
import { existsSync, readFileSync, statSync } from 'fs';
import { join } from 'path';
import EventEmitter from 'events';
import { getAllMemories } from './storage.js';

const HOME = process.env.HOME || '/root';
const MEMORY_DIR = join(HOME, '.openclaw/workspace/memory');
const MEMORIES_FILE = join(MEMORY_DIR, 'memories.json');

const DEBOUNCE_MS = 2000;
const HEALTH_CHECK_INTERVAL_MS = 30000;

class SyncWatcher extends EventEmitter {
  constructor() {
    super();
    this.watcher = null;
    this.debounceTimer = null;
    this.isRunning = false;
    this.lastStats = null;
    this.healthInterval = null;
    this._computeInitialStats();
  }

  _computeInitialStats() {
    try {
      if (existsSync(MEMORIES_FILE)) {
        const stat = statSync(MEMORIES_FILE);
        const content = readFileSync(MEMORIES_FILE, 'utf-8');
        const mems = JSON.parse(content);
        const arr = Array.isArray(mems) ? mems : (mems.memories || []);
        this.lastStats = {
          mtime: stat.mtimeMs,
          size: stat.size,
          memoryCount: arr.length,
          checksum: simpleChecksum(content)
        };
      }
    } catch { this.lastStats = null; }
  }

  _currentStats() {
    try {
      if (!existsSync(MEMORIES_FILE)) return null;
      const stat = statSync(MEMORIES_FILE);
      const content = readFileSync(MEMORIES_FILE, 'utf-8');
      const mems = JSON.parse(content);
      const arr = Array.isArray(mems) ? mems : (mems.memories || []);
      return {
        mtime: stat.mtimeMs,
        size: stat.size,
        memoryCount: arr.length,
        checksum: simpleChecksum(content)
      };
    } catch { return null; }
  }

  _changed() {
    const curr = this._currentStats();
    if (!curr || !this.lastStats) return { changed: true, type: 'init' };
    if (curr.checksum !== this.lastStats.checksum) {
      if (!this.lastStats) return { changed: true, type: 'init' };
      if (curr.memoryCount > this.lastStats.memoryCount) return { changed: true, type: 'add' };
      if (curr.memoryCount < this.lastStats.memoryCount) return { changed: true, type: 'unlink' };
      return { changed: true, type: 'change' };
    }
    return { changed: false };
  }

  _debouncedTrigger(eventType) {
    if (this.debounceTimer) {
      clearTimeout(this.debounceTimer);
    }
    this.debounceTimer = setTimeout(() => {
      this.debounceTimer = null;
      this._doTrigger(eventType);
    }, DEBOUNCE_MS);
  }

  _doTrigger(eventType) {
    const stats = this._currentStats();
    const change = this._changed();
    this.lastStats = stats;
    this.emit('sync:triggered', {
      type: change.type || eventType,
      timestamp: new Date().toISOString(),
      stats: {
        memoryCount: stats?.memoryCount || 0,
        size: stats?.size || 0
      }
    });
  }

  start() {
    if (this.isRunning) return;
    if (!existsSync(MEMORIES_FILE)) {
      this.emit('watcher:error', { error: `Memory file not found: ${MEMORIES_FILE}` });
      return;
    }

    this.isRunning = true;
    this._computeInitialStats();

    try {
      this.watcher = watch(MEMORIES_FILE, (eventType) => {
        if (eventType === 'change' || eventType === 'rename') {
          this._debouncedTrigger(eventType);
        }
      });
    } catch (err) {
      this.emit('watcher:error', { error: err.message });
      return;
    }

    this.healthInterval = setInterval(() => {
      if (!existsSync(MEMORIES_FILE) && this.isRunning) {
        this.emit('watcher:error', { error: 'Memory file deleted or moved' });
        this.stop();
      }
    }, HEALTH_CHECK_INTERVAL_MS);
  }

  stop() {
    if (this.debounceTimer) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = null;
    }
    if (this.healthInterval) {
      clearInterval(this.healthInterval);
      this.healthInterval = null;
    }
    if (this.watcher) {
      try { this.watcher.close(); } catch { /* ignore */ }
      this.watcher = null;
    }
    this.isRunning = false;
  }

  forceSync() {
    this._computeInitialStats();
    this._doTrigger('force');
  }

  getStatus() {
    return {
      running: this.isRunning,
      watching: MEMORIES_FILE,
      debounce_ms: DEBOUNCE_MS,
      last_stats: this.lastStats
    };
  }
}

function simpleChecksum(content) {
  let hash = 0;
  for (let i = 0; i < Math.min(content.length, 4096); i++) {
    hash = ((hash << 5) - hash + content.charCodeAt(i)) | 0;
  }
  return hash.toString(16);
}

// Singleton instance
let _watcherInstance = null;

export function getSyncWatcher() {
  if (!_watcherInstance) {
    _watcherInstance = new SyncWatcher();
  }
  return _watcherInstance;
}

export function startSyncWatcher() {
  const watcher = getSyncWatcher();
  watcher.start();
  return watcher;
}

export function stopSyncWatcher() {
  if (_watcherInstance) {
    _watcherInstance.stop();
  }
}

export { SyncWatcher };
export default { getSyncWatcher, startSyncWatcher, stopSyncWatcher, SyncWatcher };
/**
 * task_hierarchy.js - Task Hierarchy for Working Memory
 * 
 * Supports task trees (parent → subtasks).
 * When parent task is completed/cleared, subtasks are auto-held.
 * Cross-references with episodic memory (sessions/conversations).
 */

import {
  loadWorkingMemories,
  saveWorkingMemories,
  persistWorkingMemories,
  WorkingMemoryStatus,
  formatWorkingMemory,
} from './working_memory.js';
import { config } from './config.js';

// ============================================================================
// Task Hierarchy
// ============================================================================

/**
 * Build the task tree from working memories
 * @returns {{roots: object[], tree: Map<string, object[]>}}
 */
export function buildTaskTree() {
  const memories = loadWorkingMemories().filter(
    wm => wm.status !== WorkingMemoryStatus.CLEARED
  );

  const tree = new Map(); // parentId → children[]
  const roots = [];

  for (const wm of memories) {
    if (!wm.parentTaskId || wm.status === WorkingMemoryStatus.CLEARED) {
      roots.push(wm);
    }
  }

  // Build children map
  for (const wm of memories) {
    if (wm.parentTaskId) {
      if (!tree.has(wm.parentTaskId)) {
        tree.set(wm.parentTaskId, []);
      }
      tree.get(wm.parentTaskId).push(wm);
    }
  }

  return { roots, tree };
}

/**
 * Get subtasks of a working memory
 * @param {string} workingMemoryId
 * @returns {object[]}
 */
export function getSubtasks(workingMemoryId) {
  const memories = loadWorkingMemories();
  const wm = memories.find(w => w.id === workingMemoryId);

  if (!wm) return [];

  return (wm.subtaskIds || [])
    .map(id => memories.find(w => w.id === id))
    .filter(Boolean)
    .map(formatWorkingMemory);
}

/**
 * Add a subtask to a working memory
 * @param {string} parentId - Parent working memory ID
 * @param {string} childId - Child working memory ID
 * @returns {{success: boolean, error: string|null}}
 */
export function addSubtask(parentId, childId) {
  const memories = loadWorkingMemories();
  const parent = memories.find(w => w.id === parentId);
  const child = memories.find(w => w.id === childId);

  if (!parent) return { success: false, error: 'Parent working memory not found' };
  if (!child) return { success: false, error: 'Child working memory not found' };

  if (!parent.subtaskIds) parent.subtaskIds = [];
  if (!parent.subtaskIds.includes(childId)) {
    parent.subtaskIds.push(childId);
  }

  child.parentTaskId = parentId;
  persistWorkingMemories(memories);

  return { success: true, error: null };
}

/**
 * Remove a subtask from a parent
 * @param {string} parentId
 * @param {string} childId
 * @returns {{success: boolean}}
 */
export function removeSubtask(parentId, childId) {
  const memories = loadWorkingMemories();
  const parent = memories.find(w => w.id === parentId);
  const child = memories.find(w => w.id === childId);

  if (parent && parent.subtaskIds) {
    parent.subtaskIds = parent.subtaskIds.filter(id => id !== childId);
  }
  if (child) {
    child.parentTaskId = null;
  }

  persistWorkingMemories(memories);
  return { success: true };
}

/**
 * Complete a parent task and auto-hold all its subtasks
 * @param {string} workingMemoryId
 * @param {string} [reason]
 * @returns {{parent: object, subtasksHeld: number, error: string|null}}
 */
export function completeTask(workingMemoryId, reason = 'parent_completed') {
  const memories = loadWorkingMemories();
  const wm = memories.find(w => w.id === workingMemoryId);

  if (!wm) return { parent: null, subtasksHeld: 0, error: 'Working memory not found' };

  let subtasksHeld = 0;

  // Auto-hold all active subtasks
  if (wm.subtaskIds && wm.subtaskIds.length > 0) {
    for (const subtaskId of wm.subtaskIds) {
      const subtask = memories.find(w => w.id === subtaskId);
      if (subtask && subtask.status === WorkingMemoryStatus.ACTIVE) {
        subtask.status = WorkingMemoryStatus.HELD;
        subtask.heldAt = Date.now();
        subtask.heldReason = reason;
        subtask.updatedAt = Date.now();
        subtasksHeld++;
      }
    }
  }

  persistWorkingMemories(memories);

  return {
    parent: formatWorkingMemory(wm),
    subtasksHeld,
    error: null,
  };
}

/**
 * Get the full ancestry chain (root → ... → parent → current)
 * @param {string} workingMemoryId
 * @returns {object[]}
 */
export function getAncestry(workingMemoryId) {
  const memories = loadWorkingMemories();
  const chain = [];
  let current = memories.find(w => w.id === workingMemoryId);

  while (current) {
    chain.unshift(formatWorkingMemory(current));
    if (!current.parentTaskId) break;
    current = memories.find(w => w.taskId === current.parentTaskId);
  }

  return chain;
}

/**
 * Get all descendant working memories
 * @param {string} workingMemoryId
 * @returns {object[]}
 */
export function getDescendants(workingMemoryId) {
  const memories = loadWorkingMemories();
  const wm = memories.find(w => w.id === workingMemoryId);
  if (!wm || !wm.subtaskIds || wm.subtaskIds.length === 0) return [];

  const descendants = [];
  const queue = [...wm.subtaskIds];

  while (queue.length > 0) {
    const id = queue.shift();
    const child = memories.find(w => w.id === id);
    if (child) {
      descendants.push(formatWorkingMemory(child));
      if (child.subtaskIds) {
        queue.push(...child.subtaskIds);
      }
    }
  }

  return descendants;
}

/**
 * Link a working memory to an episode (session/conversation)
 * @param {string} workingMemoryId
 * @param {string} episodeId
 * @returns {{success: boolean}}
 */
export function linkToEpisode(workingMemoryId, episodeId) {
  const memories = loadWorkingMemories();
  const wm = memories.find(w => w.id === workingMemoryId);

  if (!wm) return { success: false };

  wm.episodeId = episodeId;
  wm.updatedAt = Date.now();
  persistWorkingMemories(memories);

  return { success: true };
}

/**
 * Get working memories linked to a specific episode
 * @param {string} episodeId
 * @returns {object[]}
 */
export function getWorkingMemoriesByEpisode(episodeId) {
  const memories = loadWorkingMemories();
  return memories
    .filter(wm => wm.episodeId === episodeId && wm.status !== WorkingMemoryStatus.CLEARED)
    .map(formatWorkingMemory);
}

/**
 * Check if a working memory has active subtasks
 * @param {string} workingMemoryId
 * @returns {{hasActiveSubtasks: boolean, activeSubtaskCount: number}}
 */
export function hasActiveSubtasks(workingMemoryId) {
  const memories = loadWorkingMemories();
  const wm = memories.find(w => w.id === workingMemoryId);

  if (!wm || !wm.subtaskIds || wm.subtaskIds.length === 0) {
    return { hasActiveSubtasks: false, activeSubtaskCount: 0 };
  }

  const activeSubtasks = wm.subtaskIds
    .map(id => memories.find(w => w.id === id))
    .filter(child => child && child.status === WorkingMemoryStatus.ACTIVE);

  return {
    hasActiveSubtasks: activeSubtasks.length > 0,
    activeSubtaskCount: activeSubtasks.length,
  };
}

/**
 * Get task tree visualization
 * @returns {string}
 */
export function visualizeTaskTree() {
  const { roots, tree } = buildTaskTree();
  const lines = ['Task Hierarchy'];

  function render(wm, indent = 0) {
    const prefix = '  '.repeat(indent);
    const statusIcon = wm.status === WorkingMemoryStatus.ACTIVE ? '●' :
                       wm.status === WorkingMemoryStatus.HELD ? '○' : '✗';
    lines.push(`${prefix}${statusIcon} [${wm.taskId}] ${wm.description}`);
    
    const children = tree.get(wm.taskId) || [];
    for (const child of children) {
      render(child, indent + 1);
    }
  }

  for (const root of roots) {
    render(root);
  }

  return lines.join('\n');
}
