    id: String(id),
    text: `Memory ${id}`,
    category: 'general',
    importance: importance ?? 0.5,
    created_at: now - daysAgo * DAY_MS,
    timestamp: now - daysAgo * DAY_MS,
    last_access: now - (lastAccessDaysAgo ?? daysAgo) * DAY_MS,
