/**
 * Tier Manager - HOT(7d) / WARM(7-30d) / COLD(>30d) 三层架构
 * Automatic tier assignment and redistribution
 */
import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join } from 'path';
import { config } from './config.js';
import { getAllMemories, saveMemories, forget as storageForget } from './storage.js';

export const TIER_CONFIG = {
  HOT: { maxAgeDays: 7, compress: false, priority: 3 },
  WARM: { maxAgeDays: 30, compress: false, priority: 2 },
  COLD: { maxAgeDays: Infinity, compress: true, priority: 1 },
};

const DAY_MS = 86400000;

function parseTimestamp(memory) {
  const raw = memory.timestamp || memory.created_at || memory.createdAt || Date.now();
  // Handle ISO string format from Python
  if (typeof raw === 'string') return new Date(raw).getTime();
  return raw;
}

function getTier(memory, now = Date.now()) {
  const ts = parseTimestamp(memory);
  const age = now - ts;
  const ageDays = age / DAY_MS;
  if (ageDays <= TIER_CONFIG.HOT.maxAgeDays) return 'HOT';
  if (ageDays <= TIER_CONFIG.WARM.maxAgeDays) return 'WARM';
  return 'COLD';
}

/**
 * Assign tier to each memory
 * @param {Array} memories
 * @returns {Array} memories with .tier field added
 */
export function assignTiers(memories, now = Date.now()) {
  return memories.map(m => ({ ...m, tier: getTier(m, now) }));
}

/**
 * Partition memories by tier
 * @param {Array} memories
 * @returns {{ HOT: Array, WARM: Array, COLD: Array }}
 */
export function partitionByTier(memories) {
  const tiers = { HOT: [], WARM: [], COLD: [] };
  for (const m of assignTiers(memories)) {
    tiers[m.tier].push(m);
  }
  return tiers;
}

/**
 * Redistribute all memories across tiers (full re-tier)
 * @param {Array} memories
 * @returns {Array}
 */
export function redistributeTiers(memories) {
  return assignTiers(memories);
}

/**
 * Compress cold tier memories (summarize / drop details)
 * Uses summarization to reduce storage while keeping essential meaning.
 * @param {Array} coldMemories
 * @returns {Array}
 */
export function compressColdTier(coldMemories) {
  return coldMemories.map(m => {
    // Pinned memories — skip compression entirely
    if (m.pinned) return m;
    // Already compressed — skip
    if (m.compressed) return m;

    const text = m.text || '';
    // Keep first 200 chars as rough summary
    const summary = text.length > 200 ? text.slice(0, 200) : text;

    return {
      ...m,
      compressed: true,
      original_length: text.length,
      // Keep essential fields
      id: m.id,
      text: summary,
      category: m.category,
      importance: m.importance,
      tags: m.tags || [],
      scope: m.scope,
      timestamp: m.timestamp,
      created_at: m.created_at,
      tier: 'COLD',
      // Drop heavy fields to save space
      embedding: undefined,
      last_access: undefined,
    };
  });
}

/**
 * Automatic tier migration based on access frequency and importance.
 * Heuristics:
 * - HOT → WARM: not accessed in 3+ days and importance < 0.5
 * - HOT → COLD: not accessed in 7+ days and importance < 0.3
 * - WARM → HOT: accessed in last 2 days and importance >= 0.5
 * - WARM → COLD: not accessed in 14+ days
 * - COLD → WARM: accessed in last 7 days and importance >= 0.4
 * - COLD → HOT: accessed in last 2 days and importance >= 0.7
 *
 * @param {Array} memories - All memories
 * @param {{ dryRun?: boolean }} options
 * @returns {{ memories: Array, changes: Array }}
 */
export function autoMigrateTiers(memories, { dryRun = false } = {}) {
  const now = Date.now();
  const DAY_MS = 86400000;
  const changes = [];

  // Work on a copy
  const updated = memories.map(m => ({ ...m }));
  const tierMap = new Map(updated.map(m => [m.id, getTier(m, now)]));

  for (const mem of updated) {
    const currentTier = tierMap.get(mem.id);
    const lastAcc = mem.last_access || mem.lastAccess || mem.timestamp || mem.created_at || mem.createdAt || now;
    const lastAccTs = typeof lastAcc === 'string' ? new Date(lastAcc).getTime() : lastAcc;
    const daysSinceAccess = (now - lastAccTs) / DAY_MS;
    const importance = mem.importance || 0.5;
    let newTier = currentTier;

    // Pinned memories: always stay in HOT, never demote
    if (mem.pinned) newTier = 'HOT';

    if (currentTier === 'HOT') {
      // Demote HOT → WARM or HOT → COLD
      if (daysSinceAccess >= 7 && importance < 0.3) {
        newTier = 'COLD';
      } else if (daysSinceAccess >= 3 && importance < 0.5) {
        newTier = 'WARM';
      }
    } else if (currentTier === 'WARM') {
      // Promote WARM → HOT or demote WARM → COLD
      if (daysSinceAccess <= 2 && importance >= 0.5) {
        newTier = 'HOT';
      } else if (daysSinceAccess >= 14) {
        newTier = 'COLD';
      }
    } else if (currentTier === 'COLD') {
      // Promote COLD → WARM or COLD → HOT
      if (daysSinceAccess <= 2 && importance >= 0.7) {
        newTier = 'HOT';
      } else if (daysSinceAccess <= 7 && importance >= 0.4) {
        newTier = 'WARM';
      }
    }

    if (newTier !== currentTier) {
      const reason = `${currentTier} → ${newTier}: daysSinceAccess=${Math.round(daysSinceAccess * 10) / 10}, importance=${importance}`;
      changes.push({ id: mem.id, fromTier: currentTier, toTier: newTier, reason, memory: mem });
      tierMap.set(mem.id, newTier);
      mem.tier = newTier;
    }
  }

  return { memories: updated, changes };
}

/**
 * Get tier stats
 * @param {Array} memories
 * @returns {{ HOT: number, WARM: number, COLD: number, total: number }}
 */
export function getTierStats(memories) {
  const tiers = partitionByTier(memories);
  return {
    HOT: tiers.HOT.length,
    WARM: tiers.WARM.length,
    COLD: tiers.COLD.length,
    total: memories.length,
  };
}

/**
 * Run lifecycle management — called by proactive_manager every 100 operations.
 * Handles:
 * 1. Archiving COLD memories older than 90 days (export summary to archive/)
 * 2. Forgetting COLD memories with significance < 0.05
 * 3. Forgetting WARM memories with significance < 0.05
 * 4. Natural decay: 30-day inactive memories get significance *= 0.95
 * @returns {{ archived: number, forgotten: number, decayed: number }}
 */
export function runLifecycle() {
  const ARCHIVE_DIR = join(config.memoryDir || process.env.HOME + '/.unified-memory', 'archive');
  const DAY_MS = 86400000;
  const now = Date.now();

  // Ensure archive directory exists
  if (!existsSync(ARCHIVE_DIR)) {
    mkdirSync(ARCHIVE_DIR, { recursive: true });
  }

  const memories = getAllMemories();
  const tiers = partitionByTier(memories);

  let archived = 0;
  let forgotten = 0;
  let decayed = 0;

  // ── 1. Archive + forget COLD memories > 90 days old ──
  const ninetyDaysMs = 90 * DAY_MS;
  for (const mem of tiers.COLD) {
    const created = mem.created_at || mem.timestamp || now;
    if (now - created > ninetyDaysMs) {
      // Archive: save summary to archive directory
      try {
        const archiveFile = join(ARCHIVE_DIR, `${mem.id}.json`);
        const summary = {
          id: mem.id,
          text: mem.text || '',
          summary: mem.text ? mem.text.slice(0, 200) : '',
          category: mem.category,
          importance: mem.importance || 0.5,
          created_at: created,
          archived_at: now,
        };
        writeFileSync(archiveFile, JSON.stringify(summary, null, 2), 'utf8');
        archived++;
      } catch (e) {
        log('WARN', `[runLifecycle] archive failed for ${mem.id}: ${e.message}`);
      }
      // Forget: remove from store + vector cache
      storageForget(mem.id);
      forgotten++;
    }
  }

  // ── 2. Forget COLD memories with significance < 0.05 ──
  for (const mem of tiers.COLD) {
    const created = mem.created_at || mem.timestamp || now;
    if (now - created <= ninetyDaysMs && (mem.importance || 0.5) < 0.05) {
      storageForget(mem.id);
      forgotten++;
    }
  }

  // ── 3. Forget WARM memories with significance < 0.05 ──
  for (const mem of tiers.WARM) {
    if ((mem.importance || 0.5) < 0.05) {
      storageForget(mem.id);
      forgotten++;
    }
  }

  // ── 4. Natural decay: memories not accessed in 30+ days get significance *= 0.95 ──
  const thirtyDaysMs = 30 * DAY_MS;
  for (const mem of memories) {
    const lastAccess = mem.last_access || mem.updated_at || mem.created_at || now;
    if (now - lastAccess > thirtyDaysMs) {
      const currentImportance = mem.importance || 0.5;
      mem.importance = Math.max(0, currentImportance * 0.95);
      decayed++;
    }
  }

  if (decayed > 0) {
    saveMemories(memories);
  }

  log('INFO', `[runLifecycle] archived=${archived} forgotten=${forgotten} decayed=${decayed}`);
  return { archived, forgotten, decayed };
}

export default { TIER_CONFIG, getTier, assignTiers, partitionByTier, redistributeTiers, compressColdTier, getTierStats, runLifecycle, autoMigrateTiers };
/**
 * tier_tools.js - Tier Management MCP Tools
 * memory_tier_status, memory_tier_migrate, memory_tier_compress
 */
import { getAllMemories, saveMemories, deleteMemory } from './storage.js';
import {
  TIER_CONFIG,
  assignTiers,
  partitionByTier,
  redistributeTiers,
  compressColdTier,
  getTierStats,
  autoMigrateTiers,
} from './tier.js';
import { log } from './config.js';

const DAY_MS = 86400000;

/**
 * memory_tier_status - View tier statistics
 */
export async function memoryTierStatusTool() {
  try {
    const memories = await getAllMemories();
    console.error(`[DEBUG] memories=${memories?.length}, type=${typeof memories}`);
    const stats = getTierStats(memories);
    const tiers = partitionByTier(memories);

    // Calculate size by tier (tier already assigned via partitionByTier)
    const sizeByTier = { HOT: 0, WARM: 0, COLD: 0 };
    for (const tierKey of ['HOT', 'WARM', 'COLD']) {
      for (const m of (tiers[tierKey] || [])) {
        const size = Buffer.byteLength(JSON.stringify(m), 'utf8');
        sizeByTier[tierKey] += size;
      }
    }

    // Access stats per tier
    const accessStats = {};
    for (const [tier, configs] of Object.entries(TIER_CONFIG)) {
      const tierMems = tiers[tier] || [];
      const recentAccess = tierMems.filter(m => {
        const lastAcc = m.last_access || m.lastAccess || m.timestamp || m.created_at || m.createdAt || 0;
        const ts = typeof lastAcc === 'string' ? new Date(lastAcc).getTime() : lastAcc;
        return (Date.now() - ts) < 7 * DAY_MS;
      }).length;
      const avgImportance = tierMems.length > 0
        ? tierMems.reduce((s, m) => s + (m.importance || 0.5), 0) / tierMems.length
        : 0;
      accessStats[tier] = {
        count: tierMems.length,
        recent_access_7d: recentAccess,
        avg_importance: Math.round(avgImportance * 1000) / 1000,
        size_bytes: sizeByTier[tier],
      };
    }

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          total_memories: memories.length,
          tier_config: {
            HOT: { maxAgeDays: TIER_CONFIG.HOT.maxAgeDays, compress: TIER_CONFIG.HOT.compress },
            WARM: { maxAgeDays: TIER_CONFIG.WARM.maxAgeDays, compress: TIER_CONFIG.WARM.compress },
            COLD: { maxAgeDays: 'unlimited', compress: TIER_CONFIG.COLD.compress },
          },
          distribution: {
            HOT: stats.HOT,
            WARM: stats.WARM,
            COLD: stats.COLD,
          },
          tier_details: accessStats,
        }, null, 2),
      }],
    };
  } catch (err) {
    log('ERROR', `[memory_tier_status] ${err.message}`);
    return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
  }
}

/**
 * memory_tier_migrate - Manually trigger tier migration
 */
export async function memoryTierMigrateTool({ apply = false } = {}) {
  try {
    const memories = await getAllMemories();
    const beforeStats = getTierStats(memories);

    // Get migration recommendations
    const migration = autoMigrateTiers(memories, { dryRun: !apply });
    const afterStats = getTierStats(migration.memories);

    const changes = [];
    for (const m of migration.changes) {
      changes.push({
        id: m.id,
        from: m.fromTier,
        to: m.toTier,
        reason: m.reason,
        importance: m.memory.importance,
      });
    }

    if (apply) {
      saveMemories(migration.memories);
      log('INFO', `[memory_tier_migrate] Applied ${changes.length} tier changes`);
    } else {
      log('INFO', `[memory_tier_migrate] Dry-run: ${changes.length} tier changes would be made`);
    }

    return {
      content: [{
        type: 'text',
        text: JSON.stringify({
          dry_run: !apply,
          before: beforeStats,
          after: afterStats,
          migrations: changes.length,
          applied: apply,
          details: changes.slice(0, 50), // cap output
        }, null, 2),
      }],
    };
  } catch (err) {
    log('ERROR', `[memory_tier_migrate] ${err.message}`);
    return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
  }
}

/**
 * memory_tier_compress - Compress COLD tier storage
 */
export async function memoryTierCompressTool({ apply = false } = {}) {
  try {
    const memories = await getAllMemories();
    const tiers = partitionByTier(memories);
    const coldMemories = tiers.COLD || [];

    if (coldMemories.length === 0) {
      return {
        content: [{
          type: 'text',
          text: JSON.stringify({
            message: 'No COLD tier memories to compress',
            cold_count: 0,
          }, null, 2),
        }],
      };
    }

    // Compress cold memories
    const compressed = compressColdTier(coldMemories);
    const originalSize = coldMemories.reduce((s, m) => s + Buffer.byteLength(JSON.stringify(m), 'utf8'), 0);
    const compressedSize = compressed.reduce((s, m) => s + Buffer.byteLength(JSON.stringify(m), 'utf8'), 0);

    const result = {
      content: [{
        type: 'text',
        text: JSON.stringify({
          dry_run: !apply,
          cold_count: coldMemories.length,
          compressed_count: compressed.length,
          original_size_bytes: originalSize,
          compressed_size_bytes: compressedSize,
          space_saved_bytes: originalSize - compressedSize,
          savings_percent: Math.round(((originalSize - compressedSize) / originalSize) * 1000) / 10,
          applied: apply,
        }, null, 2),
      }],
    };

    if (apply) {
      // Build a map of compressed memories by id
      const compressedMap = new Map(compressed.map(c => [c.id, c]));
      // Replace cold memories with their compressed versions in the full array
      const updatedMemories = memories.map(m =>
        compressedMap.has(m.id) ? compressedMap.get(m.id) : m
      );
      saveMemories(updatedMemories);
      log('INFO', `[memory_tier_compress] Compressed ${compressed.length} COLD memories`);
    }

    return result;
  } catch (err) {
    log('ERROR', `[memory_tier_compress] ${err.message}`);
    return { content: [{ type: 'text', text: `Error: ${err.message}` }], isError: true };
  }
}

export default {
  memoryTierStatusTool,
  memoryTierMigrateTool,
  memoryTierCompressTool,
};
/**
 * Token Budget Manager Enhanced - Hard Token Budget Enforcement
 * Implements strict token budget limits with automatic enforcement
 * 
 * Storage: ~/.openclaw/workspace/memory/token_budget.json
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const HOME = process.env.HOME || '/root';
const MEMORY_DIR = join(HOME, '.openclaw', 'workspace', 'memory');
const BUDGET_FILE = join(MEMORY_DIR, 'token_budget.json');

// Ensure memory directory exists
if (!existsSync(MEMORY_DIR)) {
  mkdirSync(MEMORY_DIR, { recursive: true });
}

// ============================================================================
// Configuration
// ============================================================================

const DEFAULT_CONFIG = {
  // Total context budget (tokens)
  totalBudget: 120000,
  
  // Reserved tokens for response generation
  responseReserved: 20000,
  
  // Available budget for memories
  availableBudget: 100000,
  
  // Memory type allocations (percentages)
  memoryTypeBudgets: {
    transcript: 0.30,  // 30% - main conversation transcript
    memory: 0.40,       // 40% - persistent memories
    episode: 0.15,      // 15% - session episodes
    working: 0.10,      // 10% - current task working memory
    system: 0.05,       // 5%  - system context
  },
  
  // Priority multipliers
  priorityMultipliers: {
    critical: 1.0,
    high: 0.8,
    medium: 0.5,
    low: 0.3,
  },
  
  // Hard limits
  hardLimits: {
    maxMemoriesPerType: 100,
    maxMemorySize: 2000,  // tokens per memory
    maxQueryTokens: 5000,
  },
  
  // Auto-compaction thresholds
  compactionThresholds: {
    warn: 0.70,   // 70% - warning
    compact: 0.85, // 85% - auto-compaction
    hardLimit: 0.95 // 95% - hard limit, reject new memories
  }
};

// ============================================================================
// Token Budget Manager Class
// ============================================================================

export class TokenBudgetManager {
  constructor(config = DEFAULT_CONFIG) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.usage = {
      transcript: 0,
      memory: 0,
      episode: 0,
      working: 0,
      system: 0,
      query: 0,
      total: 0
    };
    this.history = [];
  }

  /**
   * Calculate available budget
   */
  getAvailableBudget() {
    return this.config.totalBudget - this.config.responseReserved - this.usage.total;
  }

  /**
   * Calculate budget usage percentage
   */
  getUsagePercentage() {
    return this.usage.total / this.config.totalBudget;
  }

  /**
   * Check if budget is exceeded
   */
  isBudgetExceeded() {
    return this.getUsagePercentage() >= this.config.compactionThresholds.hardLimit;
  }

  /**
   * Check if auto-compaction needed
   */
  needsCompaction() {
    return this.getUsagePercentage() >= this.config.compactionThresholds.compact;
  }

  /**
   * Check if warning should be shown
   */
  shouldWarn() {
    return this.getUsagePercentage() >= this.config.compactionThresholds.warn;
  }

  /**
   * Allocate tokens for a memory type
   */
  allocate(memoryType, priority = 'medium') {
    const baseBudget = this.config.availableBudget * this.config.memoryTypeBudgets[memoryType];
    const priorityMultiplier = this.config.priorityMultipliers[priority] || 0.5;
    const allocated = baseBudget * priorityMultiplier;
    
    return {
      memoryType,
      priority,
      allocated,
      remaining: this.getAvailableBudget() - allocated
    };
  }

  /**
   * Record token usage
   */
  recordUsage(memoryType, tokens) {
    if (!this.usage[memoryType]) {
      this.usage[memoryType] = 0;
    }
    this.usage[memoryType] += tokens;
    this.usage.total += tokens;
    
    // Record history
    this.history.push({
      timestamp: new Date().toISOString(),
      memoryType,
      tokens,
      totalUsage: this.usage.total,
      usagePercentage: this.getUsagePercentage()
    });
    
    // Keep only last 100 history entries
    if (this.history.length > 100) {
      this.history.shift();
    }
  }

  /**
   * Get budget status
   */
  getStatus() {
    return {
      totalBudget: this.config.totalBudget,
      responseReserved: this.config.responseReserved,
      availableBudget: this.getAvailableBudget(),
      usage: { ...this.usage },
      usagePercentage: this.getUsagePercentage(),
      isExceeded: this.isBudgetExceeded(),
      needsCompaction: this.needsCompaction(),
      shouldWarn: this.shouldWarn(),
      hardLimits: this.config.hardLimits
    };
  }

  /**
   * Enforce hard limits
   */
  enforceHardLimits() {
    const status = this.getStatus();
    
    if (status.isExceeded) {
      return {
        success: false,
        action: 'reject',
        reason: 'Budget exceeded hard limit',
        usage: status.usagePercentage
      };
    }
    
    if (status.needsCompaction) {
      return {
        success: true,
        action: 'compact',
        reason: 'Auto-compaction needed',
        usage: status.usagePercentage
      };
    }
    
    return {
      success: true,
      action: 'none',
      reason: 'Budget OK',
      usage: status.usagePercentage
    };
  }

  /**
   * Compress memories to fit budget
   */
  compressMemories(targetBudget) {
    const currentUsage = this.usage.total;
    const budgetGap = currentUsage - targetBudget;
    
    if (budgetGap <= 0) {
      return { success: true, compressed: 0 };
    }
    
    // Strategy: compress lowest priority memories first
    // In a real implementation, this would query the memory store
    const compressed = Math.floor(budgetGap / 500); // Assume 500 tokens per memory
    
    this.usage.total -= compressed * 500;
    
    return {
      success: true,
      compressed,
      bytesFreed: compressed * 500
    };
  }

  /**
   * Get budget history
   */
  getHistory(limit = 10) {
    return this.history.slice(-limit);
  }

  /**
   * Reset usage
   */
  resetUsage() {
    this.usage = {
      transcript: 0,
      memory: 0,
      episode: 0,
      working: 0,
      system: 0,
      query: 0,
      total: 0
    };
    this.history = [];
  }

  /**
   * Save state to file
   */
  save() {
    const data = {
      config: this.config,
      usage: this.usage,
      history: this.history,
      savedAt: new Date().toISOString()
    };
    
    mkdirSync(dirname(BUDGET_FILE), { recursive: true });
    writeFileSync(BUDGET_FILE, JSON.stringify(data, null, 2), 'utf-8');
  }

  /**
   * Load state from file
   */
  static load() {
    if (!existsSync(BUDGET_FILE)) {
      return new TokenBudgetManager();
    }
    
    const data = JSON.parse(readFileSync(BUDGET_FILE, 'utf-8'));
    const manager = new TokenBudgetManager(data.config);
    manager.usage = data.usage || manager.usage;
    manager.history = data.history || [];
    return manager;
  }
}

// ============================================================================
// Singleton Instance
// ============================================================================

let _budgetManagerInstance = null;

export function getBudgetManager() {
  if (!_budgetManagerInstance) {
    _budgetManagerInstance = TokenBudgetManager.load();
  }
  return _budgetManagerInstance;
}

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Calculate memory budget for a query
 */
export function calculateBudget({ query, topK = 10, contextBudget = 120000 }) {
  const queryTokens = estimateQueryTokens(query);
  const availableBudget = contextBudget - 20000; // Reserve 20k for response
  const avgMemoryTokens = 500;
  
  const maxMemories = Math.floor((availableBudget - queryTokens) / avgMemoryTokens);
  const limit = Math.min(topK, maxMemories);
  
  return {
    queryTokens,
    contextBudget,
    availableBudget,
    maxMemories,
    limit,
    avgMemoryTokens
  };
}

/**
 * Estimate query tokens
 */
function estimateQueryTokens(query) {
  // Simple estimation: 1 character ≈ 0.25 tokens
  return Math.floor(query.length * 0.25);
}

/**
 * Get budget status
 */
export function getBudgetStatus() {
  const manager = getBudgetManager();
  return manager.getStatus();
}

/**
 * Compress if needed
 */
export function compressIfNeeded(manager) {
  if (manager.needsCompaction()) {
    return manager.compressMemories(manager.config.totalBudget * 0.8);
  }
  return { success: true, compressed: 0 };
}

/**
 * Recalculate budgets
 */
export function recalculateBudgets(manager, newConfig) {
  manager.config = { ...manager.config, ...newConfig };
  manager.save();
  return manager.getStatus();
}

